const DISEASE_DB = [
  /* ── COMMON ── */
  { name:'Fever', aliases:['fever','high temperature','pyrexia','temperature','febrile','hot body'], emoji:'🌡️', type:'common', description:'A temporary rise in body temperature, usually a sign your body is fighting an infection. Normal body temperature is around 98.6°F (37°C).', symptoms:['Body temperature above 100.4°F (38°C)','Chills and shivering','Sweating','Headache','Muscle aches','Loss of appetite','Fatigue'], causes:['Viral or bacterial infections','Heat exhaustion','Certain medications','Inflammatory conditions','Teething in infants'], homecare:['Drink plenty of fluids — water, ORS, coconut water','Rest and stay in a cool room','Take paracetamol for high fever','Wear light clothing','Apply damp cloth on forehead'], whenToSeeDoctor:'Fever above 103°F (39.4°C), lasting more than 3 days, seizures, stiff neck, or any fever in a child under 3 months.', urgency:'medium' },

  { name:'Common Cold & Flu', aliases:['cold','flu','influenza','runny nose','sneezing','sore throat','congestion','nasal','blocked nose','rhinitis'], emoji:'🤧', type:'common', description:'A viral infection of the upper respiratory tract. Very common, especially during season changes. Flu is more severe with sudden onset.', symptoms:['Runny or stuffy nose','Sneezing','Sore throat','Cough','Mild fever','Body aches','Fatigue'], causes:['Rhinovirus (cold)','Influenza virus (flu)','Close contact with infected person','Cold dry weather'], homecare:['Rest and sleep well','Drink warm fluids — ginger tea, warm water, soups','Steam inhalation for congestion','Honey and lemon for sore throat','OTC cold medicine for relief'], whenToSeeDoctor:'High fever above 103°F, difficulty breathing, symptoms lasting more than 10 days, chest pain, or persistent vomiting.', urgency:'low' },

  { name:'Headache', aliases:['headache','head pain','head ache','tension headache','pressure in head'], emoji:'😣', type:'common', description:'Headaches are extremely common and usually not serious. Tension headaches are the most common — a dull aching pain around the head.', symptoms:['Dull or throbbing pain','Pressure around forehead or sides','Neck and shoulder stiffness','Sensitivity to light or sound'], causes:['Stress and tension','Dehydration','Skipping meals','Eye strain from screens','Poor posture','Lack of sleep','Caffeine withdrawal'], homecare:['Drink a glass of water first','Rest in a quiet dark room','Apply cold or warm compress','Take paracetamol','Reduce screen time','Gentle neck stretches'], whenToSeeDoctor:'Sudden severe "worst headache of your life", headache with fever and stiff neck, after a head injury, or recurring daily headaches.', urgency:'low' },

  { name:'Back Pain', aliases:['back pain','backache','lower back','spine pain','lumbar pain','slip disc','sciatica','back ache'], emoji:'🦴', type:'common', description:'One of the most common causes of disability. Most cases are mechanical (muscle strain) and resolve with rest and gentle exercise.', symptoms:['Pain in lower, middle, or upper back','Stiffness when standing up','Pain radiating down the leg (sciatica)','Muscle spasms','Difficulty standing straight'], causes:['Poor posture while sitting or standing','Heavy lifting or sudden movements','Muscle strain or sprain','Sedentary lifestyle','Obesity','Slip disc or sciatica'], homecare:['Apply ice for first 48 hours then heat','OTC pain relievers','Gentle stretching and walking','Avoid prolonged bed rest','Correct sitting posture','Strengthen core muscles'], whenToSeeDoctor:'Pain radiating down legs, numbness or tingling, loss of bladder or bowel control, pain after injury, or no improvement after 2 weeks.', urgency:'medium' },

  { name:'Acidity & GERD', aliases:['acidity','acid reflux','heartburn','gerd','stomach acid','burning chest','indigestion','gas trouble','bloating'], emoji:'🔥', type:'common', description:'Acidity happens when stomach acid flows back into the esophagus. GERD is the chronic form. Very common due to spicy and oily food habits.', symptoms:['Burning sensation in chest (heartburn)','Sour or bitter taste in mouth','Regurgitation of food or acid','Nausea','Bloating','Difficulty swallowing','Chronic cough'], causes:['Spicy, oily, or acidic foods','Overeating and eating late at night','Caffeine, alcohol, and carbonated drinks','Lying down immediately after eating','Obesity'], homecare:['Eat small frequent meals','Avoid spicy and oily food','Do not lie down for 2-3 hours after eating','Elevate head while sleeping','Cold milk or coconut water can help','Antacids for quick relief'], whenToSeeDoctor:'Symptoms more than twice a week, difficulty swallowing, blood in stool or vomit, unexplained weight loss, or antacids stop working.', urgency:'medium' },

  { name:'Allergy', aliases:['allergy','allergic reaction','allergic','itching','hives','rash','urticaria','sneezing allergy','dust allergy','pollen allergy','food allergy','skin allergy','allergies'], emoji:'🌿', type:'common', description:'An allergy is an immune system reaction to a normally harmless substance (allergen). Allergies can affect the skin, eyes, nose, lungs, and digestive system.', symptoms:['Sneezing and runny nose','Itchy, watery, or red eyes','Skin rash or hives','Itching (skin, eyes, nose, throat)','Swelling of lips, tongue, or face','Nasal congestion','Coughing or wheezing'], causes:['Pollen, dust mites, pet dander','Certain foods (peanuts, shellfish, milk, eggs)','Insect stings','Medications (aspirin, penicillin)','Mold spores','Latex'], homecare:['Avoid known allergens','Antihistamine tablets for mild reactions','Apply calamine lotion or cold compress for skin rash','Wear a mask in dusty or polluted environments','Keep windows closed during high pollen season','Use air purifiers at home'], whenToSeeDoctor:'Severe reaction (anaphylaxis): difficulty breathing, swelling of throat, rapid heartbeat, dizziness — call emergency immediately. See an allergist for persistent or severe allergies.', urgency:'medium' },

  { name:'Conjunctivitis (Pink Eye)', aliases:['pink eye','conjunctivitis','red eye','eye infection','eye discharge','sticky eye'], emoji:'👁️', type:'common', description:'Inflammation of the outer membrane of the eye (conjunctiva). Can be caused by bacteria, viruses, or allergies. Very contagious if infectious.', symptoms:['Redness in the white of the eye','Discharge (watery or thick yellow/green)','Crusty eyelids especially after sleep','Itching or burning sensation','Sensitivity to light','Blurred vision'], causes:['Bacterial infection','Viral infection (often with common cold)','Allergic reaction','Chemical or smoke irritation'], homecare:['Clean discharge with clean damp cotton','Use prescribed eye drops if bacterial','Avoid touching eyes and wash hands frequently','Avoid sharing towels or eye products','Cool compress for relief'], whenToSeeDoctor:'Vision changes, severe pain, intense redness, symptoms not improving after 3 days, or if a newborn has eye discharge.', urgency:'medium' },

  { name:'Stomach Pain', aliases:['stomach pain','stomach ache','abdominal pain','tummy pain','belly pain','cramps','gastric pain'], emoji:'🤢', type:'common', description:'Stomach or abdominal pain is very common and can range from mild indigestion to serious conditions. Most cases are minor and resolve on their own.', symptoms:['Pain or cramps in the abdomen','Nausea','Bloating and gas','Diarrhea or constipation','Loss of appetite'], causes:['Indigestion or gas','Food poisoning','Constipation','Menstrual cramps','Gastroenteritis (stomach flu)','Ulcers'], homecare:['Rest and avoid solid food for a few hours','Drink clear fluids — water and ORS','Avoid spicy, fatty, or rich foods','Apply warm compress on abdomen','Antacids if burning or acidity'], whenToSeeDoctor:'Severe sudden pain, pain with fever above 101°F, blood in stool or vomit, pain lasting more than 3 days, or inability to keep fluids down.', urgency:'medium' },

  { name:'Diarrhea', aliases:['diarrhea','loose stools','loose motions','watery stool','stomach upset','gastroenteritis','food poisoning'], emoji:'🚽', type:'common', description:'Frequent loose or watery bowel movements. Usually caused by infection, food poisoning, or intolerance. Dehydration is the main risk.', symptoms:['Loose or watery stools 3+ times per day','Stomach cramps','Nausea and vomiting','Fever','Bloating','Urgent need to use bathroom'], causes:['Viral or bacterial infection','Food poisoning','Contaminated water','Lactose intolerance','IBS','Antibiotics side effect'], homecare:['Drink ORS frequently to replace fluids','Eat bland food — banana, rice, boiled potatoes, toast (BRAT diet)','Avoid dairy, spicy, and fatty foods','Rest','Probiotics like curd (yogurt) can help'], whenToSeeDoctor:'Bloody stool, fever above 102°F, symptoms in children under 2, signs of dehydration (no urination, dry mouth, dizziness), or diarrhea lasting more than 3 days.', urgency:'medium' },

  { name:'Constipation', aliases:['constipation','hard stool','no motion','difficulty passing stool','bowel issue'], emoji:'😣', type:'common', description:'Having fewer than 3 bowel movements per week, or stools that are hard and difficult to pass. Very common and usually easily treatable.', symptoms:['Fewer than 3 bowel movements per week','Hard, dry, or lumpy stools','Straining during bowel movements','Feeling of blockage','Bloating and discomfort'], causes:['Low fiber diet','Not drinking enough water','Sedentary lifestyle','Ignoring the urge to go','Certain medications (iron, calcium, antacids)','Stress'], homecare:['Drink 8-10 glasses of water daily','Eat high-fiber foods — fruits, vegetables, whole grains, pulses','Exercise daily — even a 30 min walk helps','Do not ignore the urge to go','Warm water with lemon in the morning'], whenToSeeDoctor:'Constipation lasting more than 3 weeks, blood in stool, unexplained weight loss, severe abdominal pain, or alternating with diarrhea.', urgency:'low' },

  { name:'Nausea & Vomiting', aliases:['nausea','vomiting','feeling sick','throwing up','motion sickness','morning sickness'], emoji:'🤮', type:'common', description:'Nausea is the feeling of wanting to vomit. It can be caused by many conditions from mild (motion sickness) to serious (food poisoning, pregnancy).', symptoms:['Uncomfortable sensation in stomach','Urge to vomit','Actual vomiting','Dizziness','Loss of appetite','Sweating or pale skin'], causes:['Motion sickness','Food poisoning','Pregnancy (morning sickness)','Migraine','Certain medications','Anxiety or stress','Viral infection'], homecare:['Sip clear fluids slowly — water, ginger tea, ORS','Eat small bland meals when able (crackers, toast, banana)','Rest in a comfortable position','Ginger — tea, candies, or capsules can help','Avoid strong smells, greasy or spicy food'], whenToSeeDoctor:'Vomiting blood, severe abdominal pain, signs of dehydration, vomiting for more than 24 hours, or if a child cannot keep any fluids down.', urgency:'medium' },

  { name:'Color Blindness', aliases:['color blindness','colour blindness','color vision deficiency','red green color blind','deuteranopia','protanopia'], emoji:'👁️', type:'common', description:'A condition where the eye cannot distinguish certain colors, most commonly red and green. Present from birth in most cases. Affects about 8% of men and 0.5% of women.', symptoms:['Difficulty distinguishing red and green (most common)','Difficulty distinguishing blue and yellow','Seeing a limited range of colors','Needing bright light to see colors properly','Difficulty reading color-coded materials'], causes:['Genetic inheritance — X-linked (most common, affects more men)','Damage to retina or optic nerve','Age-related changes','Certain medications','Diseases such as diabetes or multiple sclerosis'], homecare:['Use color-labeling apps or technology to identify colors','Wear specially designed color-corrective glasses or contact lenses','Use high-contrast settings on screens and devices','Memorize the positions of traffic lights rather than relying on color','Inform teachers, employers, or relevant people of the condition'], whenToSeeDoctor:'If you suspect color blindness, an optometrist can confirm with simple color vision tests. Acquired color vision loss in adults should be evaluated promptly as it may indicate eye or neurological disease.', urgency:'low' },

  { name:'Crossed Eyes', aliases:['crossed eyes','strabismus','squint','misaligned eyes','eye turn','wall eye'], emoji:'👁️', type:'common', description:'A condition where the eyes do not properly align with each other when looking at an object. One or both eyes may turn inward, outward, upward, or downward. Common in children but can affect adults.', symptoms:['Eyes that do not look in the same direction at the same time','Eyes that do not move together','Squinting or closing one eye in bright sunlight','Tilting or turning the head to see better','Double vision (in adults with new-onset strabismus)','Poor depth perception'], causes:['Muscle imbalance controlling eye movement','Nerve damage to eye muscles','Uncorrected refractive error (farsightedness)','Genetics and family history','Brain conditions such as stroke or tumors (in adults)','Childhood illness such as measles'], homecare:['Patching the stronger eye to strengthen the weaker one (as prescribed)','Wear corrective glasses or contact lenses if prescribed','Eye exercises as directed by an eye specialist','Early treatment gives best outcomes — do not delay'], whenToSeeDoctor:'Any child appearing to have crossed or misaligned eyes should see a pediatric ophthalmologist promptly. Adults with sudden onset of double vision or eye misalignment need urgent evaluation.', urgency:'medium' },

  { name:'Lazy Eye', aliases:['lazy eye','amblyopia','poor vision one eye','reduced vision one eye','weak eye'], emoji:'👁️', type:'common', description:'A condition where one eye develops poor vision because the brain favors the other eye. The most common cause of vision problems in children. If treated early, vision can be restored.', symptoms:['An eye that wanders inward or outward','Eyes that appear not to work together','Poor depth perception','Squinting or shutting one eye','Head tilting','Abnormal results in vision screening'], causes:['Strabismus (crossed eyes)','Refractive error difference between the two eyes','Childhood cataract or other visual obstruction','Drooping eyelid blocking vision in one eye'], homecare:['Wear the prescribed glasses consistently','Patch the stronger eye as directed by the doctor to force use of the weaker eye','Eye drops (atropine) in the stronger eye as an alternative to patching (if prescribed)','Engage in fine motor activities while patching — puzzles, drawing, reading'], whenToSeeDoctor:'Children should have vision screening by age 3-4. Any parent concerned about a child\'s vision or eye alignment should see an ophthalmologist. Treatment is most effective before age 7 but can help up to age 17.', urgency:'medium' },

  { name:'Eyelid Drooping', aliases:['eyelid drooping','ptosis','droopy eyelid','sagging eyelid','falling eyelid'], emoji:'👁️', type:'common', description:'A drooping or falling of the upper eyelid. Can affect one or both eyes. May be mild or severe enough to obstruct vision. Can be present from birth or develop later in life.', symptoms:['Upper eyelid droops lower than normal','Reduced field of vision if severe','Tilting head backwards to see better','Raised eyebrow to lift the lid','Fatigue of the eye by end of day','Asymmetrical eyelids'], causes:['Age-related weakening of the eyelid muscle (most common in adults)','Congenital (present from birth)','Nerve damage (Horner\'s syndrome, third nerve palsy)','Myasthenia gravis (autoimmune neuromuscular disease)','Injury or eye surgery','Diabetes'], homecare:['Mild drooping in older adults — cosmetic concern only, no home treatment changes it','Protect the eye from dryness if closure is incomplete (lubricating drops)','Do not ignore drooping in children — can lead to lazy eye'], whenToSeeDoctor:'Any new or sudden onset eyelid drooping in an adult requires prompt evaluation to rule out stroke, aneurysm, or Horner\'s syndrome. Drooping in children needs early assessment to prevent amblyopia. Surgical correction is available.', urgency:'medium' },

  { name:'Dacryocystitis', aliases:['dacryocystitis','lacrimal sac infection','tear sac infection','swelling beside nose eye','inner eye corner swelling'], emoji:'👁️', type:'common', description:'Infection of the lacrimal sac — the tear drainage sac located at the inner corner of the eye near the nose. Can be acute (sudden) or chronic.', symptoms:['Pain, redness, and swelling at the inner corner of the eye near the nose','Discharge or pus from the eye','Excessive tearing','Fever in acute cases','Tenderness when pressing on the swelling','Crusting around the eye'], causes:['Blocked nasolacrimal duct allowing bacterial growth','Sinusitis','Nasal injury or surgery','Nasal polyps','Congenital narrowing of the tear duct'], homecare:['Warm compress applied to the inner corner of the eye 3-4 times daily','Gentle massage of the lacrimal sac area','Prescribed antibiotic eye drops or oral antibiotics','Do not attempt to squeeze or drain the swelling yourself'], whenToSeeDoctor:'Always see a doctor for dacryocystitis — it requires antibiotic treatment. Severe cases may need hospitalization. Surgical drainage (dacryocystorhinostomy) may be needed for chronic or recurrent cases.', urgency:'medium' },

  { name:'Glaucoma', aliases:['glaucoma','eye pressure','optic nerve damage eye','glaucoma early','raised eye pressure'], emoji:'👁️', type:'common', description:'A group of eye conditions that damage the optic nerve, usually due to abnormally high pressure in the eye. One of the leading causes of blindness worldwide. Often asymptomatic until advanced.', symptoms:['Gradual loss of peripheral vision (most common type — open angle)','Tunnel vision in advanced stages','Sudden severe eye pain (acute angle-closure — emergency)','Nausea and vomiting with eye pain','Halos around lights','Blurred vision','Eye redness'], causes:['Elevated intraocular pressure (most common)','Poor drainage of aqueous humor from the eye','Age over 60','Family history','High myopia','Diabetes and hypertension'], homecare:['Prescribed eye drops must be used every day without fail','Regular exercise improves blood flow to the optic nerve','Avoid wearing tight neckties or collars','Sleep with head slightly elevated','Regular eye checkups every 6-12 months once diagnosed','Do not miss doses of eye drops'], whenToSeeDoctor:'Regular eye pressure checks are essential from age 40, or earlier with family history. Sudden eye pain with nausea, vomiting, and blurred vision is acute glaucoma — a medical emergency requiring immediate care.', urgency:'medium' },

  { name:'Cataracts', aliases:['cataracts','cataract','cloudy lens','blurry vision aging','cloudy eye','lens opacity'], emoji:'👁️', type:'common', description:'Clouding of the normally clear lens of the eye, leading to blurred or dimmed vision. Extremely common with aging. Surgery is the only effective treatment and is one of the most successful operations performed.', symptoms:['Clouded, blurred, or dim vision','Increasing difficulty with vision at night','Sensitivity to light and glare','Halos around lights','Need for brighter light for reading','Fading or yellowing of colors','Double vision in one eye','Frequent changes in glasses prescription'], causes:['Aging (most common)','Ultraviolet radiation exposure','Diabetes','Smoking','Eye injury or inflammation','Prolonged corticosteroid use','Genetic conditions'], homecare:['Use brighter lights for reading and work','Use anti-glare sunglasses outdoors','Magnifying lenses if prescribed','Manage diabetes and other underlying conditions','Quit smoking'], whenToSeeDoctor:'See an ophthalmologist annually after age 60. When cataracts significantly affect daily activities like driving, reading, or working, surgery is recommended. Surgery is very safe and highly effective.', urgency:'low' },

  { name:'Macular Degeneration', aliases:['macular degeneration','AMD','age-related macular degeneration','central vision loss','blurred central vision'], emoji:'👁️', type:'common', description:'A disease causing deterioration of the macula — the central part of the retina. Leading cause of severe vision loss in adults over 50. Two types: dry (most common, slow) and wet (fast, more severe).', symptoms:['Gradual blurring of central vision','Difficulty reading fine print','Straight lines appearing wavy (Amsler grid distortion)','Need for bright light for close work','Colors appear less bright','Blank spot in center of vision in advanced stages'], causes:['Aging (primary risk factor)','Genetics and family history','Smoking (doubles the risk)','Obesity and cardiovascular disease','Prolonged UV light exposure','Light-colored eyes may carry slightly higher risk'], homecare:['Quit smoking — the single most modifiable risk factor','Eat leafy greens, fish, and antioxidant-rich foods (lutein and zeaxanthin)','Wear sunglasses that block UV light','Maintain a healthy weight and blood pressure','Monitor vision daily with an Amsler grid at home','AREDS2 supplements if recommended by doctor'], whenToSeeDoctor:'Annual dilated eye exams from age 50, or more frequently if diagnosed. Any sudden change in central vision, new distortion of straight lines, or a blank spot in vision requires urgent evaluation as wet AMD can worsen rapidly.', urgency:'medium' },

  { name:'Otitis Externa', aliases:['otitis externa','swimmer\'s ear','outer ear infection','ear canal infection','external ear infection'], emoji:'👂', type:'common', description:'Inflammation and infection of the outer ear canal — the passage leading from the outer ear to the eardrum. Commonly called swimmer\'s ear. Caused by water remaining in the ear creating a moist environment for bacteria or fungi.', symptoms:['Ear pain that worsens when pulling the outer ear or pressing on the ear lobe','Itching in the ear canal','Redness and swelling of the outer ear','Clear, odorless discharge initially','Yellow-green pus with infection progression','Muffled hearing or a feeling of fullness','Swollen lymph nodes near the ear'], causes:['Water in the ear from swimming or bathing','Scratching the ear canal','Using cotton swabs (damages skin lining)','Hearing aid or earplug use','Skin conditions (eczema, psoriasis) in the ear canal'], homecare:['Keep the ear dry — use a dry towel, tilt head to drain water after swimming','Avoid inserting objects into the ear canal','Use prescribed antibiotic ear drops as directed','Over-the-counter swimmer\'s ear drops for mild cases','Apply a warm compress for pain relief','Avoid swimming until the infection clears'], whenToSeeDoctor:'Pain that is severe or worsening despite home care, significant swelling, fever, or hearing loss. Diabetics and immunocompromised individuals should see a doctor immediately as they are at risk of malignant otitis externa.', urgency:'medium' },

  { name:'Ear Fullness', aliases:['ear fullness','blocked ear feeling','plugged ear','ear pressure','muffled ear','clogged ear feeling'], emoji:'👂', type:'common', description:'A feeling of fullness, pressure, or blockage in the ear without actual physical blockage. Very common and usually temporary. Can affect hearing and balance.', symptoms:['Sensation of fullness or pressure in one or both ears','Muffled hearing','Popping or crackling sounds','Tinnitus (ringing)','Mild dizziness','Discomfort but not severe pain'], causes:['Eustachian tube dysfunction (most common)','Earwax buildup','Altitude changes (air travel, mountain driving)','Sinus or nasal congestion','Middle ear fluid (otitis media with effusion)','Temporomandibular joint (TMJ) problems'], homecare:['Valsalva maneuver — gently blow with nose pinched and mouth closed to equalize pressure','Swallow, yawn, or chew gum to open the Eustachian tube','Nasal decongestant spray if congestion is the cause','Avoid high altitudes or air travel if possible during congestion','Warm compress over the ear'], whenToSeeDoctor:'Ear fullness lasting more than a week, associated with significant hearing loss, severe pain, dizziness, or if it keeps recurring. Persistent middle ear fluid in children needs evaluation as it can affect speech development.', urgency:'low' },

  { name:'Balance Disorder', aliases:['balance disorder','balance problem','unsteadiness','poor balance','dizziness balance','vestibular disorder'], emoji:'👂', type:'common', description:'A condition that makes you feel unsteady, dizzy, or as though you or the world around you is moving or spinning. Can significantly affect daily life and increase fall risk.', symptoms:['Feeling of motion when standing still','Staggering when trying to walk','Lightheadedness or feeling faint','Blurred vision with movement','Disorientation or confusion','Nausea and vomiting','Difficulty walking in the dark'], causes:['Benign paroxysmal positional vertigo (BPPV) — most common','Inner ear infection (labyrinthitis)','Meniere\'s disease','Vestibular migraine','Aging (reduced sensory input and muscle strength)','Head injury','Medications that affect the inner ear'], homecare:['Epley maneuver for BPPV — repositions displaced ear crystals (learn from physiotherapist)','Move slowly when changing positions','Avoid sudden head movements','Keep home free of fall hazards — good lighting, grab bars, remove rugs','Vestibular rehabilitation exercises as prescribed'], whenToSeeDoctor:'Persistent or severe balance problems, sudden onset, or with hearing loss, vision changes, or neurological symptoms. Falls from balance disorders can cause serious injury. Vestibular physiotherapy is highly effective.', urgency:'medium' },

  /* ── COMMON: NOSE & THROAT ── */
  { name:'Deviated Nasal Septum', aliases:['deviated septum','nasal septum deviation','blocked nose one side','septum deviation','one sided nasal blockage'], emoji:'👃', type:'common', description:'A condition where the thin wall (septum) between the nasal passages is displaced to one side. Estimated to affect 80% of people to some degree. Causes nasal obstruction and breathing difficulty.', symptoms:['Nasal congestion on one or both sides','Noisy breathing during sleep','Breathing through mouth more than nose','Nosebleeds due to dry nasal passages','Frequent sinus infections','Facial pain or headache on one side','Uneven airflow through the nostrils'], causes:['Congenital — present at birth or from birth trauma','Nasal injury — blow to the nose, sports injury','Gradual worsening with age'], homecare:['Nasal saline rinse to keep passages moist and clear','Nasal decongestant sprays for short-term relief','Nasal corticosteroid spray for associated inflammation','Treat underlying sinusitis or allergies','Humidifier to reduce dryness-related nosebleeds'], whenToSeeDoctor:'If breathing difficulty significantly affects quality of life, sleep, or if recurrent sinus infections occur. Surgical correction (septoplasty) is straightforward and highly effective for severe cases.', urgency:'low' },

  { name:'Chronic Rhinitis', aliases:['chronic rhinitis','chronic runny nose','persistent rhinitis','non-allergic rhinitis','chronic nasal congestion'], emoji:'👃', type:'common', description:'Long-term inflammation of the nasal passages causing persistent runny nose, congestion, and sneezing. Can be allergic or non-allergic. Affects quality of life significantly.', symptoms:['Persistent runny or blocked nose','Frequent sneezing','Post-nasal drip','Reduced sense of smell','Nasal congestion especially at night','Watery eyes'], causes:['Chronic allergies (perennial allergic rhinitis)','Hormonal changes (pregnancy, hypothyroidism)','Medications (decongestant nasal spray overuse)','Environmental irritants (smoke, chemicals, cold air)','Infection'], homecare:['Identify and avoid allergens or irritants','Saline nasal rinse twice daily','Nasal corticosteroid spray (first-line treatment)','Antihistamines for allergic type','Use a HEPA air purifier at home','Avoid overuse of decongestant nasal sprays (limit to 3 days)'], whenToSeeDoctor:'Symptoms persisting despite nasal corticosteroid spray after 2-3 months, significant quality of life impact, or suspected allergic cause needing skin testing and immunotherapy.', urgency:'low' },

  { name:'Non-Allergic Rhinitis', aliases:['non-allergic rhinitis','vasomotor rhinitis','non-allergic runny nose','perennial rhinitis','idiopathic rhinitis'], emoji:'👃', type:'common', description:'Chronic sneezing, congestion, or runny nose that is not caused by allergies. Triggered by environmental factors rather than allergens. Often underdiagnosed.', symptoms:['Runny nose with clear mucus','Nasal congestion','Sneezing','No itchy eyes or throat (distinguishes from allergy)','Triggered by specific stimuli'], causes:['Changes in weather, temperature, or humidity','Strong odors — perfume, smoke, cleaning products','Spicy foods (gustatory rhinitis)','Certain medications (aspirin, beta-blockers)','Hormonal changes','Overuse of decongestant nasal spray'], homecare:['Identify and avoid specific triggers','Saline nasal rinse','Nasal corticosteroid sprays as first-line treatment','Nasal antihistamine spray (azelastine) for non-allergic type','Avoid strong perfumes and smoke'], whenToSeeDoctor:'Symptoms not controlled with nasal corticosteroid spray, suspected medication-induced rhinitis, or significantly affecting daily life. Allergy testing can rule out allergic component.', urgency:'low' },

  { name:'Dry Throat', aliases:['dry throat','throat dryness','parched throat','scratchy dry throat','throat feels dry'], emoji:'🗣️', type:'common', description:'A sensation of dryness, scratchiness, or irritation in the throat. Usually benign and related to dehydration, mouth breathing, or dry air. Very common especially during winter.', symptoms:['Dry, scratchy, or irritated throat','Difficulty swallowing','Increased thirst','Dry mouth along with throat dryness','Mild hoarseness','Worsens in the morning or after sleeping'], causes:['Dehydration','Breathing through the mouth (due to nasal congestion)','Dry indoor air (heating, air conditioning)','Allergies or post-nasal drip','Sleeping with mouth open','Snoring','Certain medications (antihistamines, antidepressants)'], homecare:['Drink adequate water throughout the day — at least 8 glasses','Use a humidifier in the bedroom','Honey in warm water or tea soothes and coats the throat','Avoid caffeine and alcohol which dehydrate','Breathe through the nose rather than the mouth','Saline nasal spray to reduce mouth breathing from congestion'], whenToSeeDoctor:'Persistent dry throat for more than 2 weeks, difficulty swallowing, unexplained weight loss, or lump feeling in the throat — these need evaluation.', urgency:'low' },

  { name:'Scratchy Throat', aliases:['scratchy throat','itchy throat','throat irritation','irritated throat','throat tickle','tickly throat'], emoji:'🗣️', type:'common', description:'An irritating sensation in the throat causing the urge to cough or clear the throat. Usually the first sign of a cold or allergy. Generally harmless.', symptoms:['Scratchy or itchy sensation in the throat','Urge to clear the throat repeatedly','Dry cough','Mild sore throat','Runny nose (if allergy or cold-related)','Sneezing'], causes:['Early stages of a viral cold','Allergic rhinitis and post-nasal drip','Dry air','Acid reflux irritating the throat','Irritants — smoke, dust, chemical fumes','Mouth breathing'], homecare:['Drink warm fluids — warm water with honey and lemon','Gargle with warm salt water','Throat lozenges or hard candy to stimulate saliva and coat the throat','Humidifier in the room','Avoid irritants — smoke, dust, dry air','Antihistamine if allergy is the trigger'], whenToSeeDoctor:'Scratchy throat with fever, difficulty swallowing, significant pain, or lasting more than a week without improvement — may indicate strep throat or other infection needing treatment.', urgency:'low' },

  { name:'Epiglottitis', aliases:['epiglottitis','epiglottis infection','swollen epiglottis','throat swelling emergency','severe throat infection'], emoji:'🗣️', type:'common', description:'Inflammation and swelling of the epiglottis — the flap of cartilage at the base of the tongue that covers the windpipe. A rare but life-threatening condition because it can block the airway.', symptoms:['Severe sore throat that worsens rapidly','Severe difficulty swallowing','Drooling (because swallowing is too painful)','Muffled or changed voice','High fever','Breathing difficulty — stridor (high-pitched sound when breathing in)','Leaning forward while sitting to ease breathing'], causes:['Haemophilus influenzae type b (Hib) bacteria — now rare due to vaccination','Other bacteria (Streptococcus, Staphylococcus)','Chemical burns from swallowing hot liquid or caustic substance','Physical injury to the throat'], homecare:['No home care — epiglottitis is a medical emergency','Do NOT attempt to examine the throat or press down the tongue','Keep the person calm and upright','Call emergency services immediately'], whenToSeeDoctor:'Epiglottitis is a life-threatening emergency — call an ambulance immediately. Do not attempt to drive to the hospital. Airway management must be performed by medical professionals.', urgency:'high' },

  { name:'Vocal Cord Nodules', aliases:['vocal cord nodules','voice nodules','singer\'s nodes','vocal nodules','hoarse voice nodules','voice polyps'], emoji:'🗣️', type:'common', description:'Small, benign growths on the vocal cords caused by vocal strain and overuse. Common in singers, teachers, coaches, and people who use their voice heavily.', symptoms:['Hoarse, breathy, or rough voice','Voice fatigue after speaking or singing','Lowered pitch or pitch breaks','Inability to reach high notes','Discomfort or feeling of something in the throat','Chronic throat clearing'], causes:['Vocal overuse or misuse — singing, yelling, speaking loudly for long periods','Poor vocal technique','Dehydration','Smoking and acid reflux worsen the condition'], homecare:['Voice rest — reduce speaking and avoid shouting or whispering','Stay well hydrated — drink lots of water','Steam inhalation to keep vocal cords moist','Avoid caffeine and alcohol which dry out the throat','Treat acid reflux if present','Speech therapy is the most effective non-surgical treatment'], whenToSeeDoctor:'Hoarseness lasting more than 2 weeks, significant voice changes affecting work or daily life, or pain when speaking. A laryngologist can visualize the vocal cords. Most nodules resolve with speech therapy.', urgency:'low' },

  { name:'Voice Hoarseness', aliases:['hoarseness','hoarse voice','rough voice','voice changes','raspy voice','husky voice'], emoji:'🗣️', type:'common', description:'A change in the normal quality of the voice that makes it sound breathy, raspy, strained, or different in pitch or volume. Usually temporary and caused by laryngitis.', symptoms:['Raspy, rough, or husky voice quality','Reduced vocal volume','Changed pitch','Voice tires easily','Discomfort or pain when speaking','Sensation of something stuck in throat'], causes:['Viral laryngitis (most common — after cold or flu)','Vocal overuse (cheering, shouting, prolonged speaking)','Gastroesophageal reflux disease (GERD)','Smoking','Vocal cord nodules or polyps','Rarely: thyroid disease or neurological conditions'], homecare:['Rest your voice for at least 48 hours','Drink warm fluids — honey, ginger, lemon tea','Steam inhalation','Avoid whispering — it strains the cords more than soft speaking','Humidifier in the room','Treat acid reflux if present'], whenToSeeDoctor:'Hoarseness lasting more than 2 weeks especially in a smoker, hoarseness with difficulty breathing or swallowing, blood in phlegm, or a lump in the neck — these need urgent evaluation to rule out serious conditions.', urgency:'low' },

  { name:'Chronic Cough', aliases:['chronic cough','persistent cough','long term cough','cough that won\'t go away','ongoing cough'], emoji:'💨', type:'common', description:'A cough lasting 8 weeks or more in adults (4 weeks in children). One of the most common reasons people visit a doctor. Usually has an identifiable and treatable cause.', symptoms:['Cough lasting 8 or more weeks','May be dry or productive','Postnasal drip sensation','Heartburn or sour taste (if GERD-related)','Runny nose and congestion','Shortness of breath if asthma-related','Coughing up blood (needs urgent evaluation)'], causes:['Postnasal drip (upper airway cough syndrome) — most common','Asthma (especially in non-smokers)','Gastroesophageal reflux disease (GERD)','ACE inhibitor blood pressure medications','Chronic bronchitis (smokers)','Pertussis (whooping cough)'], homecare:['Saline nasal rinse for post-nasal drip','Elevate head of bed and avoid food 3 hours before bed for GERD','Avoid smoke and known irritants','Identify and address the underlying cause'], whenToSeeDoctor:'A chronic cough lasting 8 weeks or more always warrants a medical evaluation to identify the cause. Coughing up blood, significant weight loss, night sweats, or cough with shortness of breath need urgent assessment.', urgency:'medium' },

  { name:'Productive Cough', aliases:['productive cough','wet cough','cough with phlegm','cough with mucus','chesty cough'], emoji:'💨', type:'common', description:'A cough that brings up mucus or phlegm from the airways. The body\'s way of clearing excess mucus or infection from the respiratory tract. Usually a sign of respiratory infection or inflammation.', symptoms:['Cough that produces mucus or phlegm','Mucus may be clear, white, yellow, or green','Chest congestion','Shortness of breath','Wheezing if airways are irritated','Fatigue'], causes:['Viral respiratory infection (cold, flu)','Acute bronchitis','Pneumonia','Chronic obstructive pulmonary disease (COPD)','Asthma','Smoking','Postnasal drip'], homecare:['Drink plenty of fluids to thin mucus and aid expectoration','Honey in warm water or tea to soothe airways','Steam inhalation to loosen mucus','Expectorant medication (guaifenesin) to help clear mucus','Prop up with extra pillows at night','Avoid smoking and second-hand smoke'], whenToSeeDoctor:'Productive cough with high fever, blood-tinged mucus, breathlessness at rest, chest pain, lasting more than 3 weeks, or in an older or immunocompromised person. Pneumonia requires antibiotics.', urgency:'medium' },

  { name:'Blood in Sputum', aliases:['blood in sputum','haemoptysis','hemoptysis','coughing up blood','blood in phlegm','bloody mucus'], emoji:'💨', type:'common', description:'Coughing up blood or blood-stained mucus from the respiratory tract. Even small amounts of blood in sputum should not be ignored and require medical evaluation.', symptoms:['Blood or pink, red, or rust-colored mucus when coughing','May be frothy (from lungs) or mixed with mucus','May be accompanied by cough, chest pain, or shortness of breath'], causes:['Bronchitis or respiratory infection (most common cause of small amounts)','Pneumonia','Pulmonary embolism (blood clot in lung)','Tuberculosis','Lung cancer','Bronchiectasis','Mitral stenosis (heart valve disease)','Anticoagulant medications'], homecare:['No specific home care — blood in sputum requires medical evaluation','Rest and avoid strenuous activity','Note the amount, color, and frequency to report to the doctor','Do not suppress the cough — it needs to be cleared'], whenToSeeDoctor:'Any amount of blood in sputum that is not from the mouth or nose should be evaluated by a doctor. Significant bleeding (more than a teaspoon), associated fever, weight loss, or shortness of breath requires urgent attention.', urgency:'high' },

  { name:'Sleep Apnea', aliases:['sleep apnea','sleep apnoea','obstructive sleep apnea','OSA','breathing stops during sleep','snoring apnea'], emoji:'😴', type:'common', description:'A sleep disorder where breathing repeatedly stops and starts during sleep. The most common type is obstructive sleep apnea where the throat muscles relax and block the airway. Increases risk of heart disease, stroke, and diabetes if untreated.', symptoms:['Loud snoring','Episodes of stopped breathing witnessed by a partner','Gasping or choking during sleep','Morning headache','Excessive daytime sleepiness','Difficulty concentrating','Dry mouth or sore throat on waking','Irritability and mood changes'], causes:['Obesity and excess neck weight (most common risk factor)','Large tonsils or tongue','Nasal congestion','Sleeping on back','Alcohol and sedatives before sleep','Aging — muscle tone decreases','Family history'], homecare:['Sleep on your side instead of back — tennis ball trick (sew a tennis ball in back of pyjamas)','Lose excess weight — even 10% weight loss significantly reduces sleep apnea','Avoid alcohol and sedatives, especially before sleep','Treat nasal congestion','Elevate head of bed by 4-6 inches','CPAP machine is the gold standard treatment (prescription)'], whenToSeeDoctor:'Suspected sleep apnea needs medical evaluation and a sleep study. Untreated sleep apnea significantly increases risk of hypertension, heart attack, stroke, and car accidents from drowsiness.', urgency:'medium' },

  { name:'Adenoid Enlargement', aliases:['enlarged adenoids','adenoid hypertrophy','adenoid enlargement','big adenoids','adenoid problem'], emoji:'👃', type:'common', description:'Enlargement of the adenoids — patches of tissue at the back of the nasal cavity. Most common in children aged 2-6. Adenoids normally shrink and disappear by adolescence.', symptoms:['Persistent nasal congestion and blockage','Breathing through mouth instead of nose','Snoring and noisy breathing during sleep','Sleep apnea in severe cases','Repeated ear infections','Nasal speech (sounds like talking through the nose)','Persistent runny nose'], causes:['Repeated infections causing adenoids to enlarge','Allergies','Genetic tendency for larger adenoids'], homecare:['Saline nasal rinse to clear congestion','Humidifier in bedroom','Keep head slightly elevated when sleeping','Treat underlying allergies with antihistamines or nasal sprays','Encourage nose breathing habits'], whenToSeeDoctor:'Persistent mouth breathing, snoring with pauses, recurrent ear infections, sleep disruption, or speech problems in children need assessment. Surgical removal (adenoidectomy) is straightforward and curative.', urgency:'medium' },

  { name:'Excessive Saliva', aliases:['excessive saliva','hypersalivation','drooling','sialorrhoea','too much saliva','drooling adult'], emoji:'🗣️', type:'common', description:'Production of more saliva than normal, causing drooling or the need to swallow frequently. More common in children but can affect adults, often as a result of another condition.', symptoms:['Drooling or inability to contain saliva in the mouth','Frequent need to swallow saliva','Wet lips or chin','Social embarrassment','Skin irritation around mouth from constant wetness'], causes:['Teething in infants','Oral infections or ulcers causing mouth irritation','Poorly fitting dentures','Nausea (salivation increases before vomiting)','Certain medications (clozapine, pilocarpine)','Neurological conditions (Parkinson\'s, cerebral palsy, stroke) impairing swallowing'], homecare:['Maintain good oral hygiene','Chew sugar-free gum to help manage saliva','Keep head upright to help swallow saliva naturally','Address denture fit if relevant','Treat nausea if that is the cause'], whenToSeeDoctor:'Excessive saliva with difficulty swallowing, neurological symptoms, new onset in adults, or significantly affecting quality of life. Botulinum toxin injections into salivary glands are an effective treatment for severe cases.', urgency:'low' },

  /* ── COMMON: SKIN ── */
  { name:'Seborrheic Dermatitis', aliases:['seborrheic dermatitis','seborrhoeic dermatitis','facial dandruff','oily scaly skin','seborrheic eczema','face flaking'], emoji:'🔴', type:'common', description:'A common skin condition causing scaly patches, red skin, and stubborn dandruff. Affects mainly the scalp but also oily areas like the face, chest, and back. Chronic with flares and remissions.', symptoms:['Skin flakes (dandruff) on scalp, hair, eyebrows, beard, or mustache','Greasy or oily skin patches covered with white or yellowish scales','Red skin','Itching'], causes:['Malassezia yeast that lives on skin causing inflammatory reaction in some people','Oily skin and hair','Immune system response','Stress worsens flares','Cold, dry weather'], homecare:['Use anti-dandruff shampoo containing ketoconazole, zinc pyrithione, or selenium sulfide on scalp','For face: gentle wash twice daily with mild soap','Over-the-counter antifungal cream (ketoconazole) for facial seborrheic dermatitis','Avoid harsh products and alcohol-based skin care','Manage stress — it significantly worsens the condition'], whenToSeeDoctor:'Severe, widespread, or worsening seborrheic dermatitis, involvement of the ears or eyelids, or if OTC treatments are not working after 4 weeks. Prescription antifungals and anti-inflammatories are effective.', urgency:'low' },

  { name:'Blackheads', aliases:['blackheads','open comedones','clogged pores','black spots nose','comedones'], emoji:'🔴', type:'common', description:'Small, dark spots on the skin caused by clogged hair follicles. Unlike whiteheads, they remain open at the surface and the trapped sebum oxidizes, turning dark. Part of the acne spectrum.', symptoms:['Small dark bumps on skin — usually face, nose, chin, forehead, chest, or back','Pores appear enlarged','Skin looks uneven','Not painful or tender'], causes:['Excess sebum (oil) production','Dead skin cells accumulating in pores','Hormonal changes (puberty, menstruation)','Certain cosmetics that clog pores','Sweating'], homecare:['Cleanse face twice daily with a gentle salicylic acid cleanser','Use non-comedogenic (non-pore-clogging) skincare and makeup products','Exfoliate gently 2-3 times a week (chemical exfoliant with salicylic acid or glycolic acid)','Apply retinol or adapalene at night to prevent and treat blackheads','Do not squeeze — can cause inflammation and scarring','Steam is not scientifically proven to help'], whenToSeeDoctor:'Widespread blackheads that do not respond to a consistent OTC routine after 3 months, or if accompanied by inflammatory acne. A dermatologist can prescribe retinoids or other treatments.', urgency:'low' },

  { name:'Whiteheads', aliases:['whiteheads','closed comedones','white bumps skin','milia','closed clogged pores'], emoji:'🔴', type:'common', description:'Small, white or flesh-colored bumps formed when dead skin cells, oil, and bacteria become trapped in a pore and the pore closes over the plug. Part of the acne family.', symptoms:['Small white or flesh-colored bumps on skin','Closed surface — distinguishes from blackheads','Common on forehead, nose, chin, cheeks, and around the eyes','Not typically painful unless inflamed'], causes:['Excess sebum and dead skin cell accumulation','Hormonal changes','Certain comedogenic skincare or makeup products','Diet high in dairy and high glycemic foods','Genetics'], homecare:['Cleanse with a gentle foaming cleanser twice daily','Use benzoyl peroxide gel or salicylic acid wash','Apply adapalene (retinoid) gel at night — very effective over 6-8 weeks','Use non-comedogenic products only','Do not pick or squeeze — causes scarring and hyperpigmentation'], whenToSeeDoctor:'Persistent whiteheads not responding to OTC treatment after 3 months, or if they become inflamed or pustular. Prescription retinoids or other prescription therapies may be needed.', urgency:'low' },

  { name:'Cystic Acne', aliases:['cystic acne','severe acne','deep pimples','painful acne cysts','nodular acne','acne cysts'], emoji:'🔴', type:'common', description:'The most severe form of acne, involving painful, pus-filled cysts deep in the skin. More likely to cause permanent scarring. Requires medical treatment.', symptoms:['Large, painful cysts deep under the skin','Red, swollen, and tender lumps','Pus-filled lesions that may be several centimeters wide','Most common on face, back, chest, and shoulders','Leaves scars after healing'], causes:['Same as acne — excess oil, bacteria, blocked pores','Hormonal factors play a larger role','Genetics — runs strongly in families'], homecare:['Do NOT squeeze, pop, or pick at cysts — will worsen scarring significantly','Apply ice pack for 5 minutes to reduce inflammation','Avoid touching your face','Use gentle, non-comedogenic cleanser and moisturizer','Keep hair clean and away from the face'], whenToSeeDoctor:'Cystic acne should always be evaluated by a dermatologist. It requires prescription treatment — oral antibiotics, hormonal therapy, or isotretinoin (Roaccutane). Early treatment prevents permanent scarring.', urgency:'medium' },

  { name:'Rosacea', aliases:['rosacea','facial redness','facial flushing','rosy cheeks','facial rash redness','acne rosacea'], emoji:'🔴', type:'common', description:'A common chronic skin condition causing redness and visible blood vessels in the face. May also produce acne-like breakouts. Tends to flare periodically. More common in fair-skinned women.', symptoms:['Facial redness — especially on nose, cheeks, chin, and forehead','Visible small blood vessels on nose and cheeks','Acne-like bumps and pimples','Skin that feels hot and tender','Eye irritation (redness, dryness) in some types','Enlarged nose in severe long-term cases (rhinophyma)'], causes:['Exact cause unknown','Abnormal facial blood vessel response','Demodex mite may play a role','Triggers: sunlight, heat, hot drinks, spicy food, alcohol, exercise, emotional stress'], homecare:['Identify and avoid personal triggers by keeping a diary','Always use SPF 30+ broad-spectrum sunscreen','Use gentle, fragrance-free skincare products','Cool water on face for flushing episodes','Prescribed topical metronidazole or azelaic acid (first-line)','Oral antibiotics if prescribed for papular type'], whenToSeeDoctor:'Rosacea is a chronic condition that benefits from dermatologist management. Without treatment, it tends to worsen over time. Many effective prescription treatments are available including laser therapy.', urgency:'low' },

  { name:'Melasma', aliases:['melasma','chloasma','pregnancy mask','brown patches face','facial hyperpigmentation melasma'], emoji:'🔴', type:'common', description:'A common skin condition causing brown or gray-brown patches on the face, particularly on the cheeks, bridge of the nose, forehead, and upper lip. More common in women, especially during pregnancy.', symptoms:['Brown or grayish-brown patches on face','Symmetrical patches on both sides of face','No pain or itching — only cosmetic concern','May worsen with sun exposure','Often improves after pregnancy or stopping hormonal contraception'], causes:['Sun exposure (major trigger — UV stimulates melanocytes)','Hormonal changes — pregnancy, birth control pills, hormone therapy','Family history (genetics)'], homecare:['Daily use of broad-spectrum SPF 50 sunscreen — the single most important step','Avoid direct sun during peak hours (10am-4pm)','Wear wide-brimmed hats outdoors','Azelaic acid, niacinamide, vitamin C, or kojic acid in skincare routine may help gradually fade patches','Be patient — melasma fades slowly'], whenToSeeDoctor:'For prescription treatments — hydroquinone (most effective), tretinoin, or combination creams. Chemical peels and laser treatments are available for stubborn melasma. A dermatologist can confirm the diagnosis.', urgency:'low' },

  { name:'Hyperpigmentation', aliases:['hyperpigmentation','dark spots','dark patches','post inflammatory hyperpigmentation','PIH','brown spots skin'], emoji:'🔴', type:'common', description:'Darkening of areas of the skin caused by excess melanin production. Common and usually harmless. Can occur after inflammation, sun exposure, or hormonal changes.', symptoms:['Darkened patches or spots on skin','May affect any area of the body','Usually darker than surrounding skin','No itching or pain in most cases','Can vary from small spots to large patches'], causes:['Sun exposure (sun spots or age spots)','Post-inflammatory hyperpigmentation (after acne, eczema, or skin injury)','Hormonal changes (melasma)','Addison\'s disease (adrenal insufficiency — rare)','Certain medications (antimalarials, chemotherapy drugs)'], homecare:['Daily SPF 50 broad-spectrum sunscreen — essential to prevent worsening','Vitamin C serum (reduces melanin production)','Niacinamide, kojic acid, or azelaic acid products','Alpha hydroxy acids (glycolic acid) exfoliate and improve skin turnover','Be patient — improvement takes 3-6 months'], whenToSeeDoctor:'Any rapidly growing, irregularly shaped, or raised dark spot should be evaluated to rule out skin cancer. For cosmetic concerns, a dermatologist can offer prescription treatments or procedures.', urgency:'low' },

  { name:'Dark Circles', aliases:['dark circles','dark under eyes','under eye circles','periorbital hyperpigmentation','panda eyes','dark rings under eyes'], emoji:'👁️', type:'common', description:'Darkened skin beneath both eyes. Very common and usually not a medical concern but can affect appearance and confidence. Often associated with fatigue.', symptoms:['Dark discoloration under the eyes','Puffy or swollen appearance under eyes','Sunken appearance under eyes in some cases','Skin may appear purple, blue, brown, or black depending on skin tone'], causes:['Fatigue and lack of sleep','Genetics and family history (most common cause)','Aging — skin thins and fat shifts','Allergies causing inflammation and rubbing','Dehydration','Sun exposure increasing pigmentation','Iron deficiency anemia','Prolonged screen use'], homecare:['Get 7-9 hours of quality sleep','Stay well hydrated throughout the day','Apply cold compress or chilled tea bags for 10 minutes to reduce puffiness','Use eye cream containing caffeine, vitamin C, retinol, or hyaluronic acid','Wear SPF sunscreen and sunglasses outdoors','Treat underlying allergies'], whenToSeeDoctor:'Dark circles are usually cosmetic, but sudden dark circles in an adult or circles with significant swelling may warrant evaluation to rule out allergies, anemia, or kidney issues. Cosmetic procedures are available.', urgency:'low' },

  { name:'Puffy Eyes', aliases:['puffy eyes','swollen eyes','eye puffiness','swollen eyelids','eye bags morning','periorbital edema'], emoji:'👁️', type:'common', description:'Swelling or puffiness around the eyes caused by fluid accumulation in the surrounding tissues. Usually harmless and temporary. Very common in the morning.', symptoms:['Swollen or puffy appearance around the eyes','Worse in the morning and improves throughout the day','May be accompanied by dark circles','Skin feels slightly tight or uncomfortable'], causes:['Fluid retention from sleeping flat — gravity causes fluid to pool','Lack of sleep','Crying — increased blood flow and fluid to eye area','Allergies','Salty diet causing water retention','Alcohol consumption','Aging — fat pads around eyes shift and protrude'], homecare:['Sleep with head slightly elevated','Apply cold compress — chilled spoons, cucumber slices, or cold tea bags','Reduce salt intake','Limit alcohol consumption','Stay well hydrated — dehydration causes puffiness','Antihistamines if allergy-related'], whenToSeeDoctor:'Significant, sudden, or one-sided eye swelling, puffiness with pain or vision changes, or puffy eyes associated with systemic symptoms (kidney disease, thyroid, heart issues) need medical evaluation.', urgency:'low' },

  { name:'Stretch Marks', aliases:['stretch marks','striae','stretch marks skin','striae gravidarum','stretch marks pregnancy','red lines skin'], emoji:'🔴', type:'common', description:'Narrow streaks or lines that develop on the skin surface where it has been stretched quickly. Very common during puberty, pregnancy, and rapid weight gain. Fade over time but rarely disappear completely.', symptoms:['Indented streaks or lines in skin','Pink, red, black, blue, or purple initially','Fade to a lighter or white color over time','May feel slightly itchy when forming','Common on abdomen, breasts, hips, thighs, buttocks, and upper arms'], causes:['Rapid stretching of skin during pregnancy, puberty, rapid weight gain, or muscle growth','Corticosteroid skin creams or medications','Cushing\'s syndrome (hormonal disorder)','Genetic predisposition'], homecare:['Topical retinoid cream (tretinoin) — most evidence for reducing early stretch marks','Hyaluronic acid and vitamin C products may help','Massage with moisturizing oils (coconut, almond, cocoa butter) — limited evidence but safe to try','Maintain gradual weight changes rather than rapid','Stay hydrated for skin elasticity'], whenToSeeDoctor:'Stretch marks are cosmetic and do not require medical treatment. A dermatologist can offer laser treatment, microneedling, or chemical peels to improve their appearance if desired.', urgency:'low' },

  { name:'Dry Cracked Heels', aliases:['cracked heels','dry heels','heel fissures','cracked feet','dry cracked feet'], emoji:'🦶', type:'common', description:'A very common foot problem where the skin on the heel becomes dry, hard, and cracks. Usually cosmetic but deep cracks (fissures) can be painful and become infected.', symptoms:['Dry, thickened skin on heels (callus)','Visible cracks or fissures in the skin','Pain when standing or walking in severe cases','Itching or bleeding from deep cracks','Skin may look yellowish-brown'], causes:['Dry skin (most common)','Prolonged standing on hard floors','Obesity — extra pressure on heel fat pad causes it to spread','Open-backed shoes or sandals','Deficiencies of zinc, omega-3, or vitamins','Skin conditions (eczema, psoriasis, athlete\'s foot)','Diabetes — can reduce sensation and sweat production'], homecare:['Soak feet in warm water for 10-15 minutes','Use a pumice stone or foot file to gently remove dead skin after soaking','Apply thick heel cream containing urea, salicylic acid, or lactic acid','Cover with socks overnight to seal in moisture','Wear supportive, closed-back shoes','Drink adequate water'], whenToSeeDoctor:'Deep painful fissures that bleed or show signs of infection, or if you have diabetes or peripheral vascular disease (foot infections in these conditions can be serious).', urgency:'low' },

  { name:'Chapped Lips', aliases:['chapped lips','dry lips','cracked lips','lip dryness','cheilitis','peeling lips'], emoji:'🦷', type:'common', description:'Dry, cracked, sore lips. Extremely common, especially in cold and dry weather or with dehydration. Usually easily treated with regular moisturizing.', symptoms:['Dryness and flaking of lip skin','Cracks or sores','Redness','Peeling','Tenderness or pain especially when eating or speaking','Urge to lick lips (worsens the problem)'], causes:['Cold, dry, or windy weather','Dehydration','Breathing through the mouth','Licking lips (saliva evaporates and causes more dryness)','Deficiency of B vitamins or iron','Certain medications (isotretinoin, chemotherapy)','Sun exposure'], homecare:['Apply fragrance-free lip balm with petrolatum, sheeabutter, or dimethicone frequently throughout the day','Never lick the lips — it makes them drier','Stay well hydrated — drink adequate water','Apply lip balm with SPF 30+ outdoors','Breathe through the nose','Vitamin E oil at night on lips'], whenToSeeDoctor:'Persistent chapping not responding to regular moisturizing, severe cracking at the corners of the mouth (angular cheilitis), or lips that are swollen and very painful — may need treatment for vitamin deficiency or infection.', urgency:'low' },

  { name:'Moles', aliases:['moles','naevus','skin mole','brown spots body','pigmented lesion','naevi'], emoji:'🔴', type:'common', description:'Common pigmented spots on the skin composed of a cluster of pigmented cells. Most moles are harmless but changes in size, shape, or color can indicate melanoma (skin cancer).', symptoms:['Uniformly colored brown, black, or tan spot','Round or oval shape','Smooth or slightly raised','Usually smaller than 6mm','May have hair growing from them','Most appear in childhood and adolescence'], causes:['Cluster of melanocytes (pigment cells)','Sun exposure increases number of moles','Genetics'], homecare:['Self-examine moles monthly using the ABCDE rule','A — Asymmetry (not same shape on both halves)','B — Border irregular or ragged','C — Color variation within the mole','D — Diameter greater than 6mm','E — Evolving or changing','Use sunscreen to prevent new moles','Avoid excess sun exposure'], whenToSeeDoctor:'Any mole that is new, changing, irregular, bleeding, itching, or meets any ABCDE criteria must be evaluated urgently by a doctor. Annual skin check is recommended for those with many moles or family history of melanoma.', urgency:'medium' },

  { name:'Skin Tags', aliases:['skin tags','acrochordons','skin growth','fleshy skin growth','soft skin lump','tag on skin'], emoji:'🔴', type:'common', description:'Small, soft, benign growths that hang off the skin and look like pieces of hanging skin. Very common and completely harmless. Often appear in skin folds.', symptoms:['Small, soft, flesh-colored or slightly darker hanging growths','Usually found on neck, armpits, eyelids, groin folds, and under breasts','Range from 1-5mm typically but can be larger','Painless unless twisted or irritated by clothing or jewelry'], causes:['Friction — skin rubbing against skin or clothing','Obesity — more skin folds','Pregnancy hormones','Diabetes','Genetics'], homecare:['No treatment needed if not bothersome','Avoid catching on jewelry or clothing by wearing looser clothes or smooth fabrics','Do NOT attempt to remove skin tags at home with string or scissors — risk of bleeding and infection'], whenToSeeDoctor:'If a skin tag is irritated, bleeds, or for cosmetic removal. A doctor can remove skin tags safely by freezing, burning, cutting, or tying. Any skin growth that is uncertain should be examined by a doctor.', urgency:'low' },

  { name:'Ingrown Hair', aliases:['ingrown hair','razor bumps','pseudofolliculitis','hair growing back into skin','ingrown hair bumps'], emoji:'🔴', type:'common', description:'A hair that curls back or grows sideways into the skin instead of rising from the follicle. Causes a raised, red, often itchy bump. Common after shaving, waxing, or tweezing.', symptoms:['Small, round bumps (papules) after shaving or waxing','Itching and discomfort','Redness around the bump','Pus-filled blisters','Darkened skin over time (hyperpigmentation)','Embedded hair visible under skin'], causes:['Shaving too closely, shaving dry, or using a blunt blade','Naturally curly hair is more prone to ingrowth','Waxing, threading, or tweezing','Tight clothing trapping and bending hairs'], homecare:['Exfoliate gently before shaving with a scrub or exfoliating glove','Shave with the grain (direction of hair growth)','Use a sharp single-blade razor and shaving gel or cream','Apply warm compress to soften the area','Do not pick or squeeze — releases pus but spreads infection','Use an ingrown hair serum with salicylic acid or glycolic acid'], whenToSeeDoctor:'Infected ingrown hair with pus, large painful ingrown hair requiring release, or if ingrown hairs are very frequent and causing scarring — a doctor can release the hair or recommend other hair removal methods.', urgency:'low' },

  { name:'Razor Burn', aliases:['razor burn','shaving rash','razor rash','post-shave irritation','red skin after shaving'], emoji:'🔴', type:'common', description:'Skin irritation that occurs immediately after shaving. Causes redness, burning, and itching in the shaved area. Very common and usually resolves within a day or two.', symptoms:['Redness and irritation immediately after shaving','Burning or stinging sensation','Small red bumps or pustules','Itching','Tenderness of the skin in the shaved area'], causes:['Dry shaving without lubricant','Shaving against the direction of hair growth','Using a dull or dirty razor blade','Sensitive skin','Shaving too closely or repeatedly going over the same area'], homecare:['Apply a cool compress immediately after shaving to soothe irritation','Use aloe vera gel or aftershave balm (fragrance-free)','Avoid shaving again until the irritation resolves','Apply OTC hydrocortisone cream for persistent redness and itch','Exfoliate before shaving next time','Use fresh, sharp razor blades'], whenToSeeDoctor:'Razor burn persisting for more than a week, very widespread, or showing signs of infection (spreading redness, pus, fever). Persistent razor bumps especially in African and Asian men may be folliculitis requiring medical treatment.', urgency:'low' },

  { name:'Folliculitis', aliases:['folliculitis','infected hair follicles','hot tub rash','hair follicle infection','pus bumps skin'], emoji:'🔴', type:'common', description:'Inflammation of hair follicles, usually caused by a bacterial or fungal infection. Causes clusters of small red or pus-filled bumps. Common and usually not serious.', symptoms:['Clusters of small red bumps or white-headed pimples around hair follicles','Pus-filled blisters that break open','Itching, burning, and tenderness','Inflamed, red skin around the bumps','May spread if scratched'], causes:['Staphylococcus aureus bacteria (most common)','Shaving, waxing, or wearing tight clothing','Hot tub use without adequate chlorination (hot tub folliculitis — Pseudomonas)','Fungal infection in warm climates','Blocked follicles from oils or makeup'], homecare:['Warm compress on affected area 3-4 times daily to soothe and promote drainage','Keep the area clean with antibacterial soap','OTC antibiotic cream (mupirocin) for mild bacterial folliculitis','OTC antifungal cream for fungal type','Wear loose-fitting breathable clothing','Avoid shaving affected areas until healed'], whenToSeeDoctor:'Widespread folliculitis, deep or recurring infections, fungal folliculitis, or infection spreading. Oral antibiotics or antifungals may be needed for moderate-to-severe cases.', urgency:'low' },

  { name:'Keloid Scar', aliases:['keloid','keloid scar','raised scar','overgrown scar','keloid formation'], emoji:'🔴', type:'common', description:'A raised, overgrown scar that extends beyond the original wound boundary. Caused by excessive collagen production during healing. More common in people with darker skin tones.', symptoms:['Raised, firm, rubbery scar tissue','Grows beyond the original wound boundaries','May be pink, red, or purple initially, then darker','Itching, tenderness, or pain','Continues to grow slowly over months'], causes:['Genetic predisposition — common in people with darker skin','Skin injuries — cuts, piercings, surgical incisions, acne, burns','Chest, earlobes, shoulders, and cheeks are most susceptible areas'], homecare:['Silicone gel sheets or silicone gel applied daily to flatten the scar','Compression garments over the scar area','Avoid further injury to keloid-prone skin areas','Avoid unnecessary piercings or tattoos if you have a history of keloids','Massage with moisturizer daily'], whenToSeeDoctor:'For treatment options — steroid injections (most effective first-line treatment), cryotherapy, laser therapy, radiation after surgical removal, or surgical excision. Combination treatment gives best results.', urgency:'low' },

  { name:'Hypertrophic Scar', aliases:['hypertrophic scar','raised scar healing','thick scar','red raised scar','prominent scar'], emoji:'🔴', type:'common', description:'A raised scar that stays within the boundaries of the original wound. Unlike keloids, hypertrophic scars often improve over time without treatment. Caused by excessive scar tissue formation.', symptoms:['Raised, firm scar tissue within the wound margin','Red, pink, or purple coloring initially','May be itchy or slightly painful','Tends to improve and flatten over 1-2 years','More common on areas of tension — shoulders, chest, knees'], causes:['Natural variation in wound healing response','Wounds on areas of high skin tension','Deep wounds, burns, or surgical incisions','Infection during wound healing delays normal healing'], homecare:['Silicone gel sheets applied daily for several months — most evidence-based OTC option','Massage the scar gently with moisturizer 2-3 times daily once wound is closed','Keep the wound moist during initial healing with petroleum jelly','Protect the scar from sun — UV darkens scars','OTC scar creams containing onion extract may provide mild benefit'], whenToSeeDoctor:'Scars causing significant cosmetic concern, restricting movement, or not improving after a year. Options include steroid injections, laser therapy, and surgical revision.', urgency:'low' },

  { name:'Acne Scar', aliases:['acne scar','acne scarring','pitted skin acne','post acne marks','acne marks','icepick scars'], emoji:'🔴', type:'common', description:'Permanent or long-lasting marks left on the skin after acne heals. Can be depressed (pitted) or raised. Very common — affects about 20% of people with acne.', symptoms:['Depressed pits or indentations in skin (icepick, boxcar, or rolling scars)','Raised or thickened scars (hypertrophic or keloid)','Dark or red post-inflammatory marks (technically discoloration not scars)','Uneven skin texture'], causes:['Inflammatory acne that damages deeper skin layers','Picking or squeezing acne lesions (major cause of scars)','Severe or cystic acne','Delayed treatment of acne'], homecare:['Never pick or squeeze acne — the most important prevention measure','Use retinoids (adapalene, tretinoin) to improve skin turnover and reduce scars over time','Vitamin C serum brightens post-inflammatory hyperpigmentation','Alpha hydroxy acids (AHAs) improve skin texture and color','Daily SPF sunscreen — sun exposure darkens marks significantly','Be patient — improvement takes many months'], whenToSeeDoctor:'Significant scarring affecting confidence or quality of life. Dermatologists can offer microneedling, chemical peels, laser resurfacing, dermal fillers, or subcision for depressed scars with excellent results.', urgency:'low' },

  { name:'Pitted Skin', aliases:['pitted skin','skin pitting','pockmarks','pitted face','divots in skin','depressed scars'], emoji:'🔴', type:'common', description:'Small depressions or indentations in the skin surface. Most commonly caused by acne scars, chickenpox scars, or enlarged pores. Can also be associated with certain skin conditions.', symptoms:['Small round or irregular depressions in skin','Most common on face','Uneven skin texture','May vary in size and depth'], causes:['Acne scarring (most common)','Chickenpox scars','Enlarged or stretched pores from oily skin or sun damage','Certain skin conditions (pitted keratolysis on feet from bacterial infection)'], homecare:['Retinoids stimulate collagen production and may improve mild pitting over months','Chemical exfoliants (AHAs, BHAs) improve skin texture gradually','Sunscreen prevents worsening from UV exposure','Collagen-stimulating ingredients: vitamin C, peptides, niacinamide','Results from home care are limited for established pitting'], whenToSeeDoctor:'Significant pitted skin causing distress — a dermatologist can offer microneedling, fractional laser, radiofrequency, chemical peels, or fillers which give significant improvement.', urgency:'low' },

  { name:'Uneven Skin Tone', aliases:['uneven skin tone','skin discoloration','patchy skin','blotchy skin','uneven complexion','skin pigmentation uneven'], emoji:'🔴', type:'common', description:'Variation in skin color across the face or body. Extremely common and usually caused by sun damage, post-inflammatory hyperpigmentation, or hormonal changes. Not medically dangerous but a common cosmetic concern.', symptoms:['Areas of darker or lighter skin compared to surrounding skin','Blotchiness or patchiness in skin color','May affect face, hands, neck, or body','No pain or itching in most cases'], causes:['Sun exposure causing uneven melanin distribution','Post-inflammatory hyperpigmentation after acne or inflammation','Melasma from hormonal changes','Aging (liver spots or age spots)','Scarring'], homecare:['Consistent daily use of SPF 50 broad-spectrum sunscreen — most important step','Vitamin C serum in the morning — brightens and protects','Niacinamide — reduces melanin transfer and brightens skin over time','Alpha arbutin or kojic acid to reduce pigmentation','Exfoliate regularly with glycolic or lactic acid products','Avoid sun without sunscreen'], whenToSeeDoctor:'For prescription treatments (hydroquinone, tretinoin) or in-office procedures (chemical peels, laser). Rule out underlying medical causes of pigment changes such as Addison\'s disease.', urgency:'low' },

  { name:'Age Spots', aliases:['age spots','liver spots','solar lentigines','sunspots','brown spots aging','flat brown spots'], emoji:'🔴', type:'common', description:'Flat, brown, or black spots on the skin caused by years of sun exposure. Very common in people over 50. Harmless but can resemble melanoma and should be checked if uncertain.', symptoms:['Flat, oval areas of increased pigmentation','Tan to dark brown color','Found on sun-exposed areas — hands, face, shoulders, arms, and top of feet','No pain or itching','Range in size from a freckle to about 13mm'], causes:['Decades of cumulative UV light exposure causing melanin overproduction','Aging reduces the skin\'s ability to distribute melanin evenly'], homecare:['Daily SPF 50 sunscreen on exposed areas prevents new spots and darkening of existing ones','Vitamin C serum, niacinamide, or glycolic acid may gradually fade spots over months','Wear protective clothing and hats outdoors','Retinoids (retinol or tretinoin) promote cell turnover and fade spots'], whenToSeeDoctor:'Have a doctor check any new spots or spots that are growing, changing color, have irregular borders, or multiple colors — these features can indicate melanoma. For cosmetic removal, options include laser, cryotherapy, and chemical peels.', urgency:'low' },

  { name:'Body Odor', aliases:['body odor','body odour','smelly body','BO','underarm odor','armpit smell'], emoji:'💧', type:'common', description:'Unpleasant smell from the body, particularly from armpits, feet, and groin. Caused by bacteria breaking down sweat. Very common and usually managed with hygiene measures.', symptoms:['Unpleasant smell from underarms, feet, groin, or other areas','Odor worsens with physical activity, stress, or heat','Can affect social confidence'], causes:['Bacteria on skin breaking down sweat secretions (apocrine sweat glands)','Apocrine glands become active at puberty','Diet — certain foods (garlic, onion, spices, alcohol, meat)','Poor hygiene','Hyperhidrosis (excessive sweating)','Medical conditions (diabetes, liver disease, trimethylaminuria — rare)'], homecare:['Shower daily, especially after sweating','Apply antiperspirant-deodorant to dry underarm skin (antiperspirant reduces sweat, deodorant masks smell)','Wear natural breathable fabrics (cotton, linen) rather than synthetics','Wash clothes after every wear','Trim underarm and pubic hair to reduce bacteria-trapping surface area','Reduce consumption of trigger foods'], whenToSeeDoctor:'Significant body odor not responding to hygiene measures may warrant evaluation for hyperhidrosis, dietary causes, or rare metabolic conditions. Strong prescription antiperspirants are available.', urgency:'low' },

  { name:'Intertrigo', aliases:['intertrigo','skin fold rash','rash between skin folds','skin fold infection','intertriginous dermatitis'], emoji:'🔴', type:'common', description:'A rash occurring in moist, warm skin folds where skin rubs against skin. Common in people who are overweight, in hot climates, or those with diabetes. Can become infected with bacteria or fungi.', symptoms:['Red, raw, or moist rash in skin folds','Common in armpits, under breasts, groin, between toes, under belly fold, and inner thighs','Itching, burning, or stinging','Unpleasant smell if infected','Cracking and oozing in severe cases'], causes:['Friction between skin surfaces in folds','Heat and moisture trapped between skin folds','Obesity — creates deeper skin folds','Diabetes — impairs skin healing and immunity','Hot climate or excessive sweating'], homecare:['Keep skin folds clean and dry — pat dry thoroughly after washing','Apply antifungal powder or zinc oxide paste to affected area','Wear loose, breathable cotton clothing','Keep folds separated if possible — cotton cloth strips can help','Treat underlying fungal infection with antifungal cream if present','Lose weight if excess weight is contributing'], whenToSeeDoctor:'Rash not improving with home care after a week, signs of bacterial or fungal infection (increasing redness, pus, odor), or severe painful rash. Prescription antifungal or antibiotic treatment may be needed.', urgency:'low' },

  { name:'Diaper Rash', aliases:['diaper rash','nappy rash','nappy rash infant','diaper dermatitis','baby bottom rash'], emoji:'🔴', type:'common', description:'A common form of inflamed skin (dermatitis) affecting a baby\'s diaper area. Appears as a patchwork of bright red skin on the baby\'s bottom. Usually clears up with simple home treatments.', symptoms:['Inflamed, red skin in the diaper area','Skin appears puffy and tender to touch','Baby may seem more uncomfortable than usual, especially during diaper changes','Skin may be warm to touch'], causes:['Prolonged exposure to wet or soiled diapers','Friction from diaper rubbing','Reaction to a new product (wipes, diapers, soap)','Introduction of new foods or formula (changes stool)','Antibiotic use causing yeast overgrowth','Bacterial or fungal infection'], homecare:['Change diapers as soon as soiled — frequent changes are the most important step','Gently clean the area with warm water and a soft cloth','Let the baby\'s bottom air-dry before putting on a new diaper','Apply thick barrier cream (zinc oxide paste) at each diaper change','Leave the diaper off for a period each day to air the skin','Avoid scented wipes or harsh soaps'], whenToSeeDoctor:'Rash with bright red spots or satellite spots beyond the main rash (yeast infection), blistering, open sores, fever, or rash not improving after 3-4 days of home treatment. Antifungal or antibiotic cream may be needed.', urgency:'low' },

  /* ── COMMON: DIGESTIVE ── */
  { name:'Belching', aliases:['belching','burping','eructation','excessive burping','bloating burp','belch'], emoji:'😮', type:'common', description:'Releasing air or gas from the stomach through the mouth, often with a sound. Very common and usually a normal bodily function. Excessive belching can be caused by swallowing too much air.', symptoms:['Releasing gas through the mouth','Repetitive belching','Bloating and abdominal discomfort','Rumbling sounds in stomach'], causes:['Swallowing air while eating or drinking too fast','Carbonated beverages','Chewing gum or sucking on hard candy','Anxiety causing air swallowing','Gastroesophageal reflux disease (GERD)','Gastritis or peptic ulcer','Certain foods (onions, garlic, high-fat foods)'], homecare:['Eat and drink slowly — take smaller bites','Avoid carbonated drinks, chewing gum, and hard candy','Avoid drinking through straws','Do not lie down immediately after eating','Avoid gas-producing foods if belching is excessive','Antacids if related to GERD'], whenToSeeDoctor:'Excessive belching accompanied by severe bloating, persistent abdominal pain, nausea, or heartburn may indicate an underlying GI condition like GERD or gastritis needing evaluation.', urgency:'low' },

  { name:'Excessive Gas', aliases:['excessive gas','flatulence','farting','intestinal gas','bloating gas','wind stomach'], emoji:'😮', type:'common', description:'Producing more intestinal gas than normal, leading to frequent passing of gas and abdominal bloating. Passing gas 14-23 times a day is considered normal. Primarily caused by diet and gut bacteria.', symptoms:['Frequent passing of gas (flatulence)','Bloating and abdominal distension','Abdominal cramping or discomfort','Sounds from the abdomen'], causes:['High-fiber foods — beans, lentils, cabbage, onions, broccoli','Lactose intolerance','Swallowing air while eating or drinking fast','Carbonated drinks','Irritable bowel syndrome','Changes in gut bacteria','Constipation'], homecare:['Identify and reduce gas-producing foods','Eat and drink slowly','Avoid carbonated drinks and chewing gum','OTC simethicone drops or tablets for gas pain relief','Beano enzyme supplement before high-fiber meals','Regular physical activity helps move gas through the digestive tract','Probiotics may improve gut bacteria balance'], whenToSeeDoctor:'Significant increase in gas with weight loss, blood in stool, severe pain, or a sudden change in bowel habits. These symptoms warrant evaluation for inflammatory bowel disease, malabsorption, or other conditions.', urgency:'low' },

  { name:'Stomach Gurgling', aliases:['stomach gurgling','stomach noises','borborygmi','rumbling stomach','stomach rumbling','tummy noises'], emoji:'😮', type:'common', description:'The rumbling or gurgling sounds produced by the movement of fluid and gas through the intestines. Medically called borborygmi. Usually normal and not a cause for concern.', symptoms:['Audible rumbling or gurgling sounds from abdomen','May be loud enough for others to hear','Can be accompanied by mild cramping or bloating','Often worse when hungry or after eating'], causes:['Normal intestinal motility (most common — the intestines are always moving)','Hunger — increased intestinal activity when empty','After eating — digestion stimulates movement','Gas and fluid moving through the intestines','Anxiety — gut is sensitive to stress'], homecare:['Eat regular small meals to prevent gurgling from hunger','Eat slowly and chew food thoroughly','Avoid foods that cause excess gas (beans, carbonated drinks, cruciferous vegetables)','Stay well hydrated','Manage stress with relaxation techniques'], whenToSeeDoctor:'Stomach gurgling with pain, significant bloating, change in bowel habits, diarrhea, blood in stool, or unexplained weight loss — these associated symptoms need evaluation.', urgency:'low' },

  { name:'Loss of Appetite', aliases:['loss of appetite','no appetite','poor appetite','not wanting to eat','anorexia','reduced appetite'], emoji:'🍽️', type:'common', description:'A decreased desire to eat. Can be temporary from illness or stress, or persistent indicating an underlying condition. Not the same as the eating disorder anorexia nervosa.', symptoms:['Little or no interest in eating','Eating much less than usual','Not feeling hungry at normal mealtimes','Unintentional weight loss if prolonged','Nausea at the thought of food'], causes:['Acute illness (infection, cold, flu) — most common temporary cause','Medications (antibiotics, cancer treatments, many others)','Psychological — depression, anxiety, grief, stress','Chronic conditions — cancer, kidney failure, heart failure, liver disease','Pregnancy (first trimester nausea)','Aging reduces appetite naturally'], homecare:['Eat small, frequent meals rather than three large ones','Choose nutrient-dense, appealing foods','Eat with others when possible — social eating stimulates appetite','Light physical activity before meals can stimulate appetite','Address stress, anxiety, or depression','Treat nausea with ginger tea if that is suppressing appetite'], whenToSeeDoctor:'Loss of appetite lasting more than 2 weeks, with significant weight loss, in an elderly person, accompanied by other symptoms (pain, fatigue, fever), or after starting a new medication.', urgency:'medium' },

  { name:'Difficulty Swallowing', aliases:['difficulty swallowing','dysphagia','trouble swallowing','food sticking throat','painful swallowing','swallowing difficulty'], emoji:'🗣️', type:'common', description:'Difficulty or discomfort when swallowing food or liquid. Can affect any age. Ranges from mild (food taking longer to go down) to severe (unable to swallow at all).', symptoms:['Feeling that food is sticking in throat or chest','Pain when swallowing','Drooling or inability to control saliva','Coughing or choking when eating or drinking','Bringing food or liquid back up','Unexpected weight loss from avoiding eating'], causes:['Esophageal conditions — GERD, stricture, esophagitis','Neurological causes — stroke, Parkinson\'s, multiple sclerosis','Throat infection or tonsillitis','Foreign body stuck in throat','Thyroid goiter pressing on esophagus','Cancer of the throat or esophagus (serious)'], homecare:['Eat small pieces and chew thoroughly','Sit upright while eating and for 30 minutes after','Eat softer foods if solids are difficult','Take small sips of liquid with food','Do not rush eating — take your time'], whenToSeeDoctor:'Any new or progressive difficulty swallowing should be evaluated by a doctor. Sudden swallowing difficulty with chest pain or loss of voice is an emergency. Unexplained dysphagia especially in older adults needs prompt investigation.', urgency:'medium' },

  { name:'Globus Sensation', aliases:['globus sensation','lump in throat feeling','something stuck in throat','globus pharyngeus','throat tightness feeling','knot in throat'], emoji:'🗣️', type:'common', description:'A persistent sensation of having something stuck in the throat — a lump or tightening — when nothing is actually there. Very common and almost always benign. Often worsens with stress.', symptoms:['Constant or intermittent feeling of lump or tightness in throat','Sensation that does not interfere with swallowing (food goes down normally)','Worsens with stress and anxiety','May improve when eating','Dry throat feeling'], causes:['Acid reflux (GERD) irritating throat — most common cause','Anxiety and stress','Post-nasal drip','Muscle tension in throat','Thyroid disorders','Rarely: an actual mass in the throat'], homecare:['Manage acid reflux — avoid trigger foods, elevate head, avoid eating before bed','Stress management — the sensation often worsens with anxiety','Stay hydrated — dry throat worsens the sensation','Swallowing frequently does not help and may worsen it — try to ignore the sensation','Address anxiety with relaxation techniques'], whenToSeeDoctor:'Globus sensation should be evaluated to rule out structural causes, especially if you also have difficulty swallowing, weight loss, hoarseness, or if the sensation is worsening. ENT examination is usually normal.', urgency:'low' },

  { name:'Waterbrash', aliases:['waterbrash','acid water in mouth','sudden saliva flood','hypersalivation acid reflux','water brash'], emoji:'😮', type:'common', description:'A sudden flood of watery, slightly acidic saliva in the mouth, often accompanying heartburn. The body\'s reflex to protect the esophagus from acid. A classic symptom of GERD.', symptoms:['Sudden filling of the mouth with watery saliva','Usually accompanies heartburn or acid reflux','Slightly acidic or bitter taste','May cause nausea','Often happens after meals or when lying down'], causes:['Gastroesophageal reflux disease (GERD) — the most common cause','Peptic ulcer disease','Esophagitis'], homecare:['Treat the underlying GERD — antacids or H2 blockers (OTC)','Avoid trigger foods — fatty foods, coffee, alcohol, chocolate, tomatoes, spicy food','Do not eat within 3 hours of lying down','Elevate the head of the bed by 6-8 inches','Maintain a healthy weight'], whenToSeeDoctor:'Waterbrash with frequent heartburn should be evaluated and treated as GERD. If not responding to OTC antacids or if frequent, see a doctor for further testing and prescription medication.', urgency:'low' },

  { name:'Bitter Taste in Mouth', aliases:['bitter taste in mouth','bad taste in mouth','metallic taste','persistent bitter taste','taste disturbance bitter'], emoji:'🦷', type:'common', description:'A persistent bitter, sour, or bad taste in the mouth not related to food. Common and usually related to acid reflux, medications, or oral hygiene issues.', symptoms:['Bitter, sour, or unpleasant taste in the mouth','Persists between meals or upon waking','May be accompanied by heartburn or reflux','Can affect enjoyment of food and drinks'], causes:['Acid reflux or GERD (most common)','Poor oral hygiene or gum disease','Certain medications (antibiotics, metformin, some supplements)','Dry mouth reducing saliva flow','Respiratory or sinus infections','Zinc or B12 deficiency'], homecare:['Treat GERD with antacids if relevant','Brush teeth, tongue, and gums thoroughly twice daily and floss daily','Drink adequate water throughout the day','Chew sugar-free gum to stimulate saliva','Check medication side effects — some cause bitter taste','Rinse with diluted baking soda solution to neutralize acidity in mouth'], whenToSeeDoctor:'Persistent bitter taste lasting more than 2 weeks, especially without an obvious cause, warrants evaluation. Can be a sign of GERD, dental disease, or rarely a neurological issue.', urgency:'low' },

  { name:'Metallic Taste', aliases:['metallic taste','metal taste in mouth','dysgeusia','taste of metal in mouth','iron taste mouth'], emoji:'🦷', type:'common', description:'An unusual metallic, blood-like, or chemical taste in the mouth. Can be very distressing and affect appetite. Has many causes ranging from medications to pregnancy.', symptoms:['Persistent metallic or blood-like taste in mouth','May worsen with eating','Affects ability to taste food normally','May be accompanied by dry mouth or altered smell'], causes:['Medications — antibiotics, metronidazole, metformin, blood pressure medications, antidepressants','Pregnancy (first trimester — hormonal)','Vitamin or mineral supplements (iron, zinc, multivitamins)','Poor oral hygiene','Dental issues — fillings, crowns','Zinc or B12 deficiency or excess','Head injury or neurological conditions'], homecare:['Maintain good oral hygiene — brush teeth and tongue thoroughly','Drink water with a slice of lemon (helps neutralize metallic taste)','Use plastic cutlery if metal cutlery worsens the taste','Marinate meats and use strong flavors to mask the taste during meals','Review medications with doctor if recently started a new one'], whenToSeeDoctor:'Persistent metallic taste not related to medications or pregnancy, associated with other neurological or systemic symptoms, or significantly affecting nutrition and weight.', urgency:'low' },

  { name:'Swollen Tongue', aliases:['swollen tongue','tongue swelling','macroglossia','tongue enlargement','puffy tongue'], emoji:'🦷', type:'common', description:'An enlarged or swollen tongue. Sudden swelling is a medical emergency. Gradual swelling has many possible causes. The tongue can swell from allergic reactions, infections, or systemic disease.', symptoms:['Tongue appears enlarged or puffy','Difficulty speaking, swallowing, or breathing in severe cases','Pain or tenderness in the tongue','Color change (red, pale, or white patches)','Bumpy or smooth abnormal surface'], causes:['Allergic reaction (most serious — can obstruct airway)','Angioedema','Tongue infection','Trauma or injury to the tongue','Hypothyroidism','Acromegaly','Side effect of medications (ACE inhibitors — very important cause)'], homecare:['Antihistamines for mild allergic swelling','Cold compress to the area for minor trauma','Do not apply anything to the tongue without medical advice'], whenToSeeDoctor:'Sudden or rapidly progressing tongue swelling is a medical emergency — call an ambulance immediately as it can obstruct the airway. Any gradual tongue swelling should be evaluated to identify the cause.', urgency:'high' },

  { name:'Geographic Tongue', aliases:['geographic tongue','benign migratory glossitis','map tongue','smooth patches tongue','tongue patches'], emoji:'🦷', type:'common', description:'A condition where smooth, red, irregularly shaped patches appear on the tongue surface, surrounded by white or light-colored borders. The patches migrate, giving a map-like appearance. Benign and usually harmless.', symptoms:['Irregular, smooth red patches on the tongue surface','White or slightly raised border around patches','Patches change location and shape over days or weeks','Usually painless but some people have mild sensitivity or burning','May be worsened by spicy, hot, or acidic foods'], causes:['Exact cause unknown','Genetic factors — often runs in families','May be associated with psoriasis','Nutritional deficiencies (B12, zinc, iron) in some cases','Stress may trigger flares'], homecare:['Usually no treatment needed — the condition is benign and self-limiting','Avoid spicy, acidic, or very hot foods if they cause discomfort','Good oral hygiene','Zinc or B vitamin supplement if deficiency suspected','Over-the-counter oral anesthetic gel for discomfort during flares'], whenToSeeDoctor:'First occurrence should be assessed by a dentist or doctor to confirm the diagnosis. See a doctor if discomfort is significant or if patches are persistent and not migrating.', urgency:'low' },

  { name:'Burning Tongue', aliases:['burning tongue','burning mouth syndrome','tongue burning','mouth burning sensation','glossodynia'], emoji:'🦷', type:'common', description:'A burning sensation in the mouth — most commonly the tongue, but also lips, gums, palate, or throat. Can be constant or intermittent. More common in postmenopausal women.', symptoms:['Burning or scalding sensation in the mouth and tongue','May be worse in the evening and better in the morning','Dry mouth or increased thirst','Altered taste (metallic or bitter)','Numbness or tingling of tongue','Symptoms often improve when eating or drinking'], causes:['Hormonal changes — menopause (most common in women)','Nutritional deficiencies — B12, folate, iron, zinc','Dry mouth from medications','Oral candidiasis (thrush)','Acid reflux irritating mouth','Ill-fitting dentures','Anxiety or depression'], homecare:['Sip cold water frequently throughout the day','Suck on ice chips for immediate relief','Identify and avoid trigger foods — acidic, spicy, hot foods','Good oral hygiene with gentle toothpaste (avoid cinnamon or mint if irritating)','B12, iron, or zinc supplements if deficient','Treat dry mouth — sugar-free gum, sip water regularly'], whenToSeeDoctor:'Persistent burning mouth should be evaluated to rule out B12 deficiency, thyroid disease, oral candidiasis, or other treatable causes. Treatment can significantly improve quality of life.', urgency:'low' },

  { name:'Gum Recession', aliases:['gum recession','receding gums','gums pulling back','exposed tooth root','gum line lowering'], emoji:'🦷', type:'common', description:'The process where the gum tissue that surrounds the teeth wears away or pulls back, exposing more of the tooth or its root. Can lead to tooth sensitivity and eventually tooth loss.', symptoms:['Teeth appear longer than they used to','Exposed yellowish tooth root visible','Tooth sensitivity — especially to hot, cold, or sweet','Gaps or spaces appear between teeth','Bad breath','Loose teeth in advanced cases'], causes:['Gum disease (periodontal disease) — most common cause','Brushing too hard with a hard toothbrush (abrasion)','Genetics — some people are naturally predisposed','Teeth grinding (bruxism)','Piercings in the lip or tongue rubbing on gums','Misaligned bite'], homecare:['Switch to a soft-bristled toothbrush immediately','Brush gently in small circular motions — not back and forth scrubbing','Floss gently daily','Use a sensitivity toothpaste for root exposure pain','Address teeth grinding with a night guard','Professional cleaning to remove tartar is essential'], whenToSeeDoctor:'Any noticed gum recession should be evaluated by a dentist. Once gum recession occurs, it cannot be reversed without surgery. A periodontist can offer gum graft surgery to restore coverage.', urgency:'medium' },

  { name:'Dry Socket', aliases:['dry socket','alveolar osteitis','painful tooth extraction','dry socket after tooth removal','tooth socket pain'], emoji:'🦷', type:'common', description:'A painful condition that can occur after a permanent adult tooth is extracted. The blood clot that forms in the empty socket to protect underlying bone and nerves is dislodged or dissolves before the socket heals.', symptoms:['Severe, throbbing pain 2-4 days after tooth extraction','Pain radiating from socket to ear, eye, or temple','Empty-looking socket where clot should be','Visible bone in the socket','Unpleasant taste or smell from the socket'], causes:['Sucking through a straw after extraction','Smoking (most significant risk factor)','Poor oral hygiene after extraction','Excessive spitting or rinsing after extraction','Oral contraceptive use','Trauma during the extraction'], homecare:['Do NOT smoke for at least 72 hours after extraction','Do not use straws — only drink directly from a glass','Avoid spitting forcefully or vigorous rinsing for 24 hours','Eat soft foods and avoid the extraction site when chewing','After 24 hours, gently rinse with warm salt water after meals','OTC pain relievers for discomfort while waiting for dental care'], whenToSeeDoctor:'Dry socket always requires dental treatment — the dentist will clean the socket and apply a medicated dressing that relieves pain significantly. This usually needs to be changed every 1-3 days until healing occurs.', urgency:'medium' },

  /* ── COMMON: MUSCULOSKELETAL ── */
  { name:'Morning Stiffness', aliases:['morning stiffness','stiff when waking','joint stiffness morning','stiffness after rest','getting up stiff'], emoji:'🦴', type:'common', description:'Stiffness and reduced joint mobility experienced upon waking or after periods of inactivity. Very common with aging and inflammatory arthritis. Usually improves with movement.', symptoms:['Joint stiffness when first waking up','Difficulty moving joints first thing in the morning','Stiffness lasting from minutes (osteoarthritis) to hours (rheumatoid arthritis)','Improves with gentle movement and warming up','Commonly affects hands, knees, hips, and spine'], causes:['Osteoarthritis — stiffness typically lasts less than 30 minutes','Rheumatoid arthritis — stiffness lasts more than 45 minutes (morning stiffness is a diagnostic feature)','Fibromyalgia','Inactivity during sleep causing joints and muscles to stiffen'], homecare:['Gentle morning stretching exercises before getting out of bed','Warm shower in the morning to loosen joints and muscles','Apply heat to stiff joints before and after exercise','Light physical activity daily — walking, swimming, or cycling maintain joint mobility','Anti-inflammatory diet rich in omega-3 fatty acids','Maintain a healthy weight to reduce joint load'], whenToSeeDoctor:'Morning stiffness lasting more than 45-60 minutes, stiffness affecting ability to perform daily activities, or accompanied by swelling, warmth, or redness of joints — these features suggest inflammatory arthritis needing evaluation.', urgency:'medium' },

  { name:'Joint Clicking', aliases:['joint clicking','joints clicking','knuckle cracking','joints popping','crepitus','clicking knees'], emoji:'🦴', type:'common', description:'A clicking, popping, or cracking sound from joints during movement. Very common and usually harmless. Known medically as crepitus.', symptoms:['Audible or felt clicking or popping from joints','Usually painless','Most commonly in knees, hips, ankles, knuckles, or back','May be more noticeable after periods of rest'], causes:['Gas bubbles in joint fluid popping (knuckle cracking)','Tendons or ligaments snapping over a bony prominence','Rough joint surfaces from cartilage wear (osteoarthritis)','Normal joint movement in some people'], homecare:['No treatment needed if painless','Low-impact exercise to strengthen muscles around joints','Maintain a healthy weight to reduce joint stress','Avoid repeated forceful popping or cracking as a habit'], whenToSeeDoctor:'Clicking or popping with pain, swelling, warmth, or limited range of motion needs evaluation. This could indicate a torn meniscus, loose body in the joint, or early arthritis.', urgency:'low' },

  { name:'Joint Popping', aliases:['joint popping','popping joints','pop in joint','joint snap','cracking joints loudly'], emoji:'🦴', type:'common', description:'A loud popping or snapping sensation from a joint, often more dramatic than clicking. Can be normal or indicate a structural problem depending on whether pain is associated.', symptoms:['Audible pop from a joint','Felt as well as heard','May or may not be painful','Can occur in any joint — most commonly knees, shoulders, hips, ankles'], causes:['Same as joint clicking — gas bubbles, tendon snapping','Acute injury — tear of a ligament or meniscus (painful pop)','Joint dislocation or subluxation'], homecare:['Painless popping — no treatment needed','If from an acute injury with a painful pop — follow RICE (rest, ice, compression, elevation)'], whenToSeeDoctor:'Any popping associated with sudden pain, significant swelling, giving way of the joint, or inability to bear weight. A painful pop during sport often indicates a significant injury requiring urgent assessment.', urgency:'medium' },

  { name:'Hypermobility', aliases:['hypermobility','hypermobile joints','double jointed','flexible joints','joint laxity','benign hypermobility'], emoji:'🦴', type:'common', description:'The ability to move joints beyond their normal range of motion. Affects 10-15% of children and is more common in women. Usually benign but can cause joint pain and instability.', symptoms:['Joints that extend beyond normal range','Easy bruising','Chronic joint pain and aching','Fatigue','Frequent joint sprains or dislocations','Poor coordination','Joint instability'], causes:['Loose ligaments due to genetic variation in collagen','Generalized joint hypermobility syndrome','Ehlers-Danlos syndrome (more severe hereditary form)'], homecare:['Strengthen muscles around hypermobile joints through physiotherapy exercises','Proprioception training — exercises to improve joint position sense','Wear supportive footwear and orthotics for foot hypermobility','Avoid high-impact activities that stress joints — choose swimming, cycling, pilates','OTC pain relievers during flares','Joint supports or braces for instability'], whenToSeeDoctor:'Joint pain or frequent dislocations significantly affecting daily life, severe fatigue, or features suggesting Ehlers-Danlos syndrome (skin hyperextensibility, fragile skin, significant joint instability). Physiotherapy is the main treatment.', urgency:'low' },

  { name:'Flat Feet', aliases:['flat feet','flatfoot','pes planus','fallen arches','no arch feet'], emoji:'🦶', type:'common', description:'A condition where the arches on the inside of the feet are flattened, causing the entire sole to touch the floor when standing. Common in children but usually develops arches as they grow. Many adults have flat feet without problems.', symptoms:['Feet that appear flat — no visible arch when standing','Feet may roll inward (overpronation)','Foot pain especially in arch and heel','Leg and back pain from altered gait','Shoe soles wearing unevenly'], causes:['Congenital (present from birth)','Arches that never fully developed in childhood','Injury or damage to the posterior tibial tendon','Aging','Obesity putting stress on arches','Conditions like rheumatoid arthritis or diabetes'], homecare:['Supportive shoes with good arch support','Orthotic insoles — custom or OTC with arch support','Avoid standing or walking for long periods on hard floors','Calf and arch stretching exercises daily','Strengthen the intrinsic foot muscles with exercises','Maintain healthy weight to reduce foot stress'], whenToSeeDoctor:'Flat feet causing pain, affecting walking, causing leg or back pain, or if a child\'s arches have not developed by age 5-6. Custom orthotics and physiotherapy are very effective.', urgency:'low' },

  { name:'Bunion', aliases:['bunion','hallux valgus','big toe joint bump','bunion foot','toe joint deformity'], emoji:'🦶', type:'common', description:'A bony bump that forms on the joint at the base of the big toe. Caused by the big toe pushing against the next toe, forcing the joint to stick out. More common in women and often runs in families.', symptoms:['Visible bony bump at the base of the big toe','Soreness around the big toe joint','Redness and inflammation','Corns or calluses develop where toes rub against each other','Restricted movement of the big toe','Pain when walking'], causes:['Genetics — bunions tend to run in families','Wearing narrow, pointed, or high-heeled shoes (worsens hereditary tendency)','Certain types of arthritis','Foot injuries or abnormal gait'], homecare:['Wear wide, comfortable shoes with a roomy toe box','Use bunion pads to cushion the area and reduce friction','OTC arch support insoles to improve foot mechanics','Toe spacers between the big and second toe','Ice the area to reduce inflammation','OTC pain relievers during flare-ups'], whenToSeeDoctor:'Persistent pain despite comfortable footwear, bunion limiting daily activities, or significant cosmetic concern. Surgical correction (bunionectomy) can straighten the toe and remove the bony prominence.', urgency:'low' },

  { name:'Hammer Toe', aliases:['hammer toe','hammertoe','bent toe','curled toe','claw toe','mallet toe'], emoji:'🦶', type:'common', description:'An abnormal bend in the middle joint of a toe, usually the second, third, or fourth toe, causing it to curl downward like a hammer or claw. Caused by muscle and tendon imbalance.', symptoms:['Toe bends downward at the middle joint','Difficulty straightening the toe','Corns or calluses on top of the bent joint from shoe rubbing','Pain and stiffness in the affected toe','Difficulty fitting shoes comfortably'], causes:['Imbalance of muscles and tendons controlling toe movement','Wearing ill-fitting shoes — too small, pointed, or high-heeled','Genetic predisposition','Arthritis or diabetes affecting foot structure','Injury to the toe'], homecare:['Wear shoes with a wide, deep toe box to accommodate the bent toe','Toe exercises to stretch and strengthen toe muscles — picking up marbles with toes','Use shoe inserts (orthotics) to reduce pressure','Moleskin or toe pads to protect corns and calluses','Corn plasters to manage painful calluses'], whenToSeeDoctor:'Hammer toes that are rigid (cannot be straightened even manually), causing significant pain, or affecting walking. Surgery can correct the deformity when conservative measures fail.', urgency:'low' },

  { name:'Toe Cramps', aliases:['toe cramps','toe spasm','toes cramping','foot toe cramp','toe muscle spasm'], emoji:'🦶', type:'common', description:'Sudden involuntary contractions of the muscles in the toes. Painful and often quite dramatic in appearance. Similar to muscle cramps elsewhere in the body.', symptoms:['Sudden involuntary cramping of one or more toes','Toes may curl or spread involuntarily','Sharp pain lasting seconds to minutes','Residual soreness after cramping','More common at night or after exercise'], causes:['Dehydration','Electrolyte imbalances — low potassium, magnesium, or calcium','Tight or ill-fitting footwear compressing toes','Overuse from running or walking','Poor circulation in the feet','Peripheral neuropathy (diabetes)'], homecare:['Stretch the cramped toe upward by pulling it toward the shin','Walk around or flex the foot to relieve cramping','Massage the cramped toe and foot','Ensure adequate hydration and dietary potassium, magnesium, calcium','Wear well-fitting shoes with adequate toe space','Warm foot bath to relax muscles'], whenToSeeDoctor:'Frequent toe cramps, cramps not responding to stretching and electrolyte replenishment, or cramps in a person with diabetes or peripheral vascular disease.', urgency:'low' },

  { name:'Foot Pain', aliases:['foot pain','sore foot','aching feet','foot ache','painful feet','metatarsalgia'], emoji:'🦶', type:'common', description:'Pain anywhere in the foot — a complex structure of 26 bones and many joints, tendons, ligaments, and muscles. Very common. Most foot pain has a mechanical cause and responds to conservative treatment.', symptoms:['Pain in the top, bottom, sides, or heel of the foot','Aching that worsens with standing or walking','Swelling or redness in the foot','Tenderness when pressing on specific areas'], causes:['Plantar fasciitis (heel pain)','Metatarsalgia (ball of foot pain)','Bunions, corns, or calluses','Gout (sudden severe pain)','Stress fracture','Flat feet or high arches','Ill-fitting footwear','Morton\'s neuroma (nerve pain between toes)'], homecare:['Wear well-fitting, supportive shoes with cushioning','OTC orthotic insoles for arch support','Rest and ice for acute pain','OTC anti-inflammatory pain relievers','Foot stretching and strengthening exercises','Avoid walking barefoot on hard surfaces'], whenToSeeDoctor:'Severe pain, significant swelling or bruising, inability to bear weight, foot pain after injury, or pain that persists for more than 2 weeks of home care.', urgency:'medium' },

  { name:'Ankle Swelling', aliases:['ankle swelling','swollen ankles','bilateral ankle swelling','puffy ankles','ankles puffing up'], emoji:'🦶', type:'common', description:'Enlargement of the ankles due to fluid accumulation in the tissues. Can affect one or both ankles. Very common especially in older adults. Can range from harmless to a sign of serious disease.', symptoms:['Visible swelling around one or both ankles','Skin that pits when pressed','Feeling of heaviness or tightness in ankles','Difficulty wearing shoes that normally fit','Aching or discomfort'], causes:['Prolonged sitting or standing — gravity causes fluid pooling','High salt intake','Pregnancy','Premenstrual fluid retention','Certain medications — calcium channel blockers, corticosteroids, NSAIDs','Heart failure, kidney disease, or liver disease (serious causes)','DVT — blood clot in leg (emergency if unilateral with calf pain)'], homecare:['Elevate legs above heart level when resting','Reduce salt in diet','Regular movement — calf raises, walking, ankle circles','Compression stockings','Stay well hydrated'], whenToSeeDoctor:'Sudden swelling in one leg especially with calf pain (possible blood clot — emergency). Swelling with shortness of breath, chest pain. Persistent swelling without obvious cause needs evaluation to rule out cardiac, renal, or hepatic disease.', urgency:'medium' },

  { name:'Shin Pain', aliases:['shin pain','shin splints','tibial stress','sore shins','front leg pain','medial tibial stress syndrome'], emoji:'🦵', type:'common', description:'Pain along the shinbone (tibia) — the large bone in the front of the lower leg. Shin splints are the most common cause, especially in runners and people who have recently increased activity.', symptoms:['Aching, throbbing, or sharp pain along the inner shinbone','Pain during and after exercise','Tenderness along the shinbone when touched','Mild swelling in lower leg','Pain that improves with rest'], causes:['Shin splints — overuse from running or jumping activities','Sudden increase in exercise intensity or frequency','Hard running surfaces','Poor running shoes without cushioning','Flat feet or rigid arches','Stress fracture (more serious)'], homecare:['Rest from high-impact activity','Ice the shins for 15-20 minutes after activity','OTC anti-inflammatory medication','Wear supportive running shoes with cushioning','Gradual return to activity — increase by no more than 10% per week','Stretch calves and hamstrings before running'], whenToSeeDoctor:'Severe pain, pain in one specific spot (possible stress fracture), significant swelling, or shin pain not improving after 2-3 weeks of rest. A stress fracture needs to be ruled out by imaging.', urgency:'medium' },

  { name:'Calf Pain', aliases:['calf pain','calf ache','sore calf','calf muscle pain','back of leg pain','gastrocnemius pain'], emoji:'🦵', type:'common', description:'Pain in the back of the lower leg between the knee and ankle. The most common cause is muscle strain or cramp. A blood clot (DVT) must always be considered if swelling accompanies the pain.', symptoms:['Aching, tight, or sharp pain in the calf muscle','Tenderness when pressing the calf','Swelling (possible DVT)','Worsens with exercise, improves with rest','Tightness when walking'], causes:['Muscle strain or cramp (most common)','Deep vein thrombosis (DVT) — blood clot (serious)','Peripheral artery disease — pain on walking, relieved by rest','Achilles tendinitis','Sciatica referring pain down the leg','Baker\'s cyst (fluid-filled swelling behind knee)'], homecare:['For muscle strain — RICE method (Rest, Ice, Compression, Elevation)','Calf stretches — lean against a wall with back leg straight, push heel down','OTC anti-inflammatory pain relievers','Hydration and electrolytes for cramp-related pain','Gradual return to activity after strain'], whenToSeeDoctor:'Calf pain with swelling, warmth, and redness — possible DVT, which is a medical emergency. Calf pain that is persistent, severe, or with numbness or tingling in the foot. DVT especially after long travel or immobility needs urgent assessment.', urgency:'medium' },

  { name:'Thigh Pain', aliases:['thigh pain','thigh ache','front thigh pain','outer thigh pain','inner thigh pain','quadriceps pain'], emoji:'🦵', type:'common', description:'Pain in the upper leg between the hip and knee. Causes include muscle strain, nerve irritation, referred pain, or vascular issues. Common in athletes and active individuals.', symptoms:['Aching, burning, or sharp pain in the thigh','Tenderness when pressing the thigh muscle','Pain with movement or walking','May be accompanied by bruising (strain)','Numbness or tingling (if nerve related)'], causes:['Quadriceps or hamstring strain (sports)','Meralgia paresthetica — nerve compression causing burning outer thigh pain','Referred pain from the hip or lower back','Quadriceps contusion (bruise from impact)','DVT in femoral vein (serious)'], homecare:['Rest from aggravating activity','Ice for acute strain in first 48 hours','Compression and elevation','Gentle stretching of quadriceps and hamstrings when pain subsides','OTC anti-inflammatory medication'], whenToSeeDoctor:'Significant bruising, inability to walk, numbness in the entire thigh (possible serious nerve compression), or thigh pain with swelling of the entire leg.', urgency:'medium' },

  { name:'Groin Pain', aliases:['groin pain','groin ache','inner thigh groin pain','groin strain','hip flexor pain'], emoji:'🦵', type:'common', description:'Pain in the area where the abdomen meets the inner thigh. Common in athletes and can result from muscle strains, hernia, or referred pain from the hip.', symptoms:['Pain in groin area — inner thigh and lower abdomen junction','Worsens with activity — running, kicking, climbing stairs','Tenderness when pressing the inner thigh','Pain may radiate to the inner thigh or lower abdomen','Groin bulge if hernia present'], causes:['Adductor (groin) muscle strain — most common in athletes','Inguinal hernia','Hip pathology — osteoarthritis, labral tear','Urinary tract infection in women (referred pain)','Testicular pain (referred to groin in men)','Sportsman\'s groin (athletic pubalgia)'], homecare:['Rest from aggravating activities','Ice for first 48 hours of acute strain','Gentle adductor stretches after pain subsides','OTC anti-inflammatory medication','Gradually return to activity over 2-4 weeks'], whenToSeeDoctor:'Groin pain with a visible bulge (hernia), testicular pain or swelling, fever, urinary symptoms, or groin pain not improving after 2-3 weeks. Hernia repair is needed if symptomatic.', urgency:'medium' },

  { name:'Hip Pain', aliases:['hip pain','hip ache','sore hip','hip joint pain','outer hip pain','hip flexor pain'], emoji:'🦴', type:'common', description:'Pain in or around the hip joint. One of the most common musculoskeletal complaints especially in older adults. Can significantly affect mobility and quality of life.', symptoms:['Pain in hip, groin, thigh, or buttock area','Stiffness and reduced range of motion of hip','Pain worsening with weight bearing activities','Limping','Pain at rest in advanced cases','Clicking or grinding sensation'], causes:['Osteoarthritis (most common in older adults)','Greater trochanteric bursitis (outer hip — common in runners)','Hip flexor strain','Hip labral tear','Osteonecrosis of the femoral head','Referred pain from spine or sacroiliac joint','Stress fracture (in athletes)'], homecare:['Rest from aggravating activities','Ice or heat to the painful area','OTC anti-inflammatory pain relievers','Low-impact exercise — swimming, cycling','Hip stretches and strengthening exercises','Walking aids if weight bearing is very painful'], whenToSeeDoctor:'Hip pain after a fall (fracture must be ruled out especially in older adults), severe pain limiting walking, hip pain with fever, or pain not improving after 2-3 weeks.', urgency:'medium' },

  { name:'Tailbone Pain', aliases:['tailbone pain','coccyx pain','coccydynia','sore tailbone','pain at base of spine','sitting pain tailbone'], emoji:'🦴', type:'common', description:'Pain in and around the coccyx (tailbone) — the small triangular bone at the very base of the spine. Sitting and standing up from sitting are typically painful. Usually resolves within a few months.', symptoms:['Aching or sharp pain in the tailbone area','Pain worsens when sitting for long periods','Sitting on hard surfaces is particularly painful','Pain when standing up from sitting','Discomfort during bowel movements or sexual intercourse','Tenderness when the tailbone is touched'], causes:['Fall onto the tailbone — most common cause','Prolonged sitting on hard or narrow surfaces','Childbirth (vaginal delivery)','Repetitive strain from cycling or rowing','Bone spurs on the coccyx','Rarely: tumor or infection'], homecare:['Use a coccyx (donut) cushion when sitting — U-shaped cutout cushion that removes pressure from the tailbone','Lean forward when sitting','Apply ice or heat to the area','OTC pain relievers — ibuprofen is most effective for bone pain','Avoid prolonged sitting — take regular standing breaks','Gentle stretching of the piriformis and hip flexors'], whenToSeeDoctor:'Severe pain, pain after a significant fall, tailbone pain with bowel or bladder changes, or pain not improving after 6-8 weeks. X-ray may show fracture or dislocation. Steroid injections are very effective.', urgency:'low' },

  { name:'Rib Pain', aliases:['rib pain','rib ache','sore ribs','intercostal pain','rib tenderness','pain in ribs'], emoji:'🦴', type:'common', description:'Pain in one or more of the 12 pairs of ribs. Can be caused by injury, inflammation, or referred pain. Usually felt when breathing deeply, coughing, or moving the trunk.', symptoms:['Pain that worsens with deep breathing, coughing, or sneezing','Tenderness along specific ribs when pressed','Sharp or dull aching pain','May be constant or only with movement','Pain may radiate around the chest wall'], causes:['Costochondritis — rib cartilage inflammation (most common)','Rib fracture from trauma','Intercostal muscle strain','Herpes zoster (shingles) affecting intercostal nerve','Pleurisy (lining of lung inflammation)','Referred pain from organs — liver, gallbladder, spleen'], homecare:['Rest and avoid movements that worsen pain','Apply ice or heat to the area','OTC anti-inflammatory pain relievers (ibuprofen)','Breathe deeply despite discomfort to prevent lung complications from shallow breathing','Avoid tight binding which can cause breathing problems','Pillow support when coughing or sneezing'], whenToSeeDoctor:'Rib pain after significant trauma (fracture), difficulty breathing, fever with rib pain, a rash appearing along the rib (shingles), or pain associated with abdominal symptoms.', urgency:'medium' },

  { name:'Chest Wall Pain', aliases:['chest wall pain','musculoskeletal chest pain','non cardiac chest pain','chest muscle pain','chest bone pain'], emoji:'🦴', type:'common', description:'Pain arising from the bones, cartilage, or muscles of the chest wall rather than from the heart or lungs. Very common and often mistaken for heart pain. Typically worsens with movement or pressing.', symptoms:['Chest pain that worsens when pressing on the chest wall','Pain worse with movement — turning, stretching, coughing','Localized tenderness at specific points','Sharp or dull aching pain','Does not typically radiate to the arm or jaw (unlike cardiac pain)'], causes:['Costochondritis — most common cause','Muscle strain from exercise, coughing, or awkward movement','Rib injury','Herpes zoster (shingles) before rash appears','Tietze syndrome'], homecare:['Rest and avoid aggravating movements','Apply heat or ice to the tender area','OTC anti-inflammatory medication (ibuprofen)','Gentle chest stretching once acute pain subsides'], whenToSeeDoctor:'All new chest pain should be evaluated to rule out cardiac causes first, especially if there is doubt. Once cardiac causes are excluded, chest wall pain can be managed conservatively.', urgency:'medium' },

  { name:'Breast Bone Pain', aliases:['breast bone pain','sternum pain','sternal pain','chest bone pain','pain in middle of chest bone'], emoji:'🦴', type:'common', description:'Pain at the sternum — the flat bone running down the middle of the chest. Often has musculoskeletal causes but must be distinguished from cardiac or aortic pain.', symptoms:['Pain or tenderness over the sternum','Pain worsens with pressing','Worsens with twisting or breathing deeply','May feel like pressure or sharp pain'], causes:['Costochondritis — inflammation where ribs meet sternum','Sternoclavicular joint injury or arthritis','Sternum bruise or fracture from trauma','Muscle strain from exercise or coughing','Acid reflux referring pain to sternum area'], homecare:['Apply ice for first 48 hours then heat','OTC anti-inflammatory pain relievers','Rest from activities that worsen pain','Gentle chest wall stretching exercises'], whenToSeeDoctor:'Sternal pain after trauma (possible fracture), sternal pain with radiating arm or jaw pain (cardiac), breathing difficulty, fever, or pain not improving. All new chest bone pain should be evaluated medically.', urgency:'medium' },

  { name:'Collarbone Pain', aliases:['collarbone pain','clavicle pain','shoulder collarbone pain','clavicle ache','collar bone hurts'], emoji:'🦴', type:'common', description:'Pain along the clavicle (collarbone) — the long thin bone connecting the breastbone to the shoulder. Often results from injury, joint problems, or muscle strain in the area.', symptoms:['Pain along the collarbone','Tenderness when pressing on the clavicle','Swelling or bruising over the clavicle (if fractured)','Pain moving the arm or shoulder','Clicking or popping at the collarbone-shoulder joint'], causes:['Clavicle fracture from fall or direct blow (most common cause of acute pain)','Sternoclavicular joint sprain or dislocation','Acromioclavicular joint injury','Muscle strain around the clavicle','Osteoarthritis of the acromioclavicular joint (in older adults)'], homecare:['Rest the arm in a sling if fracture is suspected','Ice for acute pain (first 48 hours)','OTC anti-inflammatory pain relievers','Avoid lifting or reaching overhead'], whenToSeeDoctor:'Any suspected clavicle fracture (visible deformity, significant pain, bruising) needs immediate evaluation. X-ray is needed to assess the fracture and guide treatment.', urgency:'medium' },

  { name:'Wrist Pain', aliases:['wrist pain','wrist ache','sore wrist','wrist joint pain','wrist injury'], emoji:'🤲', type:'common', description:'Pain in the wrist joint or surrounding area. Very common in people who use computers, do manual work, or play sport. Can result from injury, overuse, or arthritis.', symptoms:['Pain in the wrist joint','Swelling','Reduced grip strength','Stiffness','Clicking or popping with movement','Numbness or tingling if nerve involved'], causes:['Wrist sprain (most common from a fall)','Carpal tunnel syndrome (nerve compression)','De Quervain\'s tenosynovitis (thumb side of wrist)','Tendinitis from repetitive use','Ganglion cyst','Fracture (scaphoid most commonly missed)','Arthritis'], homecare:['Rest the wrist and avoid aggravating activities','Wrist splint to support and rest the joint','Ice for the first 48 hours','OTC anti-inflammatory pain relievers','Wrist stretching and strengthening exercises during recovery','Ergonomic adjustments — keyboard tilt, mouse position'], whenToSeeDoctor:'Wrist pain after a fall (possible scaphoid fracture — easily missed), significant swelling, numbness, or pain not improving after 2 weeks. A scaphoid fracture can have a normal X-ray initially — MRI may be needed.', urgency:'medium' },

  { name:'Hand Pain', aliases:['hand pain','sore hand','painful hand','hand ache','hand joint pain'], emoji:'🤲', type:'common', description:'Pain in the hand, fingers, or palm. Very common and can result from overuse, arthritis, nerve conditions, or injury. Can significantly affect daily activities.', symptoms:['Pain in the palm, fingers, or across the hand','Stiffness — especially in the morning','Swelling of finger joints','Reduced grip strength','Numbness or tingling (nerve-related)','Burning or aching pain'], causes:['Osteoarthritis of finger joints (common in older adults)','Rheumatoid arthritis','Carpal tunnel syndrome (median nerve compression)','Trigger finger (stenosing tenosynovitis)','De Quervain\'s tenosynovitis','Fractures or sprains','Dupuytren\'s contracture'], homecare:['Rest and avoid repetitive or forceful gripping activities','Warm water soaks for arthritic hands — improves flexibility','OTC anti-inflammatory medication','Hand and finger exercises to maintain mobility','Wear gloves in cold weather (cold worsens arthritis pain)','Ergonomic tools with larger, easier-to-grip handles'], whenToSeeDoctor:'Significant swelling, visible joint deformity, numbness, inability to straighten a finger, or pain from a specific injury. Rheumatoid arthritis is particularly important to diagnose and treat early.', urgency:'medium' },

  { name:'Finger Swelling', aliases:['finger swelling','swollen finger','swollen fingers','puffy fingers','finger inflammation'], emoji:'🤲', type:'common', description:'Swelling of one or more fingers. Can occur after injury, with arthritis, or from other systemic conditions. Sudden onset after trauma may indicate a fracture or dislocation.', symptoms:['Visible swelling of the finger','Reduced ability to bend or straighten the finger','Tenderness and pain','Redness and warmth (if infected or arthritic flare)','Stiffness'], causes:['Finger sprain or fracture','Gout or pseudogout (crystal arthritis)','Rheumatoid or psoriatic arthritis','Paronychia (nail fold infection)','Felon (infection of fingertip pulp)','Systemic causes — kidney disease, hypothyroidism'], homecare:['Remove rings immediately from swollen fingers before swelling increases','RICE method for injured fingers (rest, ice, compression, elevation)','OTC anti-inflammatory medication','Buddy taping a sprained finger to the adjacent finger for support'], whenToSeeDoctor:'Sudden swelling after injury (possible fracture — X-ray needed), swollen hot red finger with fever (possible serious infection), or progressive swelling across multiple fingers without obvious cause.', urgency:'medium' },

  { name:'Trigger Finger', aliases:['trigger finger','stenosing tenosynovitis','finger locking','finger clicks','stuck finger','snapping finger'], emoji:'🤲', type:'common', description:'A condition where one of the fingers gets stuck in a bent position and then snaps back like a trigger being pulled and released. Caused by inflammation of the tendon sheath.', symptoms:['Finger stiffness, especially in the morning','A popping or clicking sensation when bending the finger','Tenderness or a bump at the base of the affected finger','Finger locking in bent position — requires passive straightening','May affect thumb (trigger thumb)'], causes:['Inflammation and narrowing of the tendon sheath','Repetitive gripping activities','Diabetes (significantly increases risk)','Rheumatoid arthritis','Women are more commonly affected'], homecare:['Splint the affected finger in an extended position at night','Gentle stretching exercises for the finger','Avoid repetitive gripping tasks','Warm soak to improve flexibility','OTC anti-inflammatory medication for pain and inflammation'], whenToSeeDoctor:'Persistent or worsening trigger finger, finger that is locked and cannot be passively straightened. Steroid injection is highly effective. Surgery is an option for refractory cases.', urgency:'low' },

  { name:'Thumb Pain', aliases:['thumb pain','sore thumb','thumb ache','thumb joint pain','de quervain\'s','basal thumb pain'], emoji:'🤲', type:'common', description:'Pain in the thumb, which can significantly affect hand function. The thumb is responsible for 50% of hand function. Common causes include arthritis at the base of the thumb and De Quervain\'s tenosynovitis.', symptoms:['Pain at the base of the thumb or along the thumb side of the wrist','Swelling near the base of the thumb','Reduced grip or pinch strength','Pain when holding objects, turning keys, or opening jars','Clicking or locking of the thumb'], causes:['Basal thumb arthritis (carpometacarpal osteoarthritis) — very common in women over 40','De Quervain\'s tenosynovitis — tendon inflammation on thumb side of wrist','Trigger thumb','Skier\'s thumb — UCL ligament sprain from injury','Overuse from texting or typing'], homecare:['Rest the thumb and avoid pinching or gripping activities','Thumb spica splint to immobilize and rest the joint','OTC anti-inflammatory medication','Ice the painful area','Hand therapy exercises once acute pain subsides'], whenToSeeDoctor:'Severe pain limiting hand use, a painful snap or injury to the thumb, or persistent pain not improving after 3-4 weeks. Steroid injections and physiotherapy are effective. Surgery is available for advanced arthritis.', urgency:'low' },

  { name:'Elbow Pain', aliases:['elbow pain','elbow ache','sore elbow','elbow joint pain','olecranon pain'], emoji:'🦾', type:'common', description:'Pain in or around the elbow joint. The elbow is commonly affected by overuse injuries. Tennis elbow (lateral) and golfer\'s elbow (medial) are the two most common types.', symptoms:['Pain on the outer or inner side of the elbow','Pain radiating down the forearm','Weak grip strength','Stiffness or difficulty fully straightening the elbow','Tenderness when pressing specific points around elbow'], causes:['Tennis elbow (lateral epicondylitis) — outer elbow','Golfer\'s elbow (medial epicondylitis) — inner elbow','Olecranon bursitis (swelling of the bursa behind elbow)','Cubital tunnel syndrome (ulnar nerve compression)','Elbow fracture or dislocation (from injury)','Arthritis'], homecare:['Rest from aggravating activities','Ice the elbow for 15-20 minutes several times daily','Tennis elbow brace — counterforce strap just below elbow','OTC anti-inflammatory medication','Specific forearm stretching and strengthening exercises','Ergonomic adjustments to workstation or technique'], whenToSeeDoctor:'Pain severely limiting daily activities, with numbness or tingling in the arm (cubital tunnel), significant swelling (bursitis or fracture), or not improving after 6-8 weeks.', urgency:'low' },

  { name:'Forearm Pain', aliases:['forearm pain','forearm ache','sore forearm','forearm muscle pain','lower arm pain'], emoji:'🦾', type:'common', description:'Pain in the forearm — the section of the arm between the elbow and the wrist. Can be caused by muscle strain, nerve problems, or fracture.', symptoms:['Aching, burning, or sharp pain in the forearm','Tenderness when pressing the muscles','Pain with gripping or wrist movements','Numbness or tingling if nerve involved','Weakness in grip or wrist'], causes:['Muscle strain from overuse or repetitive movements','Tennis elbow or golfer\'s elbow referring pain to forearm','Compartment syndrome (exercise-induced — serious)','Radial or ulnar nerve compression','Stress fracture in forearm bones'], homecare:['Rest from repetitive activities','Ice for acute pain','OTC anti-inflammatory medication','Forearm stretching exercises','Ergonomic adjustments for computer use'], whenToSeeDoctor:'Severe or rapidly worsening forearm pain especially after exercise (possible compartment syndrome — emergency), numbness or weakness, or suspected fracture.', urgency:'medium' },

  { name:'Upper Arm Pain', aliases:['upper arm pain','bicep pain','upper arm ache','arm pain upper','shoulder arm pain'], emoji:'🦾', type:'common', description:'Pain in the upper arm between the shoulder and elbow. Can originate from the shoulder, neck, or arm itself. Biceps tendon injury is common.', symptoms:['Aching or sharp pain in the upper arm','Weakness when lifting objects or flexing the elbow','Tenderness over specific muscles or tendons','Pain radiating from shoulder or neck','Bruising if muscle tear'], causes:['Bicipital tendinitis or tendon rupture','Rotator cuff tear (shoulder problem referring to upper arm)','Cervical nerve compression from the neck','Deltoid muscle strain','Referred cardiac pain (left arm — important to consider)','Humerus fracture from trauma'], homecare:['Rest the arm','Ice for acute injury (first 48 hours)','OTC anti-inflammatory medication','Gentle shoulder and arm stretches','Support arm in sling if very painful'], whenToSeeDoctor:'Upper arm pain with sudden onset during activity (possible tendon rupture), pain radiating from chest (cardiac), after significant trauma, or persisting beyond 2 weeks without improvement.', urgency:'medium' },

  /* ── COMMON: HEAD & NEUROLOGICAL ── */
  { name:'Sinus Headache', aliases:['sinus headache','sinusitis headache','pressure in head','forehead headache','sinus pressure','blocked sinus pain'], emoji:'🧠', type:'common', description:'A headache caused by inflamed and swollen sinuses — air-filled spaces in the skull. Often occurs with sinusitis. Characterized by pressure and pain in the forehead, cheeks, and around the eyes.', symptoms:['Pain and pressure in forehead, cheeks, nose bridge, or behind the eyes','Pain worsens when bending forward or lying down','Nasal congestion and discharge','Reduced sense of smell','Feeling of fullness in the face','May be accompanied by fever'], causes:['Sinusitis from viral or bacterial infection','Allergies causing sinus inflammation','Nasal polyps','Dry air irritating sinus membranes'], homecare:['Steam inhalation — bowl of hot water with towel over head for 10 minutes','Saline nasal rinse to clear congestion','Warm compress over the forehead and face','OTC decongestants for short-term relief (maximum 3 days)','Stay well hydrated','OTC pain relievers (ibuprofen or paracetamol)'], whenToSeeDoctor:'Sinus pain with high fever, severe headache, stiff neck, vision changes, swelling around the eye, or symptoms not improving after 10 days. Bacterial sinusitis may need antibiotics.', urgency:'medium' },

  { name:'Cervicogenic Headache', aliases:['cervicogenic headache','neck headache','headache from neck','cervical headache','occipital headache','headache base of skull'], emoji:'🧠', type:'common', description:'A headache that originates from structures in the neck and is referred to the head. Often felt at the base of the skull and radiating over the top of the head to the front. Very common.', symptoms:['Headache starting at the base of the skull or back of the neck','Pain radiating to the forehead, temples, or behind the eyes','Neck stiffness or reduced neck movement on the same side','Worse with neck movements or prolonged neck positions','May mimic migraine — nausea and light sensitivity can occur'], causes:['Cervical spine joint degeneration (facet joint arthritis)','Muscle tension in the neck and suboccipital muscles','Poor posture — looking at screen for hours','Whiplash injury','Sleeping in awkward position','Cervical nerve compression'], homecare:['Physiotherapy — the most effective treatment for cervicogenic headache','Gentle neck stretches and strengthening exercises','Correct posture — keep screen at eye level, take breaks','Apply heat to the neck and base of skull','Neck massage to reduce muscle tension','OTC pain relievers and anti-inflammatories'], whenToSeeDoctor:'Persistent cervicogenic headaches need physiotherapy evaluation. Sudden severe headache at the back of the head needs emergency evaluation. Nerve blocks or manipulation under specialist supervision may be needed for severe cases.', urgency:'medium' },

  { name:'Medication Overuse Headache', aliases:['medication overuse headache','rebound headache','analgesic overuse headache','painkiller headache','chronic daily headache medication'], emoji:'🧠', type:'common', description:'A chronic headache caused by taking pain medications too frequently to treat headaches. A paradoxical condition where the treatment causes the problem. Very common, affecting 1-2% of the population.', symptoms:['Headache present more than 15 days per month','Worsens in the morning','Improves temporarily after taking pain medication','Need for increasing doses over time','Nausea, restlessness, difficulty concentrating'], causes:['Taking any headache medication more than 10-15 days per month','Opioids, triptans, paracetamol, NSAIDs, aspirin, or combination analgesics all can cause it','People with pre-existing migraine or tension headache are most at risk'], homecare:['The treatment is withdrawal of the overused medication — this initially causes worsening headache for 2-10 days','Take a prescribed medication tapering schedule from your doctor','Do not take any acute headache medication more than 2 days per week as a preventive rule','Stay hydrated during withdrawal'], whenToSeeDoctor:'Essential to see a neurologist or GP to confirm the diagnosis and guide withdrawal, especially for opioid overuse. Preventive migraine medications should be started simultaneously to prevent recurrence.', urgency:'medium' },

  { name:'Thunderclap Headache', aliases:['thunderclap headache','worst headache of my life','sudden severe headache','sudden headache','explosive headache'], emoji:'🧠', type:'common', description:'A very severe headache that peaks in intensity within 60 seconds, like a clap of thunder. This is a medical emergency until proven otherwise as it may indicate a life-threatening condition.', symptoms:['Sudden, extremely severe headache — often described as the worst headache of one\'s life','Reaches maximum intensity within 60 seconds','May be accompanied by stiff neck, nausea, or loss of consciousness','Persists for more than 1 hour'], causes:['Subarachnoid haemorrhage — bleeding around the brain (most dangerous cause — requires immediate CT scan)','Cerebral venous thrombosis','Hypertensive emergency','Reversible cerebral vasoconstriction syndrome (RCVS)','In some cases, no serious cause is found'], homecare:['No home care — a thunderclap headache is a medical emergency','Call an ambulance immediately or go to the nearest emergency department'], whenToSeeDoctor:'A thunderclap headache requires immediate emergency evaluation. Do not wait and do not drive yourself. CT scan of the brain is needed urgently to rule out subarachnoid haemorrhage. This is truly a red flag headache.', urgency:'high' },

  { name:'Memory Lapses', aliases:['memory lapses','forgetfulness','forgetting things','poor memory','mild memory loss','memory problems'], emoji:'🧠', type:'common', description:'Brief episodes of forgetting names, words, or recent events. Very common with aging and stress. Occasional lapses are normal — it is the pattern and severity that determines whether concern is warranted.', symptoms:['Forgetting names of familiar people or objects momentarily','Forgetting where you put things','Forgetting recent conversations or events','Difficulty recalling words','Improved memory function with prompts or reminders'], causes:['Normal aging','Sleep deprivation (one of the most common causes)','Stress, anxiety, or depression','Vitamin B12 deficiency','Hypothyroidism','Certain medications (antihistamines, sleep aids, blood pressure medication)','Alcohol use'], homecare:['Get 7-9 hours of quality sleep — the most impactful action','Regular aerobic exercise — improves memory and brain function','Mentally stimulating activities — reading, puzzles, new skills','Healthy diet — Mediterranean diet is associated with better cognitive aging','Stay socially engaged','Write things down and use reminders','Reduce alcohol intake'], whenToSeeDoctor:'Memory lapses that are frequent, progressive, affecting daily functioning, or causing concern to family members warrant medical evaluation. Blood tests and assessment can identify treatable causes.', urgency:'low' },

  { name:'Difficulty Concentrating', aliases:['difficulty concentrating','can\'t concentrate','poor concentration','trouble focusing','attention problems','inability to focus'], emoji:'🧠', type:'common', description:'Trouble maintaining attention and focus on tasks. Very common and can result from many lifestyle factors including sleep deprivation, stress, or underlying medical conditions.', symptoms:['Trouble sustaining attention on a task','Easily distracted by surroundings','Taking much longer to complete tasks','Making more errors than usual','Feeling mentally overwhelmed','Difficulty following conversations'], causes:['Sleep deprivation (most common)','Stress and anxiety','Depression','ADHD','Hypothyroidism','Iron deficiency or anemia','Medications side effects','Prolonged screen use'], homecare:['Address sleep — 7-9 hours is optimal for cognitive performance','Physical exercise significantly improves concentration','Reduce multitasking — single-task focus is more effective','Use the Pomodoro technique — 25 minutes focused work, 5 minutes break','Minimize phone and notification distractions','Meditation and mindfulness practice proven to improve focus'], whenToSeeDoctor:'Concentration problems significantly affecting work or daily life, accompanied by mood changes, suspected ADHD, or if associated with other symptoms like fatigue and cold sensitivity (thyroid).', urgency:'low' },

  { name:'Mental Fatigue', aliases:['mental fatigue','mental exhaustion','cognitive fatigue','brain tiredness','mental tiredness','cognitive exhaustion'], emoji:'🧠', type:'common', description:'A state of cognitive exhaustion — the brain feels tired even when the body is rested. Different from physical fatigue. Increasingly common in knowledge-work environments.', symptoms:['Feeling of cognitive tiredness or mental exhaustion','Difficulty thinking clearly or making decisions','Reduced productivity and motivation','Irritability','Difficulty with complex tasks','Feeling overwhelmed by normal responsibilities'], causes:['Prolonged intense cognitive work or multitasking','Chronic stress','Poor sleep quality (even if quantity seems adequate)','Depression or anxiety','Burnout','Information overload','Post-viral fatigue (long COVID)'], homecare:['Regular digital detox — scheduled periods away from screens and notifications','Short breaks every 60-90 minutes during cognitive work','Prioritize quality sleep — reduce late-night screen use','Regular physical exercise (counterintuitively reduces mental fatigue)','Practice saying no to overcommitment','Mindfulness or meditation — even 10 minutes daily is effective'], whenToSeeDoctor:'Mental fatigue lasting more than 2 weeks, significantly affecting work and relationships, or accompanied by persistent low mood, anxiety, or physical symptoms. May indicate burnout, depression, or thyroid disorder.', urgency:'low' },

  { name:'Word Finding Difficulty', aliases:['word finding difficulty','tip of tongue','can\'t find words','forgetting words','anomia','word retrieval problem'], emoji:'🧠', type:'common', description:'Difficulty retrieving specific words, especially proper nouns, resulting in the "tip of the tongue" phenomenon. Very common and usually benign, increasing with age and fatigue.', symptoms:['Knowing what you want to say but unable to find the exact word','Substituting vague words — "the thing" or "you know"','The word eventually comes after delay or prompting','More frequent when tired or stressed','Not accompanied by confusion or other language problems'], causes:['Normal aging (most common)','Fatigue and sleep deprivation','Stress and anxiety','Multilingualism — more words to manage','Migraine aura','Rarely: neurological conditions'], homecare:['Do not panic — this is almost always benign','Allow time for the word to come rather than forcing it','Regular reading and word games help maintain language fluency','Adequate sleep significantly improves word retrieval','Reduce stress — cortisol impairs memory and word retrieval'], whenToSeeDoctor:'Frequent or rapidly worsening word-finding difficulty, occurring in younger adults without obvious cause, or accompanied by confusion, difficulty understanding, or other language changes.', urgency:'low' },

  { name:'Numbness in Feet', aliases:['numbness in feet','foot numbness','numb feet','tingly feet','pins and needles feet','foot tingling'], emoji:'🦶', type:'common', description:'Loss of sensation or tingling in the feet. Common causes include nerve compression from sitting crossed-legged or peripheral neuropathy from diabetes. Requires evaluation if persistent.', symptoms:['Numbness or tingling in one or both feet','Pins and needles sensation','Burning feeling in feet','Reduced ability to feel temperature or touch','Weakness in foot muscles in severe cases','Unsteady walking'], causes:['Temporary nerve compression from crossing legs or tight footwear','Peripheral neuropathy — most commonly from diabetes','Vitamin B12 deficiency','Alcohol-related neuropathy','Chemotherapy side effects','Lumbar spine nerve compression','Hypothyroidism'], homecare:['For positional numbness — move position and shake out the foot','Ensure footwear is not too tight','Check blood sugar if diabetic and report changes','B12 supplement if at risk of deficiency (vegetarians, vegans, older adults)','Moderate alcohol intake — alcohol damages peripheral nerves'], whenToSeeDoctor:'Persistent or progressive foot numbness, both feet affected, associated with weakness, history of diabetes, or significantly affecting walking. Blood tests to check B12, blood sugar, and thyroid are appropriate first steps.', urgency:'medium' },

  { name:'Tingling in Arms', aliases:['tingling arms','arm tingling','arms tingling','pins and needles arms','arm paresthesia','numb arms tingling'], emoji:'🦾', type:'common', description:'A tingling, pins and needles, or numb sensation in one or both arms. Usually caused by pressure on a nerve or blood vessel. Most episodes are positional and temporary.', symptoms:['Tingling or pins and needles sensation in arm or arms','Numbness in part or all of the arm','May have weak or heavy feeling','Usually temporary and position-related in mild cases'], causes:['Sleeping on the arm (most common)','Cervical spine nerve compression','Thoracic outlet syndrome','Carpal or cubital tunnel syndrome','Vitamin B12 deficiency','Poor circulation','TIA or stroke (sudden onset in one arm — emergency)'], homecare:['Change position and shake the arm to restore circulation for positional cases','Check for and correct poor sleeping position','Cervical and shoulder stretching exercises','B12 supplement if at risk'], whenToSeeDoctor:'Sudden arm tingling especially with weakness, facial drooping, or speech problems (stroke — emergency). Persistent bilateral tingling, or tingling after neck injury needs evaluation.', urgency:'medium' },

  { name:'Tingling in Legs', aliases:['tingling legs','leg tingling','pins and needles legs','leg paresthesia','numb legs','leg numbness tingling'], emoji:'🦵', type:'common', description:'Abnormal sensations including tingling, numbness, or pins and needles in the legs. Very common with many causes from positional pressure to neuropathy.', symptoms:['Tingling or pins and needles in legs','Numbness','Burning sensation','Weakness in legs in more serious cases','May be bilateral (both legs) or unilateral'], causes:['Sitting with legs crossed or in one position (most common — temporary)','Lumbar spine nerve compression (sciatica)','Peripheral neuropathy from diabetes','Vitamin B12 deficiency','Multiple sclerosis (bilateral tingling)','Peripheral vascular disease'], homecare:['Change position and move around for positional tingling','Lumbar stretching and core strengthening exercises for sciatica-related tingling','B12 supplement if at risk','Control blood sugar in diabetes'], whenToSeeDoctor:'Tingling in both legs simultaneously, worsening tingling, associated weakness or bladder/bowel symptoms (possible spinal cord issue), or in a diabetic with progressive neuropathy.', urgency:'medium' },

  { name:'Pins and Needles', aliases:['pins and needles','paresthesia','tingling and numbness','pricking sensation','prickling feeling','temporary numbness'], emoji:'🧠', type:'common', description:'A tingling, prickling, or numb sensation in the body, commonly in the limbs. Usually caused by temporary pressure on nerves or blood vessels. Almost everyone experiences this at some point.', symptoms:['Tingling or prickling sensation','Temporary numbness in a limb','Sensation that the limb has "fallen asleep"','Resolves within minutes of changing position and moving','May be accompanied by mild weakness while sensation is lost'], causes:['Pressure on a nerve or blood vessel from sustained position (most common)','Sitting cross-legged, lying on an arm, or leaning on an elbow','Hyperventilation during anxiety (bilateral tingling in hands and feet)','Vitamin B12 deficiency','Diabetes (persistent)'], homecare:['Move the affected area and change position','Shake or massage the affected limb','Ensure you move regularly and do not maintain one position for too long','Avoid hyperventilating — breathe slowly and deeply if from anxiety'], whenToSeeDoctor:'Persistent pins and needles without obvious positional cause, affecting multiple areas simultaneously, or accompanied by weakness or coordination problems. B12 and blood sugar testing is the appropriate first step.', urgency:'low' },

  { name:'Facial Twitching', aliases:['facial twitching','facial spasm','hemifacial spasm','cheek twitching','face twitches','involuntary facial movement'], emoji:'🧠', type:'common', description:'Involuntary muscle contractions or twitches in the face. Can affect one side (hemifacial spasm) or specific areas like the cheek or eyelid. Usually benign but can indicate nerve irritation.', symptoms:['Involuntary twitching or spasm of facial muscles','May affect one side of the face or specific muscles','Can be intermittent or persistent','Worsens with fatigue, stress, or caffeine','May be visible to others'], causes:['Benign fasciculation — most common, related to fatigue and caffeine','Hemifacial spasm from facial nerve compression (blood vessel pressing on nerve)','Stress and anxiety','Magnesium deficiency','Tardive dyskinesia from certain medications'], homecare:['Reduce caffeine intake','Ensure adequate sleep (7-9 hours)','Manage stress with relaxation techniques','Magnesium supplement — magnesium glycinate 200-400mg daily','Warm compress to the affected area'], whenToSeeDoctor:'Facial twitching that is persistent (lasting more than 2 weeks), spreading to affect more of the face, or accompanied by facial weakness. Hemifacial spasm responds well to botulinum toxin injections.', urgency:'low' },

  { name:'Jaw Clenching', aliases:['jaw clenching','bruxism awake','teeth clenching','jaw tension','daytime clenching','masseter tension'], emoji:'🧠', type:'common', description:'The involuntary or habitual clenching of the jaw, often without grinding. Can occur during waking hours (awake bruxism) or during sleep. Closely linked to stress and anxiety.', symptoms:['Feeling of tightness or aching in the jaw','Jaw pain especially after stressful periods','Headache often in the temples','Ear pain from jaw muscle tension','Facial pain','Worn teeth from clenching force','Difficulty opening mouth wide'], causes:['Stress and anxiety (primary cause)','Concentration or frustration habits','Sleep disorders','Certain medications (SSRIs)','Caffeine and alcohol'], homecare:['Awareness — consciously check jaw position throughout the day and relax it','Lips together, teeth apart when not eating or speaking — the correct jaw rest position','Stress management — exercise, yoga, and mindfulness reduce clenching','Warm compress to jaw muscles to relax them','Reduce caffeine','Night guard (mouthguard) if clenching during sleep'], whenToSeeDoctor:'Jaw clenching causing significant tooth wear, jaw pain limiting eating, or not responding to lifestyle measures. A dentist can provide a custom night guard and assess tooth damage. Physiotherapy and cognitive behavioral therapy are also effective.', urgency:'low' },

  { name:'Visual Aura', aliases:['visual aura','migraine aura','zigzag lines vision','flashing lights migraine','scotoma','visual disturbance migraine'], emoji:'👁️', type:'common', description:'Temporary visual disturbances that typically precede a migraine headache. Includes zigzag lines, flashing lights, blind spots, or shimmering visual effects. Lasts 20-60 minutes and resolves completely.', symptoms:['Zigzag or shimmering lines in the visual field','Flashing lights or sparks','Temporary blind spot (scotoma) that slowly spreads','Visual disturbances gradually expanding and moving across vision','Resolves completely within 30-60 minutes','Usually followed by headache'], causes:['Cortical spreading depression — a wave of electrical activity across the visual cortex','Part of the migraine complex','Trigger factors — same as migraine: hormonal changes, stress, sleep changes, certain foods'], homecare:['Rest in a quiet, dark room during the aura','Aura itself does not need specific treatment — it resolves on its own','Take migraine medication at onset of aura or headache if prescribed','Stay hydrated','Keep a diary to identify migraine triggers'], whenToSeeDoctor:'First visual aura episode should be evaluated to confirm it is migraine aura and not a TIA. Aura without headache, aura lasting more than an hour, or new-onset aura in an older person or someone on the contraceptive pill needs evaluation.', urgency:'medium' },

  { name:'Phonophobia', aliases:['phonophobia','sound sensitivity','noise sensitivity','sensitive to sounds','hyperacusis','noise hurts ears'], emoji:'🧠', type:'common', description:'Abnormal sensitivity to sound, causing discomfort or pain from sounds that most people find tolerable. Very common during migraine attacks. Can also be a chronic condition.', symptoms:['Pain or discomfort from everyday sounds','Covering ears or seeking quiet environments','Associated with headache during migraines','May avoid social situations due to noise sensitivity','Irritability with background noise'], causes:['Migraine (most common context — phonophobia during attacks)','Hyperacusis — chronic sound sensitivity after noise damage','Anxiety disorders','Post-concussion syndrome','Meniere\'s disease','Certain medications'], homecare:['Use noise-canceling headphones or earplugs during attacks','Rest in a quiet room during migraine','Avoid unnecessarily loud environments','Sound therapy — gradual re-exposure to normal sounds for chronic hyperacusis (with specialist guidance)','Treat underlying migraine to reduce attack-related phonophobia'], whenToSeeDoctor:'Chronic phonophobia significantly affecting daily life should be evaluated by an audiologist (for hyperacusis) or neurologist (for migraine-related). Sound desensitization therapy is effective.', urgency:'low' },

  { name:'Smell Sensitivity', aliases:['smell sensitivity','hyperosmia','sensitive to smells','strong smell intolerance','odor sensitivity','smell causing nausea'], emoji:'👃', type:'common', description:'Heightened sensitivity to odors that are not normally offensive to others. Can cause nausea, headache, or discomfort. Common during pregnancy, migraine, and certain medical conditions.', symptoms:['Strong reaction to odors that do not bother others','Nausea triggered by certain smells','Headache from fragrances or chemicals','Avoidance of people wearing perfume or strong-smelling environments','May worsen migraine attacks'], causes:['Pregnancy (especially first trimester — hormonal)','Migraine — smell sensitivity common before and during attacks','Lyme disease','Hyperthyroidism','Autoimmune conditions','Anxiety disorders','Certain medications'], homecare:['Identify and avoid most problematic odors','Keep living spaces well ventilated','Carry a pleasant scent (lemon, mint) to counteract strong odors','Breathe through the mouth in unavoidable situations','Treat underlying migraine to reduce associated smell sensitivity'], whenToSeeDoctor:'Sudden onset smell sensitivity, associated with other new symptoms, or significantly affecting quality of life. Pregnancy-related hyperosmia usually resolves after the first trimester. Other causes need investigation.', urgency:'low' },

  /* ── COMMON: GENERAL & SYSTEMIC ── */
  { name:'Unexplained Weight Loss', aliases:['unexplained weight loss','unintentional weight loss','losing weight without trying','weight loss no reason','unintended weight loss'], emoji:'⚖️', type:'common', description:'Losing more than 5% of body weight over 6-12 months without intending to. Can be a sign of an underlying medical condition. Always warrants medical evaluation.', symptoms:['Losing weight without dieting or increased exercise','Appetite may be reduced or normal','Fatigue and weakness','Feeling full after eating small amounts'], causes:['Cancer (any type — weight loss is a classic warning sign)','Thyroid overactivity (hyperthyroidism)','Diabetes (especially type 1 or new uncontrolled type 2)','Depression or anxiety','Chronic infections (tuberculosis, HIV)','Gastrointestinal malabsorption (celiac disease, Crohn\'s)','Congestive heart failure','Medication side effects'], homecare:['No specific home management — see a doctor promptly','Keep a food diary to assess actual intake','Note any other associated symptoms to report'], whenToSeeDoctor:'Any unintentional weight loss of more than 5% in 6-12 months should be evaluated by a doctor. Blood tests, examination, and possibly imaging are needed to identify the cause. This is a red flag symptom.', urgency:'high' },

  { name:'Unexplained Weight Gain', aliases:['unexplained weight gain','sudden weight gain','unintentional weight gain','gaining weight without reason','weight gain unknown cause'], emoji:'⚖️', type:'common', description:'Gaining weight without a corresponding increase in caloric intake or decrease in activity. Can be caused by fluid retention, hormonal imbalances, or medication side effects.', symptoms:['Weight gain despite no major dietary changes','Puffiness or swelling especially in face, abdomen, and limbs','Feeling bloated or heavy','Clothes fitting more tightly than usual'], causes:['Hypothyroidism (underactive thyroid) — most common treatable cause','Polycystic ovary syndrome (PCOS) in women','Cushing\'s syndrome (excess cortisol)','Fluid retention from heart, kidney, or liver disease','Insulin resistance or type 2 diabetes','Medications — corticosteroids, antidepressants, antipsychotics, insulin','Menopause'], homecare:['Monitor salt intake — excess salt causes water retention','Reduce refined carbohydrates which contribute to insulin resistance','Regular exercise — both aerobic and strength training','Adequate sleep — sleep deprivation disrupts hunger hormones','Track food intake to ensure diet has not changed unconsciously'], whenToSeeDoctor:'Rapid unexplained weight gain, weight gain with swelling (possible fluid overload), or weight gain with fatigue, cold sensitivity, or hair loss (hypothyroidism). Blood tests including thyroid function should be checked.', urgency:'medium' },

  { name:'Sudden Fatigue', aliases:['sudden fatigue','sudden tiredness','acute fatigue','sudden extreme tiredness','sudden onset fatigue'], emoji:'😴', type:'common', description:'A rapid and unexpected onset of extreme tiredness or exhaustion. Distinguished from chronic fatigue by its acute onset. Can be a symptom of many conditions.', symptoms:['Sudden overwhelming tiredness or exhaustion','May be accompanied by weakness','Difficulty concentrating','May accompany other symptoms depending on the cause'], causes:['Acute viral infection (influenza, COVID-19, Epstein-Barr virus)','Sudden blood sugar drop (hypoglycemia)','Anemia — sudden blood loss or worsening chronic anemia','Dehydration','Cardiac event (sudden fatigue is a cardiac warning sign, especially in women)','Medication side effects','Emotional shock or acute stress'], homecare:['Rest immediately','Eat or drink something if blood sugar drop is possible','Stay well hydrated','Monitor for other accompanying symptoms'], whenToSeeDoctor:'Sudden severe fatigue with chest pain, shortness of breath, or palpitations is a cardiac emergency. Sudden fatigue with high fever needs evaluation. Any unexplained sudden fatigue lasting more than a few days should be seen by a doctor.', urgency:'medium' },

  { name:'Chronic Tiredness', aliases:['chronic tiredness','always tired','persistent tiredness','ongoing fatigue','never feel rested','constant tiredness'], emoji:'😴', type:'common', description:'Persistent tiredness that does not improve with rest and has been present for weeks or months. Very common complaint. Often has an identifiable and treatable cause.', symptoms:['Feeling tired most of the time despite adequate sleep','Fatigue not relieved by rest','Difficulty performing daily activities','Reduced motivation','Brain fog and poor concentration','Irritability'], causes:['Iron deficiency anemia (most common treatable cause)','Hypothyroidism','Vitamin D or B12 deficiency','Sleep disorders — sleep apnea, insomnia','Depression or anxiety','Chronic infections','Diabetes','Chronic fatigue syndrome (ME/CFS)'], homecare:['Blood tests to identify a treatable cause — this is essential','Improve sleep hygiene — regular sleep schedule, dark cool room','Regular moderate exercise (paradoxically improves energy)','Eat iron-rich and nutrient-dense foods','Limit alcohol and caffeine','Stress management'], whenToSeeDoctor:'Chronic tiredness lasting more than 4 weeks always warrants a medical evaluation and blood tests (full blood count, thyroid function, iron studies, vitamin D, B12, glucose). Most causes are treatable.', urgency:'medium' },

  { name:'Low Energy', aliases:['low energy','lack of energy','no energy','low vitality','energy drain','feeling drained'], emoji:'😴', type:'common', description:'A general sense of reduced physical and mental energy affecting ability to perform usual activities. Very common and usually has lifestyle or medical causes that can be addressed.', symptoms:['Feeling physically drained','Low motivation','Exercise capacity reduced','Feel tired during activities that were previously easy','Difficulty getting through the day'], causes:['Poor sleep quality or quantity','Sedentary lifestyle (inactivity worsens fatigue)','Nutritional deficiencies','Dehydration','Stress and overcommitment','Depression','Thyroid underactivity','Anemia'], homecare:['Regular moderate exercise — the strongest evidence-based intervention for low energy','Improve sleep habits','Eat regular balanced meals — avoid skipping meals','Stay well hydrated throughout the day','Reduce alcohol and sugar consumption','Address stress and mental health'], whenToSeeDoctor:'Low energy lasting more than 4 weeks, significantly affecting daily function, or accompanied by other symptoms. Blood tests to check thyroid, iron, B12, vitamin D, and blood glucose are a useful starting point.', urgency:'low' },

  { name:'Low Grade Fever', aliases:['low grade fever','slight fever','mild fever','low temperature fever','mild temperature elevation'], emoji:'🌡️', type:'common', description:'A body temperature slightly above normal — typically 37.5-38.3°C (99.5-101°F) — but below a high fever threshold. Often the body\'s response to infection or inflammation. Commonly accompanies viral illness.', symptoms:['Mildly elevated temperature','Mild fatigue and malaise','Slight chills or warmth','Mild sweating','Reduced appetite','Mild headache'], causes:['Viral infections — cold, flu, COVID-19 (most common)','Bacterial infections','Post-vaccination response','Autoimmune conditions — lupus, rheumatoid arthritis','Medications','Inflammatory conditions','Heat exhaustion'], homecare:['Rest and stay hydrated — drink extra fluids','Dress lightly and avoid excessive blankets','Cool compress to forehead','Paracetamol or ibuprofen if fever is causing discomfort','Monitor temperature every few hours'], whenToSeeDoctor:'Low grade fever lasting more than 2-3 weeks without obvious cause (fever of unknown origin), fever in an infant under 3 months (any fever is an emergency), fever with rash, stiff neck, or confusion.', urgency:'medium' },

  { name:'Night Sweats', aliases:['night sweats','sweating at night','waking up sweating','nocturnal sweating','sleep sweats'], emoji:'💧', type:'common', description:'Episodes of excessive sweating during sleep, drenching nightclothes and bedding, beyond what can be explained by a hot room. Can be caused by hormonal changes or underlying medical conditions.', symptoms:['Waking up drenched in sweat','Needing to change bedclothes or sheets','Feeling hot and clammy during sleep','May be accompanied by rapid heart rate','Not explained by a hot sleeping environment'], causes:['Menopause (most common cause in women — hot flushes at night)','Infections — tuberculosis, HIV, endocarditis','Certain cancers (lymphoma — night sweats are a B symptom)','Medications — antidepressants, tamoxifen, steroids','Hyperthyroidism','Diabetes (nocturnal hypoglycemia)','Anxiety'], homecare:['Wear lightweight, breathable sleepwear (cotton or moisture-wicking)','Keep the bedroom cool (18-20°C is ideal for sleep)','Use breathable bedding — light layers rather than heavy duvets','Avoid alcohol, caffeine, and spicy food in the evening','Cool shower before bed','Hormone replacement therapy for menopausal night sweats (discuss with doctor)'], whenToSeeDoctor:'Night sweats with fever, unintentional weight loss, or swollen lymph nodes (possible lymphoma or infection). Persistent night sweats not explained by menopause need investigation with blood tests.', urgency:'medium' },

  { name:'Hot Flashes', aliases:['hot flashes','hot flushes','menopausal flushes','hot flush','vasomotor symptoms menopause'], emoji:'🌡️', type:'common', description:'Sudden feelings of warmth or intense heat, usually in the face, neck, and chest, often accompanied by flushing and sweating. The most common symptom of menopause.', symptoms:['Sudden intense warmth in face, neck, and chest','Visible reddening of skin','Profuse sweating following the hot feeling','Chills or cold feeling after the flush','Rapid heartbeat during the episode','Episodes lasting 1-5 minutes typically'], causes:['Menopause and perimenopause (most common cause)','Surgical menopause (oophorectomy)','Certain medications — antidepressants, opioids, tamoxifen, GnRH analogues','Carcinoid syndrome (rare tumor)','Male hypogonadism'], homecare:['Identify and avoid personal triggers — hot drinks, spicy food, alcohol, hot showers, stress','Dress in layers to be able to cool down quickly','Keep bedroom cool at night','Fan or cold water spray for immediate relief','Relaxation techniques — paced breathing during episodes reduces severity','Regular aerobic exercise reduces frequency and severity over time'], whenToSeeDoctor:'Hot flashes significantly affecting quality of life, sleep, or work. Hormone replacement therapy (HRT) is the most effective treatment. Non-hormonal options are available for those who cannot take HRT.', urgency:'low' },

  { name:'Cold Sweats', aliases:['cold sweats','clammy sweating','cold and sweaty','cold perspiration','cold sweat'], emoji:'💧', type:'common', description:'Sudden cold, clammy sweating not related to heat or exertion. Often a stress response or symptom of a serious underlying condition. The combination of cold and sweating is important to recognize.', symptoms:['Feeling cold while sweating','Clammy, moist skin','Pallor (pale appearance)','May be associated with dizziness or nausea','Heart pounding or racing'], causes:['Intense anxiety or panic attack (most common)','Hypoglycemia (low blood sugar — important cause in diabetics)','Shock (from blood loss, cardiac or allergic events)','Cardiac event (heart attack — a key warning sign)','Severe infection or sepsis','Medication or withdrawal effects'], homecare:['For anxiety-related cold sweats — slow breathing, lie down, calm environment','For possible low blood sugar — drink fruit juice or eat glucose tablets','Note all accompanying symptoms carefully'], whenToSeeDoctor:'Cold sweats with chest pain, shortness of breath, palpitations, or loss of consciousness require emergency care immediately. Cold sweats with dizziness and known diabetes — treat hypoglycemia urgently.', urgency:'high' },

  { name:'Excessive Thirst', aliases:['excessive thirst','polydipsia','always thirsty','increased thirst','unquenchable thirst','drinking more water'], emoji:'💧', type:'common', description:'Unusual or persistent thirst despite drinking adequate fluids. A classic symptom of diabetes. Should not be ignored, especially if accompanied by frequent urination.', symptoms:['Thirst that is not satisfied by normal drinking','Drinking unusually large amounts of fluid','Dry mouth even after drinking','Accompanied by frequent urination (classic diabetes pair)','Fatigue','Blurred vision (if diabetes)'], causes:['Diabetes mellitus (type 1 or type 2) — most important cause to exclude','Diabetes insipidus — problems with water regulation','Dehydration','High salt or sugar diet','Certain medications (diuretics, lithium)','Hypercalcemia (elevated calcium)','Psychogenic polydipsia (excessive drinking related to mental health)'], homecare:['Sip water regularly throughout the day rather than gulping large amounts','Reduce salt and sugar in diet','Avoid excessive caffeine and alcohol which are dehydrating'], whenToSeeDoctor:'Excessive thirst always warrants a blood glucose test and urine test to check for diabetes. Especially urgent if accompanied by frequent urination, weight loss, fatigue, or blurred vision.', urgency:'medium' },

  { name:'Excessive Hunger', aliases:['excessive hunger','polyphagia','always hungry','increased appetite','constant hunger','insatiable appetite'], emoji:'🍽️', type:'common', description:'An increased or insatiable appetite, often referred to as polyphagia. Can be a normal response to increased activity or can indicate a medical condition, particularly diabetes or hyperthyroidism.', symptoms:['Feeling hungry even after meals','Eating more than usual','Never feeling satisfied','May or may not be associated with weight gain or loss','Fatigue or weakness alongside hunger'], causes:['Uncontrolled diabetes (glucose cannot enter cells — body signals starvation)','Hyperthyroidism — increased metabolism burns more energy','Pregnancy','Medications — corticosteroids, antidepressants, antipsychotics','Emotional eating from stress or anxiety','Premenstrual syndrome (food cravings)','Tapeworm or intestinal parasites (rare)'], homecare:['Regular balanced meals with adequate protein, fiber, and healthy fat reduce hunger signals','Do not skip meals — this causes hunger surges','Manage stress eating with mindful eating practices','Stay hydrated — thirst is often mistaken for hunger','Blood sugar monitoring if diabetic'], whenToSeeDoctor:'Excessive hunger with weight loss, fatigue, thirst, or frequent urination needs blood tests to check blood glucose and thyroid function. These combinations suggest diabetes or hyperthyroidism.', urgency:'medium' },

  { name:'Frequent Urination at Night', aliases:['nocturia','waking to urinate','frequent night urination','urinating at night','getting up to pee','night time urination'], emoji:'🚽', type:'common', description:'Waking up two or more times per night to urinate (nocturia). Very common in older adults. Can significantly disrupt sleep and reduce quality of life.', symptoms:['Waking up 2 or more times per night to urinate','Disrupted sleep','Daytime fatigue from poor sleep','Larger than usual urine volumes at night'], causes:['Enlarged prostate in men (most common cause in men)','Diuretic medications taken in the evening','Excessive fluid intake before bed (especially caffeine or alcohol)','Diabetes (high blood sugar causes polyuria)','Heart failure causing fluid redistribution when lying down','Bladder overactivity','Sleep apnea (increases urine production at night)','Aging — kidneys less able to concentrate urine at night'], homecare:['Reduce fluid intake in the 2-3 hours before bedtime','Avoid alcohol and caffeine in the evening','Take diuretic medications in the morning rather than evening (discuss with doctor)','Elevate legs in the afternoon — reduces fluid accumulation that is later redistributed at night','Treat sleep apnea if present'], whenToSeeDoctor:'Nocturia 2 or more times per night, especially if combined with urgency, difficulty starting urination, or weak stream. Investigation can identify treatable causes.', urgency:'medium' },

  { name:'Bedwetting in Adults', aliases:['bedwetting adults','adult bedwetting','nocturnal enuresis adults','urinary incontinence sleep','wetting bed adult'], emoji:'🚽', type:'common', description:'Involuntary urination during sleep in adults. Affects about 1-2% of adults. Can be very distressing but is often treatable.', symptoms:['Waking up having urinated in bed','May be unaware during sleep','Normal bladder control when awake'], causes:['Overactive bladder','Urinary tract infection','Diabetes — high urine output','Sleep apnea — prevents normal waking response to bladder fullness','Neurological conditions','Constipation — full bowel presses on bladder','Emotional stress or psychological factors','Certain medications','Alcohol — suppresses ADH hormone and causes heavy sleep'], homecare:['Avoid fluids for 2-3 hours before bed','Empty bladder twice before sleep — the last time right before sleeping','Set an alarm to wake and use the bathroom at a strategic time','Reduce alcohol consumption','Treat constipation if present','Incontinence pads as a temporary measure while seeking treatment'], whenToSeeDoctor:'All adults with bedwetting should see a doctor for evaluation. Urodynamic studies, blood tests, and urine tests can identify the cause. Many effective treatments are available including medication and bladder training.', urgency:'medium' },

  { name:'Involuntary Urination', aliases:['involuntary urination','urinary incontinence','leaking urine','stress incontinence','urge incontinence','bladder leakage'], emoji:'🚽', type:'common', description:'The involuntary leakage of urine. Very common — affects 1 in 3 women at some point and 1 in 10 men. Often undertreated because people feel embarrassed. Very treatable.', symptoms:['Urine leakage when coughing, sneezing, laughing, or exercising (stress incontinence)','Sudden strong urge to urinate followed by leakage before reaching the toilet (urge incontinence)','Frequent and urgent need to urinate','Leakage during sleep (nocturnal enuresis)'], causes:['Weakened pelvic floor muscles — pregnancy, childbirth, aging','Overactive bladder muscles','Enlarged prostate (in men)','Urinary tract infection','Neurological conditions — multiple sclerosis, Parkinson\'s, stroke','Certain medications — diuretics, antidepressants'], homecare:['Pelvic floor exercises (Kegel exercises) — the most effective first-line treatment','Bladder training — gradually extending time between toilet visits','Reduce caffeine and alcohol which irritate the bladder','Maintain a healthy weight — obesity worsens stress incontinence','Bladder diary to identify patterns'], whenToSeeDoctor:'Urinary incontinence always warrants evaluation as it is very treatable. Specialist physiotherapy for pelvic floor is highly effective. Medication, devices, and surgery are also available for appropriate cases.', urgency:'medium' },

  { name:'Difficulty Urinating', aliases:['difficulty urinating','urinary hesitancy','trouble urinating','weak urine flow','straining to urinate','slow urine flow'], emoji:'🚽', type:'common', description:'Difficulty starting or maintaining urination, including a weak stream or sense of incomplete emptying. Common in men with an enlarged prostate. In anyone, can indicate a UTI or other condition.', symptoms:['Difficulty starting urination (hesitancy)','Weak or interrupted urine stream','Straining to urinate','Sensation of incomplete bladder emptying','Dribbling at the end of urination','In severe cases — inability to urinate at all (retention)'], causes:['Enlarged prostate (BPH) in men over 50 (most common cause in men)','Urethral stricture — narrowing of the urethra','Urinary tract infection','Constipation — full bowel compresses urethra','Bladder dysfunction — neurogenic bladder','Certain medications — antihistamines, antidepressants'], homecare:['Relax and allow extra time for urination — do not rush','Warm bath may help relax the urethral sphincter','Double voiding — wait a minute after urinating and try again','Stay well hydrated — concentrated urine is more irritating','Avoid caffeine and alcohol'], whenToSeeDoctor:'Inability to urinate at all is a urological emergency — requires immediate catheterization. Chronic difficulty urinating should be assessed. Men over 50 should have a prostate examination.', urgency:'high' },

  { name:'Weak Urine Stream', aliases:['weak urine stream','poor urine flow','weak stream urine','slow urine stream','reduced urine flow'], emoji:'🚽', type:'common', description:'A noticeable reduction in urine flow rate. Very common in men with an enlarged prostate. In women, can indicate bladder dysfunction or pelvic floor weakness.', symptoms:['Reduced force of urine stream','May need to strain to maintain flow','Stream stops and starts','Incomplete emptying sensation','Takes longer to urinate than before'], causes:['Benign prostatic hyperplasia (BPH) — enlarged prostate in men','Urethral stricture','Bladder outlet obstruction','Bladder muscle dysfunction','In women — pelvic organ prolapse or pelvic floor dysfunction'], homecare:['Allow extra time for urination without rushing','Double voiding technique','Avoid constipation — straining with bowels worsens urinary flow','Reduce caffeine and alcohol','Pelvic floor exercises for women'], whenToSeeDoctor:'A newly developed or progressively worsening weak stream should be evaluated, especially in men over 50. Urinary flow rate testing and ultrasound of the bladder can assess the problem. Treatments for BPH are very effective.', urgency:'medium' },

  { name:'Foamy Urine', aliases:['foamy urine','bubbly urine','frothy urine','urine with bubbles','protein in urine'], emoji:'🚽', type:'common', description:'Urine that appears foamy or frothy. Occasional foamy urine from a fast urine stream is normal. Persistent foamy urine can indicate protein in the urine — a possible sign of kidney disease.', symptoms:['Urine that looks foamy or bubbly', 'Bubbles that persist and do not disappear quickly (unlike normal bubbles from a fast stream)','May be accompanied by swelling (ankles, feet, face) if kidney disease'], causes:['Concentrated urine from dehydration — most common benign cause','Fast urine stream causing air bubbles (usually disappears quickly)','Proteinuria — protein in urine (kidney disease, diabetes, high blood pressure)','Retrograde ejaculation in men (semen enters urine)'], homecare:['Drink more water — dehydration is the most common benign cause','Monitor whether foaminess persists after increased hydration'], whenToSeeDoctor:'Persistent foamy urine not explained by dehydration, especially with ankle or face swelling, should be tested with a urine dipstick for protein. Proteinuria requires further investigation of kidney function.', urgency:'medium' },

  { name:'Blood in Urine', aliases:['blood in urine','haematuria','hematuria','pink urine','red urine','bloody urine'], emoji:'🚽', type:'common', description:'The presence of blood in the urine, making it pink, red, or cola-colored. Always requires medical evaluation even if it occurs only once, as it can indicate serious conditions.', symptoms:['Urine that is pink, red, or dark brown','Blood may be visible (gross hematuria) or only detectable on testing (microscopic)','May or may not be painful (painless hematuria is particularly important to investigate)','Associated symptoms depend on cause'], causes:['Urinary tract infection — most common cause of blood in urine in young women','Kidney stones — blood with loin-to-groin pain','Bladder cancer — most common in smokers, usually painless bleeding','Kidney disease or glomerulonephritis','Enlarged prostate or prostate cancer','Strenuous exercise','Anticoagulant medications'], homecare:['Stay well hydrated','Do not take aspirin or NSAIDs which can worsen bleeding','Seek medical evaluation promptly — this is not a condition to manage at home'], whenToSeeDoctor:'Blood in urine should always be investigated by a doctor, even if it only happens once. Painless visible blood in urine in a person over 40, especially a smoker, requires urgent investigation. Urine testing, imaging, and cystoscopy may be needed.', urgency:'high' },

  { name:'Painful Urination', aliases:['painful urination','dysuria','burning when urinating','stinging when urinating','pain while peeing','burning urination'], emoji:'🚽', type:'common', description:'Pain, burning, or stinging when urinating. Usually a sign of a urinary tract infection. Very common, especially in women. Can also indicate a sexually transmitted infection or kidney stone.', symptoms:['Burning or stinging sensation when urinating','Pain during or just after urination','Frequent urge to urinate','Cloudy or strong-smelling urine','Lower abdominal pain or pelvic discomfort'], causes:['Urinary tract infection — bacteria in the bladder (most common cause)','Urethritis — sexually transmitted infection (chlamydia, gonorrhea)','Kidney stones — as they pass through the ureter','Vaginal infections (yeast or bacterial vaginosis)','Prostatitis in men','Interstitial cystitis (chronic bladder condition)'], homecare:['Drink plenty of water to dilute urine and flush bacteria','Avoid caffeine and alcohol which irritate the bladder','Apply heat pad to lower abdomen for pain relief','Cranberry products (evidence is limited but safe to try)','Avoid bath products and soaps in the genital area during infection'], whenToSeeDoctor:'Painful urination almost always warrants a urine test and may require antibiotics for UTI. See a doctor promptly if also have fever, back pain, or are pregnant. STI testing if relevant. Symptoms not improving in 2-3 days need reassessment.', urgency:'medium' },

  { name:'Lower Abdominal Pain', aliases:['lower abdominal pain','lower stomach pain','pelvic pain','lower belly pain','abdominal pain below navel'], emoji:'🤢', type:'common', description:'Pain in the lower portion of the abdomen below the navel. Has many possible causes ranging from constipation to appendicitis. The cause often depends on whether it is acute or chronic, and the patient\'s age and sex.', symptoms:['Pain or cramping below the navel','May be constant or cramping','Pain may radiate to the back, groin, or thigh','Associated symptoms vary by cause — nausea, fever, urinary symptoms, bowel changes'], causes:['Constipation (most common benign cause)','Irritable bowel syndrome','Urinary tract infection','Menstrual cramps in women','Appendicitis (right lower — emergency)','Ovarian cyst or ectopic pregnancy (women)','Hernia (groin)','Diverticulitis (in older adults)'], homecare:['Treat constipation with fiber and hydration','Warm compress for menstrual cramps','OTC pain relief for mild cramps','Monitor symptoms carefully — if worsening, seek care'], whenToSeeDoctor:'Sudden severe lower abdominal pain requires emergency evaluation. Lower abdominal pain with fever, vomiting, or significant worsening over hours. Any woman of childbearing age with lower abdominal pain and a missed period needs urgent assessment (ectopic pregnancy).', urgency:'medium' },

  { name:'Pelvic Pain', aliases:['pelvic pain','pelvic discomfort','chronic pelvic pain','pain in pelvis','lower pelvic pain'], emoji:'🌸', type:'common', description:'Pain in the lowest part of the abdomen and pelvis. In women, can be related to gynecological conditions. In men, often related to the prostate or bladder. Chronic pelvic pain significantly affects quality of life.', symptoms:['Constant or intermittent pain in the pelvic region','Heaviness or pressure in the pelvis','Pain that may worsen with sitting, intercourse, or bowel movements','May be associated with urinary or bowel symptoms','In women: pain related to menstrual cycle'], causes:['In women: endometriosis (most common), fibroids, ovarian cysts, pelvic inflammatory disease, vulvodynia','In men: prostatitis, pelvic floor dysfunction','In both: irritable bowel syndrome, interstitial cystitis, pelvic floor dysfunction, psychological factors'], homecare:['Heat to the lower abdomen and pelvis for comfort','OTC pain relievers','Pelvic floor physiotherapy (very effective for musculoskeletal causes)','Mindfulness and pain management techniques for chronic pelvic pain','Regular gentle exercise'], whenToSeeDoctor:'All new or unexplained pelvic pain should be evaluated. Sudden severe pelvic pain is an emergency in women (ectopic pregnancy, ovarian torsion). Chronic pelvic pain significantly benefits from specialist evaluation.', urgency:'medium' },

  { name:'Groin Swelling', aliases:['groin swelling','inguinal lump','lump in groin','swollen groin lymph nodes','inguinal lymphadenopathy'], emoji:'🏥', type:'common', description:'A swelling or lump in the groin area. Has several common causes including lymph node swelling, hernia, or a cyst. Some causes require urgent treatment.', symptoms:['Visible or palpable lump or swelling in the groin','May be tender or painless','May increase in size with coughing or standing (hernia)','Firmness varies by cause'], causes:['Enlarged inguinal lymph nodes (from infection in leg or foot, or STI)','Inguinal hernia — bowel or tissue through the muscle wall','Femoral hernia (more common in women)','Lipoma or sebaceous cyst','Undescended testis (in young males)'], homecare:['Do not ignore any new lump in the groin — it needs evaluation','A hernia that becomes hard, tender, and cannot be pushed back — seek emergency care immediately'], whenToSeeDoctor:'All new groin swellings should be assessed to identify the cause. A hard, fixed, or rapidly growing lump needs urgent evaluation. A tender, irreducible hernia is a surgical emergency.', urgency:'medium' },

  { name:'Body Swelling', aliases:['body swelling','generalized edema','generalized swelling','swollen body','whole body swelling'], emoji:'💧', type:'common', description:'Swelling affecting multiple parts of the body. Generalized swelling usually indicates a systemic condition involving the heart, kidneys, or liver, or can be related to medications.', symptoms:['Puffiness or swelling in multiple areas — ankles, face, abdomen','Skin that dents when pressed','Weight gain from fluid retention','Shortness of breath if lungs are affected (pulmonary edema)','Reduced urine output'], causes:['Heart failure — fluid backing up into tissues','Kidney disease — inability to excrete fluid and salt','Liver disease (cirrhosis) — low albumin causes fluid loss from blood','Severe protein deficiency','Hypothyroidism (myxedema — non-pitting swelling)','Medications — calcium channel blockers, corticosteroids'], homecare:['Low salt diet to reduce fluid retention','Elevate swollen limbs when at rest','Compression garments for limb swelling','Take prescribed diuretics as directed'], whenToSeeDoctor:'Generalized body swelling always requires medical evaluation. Swelling with shortness of breath is an emergency. Rapid assessment of cardiac, renal, and hepatic function is essential to identify the underlying cause.', urgency:'high' },

  { name:'Hand Swelling', aliases:['swollen hands','hand swelling','puffy hands','hands swelling','finger and hand swelling'], emoji:'🤲', type:'common', description:'Swelling of the hands or fingers. Can result from injury, inflammation, fluid retention, or systemic disease. Morning hand swelling that improves with movement may indicate inflammatory arthritis.', symptoms:['Visible swelling of hands or fingers','Rings become difficult to remove','Stiffness — especially in the morning','Pain and warmth if inflammatory cause','Pitting if edematous cause'], causes:['Rheumatoid arthritis (morning stiffness and symmetric hand swelling)','Injury or sprain','Fluid retention from dietary or systemic causes','Carpal tunnel syndrome (hands feel swollen but may not be visibly so)','Hot weather or physical exertion','Pregnancy','Medications'], homecare:['Remove rings from swollen hands promptly','Elevate hands when resting','Reduce salt intake','Exercise hands and fingers — clenching and extending helps fluid movement','Cold compress for injury-related swelling'], whenToSeeDoctor:'New persistent hand swelling, especially morning stiffness and symmetric swelling of finger joints (possible rheumatoid arthritis — early treatment prevents joint damage). Swelling after injury may need X-ray.', urgency:'medium' },

  { name:'Foot Swelling', aliases:['swollen feet','foot swelling','puffy feet','feet swelling','edema feet'], emoji:'🦶', type:'common', description:'Swelling of one or both feet. Very common, especially after long periods of standing or sitting, or in warm weather. Can indicate a serious underlying condition when severe or persistent.', symptoms:['Visible swelling of the foot or feet','Skin feels tight or stretched','Shoes fit more tightly than usual','May be tender','Pitting edema — skin stays indented when pressed'], causes:['Prolonged standing or sitting (most common benign cause)','Hot weather','Pregnancy','Varicose veins and poor venous return','Heart, kidney, or liver disease','Lymphedema','Deep vein thrombosis (one foot — emergency if with calf pain)','Medications'], homecare:['Elevate feet above heart level for 20-30 minutes several times a day','Wear compression stockings','Reduce salt intake','Regular exercise — walking or calf raises improve venous return','Avoid prolonged standing — take movement breaks'], whenToSeeDoctor:'One foot suddenly swelling more than the other with calf pain (possible DVT — emergency). Bilateral foot swelling with shortness of breath (heart failure — urgent). Persistent swelling without obvious cause needs evaluation.', urgency:'medium' },

  { name:'Face Swelling', aliases:['face swelling','facial swelling','swollen face','puffy face','facial edema','swelling in face'], emoji:'💧', type:'common', description:'Swelling or puffiness of the face. Can range from mild morning puffiness to severe swelling requiring emergency treatment (anaphylaxis).', symptoms:['Puffiness or visible swelling of the face','May affect eyes, cheeks, lips, or entire face','Tender or non-tender depending on cause','May be accompanied by pain, redness, or difficulty breathing'], causes:['Allergic reaction — insect sting, food, or medication (angioedema)','Dental abscess or infection','Facial cellulitis (skin infection)','Sinusitis (mild facial fullness)','Morning puffiness from fluid redistribution during sleep (benign)','Thyroid underactivity (myxedema)','Kidney disease','Corticosteroid use'], homecare:['For mild morning puffiness — sleep on back with head elevated, reduce salt and alcohol','Cold compress to reduce mild swelling','For allergic reaction — antihistamine for mild swelling'], whenToSeeDoctor:'Sudden or rapidly worsening face swelling — possible anaphylaxis — call an ambulance if breathing is difficult. Face swelling from a dental abscess or cellulitis needs urgent antibiotic treatment. Any unexplained progressive facial swelling needs evaluation.', urgency:'high' },

  { name:'Puffy Face in Morning', aliases:['puffy face morning','morning puffiness','face puffy on waking','swollen face morning','morning facial swelling'], emoji:'💧', type:'common', description:'Facial puffiness that is worse upon waking and improves throughout the day. Very common and usually benign, caused by fluid redistributing when lying flat during sleep.', symptoms:['Face appears puffy or swollen on waking','Particularly around the eyes and cheeks','Improves within 1-2 hours of being upright and moving around','More noticeable on mornings after salty food or alcohol'], causes:['Gravity — fluid distributes to the face when lying flat (most common benign cause)','Salty dinner or evening snack — water retention','Alcohol consumption — causes water retention and puffiness','Lack of sleep or disrupted sleep','Allergic reaction to pillow or bedding (latex or feathers)','Hypothyroidism — causes a myxedematous puffy face appearance'], homecare:['Sleep with head slightly elevated','Reduce salt and alcohol intake, especially in the evening','Cold compress or cold water splash on waking to reduce puffiness','Sleep on your back rather than stomach or side','Stay well hydrated throughout the day'], whenToSeeDoctor:'Persistent or worsening facial puffiness that does not resolve by midday, puffiness with fatigue and weight gain (possible thyroid), or puffiness with difficulty breathing.', urgency:'low' },

  { name:'Eye Bags', aliases:['eye bags','bags under eyes','under eye bags','puffy under eyes','under eye puffiness'], emoji:'👁️', type:'common', description:'Puffiness or swelling under the eyes giving a baggy appearance. Common and usually cosmetic, though can occasionally indicate a medical condition.', symptoms:['Puffiness or sagging skin below the eyes','May be accompanied by dark circles','Usually more noticeable in the morning','May appear worse with age'], causes:['Aging — fat pads under the eyes shift and prolapse forward','Fluid retention (from salt, alcohol, poor sleep)','Genetics — runs in families','Allergies causing inflammation and fluid retention','Thyroid disease or kidney disease (less common systemic causes)'], homecare:['Cold compress — chilled spoons or cucumber slices reduce puffiness temporarily','Elevate head when sleeping','Reduce salt and alcohol intake','Use eye cream with caffeine or retinol to improve skin tone over time','Address underlying allergies','Adequate sleep'], whenToSeeDoctor:'Eye bags are usually cosmetic and do not require medical treatment. Sudden significant new swelling under the eyes, especially with other swelling (face, ankles), may warrant assessment for kidney or thyroid disease. Cosmetic options include fillers and surgery.', urgency:'low' },

  { name:'General Itching without Rash', aliases:['itching without rash','pruritus','unexplained itching','generalized itching','itch without skin rash','body itching no rash'], emoji:'🔴', type:'common', description:'Widespread or localized itching of the skin without visible rash or skin changes. Medically called pruritus sine materia. Can be very distressing and disrupt sleep.', symptoms:['Persistent or recurrent itching','No visible rash in the itching area','Skin may be normal-looking or slightly excoriated from scratching','May be worse at night','Can affect any part of the body'], causes:['Dry skin (most common cause — especially in elderly and in winter)','Iron deficiency anemia','Kidney disease (uremia)','Liver disease (bile salts accumulate in skin)','Thyroid disorders','Certain medications (ACE inhibitors, opioids, some antibiotics)','Lymphoma or other cancers (especially Hodgkin\'s lymphoma)','Psychological (anxiety, obsessive itching)','Pregnancy cholestasis (itching without rash in pregnancy)'], homecare:['Moisturize regularly with thick, fragrance-free cream — most important for dry skin-related itching','Avoid hot showers — use lukewarm water and gentle non-soap cleanser','Wear loose, soft cotton clothing','Antihistamine at bedtime for sleep disturbance from itching','Cool compress for localized itching','Avoid caffeine, alcohol, and spicy food which can worsen itching'], whenToSeeDoctor:'Persistent unexplained itching lasting more than 2 weeks, widespread itching especially in an older adult, itching in pregnancy (especially after 28 weeks), or itching with jaundice, weight loss, night sweats. Blood tests to check iron, liver, kidney, and thyroid are essential.', urgency:'medium' },

  /* ── COMMON: WOMEN SPECIFIC ── */
  { name:'Missed Period', aliases:['missed period','absent period','no period','amenorrhea','late period missed','skipped period'], emoji:'🌸', type:'common', description:'The absence of an expected menstrual period. Primary amenorrhea is when periods have never started by age 16. Secondary amenorrhea is when established periods stop for 3 or more months. Pregnancy is the most common cause in a sexually active person.', symptoms:['No menstrual bleeding at the expected time','May be accompanied by breast tenderness and nausea (pregnancy)','Other symptoms depend on underlying cause','In hypothalamic amenorrhea: weight loss, excessive exercise, and stress'], causes:['Pregnancy (must always be excluded first)','Extreme stress or significant emotional distress','Significant weight loss or low body fat','Excessive exercise','Hormonal imbalances — PCOS, thyroid disease, hyperprolactinemia','Menopause or premature ovarian insufficiency','Contraceptive medications (especially progestogen-only pill and implant)'], homecare:['Take a pregnancy test if there is any possibility of pregnancy','Reduce excessive exercise if over-exercising','Improve nutrition if weight is very low','Manage stress levels'], whenToSeeDoctor:'Any woman who has missed 3 consecutive periods should see a doctor. Pregnancy should be excluded first. A missed period with negative pregnancy test, or primary amenorrhea by age 16, requires investigation.', urgency:'medium' },

  { name:'Late Period', aliases:['late period','period is late','delayed period','period coming late','menstrual delay'], emoji:'🌸', type:'common', description:'A menstrual period arriving later than expected. Defined as more than 5 days late for those with regular cycles. Very common and usually not serious. Pregnancy is the most important cause to exclude.', symptoms:['Period has not started at the usual expected time','May have mild cramping without bleeding','Breast tenderness','Nausea if pregnant'], causes:['Pregnancy (most important to exclude)','Stress or anxiety','Significant changes in weight or diet','Over-exercising','Thyroid disorders','PCOS','Approaching menopause (perimenopause)','Recent illness'], homecare:['Take a pregnancy test if sexually active — even if using contraception','Manage stress if this is the suspected cause','Ensure adequate caloric intake if dieting or exercising heavily'], whenToSeeDoctor:'A period more than 5-7 days late should prompt a pregnancy test. If the test is negative and periods continue to be irregular or absent for 3 or more months, see a doctor for investigation.', urgency:'low' },

  { name:'Spotting Between Periods', aliases:['spotting between periods','intermenstrual bleeding','breakthrough bleeding','mid cycle bleeding','spotting mid cycle'], emoji:'🌸', type:'common', description:'Light vaginal bleeding between menstrual periods. Very common and has many causes, from hormonal contraception to infection. Should always be evaluated to exclude serious causes.', symptoms:['Light bleeding or spotting outside of the normal menstrual period','Bleeding may be pink, brown, or red','May or may not be accompanied by pelvic pain','Normal periods otherwise continue around the spotting'], causes:['Hormonal contraception (most common — breakthrough bleeding with the pill or IUD)','Ovulation spotting (normal in some women)','Cervical infection or cervicitis','Cervical polyp','Endometrial polyp','Cervical or uterine cancer (rare — must be excluded)','Pregnancy — implantation bleeding or ectopic pregnancy'], homecare:['Note timing, amount, color, and any associated symptoms','If on hormonal contraception — this often improves after 3 months','Ensure you are taking the pill consistently without missed doses'], whenToSeeDoctor:'Any new unexplained spotting should be evaluated with a pelvic examination and cervical smear. Spotting with pelvic pain in a sexually active woman needs urgent assessment to exclude ectopic pregnancy.', urgency:'medium' },

  { name:'Painful Periods', aliases:['painful periods','dysmenorrhea','severe period pain','period cramps severe','primary dysmenorrhea'], emoji:'🌸', type:'common', description:'Significant pain during menstruation that interferes with daily activities. Affects up to 80% of women at some point. Primary dysmenorrhea has no underlying cause; secondary dysmenorrhea is caused by a condition such as endometriosis.', symptoms:['Cramping pain in lower abdomen starting 1-3 days before or with the onset of the period','Pain may radiate to lower back and thighs','Nausea and vomiting','Headache','Diarrhea','Dizziness'], causes:['Primary dysmenorrhea — excess prostaglandins causing strong uterine contractions','Secondary dysmenorrhea — endometriosis (most common), fibroids, adenomyosis, pelvic inflammatory disease'], homecare:['Ibuprofen or naproxen started 1-2 days before expected period and taken regularly for the first 2-3 days — significantly more effective than paracetamol','Heat pad on lower abdomen — as effective as OTC pain relief','Light exercise during the period reduces pain for many women','Warm bath','Magnesium supplementation may reduce pain'], whenToSeeDoctor:'Period pain that is severe enough to prevent normal daily activities, getting progressively worse over time, or not responding to ibuprofen. These features suggest secondary dysmenorrhea which needs investigation and treatment.', urgency:'medium' },

  { name:'Very Heavy Periods', aliases:['very heavy periods','heavy menstrual bleeding severe','flooding periods','soaking pads every hour','menorrhagia severe'], emoji:'🌸', type:'common', description:'Menstrual bleeding that is abnormally heavy, prolonged, or both. Defined as blood loss affecting quality of life. Can cause iron deficiency anemia. See Heavy Periods entry for standard menorrhagia.', symptoms:['Soaking through one pad or tampon per hour for several consecutive hours','Needing double protection','Passing blood clots larger than 50p/50 rupee coin','Bleeding lasting longer than 7 days','Symptoms of anemia — extreme fatigue, pallor, shortness of breath'], causes:['Uterine fibroids or polyps','Adenomyosis — endometrial tissue in uterine wall','Hormonal imbalance','Blood clotting disorders (von Willebrand disease)','Thyroid disorders','IUD (especially copper coil)'], homecare:['Track blood loss accurately to report to doctor','Iron-rich foods and supplements to prevent/treat anemia','Ibuprofen reduces blood loss by up to 30% (take from day 1)','Tranexamic acid (OTC in some countries) significantly reduces heavy bleeding'], whenToSeeDoctor:'Very heavy periods always warrant investigation to identify the cause and treat any anemia. Soaking a pad hourly for 2 or more consecutive hours is an indication to seek same-day medical care.', urgency:'medium' },

  { name:'Very Light Periods', aliases:['very light periods','hypomenorrhea','light periods','scanty periods','barely any period','minimal period'], emoji:'🌸', type:'common', description:'Menstrual periods that are unusually short or with very light flow. Can be normal for some women or indicate an underlying hormonal or uterine issue.', symptoms:['Periods lasting less than 2 days','Very light flow — one or two pads for the entire period','Periods that were previously heavier becoming lighter','May or may not have cramping'], causes:['Normal variation for some women','Hormonal contraception — pill or hormonal IUD often lightens periods (this is expected and normal)','Perimenopause — periods naturally change before menopause','Very low body weight or high athletic training','PCOS','Asherman\'s syndrome — uterine scarring (after D&C or surgery)','Thyroid disorders'], homecare:['If on hormonal contraception, light periods are a known and expected effect — not concerning','Maintain adequate caloric intake and healthy weight','Address stress if significant'], whenToSeeDoctor:'Periods becoming suddenly very light without a change in contraception, especially after a uterine procedure (D&C or miscarriage management) — possible Asherman\'s syndrome. Blood tests and ultrasound can identify hormonal or structural causes.', urgency:'low' },

  { name:'Breast Tenderness', aliases:['breast tenderness','sore breasts','tender breasts','breast soreness','breast pain cyclical'], emoji:'🌸', type:'common', description:'Breast discomfort, tenderness, or pain. Very common — affects up to 70% of women. Most commonly cyclical and related to hormonal changes around the menstrual cycle.', symptoms:['Breast aching, heaviness, or soreness','Tenderness when touching the breast','Worse in the week before periods — classic cyclical pattern','May affect one or both breasts','Swelling or lumpiness before period'], causes:['Hormonal fluctuations during the menstrual cycle (cyclical — most common)','Pregnancy','Breastfeeding — engorgement or blocked duct','Starting or changing hormonal contraception or HRT','Poorly fitting bra','Fibrocystic changes'], homecare:['Well-fitting supportive bra — wearing a soft bra at night may help','Reduce caffeine intake — linked to improvement in cyclical breast pain','Evening primrose oil 3g daily may reduce cyclical breast pain','OTC pain relievers (ibuprofen or paracetamol)','Apply warmth or cold depending on what feels better'], whenToSeeDoctor:'New breast lump, lump that persists after period, skin changes (dimpling, redness), nipple discharge, or one-sided non-cyclical breast pain. A breast examination and possibly imaging is needed.', urgency:'medium' },

  { name:'Nipple Pain', aliases:['nipple pain','sore nipples','nipple soreness','tender nipples','nipple sensitivity'], emoji:'🌸', type:'common', description:'Pain or soreness in the nipple area. Common in breastfeeding women and those approaching their period. Can also indicate infection or, rarely, a more serious condition.', symptoms:['Pain, soreness, or sensitivity in the nipple','Cracking or bleeding of the nipple (breastfeeding)','Itching or burning','Discharge from the nipple','Redness or scaly skin on the nipple'], causes:['Breastfeeding — poor latch causing friction and trauma (most common in breastfeeding)','Thrush (Candida) on nipples during breastfeeding','Premenstrual hormonal changes','Ill-fitting bra causing friction (jogger\'s nipple)','Eczema of the nipple','Paget\'s disease of the breast (rare but important — resembles eczema)'], homecare:['Breastfeeding: improve latch with help from a lactation consultant','Apply lanolin nipple cream after each feed','Let nipples air dry after feeding','Wear a correctly fitting sports bra during exercise','Treat nipple thrush with antifungal cream if prescribed'], whenToSeeDoctor:'Persistent nipple soreness not related to breastfeeding, scaly eczema-like rash on the nipple (possible Paget\'s disease — must be excluded), nipple discharge, or retracted nipple.', urgency:'medium' },

  { name:'Vaginal Dryness', aliases:['vaginal dryness','vaginal atrophy','dry vagina','vaginal moisture loss','atrophic vaginitis'], emoji:'🌸', type:'common', description:'Insufficient vaginal lubrication leading to dryness, itching, and discomfort. Very common, affecting up to 50% of postmenopausal women. Often undertreated due to embarrassment.', symptoms:['Vaginal dryness and irritation','Itching or burning in the vaginal area','Pain or discomfort during sexual intercourse (dyspareunia)','Light bleeding after intercourse','Urinary frequency or urgency from thinned vaginal tissue affecting the urethra','Recurrent urinary tract infections'], causes:['Menopause and declining estrogen levels (most common)','Breastfeeding (low estrogen state)','Certain contraceptives — particularly progestogen-only methods','Anti-estrogen cancer treatments (tamoxifen, aromatase inhibitors)','Sjögren\'s syndrome','Stress and anxiety'], homecare:['Use vaginal moisturizers regularly (non-hormonal — hyaluronic acid or Replens) 2-3 times per week','Use lubricants during intercourse (water-based or silicone-based)','Stay sexually active — stimulation maintains vaginal health','Avoid scented soaps, douches, or bath products in the vaginal area','Stay well hydrated'], whenToSeeDoctor:'Significant vaginal dryness affecting quality of life, sexual function, or causing urinary symptoms. Local vaginal estrogen (cream, ring, or pessary) is very effective and has minimal systemic absorption. Discuss with a gynecologist.', urgency:'low' },

  { name:'Vaginal Itching', aliases:['vaginal itching','vulval itching','vaginal itch','vulvar pruritus','intimate area itching','itchy vagina'], emoji:'🌸', type:'common', description:'Itching in the vaginal or vulvar area. Very common with many causes ranging from simple irritation to infection. Should not be left untreated as it often indicates a treatable condition.', symptoms:['Itching in the vagina or on the vulva (external genitalia)','May be accompanied by discharge, redness, or soreness','Burning sensation','Pain during urination or intercourse'], causes:['Yeast infection (Candida) — most common cause: thick white discharge','Bacterial vaginosis — thin gray discharge with fishy odor','Irritant — soaps, detergents, bath products, tight clothing','Trichomoniasis (STI)','Vaginal dryness from menopause','Lichen sclerosus (skin condition)','Contact dermatitis'], homecare:['Wash with plain water only — no soaps or shower gels inside the vulva','Wear loose, breathable cotton underwear','Avoid fabric softener on underwear','OTC antifungal cream if yeast infection is the suspected cause (miconazole, clotrimazole)','Avoid scratching — it worsens inflammation'], whenToSeeDoctor:'Vaginal itching with discharge (especially smelly or unusual colored), itching after new sexual partner (STI), persistent itching not responding to yeast treatment, or itching with skin changes on the vulva.', urgency:'medium' },

  { name:'Pelvic Pressure', aliases:['pelvic pressure','heaviness in pelvis','prolapse feeling','pressure in lower abdomen','bearing down feeling'], emoji:'🌸', type:'common', description:'A feeling of heaviness, fullness, or pressure in the pelvic region. Can result from a full bladder or bowel, uterine fibroids, prolapse, or other pelvic conditions.', symptoms:['Sensation of heaviness or pressure in the lower abdomen and pelvis','Feeling of something falling out of the vagina (prolapse)','Worsens with prolonged standing or activity','Improves when lying down','May be accompanied by urinary or bowel symptoms'], causes:['Pelvic organ prolapse — bladder, uterus, or bowel descending into vagina','Uterine fibroids — large fibroids create pressure','Full bladder or rectum (benign and temporary)','Constipation','Ovarian cyst','Pregnancy'], homecare:['Pelvic floor exercises (Kegel exercises) — strengthen the pelvic floor and improve mild prolapse','Treat constipation with fiber and hydration','Avoid heavy lifting which strains the pelvic floor','Maintain a healthy weight','Pessary — a supportive device inserted into the vagina (fitted by doctor)'], whenToSeeDoctor:'Persistent pelvic pressure, sensation of bulge in the vagina, or pressure significantly affecting daily activities. A physiotherapist specializing in pelvic floor can assess and treat. Surgical repair is available for significant prolapse.', urgency:'medium' },

  { name:'Bloating Before Period', aliases:['premenstrual bloating','period bloating','bloating before period','stomach bloating PMS','abdominal bloating period'], emoji:'🌸', type:'common', description:'Abdominal bloating and feeling of fullness occurring in the days before menstruation. A very common PMS symptom affecting up to 70% of menstruating women.', symptoms:['Abdominal distension and fullness before period','Clothes feeling tighter around the waist','Discomfort or mild cramping','Associated with other PMS symptoms — mood changes, breast tenderness','Resolves once the period starts'], causes:['Hormonal fluctuations — progesterone rise in the second half of the cycle','Water retention from hormonal changes','Progesterone slows gastrointestinal motility increasing gas and bloating','Individual sensitivity to these hormonal changes'], homecare:['Reduce salt intake in the week before your period — salt worsens water retention','Avoid carbonated drinks, beans, cruciferous vegetables, and other gas-producing foods premenstrually','Eat small regular meals','Regular aerobic exercise reduces bloating significantly','Magnesium 200-400mg daily may reduce PMS bloating','Calcium 1200mg daily shown to reduce PMS symptoms including bloating'], whenToSeeDoctor:'Severe bloating significantly affecting quality of life, or bloating that does not follow the cyclical pattern (present all month, not just premenstrually) — this needs evaluation for other causes.', urgency:'low' },

  { name:'Mood Swings Before Period', aliases:['mood swings before period','premenstrual mood changes','PMS mood swings','emotional before period','irritability before period'], emoji:'🌸', type:'common', description:'Emotional changes occurring in the 1-2 weeks before menstruation, including irritability, sadness, anxiety, or mood instability. Part of PMS. Affects most menstruating women to some degree.', symptoms:['Irritability or anger more than usual before period','Sadness or crying spells','Anxiety or feeling on edge','Emotional sensitivity — feeling easily upset','Improves when period starts','Food cravings and emotional eating'], causes:['Hormonal fluctuations during the luteal phase — progesterone and estrogen changes','Serotonin levels fall as progesterone rises (serotonin regulates mood)','Individual sensitivity to hormonal changes','Genetics — some women are more sensitive than others'], homecare:['Regular aerobic exercise throughout the month — most effective intervention','Good sleep habits especially in the premenstrual phase','Calcium 1200mg and magnesium 200-400mg daily shown to significantly reduce emotional PMS symptoms','Reduce caffeine and alcohol in the premenstrual phase','Mindfulness and stress management techniques','Track your cycle to prepare for difficult days'], whenToSeeDoctor:'Mood changes so severe they affect relationships, work, or daily functioning (could be PMDD requiring treatment), or if you feel unsafe. SSRIs can be taken daily or only in the second half of the cycle for PMDD with excellent results.', urgency:'medium' },

  { name:'Hot Flashes in Young Women', aliases:['hot flashes young women','hot flushes young','premature menopause symptoms','POI hot flashes','early menopause symptoms'], emoji:'🌸', type:'common', description:'Hot flashes occurring in women under 45. While perimenopause typically begins in the mid-40s, some women experience hot flashes earlier due to hormonal conditions or treatments.', symptoms:['Sudden feeling of warmth in face, neck, and chest','Flushing and sweating episodes','Night sweats','Irregular periods alongside hot flashes','Mood changes and difficulty sleeping'], causes:['Premature ovarian insufficiency (POI) — ovaries stop working normally before age 40','Early perimenopause (40-45)','Surgical menopause — oophorectomy at any age','Cancer treatments — chemotherapy, tamoxifen, GnRH analogues','Hyperthyroidism','Certain medications'], homecare:['Lifestyle measures for hot flashes — dress in layers, avoid triggers, keep bedroom cool','Avoid alcohol and caffeine which trigger flushes'], whenToSeeDoctor:'Hot flashes in a woman under 45 combined with irregular or absent periods needs prompt evaluation. FSH and estradiol blood tests are the first step. Premature ovarian insufficiency has implications for bone density and heart health, requiring HRT.', urgency:'medium' },

  { name:'Low Libido in Women', aliases:['low libido women','low sex drive women','reduced sexual desire women','loss of libido women','hypoactive sexual desire disorder'], emoji:'🌸', type:'common', description:'Decreased interest in sexual activity in women. Affects up to 40% of women at some point. Multifactorial — physical, hormonal, psychological, and relational factors all contribute.', symptoms:['Little or no interest in sexual activity','Absent sexual thoughts or fantasies','Distress about low desire','May affect relationship and self-esteem'], causes:['Menopause and low estrogen (reduced lubrication, pain)','Postpartum hormonal changes','Combined oral contraceptive pill can reduce libido in some women','Depression or anxiety','Relationship problems or lack of emotional intimacy','Fatigue and overwork','Body image issues','History of trauma or abuse'], homecare:['Address stress, sleep, and fatigue — fundamental to desire','Communicate openly with partner about needs and feelings','Consider whether the contraceptive pill may be a contributing factor (other methods may be better)','Exercise improves body confidence and hormonal balance','Mindfulness and sensate focus exercises can help reconnect with body'], whenToSeeDoctor:'Persistent low libido causing significant distress or relationship impact. HSDD (Hypoactive Sexual Desire Disorder) is a real medical condition. Hormone testing, therapy (sex therapy, couples therapy), and medical treatment options are available.', urgency:'low' },

  { name:'Painful Intercourse', aliases:['painful intercourse','dyspareunia','pain during sex','pain with intercourse','painful sex'], emoji:'🌸', type:'common', description:'Pain experienced during or after sexual intercourse. Affects up to 20% of women and can significantly impact relationships and quality of life. Has many treatable causes.', symptoms:['Pain at the entrance of the vagina during penetration (superficial dyspareunia)','Deep pelvic pain during intercourse (deep dyspareunia)','Pain that persists after intercourse','Burning, stinging, or throbbing sensation','Avoidance of sexual intimacy'], causes:['Vaginal dryness — most common and most easily treated cause','Vaginismus — involuntary tightening of vaginal muscles','Vulvodynia — chronic vulvar pain','Endometriosis (deep pain)','Pelvic inflammatory disease','Ovarian cysts','Hormonal changes from menopause or breastfeeding'], homecare:['Use generous amounts of lubricant before and during intercourse','Allow more time for arousal before penetration','Try different positions to find those causing less pain','Vaginal moisturizers for dryness (hyaluronic acid or Replens)','Pelvic floor physiotherapy exercises for vaginismus','Communicate openly with partner about discomfort'], whenToSeeDoctor:'Any persistent pain with intercourse warrants evaluation by a gynecologist. Vaginismus, endometriosis, and vulvodynia all have effective treatments. Many women suffer in silence unnecessarily.', urgency:'medium' },

  { name:'Postcoital Bleeding', aliases:['postcoital bleeding','bleeding after sex','spotting after intercourse','blood after intercourse','post sex bleeding'], emoji:'🌸', type:'common', description:'Vaginal bleeding that occurs after sexual intercourse. Always requires medical evaluation to identify the cause as it can range from minor to serious.', symptoms:['Vaginal bleeding occurring shortly after intercourse','May range from light spotting to heavier bleeding','Not related to menstrual period timing','May or may not be accompanied by pain'], causes:['Cervical ectropion (most common benign cause — fragile tissue on the cervix)','Cervical polyp','Vaginal dryness causing small tears','Cervicitis (cervical infection)','Cervical cancer (must be excluded — this is a classic symptom)','Vaginal infections'], homecare:['Use lubricant during intercourse to reduce friction-related bleeding','No home management is appropriate — all cases need assessment'], whenToSeeDoctor:'All cases of postcoital bleeding require a cervical examination and smear test to exclude cervical cancer. See a doctor promptly — do not delay even if the bleeding was mild.', urgency:'medium' },

  /* ── COMMON: MEN SPECIFIC ── */
  { name:'Testicular Pain', aliases:['testicular pain','testicle pain','ball pain','scrotal pain','orchalgia','testicular ache'], emoji:'🩺', type:'common', description:'Pain in one or both testicles. Can range from mild discomfort to severe acute pain. Sudden severe testicular pain is a urological emergency.', symptoms:['Pain in one or both testicles','May radiate to the lower abdomen or groin','Swelling or change in the size or shape of the testicle','Nausea and vomiting with severe pain','Heaviness in the scrotum'], causes:['Testicular torsion (twisting of the testis — emergency, requires surgery within 6 hours)','Epididymitis (infection — most common cause of acute testicular pain in adults)','Orchitis (testicular inflammation, often viral — mumps)','Referred pain from kidney stone','Inguinal hernia','Varicocele (enlarged testicular veins — usually a dull ache)','Testicular cancer (usually painless lump)'], homecare:['No home care for sudden severe testicular pain — seek emergency care immediately','For chronic mild testicular discomfort — scrotal support (supportive underwear) and OTC pain relief while awaiting evaluation'], whenToSeeDoctor:'Sudden severe testicular pain is a urological emergency — go to emergency room immediately as testicular torsion must be excluded (time-critical). Any testicular pain, swelling, or lump needs evaluation.', urgency:'high' },

  { name:'Testicular Swelling', aliases:['testicular swelling','swollen testicle','enlarged testicle','scrotal swelling','lump on testicle'], emoji:'🩺', type:'common', description:'Enlargement or swelling of one or both testicles. Needs medical evaluation to distinguish harmless causes from serious ones including testicular cancer.', symptoms:['One or both testicles appear larger than normal','Sensation of heaviness in the scrotum','Scrotal discomfort','Lump within the testis — firm and often painless'], causes:['Epididymal cyst (most common benign cause — harmless fluid-filled cyst)','Varicocele (swollen veins — feels like a bag of worms)','Hydrocele (fluid around the testis)','Epididymitis (infection)','Inguinal hernia extending into scrotum','Testicular cancer (any painless hard lump must be excluded)'], homecare:['Monthly testicular self-examination is recommended for all men aged 15-40','Feel each testicle between thumb and fingers — know what is normal for you','Report any new lump or change to a doctor promptly'], whenToSeeDoctor:'Any new testicular lump or swelling should be evaluated by a doctor. Testicular cancer is most common in men aged 15-40 and is highly curable when caught early. Ultrasound can distinguish between types of swelling.', urgency:'medium' },

  { name:'Scrotal Itching', aliases:['scrotal itching','scrotum itching','itchy scrotum','genital itching men','groin itching'], emoji:'🩺', type:'common', description:'Itching of the scrotal skin. Usually caused by common skin conditions, fungal infection, or irritation. Rarely indicates a serious condition.', symptoms:['Itching of the scrotal skin','Redness or rash','Dry or flaky skin','May extend to the inner thighs'], causes:['Jock itch (tinea cruris) — fungal infection (most common cause)','Contact dermatitis from soaps, detergents, or clothing','Eczema of the scrotal skin','Scabies','Pubic lice (crabs)','Psoriasis','Poor hygiene or excessive sweating'], homecare:['Keep the area clean and dry — pat dry thoroughly after bathing','Wear loose, breathable cotton underwear','Apply OTC antifungal cream for jock itch (clotrimazole, miconazole)','Use fragrance-free soaps and washing powder','Avoid synthetic underwear and tight clothing'], whenToSeeDoctor:'Itching not responding to antifungal treatment after 2 weeks, skin changes (thickening, lesions), associated pain or swelling, or if sexually transmitted infection is a possibility.', urgency:'low' },

  { name:'Groin Rash', aliases:['groin rash','rash in groin','groin skin rash','inguinal rash','inner thigh rash men'], emoji:'🔴', type:'common', description:'A rash in the groin area — the junction of the thigh and lower abdomen. Common in both men and women. Most frequently caused by fungal infection or irritation.', symptoms:['Red rash in the groin folds','Itching, burning, or stinging','Ring-shaped border with clearer center (fungal)','Scaling or flaking skin','May spread to inner thighs or buttocks'], causes:['Jock itch (tinea cruris) — most common','Intertrigo — irritation from skin-on-skin friction and moisture','Contact dermatitis from soap or clothing','Candidal intertrigo — yeast infection in skin folds','Psoriasis','Erythrasma (bacterial infection)'], homecare:['Keep groin area clean and dry','Wear loose cotton underwear','Apply OTC antifungal cream for jock itch','Antifungal powder to reduce moisture','Zinc oxide paste for irritant intertrigo','Avoid wearing tight clothing and synthetic fabrics'], whenToSeeDoctor:'Groin rash not responding to antifungal treatment, spreading significantly, having pustules, causing significant pain, or if STI is a possibility (e.g., syphilis or herpes can present as groin rash).', urgency:'low' },

  { name:'Painful Ejaculation', aliases:['painful ejaculation','pain during orgasm','ejaculatory pain','dysejaculation','genital pain ejaculation'], emoji:'🩺', type:'common', description:'Pain or discomfort occurring during or shortly after ejaculation. Affects a significant proportion of men but is often not discussed. Treatable when the cause is identified.', symptoms:['Pain or burning during ejaculation','Discomfort in the penis, perineum, or testicles','Pain persisting for minutes to hours after ejaculation','May be associated with urinary symptoms'], causes:['Prostatitis — inflammation or infection of the prostate (most common cause)','Epididymitis — infection of the epididymis','Urethritis — infection of the urethra (including STIs)','Seminal vesicle inflammation','Psychological causes — anxiety or pelvic floor tension','Medications (some antidepressants)'], homecare:['Warm baths to relax the pelvic floor','Pelvic floor relaxation exercises (for tension-related causes)','OTC pain relievers for mild discomfort while awaiting evaluation'], whenToSeeDoctor:'All cases of painful ejaculation should be evaluated — it is almost always treatable once the cause is identified. STI testing and prostate assessment are important components of the evaluation.', urgency:'medium' },

  { name:'Blood in Semen', aliases:['blood in semen','haematospermia','hematospermia','blood in ejaculate','red or brown semen'], emoji:'🩺', type:'common', description:'The presence of blood in the semen, making it pink, red, or brown. Alarming but usually benign. Most common in men under 40 where it resolves without treatment.', symptoms:['Pink, red, or brown discoloration of semen','May be associated with pain on ejaculation or urination','Usually painless'], causes:['Benign prostate or seminal vesicle inflammation (most common)','Urinary tract infection','Prostatitis','Vigorous sexual activity causing minor trauma','Prostate biopsy (expected after procedure)','Rarely: prostate cancer (in men over 40)'], homecare:['Most cases in young men resolve spontaneously without treatment','Avoid unprotected sex until cause is established (infection is possible)'], whenToSeeDoctor:'Blood in semen on more than 2-3 occasions, in men over 40, associated with painful urination or blood in urine, or if associated with a recent prostate procedure. A urine test, PSA, and examination are appropriate investigations.', urgency:'medium' },

  { name:'Low Libido in Men', aliases:['low libido men','low sex drive men','reduced sexual desire men','testosterone deficiency libido','male low desire'], emoji:'🩺', type:'common', description:'Decreased interest in sexual activity in men. Normal to fluctuate with stress and age, but persistent low libido warrants evaluation, particularly for testosterone deficiency.', symptoms:['Reduced interest in sex','Fewer spontaneous erections','Fatigue and reduced energy','Low mood and reduced motivation','Muscle weakness','In testosterone deficiency: hot flashes, hair loss, breast tissue enlargement'], causes:['Low testosterone (hypogonadism) — important and treatable cause','Stress, anxiety, and depression','Relationship problems','Sleep deprivation','Obesity — excess body fat reduces testosterone','Certain medications — antidepressants, opioids, antihypertensives','Alcohol and recreational drug use','Aging — testosterone naturally declines from age 30'], homecare:['Regular exercise — resistance training particularly helps maintain testosterone levels','Adequate sleep — testosterone is produced during deep sleep','Maintain a healthy weight — obesity significantly reduces testosterone','Reduce alcohol consumption','Address stress and mental health'], whenToSeeDoctor:'Persistent low libido in men warrants a testosterone blood test (done in the morning). Low testosterone is very treatable with hormone replacement therapy. Rule out depression and medication side effects as well.', urgency:'medium' },

  { name:'Morning Fatigue', aliases:['morning fatigue','tired in the morning','not rested after sleep','morning tiredness','feeling unrefreshed in morning','sleep inertia'], emoji:'😴', type:'common', description:'Feeling tired or unrefreshed upon waking, even after what should be adequate sleep. Very common. Often indicates poor sleep quality rather than inadequate sleep quantity.', symptoms:['Difficulty waking in the morning','Feeling tired immediately on waking','Grogginess that persists for hours','Improved energy only later in the day','Fatigue not relieved by more sleep'], causes:['Sleep apnea — the most important cause of unrefreshing sleep','Poor sleep quality (frequent awakenings without full awareness)','Depression (especially early morning fatigue and waking early)','Hypothyroidism','Anemia','Circadian rhythm disorders (delayed sleep phase)','Poor sleep hygiene — irregular sleep schedule, screen use before bed'], homecare:['Regular consistent sleep and wake times — even on weekends','Avoid screens for 1 hour before bed (blue light delays melatonin)','Keep bedroom cool, dark, and quiet','Avoid caffeine after 2pm','Regular exercise improves sleep quality significantly','Limit alcohol — it fragments sleep despite initially promoting sleep onset'], whenToSeeDoctor:'Morning fatigue lasting more than 2 weeks, partner reports snoring or breathing pauses (possible sleep apnea), or morning fatigue with persistent low mood. A sleep study and blood tests (thyroid, iron) are appropriate investigations.', urgency:'medium' },

  { name:'Excessive Hair Loss in Men', aliases:['male hair loss','androgenetic alopecia men','male pattern baldness','receding hairline','balding men','hair thinning men'], emoji:'💇', type:'common', description:'Progressive hair loss in men following a characteristic pattern — receding hairline and thinning on the crown, leading to partial or complete baldness. Affects up to 50% of men by age 50. The most common form of hair loss.', symptoms:['Receding hairline — especially at temples','Thinning hair on the crown of the head','Gradual reduction in hair density over months to years','Hair shedding — more than 100 hairs per day','Miniaturization of hair follicles — hair becomes thinner and shorter over time'], causes:['Genetics (most important factor) — autosomal dominant inheritance','Dihydrotestosterone (DHT) — a derivative of testosterone causing follicle shrinkage in genetically susceptible men','Age — process begins in some men in their 20s','Stress and illness can accelerate existing pattern hair loss'], homecare:['Minoxidil (Rogaine) 5% applied to scalp twice daily — slows loss and stimulates regrowth in some men (requires consistent long-term use)','Finasteride 1mg daily (prescription in most countries) — reduces DHT levels and is very effective at slowing hair loss','Hair thickening shampoos and styling techniques can improve appearance','Maintain a healthy diet with adequate protein, iron, and zinc','Sun protection for the scalp'], whenToSeeDoctor:'Rapid hair loss, patchy hair loss (not the typical male pattern), hair loss with scalp inflammation or scarring, or if hair loss is causing significant distress. A dermatologist can confirm androgenetic alopecia and discuss medical treatments.', urgency:'low' },
  /* - COMMOM : COMMONLY FOUND - */
  { name:'Dry Eyes', aliases:['dry eyes','dry eye','eye dryness','gritty eyes','burning eyes','sandy eyes'], emoji:'👁️', type:'common', description:'A condition where the eyes do not produce enough tears or the tears evaporate too quickly, causing discomfort and vision problems. Very common in people who use screens frequently or live in dry climates.', symptoms:['Stinging or burning sensation in eyes','Scratchy or gritty feeling','Redness of the eyes','Sensitivity to light','Blurred vision that improves with blinking','Stringy mucus around eyes','Watery eyes (reflex tearing)'], causes:['Prolonged screen use','Aging (especially after 50)','Air conditioning or dry environments','Contact lens use','Certain medications (antihistamines, antidepressants)','Hormonal changes'], homecare:['Use preservative-free artificial tear drops frequently','Blink more consciously especially during screen use','Follow the 20-20-20 rule for screen breaks','Use a humidifier in dry rooms','Wear wraparound glasses outdoors','Warm compress on closed eyelids to stimulate oil glands'], whenToSeeDoctor:'If dry eyes are persistent, affecting vision, or not improving with artificial tears after 2 weeks. See an ophthalmologist if you wear contact lenses and have pain.', urgency:'low' },

  { name:'Watery Eyes', aliases:['watery eyes','tearing eyes','excessive tearing','epiphora','eyes watering'], emoji:'👁️', type:'common', description:'Excessive tearing or watering of the eyes, which can be caused by blocked tear ducts, eye irritation, or allergies. Usually not serious but can affect daily life.', symptoms:['Constant or frequent tearing','Tears running down cheeks','Blurred vision from excess tears','Crusting around eyes','Eye redness','Sensitivity to wind and light'], causes:['Blocked or narrow tear ducts','Allergies','Eye infection or irritation','Eyelid problems (inturned or outturned lid)','Cold or windy weather','Foreign body in the eye'], homecare:['Gently massage the inner corner of the eye near the nose','Apply warm compress to help open blocked ducts','Avoid rubbing the eye','Use antihistamine drops if allergy-related','Protect eyes from wind and cold'], whenToSeeDoctor:'If watering is persistent for more than a week, accompanied by pain, swelling near the nose, or discharge. Newborns with watery eyes should see a doctor.', urgency:'low' },

  { name:'Itchy Eyes', aliases:['itchy eyes','eye itching','eyes itching','ocular itch','allergic eyes'], emoji:'👁️', type:'common', description:'An uncomfortable itching sensation in or around the eyes, most commonly caused by allergies. Rubbing the eyes worsens the condition and can introduce infection.', symptoms:['Intense itching in or around eyes','Redness','Watery discharge','Swollen eyelids','Burning sensation','Sensitivity to light'], causes:['Allergic conjunctivitis (pollen, dust, pet dander)','Contact lens irritation','Eye makeup or cosmetics','Dry eyes','Blepharitis (eyelid inflammation)'], homecare:['Avoid rubbing eyes — it worsens itching','Use cold compress on closed eyelids','Over-the-counter antihistamine eye drops','Remove contact lenses','Wash eyes with clean water if irritant exposure','Avoid known allergens'], whenToSeeDoctor:'Severe itching, vision changes, thick discharge, pain, or symptoms not improving with antihistamine drops after a few days.', urgency:'low' },

  { name:'Eye Twitching', aliases:['eye twitching','eyelid twitch','eye spasm','myokymia','eyelid spasm'], emoji:'👁️', type:'common', description:'Involuntary, repetitive spasms of the eyelid muscles. Usually affects the lower lid. Almost always benign and self-limiting, though annoying.', symptoms:['Uncontrolled blinking or eyelid spasm','Usually affects one eye','Can last seconds to minutes','May recur throughout the day','Rarely both eyes affected simultaneously'], causes:['Fatigue and lack of sleep','Eye strain from screens','Caffeine and alcohol excess','Stress and anxiety','Dry eyes','Nutritional deficiencies (magnesium)'], homecare:['Get adequate sleep (7-8 hours)','Reduce caffeine intake','Warm compress on the eye','Rest your eyes frequently from screens','Magnesium-rich foods — nuts, seeds, bananas'], whenToSeeDoctor:'Twitching lasting more than 2 weeks, spreading to other facial muscles, eye closing completely, or accompanied by facial drooping — may indicate neurological issue.', urgency:'low' },

  { name:'Floaters in Vision', aliases:['floaters','eye floaters','spots in vision','moving spots','strings in vision','cobwebs in eye'], emoji:'👁️', type:'common', description:'Small shapes like spots, strings, or cobwebs that drift across your field of vision. Usually harmless and caused by age-related changes in the vitreous gel inside the eye.', symptoms:['Spots or strings drifting in field of vision','Move when you move your eyes','More noticeable against bright backgrounds','Usually in one eye'], causes:['Age-related vitreous shrinkage (most common)','Eye inflammation','Bleeding inside the eye','Retinal tear (serious)','Nearsightedness'], homecare:['Usually no treatment needed','Move your eyes up and down to shift floaters out of view','Adequate lighting reduces their visibility','Manage screen brightness'], whenToSeeDoctor:'Sudden increase in floaters, flashes of light, loss of peripheral vision, or a shadow/curtain over vision — these are retinal emergency signs. See an eye doctor immediately.', urgency:'medium' },

  { name:'Night Blindness', aliases:['night blindness','poor night vision','difficulty seeing at night','nyctalopia','low light vision problem'], emoji:'👁️', type:'common', description:'Difficulty seeing in dim light or at night. Usually a symptom of an underlying condition rather than a disease itself. Ranges from mild to severe.', symptoms:['Difficulty seeing in low light or darkness','Slow adjustment when moving from bright to dark environments','Trouble driving at night','Stumbling in dimly lit areas'], causes:['Vitamin A deficiency (most common cause globally)','Myopia (nearsightedness)','Cataracts','Glaucoma','Retinitis pigmentosa','Certain medications'], homecare:['Eat vitamin A-rich foods — carrots, sweet potato, leafy greens, eggs, liver','Allow eyes time to adjust before moving in the dark','Avoid looking at bright lights before entering dark environments','Have an updated glasses or contact lens prescription'], whenToSeeDoctor:'Significant difficulty seeing at night, especially if worsening. Requires an eye exam to determine underlying cause. Vitamin A deficiency is treatable.', urgency:'medium' },

  { name:'Tinnitus', aliases:['tinnitus','ear ringing','ringing in ears','buzzing in ears','ear noise','hissing in ears'], emoji:'👂', type:'common', description:'The perception of noise or ringing in the ears when no external sound is present. Extremely common — affects about 15% of people. Usually not a sign of serious illness but can be distressing.', symptoms:['Ringing, buzzing, hissing, or roaring sound in ears','Can be in one or both ears','May be constant or intermittent','Can be high or low pitched','May affect concentration and sleep'], causes:['Noise-induced hearing loss (loud music, machinery)','Age-related hearing loss','Earwax blockage','Middle ear infections','Certain medications (aspirin, antibiotics)','Head or neck injuries'], homecare:['Avoid loud noises and use ear protection','Reduce caffeine and salt intake','Manage stress — stress worsens tinnitus','Use white noise or background sound to mask ringing','Sleep with a fan or white noise machine'], whenToSeeDoctor:'Sudden onset tinnitus especially in one ear, tinnitus with hearing loss or dizziness, pulsating tinnitus (in time with heartbeat), or tinnitus after head injury.', urgency:'medium' },

  { name:'Hearing Loss', aliases:['hearing loss','hard of hearing','partial deafness','hearing difficulty','reduced hearing','muffled hearing'], emoji:'👂', type:'common', description:'Partial or total inability to hear. Can affect one or both ears. Very common — affects 1 in 3 people over 65. Can be temporary or permanent depending on the cause.', symptoms:['Muffled or unclear sounds','Difficulty understanding speech especially in noise','Asking people to repeat themselves frequently','Turning up TV or phone volume','Withdrawal from conversations','Tinnitus (ringing)'], causes:['Age-related hearing loss (presbycusis)','Noise exposure','Earwax buildup','Ear infections','Ruptured eardrum','Certain medications'], homecare:['Remove earwax blockage with safe methods or see a doctor','Protect ears from loud noise — use earplugs','Avoid inserting objects in the ear canal','Lip reading and visual cues help temporarily'], whenToSeeDoctor:'Sudden hearing loss in one or both ears requires immediate medical attention. Gradual hearing loss should be evaluated by an audiologist for hearing aids or treatment.', urgency:'medium' },

  { name:'Earwax Blockage', aliases:['earwax','ear wax','blocked ear','ear blockage','cerumen impaction','wax in ear'], emoji:'👂', type:'common', description:'A buildup of earwax (cerumen) that blocks the ear canal. Very common and usually easily treated. The ear naturally produces wax to protect itself, but too much can cause problems.', symptoms:['Feeling of fullness or plugged ear','Muffled hearing','Ear pain or ache','Ringing in the ear (tinnitus)','Dizziness','Itching in the ear canal','Discharge if infected'], causes:['Overproduction of earwax','Using cotton swabs (pushes wax deeper)','Narrow ear canals','Use of hearing aids or earbuds','Older age (wax becomes drier)'], homecare:['Use over-the-counter ear drops (olive oil, hydrogen peroxide) to soften wax','Tilt head and let drops sit for a few minutes','Never insert cotton swabs or objects into the ear','Warm water irrigation from a syringe (gently)','Allow ears to self-clean naturally'], whenToSeeDoctor:'Significant hearing loss, pain, dizziness, or wax removal at home not working. A doctor can safely remove impacted wax by irrigation or microsuction.', urgency:'low' },

  { name:'Perforated Eardrum', aliases:['perforated eardrum','ruptured eardrum','torn eardrum','eardrum perforation','burst eardrum'], emoji:'👂', type:'common', description:'A hole or tear in the thin membrane (eardrum) that separates the outer and middle ear. Can heal on its own but requires care to prevent infection.', symptoms:['Sudden sharp ear pain that may subside quickly','Hearing loss','Drainage from the ear (fluid or blood)','Ringing in the ear','Dizziness','Weakness of facial muscles (rarely)'], causes:['Ear infection with pressure buildup','Sudden loud noise or explosion','Poking something in the ear','Sudden pressure changes (airplane, diving)','Head injury'], homecare:['Keep the ear dry — no swimming or submerging','Do not insert anything into the ear','Take prescribed antibiotics if infected','OTC pain relievers for discomfort','Place a clean dry cotton ball loosely in the ear to protect it (not tightly packed)'], whenToSeeDoctor:'All suspected perforated eardrums should be evaluated by a doctor. Most heal in 2-3 months. Surgery may be needed if healing does not occur.', urgency:'medium' },

  { name:'Otitis Media', aliases:['otitis media','middle ear infection','ear infection','glue ear','fluid in ear'], emoji:'👂', type:'common', description:'An infection or inflammation of the middle ear, very common in children but also affects adults. Often follows a cold or respiratory infection.', symptoms:['Ear pain (especially when lying down)','Tugging or pulling at the ear (in children)','Difficulty hearing','Fever','Fluid draining from ear','Irritability in infants','Difficulty sleeping'], causes:['Bacterial or viral infection following a cold or flu','Eustachian tube dysfunction','Secondhand smoke exposure','Bottle feeding while lying down in infants','Daycare attendance'], homecare:['Pain relief with paracetamol or ibuprofen','Warm compress on the ear','Stay hydrated','Rest','Most mild cases resolve on their own in 2-3 days'], whenToSeeDoctor:'Ear pain lasting more than 2-3 days, high fever, discharge from ear, hearing loss, or in children under 2 with ear pain — antibiotics may be needed.', urgency:'medium' },

  { name:'Labyrinthitis', aliases:['labyrinthitis','inner ear infection','vestibular neuritis','inner ear inflammation','ear balance problem'], emoji:'👂', type:'common', description:'Inflammation of the inner ear (labyrinth) that affects hearing and balance. Usually caused by a viral infection. Can cause severe dizziness and affect daily activities.', symptoms:['Sudden and severe dizziness (vertigo)','Nausea and vomiting','Loss of balance','Hearing loss in one ear','Tinnitus (ringing)','Difficulty concentrating'], causes:['Viral infection (often follows cold or flu)','Bacterial infection (less common)','Autoimmune conditions','Allergies'], homecare:['Rest as much as possible','Move slowly and carefully to avoid falls','Stay hydrated','Avoid bright lights and screens during severe vertigo','Prescribed vestibular suppressants or antiemetics for severe symptoms'], whenToSeeDoctor:'Symptoms lasting more than a few days, severe hearing loss, facial weakness, or severe vomiting preventing hydration. See a doctor to rule out more serious causes of vertigo.', urgency:'medium' },

  { name:'Stye', aliases:['stye','eye stye','hordeolum','eyelid lump','red lump on eyelid'], emoji:'👁️', type:'common', description:'A painful red lump on or inside the eyelid caused by a bacterial infection of an oil gland or eyelash follicle. Very common and usually harmless.', symptoms:['Painful red bump on the eyelid edge','Swelling of the eyelid','Tenderness to touch','Pus at the center of the bump','Watery eye','Sensitivity to light','Crusting along the eyelid'], causes:['Bacterial infection (usually Staphylococcus)','Touching eyes with unclean hands','Old or contaminated eye makeup','Blepharitis (chronic eyelid inflammation)'], homecare:['Apply warm compress for 10-15 minutes, 3-4 times daily — helps it drain','Do not squeeze or pop the stye','Remove contact lenses until healed','Do not share towels or eye makeup','Replace eye makeup that may be contaminated'], whenToSeeDoctor:'Stye not improving after 1 week, swelling spreading beyond the eyelid, affecting vision, or recurring styes. A doctor may prescribe antibiotic ointment or drain it.', urgency:'low' },

  { name:'Chalazion', aliases:['chalazion','eyelid cyst','meibomian cyst','eyelid bump','lid cyst'], emoji:'👁️', type:'common', description:'A slowly developing, painless lump on the eyelid caused by a blocked oil gland (meibomian gland). Unlike a stye, it is not infected and is usually not tender.', symptoms:['Painless lump on the upper or lower eyelid','Eyelid swelling','Blurred vision if large (presses on cornea)','Mild eye irritation','Usually grows slowly over weeks'], causes:['Blocked meibomian oil gland','Previous stye','Blepharitis (chronic eyelid inflammation)','Skin conditions like rosacea'], homecare:['Warm compress 4 times a day for 10-15 minutes for several weeks','Gentle eyelid massage after warm compress to help clear blockage','Maintain good eyelid hygiene — clean with diluted baby shampoo','Do not squeeze'], whenToSeeDoctor:'If chalazion does not resolve after 2-3 months of warm compresses, is affecting vision, or is very large. A doctor can drain it with a minor procedure.', urgency:'low' },

  { name:'Blocked Tear Duct', aliases:['blocked tear duct','nasolacrimal duct obstruction','clogged tear duct','tear duct blockage'], emoji:'👁️', type:'common', description:'Blockage of the tear drainage system causing tears to overflow onto the face rather than draining properly. Common in newborns but also affects adults.', symptoms:['Excessive tearing and watery eyes','Discharge or crusting in the inner corner of the eye','Recurrent eye infections','Blurred vision','Painful swelling near inner corner of eye'], causes:['Congenital narrowing (in newborns)','Age-related narrowing of tear ducts','Eye infection or inflammation','Injury or trauma to the nose or eye area','Sinus surgery or facial injury'], homecare:['Gently massage the inner corner of the eye 2-3 times daily (especially in infants)','Keep the eye clean by wiping from inner to outer corner','Warm compress to the area','Wash hands before touching the eye area'], whenToSeeDoctor:'Persistent tearing beyond 6-12 months in infants, swelling and redness near the nose bridge, or recurrent infections. Adults with blocked tear ducts often need a minor procedure.', urgency:'low' },

  /* ── COMMON: NOSE & THROAT ── */
  { name:'Post Nasal Drip', aliases:['post nasal drip','mucus in throat','postnasal drip','throat drip','phlegm in throat','mucus dripping'], emoji:'👃', type:'common', description:'A sensation of mucus dripping from the back of the nose into the throat. Very common and often caused by allergies, colds, or sinusitis. Can cause a persistent cough.', symptoms:['Feeling of mucus at back of throat','Frequent need to clear throat','Chronic cough especially at night','Sore throat','Hoarse voice','Nausea from swallowing excess mucus'], causes:['Allergies (allergic rhinitis)','Common cold or flu','Sinusitis','Cold and dry weather','Certain medications','Pregnancy'], homecare:['Stay well hydrated — thins mucus','Saline nasal rinse (Neti pot) twice daily','Steam inhalation','Sleep with head slightly elevated','Avoid dairy if it thickens mucus for you','Antihistamines if allergy-related'], whenToSeeDoctor:'Symptoms lasting more than 10 days, foul-smelling mucus, blood in mucus, fever, or severe sinus pain.', urgency:'low' },

  { name:'Nasal Polyps', aliases:['nasal polyps','nasal polyp','nose polyp','growths in nose','blocked nose polyp'], emoji:'👃', type:'common', description:'Soft, painless, noncancerous growths on the lining of the nasal passages or sinuses. They can cause nasal blockage, loss of smell, and frequent infections.', symptoms:['Persistent nasal congestion','Reduced or absent sense of smell','Loss of taste','Runny nose','Postnasal drip','Facial pressure or headache','Snoring'], causes:['Chronic inflammation from allergies or asthma','Chronic sinusitis','Aspirin sensitivity','Cystic fibrosis','Immune disorders'], homecare:['Nasal corticosteroid sprays (prescribed) are first-line treatment','Saline nasal irrigation','Manage underlying allergies or asthma','Avoid nasal irritants — smoke, dust, chemical fumes','Humidifier in dry rooms'], whenToSeeDoctor:'Persistent nasal blockage, significant loss of smell, or symptoms not responding to nasal sprays. Large polyps usually require medication or surgery.', urgency:'medium' },

  { name:'Allergic Rhinitis', aliases:['allergic rhinitis','hay fever','pollen allergy','dust allergy rhinitis','seasonal allergy','nasal allergy'], emoji:'👃', type:'common', description:'Inflammation of the nasal passages triggered by allergens like pollen, dust mites, or pet dander. Affects up to 40% of people globally. Often called hay fever.', symptoms:['Sneezing repeatedly','Runny nose (clear discharge)','Nasal congestion','Itchy nose, eyes, and throat','Watery eyes','Reduced sense of smell','Fatigue'], causes:['Pollen (seasonal — trees, grass, weeds)','Dust mites (perennial)','Pet dander','Mold spores','Cockroach allergens'], homecare:['Identify and avoid triggers','Antihistamine tablets for symptom relief','Nasal corticosteroid sprays for congestion','Saline nasal wash','Keep windows closed during high pollen season','Use HEPA air purifiers indoors','Wear sunglasses outdoors during pollen season'], whenToSeeDoctor:'Symptoms significantly affecting quality of life, not responding to antihistamines, or if you develop asthma symptoms. An allergist can do skin prick testing and offer immunotherapy.', urgency:'low' },

  { name:'Loss of Smell', aliases:['loss of smell','anosmia','reduced smell','cannot smell','smell loss','hyposmia'], emoji:'👃', type:'common', description:'Partial or total loss of the sense of smell. Can be temporary (due to cold or allergy) or permanent. Also affects taste since both senses are linked.', symptoms:['Unable to detect odors','Reduced taste (since smell and taste are linked)','May not notice food smells','Difficulty detecting gas leaks or smoke','Phantom smells in some cases'], causes:['Common cold or flu (most common — temporary)','COVID-19','Nasal polyps','Sinusitis','Head injury','Aging','Certain medications','Neurological conditions (Parkinson\'s, Alzheimer\'s)'], homecare:['Smell training — sniff 4 different scents (rose, lemon, eucalyptus, clove) twice daily for several months','Treat underlying cause (infection, polyps, allergy)','Nasal saline rinse','Stay patient — smell often returns slowly'], whenToSeeDoctor:'Loss of smell lasting more than 4 weeks, after a head injury, or if accompanied by other neurological symptoms. Persistent anosmia needs evaluation.', urgency:'medium' },

  { name:'Loss of Taste', aliases:['loss of taste','ageusia','reduced taste','cannot taste','taste loss','hypogeusia'], emoji:'👅', type:'common', description:'Partial or total loss of the sense of taste. Usually linked to loss of smell since both work together. Often temporary after infections.', symptoms:['Food tastes bland or flavorless','Cannot distinguish sweet, salty, sour, or bitter','Reduced enjoyment of food','May still detect very strong flavors'], causes:['Common cold or flu','COVID-19','Zinc deficiency','Dry mouth','Smoking','Certain medications','Nasal congestion blocking smell'], homecare:['Treat underlying cause (cold, COVID)','Zinc supplements if deficient','Stay hydrated — dry mouth worsens taste','Stop smoking','Smell training also helps restore taste','Strong flavors (ginger, lemon, spices) may help stimulate receptors'], whenToSeeDoctor:'Loss of taste lasting more than 4 weeks after infection has cleared, or if accompanied by other unexplained symptoms.', urgency:'low' },

  { name:'Pharyngitis', aliases:['pharyngitis','throat infection','sore throat infection','throat inflammation','painful throat'], emoji:'🗣️', type:'common', description:'Inflammation of the pharynx (back of the throat) causing soreness, scratchiness, and difficulty swallowing. Usually viral and self-limiting.', symptoms:['Sore, scratchy throat','Pain when swallowing','Red and swollen throat','Swollen tonsils','Swollen neck glands','Runny nose','Mild fever'], causes:['Viral infection (most common — rhinovirus, adenovirus)','Bacterial infection (Streptococcus — strep throat)','Allergies','Dry air','Smoke or chemical irritation'], homecare:['Warm salt water gargle several times a day','Drink warm fluids — honey and ginger tea','Throat lozenges or sprays for pain relief','Rest your voice','Paracetamol or ibuprofen for pain and fever','Humidifier to add moisture to air'], whenToSeeDoctor:'Severe throat pain, difficulty breathing or swallowing, drooling, fever above 101°F, white patches on tonsils, or symptoms lasting more than a week. Strep throat requires antibiotics.', urgency:'low' },

  { name:'Strep Throat', aliases:['strep throat','streptococcal throat','bacterial throat infection','strep','group a strep'], emoji:'🗣️', type:'common', description:'A bacterial throat infection caused by Group A Streptococcus bacteria. Unlike viral sore throat, strep throat requires antibiotic treatment to prevent complications.', symptoms:['Sudden severe sore throat','Painful swallowing','Fever (usually above 101°F)','Red and swollen tonsils','White patches or pus on tonsils','Swollen tender lymph nodes in neck','Headache','No cough (distinguishes from viral)'], causes:['Group A Streptococcus bacteria','Spread through respiratory droplets','Direct contact with infected person','Most common in children 5-15 years'], homecare:['Take prescribed antibiotics — complete the full course','Warm salt water gargle','Rest and plenty of fluids','Paracetamol or ibuprofen for pain and fever','Cold drinks or ice cream can soothe throat','Soft foods easy to swallow'], whenToSeeDoctor:'Any suspected strep throat needs a throat swab test and antibiotics. Untreated strep can lead to rheumatic fever and kidney problems. See a doctor promptly.', urgency:'medium' },

  { name:'Tonsil Stones', aliases:['tonsil stones','tonsilloliths','white spots on tonsils','tonsil lumps','stones in tonsils'], emoji:'🗣️', type:'common', description:'Small, hard deposits that form in the crevices of the tonsils, made up of bacteria, food particles, and dead cells. Common and usually harmless but can cause bad breath.', symptoms:['Bad breath (halitosis)','Small white or yellowish lumps on tonsils','Sore throat','Difficulty swallowing','Ear pain (referred pain)','Feeling of something stuck in the throat','Persistent cough'], causes:['Bacteria and debris trapped in tonsil crypts','Poor oral hygiene','Chronic tonsillitis','Large tonsil crevices','Dry mouth'], homecare:['Gargle with warm salt water to dislodge stones','Use a water flosser on low pressure to flush them out','Maintain good oral hygiene — brush tongue too','Stay well hydrated','Avoid dairy if it increases mucus production'], whenToSeeDoctor:'Tonsil stones causing significant discomfort, very large stones, recurrent tonsillitis, or difficulty swallowing. Recurrent cases may need tonsillectomy.', urgency:'low' },

  { name:'Bad Breath', aliases:['bad breath','halitosis','mouth odor','smelly breath','oral malodor'], emoji:'🦷', type:'common', description:'Persistent unpleasant odor from the mouth. Extremely common and usually caused by poor oral hygiene or certain foods. Can sometimes indicate a medical condition.', symptoms:['Unpleasant mouth odor','Dry mouth','Coating on the tongue','Bitter or sour taste','Others stepping back during conversation'], causes:['Poor oral hygiene','Food (garlic, onion, spicy foods)','Dry mouth (saliva reduces bacteria)','Gum disease','Dental cavities','Tonsil stones','Smoking','Certain medical conditions (diabetes, GERD, sinus infection)'], homecare:['Brush teeth twice daily and floss once daily','Brush the tongue','Drink plenty of water','Chew sugar-free gum to stimulate saliva','Avoid smoking','Regular dental checkups every 6 months','Mouthwash as an adjunct (not a substitute for brushing)'], whenToSeeDoctor:'Bad breath persisting despite good oral hygiene may indicate gum disease, dental abscess, sinus infection, GERD, or other medical conditions. See a dentist first.', urgency:'low' },

  { name:'Dry Mouth', aliases:['dry mouth','xerostomia','mouth dryness','not enough saliva','cottonmouth'], emoji:'🦷', type:'common', description:'A condition where the salivary glands do not produce enough saliva. Saliva is essential for digestion, oral health, and fighting bacteria. More common in older adults.', symptoms:['Dryness or stickiness in the mouth','Thick or stringy saliva','Bad breath','Difficulty chewing, swallowing, or speaking','Sore or dry throat','Dry or cracked lips','Changed sense of taste','Mouth sores'], causes:['Certain medications (antihistamines, antidepressants, diuretics)','Aging','Dehydration','Breathing through the mouth','Sjögren\'s syndrome (autoimmune)','Radiation therapy to the head and neck'], homecare:['Sip water frequently throughout the day','Chew sugar-free gum or suck sugar-free candy to stimulate saliva','Breathe through nose rather than mouth','Use a humidifier at night','Avoid alcohol, caffeine, and tobacco','Saliva substitute products are available'], whenToSeeDoctor:'Severe dry mouth affecting eating or speaking, dental problems from dryness, or if it is a medication side effect. Medication adjustment may help.', urgency:'low' },

  { name:'Snoring', aliases:['snoring','loud snoring','snore','night snoring','snoring problem'], emoji:'😴', type:'common', description:'The harsh sound produced when air flows past relaxed tissues in the throat causing them to vibrate during breathing. Very common — affects up to 40% of adults.', symptoms:['Loud or harsh breathing sounds during sleep','Gasping or choking sounds','Restless sleep','Morning headache','Excessive daytime sleepiness','Dry mouth or sore throat on waking','Difficulty concentrating'], causes:['Nasal congestion or blockage','Obesity and excess weight around the neck','Sleeping on the back','Alcohol consumption before bed','Enlarged tonsils or adenoids','Age-related muscle relaxation','Sleep apnea'], homecare:['Sleep on your side instead of your back','Lose excess weight','Avoid alcohol within 3 hours of bedtime','Treat nasal congestion (saline spray, decongestants)','Elevate the head of the bed slightly','Nasal strips to open nasal passages'], whenToSeeDoctor:'Snoring with gasping or choking during sleep (possible sleep apnea), excessive daytime sleepiness, observed breathing pauses during sleep, or morning headaches.', urgency:'low' },

  /* ── COMMON: SKIN ── */
  { name:'Sunburn', aliases:['sunburn','sun burn','sunburned skin','burned by sun','solar erythema'], emoji:'☀️', type:'common', description:'Skin damage caused by overexposure to ultraviolet (UV) radiation from the sun. Painful and uncomfortable, and repeated sunburns significantly increase skin cancer risk.', symptoms:['Red, warm, or hot skin','Pain and tenderness to touch','Swelling','Blistering in severe cases','Peeling skin as it heals','Headache and fever (severe sunburn)','Dehydration'], causes:['Overexposure to UV radiation','Not using sunscreen','Peak sun hours (10am-4pm) exposure','Reflective surfaces (water, sand, snow) amplifying UV','Certain medications increasing sun sensitivity'], homecare:['Get out of the sun immediately','Apply cool (not cold) compresses to skin','Moisturize with aloe vera gel or after-sun lotion','Take ibuprofen to reduce inflammation and pain','Drink plenty of water to rehydrate','Do not pop blisters','Cool bath or shower'], whenToSeeDoctor:'Severe blistering over a large area, fever above 103°F with sunburn, confusion or fainting (sun stroke), or if a child has significant sunburn.', urgency:'medium' },

  { name:'Hives', aliases:['hives','urticaria','wheals','welts','itchy bumps','nettle rash'], emoji:'🔴', type:'common', description:'Raised, itchy welts on the skin that appear suddenly, often as an allergic reaction. Can appear anywhere on the body and vary in size. Usually self-limiting.', symptoms:['Raised, red or skin-colored welts','Intense itching','Welts that appear and disappear within hours','Swelling of lips, eyes, or face (angioedema)','Burning or stinging sensation'], causes:['Allergic reaction to food, medication, or insect sting','Infections','Physical triggers — heat, cold, pressure, exercise','Stress','Autoimmune conditions','Often no identifiable cause (chronic urticaria)'], homecare:['Antihistamine tablets for itch relief','Avoid scratching — it worsens hives','Cool compress to affected areas','Identify and avoid triggers','Wear loose, smooth-textured clothing','Oatmeal bath for widespread hives'], whenToSeeDoctor:'Hives with difficulty breathing, swelling of throat or tongue, dizziness, or chest pain — this is anaphylaxis and is a medical emergency. Chronic hives (lasting more than 6 weeks) need evaluation.', urgency:'medium' },

  { name:'Contact Dermatitis', aliases:['contact dermatitis','skin reaction','allergic contact dermatitis','irritant dermatitis','chemical skin reaction'], emoji:'🔴', type:'common', description:'A red, itchy rash caused by direct contact with a substance that irritates the skin or causes an allergic reaction. Common triggers include soaps, cosmetics, jewelry, and plants.', symptoms:['Red rash limited to area of contact','Itching (can be severe)','Dry, cracked, or scaly skin','Blisters and weeping in severe cases','Burning or stinging sensation','Swelling'], causes:['Soaps, detergents, and cleaning products','Cosmetics and skincare products','Jewelry containing nickel','Latex (rubber)','Plants like poison ivy','Certain medications applied to skin'], homecare:['Remove or avoid the irritant immediately','Wash the affected skin with mild soap and water','Apply hydrocortisone cream to reduce inflammation','Cool compress for itch relief','Antihistamine for severe itching','Moisturize regularly to restore skin barrier'], whenToSeeDoctor:'Severe rash spreading beyond contact area, blistering over large areas, rash on face or genitals, or no improvement after a week. Prescription steroid cream may be needed.', urgency:'low' },

  { name:'Eczema', aliases:['eczema','atopic dermatitis','atopic eczema','dry itchy skin','infantile eczema'], emoji:'🔴', type:'common', description:'A chronic condition causing inflamed, itchy, and dry skin. Very common especially in children. Often runs in families alongside asthma and allergies. Has flares and remissions.', symptoms:['Dry, sensitive skin','Intense itching especially at night','Red or brownish-gray patches','Small raised bumps that may weep','Thickened, cracked, or scaly skin','Raw and swollen skin from scratching','Most commonly affects hands, feet, ankles, wrists, neck, eyelids, inside of elbows and knees'], causes:['Genetic factors — skin barrier defect','Immune system overreaction','Environmental triggers (soaps, wool, sweat, stress, heat)','Allergies','Family history of eczema, asthma, or hay fever'], homecare:['Moisturize skin at least twice daily with thick cream or ointment','Apply moisturizer right after bathing to lock in moisture','Use mild, fragrance-free soap and detergent','Avoid scratching — keep nails short','Wear soft cotton clothing','Identify and avoid personal triggers','Cool wet compress for flares'], whenToSeeDoctor:'Eczema causing sleep disruption, becoming infected (pus, yellow crusting, fever), spreading significantly, or not responding to moisturizers. Prescription treatments are very effective.', urgency:'medium' },

  { name:'Psoriasis', aliases:['psoriasis','psoriasis skin','psoriatic skin','scaly skin patches','silver scales skin'], emoji:'🔴', type:'common', description:'A chronic autoimmune skin condition that speeds up the skin cell life cycle, causing cells to build up rapidly on the skin surface forming scales and red patches.', symptoms:['Red patches covered with thick silvery scales','Dry cracked skin that may bleed','Itching, burning, or soreness','Thickened, pitted, or ridged nails','Swollen and stiff joints (psoriatic arthritis)','Most common on elbows, knees, scalp, lower back'], causes:['Immune system malfunction causing rapid skin cell turnover','Genetic factors','Triggers: stress, infections, certain medications, injury to skin','Smoking and obesity worsen psoriasis'], homecare:['Moisturize thoroughly and frequently','Keep skin hydrated — short lukewarm baths','Gentle, fragrance-free soap','Medicated shampoos for scalp psoriasis','Avoid triggers — stress management, avoid skin injuries','Sunlight in small doses may help (but avoid sunburn)','OTC salicylic acid or coal tar products'], whenToSeeDoctor:'Psoriasis affecting large areas of skin, causing joint pain, significantly affecting quality of life, or becoming inflamed and infected. Many effective treatments are available.', urgency:'medium' },

  { name:'Acne', aliases:['acne','pimples','zits','acne vulgaris','spots','breakout'], emoji:'🔴', type:'common', description:'A skin condition that occurs when hair follicles become plugged with oil and dead skin cells. Causes whiteheads, blackheads, and pimples. Extremely common — affects up to 85% of people at some point.', symptoms:['Whiteheads (closed clogged pores)','Blackheads (open clogged pores)','Papules (small red tender bumps)','Pimples with pus at tips','Large solid painful lumps (nodules or cysts)','Most common on face, forehead, chest, upper back, and shoulders'], causes:['Excess oil (sebum) production','Hair follicles clogged with oil and dead skin','Bacteria (Cutibacterium acnes)','Hormonal changes (puberty, menstruation, pregnancy)','Certain medications','Diet (dairy, high glycemic foods may worsen)'], homecare:['Wash face twice daily with gentle cleanser (not more)','Use non-comedogenic (won\'t clog pores) skincare products','OTC products with benzoyl peroxide, salicylic acid, or retinol','Do not pop or squeeze pimples — causes scarring','Change pillowcase frequently','Remove makeup before sleeping','Avoid touching face'], whenToSeeDoctor:'Severe or cystic acne, acne leaving scars, acne not responding to OTC treatments after 2-3 months, or acne causing significant emotional distress. Prescription treatments are highly effective.', urgency:'low' },

  { name:'Dandruff', aliases:['dandruff','flaky scalp','seborrheic dermatitis scalp','white flakes hair','itchy scalp'], emoji:'🧴', type:'common', description:'A common condition causing the skin on the scalp to flake, resulting in white or yellowish flakes on the hair and shoulders. Usually not contagious or serious.', symptoms:['White or yellowish skin flakes on scalp, hair, and shoulders','Itchy scalp','Dry or oily scalp','Redness of scalp','Scaling on eyebrows, ears, or sides of nose in severe cases'], causes:['Malassezia fungus on the scalp','Dry skin (winter dandruff)','Sensitivity to hair products','Seborrheic dermatitis (oily, irritated skin)','Infrequent shampooing'], homecare:['Use anti-dandruff shampoo regularly (zinc pyrithione, selenium sulfide, or ketoconazole)','Leave shampoo on for a few minutes before rinsing','Wash hair regularly','Avoid hair styling products that build up on scalp','Manage stress (worsens dandruff)','Tea tree oil shampoo may help mild dandruff'], whenToSeeDoctor:'Severe scalp inflammation, redness spreading to face and ears, hair loss with dandruff, or no improvement with anti-dandruff shampoos after 1 month.', urgency:'low' },

  { name:'Excessive Sweating', aliases:['excessive sweating','hyperhidrosis','sweating too much','profuse sweating','heavy sweating'], emoji:'💧', type:'common', description:'Sweating significantly more than the body needs to regulate temperature. Can affect the whole body or specific areas like the palms, feet, armpits, or face. Can be embarrassing and affect quality of life.', symptoms:['Profuse sweating even without physical activity or heat','Wet or clammy palms and soles','Frequent visible soaking of clothing','Skin problems from constant moisture (infections, rashes)','Social anxiety from sweating'], causes:['Primary hyperhidrosis — overactive sweat glands (often genetic, no underlying cause)','Secondary hyperhidrosis — diabetes, thyroid disease, menopause, infections, medications','Anxiety and stress'], homecare:['Use clinical-strength antiperspirant (aluminum chloride) applied at night','Wear breathable natural fabrics','Bathe daily and dry thoroughly','Change clothes frequently','Manage stress — yoga, breathing exercises','Avoid triggers — spicy food, caffeine, alcohol'], whenToSeeDoctor:'Sweating disrupting daily activities and relationships, sudden onset of generalized sweating in an adult (may indicate underlying disease), or night sweats.', urgency:'low' },

  { name:'Prickly Heat', aliases:['prickly heat','heat rash','miliaria','sweat rash','summer rash','red bumps heat'], emoji:'🌡️', type:'common', description:'A skin rash caused by blocked sweat ducts during hot, humid weather. Common in hot climates. Very common in infants but affects people of all ages.', symptoms:['Small red bumps or blisters on skin','Prickling or itching sensation','Redness in skin folds and areas covered by clothing','Most common on neck, chest, back, armpits, and groin','Discomfort that worsens with heat'], causes:['Hot and humid weather','Excessive sweating blocking sweat ducts','Tight or synthetic clothing that traps sweat','Physical activity in hot weather','High fever'], homecare:['Move to a cool, air-conditioned environment','Wear loose, lightweight, breathable cotton clothing','Keep skin clean and dry','Cool shower and pat dry gently','Calamine lotion to soothe itch','Avoid heavy creams or ointments that block pores'], whenToSeeDoctor:'Prickly heat not improving after a few days of home care, signs of infection (pus, increased redness, fever), or if it spreads significantly.', urgency:'low' },

  { name:'Athlete\'s Foot', aliases:['athlete\'s foot','tinea pedis','foot fungus','fungal foot infection','foot itching','foot ringworm'], emoji:'🦶', type:'common', description:'A fungal infection of the feet that causes itching, scaling, and redness between the toes and on the soles. Very contagious through contact with infected surfaces.', symptoms:['Itching, stinging, and burning between toes or on soles','Blistering feet','Cracking and peeling skin especially between toes','Dry skin on soles and sides of foot','Toenail discoloration and thickening if nails involved','Foul smell'], causes:['Dermatophyte fungus','Warm, moist environments (locker rooms, swimming pools)','Walking barefoot in public areas','Tight shoes trapping moisture','Sweaty feet'], homecare:['Use OTC antifungal cream, spray, or powder (clotrimazole, miconazole) for 2-4 weeks','Keep feet clean and completely dry especially between toes','Wear moisture-wicking socks','Change socks daily','Wear sandals in public showers and locker rooms','Alternate shoes to allow drying'], whenToSeeDoctor:'Infection spreading to toenails, not improving after 2 weeks of OTC treatment, blistering and weeping, or if you have diabetes (foot infections are serious in diabetes).', urgency:'low' },

  { name:'Ringworm', aliases:['ringworm','tinea corporis','fungal skin infection','ring shaped rash','tinea'], emoji:'🔴', type:'common', description:'A common fungal infection causing a ring-shaped itchy rash on the skin. Despite the name, no worm is involved. It is caused by the same type of fungus as athlete\'s foot and jock itch.', symptoms:['Circular, ring-shaped rash with clear center','Red, scaly, and itchy patch','Slowly expanding ring at the edges','Can appear on body, scalp, groin, or between toes','Itching at the site'], causes:['Dermatophyte fungi','Direct contact with infected person or animal (cats and dogs)','Contact with contaminated objects (combs, clothing, towels)','Warm and moist environments'], homecare:['Apply OTC antifungal cream (clotrimazole, terbinafine) twice daily for at least 2-4 weeks','Keep affected area clean and dry','Avoid sharing personal items','Wash clothing and bedding frequently','Treat pets if they are the source'], whenToSeeDoctor:'Ringworm on the scalp (needs oral antifungal), not responding to OTC treatment after 2 weeks, widespread infection, or in a person with weakened immune system.', urgency:'low' },

  { name:'Jock Itch', aliases:['jock itch','tinea cruris','groin fungal infection','groin rash','inner thigh rash'], emoji:'🔴', type:'common', description:'A fungal infection of the groin area causing an itchy, red rash. More common in men and athletes. Same fungus as athlete\'s foot and ringworm.', symptoms:['Itchy, red rash in the groin folds and inner thighs','Ring-shaped or circular rash','Chafing and burning sensation','Skin may be dry and scaly','Rash may have a clear center','Can spread to inner thighs and buttocks'], causes:['Dermatophyte fungi in warm moist groin area','Excessive sweating','Tight clothing','Obesity','Sharing towels or clothing','Having athlete\'s foot (can spread from feet'], homecare:['Apply OTC antifungal cream (clotrimazole, miconazole) twice daily for 2-4 weeks','Keep the groin area clean and dry','Wear loose, breathable cotton underwear','Change underwear daily','Dust antifungal powder in the groin area after bathing','Treat athlete\'s foot simultaneously if present'], whenToSeeDoctor:'Not improving after 2 weeks of OTC treatment, severe inflammation, spreading rash, or recurring jock itch. Oral antifungals may be prescribed.', urgency:'low' },

  { name:'Scabies', aliases:['scabies','itch mite','skin mites','scabies rash','intense itching rash'], emoji:'🔴', type:'common', description:'A skin infestation caused by a tiny mite that burrows into the skin, causing intense itching and a rash. Very contagious through close skin-to-skin contact. Requires treatment to resolve.', symptoms:['Intense itching especially at night','Thin irregular burrow tracks — tiny lines on skin','Rash with small red bumps or blisters','Most common in finger webs, wrists, waistline, armpits, and between fingers','Scratching can cause sores that become infected'], causes:['Sarcoptes scabiei mite','Prolonged skin-to-skin contact with infected person','Sharing bedding, clothing, or towels','Crowded living conditions'], homecare:['Prescription treatment is required — OTC products are not effective','Apply prescription permethrin cream to entire body from neck down (leave on 8-14 hours)','All household members and close contacts should be treated simultaneously','Wash all clothing, bedding, and towels in hot water','Items that cannot be washed should be sealed in a plastic bag for 72 hours'], whenToSeeDoctor:'Always see a doctor for scabies — it requires prescription medication. Itching may continue for 2-4 weeks after successful treatment.', urgency:'medium' },

  { name:'Head Lice', aliases:['lice','head lice','nits','louse','head lice infestation','pediculosis'], emoji:'🦟', type:'common', description:'Tiny insects that infest the scalp and hair. Spread easily among children through head-to-head contact. Cause intense scalp itching but are not dangerous and do not spread disease.', symptoms:['Intense scalp itching especially behind ears and at back of neck','Feeling of movement in hair','Visible lice on scalp (sesame seed-sized, gray-brown)','Nits (eggs) attached to hair shaft near scalp','Sores on scalp from scratching'], causes:['Direct head-to-head contact with infested person','Less commonly through sharing combs, hats, or pillows','Most common in school-age children'], homecare:['OTC medicated shampoo or lotion (permethrin, pyrethrin) — apply as directed','Comb out nits with a fine-toothed nit comb thoroughly','Repeat treatment after 9 days','Wash clothing, bedding, and hats used in last 48 hours in hot water','Soak combs in hot water','No need to fumigate the house — lice die within 24-48 hours off a head'], whenToSeeDoctor:'Lice not responding to OTC treatment, severe scalp infection from scratching, or for prescription-strength treatments.', urgency:'low' },

  { name:'Nail Fungus', aliases:['nail fungus','onychomycosis','fungal nails','yellow nails','thick nails','toenail fungus'], emoji:'💅', type:'common', description:'A fungal infection of the fingernails or toenails causing discoloration, thickening, and crumbling of the nail. Toenails are much more commonly affected than fingernails.', symptoms:['Thickened nails','Whitish, yellowish, brownish, or black discoloration','Brittle, crumbly, or ragged nails','Nail shape distortion','Foul smell from affected nail','Slightly painful nail in advanced cases'], causes:['Dermatophyte fungi (most common)','Yeasts and molds','Walking barefoot in public areas (pools, locker rooms)','Nail injury','Diabetes and poor circulation','Older age'], homecare:['OTC antifungal nail lacquer or cream — requires months of consistent use','Keep nails short, dry, and clean','Wear moisture-wicking socks','Use antifungal powder in shoes','Wear sandals in public showers','Allow feet to breathe — avoid tight shoes'], whenToSeeDoctor:'Nail fungus usually needs prescription oral antifungal medication for best results. See a doctor if OTC treatment fails after 3 months, if you have diabetes, or if infection is severe.', urgency:'low' },

  { name:'Boil', aliases:['boil','furuncle','skin boil','pus lump','red painful lump','carbuncle'], emoji:'🔴', type:'common', description:'A skin infection that starts in a hair follicle or oil gland. At first the skin turns red, then a tender lump forms filled with pus. Most boils resolve with home treatment.', symptoms:['Painful, red lump that starts small and grows','Warm and tender to touch','White or yellow center as pus collects','May rupture and drain on its own','Swollen lymph nodes nearby in large boils','Fever in severe cases'], causes:['Bacterial infection (usually Staphylococcus aureus)','Friction from tight clothing','Excessive sweating','Poor hygiene','Cuts or skin breaks allowing bacteria entry','Weak immune system'], homecare:['Apply warm compress 3-4 times daily for 20 minutes to speed drainage','Keep the area clean','Do NOT squeeze, pop, or lance the boil — this spreads infection','Once it drains naturally, clean with antiseptic and cover with a bandage','Wash hands after touching the area'], whenToSeeDoctor:'Boil on the face, spine, or groin (dangerous areas), boil with fever, very large or extremely painful boil, boil in a person with diabetes, or boil not improving after a week. A doctor may need to lance and drain it.', urgency:'medium' },

  { name:'Ingrown Toenail', aliases:['ingrown toenail','ingrown nail','nail growing into skin','painful toenail','toenail infection'], emoji:'🦶', type:'common', description:'A common condition where the corner or side of a toenail grows into the soft flesh of the toe. Causes pain, redness, and swelling. The big toe is most commonly affected.', symptoms:['Pain and tenderness along one or both sides of nail','Redness around the toenail','Swelling of the toe','Infection if bacteria enter (increased pain, pus, odor)','Skin growing over part of the nail'], causes:['Cutting toenails too short or rounding the corners','Tight footwear','Toenail injury','Naturally curved toenails','Poor foot hygiene'], homecare:['Soak the foot in warm salt water 3-4 times daily for 20 minutes','Gently lift the ingrown nail edge and place a small piece of cotton underneath','Keep the foot clean and dry','Wear roomy footwear that does not press on toes','Trim nails straight across — do not curve the corners'], whenToSeeDoctor:'Signs of infection (redness spreading, pus, increasing pain, fever), recurring ingrown nails, or if you have diabetes or poor circulation — foot infections are serious in these conditions.', urgency:'medium' },

  { name:'Warts', aliases:['warts','common wart','verruca','plantar wart','viral wart','wart on hand'], emoji:'🔴', type:'common', description:'Small, rough growths on the skin caused by the human papillomavirus (HPV). Common and usually harmless. Spread by touch — both person to person and on the same body.', symptoms:['Rough, grainy bumps on skin','Flesh-colored, white, pink, or tan color','May have tiny black dots (clotted blood vessels)','Plantar warts on soles of feet may be flat and grow inward','Can appear singly or in clusters'], causes:['Human papillomavirus (HPV) infection','Direct contact with wart (own or another person\'s)','Indirect contact through shared towels or surfaces','Cuts or breaks in skin make entry easier','Weakened immune system'], homecare:['OTC salicylic acid preparations — apply daily after soaking and filing','Cover the wart with duct tape for a week, remove, file with emery board, repeat','Cryotherapy (freezing) products available over the counter','Be patient — warts often take months to resolve','Avoid picking — can spread the virus'], whenToSeeDoctor:'Warts on the face or genitals, warts causing pain or affecting function, warts not responding to home treatment after 3 months, or if you are unsure the growth is a wart.', urgency:'low' },

  { name:'Calluses', aliases:['callus','calluses','hardened skin','thick skin','skin callus','corn on foot'], emoji:'🦶', type:'common', description:'Areas of thickened, hardened skin that develop when the skin tries to protect itself from friction and pressure. Very common on hands and feet. Rarely serious.', symptoms:['Thick, rough area of skin','Hardened or firm skin patch','Less sensitive to touch than surrounding skin','Yellowish or grayish color','Dry, waxy, or flaky appearance','Corns (smaller, more defined callus with a hard center) on toes'], causes:['Repeated friction or pressure','Ill-fitting shoes','Standing or walking for long periods','Playing an instrument or using tools without gloves'], homecare:['Soak the area in warm soapy water to soften','Gently rub with a pumice stone or foot file after soaking','Moisturize regularly with thick cream','Wear well-fitting, padded footwear','Padding over callus areas in shoes'], whenToSeeDoctor:'Painful callus, callus showing signs of infection, callus in a person with diabetes or poor circulation, or if you are unsure it is a callus (not a plantar wart).', urgency:'low' },

  /* ── COMMON: DIGESTIVE ── */
  { name:'Hiccups', aliases:['hiccups','hiccup','singultus','hiccoughs'], emoji:'😮', type:'common', description:'Involuntary contractions of the diaphragm followed by sudden closure of the vocal cords, producing the characteristic "hic" sound. Almost always temporary and harmless.', symptoms:['Repetitive involuntary "hic" sound','Brief feeling of tightening in chest or throat','Usually resolves within a few minutes'], causes:['Eating too quickly or too much','Swallowing air','Carbonated drinks','Sudden temperature changes in the stomach','Alcohol','Excitement or stress'], homecare:['Hold breath for 10-15 seconds and release slowly','Breathe into a paper bag (not plastic) for a minute','Swallow three times before breathing again','Drink a glass of water slowly without stopping','A spoonful of sugar may help','Gently pull the tongue forward'], whenToSeeDoctor:'Hiccups lasting more than 48 hours, severely interrupting sleep or eating, or accompanied by severe abdominal pain or vomiting — persistent hiccups can rarely indicate a serious underlying condition.', urgency:'low' },

  { name:'Mouth Ulcers', aliases:['mouth ulcers','canker sores','aphthous ulcers','oral ulcers','sores in mouth','painful mouth sores'], emoji:'🦷', type:'common', description:'Painful sores that appear inside the mouth — on the tongue, gums, inside of cheeks, or lips. Very common and usually harmless, healing on their own within 1-2 weeks.', symptoms:['Round or oval sores inside the mouth','White, yellow, or gray center with red border','Painful especially when eating, drinking, or speaking','Single or multiple ulcers','Tingling or burning sensation before ulcer appears'], causes:['Minor injury (biting cheek, braces, hard food)','Stress and hormonal changes','Vitamin B12, iron, or folate deficiency','Food sensitivities (acidic fruits, spicy food)','Certain medications','Crohn\'s disease or celiac disease'], homecare:['Rinse with warm salt water several times a day','Apply OTC ulcer gel or paste (lignocaine, triamcinolone)','Avoid acidic, spicy, or hard foods while healing','Use a soft toothbrush','Maintain good oral hygiene','Vitamin B12 or iron supplements if deficient'], whenToSeeDoctor:'Ulcers lasting more than 3 weeks, unusually large or painful, recurring frequently, spreading, or accompanied by fever. Rarely, mouth ulcers can indicate more serious conditions.', urgency:'low' },

  { name:'Cold Sores', aliases:['cold sores','fever blisters','herpes labialis','lip sores','oral herpes','blisters on lips'], emoji:'🦷', type:'common', description:'Small blisters that develop on or around the lips caused by the herpes simplex virus (HSV-1). Extremely common — about 67% of people carry the virus. Recur periodically.', symptoms:['Tingling, itching, or burning around lips before blisters appear','Small fluid-filled blisters on or around lips','Blisters break and crust over','Sore or pain at the site','Mild fever or swollen lymph nodes in first outbreak'], causes:['Herpes simplex virus type 1 (HSV-1)','Virus stays dormant and reactivates with triggers','Triggers: stress, fever, sun exposure, cold wind, hormonal changes, illness'], homecare:['Apply antiviral cream (acyclovir) at first sign of tingling to shorten outbreak','Keep the area clean and moisturized with petroleum jelly','Do not touch the sore and wash hands frequently','Avoid kissing and sharing lip products during outbreak','Ice pack on blisters for pain relief','Sunscreen lip balm to prevent sun-triggered outbreaks'], whenToSeeDoctor:'Very frequent outbreaks (more than 6 per year), cold sores in or near the eye, sores spreading to other areas, or in a person with weakened immunity — oral antivirals may be prescribed.', urgency:'low' },

  { name:'Bleeding Gums', aliases:['bleeding gums','gum bleeding','gingivitis','gums bleed','blood in mouth brushing'], emoji:'🦷', type:'common', description:'Gums that bleed during brushing or flossing. Very common and usually a sign of gum disease (gingivitis) that is treatable. Should not be ignored.', symptoms:['Gums bleed when brushing or flossing','Red, swollen, or tender gums','Receding gums','Persistent bad breath','Loose teeth in advanced stages'], causes:['Gingivitis (plaque buildup on gums)','Brushing too hard with a hard toothbrush','Vitamin C or K deficiency','Blood thinning medications','Hormonal changes in pregnancy','Vitamin deficiency'], homecare:['Brush gently twice daily with a soft-bristled toothbrush','Floss daily — regular flossing actually reduces bleeding over time','Rinse with antiseptic mouthwash','Eat a balanced diet — adequate vitamin C and K','Avoid smoking — it worsens gum disease'], whenToSeeDoctor:'Gums that bleed heavily or spontaneously without brushing, persistent bleeding beyond 2 weeks of improved hygiene, loose teeth, or gum bleeding with other unusual bleeding — needs dental checkup.', urgency:'medium' },

  { name:'Gingivitis', aliases:['gingivitis','gum disease','gum inflammation','swollen gums','periodontal disease early'], emoji:'🦷', type:'common', description:'Mild inflammation of the gums (gingiva) caused by plaque buildup on teeth. The most common form of gum disease. Reversible with good oral hygiene and professional cleaning.', symptoms:['Red, swollen, or puffy gums','Gums that bleed easily when brushing or flossing','Bad breath','Tender gums','Gum recession','Dark red gums instead of healthy pink'], causes:['Plaque buildup on teeth (most common)','Poor oral hygiene','Smoking or tobacco use','Dry mouth','Certain medications','Pregnancy hormones','Vitamin C deficiency'], homecare:['Brush teeth twice daily with fluoride toothpaste','Use a soft-bristled brush and gentle circular motion','Floss once daily to remove plaque between teeth','Use antiseptic mouthwash','Professional dental cleaning to remove tartar (cannot be removed at home)','Quit smoking'], whenToSeeDoctor:'See a dentist for professional cleaning if gingivitis does not improve with better home care after 2 weeks. Untreated gingivitis progresses to periodontitis (serious gum disease).', urgency:'medium' },

  { name:'Sensitive Teeth', aliases:['sensitive teeth','tooth sensitivity','teeth sensitivity','pain from cold food','pain from hot food','dentin hypersensitivity'], emoji:'🦷', type:'common', description:'Sharp, temporary pain in teeth triggered by certain stimuli like hot, cold, sweet, or acidic foods. Very common — affects about 1 in 8 adults. Usually treatable.', symptoms:['Sharp, sudden pain when consuming hot, cold, sweet, or acidic food or drinks','Pain from cold air on teeth','Discomfort when brushing or flossing','Pain that subsides quickly after stimulus is removed'], causes:['Enamel erosion from acidic foods and drinks','Brushing too hard (wears away enamel)','Gum recession exposing root surfaces','Teeth grinding (bruxism)','Cracked tooth','Tooth decay or old fillings'], homecare:['Use desensitizing toothpaste (potassium nitrate or stannous fluoride) — takes 4-6 weeks','Brush with a soft-bristled toothbrush and gentle pressure','Avoid highly acidic foods and drinks','Use fluoride mouthwash','Wait 30 minutes after eating before brushing','Wear a night guard if grinding teeth'], whenToSeeDoctor:'Severe or persistent sensitivity, sensitivity that does not improve after 4-6 weeks of desensitizing toothpaste, or if only one specific tooth is sensitive (may need treatment).', urgency:'low' },

  { name:'Teeth Grinding', aliases:['teeth grinding','bruxism','jaw clenching','grinding teeth during sleep','nocturnal bruxism'], emoji:'🦷', type:'common', description:'Involuntary grinding, gnashing, or clenching of the teeth. Most often occurs during sleep. Very common and often linked to stress. Can damage teeth over time.', symptoms:['Worn down, flattened, or chipped teeth','Increased tooth sensitivity','Jaw pain or tightness','Headache (especially in morning)','Earache-like pain','Facial pain','Disrupted sleep of partner from grinding sounds'], causes:['Stress and anxiety (most common cause)','Sleep disorders (sleep apnea)','Certain medications (SSRIs)','Caffeine or alcohol','Misaligned teeth','Personality type (competitive, aggressive tendencies)'], homecare:['Wear a custom night guard (mouthguard) during sleep','Manage stress — exercise, yoga, meditation','Reduce caffeine and alcohol especially before bed','Jaw relaxation exercises','Apply warm compress to jaw muscles before bed','Be aware of clenching during the day and consciously relax jaw'], whenToSeeDoctor:'Significant tooth wear, jaw pain or TMJ problems, morning headaches, or sleep disruption. A dentist can provide a custom night guard and check for tooth damage.', urgency:'low' },

  { name:'TMJ Disorder', aliases:['tmj','temporomandibular joint','jaw pain','jaw clicking','jaw locking','jaw disorder'], emoji:'🦷', type:'common', description:'A group of conditions causing pain and dysfunction in the jaw joint (temporomandibular joint) and the muscles that control jaw movement. Very common — affects up to 15% of adults.', symptoms:['Pain or tenderness in jaw','Aching pain in and around the ear','Difficulty or pain while chewing','Aching facial pain','Jaw clicking, popping, or grating','Locking of the jaw joint (difficulty opening or closing mouth)','Headaches'], causes:['Teeth grinding or clenching (bruxism)','Jaw injury or arthritis','Stress causing jaw tightening','Misaligned bite','Jaw muscle overuse'], homecare:['Eat soft foods and cut food into small pieces','Avoid hard, chewy, or crunchy foods','Apply ice or warm compress to the jaw area','Avoid extreme jaw movements (wide yawning, gum chewing)','Jaw stretching and relaxation exercises','OTC anti-inflammatory pain relievers','Stress management'], whenToSeeDoctor:'Jaw locking, severe pain, difficulty eating, or symptoms persisting more than a few weeks. A dentist or specialist can provide night guards, physical therapy, or other treatments.', urgency:'low' },

  /* ── COMMON: MUSCULOSKELETAL ── */
  { name:'Muscle Cramp', aliases:['muscle cramp','leg cramp','muscle spasm','charley horse','cramps in legs','night cramps'], emoji:'🦵', type:'common', description:'A sudden, involuntary contraction of one or more muscles. Often occurs in the legs, especially the calf. Very common and usually harmless though painful.', symptoms:['Sudden intense pain in the muscle','Hard, tight lump visible under skin','Muscle that feels firm to touch','Involuntary visible twitching','Lasts from a few seconds to several minutes','Residual soreness after the cramp'], causes:['Dehydration','Electrolyte imbalance (low potassium, calcium, magnesium)','Muscle overuse or fatigue','Prolonged sitting or standing in one position','Poor circulation','Certain medications (diuretics, statins)'], homecare:['Stretch the cramped muscle — for calf cramp, flex foot upward','Massage the muscle firmly','Apply heat (warm towel or heating pad) to relax the muscle','Drink water and electrolyte solution','Walk around to improve circulation','Increase dietary potassium (bananas), magnesium (nuts, seeds), and calcium'], whenToSeeDoctor:'Frequent or severe muscle cramps, cramps not responding to stretching, cramps with significant swelling or redness, or if associated with leg pain at rest (may indicate circulation problem).', urgency:'low' },

  { name:'Sprain', aliases:['sprain','ankle sprain','wrist sprain','ligament sprain','twisted ankle','joint sprain'], emoji:'🦶', type:'common', description:'A stretching or tearing of ligaments — the tough bands of fibrous tissue connecting bones in a joint. Ankle sprains are the most common. Almost everyone sprains something at some point.', symptoms:['Pain at the joint','Swelling','Bruising','Limited range of motion','Instability of the joint','Muscle spasm around the joint'], causes:['Sudden twisting or rolling of a joint beyond normal range','Falls','Sudden impact during sports','Landing awkwardly'], homecare:['RICE method immediately: Rest, Ice (20 min on, 20 off), Compression (elastic bandage), Elevation above heart level','Take OTC pain relievers (ibuprofen) for pain and swelling','Avoid bearing weight on a severe sprain','After swelling reduces, gentle range-of-motion exercises','Use a brace or support during recovery'], whenToSeeDoctor:'Inability to bear weight at all, severe swelling or bruising, numbness, pop heard at time of injury, or no improvement after 2-3 days. Severe sprains or fractures need X-ray.', urgency:'medium' },

  { name:'Muscle Strain', aliases:['muscle strain','pulled muscle','muscle pull','muscle tear','muscle injury','strained muscle'], emoji:'💪', type:'common', description:'An injury to a muscle or tendon — the fibrous tissue connecting muscle to bone. Ranges from overstretching to a partial or complete tear. Very common in athletes and active people.', symptoms:['Sudden pain during activity','Muscle weakness','Swelling and bruising','Limited range of motion','Muscle spasms','Stiffness'], causes:['Sudden forceful movement','Overexertion or lifting heavy objects improperly','Inadequate warm-up before exercise','Fatigue or poor flexibility','Sports injuries'], homecare:['Rest the injured muscle — avoid activities that cause pain','Ice for first 48 hours (20 minutes on, 20 off)','Compression with an elastic bandage','Elevation of the injured limb','OTC anti-inflammatory pain relievers','After 48-72 hours, gentle stretching and movement'], whenToSeeDoctor:'Unable to move the affected area, severe pain or bruising, muscle deformity, or no improvement after a week. A complete tear may require physiotherapy or surgery.', urgency:'medium' },

  { name:'Neck Pain', aliases:['neck pain','neck ache','stiff neck','cervical pain','sore neck','neck stiffness'], emoji:'🦴', type:'common', description:'Pain and stiffness in the neck area, one of the most common musculoskeletal complaints. Usually caused by poor posture, muscle tension, or sleeping awkwardly. Rarely serious.', symptoms:['Pain and stiffness in neck','Headache starting at base of skull','Pain radiating to shoulder or arm','Difficulty turning head','Muscle tightness or spasms','Numbness or tingling in arm or hand (if nerve involved)'], causes:['Poor posture (looking down at phone — text neck)','Sleeping in awkward position','Stress and tension','Sitting at desk for long hours','Whiplash from injury','Cervical spondylosis (age-related wear)'], homecare:['Gentle neck stretches and rotation exercises','Apply heat or cold to affected area','OTC pain relievers','Maintain good posture — keep screen at eye level','Use a supportive pillow','Take breaks from sitting — move around every hour'], whenToSeeDoctor:'Neck pain after a car accident or fall, pain with numbness or weakness in arms or hands, severe headache with neck stiffness and fever (possible meningitis — emergency), or pain lasting more than a week.', urgency:'medium' },

  { name:'Shoulder Pain', aliases:['shoulder pain','shoulder ache','sore shoulder','shoulder joint pain','rotator cuff pain'], emoji:'🦴', type:'common', description:'Pain in or around the shoulder joint. The shoulder is the most mobile joint in the body and very prone to injury and overuse. Common causes range from muscle strain to rotator cuff problems.', symptoms:['Aching or sharp pain in shoulder','Pain reaching overhead or behind the back','Limited range of motion','Weakness in the arm','Swelling or bruising around shoulder','Pain worse at night or when lying on shoulder'], causes:['Rotator cuff injury (most common)','Frozen shoulder (adhesive capsulitis)','Shoulder impingement syndrome','Tendinitis or bursitis','Dislocation or fracture','Referred pain from neck or heart (left shoulder)'], homecare:['Rest and avoid aggravating movements','Ice for acute pain (first 48 hours), then heat','OTC anti-inflammatory medication','Gentle shoulder range-of-motion exercises','Physiotherapy exercises if no improvement after a week'], whenToSeeDoctor:'Sudden severe pain with deformity, inability to move arm, pain after injury, chest pain with left shoulder pain (cardiac emergency), or pain persisting for more than 2-3 weeks.', urgency:'medium' },

  { name:'Knee Pain', aliases:['knee pain','knee ache','sore knee','knee joint pain','knee problem'], emoji:'🦵', type:'common', description:'Pain in or around the knee joint. Extremely common — the knee is one of the most commonly injured joints in the body. Causes range from mild overuse to serious injury.', symptoms:['Pain in or around the knee','Swelling and stiffness','Redness and warmth to touch','Popping or crunching sounds','Weakness or instability','Inability to fully straighten or bend the knee'], causes:['Runner\'s knee (patellofemoral pain)','ACL or ligament injury','Meniscus tear','Osteoarthritis (older adults)','Tendinitis','Bursitis (fluid-filled sac inflammation)','Obesity (excess stress on joints)'], homecare:['Rest from aggravating activities','Ice for 20 minutes several times a day','Compression bandage','Elevate the leg when resting','OTC anti-inflammatory pain relievers','Low-impact exercise — swimming, cycling','Strengthening exercises for the quadriceps and hamstrings'], whenToSeeDoctor:'Severe swelling, inability to bear weight, significant deformity, knee giving way, pop at time of injury, or pain not improving after 2-3 weeks of home treatment.', urgency:'medium' },

  { name:'Heel Pain', aliases:['heel pain','heel ache','plantar fasciitis','sore heel','bottom of foot pain'], emoji:'🦶', type:'common', description:'Pain at the bottom or back of the heel. Plantar fasciitis is the most common cause — affecting the thick band of tissue connecting the heel bone to the toes. Very common in runners and people who stand all day.', symptoms:['Stabbing pain in the bottom of the foot near the heel','Pain worst with first steps in the morning or after rest','Pain that decreases after a few minutes of walking but returns with prolonged standing','Tenderness when pressing on the heel'], causes:['Plantar fasciitis — overuse and strain of plantar fascia','Heel spur (bony growth on heel)','Achilles tendinitis','Standing for long periods on hard surfaces','Obesity','Ill-fitting shoes with inadequate support','Flat feet or high arches'], homecare:['Rest and avoid high-impact activities','Ice the heel for 15-20 minutes several times daily','Stretch the plantar fascia and calf muscles before getting out of bed','Wear supportive shoes with good arch support — avoid bare feet on hard floors','Heel pads or orthotic insoles in shoes','OTC anti-inflammatory medication'], whenToSeeDoctor:'Severe heel pain that does not improve after 2-3 weeks, pain with swelling or numbness, pain after a fall or injury, or if the pain significantly limits walking.', urgency:'low' },

  { name:'Ankle Pain', aliases:['ankle pain','sore ankle','ankle ache','ankle injury','ankle swelling'], emoji:'🦶', type:'common', description:'Pain in or around the ankle joint, one of the most commonly injured areas of the body. Can result from sprains, tendinitis, or overuse.', symptoms:['Pain and tenderness around the ankle','Swelling','Bruising','Stiffness and limited movement','Instability when walking','Warmth around the joint'], causes:['Ankle sprain (most common)','Achilles tendinitis','Stress fracture','Gout (sudden severe ankle pain)','Arthritis','Overuse from running or sports'], homecare:['RICE method — Rest, Ice, Compression, Elevation','OTC anti-inflammatory pain relievers','Ankle support or brace','Avoid high-impact activities until pain subsides','Gentle range-of-motion exercises as pain improves'], whenToSeeDoctor:'Inability to bear weight, severe swelling, numbness, deformity, or suspected fracture. X-ray may be needed to rule out fracture.', urgency:'medium' },

  { name:'Frozen Shoulder', aliases:['frozen shoulder','adhesive capsulitis','stiff shoulder','shoulder stiffness','shoulder capsulitis'], emoji:'🦴', type:'common', description:'A condition causing stiffness and pain in the shoulder joint that progressively worsens over time. Can last 1-3 years. More common in people with diabetes and those aged 40-60.', symptoms:['Dull or aching shoulder pain','Gradually increasing stiffness limiting range of motion','Difficulty reaching overhead, behind the back, or across the body','Pain worse at night','3 phases: freezing (painful), frozen (stiff but less pain), thawing (gradual improvement)'], causes:['Often no clear cause','Post-surgery or injury immobilization','Diabetes significantly increases risk','Thyroid disease','Previous shoulder conditions'], homecare:['Gentle daily stretching exercises to maintain and improve range of motion','Apply heat before exercises to loosen the joint','OTC anti-inflammatory medication for pain','Physical therapy is the most effective treatment','Do not stop moving the shoulder — inactivity worsens stiffness'], whenToSeeDoctor:'Significant shoulder stiffness lasting more than a few weeks. A physiotherapist is essential for managing this condition. Steroid injections or manipulation under anesthesia may be needed.', urgency:'medium' },

  { name:'Tennis Elbow', aliases:['tennis elbow','lateral epicondylitis','elbow pain','outer elbow pain','elbow tendinitis'], emoji:'🦾', type:'common', description:'A painful condition caused by overuse of the arm, forearm, and hand muscles, leading to pain and tenderness on the outside of the elbow. Despite the name, most cases are not from tennis.', symptoms:['Pain and burning on the outer side of the elbow','Weak grip strength','Pain worsens with forearm activity','Pain when lifting, using tools, or opening jars','Tenderness when pressing the outer elbow'], causes:['Repetitive arm, forearm, and wrist movements','Computer mouse use','Carpentry, plumbing, painting','Racket sports — tennis, badminton','Age-related tendon degeneration'], homecare:['Rest from aggravating activities','Ice the elbow for 15-20 minutes several times daily','OTC anti-inflammatory medication','Tennis elbow brace (counterforce strap) just below the elbow','Specific forearm stretching and strengthening exercises','Ergonomic adjustments to workstation'], whenToSeeDoctor:'Pain severely limiting daily activities, not improving after 6-8 weeks of home care, or affecting work. Physiotherapy and steroid injections are effective treatments.', urgency:'low' },

  { name:'Carpal Tunnel Syndrome', aliases:['carpal tunnel','carpal tunnel syndrome','wrist nerve pain','tingling hands','numb hands','hand numbness wrist'], emoji:'🤲', type:'common', description:'A condition caused by pressure on the median nerve in the wrist, causing pain, numbness, and tingling in the hand and arm. Very common especially in office workers and people doing repetitive hand work.', symptoms:['Numbness or tingling in thumb, index, middle, and ring fingers','Burning or aching pain in wrist and hand','Pain radiating up the arm','Weakness in grip','Dropping things','Symptoms worse at night','Symptoms worse after prolonged use of the hand'], causes:['Repetitive hand and wrist movements','Pregnancy (fluid retention)','Obesity','Diabetes, hypothyroidism, or rheumatoid arthritis','Anatomically smaller carpal tunnel','Wrist fracture'], homecare:['Wear a wrist splint especially at night to keep wrist neutral','Take frequent breaks from repetitive hand activities','Ice the wrist for pain relief','Keep wrist in neutral position while using computer','Specific wrist and hand stretching exercises','OTC anti-inflammatory medication for pain'], whenToSeeDoctor:'Significant numbness or weakness, symptoms waking you from sleep frequently, symptoms in both hands, or affecting work. Nerve conduction study can confirm. Surgery is very effective for severe cases.', urgency:'medium' },

  { name:'Costochondritis', aliases:['costochondritis','chest wall pain','rib pain','cartilage chest pain','tietze syndrome','non cardiac chest pain'], emoji:'🦴', type:'common', description:'Inflammation of the cartilage connecting the ribs to the breastbone (sternum). Causes chest pain that can be mistaken for a heart attack. Very common and not dangerous.', symptoms:['Sharp chest pain that worsens with deep breathing or coughing','Tenderness when pressing on the ribs at the breastbone','Pain usually on the left side','Pain worsens with movement or exercise','Pain may radiate to arm'], causes:['Often no clear cause','Upper respiratory infections','Physical strain or injury to the chest wall','Repetitive movements (rowing, heavy lifting)','Arthritis'], homecare:['Rest and avoid activities that worsen pain','Apply heat or ice to the tender area','OTC anti-inflammatory medication (ibuprofen)','Gentle stretching of the chest muscles','Sleep on your back or unaffected side','Reassurance — it is not a heart condition'], whenToSeeDoctor:'First episode of chest pain should always be evaluated to rule out cardiac cause. If costochondritis is confirmed and not improving after a few weeks, see a doctor for further management.', urgency:'medium' },

  { name:'Varicose Veins', aliases:['varicose veins','varicose','bulging veins','swollen veins','spider veins','leg veins'], emoji:'🦵', type:'common', description:'Swollen, twisted veins visible under the skin, usually in the legs. They develop when valves in the veins weaken, causing blood to pool. Very common — affects about 1 in 3 adults.', symptoms:['Dark blue or purple veins visible under skin','Bulging, twisted, or rope-like veins','Aching, heavy feeling in legs','Muscle cramping and swelling in lower legs','Itching around affected veins','Pain worsening after prolonged sitting or standing'], causes:['Weakened or damaged vein valves','Standing or sitting for long periods','Pregnancy','Obesity','Older age','Family history'], homecare:['Wear compression stockings to improve circulation','Elevate legs when resting','Exercise regularly — walking, cycling, swimming','Avoid prolonged standing or sitting — take breaks','Maintain a healthy weight','Avoid tight clothing around waist or legs'], whenToSeeDoctor:'Severe pain, skin changes (discoloration, thickening) near the varicose veins, leg ulcers, bleeding from a vein, or if appearance or discomfort is significantly bothersome. Several treatments are available.', urgency:'low' },

  { name:'Restless Legs Syndrome', aliases:['restless legs','restless leg syndrome','rls','leg discomfort at night','urge to move legs','crawling sensation legs'], emoji:'🦵', type:'common', description:'A nervous system disorder causing an uncomfortable urge to move the legs, especially at night. Significantly disrupts sleep. More common in women and older adults.', symptoms:['Uncomfortable sensations in legs described as crawling, itching, tingling, or pulling','Urge to move legs that is hard to resist','Sensations worse when at rest or lying down','Temporary relief with movement','Symptoms worse in the evening and at night','Sleep disturbance from discomfort'], causes:['Often no identifiable cause (primary RLS)','Iron deficiency anemia','Pregnancy','Kidney failure','Certain medications (antidepressants, antihistamines)','Family history'], homecare:['Leg massage before bed','Hot or cold compress on legs','Regular moderate exercise (but not late at night)','Good sleep hygiene','Reduce caffeine, alcohol, and tobacco','Iron supplements if iron deficient — check iron levels first','Take a warm bath before bed'], whenToSeeDoctor:'Symptoms significantly disrupting sleep and quality of life, or if iron deficiency is suspected. Medication is available for moderate to severe RLS.', urgency:'low' },

  { name:'Water Retention', aliases:['water retention','edema','oedema','swollen ankles','puffiness','fluid retention','bloating swelling'], emoji:'💧', type:'common', description:'Accumulation of excess fluid in body tissues causing swelling (edema). Commonly affects the ankles, feet, and legs. Can have many causes from mild (prolonged sitting) to serious (heart or kidney disease).', symptoms:['Swelling in ankles, feet, legs, or hands','Puffiness of the skin','Skin that retains a dimple after pressing (pitting edema)','Feeling of heaviness in legs','Bloated abdomen','Weight fluctuations'], causes:['Prolonged sitting or standing','Hot weather','High salt diet','Premenstrual syndrome','Pregnancy','Certain medications (calcium channel blockers, steroids)','Heart failure, kidney disease, or liver disease (serious causes)'], homecare:['Reduce salt intake','Elevate swollen limbs above heart level when resting','Exercise regularly to improve circulation','Compression stockings','Drink adequate water — dehydration paradoxically worsens retention','Reduce refined carbohydrates'], whenToSeeDoctor:'Sudden or severe swelling especially in one leg (possible blood clot), swelling with shortness of breath or chest pain, swelling that pits deeply, swelling with heart or kidney disease, or no obvious cause.', urgency:'medium' },

  /* ── COMMON: GENERAL & SYSTEMIC ── */
  { name:'Nose Bleed', aliases:['nose bleed','nosebleed','epistaxis','bleeding from nose','blood from nose'], emoji:'👃', type:'common', description:'Bleeding from the nostril, nasal cavity, or nasopharynx. Very common — especially in children and older adults. Usually not serious. Most nosebleeds come from the front of the nose (anterior).', symptoms:['Blood flowing from one or both nostrils','May feel blood dripping at back of throat','Nausea from swallowing blood'], causes:['Dry nasal membranes (dry climate or indoor heating)','Nose picking','Blowing nose forcefully','Allergies or colds causing nasal inflammation','Injury to the nose','Blood thinning medications','High blood pressure'], homecare:['Sit upright and lean slightly forward (not back — swallowing blood causes nausea)','Pinch the soft part of the nose firmly for 10-15 minutes without releasing','Breathe through mouth','Apply a cold compress to the nose bridge','After bleeding stops, avoid blowing nose for several hours','Use saline nasal spray to keep nasal passages moist'], whenToSeeDoctor:'Bleeding not stopping after 20 minutes, very heavy blood loss, nosebleed after a head injury, frequent recurring nosebleeds, or nosebleed in someone on blood thinners.', urgency:'medium' },

  { name:'Insect Bite', aliases:['insect bite','mosquito bite','bug bite','ant bite','insect sting','mosquito bite reaction'], emoji:'🦟', type:'common', description:'The skin reaction to a bite or sting from an insect. Most are harmless and cause only local irritation, though some can cause allergic reactions or transmit disease.', symptoms:['Small red bump or raised weal at bite site','Itching and irritation','Swelling around the site','Pain if stung (bee, wasp)','Multiple bites may cause widespread itching'], causes:['Mosquitoes, flies, midges','Ants, beetles','Fleas and bed bugs','Spiders','Being outdoors especially at dawn and dusk'], homecare:['Do not scratch — causes infection and worsens itching','Apply cold compress or ice to reduce swelling','Antihistamine cream or tablets for significant itching','Calamine lotion for itch relief','Wash bite area with soap and water','Hydrocortisone cream for inflammation'], whenToSeeDoctor:'Signs of severe allergic reaction (anaphylaxis) — difficulty breathing, swelling of face or throat, rapid heartbeat, dizziness — call emergency immediately. Also see doctor for bites from potentially dangerous spiders or if signs of infection develop.', urgency:'medium' },

  { name:'Bee Sting', aliases:['bee sting','wasp sting','bee bite','hornet sting','venom sting'], emoji:'🐝', type:'common', description:'An injection of venom from a bee, wasp, or hornet into the skin. Usually causes local pain and swelling. Can be dangerous in people with venom allergies.', symptoms:['Instant sharp pain at sting site','Red weal or raised bump','Swelling around the sting area','Itching and warmth','Bee leaves stinger in skin (wasps do not)'], causes:['Bee, wasp, or hornet sting when disturbed or threatened'], homecare:['Remove bee stinger quickly by scraping sideways (do not pinch — squeezes more venom in)','Wash area with soap and water','Apply cold compress or ice pack for pain and swelling','Take antihistamine tablet for itching and mild allergic reaction','OTC pain reliever if needed'], whenToSeeDoctor:'Signs of anaphylaxis — difficulty breathing, swelling of lips or throat, rapid heartbeat, dizziness, or pale skin — this is a medical emergency, call ambulance immediately. Those with known bee allergies should carry an epinephrine auto-injector (EpiPen).', urgency:'high' },

  { name:'Food Poisoning', aliases:['food poisoning','food borne illness','contaminated food','bacterial food poisoning','vomiting and diarrhea','stomach bug'], emoji:'🤢', type:'common', description:'Illness caused by eating food contaminated with bacteria, viruses, or toxins. Ranges from mild to severe. Usually resolves within a few days with good hydration.', symptoms:['Nausea and vomiting','Diarrhea (may be bloody)','Stomach cramps and pain','Fever','Weakness and fatigue','Onset usually within hours of eating contaminated food'], causes:['Bacteria (Salmonella, E. coli, Campylobacter, Staphylococcus)','Viruses (Norovirus, Hepatitis A)','Toxins from bacteria in food','Undercooked meat, poultry, seafood, or eggs','Unwashed fruits and vegetables','Improper food storage'], homecare:['Rest and stay hydrated — sip ORS or clear fluids frequently','Start with bland foods when tolerable (BRAT diet: banana, rice, applesauce, toast)','Avoid dairy, fatty, spicy, or sweet foods while recovering','Do not take anti-diarrheal medication if there is fever or blood in stool'], whenToSeeDoctor:'Blood in vomit or stool, fever above 102°F, signs of dehydration, severe abdominal pain, diarrhea lasting more than 3 days, neurological symptoms (blurred vision, muscle weakness — possible botulism), or in elderly, infants, or immunocompromised.', urgency:'medium' },

  { name:'Motion Sickness', aliases:['motion sickness','travel sickness','car sickness','seasickness','sea sickness','airsickness'], emoji:'🚗', type:'common', description:'Nausea, dizziness, and discomfort caused by a conflict between what your eyes see and what your inner ear senses. Extremely common — affects up to 33% of people.', symptoms:['Nausea and vomiting','Pale or cold sweaty skin','Dizziness','Headache','Fatigue and drowsiness','Increased saliva production','Belching'], causes:['Conflict between visual and inner ear (vestibular) signals','Car, boat, airplane, or bus travel','Reading while in a moving vehicle','Sitting in rear seats of vehicles','VR headsets and simulators'], homecare:['Sit in the front seat of car, front of bus, over wings in airplane, or deck of ship','Look at the horizon or a fixed point in the distance','Avoid reading or screens during travel','Fresh air — open window or air conditioning','Ginger — tea, candies, or capsules reduce nausea','OTC antihistamines (dimenhydrinate, meclizine) taken before travel'], whenToSeeDoctor:'Severe motion sickness significantly affecting travel, if home remedies and OTC medications fail. Prescription medications (scopolamine patch) are very effective.', urgency:'low' },

  { name:'Sunstroke', aliases:['sunstroke','sun stroke','heat stroke sun','sun heatstroke'], emoji:'☀️', type:'common', description:'A severe form of heat injury caused by prolonged exposure to the sun, resulting in the body\'s temperature regulation failing. A medical emergency requiring immediate action.', symptoms:['High body temperature — above 103°F (39.4°C)','Hot, red, dry skin (no sweating)','Rapid, strong pulse','Confusion, disorientation, or unconsciousness','Headache and dizziness','Nausea','Slurred speech'], causes:['Prolonged sun exposure without shade','Dehydration','Vigorous outdoor exercise in hot weather','Inadequate fluid intake','Being in a hot enclosed space'], homecare:['Move to cool shade or air-conditioned area immediately','Remove excess clothing','Cool down with cool (not ice cold) water — spray, sponge, or cool wet cloths','Fan the person while misting with water','Place ice packs or cold wet towels at neck, armpits, and groin','Do not give fluids if person is unconscious'], whenToSeeDoctor:'Sunstroke is a medical emergency — call an ambulance immediately. Do not wait to see if the person improves. Brain damage can occur rapidly with sustained high body temperature.', urgency:'high' },

  { name:'Swollen Lymph Nodes', aliases:['swollen lymph nodes','swollen glands','lymph node swelling','enlarged lymph nodes','lumps in neck','glands in neck'], emoji:'🤒', type:'common', description:'Lymph nodes are small bean-shaped structures part of the immune system. They swell when fighting infection. Usually a normal sign the body is responding to illness.', symptoms:['Tender, swollen lumps under skin — most commonly in neck, armpits, or groin','Runny nose, sore throat, fever (if due to infection)','Hard, immovable, or painless swollen nodes can indicate something more serious'], causes:['Infection (cold, flu, strep throat, ear infection — most common)','Skin infection near the node','Dental abscess','Certain viral infections (glandular fever)','Rarely: lymphoma or other cancers'], homecare:['Rest and treat the underlying infection','OTC pain relievers for tender nodes','Warm compress for comfort','Most lymph nodes return to normal within 2-4 weeks of infection resolving'], whenToSeeDoctor:'Nodes larger than 1 inch, hard or rubbery texture, not tender, present for more than 2-4 weeks, not related to an obvious infection, accompanied by weight loss or night sweats — needs evaluation.', urgency:'medium' },

  { name:'Tonsillitis', aliases:['tonsillitis','swollen tonsils','tonsil infection','throat tonsil','inflamed tonsils'], emoji:'🗣️', type:'common', description:'Inflammation of the tonsils — two lymph nodes at the back of the throat. Very common especially in children. Can be caused by bacteria or viruses.', symptoms:['Sore throat','Red, swollen tonsils','White or yellow coating or spots on tonsils','Difficulty swallowing','Fever','Swollen lymph nodes in neck','Bad breath','Headache'], causes:['Viral infection (most common)','Streptococcus bacteria (strep throat)','Spreads through droplets or direct contact'], homecare:['Rest and drink plenty of fluids','Warm salt water gargle','Cold foods like ice cream or popsicles soothe throat','OTC pain relievers and fever reducers','Honey and lemon tea','Soft foods easy to swallow'], whenToSeeDoctor:'Severe difficulty swallowing or breathing, drooling, muffled voice, unable to open mouth fully — these may indicate a peritonsillar abscess (emergency). Also see a doctor if bacterial (strep) tonsillitis is suspected — needs antibiotics.', urgency:'medium' },

  { name:'Laryngitis', aliases:['laryngitis','voice loss','lost voice','hoarse voice','inflamed larynx','voice box infection'], emoji:'🗣️', type:'common', description:'Inflammation of the larynx (voice box) causing a hoarse, raspy, or lost voice. Usually temporary and resolves within a week. Most cases are caused by a viral infection.', symptoms:['Hoarse, raspy, or weak voice','Partial or complete loss of voice','Sore or dry throat','Dry cough','Tickling sensation in throat','Mild fever'], causes:['Viral infection (most common — cold, flu)','Vocal overuse (shouting, singing)','Irritants — smoke, alcohol, dry air','Bacterial infection (less common)','Acid reflux (GERD)'], homecare:['Rest your voice as much as possible — avoid whispering (strains the voice more than talking quietly)','Drink plenty of warm fluids — honey and ginger tea','Breathe steam to soothe irritation','Use a humidifier','Avoid smoke, alcohol, and caffeine','Do not clear throat excessively — it irritates the vocal cords'], whenToSeeDoctor:'Hoarseness lasting more than 2 weeks, difficulty breathing or swallowing, blood in phlegm, persistent lump feeling in throat, or loss of voice with no obvious cause.', urgency:'low' },

  { name:'Bronchitis', aliases:['bronchitis','chest infection','bronchial infection','productive cough','phlegm cough','bronchitis cough'], emoji:'💨', type:'common', description:'Inflammation of the bronchial tubes (airways carrying air to the lungs) usually causing a persistent cough with phlegm. Acute bronchitis follows a cold or flu. Chronic bronchitis is caused by smoking.', symptoms:['Persistent cough producing mucus (clear, yellow, or green)','Chest discomfort or tightness','Shortness of breath','Mild fever and chills','Fatigue','Wheezing'], causes:['Viral infection following a cold or flu (acute bronchitis — most common)','Cigarette smoking (chronic bronchitis)','Air pollution and dust exposure','Bacterial infection (less common)'], homecare:['Rest and drink plenty of fluids to thin mucus','Honey in warm water or tea for cough','Steam inhalation for congestion','Humidifier in the room','OTC cough expectorant to help clear mucus','Avoid smoke and irritants'], whenToSeeDoctor:'Cough lasting more than 3 weeks, blood in phlegm, shortness of breath at rest, fever above 102°F, or symptoms in an elderly or immunocompromised person.', urgency:'medium' },

  { name:'Hemorrhoids', aliases:['hemorrhoids','haemorrhoids','piles','anal piles','rectal bleeding piles','itchy anus'], emoji:'🚽', type:'common', description:'Swollen veins in the lower rectum or anus. Extremely common — affect about 75% of people at some point. Most cases are not serious and resolve with home treatment.', symptoms:['Painless bleeding during bowel movements (bright red blood on toilet paper or in bowl)','Itching or irritation in anal region','Pain or discomfort','Swelling around anus','Leakage of feces','Feeling of incomplete bowel movement'], causes:['Straining during bowel movements','Chronic constipation or diarrhea','Pregnancy','Low-fiber diet','Sitting for prolonged periods especially on toilet','Obesity'], homecare:['Increase fiber intake to soften stools — fruits, vegetables, whole grains, legumes','Drink 8-10 glasses of water daily','Do not strain during bowel movements','Sitz bath — soak anal area in warm water for 15-20 minutes several times a day','OTC hemorrhoid creams or suppositories for relief','Avoid sitting for long periods on the toilet'], whenToSeeDoctor:'Significant rectal bleeding (always needs evaluation to rule out other causes), painful anal lump, hemorrhoids not improving with home care after a week, or if the hemorrhoid prolapses (comes outside the anus).', urgency:'medium' },

  { name:'Appendicitis', aliases:['appendicitis','appendix pain','right side stomach pain','appendix infection','appendix inflammation'], emoji:'🤢', type:'common', description:'Inflammation of the appendix — a finger-shaped pouch attached to the large intestine. A medical emergency requiring prompt surgery. Very common — affects 1 in 14 people in their lifetime.', symptoms:['Sudden pain beginning around the navel that shifts to lower right abdomen','Pain worsens over 12-24 hours and becomes severe','Loss of appetite','Nausea and vomiting','Low-grade fever that worsens','Abdominal bloating','Pain worsens with movement, coughing, or deep breathing'], causes:['Blockage inside the appendix (by hardened stool, foreign body, or infection)','Bacterial infection following blockage'], homecare:['No home care — appendicitis is a medical emergency','Do NOT apply heat to the abdomen','Do NOT take strong pain medication or anti-diarrheal drugs before diagnosis','Seek emergency care immediately'], whenToSeeDoctor:'Any suspected appendicitis is a medical emergency. Go to the emergency room immediately. A ruptured appendix is life-threatening. Do not wait — see a doctor urgently.', urgency:'high' },

  { name:'Hernia', aliases:['hernia','inguinal hernia','abdominal hernia','groin hernia','belly button hernia','umbilical hernia'], emoji:'🏥', type:'common', description:'A hernia occurs when an internal part of the body (usually bowel or fatty tissue) pushes through a weakness in the muscle or tissue wall surrounding it. Can occur in the groin, abdomen, navel, or near a surgical scar.', symptoms:['Visible bulge under the skin — especially when coughing, bending, or lifting','Aching or discomfort at the bulge site','Heaviness or dragging sensation in the groin','Pain especially when bending over, coughing, or lifting','Weakness, pressure, or a feeling of heaviness in the abdomen'], causes:['Muscle weakness combined with straining or pressure','Heavy lifting','Persistent cough or constipation','Pregnancy','Obesity','Previous surgery site (incisional hernia)'], homecare:['Avoid heavy lifting and straining','Manage constipation with high-fiber diet','Lose weight if overweight to reduce abdominal pressure','Wear a supportive truss for inguinal hernia temporarily','Avoid activities that worsen symptoms'], whenToSeeDoctor:'All hernias should be evaluated by a doctor. A hernia that becomes hard, tender, and cannot be pushed back in is a strangulated hernia — a medical emergency requiring immediate surgery.', urgency:'medium' },

  { name:'Gallstones', aliases:['gallstones','gallbladder stones','cholecystitis','gallbladder pain','biliary colic','right side pain after eating'], emoji:'🪨', type:'common', description:'Hardened deposits in the gallbladder, a small organ under the liver that stores bile. Very common — affect up to 15% of adults. Many people have them without symptoms.', symptoms:['Sudden intense pain in upper right abdomen or center of abdomen','Pain radiating to right shoulder or back','Nausea and vomiting','Pain after eating fatty meals','Yellowing of skin or eyes (if blocking bile duct — jaundice)','Fever and chills (if infected — cholecystitis)'], causes:['Excess cholesterol in bile forming crystals','Excess bilirubin in bile','Gallbladder not emptying properly','Obesity and rapid weight loss','Pregnancy','High fat diet','Family history'], homecare:['Avoid fatty, greasy, and fried foods','Small, low-fat meals are better tolerated','Stay well hydrated','Lose weight gradually (not rapidly — increases stone formation)','Pain management with OTC pain relievers for mild attacks'], whenToSeeDoctor:'First episode of gallstone-type pain needs medical evaluation. Fever with abdominal pain, jaundice, or severe persistent pain are emergencies — may indicate infection or blockage.', urgency:'high' },

  { name:'Plantar Fasciitis', aliases:['plantar fasciitis','heel spur','bottom foot pain','plantar fascia','morning heel pain'], emoji:'🦶', type:'common', description:'Inflammation of the plantar fascia — the thick band of tissue running across the bottom of the foot connecting the heel bone to the toes. The most common cause of heel pain.', symptoms:['Stabbing pain in the bottom of the foot near the heel','Pain worst with first steps in the morning','Pain after long periods of standing or after rising from sitting','Pain typically decreases after a few minutes of walking','Tenderness along the bottom of the foot'], causes:['Overuse and repetitive strain','Running or standing on hard surfaces for long periods','Flat feet or high arches (abnormal foot mechanics)','Tight calf muscles','Obesity','Improper footwear'], homecare:['Stretch the plantar fascia before getting out of bed — flex foot up and down 10 times','Calf stretches against a wall','Roll foot over a frozen water bottle or tennis ball','Wear supportive shoes with arch support — avoid bare feet','Ice the heel 15-20 minutes after activity','OTC orthotic insoles for arch support'], whenToSeeDoctor:'Significant heel pain not improving after 2-3 months of home treatment. Physiotherapy, steroid injections, or custom orthotics are very effective.', urgency:'low' },

  { name:'Worm Infection', aliases:['worm infection','intestinal worms','roundworm','pinworm','tapeworm','worms in stomach','helminth infection'], emoji:'🦠', type:'common', description:'Parasitic worms infecting the intestines. Very common globally, especially in children. Most intestinal worm infections are treatable with a single dose of medication.', symptoms:['Abdominal pain and cramping','Nausea and vomiting','Diarrhea or constipation','Itching around the anus (especially pinworms)','Visible worms in stool or around anus','Weight loss despite adequate eating','Fatigue and weakness'], causes:['Swallowing worm eggs through contaminated food or water','Poor hand hygiene after toilet use','Walking barefoot on contaminated soil (hookworm)','Eating undercooked meat (tapeworm)'], homecare:['Take prescribed antiparasitic medication (mebendazole, albendazole) — often single dose','All family members should be treated simultaneously for pinworms','Wash hands thoroughly before eating and after toilet use','Keep fingernails short and clean','Wash bedding, underwear, and nightclothes in hot water'], whenToSeeDoctor:'Worm infection always requires medication — see a doctor for proper diagnosis and treatment. If worms are visible in stool, take a photo and show the doctor.', urgency:'medium' },

  { name:'Cyst', aliases:['cyst','sebaceous cyst','skin cyst','epidermoid cyst','lump under skin','pilar cyst'], emoji:'🔴', type:'common', description:'A closed pocket of tissue filled with fluid, semi-solid material, or air. Can develop anywhere in the body or under the skin. Most are benign and harmless.', symptoms:['Smooth, round lump under the skin','Usually moves slightly when pressed','May have a tiny opening (punctum) at the center','Usually painless unless infected','If infected: red, warm, tender, and may drain pus'], causes:['Blocked oil or sweat gland ducts','Infected hair follicle','Clogged sebaceous glands','Skin trauma','Certain skin conditions'], homecare:['Do not squeeze or pop — increases infection risk and worsens it','Warm compress to the area if inflamed to help it drain naturally','Keep area clean','If infected, see a doctor — antibiotics or drainage may be needed'], whenToSeeDoctor:'Cyst that is growing rapidly, infected, painful, draining pus, in a cosmetically important area, or if you are unsure it is a cyst. A doctor can drain or remove it.', urgency:'low' },

  { name:'Lipoma', aliases:['lipoma','fatty lump','fat lump under skin','soft lump','benign fatty tumor'], emoji:'🔵', type:'common', description:'A slow-growing, fatty lump between the skin and underlying muscle layer. Soft, doughy to the touch, and generally harmless. Very common in adults aged 40-60.', symptoms:['Soft, doughy lump under the skin','Moves easily when pressed with a finger','Usually 2-3 cm in size but can be larger','Located on neck, shoulders, back, abdomen, arms, or thighs','Usually painless (may be painful if over nerves)'], causes:['Exact cause unknown','Genetic predisposition','May develop after minor injury','More common with middle age'], homecare:['No treatment needed for most lipomas','Monitor for changes in size, shape, or texture'], whenToSeeDoctor:'Any new lump should be evaluated. See a doctor if the lipoma becomes painful, grows rapidly, feels hard or firm, is fixed and does not move, or if you want it removed for cosmetic or comfort reasons.', urgency:'low' },

  { name:'Leg Cramps', aliases:['leg cramps','night cramps','calf cramps','nocturnal leg cramps','charley horse leg'], emoji:'🦵', type:'common', description:'Sudden involuntary muscle contractions most commonly in the calf muscle, often occurring at night (nocturnal leg cramps). Very common, especially in older adults and during pregnancy.', symptoms:['Sudden intense cramping pain in the calf','Tight, hard muscle visible under skin','Lasts from seconds to several minutes','Residual aching after the cramp','Usually occurs at night or during rest'], causes:['Dehydration','Electrolyte imbalances (low potassium, magnesium, calcium)','Prolonged sitting or poor circulation','Certain medications (diuretics, statins)','Pregnancy','Overexertion'], homecare:['Immediately flex the foot upward (toes toward shin) and hold to stop the cramp','Stand on the leg and walk around if possible','Massage the muscle firmly','Apply heat after cramp passes','Ensure adequate hydration and electrolytes throughout the day','Gentle calf stretches before bed'], whenToSeeDoctor:'Frequent severe leg cramps disrupting sleep, leg cramps with significant swelling or discoloration, or cramps with leg pain at rest (may indicate peripheral artery disease).', urgency:'low' },

  { name:'Frequent Urination', aliases:['frequent urination','urinary frequency','urinating often','overactive bladder','peeing often','pollakiuria'], emoji:'🚽', type:'common', description:'Needing to urinate more often than normal. Average is 6-7 times in 24 hours. More than 8 times a day or waking more than once per night to urinate may warrant investigation.', symptoms:['Urinating more than 8 times per day','Waking more than once per night to urinate','Strong or sudden urge to urinate','May or may not have pain or burning'], causes:['Urinary tract infection (most common — with burning)','Overactive bladder','Diabetes (with excessive thirst)','Pregnancy','Diuretic medications','Large fluid intake','Anxiety','Enlarged prostate in men','Bladder irritants — caffeine, alcohol'], homecare:['Reduce caffeine and alcohol which irritate the bladder','Bladder training — gradually extend time between bathroom visits','Pelvic floor exercises (Kegel exercises)','Limit fluid intake in the evening if night urination is the problem','Do not reduce total fluid intake significantly during the day'], whenToSeeDoctor:'Frequent urination with pain or burning (UTI), blood in urine, excessive thirst alongside frequent urination (possible diabetes), significant impact on quality of life, or urinary incontinence.', urgency:'medium' },

  { name:'Hair Fall', aliases:['hair fall','hair loss','alopecia','balding','thinning hair','excessive hair fall'], emoji:'💇', type:'common', description:'Losing more than 100 hairs per day is considered abnormal hair fall. Many types exist from temporary to permanent. Losing hair can be distressing but many causes are treatable.', symptoms:['Gradual thinning on top of head','Circular or patchy bald spots','Sudden loosening of hair','Full body hair loss (from medical treatments)','Patches of scaling (if scalp infection)','Receding hairline'], causes:['Androgenetic alopecia (genetic — most common)','Telogen effluvium (stress, illness, hormonal change causing temporary shedding)','Iron deficiency anemia','Thyroid disorders','Nutritional deficiencies (protein, biotin, zinc)','PCOS in women','Scalp infections'], homecare:['Identify and treat the underlying cause','Eat protein-rich diet — eggs, lentils, meat, dairy','Iron, zinc, and biotin supplementation if deficient','Avoid tight hairstyles and excessive heat styling','Gentle hair care — wide-tooth comb on wet hair','Minoxidil applied to scalp (OTC) may help in androgenetic alopecia'], whenToSeeDoctor:'Sudden dramatic hair loss, patchy hair loss (alopecia areata), hair loss with scalp pain or itching, or hair loss not improving after addressing nutritional causes. Dermatologist evaluation recommended.', urgency:'low' },

  { name:'Kidney Infection', aliases:['kidney infection','pyelonephritis','upper urinary tract infection','kidney uti','back pain with fever'], emoji:'🔥', type:'common', description:'A bacterial infection of one or both kidneys, usually starting as a bladder infection that ascends. More serious than a bladder infection and requires prompt antibiotic treatment.', symptoms:['High fever and chills','Back, side, or groin pain (often severe)','Nausea and vomiting','Frequent and painful urination','Burning sensation when urinating','Cloudy or foul-smelling urine','Blood in urine'], causes:['Bacteria (usually E. coli) traveling from bladder to kidneys','Untreated UTI that spreads upward','Kidney stones blocking the urinary tract','Urinary catheters','Weakened immune system'], homecare:['This requires prescription antibiotics — see a doctor immediately','Drink plenty of fluids to help flush out bacteria','OTC pain relievers for discomfort while awaiting medical care','Rest','Complete the full antibiotic course even if feeling better'], whenToSeeDoctor:'Kidney infection always requires medical treatment with antibiotics. Go to the doctor or emergency room promptly — untreated kidney infection can lead to sepsis (life-threatening blood infection).', urgency:'high' },

  { name:'Yeast Infection', aliases:['yeast infection','vaginal yeast infection','candidal vaginitis','thrush vaginal','vaginal candidiasis'], emoji:'🌸', type:'common', description:'A fungal infection caused by an overgrowth of Candida yeast in the vagina. Very common — 75% of women experience at least one in their lifetime. Treatable and not sexually transmitted.', symptoms:['Itching and irritation in the vagina and vulva','Burning sensation, especially during intercourse or urination','Redness and swelling of the vulva','Thick, white, odorless vaginal discharge (cottage cheese appearance)','Vaginal pain and soreness'], causes:['Candida yeast overgrowth (normally present in small amounts)','Antibiotic use (disrupts normal vaginal bacteria)','Pregnancy hormones','Uncontrolled diabetes','Weakened immune system','High estrogen levels'], homecare:['OTC antifungal cream, ointment, or suppository (clotrimazole, miconazole) for 1-7 days','Wear loose, breathable cotton underwear','Avoid scented feminine hygiene products','Wipe front to back after toilet use','Do not douche','Eat probiotic foods (yogurt with live cultures) to restore good bacteria'], whenToSeeDoctor:'First yeast infection (confirm diagnosis), recurring infections (more than 4 per year), pregnancy, symptoms not improving after OTC treatment, or if symptoms could be an STI.', urgency:'low' },

  { name:'Menstrual Cramps', aliases:['menstrual cramps','period pain','dysmenorrhea','period cramps','painful periods'], emoji:'🌸', type:'common', description:'Painful cramping of the uterus around the time of menstruation. Extremely common — affecting up to 80% of menstruating people. Usually manageable with home care.', symptoms:['Throbbing or cramping pain in the lower abdomen','Pain starting 1-3 days before period and lasting 2-3 days','Pain radiating to lower back and thighs','Nausea','Headache','Dizziness','Loose stools'], causes:['Prostaglandins causing uterine contractions (primary dysmenorrhea — most common)','Endometriosis','Fibroids','Adenomyosis','Pelvic inflammatory disease'], homecare:['Apply heat to lower abdomen (heating pad or hot water bottle) — as effective as medication','Take ibuprofen starting 1-2 days before expected period for better effect','Light exercise — walking or yoga reduces prostaglandins','Warm bath for overall muscle relaxation','Avoid caffeine, salt, and alcohol which worsen cramping'], whenToSeeDoctor:'Cramps severe enough to prevent normal daily activities, getting progressively worse over time, cramps with very heavy bleeding or irregular periods, or not responding to ibuprofen — could indicate endometriosis or fibroids.', urgency:'medium' },

  { name:'Heavy Periods', aliases:['heavy periods','heavy menstrual bleeding','menorrhagia','heavy flow','flooding periods'], emoji:'🌸', type:'common', description:'Menstrual periods with abnormally heavy or prolonged bleeding. Affects about 1 in 5 women. Can lead to anemia and significantly affect quality of life.', symptoms:['Soaking through a pad or tampon every hour for several consecutive hours','Needing to use double protection (pad and tampon)','Bleeding lasting more than 7 days','Passing blood clots larger than a 50-paise coin','Symptoms of anemia — fatigue, shortness of breath, pallor'], causes:['Hormonal imbalance','Uterine fibroids or polyps','Adenomyosis','PCOS','IUD (copper coil) use','Blood clotting disorders','Thyroid disorders'], homecare:['Iron-rich foods and iron supplements to prevent anemia','Ibuprofen reduces bleeding and pain (take from day 1 of period)','Stay well hydrated','Keep track of your cycle and flow for the doctor'], whenToSeeDoctor:'Heavy periods always warrant medical evaluation to identify the cause. Bleeding soaking a pad every hour or less for more than 2 hours is an emergency. Anaemia symptoms also require prompt assessment.', urgency:'medium' },

  { name:'Breast Pain', aliases:['breast pain','mastalgia','breast tenderness','sore breasts','breast ache'], emoji:'🌸', type:'common', description:'Pain in one or both breasts. Very common — about 70% of women experience breast pain at some point. Most cases are benign and related to hormonal changes.', symptoms:['Aching, heaviness, or tenderness in breasts','Pain may affect one or both breasts','Cyclic breast pain — worse before periods and improves after','Non-cyclic pain — constant or intermittent, not related to cycle','Breast swelling or lumpiness before period'], causes:['Hormonal fluctuations (most common — cyclic)','Poorly fitting bra','Pregnancy','Breastfeeding — engorgement or mastitis','Fibrocystic breast changes','Certain medications (hormones, antidepressants)','Injury'], homecare:['Wear a well-fitting, supportive bra — consider a sports bra at night','Reduce caffeine intake — can worsen cyclic breast pain','Evening primrose oil may reduce cyclic breast pain','OTC pain relievers (ibuprofen)','Warm or cool compress for comfort'], whenToSeeDoctor:'New breast lump, lump that does not go away after your period, skin changes (dimpling, redness, puckering), nipple discharge, or breast pain on one side only in a non-cyclic pattern.', urgency:'medium' },

  { name:'Prostate Issues', aliases:['prostate','prostate problems','BPH','enlarged prostate','benign prostatic hyperplasia','prostate pain'], emoji:'🩺', type:'common', description:'The prostate gland can cause urinary problems when enlarged (BPH — benign prostatic hyperplasia), a very common condition in men over 50. Not the same as prostate cancer.', symptoms:['Frequent urination especially at night','Weak or slow urine stream','Difficulty starting urination','Dribbling at the end of urination','Feeling of incomplete bladder emptying','Urgency to urinate'], causes:['Aging — the prostate normally grows with age','Hormonal changes in older men','Family history'], homecare:['Reduce fluid intake in the evening','Limit caffeine and alcohol','Do not delay when you feel the urge to urinate','Double voiding — after urinating, wait a moment and try again','Pelvic floor exercises','Maintain a healthy weight and regular exercise'], whenToSeeDoctor:'Urinary symptoms in men over 40 should be evaluated. Inability to urinate (urinary retention) is a medical emergency. Annual PSA test and prostate exam recommended from age 50 (or 40 with family history).', urgency:'medium' },

  { name:'Low Libido', aliases:['low libido','low sex drive','loss of libido','reduced sexual desire','low sexual interest'], emoji:'💊', type:'common', description:'Decreased interest in sexual activity. Common in both men and women and can result from physical, hormonal, psychological, or relationship factors. Usually treatable.', symptoms:['Little or no interest in sexual activity','No sexual thoughts or fantasies','Concerned about lack of desire','May affect relationship and self-esteem'], causes:['Hormonal changes (low testosterone in men, menopause in women)','Stress, anxiety, or depression','Relationship problems','Fatigue and poor sleep','Certain medications (antidepressants, contraceptive pill)','Chronic illness or pain','Body image issues'], homecare:['Address stress and improve sleep quality','Regular exercise improves hormones and energy levels','Open communication with partner','Reduce alcohol','Review medications with doctor — alternatives may be available','If depression or anxiety — seek treatment'], whenToSeeDoctor:'Persistent low libido causing distress, suspected hormonal cause (check testosterone or estrogen levels), or if related to depression or medication side effects. A GP, endocrinologist, or sex therapist can help.', urgency:'low' },

  { name:'Premature Greying', aliases:['premature greying','premature gray hair','early white hair','grey hair early','premature gray','white hair young'], emoji:'💇', type:'common', description:'Hair turning grey or white before the age of 35. Caused by reduction in melanin production in hair follicles. Often genetic but can have medical causes.', symptoms:['Grey or white hair before age 35','May start with a few strands and progress','No other physical symptoms in most cases'], causes:['Genetics — the most significant factor','Vitamin B12 deficiency','Thyroid disorders (hypo or hyperthyroidism)','Vitiligo (pigmentation loss)','Chronic stress may contribute','Smoking — doubles the risk'], homecare:['Ensure adequate vitamin B12 — eggs, meat, dairy, or supplements for vegetarians','Check thyroid function and treat if abnormal','Quit smoking','Eat a balanced diet rich in antioxidants','Hair dyes and henna are cosmetic options'], whenToSeeDoctor:'Premature greying in someone under 20, especially if sudden or in patches. Blood test to check vitamin B12 and thyroid levels.', urgency:'low' },

  /* ── COMMON: WOMEN SPECIFIC ── */
  { name:'PMS', aliases:['pms','premenstrual syndrome','premenstrual tension','pmt','symptoms before period','mood changes before period'], emoji:'🌸', type:'common', description:'A combination of physical and emotional symptoms that occur in the 1-2 weeks before menstruation. Affects up to 75% of menstruating women to varying degrees.', symptoms:['Mood swings, irritability, or anxiety','Depression or feeling of sadness','Crying spells','Fatigue and sleep problems','Food cravings (especially sweets)','Breast tenderness','Headache','Bloating and water retention','Acne flare'], causes:['Hormonal fluctuations during the luteal phase of the menstrual cycle','Serotonin levels drop as progesterone rises','Genetics','Stress worsens PMS','Nutritional deficiencies (magnesium, vitamin B6)'], homecare:['Regular aerobic exercise throughout the month — significantly reduces PMS symptoms','Eat small, frequent meals and reduce salt, caffeine, and sugar in the second half of the cycle','Calcium (1200mg) and magnesium supplements shown to reduce symptoms','Get adequate sleep','Stress management — yoga, mindfulness','Evening primrose oil or vitamin B6 may help some women'], whenToSeeDoctor:'Symptoms severely affecting daily life, relationships, or work — could be PMDD (Premenstrual Dysphoric Disorder), a more severe form that responds well to treatment.', urgency:'low' },

  { name:'Vaginal Discharge', aliases:['vaginal discharge','white discharge','leucorrhoea','vaginal fluid','abnormal discharge'], emoji:'🌸', type:'common', description:'Some vaginal discharge is completely normal — it keeps the vagina clean and moist. Abnormal discharge in terms of color, smell, consistency, or amount may indicate infection.', symptoms:['Normal: clear to white, mild or no odor, varies with cycle','Abnormal: yellow, green, gray, or thick white (cottage cheese)','Abnormal: strong or foul odor','Itching, burning, or irritation in vaginal area','Pain during intercourse or urination'], causes:['Normal hormonal discharge (clear, odorless)','Yeast infection (thick white, cottage cheese)','Bacterial vaginosis (thin gray, fishy odor)','Trichomoniasis (yellow-green, frothy — STI)','Cervical or uterine infections'], homecare:['Maintain good genital hygiene — wash with water only, no douching','Wear breathable cotton underwear','Change underwear daily','Avoid scented products in the genital area'], whenToSeeDoctor:'Yellow, green, gray, or strongly odorous discharge — these indicate infection requiring treatment. Also see a doctor for any new or different discharge pattern, or discharge with pain, itching, or bleeding.', urgency:'medium' },

  /* ── COMMON: MEN SPECIFIC ── */
  { name:'Erectile Dysfunction', aliases:['erectile dysfunction','impotence','ed','erection problem','erectile issues','cannot maintain erection'], emoji:'🩺', type:'common', description:'The inability to get or maintain an erection firm enough for sexual activity. Very common — affects up to 40% of men over 40. Often has physical or psychological causes that are treatable.', symptoms:['Difficulty getting an erection','Difficulty maintaining an erection','Reduced sexual desire'], causes:['Cardiovascular disease (most common physical cause — reduced blood flow)','Diabetes — damages blood vessels and nerves','High blood pressure or cholesterol','Obesity','Low testosterone','Psychological — anxiety, depression, stress, relationship problems','Medications (antidepressants, antihypertensives)','Smoking and alcohol'], homecare:['Regular exercise (especially cardiovascular) significantly improves ED','Maintain a healthy weight','Quit smoking — major cause of vascular ED','Reduce alcohol consumption','Manage stress, anxiety, and depression','Open communication with partner'], whenToSeeDoctor:'Persistent ED lasting more than a few weeks, especially if newly developed. ED can be an early warning sign of cardiovascular disease. A doctor can assess underlying causes and recommend effective treatments.', urgency:'medium' },

  /* ── COMMON: HEAD & NEUROLOGICAL ── */
  { name:'Brain Fog', aliases:['brain fog','mental fog','cognitive fog','difficulty concentrating','fuzzy thinking','cloudy mind'], emoji:'🧠', type:'common', description:'A term for a collection of symptoms including poor concentration, memory problems, and mental fatigue. Not a medical condition itself but a symptom of many underlying issues.', symptoms:['Difficulty concentrating or focusing','Memory lapses','Feeling mentally slow or sluggish','Difficulty finding words','Confusion or mental cloudiness','Fatigue alongside mental symptoms','Difficulty making decisions'], causes:['Sleep deprivation','Stress and anxiety','Nutritional deficiencies (B12, iron, vitamin D)','Hypothyroidism','Chronic fatigue syndrome','Post-viral illness (including long COVID)','Medications','Hormonal changes (menopause)'], homecare:['Prioritize 7-9 hours of quality sleep','Stay hydrated throughout the day','Regular physical exercise — improves blood flow to brain','Eat a balanced diet — reduce processed foods and sugar','Limit alcohol and caffeine','Address stress — mindfulness and meditation help','Check for vitamin deficiencies'], whenToSeeDoctor:'Brain fog lasting more than 2 weeks, significantly affecting work or daily function, or accompanied by other symptoms. Blood tests can identify treatable causes (thyroid, vitamins, anemia).', urgency:'low' },

  { name:'Cluster Headache', aliases:['cluster headache','cluster headaches','eye pain headache','severe one sided headache','alarm clock headache'], emoji:'🧠', type:'common', description:'Extremely painful headaches occurring in groups (clusters). Often called "suicide headaches" due to their severity. Among the most painful conditions known, but treatable.', symptoms:['Excruciating one-sided pain around or behind one eye','Pain rated 10/10 by sufferers','Attacks lasting 15 min to 3 hours','Eye redness and tearing on affected side','Drooping eyelid','Runny or blocked nose on affected side','Restlessness — unable to lie still (unlike migraine)','Attacks occur at same time daily during cluster period'], causes:['Hypothalamus abnormality (the body\'s biological clock)','Exact cause unknown','Alcohol and strong smells can trigger during cluster period','Genetics play a role'], homecare:['High-flow oxygen through a mask — very effective at aborting attacks (requires prescription)','Sumatriptan injection at onset of attack (prescription)','Avoid alcohol completely during cluster period','Maintain regular sleep schedule','Ergotamine preparations (prescription)'], whenToSeeDoctor:'Always see a neurologist for cluster headaches — they are a distinct condition requiring specific treatment different from migraine. Many effective preventive and abortive treatments are available.', urgency:'high' },

  { name:'Facial Numbness', aliases:['facial numbness','face numbness','numb face','tingling face','facial tingling'], emoji:'🧠', type:'common', description:'Loss of sensation or tingling in parts or all of the face. The cause determines whether it is benign or serious. Any sudden facial numbness should be evaluated promptly.', symptoms:['Loss of feeling in parts of the face','Tingling or pins and needles sensation','May affect one or both sides','May involve lips, cheeks, forehead, or chin','May accompany muscle weakness'], causes:['Dental procedures (temporary, local)','Bell\'s palsy (viral nerve inflammation)','Migraine with aura','Multiple sclerosis','Anxiety and hyperventilation','TIA or stroke (emergency)','Nerve compression'], homecare:['If due to hyperventilation — breathe slowly into a paper bag or use controlled breathing','Dental numbness is expected and temporary after procedures','Bell\'s palsy — corticosteroids if prescribed, keep eye moist if unable to close it'], whenToSeeDoctor:'Sudden unexplained facial numbness requires immediate evaluation to rule out TIA or stroke. Also see a doctor if facial numbness is persistent, progressive, or associated with other neurological symptoms.', urgency:'high' },

  { name:'Photophobia', aliases:['photophobia','light sensitivity','sensitive to light','light hurts eyes','eyes sensitive to light'], emoji:'👁️', type:'common', description:'Abnormal sensitivity to light, causing discomfort or pain when the eyes are exposed to light. A symptom rather than a disease. Very common with migraines.', symptoms:['Pain or discomfort in bright light','Squinting or closing eyes in normal light','Eye pain that worsens in light','Headache associated with light sensitivity','Preference for dark environments'], causes:['Migraine (most common)','Meningitis (with fever and stiff neck — emergency)','Concussion or head injury','Corneal abrasion','Iritis (iris inflammation)','Blepharitis','Dry eyes','Albinism'], homecare:['Wear sunglasses — especially polarized or wrap-around style','Dim indoor lighting during episodes','Rest in a dark room during migraine','Eye drops for dry eyes if that is the cause','Treat the underlying migraine or eye condition'], whenToSeeDoctor:'Photophobia with fever, stiff neck, severe headache — possible meningitis, seek emergency care immediately. Also see a doctor for persistent photophobia to identify and treat the cause.', urgency:'medium' },

  { name:'Numbness in Hands', aliases:['numbness in hands','hand numbness','tingling hands','pins and needles hands','numb fingers'], emoji:'🤲', type:'common', description:'Loss of sensation or tingling in the hands and fingers. Very common and usually caused by pressure on nerves or carpal tunnel syndrome. Occasionally indicates systemic disease.', symptoms:['Numbness or tingling in fingers or hand','Pins and needles sensation','Weakness in grip','Worsens at night or with certain positions','May affect thumb and first three fingers (carpal tunnel) or entire hand'], causes:['Carpal tunnel syndrome (most common)','Sleeping on the arm or prolonged pressure on nerve','Cervical spine nerve compression','Diabetes (peripheral neuropathy)','Vitamin B12 deficiency','Poor circulation','Repetitive hand use'], homecare:['Shake and move the hand to restore circulation if positional','Wrist splint at night for carpal tunnel symptoms','Take regular breaks from repetitive hand activities','Check B12 levels if dietary risk (vegetarians, vegans, older adults)','Cervical exercises if neck is the source'], whenToSeeDoctor:'Persistent or worsening hand numbness, both hands affected, weakness or clumsiness, associated with neck pain, or if you have diabetes — peripheral neuropathy needs treatment.', urgency:'medium' },

  /* ── CHRONIC ── */
  { name:'Diabetes', aliases:['diabetes','diabetes mellitus','blood sugar','high sugar','type 1 diabetes','type 2 diabetes','diabetic','insulin resistance','sugar disease'], emoji:'🩸', type:'chronic', description:'A chronic condition where the body cannot properly regulate blood sugar (glucose). Type 1 is autoimmune; Type 2 is lifestyle-related. Both require ongoing management.', symptoms:['Frequent urination','Excessive thirst','Unexplained weight loss','Fatigue and weakness','Blurred vision','Slow-healing wounds','Tingling in hands and feet'], causes:['Insulin resistance (Type 2)','Autoimmune destruction of beta cells (Type 1)','Obesity and sedentary lifestyle','Genetic factors','Poor diet high in refined carbohydrates'], homecare:['Monitor blood glucose regularly','Follow a low-glycemic diet (avoid white rice, sugar, maida)','Exercise 30 minutes daily (walking, yoga)','Take medications as prescribed','Maintain a healthy weight'], whenToSeeDoctor:'If you notice any symptoms, or if blood sugar is consistently above 180 mg/dL after meals or below 70 mg/dL. Routine checkups every 3-6 months.', urgency:'high' },

  { name:'Hypertension', aliases:['high blood pressure','hypertension','blood pressure','bp','hbp','high bp'], emoji:'❤️', type:'chronic', description:'Blood pressure above 130/80 mmHg that puts strain on the heart and blood vessels. Called the "silent killer" because it often has no symptoms until severe.', symptoms:['Usually no symptoms','Headaches in severe cases','Dizziness','Shortness of breath','Nosebleeds (in crisis)','Blurred vision'], causes:['High salt diet','Obesity and lack of exercise','Smoking and alcohol','Stress','Family history','Kidney disease'], homecare:['Reduce salt intake (less than 5g per day)','Exercise regularly — 30 min walks daily','Quit smoking and limit alcohol','Manage stress with yoga or meditation','Monitor BP at home','Take medications as prescribed'], whenToSeeDoctor:'BP consistently above 140/90, severe headache with vision changes, chest pain, or sudden confusion — these are emergency signs.', urgency:'high' },

  { name:'Asthma', aliases:['asthma','breathing problem','wheezing','breathless','shortness of breath','inhaler','difficulty breathing','respiratory'], emoji:'💨', type:'chronic', description:'A chronic lung condition where airways become inflamed and narrowed, making breathing difficult. Episodes (attacks) can be triggered by various factors.', symptoms:['Wheezing (whistling sound when breathing)','Shortness of breath','Chest tightness','Coughing especially at night','Trouble sleeping due to breathing'], causes:['Allergens — dust, pollen, pet dander','Air pollution and smoke','Exercise-induced asthma','Cold air','Respiratory infections','Stress'], homecare:['Use prescribed inhalers as directed','Identify and avoid your triggers','Keep bedroom dust-free','Do not smoke and avoid secondhand smoke','Breathing exercises (pursed-lip breathing)'], whenToSeeDoctor:'Frequent attacks, inhaler not relieving symptoms, blue lips or fingernails, or struggling to speak during an attack — go to emergency.', urgency:'high' },

  { name:'Migraine', aliases:['migraine','severe headache','half head pain','throbbing headache','aura','one-sided headache','migraine attack'], emoji:'🧠', type:'chronic', description:'A neurological condition causing intense throbbing headaches, usually on one side. Often accompanied by nausea, vomiting, and sensitivity to light and sound.', symptoms:['Severe throbbing headache (often one side)','Nausea and vomiting','Sensitivity to light and sound','Visual disturbances (aura)','Dizziness','Fatigue before or after attack'], causes:['Hormonal changes','Stress and anxiety','Skipping meals or dehydration','Bright lights or loud sounds','Strong smells','Certain foods (cheese, wine, caffeine)','Lack of sleep'], homecare:['Rest in a dark quiet room','Apply cold or warm compress to head','Stay hydrated','OTC pain relievers (ibuprofen, aspirin) at onset','Keep a migraine diary to track triggers'], whenToSeeDoctor:'Migraines more than 4 times a month, sudden "thunderclap" headache, headache with fever and stiff neck, or OTC medicine stops working.', urgency:'medium' },

  { name:'Arthritis', aliases:['arthritis','joint pain','joint swelling','rheumatoid','osteoarthritis','knee pain','joint stiffness','painful joints'], emoji:'🦴', type:'chronic', description:'Inflammation of one or more joints causing pain and stiffness. Two main types: osteoarthritis (wear and tear) and rheumatoid arthritis (autoimmune).', symptoms:['Joint pain and tenderness','Stiffness especially in the morning','Swelling around joints','Reduced range of motion','Redness and warmth around joints'], causes:['Age-related wear and tear (osteoarthritis)','Autoimmune disease (rheumatoid arthritis)','Previous joint injury','Obesity','Family history','Gout or infections'], homecare:['Apply hot or cold compress to affected joints','Gentle exercises — swimming and walking are ideal','Maintain a healthy weight to reduce joint stress','OTC pain relievers and anti-inflammatories','Turmeric milk or ginger tea may help reduce inflammation'], whenToSeeDoctor:'Severe joint pain, sudden joint swelling, inability to use the joint, or fever with joint pain.', urgency:'medium' },

  { name:'Thyroid Disorder', aliases:['thyroid','hypothyroidism','hyperthyroidism','thyroid problem','low thyroid','high thyroid','thyroid disease'], emoji:'🦋', type:'chronic', description:'The thyroid gland controls metabolism. Hypothyroidism (underactive) slows the body down; hyperthyroidism (overactive) speeds it up. Both are very treatable.', symptoms:['Fatigue (hypothyroid) or nervousness (hyperthyroid)','Weight gain or unexplained weight loss','Cold intolerance or heat intolerance','Slow or fast heart rate','Hair thinning or loss','Swelling in neck','Constipation or diarrhea'], causes:['Autoimmune conditions (Hashimoto, Graves disease)','Iodine deficiency','Previous thyroid surgery or radiation','Family history','Certain medications'], homecare:['Take prescribed thyroid medication at same time every day','Eat iodine-rich foods — seafood, iodized salt, dairy','Avoid raw cruciferous vegetables in excess (hypothyroid)','Regular exercise','Get thyroid levels checked regularly'], whenToSeeDoctor:'Suspected thyroid disorder requires blood tests (TSH, T3, T4). See an endocrinologist for proper diagnosis and medication management.', urgency:'medium' },

  { name:'Anemia', aliases:['anemia','anaemia','low hemoglobin','low haemoglobin','iron deficiency','low blood','weakness','pale'], emoji:'🩸', type:'chronic', description:'A condition where you lack enough healthy red blood cells to carry adequate oxygen to your body. Iron deficiency anemia is the most common type worldwide.', symptoms:['Extreme fatigue and weakness','Pale skin and gums','Shortness of breath','Dizziness or lightheadedness','Cold hands and feet','Headache','Chest pain'], causes:['Iron deficiency (most common)','Vitamin B12 or folate deficiency','Chronic blood loss (heavy periods, ulcers)','Chronic diseases (kidney disease, cancer)','Inherited conditions (sickle cell, thalassemia)'], homecare:['Eat iron-rich foods — leafy greens, beans, meat, fortified cereals','Eat vitamin C with iron foods to improve absorption','Take iron supplements as prescribed','Avoid tea or coffee immediately after meals (blocks iron absorption)','Cook in iron vessels'], whenToSeeDoctor:'Severe fatigue, chest pain or rapid heartbeat, very pale appearance, or hemoglobin confirmed low on blood test. Diagnosis requires blood work.', urgency:'medium' },
    
  /* ── CHRONIC: CARDIOVASCULAR ── */

  { name:'Heart Disease', aliases:['heart disease','cardiac disease','heart problem','heart condition','cardiovascular disease','heart trouble'], emoji:'🫀', type:'chronic', description:'A broad term covering several conditions that affect the heart\'s structure and function. The leading cause of death globally. Includes coronary artery disease, heart failure, arrhythmias, and more. Most types are preventable with lifestyle changes.', symptoms:['Chest pain or pressure','Shortness of breath','Fatigue with minimal exertion','Swelling in legs, ankles, or feet','Irregular heartbeat','Dizziness or lightheadedness','Pain radiating to arm, neck, or jaw'], causes:['High blood pressure','High cholesterol','Diabetes','Smoking','Obesity and sedentary lifestyle','Family history','Age (risk increases after 45 in men, 55 in women)','Poor diet'], homecare:['Eat a heart-healthy diet — reduce saturated fats, salt, and sugar','Exercise 30 minutes most days (as advised by doctor)','Quit smoking completely','Limit alcohol','Maintain a healthy weight','Monitor and control blood pressure, cholesterol, and blood sugar','Take prescribed medications consistently'], whenToSeeDoctor:'Any chest pain, especially with arm, neck, or jaw pain, shortness of breath, or sweating — seek emergency care immediately. Regular checkups every 6-12 months for those diagnosed with heart disease.', urgency:'high' },

  { name:'Heart Failure', aliases:['heart failure','congestive heart failure','chf','weak heart','heart not pumping','cardiac failure'], emoji:'🫀', type:'chronic', description:'A chronic condition where the heart does not pump blood as well as it should. Does not mean the heart has stopped — it means the heart is not working efficiently enough to meet the body\'s needs.', symptoms:['Shortness of breath especially when lying down or with exertion','Fatigue and weakness','Swelling in legs, ankles, and feet','Rapid or irregular heartbeat','Persistent cough producing white or pinkish mucus','Reduced ability to exercise','Nausea and loss of appetite','Sudden weight gain from fluid retention'], causes:['Coronary artery disease and heart attack','High blood pressure','Diabetes','Obesity','Valvular heart disease','Cardiomyopathy (heart muscle disease)','Previous viral infection of the heart'], homecare:['Weigh yourself daily — sudden gain of 2kg or more in 2 days signals fluid buildup, call doctor','Restrict salt intake (less than 2g daily)','Restrict fluids as advised by doctor','Take all medications exactly as prescribed — do not skip','Elevate legs when resting','Avoid alcohol completely','Light activity as tolerated — cardiac rehabilitation is very helpful'], whenToSeeDoctor:'Sudden worsening of shortness of breath, chest pain, coughing up blood, fainting, or rapid unexpected weight gain. Regular 3-monthly cardiologist review is essential.', urgency:'high' },

  { name:'Coronary Artery Disease', aliases:['coronary artery disease','cad','blocked arteries','coronary heart disease','ischemic heart disease','narrowed arteries heart'], emoji:'🫀', type:'chronic', description:'The most common type of heart disease, caused by plaque buildup inside the coronary arteries that supply blood to the heart muscle. Leads to reduced blood flow which can cause angina or heart attack.', symptoms:['Chest pain or tightness (angina) triggered by exertion or stress','Shortness of breath','Heart attack if artery becomes completely blocked','Fatigue','Sweating with chest discomfort','Pain in the arm, neck, or jaw'], causes:['Atherosclerosis — plaque buildup from cholesterol, fats, and calcium','High blood pressure','High cholesterol','Diabetes','Smoking','Obesity','Sedentary lifestyle','Family history'], homecare:['Heart-healthy diet — Mediterranean diet is well-supported','Exercise as directed by cardiologist','Quit smoking — most important modifiable risk factor','Control blood pressure, cholesterol, and blood sugar through diet, exercise, and medications','Take prescribed medications (statins, aspirin, beta-blockers) without skipping'], whenToSeeDoctor:'Chest pain at rest, new or worsening chest pain, chest pain with sweating and nausea — this may be a heart attack. Call emergency services immediately. Regular cardiologist follow-up every 6 months.', urgency:'high' },

  { name:'Angina', aliases:['angina','chest tightness','angina pectoris','chest pressure','cardiac chest pain','stable angina','unstable angina'], emoji:'🫀', type:'chronic', description:'Chest pain or discomfort caused by reduced blood flow to the heart muscle, usually during physical activity or stress. It is a symptom of coronary artery disease, not a disease itself.', symptoms:['Pressure, squeezing, or tightness in the chest','Pain spreading to arm, neck, jaw, or back','Triggered by exertion, stress, cold, or heavy meals','Usually relieved by rest or nitroglycerin within a few minutes','Shortness of breath','Sweating and nausea'], causes:['Coronary artery disease reducing blood flow to the heart','Physical exertion increasing the heart\'s demand for oxygen','Emotional stress','Cold weather','Heavy meals (increases work for the heart)'], homecare:['Rest immediately when chest pain begins','Take prescribed nitroglycerin spray or tablet under tongue if given','Avoid sudden strenuous exertion','Eat smaller meals','Dress warmly in cold weather','Take all cardiac medications as prescribed','Cardiac rehabilitation exercise program'], whenToSeeDoctor:'New chest pain always needs urgent evaluation. Unstable angina (pain at rest or with increasing frequency and severity) is a medical emergency — go to hospital immediately as it can precede a heart attack.', urgency:'high' },

  { name:'Atrial Fibrillation', aliases:['atrial fibrillation','afib','af','irregular heartbeat','heart flutter','heart arrhythmia'], emoji:'🫀', type:'chronic', description:'An irregular and often rapid heart rate that occurs when the two upper chambers of the heart experience chaotic electrical signals. Increases the risk of stroke and heart failure. Very common — affects over 33 million people worldwide.', symptoms:['Heart palpitations — racing, fluttering, or irregular heartbeat','Weakness and fatigue','Reduced ability to exercise','Dizziness or lightheadedness','Shortness of breath','Chest pain or discomfort','Some people have no symptoms at all (silent AFib)'], causes:['High blood pressure (most common cause)','Previous heart attack or heart surgery','Coronary artery disease','Overactive thyroid','Sleep apnea','Excessive alcohol (holiday heart syndrome)','Age','Family history'], homecare:['Take blood thinners (anticoagulants) exactly as prescribed — crucial for stroke prevention','Monitor heart rate and rhythm at home if advised','Avoid caffeine and alcohol triggers','Manage stress','Get treated for sleep apnea if present','Maintain a healthy weight'], whenToSeeDoctor:'New or worsening palpitations, chest pain, severe shortness of breath, or fainting — seek emergency care. Regular cardiologist follow-up is essential for AFib management and stroke risk assessment.', urgency:'high' },

  { name:'Heart Palpitations', aliases:['heart palpitations','palpitations','racing heart','heart fluttering','skipped beats','fast heartbeat','irregular pulse'], emoji:'🫀', type:'common', description:'Sensations of a fast, fluttering, or pounding heartbeat. Often harmless and related to anxiety, caffeine, or exercise. Sometimes a sign of an underlying heart condition requiring evaluation.', symptoms:['Feeling of heart racing, fluttering, pounding, or skipping beats','May occur at rest or during activity','Sensation in the chest, throat, or neck','Usually brief — seconds to minutes','May be accompanied by anxiety or shortness of breath'], causes:['Anxiety and stress','Caffeine and energy drinks','Alcohol','Nicotine','Strenuous exercise','Dehydration','Anemia','Thyroid disease','Cardiac arrhythmia'], homecare:['Reduce caffeine, alcohol, and nicotine','Manage stress with breathing exercises and meditation','Stay well hydrated','Eat regular meals (skipping meals can trigger palpitations)','Track when palpitations occur — timing, duration, triggers'], whenToSeeDoctor:'Palpitations with chest pain, shortness of breath, fainting, or dizziness — seek emergency care. Also see a doctor if palpitations are frequent, long lasting, or a new symptom. An ECG can identify arrhythmias.', urgency:'medium' },

  { name:'Stroke', aliases:['stroke','brain stroke','cerebrovascular accident','cva','brain attack','paralysis stroke'], emoji:'🧠', type:'chronic', description:'A medical emergency where blood supply to part of the brain is cut off, causing brain cells to die. Every minute counts — "Time is Brain." Stroke is a leading cause of disability worldwide but is largely preventable.', symptoms:['Sudden face drooping on one side','Sudden arm weakness or numbness on one side','Sudden speech difficulty — slurred or strange speech','Sudden severe headache with no known cause','Sudden vision problems in one or both eyes','Sudden loss of balance or coordination','Sudden confusion'], causes:['Blocked blood vessel (ischemic stroke — 85% of cases)','Burst blood vessel (hemorrhagic stroke)','Blood clot traveling to the brain','Atrial fibrillation','High blood pressure','Diabetes','Smoking','High cholesterol'], homecare:['FAST test: Face drooping, Arm weakness, Speech difficulty, Time to call emergency — act immediately','Stroke is not managed at home — call emergency services without delay','After stroke: attend all rehabilitation — physiotherapy, speech therapy, occupational therapy','Take prescribed blood thinners or antiplatelet medications','Manage all stroke risk factors aggressively'], whenToSeeDoctor:'Any stroke symptoms are a medical emergency — call ambulance immediately. The clot-busting drug (tPA) must be given within 4.5 hours to be effective. Seconds save brain cells.', urgency:'high' },

  { name:'TIA', aliases:['tia','mini stroke','transient ischemic attack','mini brain attack','warning stroke','transient stroke'], emoji:'🧠', type:'chronic', description:'A Transient Ischemic Attack is a temporary blockage of blood flow to the brain lasting minutes to hours with complete recovery. Often called a "warning stroke" because it signals a high risk of a full stroke in the coming days.', symptoms:['Sudden weakness or numbness on one side of face, arm, or leg','Sudden temporary vision loss in one eye','Sudden speech difficulty or confusion','Sudden severe headache','Sudden dizziness or loss of balance','Symptoms resolve completely within 24 hours (usually within an hour)'], causes:['Blood clot temporarily blocking a brain artery','Narrowing of arteries supplying the brain','Atrial fibrillation causing clots','High blood pressure','Diabetes and high cholesterol'], homecare:['TIA is a medical emergency — go to hospital immediately even if symptoms have resolved','Start prescribed antiplatelet medication (aspirin) immediately if advised','Control all vascular risk factors aggressively starting immediately','Do not drive until cleared by a doctor'], whenToSeeDoctor:'Go to emergency immediately for any TIA symptoms even if fully recovered — the risk of stroke in the next 48 hours is highest and urgent investigation and treatment can prevent it.', urgency:'high' },

  { name:'Peripheral Artery Disease', aliases:['peripheral artery disease','pad','leg artery disease','poor leg circulation','claudication','clogged leg arteries'], emoji:'🦵', type:'chronic', description:'Narrowing of peripheral arteries reducing blood flow to the limbs, usually the legs. A sign of widespread atherosclerosis. Significantly increases the risk of heart attack and stroke.', symptoms:['Leg pain, cramping, or aching when walking (claudication) that stops with rest','Cold legs or feet','Leg weakness','Sores or wounds on toes or feet that heal slowly','Shiny skin on legs','Weak or absent pulse in the legs','Erectile dysfunction in men'], causes:['Atherosclerosis — plaque buildup in arteries','Smoking (major risk factor)','Diabetes','High blood pressure and cholesterol','Obesity','Age over 50'], homecare:['Quit smoking — the single most important step','Walk regularly — supervised walking program improves symptoms over time','Foot care is crucial — inspect feet daily, treat small wounds promptly','Maintain a healthy weight','Control blood sugar, blood pressure, and cholesterol','Take prescribed medications'], whenToSeeDoctor:'Leg pain with walking not relieved by rest, foot wounds not healing, rest pain in foot or toes (indicates severe PAD), or cold blue feet. Regular vascular specialist follow-up is essential.', urgency:'high' },

  { name:'Deep Vein Thrombosis', aliases:['deep vein thrombosis','dvt','blood clot leg','leg clot','deep vein clot','vein thrombosis'], emoji:'🦵', type:'chronic', description:'A blood clot that forms in a deep vein, usually in the leg. Dangerous because the clot can break off and travel to the lungs (pulmonary embolism), which is life-threatening.', symptoms:['Swelling in one leg (usually)','Pain or tenderness in the leg — often described as cramping or soreness','Red or discolored skin on the leg','Warmth in the affected area','Leg feels heavy'], causes:['Prolonged immobility — long flights or bed rest after surgery','Recent surgery especially orthopedic','Cancer and its treatment','Blood clotting disorders','Pregnancy','Oral contraceptive pills','Dehydration','Obesity'], homecare:['If DVT is suspected — do not massage the leg (may dislodge clot)','Seek medical care immediately for diagnosis and anticoagulant treatment','Wear prescribed compression stockings','Walk as soon as medically advised after starting treatment','Stay hydrated on long journeys','Move legs regularly on long flights or car trips'], whenToSeeDoctor:'Any suspected DVT needs immediate medical evaluation — blood thinners (anticoagulants) are the treatment. Symptoms of pulmonary embolism (chest pain, breathlessness, coughing blood) — call emergency services immediately.', urgency:'high' },

  { name:'Pulmonary Embolism', aliases:['pulmonary embolism','pe','lung clot','blood clot lung','lung embolism','clot in lung'], emoji:'💨', type:'chronic', description:'A blockage in one of the pulmonary arteries in the lungs, usually caused by blood clots traveling from deep veins in the legs. A life-threatening emergency requiring immediate treatment.', symptoms:['Sudden shortness of breath at rest or with minimal activity','Chest pain that may worsen with deep breathing or coughing','Coughing up blood','Rapid or irregular heartbeat','Dizziness or lightheadedness','Fainting','Leg swelling, pain, or redness (from underlying DVT)'], causes:['Blood clot from deep vein thrombosis traveling to lungs','Prolonged immobility','Surgery','Cancer','Clotting disorders','Pregnancy and postpartum period'], homecare:['Pulmonary embolism is a medical emergency — call emergency services immediately','No home management — requires hospital treatment with anticoagulants or thrombolytics','After discharge: take blood thinners as prescribed, attend follow-up'], whenToSeeDoctor:'Any sudden unexplained breathlessness, chest pain, or coughing blood — these are signs of pulmonary embolism. Call an ambulance immediately. This condition can be rapidly fatal without treatment.', urgency:'high' },

  /* ── CHRONIC: RESPIRATORY ── */
  { name:'COPD', aliases:['copd','chronic obstructive pulmonary disease','chronic lung disease','emphysema copd','chronic bronchitis copd'], emoji:'💨', type:'chronic', description:'Chronic Obstructive Pulmonary Disease is a chronic inflammatory lung disease causing obstructed airflow. Includes chronic bronchitis and emphysema. The third leading cause of death globally. Strongly linked to smoking.', symptoms:['Persistent cough often with mucus','Shortness of breath especially with activity','Wheezing','Chest tightness','Frequent respiratory infections','Fatigue','In advanced stages: cyanosis (bluish lips), weight loss'], causes:['Cigarette smoking (most common cause — 85-90% of cases)','Long-term exposure to dust, chemical fumes, or air pollution','Alpha-1 antitrypsin deficiency (genetic)','Repeated childhood respiratory infections'], homecare:['Quit smoking — the most critical step to slow progression','Take all inhalers (bronchodilators, steroids) exactly as prescribed','Pulmonary rehabilitation — exercise training and education program','Annual flu vaccine and pneumococcal vaccine','Avoid lung irritants — dust, smoke, fumes','Breathing techniques — pursed lip breathing to trap air less'], whenToSeeDoctor:'Worsening shortness of breath, significant increase in mucus, change in mucus color (yellow or green — infection), confusion, or blue lips or fingernails — these indicate a COPD exacerbation requiring urgent treatment.', urgency:'high' },

  { name:'Chronic Bronchitis', aliases:['chronic bronchitis','chronic cough','smoker\'s cough','persistent productive cough','chronic airway inflammation'], emoji:'💨', type:'chronic', description:'A form of COPD defined as a productive cough (with mucus) lasting at least 3 months a year for 2 consecutive years. Caused primarily by smoking. Leads to permanent airway damage over time.', symptoms:['Persistent productive cough lasting months','Increased mucus production — clear, white, yellow, or green','Shortness of breath with exertion','Wheezing','Frequent respiratory infections','Fatigue'], causes:['Cigarette smoking (primary cause)','Secondhand smoke exposure','Air pollution and occupational dust or fumes','Repeated respiratory infections'], homecare:['Quit smoking immediately — primary treatment','Stay up to date on flu and pneumococcal vaccines','Avoid smoke and air pollutants','Stay well hydrated to thin mucus','Bronchodilator and corticosteroid inhalers as prescribed','Pulmonary rehabilitation'], whenToSeeDoctor:'Increased breathlessness, change in mucus amount or color, fever, or significantly increased coughing. Regular 6-monthly review with a pulmonologist.', urgency:'high' },

  { name:'Emphysema', aliases:['emphysema','lung damage','air sac damage','barrel chest','smoker lung disease'], emoji:'💨', type:'chronic', description:'A lung disease where the tiny air sacs (alveoli) are damaged and enlarged, reducing the surface area for gas exchange. A form of COPD. Irreversible damage but progression can be slowed.', symptoms:['Progressive shortness of breath — first with exertion then at rest','Barrel-shaped chest (air trapping)','Reduced exercise tolerance','Wheezing','Chronic cough','Weight loss in advanced disease','Blue-tinged lips (cyanosis) in severe cases'], causes:['Cigarette smoking (overwhelming cause)','Alpha-1 antitrypsin deficiency (genetic — causes early-onset emphysema)','Long-term exposure to coal dust, silica, or other irritants'], homecare:['Quit smoking — the only intervention proven to slow progression','Bronchodilator inhalers as prescribed','Supplemental oxygen at home if prescribed (usually when SpO2 < 88%)','Pulmonary rehabilitation program','Breathing exercises — pursed lip breathing helps air escape slowly','Adequate nutrition to maintain weight'], whenToSeeDoctor:'Worsening shortness of breath, increased cough, confusion, or blue lips. Regular 6-monthly pulmonologist review. Lung volume reduction surgery or transplant evaluation for advanced cases.', urgency:'high' },

  { name:'Pulmonary Fibrosis', aliases:['pulmonary fibrosis','lung fibrosis','idiopathic pulmonary fibrosis','ipf','scarred lungs','lung scarring'], emoji:'💨', type:'chronic', description:'A serious lung disease where the lung tissue becomes damaged and scarred (fibrosed), making it difficult for the lungs to work properly. The scarring is irreversible but treatment can slow progression.', symptoms:['Progressive shortness of breath','Dry, persistent cough','Fatigue and weakness','Unexplained weight loss','Aching joints and muscles','Clubbing — widening and rounding of fingertips','Crackling sound in lungs when breathing'], causes:['Idiopathic (no known cause — most common)','Long-term exposure to hazardous materials (asbestos, silica dust)','Radiation therapy to the chest','Certain medications','Other autoimmune diseases (rheumatoid arthritis, lupus)','Chronic acid reflux'], homecare:['Take prescribed antifibrotic medications consistently','Supplemental oxygen as prescribed','Pulmonary rehabilitation','Annual flu and pneumococcal vaccines','Avoid respiratory infections as much as possible','Stop smoking if applicable','Maintain good nutrition — weight loss worsens prognosis'], whenToSeeDoctor:'Any worsening of breathlessness, suspected respiratory infection, or new symptoms. Regular 3-monthly pulmonologist review. Lung transplant evaluation for eligible patients.', urgency:'high' },

  { name:'Sleep Apnea', aliases:['sleep apnea','sleep apnoea','obstructive sleep apnea','osa','snoring apnea','breathing stops sleep','cpap'], emoji:'😴', type:'chronic', description:'A potentially serious sleep disorder where breathing repeatedly stops and starts during sleep. Obstructive sleep apnea (OSA) is the most common type. Causes poor sleep quality and daytime fatigue.', symptoms:['Loud snoring','Episodes of stopped breathing during sleep (reported by partner)','Gasping or choking during sleep','Waking with dry mouth or sore throat','Morning headache','Excessive daytime sleepiness','Difficulty concentrating','Mood changes, irritability'], causes:['Excess weight — fatty tissue around upper airway','Narrow airway (anatomical)','Being male — more common in men','Age — more common over 40','Smoking and alcohol','Family history','Nasal congestion'], homecare:['Lose weight if overweight — significant weight loss can resolve OSA','Sleep on your side instead of your back','Avoid alcohol and sedatives before bedtime','Quit smoking','Use CPAP (Continuous Positive Airway Pressure) machine as prescribed — most effective treatment','Maintain a regular sleep schedule'], whenToSeeDoctor:'Excessive daytime sleepiness, partner reporting breathing pauses during sleep, or waking choking or gasping. A sleep study (polysomnography) is needed for diagnosis. Untreated OSA increases risk of hypertension, heart disease, and stroke.', urgency:'medium' },

  /* ── CHRONIC: NEUROLOGICAL ── */
  { name:'Chronic Fatigue Syndrome', aliases:['chronic fatigue syndrome','cfs','me','myalgic encephalomyelitis','systemic exertion intolerance','post viral fatigue'], emoji:'😴', type:'chronic', description:'A complex disorder characterized by extreme fatigue that cannot be explained by an underlying medical condition and does not improve with rest. Often triggered by a viral illness. Affects daily function significantly.', symptoms:['Profound fatigue lasting more than 6 months','Fatigue worsens with physical or mental activity (post-exertional malaise)','Sleep problems — unrefreshing sleep','Cognitive difficulties — brain fog, memory and concentration problems','Headache','Sore throat and swollen lymph nodes','Muscle and joint pain','Dizziness'], causes:['Often follows a viral infection (Epstein-Barr, COVID-19)','Immune system dysfunction','Hormonal imbalances','Genetic predisposition','Psychological and physical stress may trigger'], homecare:['Pacing — carefully manage activity levels to stay within your energy envelope','Do not push through fatigue (boom-bust cycle worsens CFS)','Maintain gentle routine activity within tolerance','Good sleep hygiene','Cognitive behavioral therapy (CBT) may help some patients','Manage stress — gentle yoga, mindfulness'], whenToSeeDoctor:'Any significant unexplained fatigue lasting more than 4-6 weeks needs medical evaluation to rule out other causes. A specialist in CFS or internal medicine can help with management and pacing strategies.', urgency:'medium' },

  { name:'Fibromyalgia', aliases:['fibromyalgia','fibro','widespread pain','chronic pain syndrome fibro','muscle pain condition'], emoji:'🦴', type:'chronic', description:'A disorder characterized by widespread musculoskeletal pain accompanied by fatigue, sleep, memory, and mood issues. The exact cause is unknown but involves altered pain processing in the brain.', symptoms:['Widespread pain — aching, burning, or throbbing all over the body','Fatigue and exhaustion','Sleep disturbances — waking unrefreshed','Cognitive problems — fibro fog (memory and concentration difficulty)','Headaches','Depression and anxiety','Irritable bowel syndrome frequently coexists','Heightened sensitivity to touch, temperature, and sound'], causes:['Altered pain perception — the brain amplifies pain signals','Often triggered by infection, physical trauma, or significant psychological stress','Genetics — tends to run in families','Female sex — affects women more than men'], homecare:['Low-impact aerobic exercise — the most effective long-term treatment (walking, swimming, tai chi)','Start very slowly and gradually increase to avoid flares','Prioritize sleep — good sleep hygiene is essential','Stress management — mindfulness, CBT, relaxation techniques','Warm baths and heat application for pain relief','Pacing daily activities'], whenToSeeDoctor:'Diagnosis requires a rheumatologist or specialist to rule out other conditions. Combination of medication (duloxetine, pregabalin), physiotherapy, and psychological support gives the best results.', urgency:'medium' },

  { name:'Lupus', aliases:['lupus','sle','systemic lupus erythematosus','butterfly rash','autoimmune lupus','lupus disease'], emoji:'🦋', type:'chronic', description:'A systemic autoimmune disease where the body\'s immune system attacks its own tissues and organs. Can affect the joints, skin, kidneys, blood cells, brain, heart, and lungs. Characterized by flares and remissions.', symptoms:['Butterfly-shaped rash across cheeks and nose','Fatigue (often severe)','Joint pain, stiffness, and swelling','Fever','Skin lesions worsened by sun exposure','Chest pain with deep breathing (pleuritis)','Hair loss','Mouth sores','Kidney problems (foamy urine, swelling)','Raynaud\'s phenomenon (fingers turning white or blue in cold)'], causes:['Autoimmune — immune system attacks own tissues','Genetic predisposition','Hormonal factors — more common in women of childbearing age','Environmental triggers — sunlight, infections, certain medications'], homecare:['Protect skin from sun — high-SPF sunscreen, protective clothing, avoid peak sun hours','Take all prescribed medications (hydroxychloroquine, steroids, immunosuppressants)','Get regular blood and urine tests to monitor organ function','Avoid smoking','Manage stress','Adequate rest during flares','Calcium and vitamin D supplements (corticosteroids deplete bone density)'], whenToSeeDoctor:'Regular 3-monthly rheumatologist review. Urgent care for chest pain, significant kidney symptoms (very foamy urine, significant leg swelling), severe headache, or any signs of organ involvement.', urgency:'high' },

  { name:'Multiple Sclerosis', aliases:['multiple sclerosis','ms','demyelinating disease','ms symptoms','ms diagnosis'], emoji:'🧠', type:'chronic', description:'A disease in which the immune system eats away at the protective myelin covering of nerves, disrupting communication between the brain and the rest of the body. Affects over 2.8 million people worldwide.', symptoms:['Numbness or weakness in one or more limbs','Electric shock sensation with neck movements (Lhermitte\'s sign)','Vision problems — blurred vision, double vision, vision loss in one eye','Tremor, lack of coordination','Slurred speech','Fatigue (often severe and disproportionate)','Bladder and bowel problems','Cognitive changes'], causes:['Autoimmune destruction of myelin sheath','Genetic susceptibility combined with environmental factors','Vitamin D deficiency (linked to higher risk)','Certain viral infections (Epstein-Barr)','More common in women and in people farther from the equator'], homecare:['Take disease-modifying therapies as prescribed to reduce relapses and slow progression','Stay cool — heat worsens MS symptoms (Uhthoff\'s phenomenon)','Regular low-intensity exercise — swimming, yoga, tai chi','Eat an anti-inflammatory diet — Mediterranean diet','Vitamin D supplementation (discuss dose with neurologist)','Physiotherapy and occupational therapy for function'], whenToSeeDoctor:'Regular 6-monthly neurologist review. Urgent care for a relapse — new or worsening neurological symptoms lasting more than 24 hours — early steroid treatment shortens relapses.', urgency:'high' },

  { name:'Parkinson\'s Disease', aliases:['parkinson','parkinson\'s disease','parkinsonism','tremor disease','shaking palsy'], emoji:'🧠', type:'chronic', description:'A progressive nervous system disorder affecting movement. Caused by loss of dopamine-producing neurons in the brain. Symptoms develop gradually, starting with a barely noticeable tremor in one hand.', symptoms:['Tremor — usually begins in a limb, often the hand or fingers','Bradykinesia — slowed movement making simple tasks difficult','Rigid muscles limiting range of motion','Impaired posture and balance','Loss of automatic movements (blinking, smiling, swinging arms)','Speech changes — soft, slurred, or monotone','Writing changes — smaller handwriting (micrographia)'], causes:['Loss of dopaminergic neurons in the substantia nigra region of the brain','Genetic mutations (in some cases)','Environmental factors — exposure to herbicides and pesticides','Exact cause unknown in most cases'], homecare:['Take levodopa and other dopaminergic medications exactly as scheduled — timing is critical','Regular exercise is extremely beneficial — cycling, tai chi, boxing exercise programs designed for Parkinson\'s','Physical therapy for balance and gait','Occupational therapy for daily tasks and handwriting','Speech therapy for voice and swallowing problems','Join a Parkinson\'s support group'], whenToSeeDoctor:'Regular 6-monthly neurology review. Report any falls, changes in medication effectiveness (wearing off between doses), swallowing difficulties, or significant cognitive changes.', urgency:'high' },

  { name:'Alzheimer\'s Disease', aliases:['alzheimer\'s','alzheimer disease','alzheimers','dementia alzheimer','memory loss disease','alzheimer dementia'], emoji:'🧠', type:'chronic', description:'The most common cause of dementia. A progressive brain disease that destroys memory and other important mental functions. Currently no cure but treatments can temporarily slow worsening.', symptoms:['Memory loss disrupting daily life — especially recent memories','Difficulty planning or solving problems','Confusion with time and place','Trouble with familiar tasks','New problems with words in speaking or writing','Misplacing things and inability to retrace steps','Decreased judgment','Withdrawal from social activities','Mood and personality changes'], causes:['Abnormal protein deposits in the brain (amyloid plaques, tau tangles)','Genetic risk factors (APOE e4 gene)','Age — risk doubles every 5 years after 65','Family history','Cardiovascular risk factors (hypertension, diabetes, high cholesterol)'], homecare:['Maintain a daily routine to reduce confusion','Keep the home safe — remove tripping hazards, label rooms','Use memory aids — notes, calendars, medication organizers','Regular gentle exercise — walks with supervision','Social engagement and mental stimulation — music, familiar activities','Caregiver support and respite care are essential'], whenToSeeDoctor:'Memory concerns should be evaluated early — treatable causes of memory loss must be excluded. Regular neurologist or geriatrician review. Advance care planning discussions should happen early in the disease.', urgency:'high' },

  { name:'Dementia', aliases:['dementia','memory loss elderly','cognitive decline','senility','vascular dementia','frontotemporal dementia'], emoji:'🧠', type:'chronic', description:'An umbrella term for a range of conditions caused by abnormal brain changes that trigger a decline in memory, thinking, behavior, and social abilities severe enough to interfere with daily life. Alzheimer\'s causes 60-80% of cases.', symptoms:['Memory loss (especially recent events)','Difficulty with complex tasks and problem solving','Language problems — finding words or following conversations','Disorientation — getting lost in familiar places','Personality and behavior changes','Poor judgment and decision making','Depression, anxiety, or paranoia','Difficulty with basic daily tasks in later stages'], causes:['Alzheimer\'s disease (most common)','Vascular dementia — from strokes or reduced brain blood flow','Lewy body dementia','Frontotemporal dementia','Parkinson\'s disease','Reversible causes: thyroid disease, vitamin B12 deficiency, medication side effects'], homecare:['Create a safe and structured home environment','Establish consistent daily routines','Label common items and important locations','Engage in familiar, enjoyable activities','Social interaction and mental stimulation slow decline','Caregiver wellbeing is critical — seek respite care'], whenToSeeDoctor:'Any significant memory or cognitive concerns should be evaluated. Reversible causes can be treated. Early diagnosis allows planning and access to treatments. Geriatric specialist or neurologist referral recommended.', urgency:'medium' },

  { name:'Epilepsy', aliases:['epilepsy','seizures','epileptic seizures','fits','convulsions','epileptic fits'], emoji:'🧠', type:'chronic', description:'A neurological disorder characterized by recurrent, unprovoked seizures — sudden bursts of electrical activity in the brain. Affects over 50 million people worldwide. Most people with epilepsy can live full, active lives.', symptoms:['Seizures — ranging from brief lapses of attention (absence) to violent convulsions','Temporary confusion','Staring spell','Uncontrollable jerking movements of arms and legs','Loss of consciousness or awareness','Fear, anxiety, or deja vu sensation before a seizure (aura)'], causes:['Genetic factors','Brain injury or trauma','Brain tumors','Stroke','Infections (meningitis, encephalitis)','In many cases, cause is unknown'], homecare:['Take antiepileptic medication exactly as prescribed — never skip doses','Get sufficient sleep — sleep deprivation is a major seizure trigger','Avoid alcohol and recreational drugs','Identify and avoid personal triggers (flashing lights, stress)','Carry a medical ID bracelet','Seizure safety: clear the area, place on side, time the seizure, do not restrain'], whenToSeeDoctor:'First seizure always needs urgent medical evaluation. Regular 6-monthly neurologist review. A seizure lasting more than 5 minutes or person not recovering normally after a seizure — call emergency services immediately (status epilepticus).', urgency:'high' },

  { name:'Neuropathy', aliases:['neuropathy','peripheral neuropathy','nerve damage','diabetic neuropathy','tingling numbness feet','nerve pain'], emoji:'🧠', type:'chronic', description:'Damage or dysfunction of peripheral nerves causing weakness, numbness, and pain, usually in the hands and feet. Diabetic neuropathy is the most common form. Many causes exist.', symptoms:['Gradual onset of numbness and tingling in feet or hands spreading upward','Sharp, jabbing, throbbing, or burning pain','Extreme sensitivity to touch','Lack of coordination and falling','Muscle weakness','Feeling like you are wearing socks or gloves when you are not','Autonomic symptoms — blood pressure changes, bowel and bladder problems'], causes:['Diabetes (most common — diabetic peripheral neuropathy)','Vitamin B12 deficiency','Excessive alcohol use','Autoimmune diseases','Infections (shingles, HIV, Lyme disease)','Certain chemotherapy drugs','Kidney disease'], homecare:['Strictly control blood sugar if diabetic — the most important step','Daily foot inspection for wounds (diabetics especially)','Take prescribed medications for nerve pain (pregabalin, duloxetine, amitriptyline)','Vitamin B12 supplementation if deficient','Avoid alcohol','Physical therapy to maintain strength and balance','Protective footwear'], whenToSeeDoctor:'Any significant numbness, burning pain in extremities, unexplained weakness, or balance problems. Diagnosis and identifying the cause requires tests including blood work and nerve conduction studies.', urgency:'medium' },

  /* ── CHRONIC: KIDNEY & LIVER ── */
  { name:'Chronic Kidney Disease', aliases:['chronic kidney disease','ckd','kidney disease','renal disease','kidney damage','reduced kidney function'], emoji:'🫘', type:'chronic', description:'A long-term condition where the kidneys do not work as well as they should. Develops slowly over years. The kidneys filter waste from blood — when impaired, harmful waste accumulates. Diabetes and hypertension are the leading causes.', symptoms:['Fatigue and weakness','Swollen ankles, feet, or hands','Shortness of breath','Nausea and vomiting','Loss of appetite','Blood in urine or foamy urine (protein in urine)','High blood pressure','Muscle cramps','Itchy skin','Difficulty concentrating'], causes:['Diabetes (most common cause)','High blood pressure (second most common)','Glomerulonephritis (kidney inflammation)','Polycystic kidney disease (genetic)','Recurrent kidney infections','Long-term use of NSAIDs (painkillers like ibuprofen)'], homecare:['Control blood sugar and blood pressure aggressively — critical to slowing progression','Take prescribed medications (ACE inhibitors or ARBs protect the kidney)','Low-protein diet if advised by nephrologist','Low-potassium and low-phosphorus diet in advanced stages','Restrict salt intake','Stay hydrated but not excessively','Avoid NSAIDs (ibuprofen, naproxen) — extremely harmful to kidneys'], whenToSeeDoctor:'Regular 3-monthly nephrologist review. CKD is monitored with blood (creatinine, eGFR) and urine tests. Plan for dialysis or transplant evaluation begins when eGFR falls below 30.', urgency:'high' },

  { name:'Kidney Failure', aliases:['kidney failure','renal failure','end stage renal disease','esrd','dialysis kidney','acute kidney failure'], emoji:'🫘', type:'chronic', description:'The final stage of chronic kidney disease where the kidneys lose almost all ability to function. Requires dialysis or a kidney transplant to sustain life. Can also occur acutely from sudden severe illness or injury.', symptoms:['Severely reduced or absent urine output','Swelling throughout the body','Extreme fatigue','Confusion and difficulty concentrating','Nausea, vomiting, and loss of appetite','Shortness of breath from fluid in lungs','Chest pain','Itching all over the body','Muscle twitching and cramps'], causes:['End stage of chronic kidney disease from diabetes or hypertension','Acute causes: severe dehydration, sepsis, major surgery, certain medications, contrast dye'], homecare:['Follow prescribed dialysis schedule without missing sessions','Strict dietary restrictions — potassium, phosphorus, fluid, and protein limits as advised by renal dietitian','Take all prescribed medications including phosphate binders and erythropoietin','Skin care for itching — moisturizing, avoiding scratches','Monitor weight daily for fluid accumulation','Discuss kidney transplant eligibility with nephrologist'], whenToSeeDoctor:'Kidney failure requires specialist nephrology care. Emergency dialysis may be needed for acute kidney failure with life-threatening electrolyte disturbances. Immediate care if symptoms worsen rapidly.', urgency:'high' },

  { name:'Liver Cirrhosis', aliases:['cirrhosis','liver cirrhosis','liver scarring','end stage liver disease','fibrosis liver','alcoholic cirrhosis'], emoji:'🍋', type:'chronic', description:'Late-stage scarring of the liver caused by many forms of liver diseases and conditions, such as hepatitis and chronic alcoholism. Healthy liver tissue is replaced by scar tissue, preventing the liver from functioning properly.', symptoms:['Fatigue and weakness','Easy bruising and bleeding','Loss of appetite and weight loss','Nausea','Yellowing of skin and eyes (jaundice)','Swollen abdomen (ascites — fluid buildup)','Swollen legs','Itching','Spider-like blood vessels visible on skin','Mental confusion (hepatic encephalopathy)'], causes:['Chronic alcohol use (most common in many countries)','Chronic viral hepatitis B or C','Non-alcoholic fatty liver disease (NAFLD/NASH)','Autoimmune hepatitis','Genetic disorders (Wilson\'s disease, hemochromatosis)'], homecare:['Stop alcohol completely — the most critical step for alcohol-related cirrhosis','Take prescribed medications — diuretics for ascites, lactulose for encephalopathy, beta-blockers for varices','Low-sodium diet to reduce fluid retention','Hepatitis B and A vaccinations','Avoid all hepatotoxic substances — alcohol, many herbal remedies, NSAIDs','Regular 3-6 monthly ultrasound and AFP blood test for liver cancer screening'], whenToSeeDoctor:'Vomiting blood, black tarry stools (variceal bleeding — emergency), sudden confusion (hepatic encephalopathy), rapidly increasing abdominal swelling, or fever — these are liver-related emergencies.', urgency:'high' },

  { name:'Fatty Liver', aliases:['fatty liver','nafld','steatosis','fatty liver disease','liver fat','hepatic steatosis'], emoji:'🍋', type:'chronic', description:'A condition where fat accumulates in the liver. Simple fatty liver is usually harmless, but non-alcoholic steatohepatitis (NASH) can progress to cirrhosis. Extremely common — affects up to 25% of the global population.', symptoms:['Usually no symptoms in early stages','Fatigue','Discomfort or pain in upper right abdomen','Slightly enlarged liver found incidentally on ultrasound','In NASH: jaundice, swelling, symptoms of cirrhosis if advanced'], causes:['Obesity and excess abdominal fat (most common)','Type 2 diabetes and insulin resistance','High triglycerides','Metabolic syndrome','Rapid weight loss','Alcohol use (alcoholic fatty liver)'], homecare:['Lose weight gradually (5-10% body weight loss can significantly reduce liver fat)','Follow a low-sugar, low-refined carbohydrate diet','Exercise 150-300 minutes per week','Avoid alcohol completely','Control blood sugar and cholesterol','Avoid fructose-rich foods and sugary drinks'], whenToSeeDoctor:'Diagnosis requires ultrasound or liver function blood tests. Annual liver function tests and ultrasound recommended for those with NASH. A hepatologist should evaluate if enzymes are significantly elevated or liver function declines.', urgency:'medium' },

  { name:'Non-Alcoholic Fatty Liver Disease', aliases:['non alcoholic fatty liver','nafld','nash','non alcoholic steatohepatitis','fatty liver non drinker'], emoji:'🍋', type:'chronic', description:'Fatty liver disease occurring in people who drink little or no alcohol. Ranges from simple fat accumulation (steatosis) to non-alcoholic steatohepatitis (NASH) which includes inflammation and can progress to cirrhosis.', symptoms:['Usually asymptomatic in early stage','Fatigue','Mild right upper abdominal discomfort','Raised liver enzymes found on blood test','Enlarged liver on ultrasound','In advanced NASH: jaundice, spider veins, swollen abdomen'], causes:['Insulin resistance and type 2 diabetes','Obesity — especially abdominal obesity','High triglycerides and cholesterol','Metabolic syndrome','Hypothyroidism','Rapid weight loss or malnutrition'], homecare:['Weight loss is the most effective treatment — even 7-10% reduction significantly improves liver health','Mediterranean diet — reduce refined carbs, sugar, and processed foods','Regular aerobic and resistance exercise','Avoid alcohol even though not the primary cause','Control blood sugar and lipid levels','Vitamin E may help in non-diabetic NASH (discuss with doctor)'], whenToSeeDoctor:'Anyone with persistently elevated liver enzymes, obesity with metabolic syndrome, or known diabetes should be screened for NAFLD. Hepatologist referral if NASH or advanced fibrosis is suspected.', urgency:'medium' },

  /* ── CHRONIC: GASTROINTESTINAL ── */
  { name:'Crohn\'s Disease', aliases:['crohn\'s','crohn\'s disease','crohn disease','inflammatory bowel crohn','crohns'], emoji:'🏥', type:'chronic', description:'A type of inflammatory bowel disease that causes inflammation of the digestive tract lining. Can involve any part of the GI tract from mouth to anus. Causes significant pain, diarrhea, fatigue, and malnutrition.', symptoms:['Diarrhea (often persistent and sometimes severe)','Abdominal pain and cramping','Blood in stool','Fatigue','Fever','Weight loss and malnutrition','Mouth sores','Reduced appetite','Perianal complications — fistulas, abscesses'], causes:['Immune system malfunction — attacks digestive tract lining','Genetic factors — family history increases risk','Imbalance in gut microbiome','Smoking significantly worsens Crohn\'s disease','Environmental factors'], homecare:['Take prescribed medications consistently — immunosuppressants, biologics, steroids during flares','Eat small, frequent meals','Keep a food diary to identify personal trigger foods','Avoid smoking','Stay well hydrated — diarrhea causes fluid loss','Nutritional supplements if malabsorption is occurring','Manage stress which can trigger flares'], whenToSeeDoctor:'Regular 3-monthly gastroenterologist review. Urgent care for high fever, severe abdominal pain, significant rectal bleeding, or signs of obstruction — bowel complications require emergency treatment.', urgency:'high' },

  { name:'Ulcerative Colitis', aliases:['ulcerative colitis','uc','colitis','inflammatory bowel disease colitis','ibd colitis'], emoji:'🏥', type:'chronic', description:'A chronic inflammatory bowel disease that causes long-lasting inflammation and ulcers (sores) in the innermost lining of the large intestine and rectum. Characterized by flares and periods of remission.', symptoms:['Diarrhea often with blood or pus','Abdominal pain and cramping','Rectal pain and urgency','Inability to defecate despite urgency (tenesmus)','Unexplained weight loss','Fatigue','Fever during flares','In children: delayed growth'], causes:['Immune system dysfunction — attacks the colon lining','Genetic factors — more common in those with family history','Imbalance in gut bacteria','Environmental factors (diet, antibiotic use in early life)'], homecare:['Take prescribed medications throughout remission — not just during flares (crucial for preventing relapse)','Eat a low-residue diet during flares (low fiber)','Identify personal trigger foods','Stay hydrated during diarrhea episodes','Manage stress','Probiotics may help maintain remission','Annual colonoscopy for cancer surveillance after 8-10 years of disease'], whenToSeeDoctor:'Regular gastroenterologist follow-up every 3-6 months. Urgent care for very frequent bloody diarrhea, high fever, or severe abdominal pain — severe UC flares require hospital admission.', urgency:'high' },

  { name:'Inflammatory Bowel Disease', aliases:['inflammatory bowel disease','ibd','bowel inflammation','chronic bowel disease','crohn or colitis'], emoji:'🏥', type:'chronic', description:'An umbrella term for chronic inflammatory conditions of the gastrointestinal tract, primarily Crohn\'s disease and ulcerative colitis. Affects over 7 million people worldwide. Characterized by flares and remissions.', symptoms:['Persistent diarrhea (sometimes with blood)','Abdominal pain and cramping','Fatigue','Weight loss','Fever during flares','Reduced appetite','Joint pain, eye inflammation, skin rashes (extraintestinal manifestations)'], causes:['Autoimmune dysfunction attacking the GI tract','Genetic predisposition','Environmental triggers — diet, infections, antibiotic use','Imbalance of gut microbiome','Stress can trigger or worsen flares'], homecare:['Take all prescribed medications as directed — the foundation of IBD management','Keep a symptom and food diary','Avoid known dietary triggers — differs between individuals','Eat small frequent meals during flares','Stay hydrated','Do not smoke — particularly important in Crohn\'s disease','Manage stress through mindfulness, yoga, or therapy'], whenToSeeDoctor:'Regular gastroenterologist review is essential. Emergency care for severe bleeding, high fever, severe pain, or signs of bowel perforation or obstruction.', urgency:'high' },

  { name:'Peptic Ulcer', aliases:['peptic ulcer','stomach ulcer','gastric ulcer','duodenal ulcer','ulcer in stomach'], emoji:'🔥', type:'chronic', description:'A sore that develops on the lining of the stomach, small intestine, or esophagus when stomach acid erodes the mucus layer. H. pylori bacteria and NSAIDs are the main causes. Highly treatable.', symptoms:['Burning or gnawing stomach pain — often between meals and at night','Pain temporarily relieved by eating or antacids','Nausea','Loss of appetite','Bloating','Burping','In severe cases: blood in vomit (hematemesis) or black tarry stools (melena)'], causes:['Helicobacter pylori (H. pylori) bacterial infection (most common)','Long-term use of NSAIDs (aspirin, ibuprofen, naproxen)','Excessive stomach acid production (Zollinger-Ellison syndrome — rare)','Smoking and alcohol worsen ulcers'], homecare:['Take prescribed antibiotics and proton pump inhibitors (PPIs) for H. pylori — complete the full course','Take antacids for temporary relief','Eat small frequent meals','Avoid spicy, acidic, or fatty foods during healing','Stop NSAIDs — use paracetamol for pain instead','Quit smoking and avoid alcohol'], whenToSeeDoctor:'Blood in vomit, black tarry stools, sudden severe abdominal pain — these are ulcer complications requiring emergency care. All suspected ulcers need endoscopy for diagnosis and H. pylori testing.', urgency:'high' },

  { name:'Gastric Ulcer', aliases:['gastric ulcer','stomach ulcer','stomach sore','ulcer in stomach lining'], emoji:'🔥', type:'chronic', description:'An open sore in the lining of the stomach (gastric mucosa). A type of peptic ulcer. Pain is often felt during or shortly after eating. Requires medical treatment to heal and prevent complications.', symptoms:['Dull or burning pain in upper abdomen — often during or right after eating','Nausea and vomiting','Bloating and belching','Feeling full quickly','Weight loss (pain discourages eating)','Blood in vomit or black tarry stools (if bleeding — emergency)'], causes:['H. pylori infection','Long-term NSAID use','Excessive alcohol consumption','Smoking','Stress does not cause but worsens symptoms'], homecare:['Take all prescribed medications (PPIs, H. pylori eradication regimen)','Eat small, gentle meals — avoid spicy, acidic, fatty food','Avoid alcohol completely during treatment','Stop NSAIDs','Quit smoking','Do not skip doses — ulcers can recur without complete treatment'], whenToSeeDoctor:'All gastric ulcers need endoscopy at diagnosis and follow-up endoscopy to confirm healing (to rule out gastric cancer). Seek emergency care for vomiting blood or black stools.', urgency:'high' },

  { name:'Duodenal Ulcer', aliases:['duodenal ulcer','duodenum ulcer','small intestine ulcer','hunger pain ulcer','night pain ulcer'], emoji:'🔥', type:'chronic', description:'A peptic ulcer occurring in the first part of the small intestine (duodenum). The most common type of peptic ulcer. Pain typically occurs on an empty stomach and is relieved by eating.', symptoms:['Burning or aching pain in upper abdomen — worse when stomach is empty','Pain 2-3 hours after meals','Night pain waking from sleep','Pain relieved by eating or taking antacids','Nausea','Weight gain (eating relieves pain)','In severe cases: blood in vomit or black tarry stools'], causes:['H. pylori infection (most common)','Long-term NSAID use','Excess acid production','Smoking'], homecare:['Take prescribed medications consistently — PPI and H. pylori eradication','Take antacids for pain relief until medication kicks in','Eat regular meals — do not skip (empty stomach worsens pain)','Avoid NSAIDs — use paracetamol instead','Avoid coffee, alcohol, and spicy food','Quit smoking'], whenToSeeDoctor:'All suspected duodenal ulcers need endoscopy and H. pylori test. Emergency care for vomiting blood, black tarry stools, or sudden severe abdominal pain (perforation).', urgency:'high' },

  { name:'Celiac Disease', aliases:['celiac disease','coeliac disease','gluten disease','gluten intolerance celiac','wheat allergy celiac'], emoji:'🌾', type:'chronic', description:'An autoimmune disorder where eating gluten — a protein in wheat, barley, and rye — triggers an immune response that damages the small intestine lining, preventing nutrient absorption. Managed entirely by a strict lifelong gluten-free diet.', symptoms:['Diarrhea, constipation, or both','Abdominal bloating and pain','Nausea and vomiting','Weight loss and malnutrition','Fatigue','Anemia (from iron malabsorption)','Bone or joint pain','Itchy blistering skin rash (dermatitis herpetiformis)','Mouth sores','Headaches and fatigue'], causes:['Autoimmune reaction to gluten triggered by genetic susceptibility (HLA-DQ2 and DQ8 genes)','Family history of celiac disease or dermatitis herpetiformis','Associated with other autoimmune conditions (Type 1 diabetes, thyroid disease)'], homecare:['Strict lifelong gluten-free diet — the only treatment','Read all food labels carefully — gluten hides in many processed foods','Avoid cross-contamination in cooking','Replace nutrients depleted by malabsorption — iron, calcium, vitamin D, B vitamins','Join a celiac support group for dietary guidance'], whenToSeeDoctor:'Diagnosis requires blood tests (anti-tTG antibodies) and small bowel biopsy via endoscopy. Annual gastroenterologist and dietitian review. Monitor bone density (DEXA scan) due to malabsorption risk.', urgency:'medium' },

  { name:'Diverticulitis', aliases:['diverticulitis','diverticular disease','diverticular inflammation','colon pockets inflamed'], emoji:'🏥', type:'chronic', description:'Inflammation or infection of small pouches (diverticula) that can form in the walls of the large intestine. Common in older adults. Ranges from mild to severe requiring hospitalization.', symptoms:['Sudden, severe pain in left lower abdomen','Fever and chills','Nausea and vomiting','Change in bowel habits (constipation or diarrhea)','Bloating','Tenderness in left lower abdomen'], causes:['Pre-existing diverticulosis (small pouches in colon wall)','Low-fiber diet causing constipation and pressure on colon wall','Aging — diverticulosis increases with age','Obesity and sedentary lifestyle'], homecare:['During acute attack: clear liquid diet for a few days until symptoms improve','Take prescribed antibiotics for the full course','Paracetamol for pain (avoid NSAIDs which can worsen)','Once recovered: high-fiber diet to prevent recurrence — vegetables, fruits, whole grains','Drink plenty of water','Regular exercise'], whenToSeeDoctor:'Suspected diverticulitis needs medical evaluation. Severe pain, high fever, vomiting, or inability to keep fluids down needs emergency care — perforation or abscess may require surgery. CT scan is the standard diagnostic test.', urgency:'high' },

  /* ── CHRONIC: MUSCULOSKELETAL & AUTOIMMUNE ── */
  { name:'Rheumatoid Arthritis', aliases:['rheumatoid arthritis','ra','autoimmune arthritis','ra joint disease','inflammatory arthritis'], emoji:'🦴', type:'chronic', description:'A chronic autoimmune inflammatory disorder that primarily affects the joints, causing painful swelling, eventually resulting in bone erosion and joint deformity. Unlike osteoarthritis, it is not due to wear and tear.', symptoms:['Tender, warm, swollen joints','Joint stiffness worst in the morning and after inactivity — lasting more than 1 hour','Fatigue and malaise','Fever','Symmetrical joint involvement (both hands or both knees)','Rheumatoid nodules — firm bumps under skin','Over time: joint deformity and loss of function'], causes:['Autoimmune — immune system attacks the synovium (joint lining)','Genetic predisposition (HLA genes)','Environmental triggers — infection, smoking','Hormonal factors — more common in women'], homecare:['Take prescribed DMARDs (methotrexate, hydroxychloroquine) consistently — they protect the joints from damage','Do not wait for a flare to take medication','Apply warm compress in morning for stiffness','Regular gentle exercise — swimming, cycling, yoga — to maintain joint function','Protect joints — use assistive devices, avoid overloading joints','Quit smoking — worsens RA and reduces medication effectiveness'], whenToSeeDoctor:'Regular 3-monthly rheumatologist review. Any sudden joint swelling, fever, or new symptoms should be evaluated promptly. Early aggressive treatment prevents joint damage.', urgency:'high' },

  { name:'Psoriatic Arthritis', aliases:['psoriatic arthritis','psa','psoriasis arthritis','skin and joint disease'], emoji:'🦴', type:'chronic', description:'A form of inflammatory arthritis affecting some people with psoriasis — the chronic skin condition causing scaly patches. Can affect any joint and ranges from mild to severe. Requires early treatment to prevent joint damage.', symptoms:['Swollen, painful joints','Swollen fingers or toes (dactylitis — "sausage digits")','Joint stiffness especially in the morning','Lower back pain and stiffness (sacroiliitis)','Nail changes — pitting, discoloration, separation from nail bed','Skin psoriasis patches','Eye inflammation (uveitis)'], causes:['Autoimmune — immune system attacks healthy joint tissue','Pre-existing psoriasis (30% of psoriasis patients develop PsA)','Genetic factors','Infections may trigger onset'], homecare:['Take prescribed medications (DMARDs, biologics, NSAIDs) as directed','Apply warm or cold compress to affected joints','Regular low-impact exercise to maintain joint mobility','Maintain a healthy weight to reduce joint stress','Manage psoriasis skin condition simultaneously — treating skin often helps joints'], whenToSeeDoctor:'Regular rheumatologist review. Prompt attention if new joints become involved or existing joint symptoms worsen. Early treatment is key to preventing irreversible joint damage.', urgency:'high' },

  { name:'Gout', aliases:['gout','gouty arthritis','uric acid joint pain','big toe pain gout','hyperuricemia gout'], emoji:'🦴', type:'chronic', description:'A complex form of arthritis characterized by sudden, severe attacks of pain, swelling, redness, and tenderness in joints — most often the joint at the base of the big toe. Caused by excess uric acid in the blood.', symptoms:['Intense, severe joint pain — often wakes from sleep','Most commonly affects the big toe joint','Also affects ankles, knees, elbows, wrists, and fingers','Swelling, redness, and warmth at the affected joint','Lingering discomfort after the worst pain subsides','Limited range of motion','Tophi — chalky deposits of uric acid crystals under skin (chronic gout)'], causes:['Hyperuricemia — too much uric acid in the blood','Uric acid crystals depositing in joints causing inflammation','Diet high in purines — red meat, organ meat, shellfish, alcohol (especially beer)','Dehydration','Certain medications (diuretics)','Obesity','Family history'], homecare:['During an attack: rest the affected joint and apply ice packs','Take prescribed colchicine or NSAIDs at the first sign of an attack','Drink at least 2-3 liters of water daily','Avoid alcohol especially beer and spirits','Avoid purine-rich foods during and after attacks','Allopurinol (prescribed) lowers uric acid long-term — take consistently'], whenToSeeDoctor:'First gout attack needs medical confirmation and uric acid level testing. Regular review with a doctor to monitor uric acid levels and adjust medications. Chronic gout needs ongoing urate-lowering therapy.', urgency:'medium' },

  { name:'Osteoporosis', aliases:['osteoporosis','bone loss','weak bones','low bone density','brittle bones','osteoporotic fracture'], emoji:'🦴', type:'chronic', description:'A condition in which bones become weak and brittle — so fragile that a fall or even mild stress like bending over can cause a fracture. Often called a "silent disease" because bone loss occurs without symptoms.', symptoms:['Usually no symptoms until a fracture occurs','Back pain from a fractured or collapsed vertebra','Loss of height over time','Stooped posture','Fractures from minor falls or even no injury (fragility fractures)','Most common fracture sites: hip, wrist, spine'], causes:['Age-related bone density loss (accelerates after menopause in women)','Estrogen deficiency (menopause)','Calcium and vitamin D deficiency','Sedentary lifestyle','Smoking and excessive alcohol','Long-term corticosteroid use','Thin body build and low body weight'], homecare:['Calcium-rich diet — dairy, fortified plant milks, leafy greens, sesame seeds','Vitamin D3 and calcium supplements if deficient or recommended','Weight-bearing exercise — walking, dancing, resistance training','Quit smoking and limit alcohol','Fall prevention at home — remove rugs, install grab bars, improve lighting','Take prescribed bisphosphonates or other bone-strengthening medications'], whenToSeeDoctor:'DEXA scan (bone density test) recommended for all women over 65 and all men over 70, or younger if risk factors. Any fragility fracture needs urgent evaluation and treatment initiation.', urgency:'medium' },

  { name:'Ankylosing Spondylitis', aliases:['ankylosing spondylitis','as','axial spondyloarthritis','inflammatory back pain','spinal arthritis','bamboo spine'], emoji:'🦴', type:'chronic', description:'A type of inflammatory arthritis primarily affecting the spine, causing severe inflammation of the vertebrae leading to chronic pain and potential fusion of the spine. More common in young men.', symptoms:['Chronic lower back and buttock pain and stiffness','Morning stiffness lasting more than 30 minutes, improving with movement','Alternating buttock pain','Reduced flexibility of the spine','Chest pain with breathing (costovertebral joint involvement)','Fatigue','Eye inflammation (uveitis) — sudden red painful eye','Heel pain (enthesitis)'], causes:['Autoimmune inflammation of spinal joints and entheses (where tendons attach to bone)','Strong genetic association — HLA-B27 gene','Usually begins between age 17-45'], homecare:['Regular daily exercise and physiotherapy are critical — the most important treatment besides medication','Swimming and specific back stretches to maintain flexibility','Sleep on a firm mattress in a flat position','Avoid prolonged sitting — stand and stretch every 30 minutes','Hot shower in the morning to relieve stiffness','Quit smoking — worsens radiological progression','Take prescribed NSAIDs and biologic medications as directed'], whenToSeeDoctor:'Chronic back pain starting before age 40, worse in the morning and improved with activity (inflammatory pattern), should be evaluated by a rheumatologist. Early treatment prevents fusion.', urgency:'medium' },

  { name:'Raynaud\'s Disease', aliases:['raynaud\'s','raynaud disease','raynaud phenomenon','fingers turning white','cold fingers color change','vasospasm fingers'], emoji:'❄️', type:'chronic', description:'A condition causing some areas of the body — especially fingers and toes — to feel numb and cold in response to cold temperatures or stress, when blood vessels in those areas temporarily narrow.', symptoms:['Fingers or toes turning white then blue in the cold or during stress','Affected areas feel numb and cold','Upon warming — skin turns red and throbbing or tingling begins','Color changes occur in phases: white (pallor) → blue (cyanosis) → red (reactive hyperemia)','In severe cases: sores or ulcers on fingertips'], causes:['Primary Raynaud\'s: no underlying disease — arteries overreact to cold (most common)','Secondary Raynaud\'s: associated with connective tissue disease (lupus, scleroderma), arterial disease, or certain medications'], homecare:['Dress warmly — especially hands and feet, hat and scarf','Wear mittens rather than gloves','Warm up car before driving in winter','Avoid cold-stored drinks directly from freezer','Avoid nicotine and caffeine — both constrict blood vessels','Manage stress','Chemical hand warmers during outdoor activities'], whenToSeeDoctor:'All cases of Raynaud\'s should be evaluated to rule out secondary causes (autoimmune disease). Severe attacks causing sores or ulcers need urgent specialist care.', urgency:'low' },

  { name:'Scleroderma', aliases:['scleroderma','systemic sclerosis','hardening of skin','connective tissue disease sclero'], emoji:'🏥', type:'chronic', description:'A rare group of autoimmune diseases characterized by hardening and tightening of the skin and connective tissues. Can affect internal organs including the lungs, heart, kidneys, and digestive tract.', symptoms:['Hardening and thickening of skin','Raynaud\'s phenomenon — fingers turning white or blue in cold','Sores on fingertips','Swollen fingers and hands','Tight shiny skin on face','Heartburn and digestive problems','Shortness of breath','Joint pain and stiffness'], causes:['Autoimmune — immune system triggers overproduction of collagen','Genetic factors and environmental exposures','Exact cause unknown'], homecare:['Moisturize skin daily to reduce tightness and cracking','Raynaud\'s management — warmth and layering','Elevate head of bed for heartburn/reflux','Physical and occupational therapy to maintain range of motion','Prescribed medications for each affected system','Avoid cold and emotional stress'], whenToSeeDoctor:'Scleroderma requires specialist rheumatologist management with regular monitoring of lung, heart, and kidney function. Annual pulmonary function tests and echocardiogram for lung/heart complications.', urgency:'high' },

  { name:'Sjögren\'s Syndrome', aliases:['sjogren\'s','sjogren syndrome','dry eyes dry mouth autoimmune','sicca syndrome'], emoji:'🏥', type:'chronic', description:'A systemic autoimmune disease where the immune system attacks moisture-producing glands, causing dryness of the eyes and mouth. Can affect other organs including joints, lungs, kidneys, and nervous system.', symptoms:['Dry eyes — gritty, burning sensation','Dry mouth — difficulty chewing, swallowing, or speaking','Dental decay from reduced saliva','Swollen salivary glands','Joint pain and swelling','Skin rash','Vaginal dryness','Fatigue','Peripheral neuropathy'], causes:['Autoimmune attack on exocrine glands (tear and salivary glands)','Can be primary (alone) or secondary (with RA, lupus, or scleroderma)','Genetic and hormonal factors — affects women predominantly'], homecare:['Preservative-free artificial tear drops throughout the day','Saliva substitutes or frequent water sips for dry mouth','Meticulous dental hygiene — dental decay accelerates without saliva','Sugar-free gum to stimulate saliva','Eye protection outdoors','Vaginal lubricants if needed','Hydroxychloroquine as prescribed for systemic symptoms'], whenToSeeDoctor:'Regular rheumatologist and ophthalmologist review. Annual check for lymphoma (slightly elevated risk with Sjögren\'s). Urgent care for significant kidney, lung, or nervous system symptoms.', urgency:'medium' },

  { name:'Vasculitis', aliases:['vasculitis','blood vessel inflammation','vascular inflammation','arteritis'], emoji:'🏥', type:'chronic', description:'A group of disorders involving inflammation of blood vessels, which can restrict blood flow and damage organs. Many types exist ranging from mild skin involvement to life-threatening internal organ damage.', symptoms:['Fever and fatigue','Weight loss','Headache','Muscle and joint pain','Skin rash or purpura (purple-red spots from bleeding under skin)','Numbness or weakness in limbs','Shortness of breath','Abdominal pain'], causes:['Autoimmune — immune system attacks blood vessels','Some infections trigger vasculitis (hepatitis B, C)','Certain medications','Specific types affect specific vessel sizes — giant cell arteritis affects large vessels; ANCA vasculitis affects small vessels'], homecare:['Take prescribed immunosuppressive medications (corticosteroids, cyclophosphamide) as directed','Report any new symptoms promptly','Avoid infections — vaccinations should be kept up to date (but live vaccines avoided on immunosuppressives)','Adequate rest during flares','Calcium and vitamin D with long-term steroids'], whenToSeeDoctor:'Vasculitis requires specialist rheumatologist or relevant organ specialist management. Any new or worsening symptoms need prompt evaluation. Regular blood and urine monitoring for organ involvement.', urgency:'high' },

  { name:'Myasthenia Gravis', aliases:['myasthenia gravis','mg','muscle weakness disease','neuromuscular disease','drooping eyelid weakness'], emoji:'🏥', type:'chronic', description:'A chronic autoimmune neuromuscular disease that causes weakness in the skeletal muscles, which are responsible for breathing and moving parts of the body. A myasthenic crisis affecting breathing is a medical emergency.', symptoms:['Drooping of one or both eyelids (ptosis)','Blurred or double vision','Slurred speech','Difficulty swallowing and chewing','Weakness in arms and legs','Fatigue with repetitive use of a muscle','Difficulty breathing (myasthenic crisis — emergency)'], causes:['Autoimmune — antibodies block acetylcholine receptors at the neuromuscular junction','Thymus gland abnormalities (thymoma or hyperplasia) play a role','Genetic susceptibility'], homecare:['Take prescribed acetylcholinesterase inhibitors (pyridostigmine) at exact prescribed times — timing is critical','Avoid triggers: physical overexertion, infections, heat, emotional stress, certain medications (aminoglycosides, quinolones, beta-blockers)','Plan activities for when medication is working (peak effect)','Rest between activities','Inform all doctors and dentists about condition before any medication is prescribed'], whenToSeeDoctor:'Regular neurology review every 3-6 months. Myasthenic crisis (sudden breathing difficulty) is a life-threatening emergency — call ambulance immediately. Any new medication should be checked for MG compatibility.', urgency:'high' },

  { name:'Guillain-Barré Syndrome', aliases:['guillain barre','gbs','ascending paralysis','acute inflammatory polyneuropathy','gbs syndrome'], emoji:'🏥', type:'chronic', description:'A rare but serious autoimmune disorder in which the immune system attacks the peripheral nervous system, causing rapidly ascending weakness and paralysis. Usually triggered by an infection. Most people recover fully but the process takes months to years.', symptoms:['Weakness or tingling starting in legs and spreading upward','Difficulty walking or climbing stairs','Difficulty with eye movements or facial movements','Difficulty swallowing or speaking','Severe pain (often described as achy or shooting)','Rapid heart rate and blood pressure fluctuations','In severe cases: paralysis and respiratory failure'], causes:['Autoimmune attack on peripheral nerves following a triggering infection','Most commonly triggered by Campylobacter jejuni gastroenteritis, influenza, or COVID-19','Rarely triggered by vaccinations'], homecare:['GBS requires hospital care — there is no home management in the acute phase','Recovery phase: intensive physiotherapy for muscle restrengthening','Occupational therapy to regain daily function','Pain management as prescribed','Psychological support — recovery is slow and can be frightening'], whenToSeeDoctor:'GBS is a medical emergency — go to hospital immediately if ascending weakness develops, especially if breathing is affected. Intravenous immunoglobulin (IVIG) or plasmapheresis must be started early.', urgency:'high' },

  { name:'Muscular Dystrophy', aliases:['muscular dystrophy','md','duchenne','becker','muscle wasting disease','genetic muscle disease'], emoji:'🏥', type:'chronic', description:'A group of inherited diseases characterized by progressive weakness and loss of muscle mass. Abnormal or absent genes interfere with the production of proteins needed to maintain healthy muscle. Duchenne muscular dystrophy is the most common severe type.', symptoms:['Progressive muscle weakness — usually beginning in childhood or adolescence','Frequent falls and difficulty running','Waddling gait','Walking on toes','Large calf muscles (pseudohypertrophy in Duchenne)','Learning disabilities in some types','Heart and respiratory problems in advanced stages'], causes:['Genetic mutations affecting dystrophin protein production','X-linked inheritance (Duchenne and Becker primarily affect males)','Different types caused by different gene mutations'], homecare:['Physiotherapy to maintain muscle function and prevent contractures','Range-of-motion exercises daily','Orthotic braces for support and mobility','Respiratory support as needed — physiotherapy, cough assist devices','Cardiac medications if cardiomyopathy develops','Psychological and social support for family'], whenToSeeDoctor:'Regular multidisciplinary team review — neurologist, cardiologist, pulmonologist, physiotherapist, and dietitian. Cardiac function must be monitored annually. Corticosteroids slow progression in Duchenne MD.', urgency:'high' },

  { name:'ALS', aliases:['als','amyotrophic lateral sclerosis','motor neurone disease','mnd','lou gehrig disease'], emoji:'🏥', type:'chronic', description:'Amyotrophic Lateral Sclerosis is a progressive neurodegenerative disease affecting motor neurons in the brain and spinal cord, leading to loss of voluntary muscle control. Eventually affects breathing and swallowing.', symptoms:['Muscle weakness and twitching (fasciculations)','Slurred speech (dysarthria)','Difficulty swallowing (dysphagia)','Muscle cramps and stiffness','Tripping and falling','Difficulty using hands and fingers','Shortness of breath','Emotional lability'], causes:['Mostly sporadic (no clear cause)','5-10% familial (genetic — SOD1, C9orf72 mutations)','Complex interplay of genetic and environmental factors'], homecare:['Multidisciplinary care team approach — neurologist, physiotherapist, speech therapist, dietitian, palliative care','Riluzole medication as prescribed — modestly slows progression','Respiratory support — NIV (BiPAP) for breathing assistance','Communication aids as speech deteriorates','Nutritional support — PEG tube when swallowing becomes hazardous','Psychological and family support'], whenToSeeDoctor:'ALS requires specialist neurologist management with regular multidisciplinary reviews every 2-3 months. Advance care planning for respiratory support should be discussed early while the patient can express wishes.', urgency:'high' },

  { name:'Huntington\'s Disease', aliases:['huntington\'s disease','huntington disease','hd','huntington chorea','inherited brain disease'], emoji:'🧠', type:'chronic', description:'A rare inherited disease that causes progressive breakdown of nerve cells in the brain. It has wide-ranging impact on a person\'s functional abilities producing movement, thinking, and psychiatric disorders.', symptoms:['Involuntary jerking or writhing movements (chorea)','Muscle rigidity or contracture','Slow or abnormal eye movements','Balance impairment and falls','Difficulty speaking and swallowing','Cognitive decline — difficulty organizing and concentrating','Psychiatric symptoms — depression, irritability, social withdrawal','Obsessive-compulsive behavior'], causes:['Mutation in the HTT gene — autosomal dominant inheritance','Each child of an affected parent has 50% chance of inheriting the disease','Symptoms typically develop between age 30-50'], homecare:['Physical therapy for movement and balance','Occupational therapy for daily function','Speech therapy for communication and swallowing','Psychiatric medications for mood and behavioral symptoms','High-calorie diet (increased caloric need due to constant movement)','Family caregiver support and respite care'], whenToSeeDoctor:'Genetic counseling before genetic testing is strongly recommended. Regular multidisciplinary neurology team review. Genetic testing of family members requires careful psychological preparation.', urgency:'high' },

  { name:'Cerebral Palsy', aliases:['cerebral palsy','cp','brain injury child','spastic cerebral palsy','motor disability child'], emoji:'🏥', type:'chronic', description:'A group of disorders affecting movement, muscle tone, or posture caused by damage to the developing brain, usually before birth. The most common childhood physical disability. Symptoms vary widely from mild to severe.', symptoms:['Variations in muscle tone — too stiff or too floppy','Spastic movements (jerky or stiff)','Involuntary movements or tremors','Lack of balance and coordination (ataxia)','Delays in motor developmental milestones','Favoring one side of the body','Difficulty with fine motor skills','Speech problems (dysarthria)','In some: intellectual disability, seizures, vision/hearing problems'], causes:['Brain damage or abnormal brain development before, during, or after birth','Premature birth','Infections during pregnancy (rubella, CMV)','Birth asphyxia (oxygen deprivation during delivery)','Severe jaundice in newborn','Traumatic brain injury in early childhood'], homecare:['Regular physiotherapy to maximize mobility and prevent contractures','Occupational therapy for daily living skills','Speech and language therapy','Orthotic devices and adaptive equipment','Medications for spasticity (baclofen, botulinum toxin injections)','Inclusive education and social participation'], whenToSeeDoctor:'Multidisciplinary team approach — pediatric neurologist, physiotherapist, occupational therapist, speech therapist. Regular reviews as the child grows. Seizures require neurologist management.', urgency:'medium' },

  /* ── CHRONIC: MENTAL / NEURODEVELOPMENTAL ── */
  { name:'Bipolar Disorder', aliases:['bipolar disorder','bipolar','manic depression','bipolar affective disorder','mood disorder bipolar','mania depression'], emoji:'🧠', type:'chronic', description:'A mental health condition causing extreme mood swings — including emotional highs (mania or hypomania) and lows (depression). The swings can affect sleep, energy, thinking, and behavior. Highly treatable with the right combination of medication and therapy.', symptoms:['Manic episodes: abnormally elevated mood, decreased need for sleep, racing thoughts, impulsive or risky behavior, grandiosity','Depressive episodes: sadness, hopelessness, loss of interest, fatigue, difficulty concentrating, suicidal thoughts','Hypomanic episodes (less severe mania)','Mixed episodes with features of both'], causes:['Genetic factors — strongly hereditary','Brain chemistry and structure differences','Stress and sleep disruption can trigger episodes','Substance use can precipitate episodes'], homecare:['Take mood stabilizers (lithium, valproate, lamotrigine) and prescribed medications consistently — stopping suddenly is dangerous','Maintain regular sleep schedule — sleep disruption is a major trigger','Mood diary to track mood patterns and identify early warning signs','Avoid alcohol and recreational drugs','Build a crisis plan with trusted people for when symptoms escalate'], whenToSeeDoctor:'Regular psychiatrist review every 3-6 months. Urgent care for suicidal thoughts, psychosis, or a manic episode with dangerous behavior. Never stop medication without medical guidance.', urgency:'high' },

  { name:'Schizophrenia', aliases:['schizophrenia','psychosis chronic','schizophrenic disorder','psychotic disorder','voices hearing schizophrenia'], emoji:'🧠', type:'chronic', description:'A serious mental disorder that affects how a person thinks, feels, and behaves. Characterized by episodes of psychosis. With proper treatment, many people with schizophrenia lead full, productive lives.', symptoms:['Hallucinations — hearing voices (most common), seeing or feeling things others do not','Delusions — false beliefs not based in reality','Disorganized thinking and speech','Disorganized or unusual behavior','Negative symptoms — reduced emotional expression, social withdrawal, reduced motivation','Cognitive difficulties — concentration and memory problems'], causes:['Complex interplay of genetic and environmental factors','Brain structure and chemistry differences','Dopamine dysregulation','Prenatal exposure to infections or malnutrition','Birth complications','Cannabis use especially in adolescence significantly increases risk'], homecare:['Take antipsychotic medications exactly as prescribed — stopping is the most common cause of relapse','Build a support routine — regular activities, social contact, adequate sleep','Avoid cannabis and recreational drugs — these cause relapses','Family involvement and education significantly improves outcomes','Supported employment and education rehabilitation'], whenToSeeDoctor:'Regular psychiatrist review monthly to 6-monthly depending on stability. Psychosis is a psychiatric emergency — contact a psychiatrist or go to a hospital if delusions or hallucinations significantly worsen or safety is a concern.', urgency:'high' },

  { name:'OCD', aliases:['ocd','obsessive compulsive disorder','obsessions compulsions','intrusive thoughts ocd','hand washing ocd'], emoji:'🧠', type:'chronic', description:'Obsessive-Compulsive Disorder is a mental health condition characterized by unwanted, repetitive thoughts (obsessions) and repetitive behaviors or mental acts (compulsions) performed to relieve anxiety. Highly treatable.', symptoms:['Obsessions: persistent, unwanted, intrusive thoughts, images, or urges','Fear of contamination or dirt','Fear of harming self or others','Need for symmetry or exactness','Religious or sexual intrusive thoughts','Compulsions: repetitive behaviors to reduce anxiety from obsessions','Excessive handwashing or cleaning','Checking and rechecking (locks, appliances)','Counting, repeating, or arranging','Significant time consumed (more than 1 hour daily) and distress'], causes:['Genetic factors — family history increases risk','Brain chemistry — serotonin dysregulation','Environmental stress or trauma can trigger onset','Streptococcal infection may trigger OCD in some children (PANDAS)'], homecare:['Exposure and Response Prevention (ERP) therapy — the gold standard treatment','Take prescribed SSRIs as directed — requires 8-12 weeks at adequate dose to work','Do not avoid obsessional triggers — avoidance maintains OCD','Do not perform compulsions — gradual response prevention reduces OCD over time','OCD support groups and family education are helpful'], whenToSeeDoctor:'OCD occupying more than 1 hour daily or significantly impairing function needs specialist psychiatric or psychologist assessment. CBT with ERP combined with SSRIs gives the best results.', urgency:'medium' },

  { name:'PTSD', aliases:['ptsd','post traumatic stress disorder','trauma disorder','flashbacks ptsd','combat stress','trauma ptsd'], emoji:'🧠', type:'chronic', description:'Post-Traumatic Stress Disorder develops in some people who have experienced a shocking, scary, or dangerous event. It causes lasting psychological distress with intrusive symptoms, avoidance, and hyperarousal.', symptoms:['Flashbacks — reliving the traumatic event through vivid, involuntary memories','Nightmares','Severe anxiety and emotional distress when reminded of the trauma','Avoidance of reminders of the trauma (places, people, thoughts)','Negative changes in thinking and mood','Hyperarousal — easily startled, always on guard, irritability, sleep problems','Emotional numbing and detachment'], causes:['Experiencing or witnessing a life-threatening event — combat, assault, accidents, natural disasters, childhood abuse','Not everyone who experiences trauma develops PTSD — resilience factors are important','Prior mental health conditions and lack of social support increase risk'], homecare:['Trauma-focused CBT (TF-CBT) and EMDR are the most effective psychological treatments','Take prescribed medications (SSRIs) as directed','Build a safety and support network — trusted people to talk to','Practice grounding techniques during flashbacks (5-4-3-2-1 senses exercise)','Avoid alcohol and drugs which worsen PTSD','Gradually face avoided situations with professional support'], whenToSeeDoctor:'Any PTSD symptoms significantly affecting daily life warrant specialist psychological assessment. Suicide risk in PTSD is significant — if experiencing suicidal thoughts, seek urgent help immediately.', urgency:'high' },

  { name:'Borderline Personality Disorder', aliases:['borderline personality disorder','bpd','emotionally unstable personality','borderline personality','bpd symptoms'], emoji:'🧠', type:'chronic', description:'A mental health disorder characterized by unstable relationships, self-image, and emotions, as well as impulsivity. Intense episodes of anger, depression, and anxiety lasting hours to days. Treatable with specialized therapy.', symptoms:['Intense fear of abandonment','Unstable, intense relationships (idealization and devaluation)','Unstable self-image or sense of self','Impulsive and self-destructive behaviors','Self-harm or suicidal behavior','Extreme mood swings','Chronic feelings of emptiness','Explosive anger','Dissociation under stress'], causes:['Combination of genetic and environmental factors','Childhood trauma — abuse, neglect, or separation from parents','Genetic predisposition to emotional reactivity','Brain differences in emotional regulation areas'], homecare:['DBT (Dialectical Behavior Therapy) is the most evidence-based treatment — skills training in mindfulness, distress tolerance, emotion regulation, and interpersonal effectiveness','Practice grounding techniques during emotional crises','Maintain a predictable routine','Avoid alcohol and substance use which intensify emotional dysregulation','Identify crisis support contacts in advance'], whenToSeeDoctor:'BPD requires specialist psychiatric and psychological assessment. Any self-harm or suicidal behavior needs urgent care. DBT therapist is the key treatment provider.', urgency:'high' },

  { name:'Anorexia Nervosa', aliases:['anorexia','anorexia nervosa','eating disorder starvation','not eating disorder','food restriction disorder'], emoji:'🏥', type:'chronic', description:'A serious and potentially life-threatening eating disorder characterized by an abnormally low body weight, intense fear of gaining weight, and a distorted perception of body weight. Has the highest mortality rate of any psychiatric disorder.', symptoms:['Severely restricted food intake','Extremely low body weight','Intense fear of gaining weight despite being underweight','Distorted body image — feeling fat despite being thin','Denial of the seriousness of low body weight','Excessive exercise','In women: absence of menstrual periods','Physical: hair loss, cold intolerance, fatigue, heart abnormalities'], causes:['Complex interplay of genetic, psychological, and sociocultural factors','Perfectionism and low self-esteem','Family history of eating disorders or anxiety','Cultural pressure around thinness','Dieting often precedes onset'], homecare:['Professional treatment is essential — home management alone is insufficient and dangerous','Support the affected person without commenting on food, weight, or appearance','Provide a non-judgmental, warm environment','Medical monitoring for cardiac arrhythmias and electrolyte imbalances','Recovery takes time — focus on emotional wellbeing not just weight'], whenToSeeDoctor:'Any suspected anorexia needs urgent medical and psychiatric assessment. Severe restriction, fainting, cardiac symptoms, or electrolyte abnormalities require hospital admission. A multidisciplinary team (psychiatrist, physician, dietitian, therapist) is essential.', urgency:'high' },

  { name:'Bulimia Nervosa', aliases:['bulimia','bulimia nervosa','binge purge disorder','vomiting eating disorder','bulimia symptoms'], emoji:'🏥', type:'chronic', description:'A serious eating disorder marked by a cycle of binge eating followed by behaviors to undo the effects — purging by vomiting, misusing laxatives, fasting, or excessive exercise. Often kept secret and not obvious by appearance.', symptoms:['Recurrent episodes of eating abnormally large amounts in a short time (bingeing)','Feeling a lack of control during binge episodes','Purging behaviors: self-induced vomiting, laxative misuse, excessive exercise, fasting','Fear of gaining weight','Distorted body image','Physical: swollen cheeks (parotid glands), dental erosion, calluses on knuckles (Russell\'s sign), electrolyte imbalances','Mood instability'], causes:['Genetic predisposition','Psychological factors — low self-esteem, perfectionism, depression, anxiety','Sociocultural pressures around body image','History of dieting or food restriction'], homecare:['Specialist treatment is required — do not attempt to manage alone','CBT for eating disorders is the most evidence-based treatment','Family-based treatment for adolescents','Antidepressants (fluoxetine) reduce binge-purge frequency','Remove opportunity for purging where possible — supportive not punitive approach','Regular structured meals to reduce binge urges'], whenToSeeDoctor:'Suspected bulimia needs assessment by a physician and specialist eating disorder team. Electrolyte imbalances from purging can cause fatal cardiac arrhythmias — medical monitoring is essential.', urgency:'high' },

  { name:'Binge Eating Disorder', aliases:['binge eating disorder','bed','binge eating','compulsive eating','overeating disorder'], emoji:'🏥', type:'chronic', description:'The most common eating disorder in adults. Characterized by recurring episodes of eating large quantities of food, often very quickly and to the point of discomfort, without compensatory purging behaviors.', symptoms:['Recurring episodes of eating unusually large amounts rapidly','Eating when not physically hungry','Eating until uncomfortably full','Eating alone due to shame about the amount eaten','Feeling disgusted, depressed, or guilty after overeating','Significant distress about binge eating','No regular compensatory behaviors (unlike bulimia)'], causes:['Genetic factors','Psychological — depression, anxiety, trauma, low self-esteem','Dieting and food restriction paradoxically increase binge risk','Certain brain chemistry differences affect appetite regulation'], homecare:['CBT for binge eating is highly effective','Regular structured meals — skipping meals increases binge risk','Identify emotional triggers for binge eating','Mindful eating practices','Remove binge foods from home while in recovery','Address underlying depression or anxiety simultaneously'], whenToSeeDoctor:'Binge eating disorder requires specialist eating disorder assessment. CBT with a psychologist or therapist is the primary treatment. Medication (lisdexamfetamine, antidepressants) may be helpful in some cases.', urgency:'medium' },

  { name:'Alcohol Dependency', aliases:['alcohol dependency','alcoholism','alcohol use disorder','alcohol addiction','aud','alcohol dependence'], emoji:'🍺', type:'chronic', description:'A chronic disease characterized by an inability to control or stop alcohol use despite negative social, occupational, or health consequences. Involves both physical dependence (withdrawal symptoms) and psychological craving.', symptoms:['Strong craving for alcohol','Inability to limit drinking despite trying','Needing to drink more to get the same effect (tolerance)','Withdrawal symptoms when not drinking — tremors, sweating, anxiety, seizures','Continuing to drink despite health, relationship, or work problems','Spending excessive time obtaining, drinking, or recovering from alcohol','Neglecting activities and responsibilities'], causes:['Genetic predisposition (40-60% heritable)','Psychological factors — depression, anxiety, trauma','Social and environmental factors','Chronic stress','Early onset of alcohol use'], homecare:['Do not attempt to stop suddenly without medical supervision — alcohol withdrawal can be life-threatening (seizures)','Medical detoxification under supervision is essential for dependent drinkers','Attend AA meetings or SMART Recovery groups','CBT and motivational interviewing are effective therapies','Prescribed medications (naltrexone, acamprosate, disulfiram) reduce craving and relapse'], whenToSeeDoctor:'Any significant alcohol dependence needs medical assessment before stopping. Specialist addiction services provide comprehensive treatment. Alcohol withdrawal with seizures or severe confusion (delirium tremens) is a medical emergency.', urgency:'high' },

  { name:'Drug Dependency', aliases:['drug dependency','drug addiction','substance use disorder','narcotics addiction','drug abuse','opioid dependency'], emoji:'💊', type:'chronic', description:'A chronic, relapsing disorder characterized by compulsive drug seeking and use despite harmful consequences. Changes in brain structure and function produce strong cravings and impaired control. Recovery is possible with the right treatment.', symptoms:['Intense urge or craving for the substance','Loss of control over drug use','Continuing use despite obvious harm to health, relationships, and work','Tolerance — needing more to achieve the same effect','Withdrawal symptoms without the drug','Neglecting responsibilities and activities','Spending most time obtaining, using, or recovering from the drug'], causes:['Brain changes in reward pathways','Genetic vulnerability','Mental health disorders (self-medication)','Environmental factors — peer influence, stress, trauma','Early exposure to drugs'], homecare:['Seek medical help before stopping — abrupt withdrawal from some substances is dangerous','Opioid substitution therapy (methadone, buprenorphine) for opioid dependency — highly effective','Attend structured rehabilitation program','CBT and relapse prevention therapy','Build a sober support network — NA meetings or other peer support','Address underlying mental health conditions'], whenToSeeDoctor:'Any significant drug dependency needs specialist addiction medicine assessment. Opioid overdose (unresponsive, slow breathing) is a medical emergency — naloxone reverses it. Do not hesitate to seek medical help.', urgency:'high' },

  { name:'Nicotine Dependency', aliases:['nicotine dependency','nicotine addiction','smoking addiction','tobacco addiction','cigarette addiction','smoking cessation'], emoji:'🚬', type:'chronic', description:'A strong physical and psychological addiction to nicotine found in tobacco products. Smoking is the leading preventable cause of death. Quitting is the single most beneficial health improvement a smoker can make.', symptoms:['Craving to smoke especially after waking, meals, or in stressful situations','Inability to stop smoking despite wanting to','Withdrawal symptoms without cigarettes — irritability, anxiety, difficulty concentrating, increased appetite','Continuing to smoke despite diagnosed health problems','Needing to smoke within 30 minutes of waking (sign of strong dependence)'], causes:['Nicotine activates brain reward pathways causing dopamine release','Rapid onset and offset of nicotine creates frequent craving cycles','Psychological associations — stress, meals, social situations','Genetic factors influence addiction susceptibility'], homecare:['Nicotine Replacement Therapy (NRT) — patches, gum, lozenges, inhaler — doubles quit success rate','Set a definite quit date','Identify and plan for triggers','Inform family and friends for support','Remove all cigarettes and smoking paraphernalia from the home','Stay physically active to manage withdrawal','Use NRT consistently — most people use too low a dose'], whenToSeeDoctor:'See a doctor for prescription cessation medications (varenicline/Champix or bupropion) which significantly improve quit rates. Combination of medication and behavioral support gives the highest success rates.', urgency:'medium' },

  { name:'Chronic Pain Syndrome', aliases:['chronic pain','chronic pain syndrome','persistent pain','long term pain','chronic widespread pain'], emoji:'🦴', type:'chronic', description:'Pain that persists for more than 3 months beyond the expected healing time of an injury or illness. Can become self-sustaining even when the original cause is treated. Significantly affects quality of life and mental health.', symptoms:['Persistent pain lasting more than 3 months','Pain may be burning, shooting, stabbing, or aching','May be constant or intermittent','Fatigue and sleep disturbances','Depression and anxiety (very commonly co-exist)','Reduced physical function and activity avoidance','Cognitive difficulties (pain-related brain fog)'], causes:['Central sensitization — the nervous system amplifies pain signals','Nerve damage from injury or disease','Failed back surgery','Fibromyalgia','Complex regional pain syndrome (CRPS)','Psychological factors amplify and maintain pain'], homecare:['Pacing — carefully manage activity to avoid boom-bust cycles','Regular gentle movement — exercise reduces central sensitization over time (start very slowly)','Pain psychology approaches — acceptance-based therapy, CBT for pain is very effective','Heat, cold, TENS for local pain relief','Mindfulness and meditation','Address sleep problems — poor sleep amplifies pain'], whenToSeeDoctor:'Chronic pain requires a multidisciplinary pain management approach — pain specialist, physiotherapist, psychologist, and occupational therapist. Do not solely rely on opioid medication — it is poorly effective for chronic non-cancer pain and worsens outcomes.', urgency:'medium' },

  /* ── CHRONIC: REPRODUCTIVE ── */
  { name:'Endometriosis', aliases:['endometriosis','endo','endometriosis pain','endometriosis symptoms','period pain endometriosis'], emoji:'🌸', type:'chronic', description:'A condition where tissue similar to the uterine lining grows outside the uterus — on ovaries, fallopian tubes, or other pelvic organs. Causes significant pain, especially during menstruation, and can affect fertility. Affects 1 in 10 women.', symptoms:['Severe menstrual cramps — much worse than typical period pain','Chronic pelvic pain extending beyond menstrual periods','Pain with intercourse','Pain during bowel movements or urination during periods','Excessive bleeding — heavy periods or bleeding between periods','Infertility','Fatigue, especially during periods'], causes:['Exact cause unknown — several theories including retrograde menstruation, immune dysfunction','Genetic predisposition — family history increases risk','Estrogen dependence — endometriosis grows under estrogen stimulation'], homecare:['NSAIDs (ibuprofen) taken 1-2 days before period onset for pain management','Heat therapy — heating pad on pelvis and lower back','Hormonal treatments (prescribed) suppress endometriosis growth','Gentle exercise such as yoga and swimming','Track symptoms to monitor pattern and response to treatment','Join an endometriosis support group — lived experience support is invaluable'], whenToSeeDoctor:'Suspected endometriosis needs gynecologist evaluation. Diagnosis typically requires laparoscopy. Seek specialist care if fertility is affected or if quality of life is significantly impaired. Pain should not be dismissed as "normal period pain."', urgency:'medium' },

  { name:'Uterine Fibroids', aliases:['uterine fibroids','fibroids','uterine myoma','fibroid uterus','womb fibroids'], emoji:'🌸', type:'chronic', description:'Noncancerous growths of the uterus that often appear during childbearing years. They are almost never cancerous. Many women have fibroids without symptoms. They can cause heavy periods, pelvic pain, and fertility issues.', symptoms:['Heavy menstrual bleeding','Menstrual periods lasting more than a week','Pelvic pressure or pain','Frequent urination','Difficulty emptying the bladder','Constipation','Backache or leg pain','In some: enlarged abdomen'], causes:['Estrogen and progesterone stimulate fibroid growth','Genetic factors — fibroids run in families','African-American women have higher risk and more severe fibroids','Obesity increases estrogen levels promoting growth'], homecare:['NSAIDs and hormonal medications (prescribed) to reduce heavy bleeding and pain','Iron supplements if heavy periods cause anemia','Monitor with ultrasound for changes in size','Maintain a healthy weight — excess estrogen from fat tissue promotes growth','Heat for pelvic pain relief'], whenToSeeDoctor:'Heavy bleeding affecting quality of life or causing anemia, significant pelvic pain, urinary symptoms, or infertility — gynecologist evaluation needed. Many treatment options exist from medication to minimally invasive procedures to surgery.', urgency:'medium' },

  /* ── CHRONIC: GENETIC & BLOOD DISORDERS ── */
  { name:'Polycystic Kidney Disease', aliases:['polycystic kidney disease','pkd','kidney cysts','pkd genetic','autosomal dominant pkd'], emoji:'🫘', type:'chronic', description:'An inherited disorder in which clusters of cysts develop primarily within the kidneys, causing the kidneys to enlarge and lose function over time. The most common life-threatening genetic disease, affecting 1 in 500-1000 people.', symptoms:['High blood pressure (often early sign)','Back or side pain from enlarged kidneys','Headache','Blood in urine','Urinary tract infections','Kidney stones','In advanced disease: kidney failure symptoms'], causes:['Autosomal dominant PKD (ADPKD) — one copy of mutated gene from one parent is sufficient','Autosomal recessive PKD (ARPKD) — rare, both copies mutated, severe in childhood','PKD1 or PKD2 gene mutations'], homecare:['Strictly control blood pressure (ACE inhibitors or ARBs are preferred)','Stay well hydrated — 3 liters per day to slow cyst growth','Low-sodium diet to help control blood pressure','Avoid tobacco and excessive caffeine','Tolvaptan medication (if prescribed) slows cyst growth and kidney function decline','Treat UTIs promptly — prevent them from reaching kidneys'], whenToSeeDoctor:'Regular 6-monthly nephrology review. Monitor blood pressure, kidney function (eGFR), and cyst volume with annual MRI or ultrasound. Genetic counseling for family members.', urgency:'high' },

  { name:'Hemophilia', aliases:['hemophilia','haemophilia','clotting disorder','bleeding disorder','hemophilia a','hemophilia b'], emoji:'🩸', type:'chronic', description:'A rare inherited bleeding disorder in which the blood does not clot properly. People with hemophilia bleed longer than normal after injury. Internal bleeding, especially in joints and muscles, is the main concern.', symptoms:['Unexplained and excessive bleeding from cuts or injuries','Prolonged bleeding after surgery, dental work, or injury','Easy bruising','Pain, swelling, and tightness in joints from internal bleeding','Blood in urine or stool','Bleeding after vaccinations','In severe hemophilia: spontaneous joint bleeding without obvious injury'], causes:['X-linked genetic condition — primarily affects males','Hemophilia A: deficiency in clotting Factor VIII (most common)','Hemophilia B (Christmas disease): deficiency in clotting Factor IX','Female carriers rarely have significant symptoms'], homecare:['Carry medical ID at all times identifying hemophilia type and severity','Inform all healthcare providers including dentist before any procedure','Apply firm pressure and ice to external cuts','Avoid aspirin and NSAIDs — use paracetamol only for pain','Protect joints — wear protective gear during sports','Low-impact exercise (swimming) to strengthen muscles that protect joints'], whenToSeeDoctor:'Joint bleeds require prompt treatment with factor replacement — do not wait. Any head injury, significant fall, or spontaneous bleeding needs immediate medical attention. Regular hematologist review every 6-12 months.', urgency:'high' },

  { name:'Sickle Cell Disease', aliases:['sickle cell disease','sickle cell','scd','sickle cell anemia','haemoglobin ss','sickle cell pain'], emoji:'🩸', type:'chronic', description:'An inherited blood disorder where red blood cells are misshapen (sickle or crescent shaped) causing them to break down prematurely and block blood flow in small vessels, causing pain crises and organ damage.', symptoms:['Pain crises — sudden severe pain in chest, abdomen, joints, or bones','Anemia — fatigue, pallor, jaundice','Frequent infections','Swelling of hands and feet (dactylitis) in infants','Delayed growth','Vision problems','Stroke (particularly in children)','Acute chest syndrome — chest pain, fever, breathing difficulty (emergency)'], causes:['Inherited mutation in hemoglobin gene — autosomal recessive','Both parents must carry the sickle cell trait for the child to have the disease','More common in people of African, Mediterranean, Middle Eastern, and Indian ancestry'], homecare:['Stay well hydrated — dehydration is a major trigger for pain crises','Avoid extreme temperatures, high altitudes, and strenuous exertion','Take daily folic acid and prescribed penicillin prophylaxis (in children)','Hydroxyurea medication as prescribed — reduces frequency and severity of crises','Recognize early signs of crisis and seek treatment promptly','Annual transcranial Doppler ultrasound for children to assess stroke risk'], whenToSeeDoctor:'Regular hematologist review every 3-6 months. Acute chest syndrome, stroke symptoms, high fever, priapism (painful persistent erection), or severe pain crisis — go to emergency immediately. These are life-threatening complications.', urgency:'high' },

  { name:'Thalassemia', aliases:['thalassemia','thalassaemia','thalassemia major','thalassemia minor','beta thalassemia','hemoglobin disorder'], emoji:'🩸', type:'chronic', description:'An inherited blood disorder in which the body makes an abnormal or insufficient amount of hemoglobin, leading to excessive destruction of red blood cells and anemia. Ranges from mild (thalassemia minor — often asymptomatic) to severe (thalassemia major — transfusion dependent).', symptoms:['Thalassemia minor: usually mild or no anemia — mild fatigue','Thalassemia major: severe anemia requiring regular transfusions','Pale or yellowish skin','Facial bone deformities from expanded bone marrow','Slow growth in children','Abdominal swelling from enlarged spleen and liver','Dark urine','Fatigue and weakness'], causes:['Mutations in alpha-globin or beta-globin genes','Autosomal recessive — both parents must carry the mutation for severe disease','Common in Mediterranean, Middle Eastern, African, and South and Southeast Asian populations'], homecare:['Thalassemia minor: may not need treatment — iron supplementation only if iron-deficient (avoid iron overload)','Thalassemia major: regular blood transfusions every 3-4 weeks','Iron chelation therapy essential to prevent iron overload from transfusions','Folic acid supplements','Annual cardiac, liver, and endocrine monitoring for iron overload complications','Bone marrow transplant — the only cure — discuss eligibility with hematologist'], whenToSeeDoctor:'Regular hematologist review every 3-6 months. Genetic counseling and thalassemia screening for couples planning pregnancy in high-prevalence regions.', urgency:'high' },

  { name:'Type 1 Diabetes', aliases:['type 1 diabetes','t1dm','type 1 diabetes mellitus','insulin dependent diabetes','juvenile diabetes','autoimmune diabetes'], emoji:'🩸', type:'chronic', description:'An autoimmune disease where the immune system destroys insulin-producing beta cells in the pancreas, leaving the body unable to produce insulin. Requires lifelong insulin therapy. Onset commonly in childhood or young adulthood.', symptoms:['Excessive thirst and frequent urination','Extreme hunger despite eating','Unintentional rapid weight loss','Fatigue and weakness','Blurred vision','Slow-healing sores','Frequent infections','Mood changes','In severe undiagnosed cases: diabetic ketoacidosis (DKA) — vomiting, abdominal pain, fruity breath, confusion'], causes:['Autoimmune destruction of pancreatic beta cells','Genetic predisposition combined with environmental triggers (viral infections)','Distinct from Type 2 diabetes — not caused by lifestyle factors'], homecare:['Multiple daily insulin injections or insulin pump therapy — the cornerstone of Type 1 management','Continuous glucose monitoring (CGM) for real-time blood sugar readings','Carbohydrate counting for insulin dose calculation','Regular blood glucose monitoring before meals and activities','Carry fast-acting glucose (glucose tablets, juice) for hypoglycemia at all times','Medical ID bracelet identifying as insulin-dependent diabetic'], whenToSeeDoctor:'Regular endocrinologist review every 3 months. Annual screening for complications — retinopathy, nephropathy, neuropathy, and foot health. Suspected DKA (vomiting, confusion, fruity breath, high glucose) is a medical emergency — go to hospital immediately.', urgency:'high' },

  /* ── CHRONIC: CANCER ── */
  { name:'Colorectal Cancer', aliases:['colorectal cancer','colon cancer','bowel cancer','rectal cancer','large bowel cancer'], emoji:'🏥', type:'chronic', description:'Cancer of the colon or rectum (large intestine). The third most common cancer worldwide. Highly treatable when detected early — regular screening can catch precancerous polyps before they become cancer.', symptoms:['Change in bowel habits — diarrhea, constipation, or narrowing of stool lasting weeks','Blood in stool (bright red or dark maroon)','Abdominal cramping or pain','Unexplained weight loss','Fatigue and weakness','Feeling that bowel does not empty completely','Iron deficiency anemia without obvious cause'], causes:['Age — risk increases significantly after 50','Family history of colorectal cancer or polyps','Personal history of colon polyps or inflammatory bowel disease','Low-fiber, high-fat diet','Obesity and sedentary lifestyle','Smoking and heavy alcohol use','Type 2 diabetes'], homecare:['Follow all prescribed treatment protocols — surgery, chemotherapy, radiation as recommended','High-fiber, low-red-meat diet during and after treatment','Stay physically active as tolerated','Maintain follow-up colonoscopy schedule','Family members should be screened earlier (from age 40 or 10 years before the affected family member\'s diagnosis)'], whenToSeeDoctor:'Any unexplained change in bowel habits lasting more than 4 weeks, blood in stool, or unexplained weight loss needs urgent evaluation. Colonoscopy is the gold standard diagnostic test. Screening colonoscopy from age 45-50 is recommended for average-risk individuals.', urgency:'high' },

  { name:'Breast Cancer', aliases:['breast cancer','breast tumor','breast malignancy','breast lump cancer','mammary cancer'], emoji:'🌸', type:'chronic', description:'The most common cancer in women globally, though it also affects men. Survival rates have improved dramatically with early detection and advances in treatment. Monthly self-examination and regular mammograms are essential.', symptoms:['New lump in the breast or armpit','Change in size, shape, or appearance of a breast','Dimpling, puckering, or pitting of breast skin','Redness or orange-peel texture of breast skin','Nipple inversion or change in position','Nipple discharge other than breast milk','Peeling or flaking of nipple skin','Breast pain (less commonly)'], causes:['Female sex and increasing age (most significant risk factors)','Family history of breast cancer (BRCA1, BRCA2 gene mutations)','Dense breast tissue','Previous radiation to chest','Obesity after menopause','Alcohol consumption','Hormone replacement therapy'], homecare:['Attend all scheduled mammograms and follow-up appointments','Perform monthly breast self-examination to detect changes early','Maintain a healthy weight and exercise regularly','Limit alcohol','Take prescribed hormonal therapies (tamoxifen, aromatase inhibitors) consistently — they significantly reduce recurrence risk','Genetic counseling for family members if BRCA mutation identified'], whenToSeeDoctor:'Any new breast lump or breast change should be evaluated within 2 weeks. Annual mammogram from age 40-50 depending on risk level. BRCA testing for those with strong family history.', urgency:'high' },

  { name:'Lung Cancer', aliases:['lung cancer','lung malignancy','lung tumor','bronchogenic carcinoma','nsclc','sclc'], emoji:'💨', type:'chronic', description:'The leading cause of cancer death worldwide. Most cases are directly caused by smoking. Outcomes are significantly better when detected at an early stage.', symptoms:['Persistent cough that does not go away or worsens','Coughing up blood (haemoptysis)','Shortness of breath','Chest pain','Hoarseness','Unexplained weight loss','Fatigue','Recurrent respiratory infections like bronchitis or pneumonia','Bone pain if spread to bones'], causes:['Cigarette smoking (85-90% of cases)','Secondhand smoke exposure','Radon gas exposure','Asbestos or other carcinogens','Air pollution','Family history or previous lung disease'], homecare:['Attend all chemotherapy, radiation, immunotherapy, or targeted therapy sessions as scheduled','Quit smoking immediately — even after diagnosis it improves treatment outcomes and survival','Pulmonary rehabilitation for breathlessness','Adequate nutrition — cancer and treatment can cause significant weight loss','Palliative care for symptom management — essential alongside curative treatment','Low-dose CT screening for high-risk smokers aged 50-80'], whenToSeeDoctor:'Any persistent unexplained cough (over 3 weeks), blood in sputum, unexplained weight loss, or hoarseness needs urgent evaluation. High-risk smokers should discuss annual low-dose CT screening.', urgency:'high' },

  { name:'Prostate Cancer', aliases:['prostate cancer','prostate malignancy','prostate tumor','psa cancer'], emoji:'🩺', type:'chronic', description:'The most common cancer in men after skin cancer. Grows slowly in most cases and may not cause problems for years. Highly treatable when detected early. PSA screening is controversial but beneficial in high-risk men.', symptoms:['Often no symptoms in early stages','Urinary symptoms (similar to BPH): frequent urination, weak stream, difficulty starting','Blood in urine or semen','Erectile dysfunction','Pelvic discomfort','Bone pain if cancer has spread (usually to spine, hips, or ribs) — indicates advanced disease'], causes:['Age — rare before 50, common after 65','Family history of prostate cancer','African descent — higher risk and more aggressive disease','Obesity','High-fat diet'], homecare:['Active surveillance for low-risk disease — regular PSA and biopsy monitoring without immediate treatment','Take prescribed hormonal therapy (androgen deprivation therapy) as directed if needed','Maintain a healthy weight and exercise regularly','Discuss and choose treatment options carefully with a urologist and oncologist — watchful waiting vs active treatment'], whenToSeeDoctor:'Annual PSA test discussion with doctor from age 50 (or 40-45 with family history or African descent). Any urinary symptoms or bone pain in men over 50 needs evaluation.', urgency:'high' },

  { name:'Cervical Cancer', aliases:['cervical cancer','cervix cancer','hpv cancer cervix','cervical malignancy'], emoji:'🌸', type:'chronic', description:'Cancer of the cervix (lower part of the uterus). Almost all cases are caused by the human papillomavirus (HPV). Largely preventable through HPV vaccination and regular Pap smears.', symptoms:['Early stage: often no symptoms','Vaginal bleeding after intercourse, between periods, or after menopause','Watery, bloody vaginal discharge that may smell','Pelvic pain during intercourse','Pain in the pelvic area','Advanced: leg swelling, back pain, difficulty urinating'], causes:['Human papillomavirus (HPV) infection — almost all cases (HPV 16 and 18 most common)','Multiple sexual partners','Smoking','Weakened immune system (HIV)','Long-term oral contraceptive use','Family history'], homecare:['Attend all scheduled chemotherapy, radiation, and surgery appointments as recommended','HPV vaccination of daughters and eligible family members','Follow up with regular Pap smears and HPV tests after treatment','Pelvic floor exercises after surgery or radiation','Vaginal dilator use after radiation if advised by oncologist'], whenToSeeDoctor:'Attend regular Pap smear and HPV test screening (every 3-5 years from age 21-25 depending on local guidelines). Any abnormal vaginal bleeding or pelvic pain should be evaluated promptly.', urgency:'high' },

  { name:'Ovarian Cancer', aliases:['ovarian cancer','ovarian malignancy','ovarian tumor','silent cancer'], emoji:'🌸', type:'chronic', description:'Cancer that begins in the ovaries. Often called the "silent killer" because symptoms are vague and often attributed to other causes. Most cases are diagnosed at an advanced stage — making early detection awareness critical.', symptoms:['Bloating and abdominal distension','Pelvic or abdominal pain','Difficulty eating or feeling full quickly','Urinary urgency or frequency','Unexplained weight loss or gain','Fatigue','Back pain','Changes in bowel habits','These symptoms are common but persistent and unexplained ones warrant evaluation'], causes:['Increasing age','Family history of ovarian, breast, or colorectal cancer','BRCA1 or BRCA2 gene mutations','Lynch syndrome','Never having been pregnant','Hormone replacement therapy'], homecare:['Attend all chemotherapy and surgery follow-up appointments','Genetic counseling for family members if BRCA mutation confirmed','CA-125 monitoring as directed by oncologist','Nutritional support during treatment — dietitian is important'], whenToSeeDoctor:'Persistent bloating, pelvic pain, or urinary symptoms lasting more than 2-3 weeks should be evaluated. Any woman with BRCA1/2 should discuss risk-reducing salpingo-oophorectomy with a gynecologist. There is currently no reliable population screening test.', urgency:'high' },

  { name:'Skin Cancer', aliases:['skin cancer','basal cell carcinoma','squamous cell carcinoma','skin malignancy','non melanoma skin cancer'], emoji:'🔴', type:'chronic', description:'The most common form of cancer globally. Basal cell and squamous cell carcinomas are common and rarely spread. Melanoma is less common but far more dangerous. Excessive UV exposure is the primary cause.', symptoms:['Basal cell carcinoma: pearly or waxy bump, flat flesh-colored or brown scar-like lesion, bleeding or scabbing sore that heals and returns','Squamous cell carcinoma: firm red nodule, flat lesion with scaly surface, new sore on old scar','Any new skin growth or change in an existing mole or spot'], causes:['Ultraviolet (UV) radiation from sun or tanning beds','Fair skin, light hair, and light eyes — less melanin protection','History of sunburns','Weakened immune system','Certain chemicals (arsenic)','Family history of skin cancer'], homecare:['Daily sunscreen SPF 30+ on all exposed skin even on cloudy days','Wear protective clothing, wide-brimmed hats, and UV-protective sunglasses','Avoid sun exposure between 10am-4pm','Never use tanning beds','Monthly skin self-examination for new or changing spots','Annual full-body skin examination by a dermatologist especially if fair-skinned or high-risk'], whenToSeeDoctor:'Any new skin growth, changing mole (ABCDE: Asymmetry, Border irregularity, Color variation, Diameter >6mm, Evolution/change), non-healing sore, or suspicious skin lesion needs prompt dermatologist evaluation.', urgency:'high' },

  { name:'Melanoma', aliases:['melanoma','malignant melanoma','skin melanoma','dangerous mole','melanoma cancer'], emoji:'🔴', type:'chronic', description:'The most dangerous type of skin cancer, arising from pigment-producing cells (melanocytes). Can spread rapidly to other parts of the body. Survival rates are dramatically higher with early detection.', symptoms:['A mole that changes in size, shape, or color','A lesion with irregular, ragged, or blurred border','A lesion with multiple colors — brown, black, red, white, or blue','A lesion larger than 6mm (pencil eraser)','An evolving mole that looks different from surrounding moles (ugly duckling sign)','Itching, bleeding, or crusting of a mole'], causes:['Excessive UV radiation from sun or tanning beds','Many moles (>50)','History of severe sunburns especially in childhood','Fair skin, freckles, and light hair','Family or personal history of melanoma','Weakened immune system'], homecare:['Monthly skin self-examination using a full-length mirror and hand mirror','ABCDE rule for monitoring moles','Strict sun protection — daily SPF 50+, protective clothing','Annual dermatologist skin check','Take prescribed immunotherapy or targeted therapy as directed'], whenToSeeDoctor:'Any changing mole or suspicious lesion should be seen by a dermatologist within 2 weeks. Melanoma diagnosed and treated at an early stage has a 5-year survival rate above 98%. Do not delay.', urgency:'high' },

  { name:'Leukemia', aliases:['leukemia','leukaemia','blood cancer','acute leukemia','chronic leukemia','white blood cell cancer'], emoji:'🩸', type:'chronic', description:'Cancer of the blood-forming tissues including bone marrow and lymphatic system. Many types exist — acute forms progress rapidly; chronic forms more slowly. Treatment has improved dramatically in recent decades.', symptoms:['Fatigue and weakness','Frequent or severe infections','Fever or chills','Unexplained weight loss','Swollen lymph nodes (painless)','Enlarged spleen or liver (left-side abdominal discomfort)','Easy bleeding or bruising','Frequent nosebleeds','Bone pain or tenderness','Night sweats','Petechiae — tiny red spots on skin'], causes:['Genetic mutations in blood cells causing abnormal growth','Previous cancer treatment (radiation or chemotherapy)','Genetic disorders (Down syndrome increases risk)','Exposure to certain chemicals (benzene)','Smoking','Family history'], homecare:['Attend all chemotherapy, targeted therapy, radiation, or bone marrow transplant appointments','Infection prevention — meticulous hand hygiene, avoid sick contacts (chemotherapy causes immune suppression)','Monitor and report fever above 38°C immediately (febrile neutropenia is an emergency)','Adequate nutrition to support recovery','Psychological support and peer support groups'], whenToSeeDoctor:'Unexplained fatigue, frequent infections, easy bruising, swollen lymph nodes, or unexplained weight loss needs urgent blood count evaluation. Febrile neutropenia during treatment is a medical emergency.', urgency:'high' },

  { name:'Lymphoma', aliases:['lymphoma','hodgkin lymphoma','non hodgkin lymphoma','lymph node cancer','lymphatic cancer'], emoji:'🩸', type:'chronic', description:'Cancer that begins in cells of the lymphatic system. Two main types: Hodgkin\'s lymphoma (more common in young adults, highly curable) and Non-Hodgkin\'s lymphoma (more diverse, varies widely in behavior and treatment).', symptoms:['Painless swelling of lymph nodes — neck, armpits, or groin','Fatigue','Fever (particularly night sweats and fever — B symptoms)','Unexplained weight loss','Itching all over the body','Shortness of breath or cough (if chest lymph nodes enlarged)','Abdominal pain or swelling'], causes:['Abnormal lymphocyte growth due to genetic mutations','Weakened immune system (HIV, immunosuppressive medications)','Certain infections (Epstein-Barr virus, H. pylori)','Age and sex — varies by type','Exposure to certain chemicals'], homecare:['Attend all chemotherapy, radiation, or immunotherapy sessions','Prevent infections during treatment — hand hygiene, food safety','Maintain nutrition during treatment — dietitian support','Report fever promptly — immunocompromised patients are at high risk','Psychological support and lymphoma support groups are valuable'], whenToSeeDoctor:'Persistent painless lymph node swelling (more than 2-4 weeks), night sweats, unexplained weight loss, and fatigue warrant urgent evaluation with blood tests and possible lymph node biopsy.', urgency:'high' },

  { name:'Brain Tumor', aliases:['brain tumor','brain tumour','brain cancer','cerebral tumor','glioma','meningioma'], emoji:'🧠', type:'chronic', description:'An abnormal growth of cells in the brain. Can be primary (originating in the brain) or secondary (spread from cancer elsewhere). Ranges from benign (meningioma) to highly malignant (glioblastoma). Symptoms depend on location and size.', symptoms:['Headaches — often worse in the morning or waking from sleep','Seizures (new onset in an adult)','Nausea and vomiting especially in the morning','Vision, hearing, or speech problems','Personality or behavior changes','Balance and coordination problems','Memory problems or cognitive changes','Weakness or numbness on one side'], causes:['Primary brain tumors: cause often unknown — some genetic factors','Secondary (metastatic): cancer spreading from lung, breast, colon, kidney, or melanoma','Radiation exposure to the head','Certain rare genetic syndromes'], homecare:['Take anti-seizure medications exactly as prescribed and never miss a dose','Corticosteroids as prescribed to reduce brain swelling','Cognitive rehabilitation for memory and function','Physiotherapy and occupational therapy after surgery or radiation','Palliative care for symptom management in advanced cases','Caregiver support is essential'], whenToSeeDoctor:'New onset seizures in an adult, persistent morning headaches that worsen over days, sudden personality changes, or any focal neurological symptoms need urgent brain MRI evaluation.', urgency:'high' },

  { name:'Pancreatic Cancer', aliases:['pancreatic cancer','pancreas cancer','pancreatic malignancy','pancreatic tumor'], emoji:'🏥', type:'chronic', description:'One of the most serious cancers, often diagnosed at an advanced stage because early disease is usually asymptomatic. A leading cause of cancer death. Surgery (Whipple procedure) is the only curative option and only possible in early-stage disease.', symptoms:['Jaundice — yellow skin and eyes (often the first noticeable sign)','Dark urine and pale stools','Abdominal or back pain — dull aching pain radiating to the back','Unexplained weight loss','Loss of appetite','New-onset diabetes or worsening of existing diabetes','Nausea and vomiting','Fatigue','Blood clots'], causes:['Smoking (significant risk factor — doubles risk)','Chronic pancreatitis','Obesity and type 2 diabetes','Family history or genetic syndromes (BRCA2, Lynch syndrome)','Age over 60','Heavy alcohol use'], homecare:['Attend all oncology appointments and treatment sessions','Nutritional support — pancreatic enzyme supplements to help digest food','Pain management — palliative care team for uncontrolled pain','Quit smoking immediately upon diagnosis','Psychological support and palliative care planning'], whenToSeeDoctor:'Jaundice, unexplained weight loss, new-onset diabetes over 50, or persistent abdominal/back pain need urgent evaluation. Those with family history of pancreatic cancer or BRCA2 should discuss surveillance.', urgency:'high' },

  { name:'Stomach Cancer', aliases:['stomach cancer','gastric cancer','stomach malignancy','gastric tumor','stomach carcinoma'], emoji:'🏥', type:'chronic', description:'Cancer developing in the stomach lining. Rates have declined globally with reduced H. pylori infection and less smoked and salted food. Often diagnosed late as early symptoms are non-specific.', symptoms:['Indigestion and stomach pain after eating','Feeling bloated after meals','Heartburn','Loss of appetite','Nausea','Difficulty swallowing','Unexplained weight loss','Fatigue and weakness','Blood in vomit or black tarry stools (advanced)'], causes:['H. pylori bacterial infection (main risk factor)','Smoking','High salt diet, smoked or pickled foods','Previous stomach surgery','Pernicious anemia','Family history'], homecare:['Take all prescribed cancer treatments as directed','Eat small frequent meals if difficulty eating — diet modifications with dietitian','H. pylori eradication if still present','Manage nausea from chemotherapy with prescribed antiemetics','Nutritional supplements if malabsorption'], whenToSeeDoctor:'Persistent unexplained indigestion, weight loss, or abdominal pain especially in those over 55 or with H. pylori history needs endoscopy for evaluation. H. pylori testing and eradication is recommended to reduce stomach cancer risk.', urgency:'high' },

  { name:'Liver Cancer', aliases:['liver cancer','hepatocellular carcinoma','hcc','liver malignancy','liver tumor','primary liver cancer'], emoji:'🍋', type:'chronic', description:'Cancer that begins in the cells of the liver. Hepatocellular carcinoma (HCC) is the most common type, arising from chronic liver damage. Most liver cancers develop in the setting of cirrhosis.', symptoms:['Unintentional weight loss','Loss of appetite','Upper abdominal pain or tenderness','Nausea and vomiting','Fatigue and weakness','Jaundice — yellowing of skin and eyes','White, chalky stools','Abdominal swelling from ascites'], causes:['Liver cirrhosis from chronic hepatitis B or C','Alcoholic cirrhosis','Non-alcoholic fatty liver disease (NASH)','Aflatoxin exposure (moldy grains or legumes)','Metabolic syndrome'], homecare:['Regular 6-monthly ultrasound and AFP blood test screening for cirrhosis patients','Attend all oncology treatment appointments (ablation, TACE, sorafenib, immunotherapy)','Strict alcohol abstinence','Antiviral treatment for hepatitis B or C underlying the cancer','Nutritional support — cirrhotic patients often malnourished'], whenToSeeDoctor:'All patients with cirrhosis should receive surveillance ultrasound and AFP every 6 months. Rising AFP or suspicious liver lesion on ultrasound needs urgent liver specialist evaluation.', urgency:'high' },

  { name:'Kidney Cancer', aliases:['kidney cancer','renal cell carcinoma','rcc','renal cancer','kidney tumor'], emoji:'🫘', type:'chronic', description:'Cancer that originates in the kidneys. Renal cell carcinoma is the most common type. Often discovered incidentally on imaging performed for other reasons. Highly treatable in early stages.', symptoms:['Blood in urine (hematuria) — most common early sign','Persistent pain in the side or back','Lump in the side or back','Fatigue','Unexplained weight loss','Fever not caused by infection','High blood pressure (in some cases)','Anemia'], causes:['Smoking (doubles the risk)','Obesity','High blood pressure','Family history','Polycystic kidney disease','Long-term dialysis'], homecare:['Take all prescribed targeted therapy or immunotherapy medications as directed','Monitor blood pressure — hypertension is a common side effect of many kidney cancer medications','Report side effects from medications promptly to oncologist','Quit smoking immediately upon diagnosis','Maintain adequate hydration'], whenToSeeDoctor:'Blood in urine or a back/flank mass needs urgent evaluation. Regular oncology review every 3 months during active treatment. Surveillance imaging after treatment to monitor for recurrence.', urgency:'high' },

  { name:'Bladder Cancer', aliases:['bladder cancer','bladder malignancy','urothelial cancer','bladder tumor','transitional cell carcinoma'], emoji:'🏥', type:'chronic', description:'Cancer that begins in the cells lining the urinary bladder. Blood in the urine (hematuria) is the most common symptom. Closely linked to smoking. Recurrence rates are high requiring ongoing surveillance.', symptoms:['Blood in urine — painless hematuria (most common early sign)','Frequent urination','Painful urination','Back pain','Pelvic pain (advanced disease)','Urinary urgency'], causes:['Cigarette smoking (most significant risk factor — responsible for 50% of cases)','Occupational exposure to chemicals (dyes, rubber, leather, paint)','Chronic bladder inflammation (repeated UTIs, bladder stones)','Previous pelvic radiation','Certain chemotherapy drugs (cyclophosphamide)'], homecare:['Quit smoking — the most important prevention and post-treatment measure','Stay well hydrated — dilutes potential carcinogens in urine','Follow surveillance cystoscopy schedule — bladder cancer recurs frequently and needs regular monitoring','Intravesical BCG instillations as prescribed for non-muscle-invasive disease'], whenToSeeDoctor:'Any blood in urine in an adult (especially over 45 or with smoking history) warrants urgent cystoscopy evaluation. Regular 3-monthly cystoscopy during the first 2 years after treatment.', urgency:'high' },

  { name:'Thyroid Cancer', aliases:['thyroid cancer','thyroid malignancy','thyroid tumor','papillary thyroid cancer','thyroid carcinoma'], emoji:'🦋', type:'chronic', description:'Cancer that develops in the thyroid gland. Most types (papillary and follicular) are highly curable with excellent long-term survival rates. Incidence is increasing globally.', symptoms:['Lump (nodule) in the neck — often the only sign','Swollen lymph nodes in neck','Voice changes — hoarseness','Difficulty swallowing','Difficulty breathing','Throat or neck pain'], causes:['Radiation exposure especially in childhood','Family history or genetic syndromes (MEN2 — medullary thyroid cancer)','Gender — more common in women','Iodine deficiency (less common with iodized salt)'], homecare:['Take prescribed thyroid hormone replacement (levothyroxine) consistently after surgery — also suppresses TSH to reduce recurrence risk','Attend regular thyroglobulin blood tests and neck ultrasound for surveillance','Radioactive iodine treatment compliance if prescribed','Calcium and vitamin D supplementation if parathyroid glands affected during surgery'], whenToSeeDoctor:'Any new neck lump should be evaluated by a doctor. Regular endocrinologist follow-up after treatment — initially every 6 months. Papillary and follicular thyroid cancers have 5-year survival rates above 98%.', urgency:'medium' },

  { name:'Oral Cancer', aliases:['oral cancer','mouth cancer','oral malignancy','tongue cancer','lip cancer','oral cavity cancer'], emoji:'🦷', type:'chronic', description:'Cancer occurring in the mouth — including lips, tongue, gums, cheeks, floor of the mouth, and hard and soft palate. Strongly linked to tobacco and alcohol. Early detection dramatically improves survival.', symptoms:['A sore or ulcer in the mouth that does not heal within 3 weeks','Red or white patches inside the mouth (erythroplakia or leukoplakia)','Lump or thickening in cheek, lip, or throat','Difficulty or pain when chewing or swallowing','Tongue or jaw numbness or pain','Loose teeth without dental cause','Voice changes','Persistent ear pain'], causes:['Tobacco — smoking and chewing tobacco (most common cause)','Heavy alcohol consumption — synergistic with tobacco','HPV infection (increasing cause, especially HPV 16)','Excessive sun exposure (lip cancer)','Betel nut chewing (common in South Asia)'], homecare:['Monthly oral self-examination — look for sores, patches, or lumps that do not go away','Quit tobacco and reduce alcohol','Attend regular dental checkups — dentists screen for oral cancer','Sunscreen lip balm for lip protection'], whenToSeeDoctor:'Any mouth ulcer or lesion not healed after 3 weeks, white or red patches, or lumps in the mouth or neck need urgent dental or ENT evaluation for biopsy. Early-stage oral cancer is highly curable.', urgency:'high' },

  { name:'Esophageal Cancer', aliases:['esophageal cancer','oesophageal cancer','esophagus cancer','gullet cancer','food pipe cancer'], emoji:'🏥', type:'chronic', description:'Cancer developing in the esophagus (food pipe connecting throat to stomach). Two main types: squamous cell carcinoma and adenocarcinoma. Often diagnosed at a late stage.', symptoms:['Progressive difficulty swallowing — starts with solid foods then liquids','Unintentional weight loss','Chest pain or discomfort behind the breastbone','Worsening heartburn or indigestion','Cough or hoarseness','Vomiting blood (advanced)'], causes:['Squamous cell: smoking and heavy alcohol use','Adenocarcinoma: chronic GERD and Barrett\'s esophagus','Obesity','Low fruit and vegetable intake'], homecare:['Attend all oncology treatment appointments — surgery, chemotherapy, radiation, targeted therapy','Nutritional support — esophageal cancer and treatment severely affect ability to eat','Nasogastric or gastrostomy tube feeding if unable to swallow adequately','Management of GERD to protect remaining esophagus','Quit smoking immediately'], whenToSeeDoctor:'Progressive difficulty swallowing is a red flag symptom requiring urgent endoscopy evaluation. Regular surveillance endoscopy for Barrett\'s esophagus (precancerous condition from chronic GERD).', urgency:'high' },

  { name:'Uterine Cancer', aliases:['uterine cancer','endometrial cancer','womb cancer','uterus cancer','endometrial malignancy'], emoji:'🌸', type:'chronic', description:'The most common gynecological cancer in developed countries, arising from the uterine lining (endometrium). Postmenopausal bleeding is the most common early warning sign, enabling early detection and good outcomes.', symptoms:['Vaginal bleeding after menopause (most common and important symptom)','Abnormal vaginal bleeding between periods in premenopausal women','Watery or blood-tinged vaginal discharge','Pelvic pain','Pain during intercourse'], causes:['Estrogen dominance — obesity, hormone replacement therapy with estrogen alone','Diabetes','PCOS','Late menopause or early periods (more lifetime estrogen exposure)','Family history or Lynch syndrome','Previous breast cancer treatment with tamoxifen'], homecare:['Maintain healthy weight — obesity is the major modifiable risk factor','Regular exercise reduces estrogen levels','Attend all oncology follow-up appointments after surgery or radiation','Genetic counseling if Lynch syndrome is identified in the family'], whenToSeeDoctor:'Any postmenopausal vaginal bleeding must be evaluated promptly by a gynecologist — uterine cancer is the most common cause and is highly treatable when caught early. Premenopausal women with very irregular bleeding also warrant evaluation.', urgency:'high' },

  { name:'Testicular Cancer', aliases:['testicular cancer','testis cancer','testicular tumor','germ cell tumor','orchic cancer'], emoji:'🩺', type:'chronic', description:'Cancer in the testicles. The most common cancer in men between ages 15-35. Highly curable even when spread — with an overall cure rate above 95%. Monthly self-examination is important for early detection.', symptoms:['Painless lump or swelling in a testicle','Feeling of heaviness in the scrotum','Dull ache in the lower abdomen, back, or groin','Sudden collection of fluid in the scrotum','Breast growth or tenderness (from hormone-producing tumors)','In advanced: back pain, shortness of breath, cough, neck lump'], causes:['Undescended testicle (cryptorchidism) — major risk factor','Family history of testicular cancer','Personal history of testicular cancer in the other testicle','Klinefelter syndrome'], homecare:['Monthly testicular self-examination — best done after a warm shower when the scrotum is relaxed','Attend all chemotherapy sessions if prescribed — testicular cancer is exquisitely chemosensitive','Sperm banking before chemotherapy or radiation — recommended to preserve fertility','Testosterone replacement if both testicles removed'], whenToSeeDoctor:'Any new painless testicular lump or swelling should be evaluated urgently by a urologist with ultrasound. Do not wait or assume it is a benign condition — testicular cancer spreads and early treatment is curative.', urgency:'high' },

  { name:'Bone Cancer', aliases:['bone cancer','osteosarcoma','bone malignancy','bone tumor','ewing sarcoma','bone sarcoma'], emoji:'🦴', type:'chronic', description:'Cancer that originates in bone tissue. Primary bone cancer is rare — most bone tumors are secondary (metastatic cancer spreading from elsewhere). Osteosarcoma and Ewing sarcoma are the most common primary types, affecting mainly children and young adults.', symptoms:['Bone pain — persistent and worsening, often worse at night','Swelling and tenderness near the affected bone','Weakened bone leading to fracture from minor injury (pathological fracture)','Fatigue','Unexplained weight loss','Fever (particularly Ewing sarcoma)'], causes:['Primary bone cancer: exact cause often unknown — certain genetic conditions increase risk (Li-Fraumeni syndrome)','Previous radiation therapy','Paget\'s disease of bone (increases osteosarcoma risk)','Secondary: metastasis from breast, lung, prostate, kidney, or thyroid cancer'], homecare:['Attend all chemotherapy, surgery, and radiation appointments','Bone strengthening medications (bisphosphonates) to reduce fracture risk and metastatic bone pain','Pain management with prescribed medications — palliative care team involvement','Mobility aids and physiotherapy after surgery or during treatment','Psychological support — bone cancer often affects young patients'], whenToSeeDoctor:'Persistent bone pain especially in children or young adults, swelling over bone, or unexplained fractures need urgent evaluation with X-ray and MRI. Bone pain in known cancer patients needs prompt assessment for metastasis.', urgency:'high' },

  /* ── INFECTIOUS ── */
  /* ── BACTERIAL ── */
  { name:'Tuberculosis', aliases:['tuberculosis','tb','pulmonary tb','lung tb','koch\'s disease','tb infection','latent tb','active tb','mycobacterium tuberculosis'], emoji:'🫁', type:'infectious', description:'A serious bacterial infection caused by Mycobacterium tuberculosis, primarily affecting the lungs but capable of attacking any organ. One of the world\'s leading infectious disease killers. Spreads through the air when an infected person coughs or sneezes.', symptoms:['Persistent cough lasting more than 3 weeks','Coughing up blood or blood-stained sputum','Chest pain','Fever especially in the evenings','Night sweats','Unintentional weight loss','Fatigue and weakness','Loss of appetite'], causes:['Mycobacterium tuberculosis bacteria','Spread through airborne droplets from coughing, sneezing, or talking','Close contact with an infected person','Weakened immune system (HIV, diabetes, malnutrition)','Overcrowded living conditions'], homecare:['Take all TB medications exactly as prescribed — stopping early causes drug resistance','Cover mouth and nose when coughing or sneezing','Ensure good ventilation in living spaces','Eat a nutritious diet to support immunity','Avoid alcohol during treatment','Inform close contacts so they can be tested'], whenToSeeDoctor:'Immediately if you have a persistent cough lasting 3+ weeks, blood in sputum, unexplained weight loss, or night sweats. TB is curable with a full 6-month course of antibiotics but requires doctor management throughout.', urgency:'high' },

  { name:'Tetanus', aliases:['tetanus','lockjaw','jaw lock','muscle spasms wound','clostridium tetani','tetanus infection'], emoji:'⚠️', type:'infectious', description:'A serious bacterial infection caused by Clostridium tetani that affects the nervous system, causing painful muscle contractions — especially of the jaw and neck. Enters through wounds. Preventable by vaccination.', symptoms:['Jaw stiffness and difficulty opening mouth (lockjaw)','Muscle stiffness and spasms in neck, abdomen, and limbs','Difficulty swallowing','Painful muscle contractions triggered by noise or touch','Fever and sweating','High blood pressure and rapid heart rate'], causes:['Clostridium tetani bacteria found in soil, dust, and animal feces','Enters body through cuts, puncture wounds, burns, or animal bites','Rusty nail injuries','Unvaccinated or under-vaccinated individuals are at highest risk'], homecare:['This is a medical emergency — do NOT attempt home management alone','Clean any wound immediately with soap and water and go to emergency services','Ensure tetanus vaccination status is up to date (booster every 10 years)','Seek medical care within 24 hours of any deep or contaminated wound'], whenToSeeDoctor:'Immediately after any deep or contaminated wound if not vaccinated in the last 5 years. If muscle stiffness or jaw lock develops after a wound, go to emergency services immediately — tetanus is life-threatening without treatment.', urgency:'high' },

  { name:'Cholera', aliases:['cholera','rice water stool','severe dehydration diarrhea','vibrio cholerae','watery diarrhea infection'], emoji:'💧', type:'infectious', description:'A severe diarrheal illness caused by the bacterium Vibrio cholerae. Spread through contaminated water and food. Can cause death from dehydration within hours if untreated. Primarily affects areas with poor sanitation.', symptoms:['Sudden onset of profuse, watery diarrhea (described as "rice water" stool)','Nausea and vomiting','Rapid severe dehydration','Muscle cramps','Sunken eyes and dry skin','Low or no urine output','Rapid heartbeat and low blood pressure'], causes:['Vibrio cholerae bacteria in contaminated water or food','Drinking untreated or contaminated water','Eating raw shellfish from contaminated waters','Poor sanitation and hygiene','Flooding and natural disasters that contaminate water supplies'], homecare:['Begin oral rehydration solution (ORS) immediately — this is lifesaving','Drink boiled or treated water only','Maintain strict hand hygiene — wash with soap before eating and after toilet','Cook food thoroughly — avoid raw seafood','Do not share utensils or food with an infected person'], whenToSeeDoctor:'Immediately — cholera can be fatal within hours from dehydration. If profuse watery diarrhea starts suddenly, begin ORS and go to hospital immediately. Intravenous fluids and antibiotics are required for severe cases.', urgency:'high' },

  { name:'Dysentery', aliases:['dysentery','bloody diarrhea','amoebic dysentery','bacillary dysentery','blood in stool diarrhea','shigella','loose motions with blood'], emoji:'🦠', type:'infectious', description:'A type of gastroenteritis causing severe diarrhea with blood and mucus in the stool. Can be caused by bacteria (bacillary dysentery — Shigella) or a parasite (amoebic dysentery — Entamoeba histolytica). Spreads through contaminated food and water.', symptoms:['Diarrhea with blood and mucus','Severe abdominal cramps and pain','Urgent and frequent need to defecate','Fever','Nausea and vomiting','Tenesmus — feeling of incomplete emptying'], causes:['Shigella bacteria (bacillary dysentery)','Entamoeba histolytica parasite (amoebic dysentery)','Contaminated food or water','Poor hand hygiene','Contact with infected person'], homecare:['Drink ORS frequently to prevent dehydration','Wash hands thoroughly with soap before eating and after toilet','Avoid solid food initially — clear liquids then bland foods','Avoid dairy and fatty foods','Do not take antidiarrheal medications without medical advice — they can worsen bacterial dysentery'], whenToSeeDoctor:'Any diarrhea with blood requires medical attention. Seek emergency care if dehydration signs are present, high fever, or if a child or elderly person is affected. Antibiotics or antiparasitic medications are required.', urgency:'high' },

  { name:'Leptospirosis', aliases:['leptospirosis','weil\'s disease','rat fever','floodwater disease','leptospira infection','rat urine infection'], emoji:'🐀', type:'infectious', description:'A bacterial infection caused by Leptospira bacteria, spread through the urine of infected animals (especially rats) in water or soil. Common after flooding. Can cause severe liver and kidney failure in its serious form (Weil\'s disease).', symptoms:['High fever, headache, and muscle aches','Red eyes (conjunctival suffusion)','Nausea, vomiting, and diarrhea','Muscle pain especially calves','Jaundice (yellow skin and eyes) in severe cases','Dark urine and decreased urine output','Rash'], causes:['Leptospira bacteria from urine of rats, dogs, cattle, pigs','Wading through floodwater contaminated with animal urine','Swimming in contaminated rivers or lakes','Occupational exposure — farmers, sewer workers, veterinarians','Handling infected animals'], homecare:['Avoid wading in floodwater without rubber boots and protective clothing','Wear waterproof gloves when handling potentially contaminated soil or water','Cover any cuts or wounds before working outdoors','Wash hands and feet after outdoor exposure','If exposed, inform doctor promptly for preventive antibiotics'], whenToSeeDoctor:'Immediately after exposure in flood conditions with fever and muscle pain — early antibiotics are highly effective. Severe cases (Weil\'s disease) with jaundice or kidney failure require hospitalization.', urgency:'high' },

  { name:'Plague', aliases:['plague','bubonic plague','pneumonic plague','yersinia pestis','black death','buboes'], emoji:'☠️', type:'infectious', description:'A severe bacterial infection caused by Yersinia pestis, primarily spread through flea bites from infected rodents. Three forms: bubonic (swollen lymph nodes), septicemic (bloodstream), and pneumonic (lungs). Historically caused the Black Death pandemic.', symptoms:['Bubonic: sudden fever, headache, painful swollen lymph nodes (buboes) in groin, armpit, or neck','Pneumonic: severe pneumonia with bloody sputum','Septicemic: fever, chills, extreme weakness, abdominal pain, bleeding into skin (dark patches)','Rapid deterioration in all forms','Nausea and vomiting'], causes:['Yersinia pestis bacteria','Primarily spread through bites of infected fleas from rodents','Handling infected animals','Pneumonic plague spreads person to person through respiratory droplets'], homecare:['This is a notifiable public health emergency — seek immediate medical care','Avoid contact with wild rodents and their fleas','Use insect repellent in endemic areas','Do not handle dead animals without protection','Wear gloves and masks when in contact with potentially infected persons'], whenToSeeDoctor:'Immediately — plague progresses rapidly and is fatal without prompt antibiotic treatment. Pneumonic plague can be fatal within 24 hours. Any suspected case is a public health emergency requiring immediate hospitalization and isolation.', urgency:'high' },

  { name:'Anthrax', aliases:['anthrax','bacillus anthracis','inhalation anthrax','cutaneous anthrax','bioterrorism disease','woolsorter\'s disease'], emoji:'⚗️', type:'infectious', description:'A serious infection caused by Bacillus anthracis spores. Can affect the skin (cutaneous), lungs (inhalation), or digestive system. Naturally found in soil and can infect livestock. Also a known bioterrorism agent.', symptoms:['Cutaneous: small blister that becomes a painless black ulcer (eschar) with swelling','Inhalation: initially flu-like then rapidly progressing to severe breathing difficulty, shock','Gastrointestinal: nausea, vomiting blood, severe abdominal pain','All forms: fever and fatigue'], causes:['Bacillus anthracis spores from infected animals (cattle, sheep, goats, horses)','Handling infected animal products — wool, hides, bone meal','Ingesting undercooked meat from infected animals','Inhalation of spores in industrial or bioterrorism settings'], homecare:['Seek immediate emergency medical care — anthrax progresses rapidly','Do not handle suspicious packages or white powder — call authorities','Workers with animal exposure should wear protective equipment','Vaccination available for high-risk occupations'], whenToSeeDoctor:'Immediately — any form of anthrax is life-threatening without prompt antibiotic treatment. Inhalation anthrax has high mortality even with treatment. Suspected anthrax is a public health emergency.', urgency:'high' },

  { name:'Brucellosis', aliases:['brucellosis','undulant fever','malta fever','mediterranean fever','brucella infection','livestock fever'], emoji:'🐄', type:'infectious', description:'A bacterial infection caused by Brucella species, primarily spread to humans from animals (cattle, goats, pigs, dogs). Common in farmers, veterinarians, and those consuming unpasteurized dairy products.', symptoms:['Undulating (rising and falling) fever','Sweating, especially at night','Fatigue and muscle pain','Joint pain and swelling','Headache','Loss of appetite and weight loss','Spleen and liver enlargement'], causes:['Brucella bacteria from cattle, goats, sheep, pigs, or dogs','Consuming unpasteurized milk or cheese from infected animals','Direct contact with infected animal blood, tissue, or fluids during birthing or butchering','Occupational exposure in farmers, veterinarians, abattoir workers'], homecare:['Consume only pasteurized dairy products','Wear protective gloves when handling animals or animal products','Veterinarians and farmers should take extra precautions during birthing season','Complete full course of prescribed antibiotics — treatment takes 6 weeks or more'], whenToSeeDoctor:'If you have prolonged undulating fever with muscle and joint pain, especially after animal contact or consuming unpasteurized dairy. Brucellosis requires prolonged antibiotic therapy from a physician.', urgency:'medium' },

  { name:'Meningitis', aliases:['meningitis','bacterial meningitis','viral meningitis','meningococcal','brain membrane infection','stiff neck fever','meningeal infection'], emoji:'🧠', type:'infectious', description:'Inflammation of the membranes (meninges) surrounding the brain and spinal cord. Can be bacterial (most severe), viral (most common), or fungal. Bacterial meningitis is a medical emergency that can be fatal within 24 hours.', symptoms:['Sudden severe headache','High fever','Stiff neck — cannot bend chin to chest','Sensitivity to light (photophobia) and sound','Nausea and vomiting','Confusion or altered consciousness','Non-blanching rash (does not fade when pressed — in meningococcal disease)'], causes:['Neisseria meningitidis (bacterial — most dangerous)','Streptococcus pneumoniae','Viral: enteroviruses (most common cause overall)','Fungal: Cryptococcus (in immunocompromised)','Spread through respiratory droplets and close contact'], homecare:['This is a medical emergency — do NOT wait to seek care','If non-blanching purple rash appears, call emergency services immediately','Avoid close contact with confirmed cases','Vaccination is available against major bacterial causes (meningococcal, pneumococcal)'], whenToSeeDoctor:'Immediately if there is severe headache with stiff neck and fever — this is a medical emergency. Go to emergency services without delay. Every hour without treatment increases the risk of death or serious disability.', urgency:'high' },

  { name:'Encephalitis', aliases:['encephalitis','brain inflammation','brain infection','viral encephalitis','herpes encephalitis','brain swelling infection'], emoji:'🧠', type:'infectious', description:'Inflammation of the brain itself, usually caused by a viral infection. Can be life-threatening and lead to long-term neurological complications. Distinct from meningitis which affects the brain\'s coverings.', symptoms:['Severe headache','High fever','Confusion, disorientation, or altered consciousness','Seizures','Weakness or numbness in limbs','Personality or behavior changes','Difficulty speaking or moving','Extreme sensitivity to light'], causes:['Herpes simplex virus (most common cause of severe encephalitis)','Enteroviruses','Arboviruses — Japanese encephalitis, West Nile virus, Nipah virus','Rabies virus','Autoimmune causes (antibodies attacking brain)'], homecare:['This is a medical emergency — seek care immediately','Do not leave the person alone if they are confused or having seizures','Lay the person on their side if they have a seizure','Prevent mosquito bites in endemic areas (mosquito nets, repellent)'], whenToSeeDoctor:'Any confusion, seizures, or severe headache with fever is a medical emergency. Require immediate hospitalization. Antiviral treatment for herpes encephalitis must be started immediately for best outcome.', urgency:'high' },

  { name:'Septicemia', aliases:['septicemia','blood poisoning','sepsis','bacteremia','infection in blood','septic shock','bacteria in blood'], emoji:'🩸', type:'infectious', description:'A life-threatening medical emergency where a bacterial infection enters the bloodstream and spreads throughout the body, triggering a dangerous immune response. Can rapidly progress to septic shock and multiple organ failure.', symptoms:['High fever or abnormally low temperature','Rapid heart rate','Rapid breathing','Confusion or altered mental status','Extreme low blood pressure','Cold, clammy, or mottled skin','Decreased urine output','Feeling of extreme illness'], causes:['Bacterial infection that spreads to the bloodstream from any source (lung, urine, abdomen, wound)','Pneumonia, urinary tract infections, abdominal infections are common sources','Weakened immune system','Recent surgery or invasive procedure','Indwelling catheters or IV lines'], homecare:['This is a medical emergency — call emergency services immediately','Do not attempt home treatment for suspected sepsis','Keep person warm and calm while awaiting emergency services','Inform emergency responders of any recent infections, surgeries, or procedures'], whenToSeeDoctor:'Immediately — sepsis is a medical emergency. If you suspect sepsis (fever + rapid heart rate + confusion), call emergency services. Hours matter — delayed treatment dramatically increases mortality.', urgency:'high' },

  { name:'Blood Poisoning', aliases:['blood poisoning','blood infection','toxemia','bacteria spreading in blood','infected blood','septic blood'], emoji:'🩸', type:'infectious', description:'A common lay term for septicemia or toxemia — when bacterial toxins or the bacteria themselves enter the bloodstream. Represents the same life-threatening condition as septicemia and requires the same immediate emergency response.', symptoms:['Red streaks radiating from a wound (tracking up the limb)','High fever and chills','Rapid breathing and heart rate','Confusion','Extreme weakness and feeling very unwell','Cold and clammy skin','Wound that is spreading red and hot'], causes:['Untreated or inadequately treated bacterial infections (wound infections, cellulitis, pneumonia, UTI)','Deep wounds contaminated with bacteria','Compromised immune system allowing bacteria to escape local infection'], homecare:['Go to emergency services immediately — do not wait','If red streaks are spreading from a wound, this is a surgical emergency','Keep any infected wound elevated while transporting to hospital','Do not lance or squeeze an infected wound at home'], whenToSeeDoctor:'Immediately — blood poisoning/septicemia progresses within hours to shock and death without IV antibiotics and hospital care.', urgency:'high' },

  { name:'Cellulitis', aliases:['cellulitis','skin infection spreading','red hot swollen skin','cellulitis infection','spreading skin redness'], emoji:'🔴', type:'infectious', description:'A bacterial skin infection affecting the deeper layers of the skin and underlying tissue. Commonly caused by Streptococcus or Staphylococcus. If untreated, can spread to the bloodstream (septicemia).', symptoms:['Red, swollen, and warm area of skin','Skin tenderness and pain','Rapid spreading of redness','Fever and chills','Red streaks extending from the affected area','Skin may appear pitted (like orange peel)','Blisters in severe cases'], causes:['Streptococcus pyogenes or Staphylococcus aureus bacteria','Bacteria enter through a break in the skin — cut, wound, insect bite, ulcer','Pre-existing skin conditions — eczema, athlete\'s foot','Lymphedema or circulatory problems'], homecare:['Elevate the affected limb to reduce swelling','Take antibiotics as prescribed for the full course','Apply clean cool compresses for comfort','Mark the border of redness with a pen to monitor spreading','Avoid squeezing or puncturing the area'], whenToSeeDoctor:'See a doctor promptly — cellulitis requires antibiotics. Go to emergency immediately if red streaks are spreading rapidly, you develop high fever, feel extremely unwell, or are immunocompromised or diabetic.', urgency:'high' },

  { name:'Erysipelas', aliases:['erysipelas','st anthony\'s fire','raised red skin infection','skin strep infection','superficial cellulitis','red raised skin patch'], emoji:'🔴', type:'infectious', description:'A superficial bacterial skin infection (affecting upper dermis and lymphatics) caused almost always by Group A Streptococcus. Distinguished from cellulitis by a sharply demarcated, raised, bright red area with a clear border.', symptoms:['Bright red, swollen, shiny patch of skin with clearly raised borders','Burning pain and warmth over affected area','Fever, chills, and malaise preceding the skin changes','Rapid spreading of the red patch','Blistering in severe cases','Commonly affects the face (butterfly pattern) or lower legs'], causes:['Group A Streptococcus bacteria','Enters through small breaks in skin — cracks, ulcers, insect bites','Lymphatic obstruction increases risk','Elderly, diabetic, and immunocompromised individuals most at risk'], homecare:['Take prescribed antibiotics for the complete course','Rest and elevate the affected area','Apply cool moist cloths for comfort','Mark the border of redness to monitor whether it is spreading','Do not attempt to drain or lance the area'], whenToSeeDoctor:'See a doctor promptly for diagnosis and antibiotics. Go to emergency if high fever, rapidly spreading redness, or signs of sepsis develop. Facial erysipelas can affect the eyes and requires urgent attention.', urgency:'high' },

  { name:'Impetigo', aliases:['impetigo','school sores','honey crust skin','contagious skin sores','staphylococcal skin','strep skin infection','crusty blisters skin'], emoji:'🩹', type:'infectious', description:'A highly contagious superficial bacterial skin infection most common in children, caused by Staphylococcus aureus or Streptococcus pyogenes. Causes honey-colored crusted sores, typically around the nose and mouth.', symptoms:['Red sores that quickly rupture, ooze, and form honey-colored crusts','Most common around nose and mouth, hands, or forearms','Itching','Painless blisters (bullous impetigo) filled with clear fluid','Spreads easily to other areas by touching','Mildly enlarged lymph nodes nearby'], causes:['Staphylococcus aureus (most common)','Streptococcus pyogenes','Spreads through direct contact with sores or sharing towels, clothing, or surfaces','Minor cuts, insect bites, or eczema provide entry points'], homecare:['Gently clean sores with soap and water and pat dry','Apply prescribed antibiotic cream to sores','Keep child home from school until 24-48 hours after starting antibiotics','Do not share towels, pillowcases, or clothing','Wash hands frequently and cut fingernails short to prevent scratching and spreading'], whenToSeeDoctor:'See a doctor for any spreading crusty skin sores in a child, or if spreading despite topical treatment. Oral antibiotics are needed for widespread impetigo. Watch for signs of kidney complications (rare) — blood in urine.', urgency:'medium' },

  { name:'Folliculitis', aliases:['folliculitis','hair follicle infection','infected hair follicles','razor bumps','hot tub rash','follicle inflammation'], emoji:'🔴', type:'infectious', description:'Inflammation and infection of the hair follicles, usually caused by Staphylococcus aureus bacteria. Appears as small red bumps or white-headed pimples around hair follicles. Usually mild and responds well to treatment.', symptoms:['Small red bumps or white-headed pimples clustered around hair follicles','Pus-filled blisters that break open and crust over','Itching, burning, and tenderness of affected skin','Commonly on the thighs, buttocks, armpits, and beard area'], causes:['Staphylococcus aureus bacteria (most common)','Pseudomonas aeruginosa from contaminated pools or hot tubs (hot tub folliculitis)','Shaving, waxing, or wearing tight clothing trapping sweat','Friction from skin rubbing','Ingrown hairs'], homecare:['Apply warm compresses 3-4 times a day to help pimples drain','Use antibacterial soap on affected areas','Avoid shaving over infected area until healed','Wear loose-fitting clothing','Shower immediately after using pools or hot tubs'], whenToSeeDoctor:'If folliculitis is spreading, recurring frequently, or not responding to hygiene measures. Prescription antibiotic cream or oral antibiotics may be needed. Recurrent folliculitis may indicate MRSA and needs swab testing.', urgency:'low' },

  { name:'Furuncle', aliases:['furuncle','boil','skin boil','staphylococcal boil','painful lump skin','abscess hair follicle','furuncle infection'], emoji:'🔴', type:'infectious', description:'A deep infection of a hair follicle and surrounding skin, commonly called a boil. Caused by Staphylococcus aureus. Starts as a painful red lump that fills with pus. More severe than folliculitis, involving deeper tissue.', symptoms:['Painful, red, swollen lump (2-5 cm) under the skin','Lump grows and fills with pus over 3-5 days','Skin around the lump becomes inflamed','The boil may rupture and drain pus spontaneously','Fever in some cases','Commonly on face, neck, armpits, buttocks, thighs'], causes:['Staphylococcus aureus bacteria','Friction, tight clothing, and sweat','Pre-existing folliculitis progressing deeper','Diabetes, obesity, or immune deficiency increase risk'], homecare:['Apply warm compresses for 20 minutes 3-4 times daily to encourage drainage','Keep the area clean and covered','Do not squeeze or lance a boil — this can spread infection deeper or cause septicemia','Wash hands before and after touching the area','Keep towels and clothing separate from other household members'], whenToSeeDoctor:'If the boil is on the face or spine, is very large, has a fever, or does not improve after 2 weeks. Never squeeze a boil on the face. A doctor may need to incise and drain it. Oral antibiotics are prescribed for severe cases.', urgency:'medium' },

  { name:'Carbuncle', aliases:['carbuncle','cluster of boils','multiple boils','deep skin abscess','merged boils','carbuncle infection'], emoji:'🔴', type:'infectious', description:'A cluster of several interconnected boils (furuncles) that form a larger, deeper abscess under the skin with multiple pus-draining openings. More serious than a single boil and almost always requires medical treatment.', symptoms:['Large, painful red lump with multiple pus-draining openings','Deeper and larger than a single boil','Fever and feeling generally unwell','The skin over the lump may appear shiny and thin','Significant local pain and tenderness','Commonly on the back of the neck, shoulders, or thighs'], causes:['Staphylococcus aureus bacteria (same as boils but deeper cluster)','MRSA in recurrent cases','Diabetes significantly increases risk','Crowded living conditions','Poor skin hygiene'], homecare:['Apply warm compresses to encourage drainage','Do not squeeze, cut, or puncture — this spreads infection','Keep the area covered with clean dressings','Wash hands frequently and keep personal items separate','Good blood sugar control is essential in diabetics with recurrent carbuncles'], whenToSeeDoctor:'Always see a doctor for a carbuncle — incision and drainage by a doctor is almost always required. Oral antibiotics are needed. Test for MRSA in recurrent cases. Diabetics are at high risk of serious complications.', urgency:'high' },

  { name:'Necrotizing Fasciitis', aliases:['necrotizing fasciitis','flesh eating disease','flesh eating bacteria','necrotizing infection','fascia infection','gas gangrene soft tissue'], emoji:'☠️', type:'infectious', description:'A rare but life-threatening bacterial infection that rapidly destroys the fascia (tissue under the skin) and surrounding soft tissue. Called the "flesh-eating disease" in media. Requires emergency surgery and has high mortality.', symptoms:['Severe pain out of proportion to the visible wound — the hallmark sign','Rapid spreading redness, warmth, and swelling','Skin may become discolored — purple or black — as tissue dies','Fever and signs of severe illness','Blistering and skin breakdown','Crepitus — crackling sensation under skin from gas produced by bacteria'], causes:['Mixed bacterial infection including Group A Streptococcus, Clostridium, Klebsiella, and others','Enters through wounds, cuts, surgical sites, insect bites, or even without visible injury','Diabetes, peripheral vascular disease, and immunosuppression are major risk factors'], homecare:['This is a surgical emergency — do NOT attempt home management','Call emergency services immediately if a wound has severe pain, rapidly spreading swelling, or skin color changes','Time from symptom onset to surgery directly determines survival'], whenToSeeDoctor:'Immediately — necrotizing fasciitis requires emergency surgery (surgical debridement), intensive care, and IV antibiotics. Every hour of delay significantly increases mortality. Do not wait.', urgency:'high' },

  { name:'Gas Gangrene', aliases:['gas gangrene','clostridial myonecrosis','wound gangrene','clostridium gas','gas in wound','gas gangrene infection'], emoji:'☠️', type:'infectious', description:'A rapidly progressing, life-threatening infection of muscle tissue caused by Clostridium bacteria that produce gas as they destroy muscle. Medical and surgical emergency. Associated with traumatic injuries and contaminated wounds.', symptoms:['Sudden onset of severe pain at a wound or injury site','Rapid swelling and skin becoming brownish-gray or bronze','Visible gas bubbles under the skin (crepitus — crackling on touch)','Wound may produce a sweet or foul-smelling gas','Extreme systemic illness — rapid heart rate, low blood pressure, confusion','Skin blistering and tissue death'], causes:['Clostridium perfringens and related species — found in soil and gut','Contaminated traumatic wounds — war injuries, road accidents, farm injuries','Occurs in wounds with poor blood supply and dead tissue','Rare complication of surgery or injection drug use'], homecare:['This is a surgical emergency — call emergency services immediately','Any wound with gas bubbling, severe pain out of proportion, and rapid illness is an emergency','Do not attempt to clean or dress the wound at home — go to hospital directly'], whenToSeeDoctor:'Immediately — gas gangrene progresses in hours. Requires emergency surgery (amputation may be needed), hyperbaric oxygen therapy, and IV antibiotics. Mortality remains high even with optimal treatment.', urgency:'high' },

  { name:'Osteomyelitis', aliases:['osteomyelitis','bone infection','infected bone','staph bone infection','bone marrow infection','chronic bone infection'], emoji:'🦴', type:'infectious', description:'An infection of the bone caused by bacteria (most often Staphylococcus aureus) or occasionally fungi. Can be acute (recent onset) or chronic (long-standing). Can lead to bone death if untreated.', symptoms:['Deep bone pain (more severe than expected from surface appearance)','Swelling, warmth, and redness over the affected bone','Fever and chills','Difficulty moving the affected limb or joint','In children: refusal to use a limb or bear weight','Draining pus in chronic cases'], causes:['Staphylococcus aureus (most common)','Spreads to bone via bloodstream from another infection site','Direct infection from open fractures, surgery, or implants','Spread from adjacent soft tissue infection','Diabetes and peripheral vascular disease increase risk significantly'], homecare:['Take antibiotics for the full prescribed course — often 4-6 weeks or longer','Keep the affected area rested and elevated','Follow up regularly — treatment must be monitored by imaging','Control blood sugar if diabetic','Never skip antibiotic doses'], whenToSeeDoctor:'Any deep persistent bone pain with fever requires urgent medical assessment. Osteomyelitis requires prolonged antibiotics and sometimes surgery. Early treatment prevents chronic bone damage and bone death.', urgency:'high' },

  { name:'Septic Arthritis', aliases:['septic arthritis','infected joint','joint infection','bacterial arthritis','hot joint infection','pyogenic arthritis'], emoji:'🦵', type:'infectious', description:'A serious infection inside a joint space, most often caused by Staphylococcus aureus. Requires emergency drainage of the joint. Can destroy joint cartilage within days if untreated.', symptoms:['Severe, rapidly worsening pain in one joint','Swollen, red, hot, and exquisitely tender joint','High fever and feeling very unwell','Difficulty or inability to move the affected joint','Commonly affects knee, hip, shoulder, or wrist','Children may refuse to move a limb'], causes:['Staphylococcus aureus (most common)','Bacteria spread through bloodstream from another infection site','Direct inoculation from joint surgery or injection','Gonorrhea (most common cause in sexually active young adults)','Prosthetic joints at higher risk'], homecare:['This is a medical emergency — do NOT attempt home management','Go to emergency services immediately if a joint is suddenly hot, red, severely painful, and you have a fever','Do not apply heat or ice packs as a primary treatment — go to hospital'], whenToSeeDoctor:'Immediately — septic arthritis destroys joint cartilage within 24-72 hours without treatment. Requires urgent joint aspiration (removal of infected fluid), cultures, and IV antibiotics. Surgery may be required.', urgency:'high' },

  { name:'Endocarditis', aliases:['endocarditis','heart valve infection','infective endocarditis','bacterial endocarditis','heart lining infection','ie'], emoji:'❤️', type:'infectious', description:'An infection of the inner lining of the heart chambers and valves (endocardium), usually caused by bacteria that enter the bloodstream. Can permanently damage heart valves and is potentially fatal.', symptoms:['Prolonged fever — persistent and unexplained','Heart murmur (new or changed)','Fatigue and weakness','Night sweats','Joint pain and muscle aches','Tiny red or purple spots under fingernails or skin (petechiae, Janeway lesions)','Shortness of breath','In severe cases: stroke or heart failure symptoms'], causes:['Streptococcus viridans, Staphylococcus aureus, Enterococcus (most common bacteria)','Bacteria enter bloodstream during dental procedures, surgery, or IV drug use','Pre-existing heart valve disease or congenital heart defects increase risk','IV drug users at particularly high risk'], homecare:['Always inform dentists and surgeons about any heart valve condition — preventive antibiotics may be given','Maintain strict dental hygiene to reduce bacteremia from mouth bacteria','Avoid IV drug use completely','Take all prescribed antibiotics for the full duration — typically 4-6 weeks IV in hospital'], whenToSeeDoctor:'Prolonged unexplained fever with any heart condition history requires urgent medical evaluation. Once diagnosed, hospitalization and 4-6 weeks of IV antibiotics are needed. Heart surgery may be required in severe cases.', urgency:'high' },

  { name:'Myocarditis', aliases:['myocarditis','heart muscle infection','inflamed heart','viral myocarditis','myocarditis infection'], emoji:'❤️', type:'infectious', description:'Inflammation of the myocardium (heart muscle) most commonly caused by viral infections. Can impair the heart\'s ability to pump blood and in severe cases lead to heart failure, arrhythmia, or sudden cardiac death.', symptoms:['Chest pain (often sharp)','Shortness of breath, especially with exertion','Fatigue and weakness','Rapid or irregular heartbeat (palpitations)','Swelling in legs and feet','Fainting or near-fainting','Fever'], causes:['Viral infections: Coxsackievirus B (most common), adenovirus, influenza, COVID-19, SARS-CoV-2','Bacterial infections','Autoimmune conditions','Certain medications and toxins','Post-vaccination (very rare)'], homecare:['Rest completely — avoid all physical exertion until cleared by doctor','Do not exercise during and for several months after myocarditis — sudden cardiac death risk is real','Take prescribed medications — anti-inflammatory drugs, heart medications','Avoid alcohol and NSAIDs unless specifically prescribed'], whenToSeeDoctor:'Any chest pain with rapid heartbeat and shortness of breath after a recent viral illness requires urgent evaluation. Myocarditis is diagnosed by ECG, echocardiogram, and MRI. Severe cases require hospitalization.', urgency:'high' },

  { name:'Pericarditis', aliases:['pericarditis','pericardial infection','heart sac infection','inflamed pericardium','pleuritic chest pain','pericardial inflammation'], emoji:'❤️', type:'infectious', description:'Inflammation of the pericardium — the two-layered sac surrounding the heart. Usually caused by viral infections. Causes a characteristic sharp chest pain that worsens on lying down and improves on leaning forward.', symptoms:['Sharp, stabbing chest pain worse when lying flat and improved by leaning forward','Pain may radiate to the left shoulder or neck','Fever and fatigue','Pericardial friction rub (scratching sound heard by stethoscope)','Shortness of breath when lying down','In severe cases: cardiac tamponade — fluid compresses the heart'], causes:['Viral infection (most common — Coxsackievirus, echovirus)','Bacterial infection (Staphylococcus, Streptococcus, TB)','Inflammatory conditions (lupus, rheumatoid arthritis)','After heart attack or heart surgery','Renal failure'], homecare:['Rest and avoid physical activity until pain resolves','Take anti-inflammatory medications as prescribed (NSAIDs, colchicine)','Sit upright and lean forward for pain relief','Avoid alcohol and strenuous exercise','Monitor for worsening shortness of breath'], whenToSeeDoctor:'All cases of pericarditis require medical assessment to confirm diagnosis and rule out cardiac tamponade. Seek emergency care for sudden worsening chest pain with rapid heart rate and low blood pressure.', urgency:'high' },

  { name:'Legionnaires Disease', aliases:['legionnaires disease','legionella','legionella pneumonia','atypical pneumonia legionella','cooling tower infection','legionellosis'], emoji:'🌬️', type:'infectious', description:'A severe form of pneumonia caused by Legionella pneumophila bacteria found in water systems. Spread by inhaling water droplets from cooling towers, air conditioning systems, or contaminated water. Not spread person to person.', symptoms:['High fever and chills','Severe pneumonia with productive cough','Shortness of breath','Chest pain','Muscle aches and headache','Nausea, diarrhea, and confusion (distinguishes it from other pneumonias)','Relative bradycardia — heart rate lower than expected for fever'], causes:['Legionella pneumophila bacteria in warm stagnant water (20-50°C)','Cooling towers, air conditioning systems, hot water tanks, fountains, nebulizers','Inhaling contaminated aerosol droplets','Hospital-acquired or travel-associated exposure'], homecare:['Report to public health authorities — it is a notifiable disease to trace the water source','Take antibiotics for the prescribed duration (usually 10-21 days)','Rest and maintain adequate hydration','Ensure water heating systems at home are set above 60°C to prevent Legionella growth'], whenToSeeDoctor:'Any suspected Legionnaires\' pneumonia requires hospitalization. It does not respond to standard penicillin-type antibiotics — specific antibiotics (fluoroquinolones, azithromycin) are required. Mortality is 10-15% in untreated cases.', urgency:'high' },

  { name:'Q Fever', aliases:['q fever','coxiella burnetii','query fever','livestock pneumonia','abattoir fever','farm fever'], emoji:'🐑', type:'infectious', description:'An infectious disease caused by Coxiella burnetii, a bacterium found in cattle, sheep, and goats. Spread by inhaling contaminated dust or particles from animal birth products. Can cause acute flu-like illness or chronic endocarditis.', symptoms:['Acute: sudden high fever, severe headache, muscle pain, and fatigue','Non-productive cough and chest pain (atypical pneumonia)','Nausea and diarrhea','Liver inflammation (hepatitis) with right upper abdominal pain','Chronic form: endocarditis lasting months to years'], causes:['Coxiella burnetii bacteria','Inhalation of contaminated aerosols from placentas, amniotic fluid, urine, feces of infected animals','Slaughterhouse workers, farmers, veterinarians at highest risk','Can also spread via raw milk'], homecare:['Wear masks and protective clothing when assisting animal deliveries','Avoid consuming unpasteurized milk and dairy products','Burn or bury animal birth materials rather than leaving them exposed','Report to doctor if occupational exposure has occurred and symptoms develop'], whenToSeeDoctor:'A doctor is needed to diagnose Q fever through blood tests. Specific antibiotics (doxycycline) are required. Chronic Q fever (endocarditis) requires prolonged treatment of 18+ months and cardiology involvement.', urgency:'medium' },

  { name:'Psittacosis', aliases:['psittacosis','parrot fever','chlamydia psittaci','bird disease','ornithosis','bird handler disease'], emoji:'🦜', type:'infectious', description:'An infection caused by Chlamydia psittaci, transmitted from birds (especially parrots, parakeets, pigeons) to humans through inhalation of dried bird droppings, feather dust, or secretions.', symptoms:['Fever, chills, and headache','Dry cough and atypical pneumonia','Muscle aches and joint pain','Fatigue and weakness','Nausea and vomiting','Confusion in severe cases','Rash (rare)'], causes:['Chlamydia psittaci bacteria from birds','Inhalation of dried droppings, feathers, or secretions of infected birds','Bird owners, pet shop workers, and poultry workers at highest risk','Birds may appear healthy but still carry the bacteria'], homecare:['Wear a mask when cleaning bird cages or handling birds','Regularly clean cages — prevent accumulation of droppings','Wash hands thoroughly after bird contact','Quarantine new birds before introducing them to existing pets'], whenToSeeDoctor:'See a doctor if you have an atypical pneumonia after bird exposure. Psittacosis responds well to doxycycline or tetracycline antibiotics. It does not respond to penicillin. Notify public health authorities as it is notifiable.', urgency:'medium' },

  { name:'H. Pylori Infection', aliases:['h pylori infection','helicobacter pylori','stomach bacteria','ulcer bacteria','h pylori gastritis','heliobacter pylori'], emoji:'🔬', type:'infectious', description:'An infection of the stomach lining by Helicobacter pylori bacteria. The most common cause of peptic ulcers worldwide. Most infected people have no symptoms, but it can cause gastritis, ulcers, and in rare cases stomach cancer.', symptoms:['Many people have no symptoms','Burning or gnawing pain in the stomach (especially when empty or at night)','Nausea','Frequent belching','Bloating','Loss of appetite','Unintentional weight loss in some cases'], causes:['Helicobacter pylori bacteria','Spread through contaminated food and water (fecal-oral route)','Close person-to-person contact','Most commonly acquired in childhood especially in areas with poor sanitation'], homecare:['Take the full antibiotic course — "triple therapy" or "quadruple therapy" for 10-14 days exactly as prescribed','Avoid NSAIDs (ibuprofen, aspirin) during treatment — they worsen stomach lining damage','Eat small regular meals and avoid spicy foods during treatment','Avoid alcohol and smoking which delay healing','Confirm eradication by repeat breath test after treatment'], whenToSeeDoctor:'See a doctor if you have recurring stomach pain, bloating, or suspected peptic ulcer. H. pylori is diagnosed by breath test, stool antigen test, or endoscopy. Eradication requires a specific combination of antibiotics and proton pump inhibitors.', urgency:'medium' },

  { name:'Salmonellosis', aliases:['salmonellosis','salmonella infection','food poisoning salmonella','non-typhoidal salmonella','egg food poisoning','chicken salmonella'], emoji:'🍗', type:'infectious', description:'A common foodborne illness caused by non-typhoidal Salmonella bacteria. Typically causes self-limiting gastroenteritis but can cause serious bloodstream infections in vulnerable populations.', symptoms:['Diarrhea (may be bloody)','Nausea and vomiting','Abdominal cramps','Fever (usually 38-39°C)','Headache','Symptoms begin 6-72 hours after exposure and last 3-7 days'], causes:['Contaminated poultry, eggs, beef, pork, and dairy products','Raw fruits and vegetables cross-contaminated during processing','Contact with infected reptiles, birds, or other animals','Undercooked meat and eggs','Poor food handling and hygiene'], homecare:['Drink ORS to prevent dehydration','Eat bland foods — rice, toast, bananas, boiled potatoes','Rest','Wash hands thoroughly after handling raw meat, eggs, and before eating','Cook poultry and eggs thoroughly — no pink meat, yolks fully set'], whenToSeeDoctor:'See a doctor if you have bloody diarrhea, fever above 38.5°C lasting more than 2-3 days, signs of dehydration, or are immunocompromised, elderly, or have an infant with salmonellosis. Antibiotics are only given in specific circumstances.', urgency:'medium' },

  { name:'Listeriosis', aliases:['listeriosis','listeria infection','listeria monocytogenes','deli meat infection','soft cheese infection','listeria food poisoning'], emoji:'🧀', type:'infectious', description:'A serious foodborne infection caused by Listeria monocytogenes bacteria. While rare, it has a much higher mortality rate than most food poisonings. Particularly dangerous for pregnant women, newborns, elderly, and immunocompromised individuals.', symptoms:['Fever, muscle aches, and fatigue','Nausea and diarrhea (mild gastrointestinal form)','Severe form (invasive listeriosis): severe headache, stiff neck, confusion, seizures — meningitis and septicemia','In pregnant women: mild flu-like illness in mother, but can cause premature birth, stillbirth, or severe infection in newborn'], causes:['Listeria monocytogenes in ready-to-eat foods — deli meats, hot dogs, soft cheeses, smoked fish, unpasteurized dairy','Can grow in the refrigerator at 4°C (unlike most bacteria)','Contaminated raw vegetables','Bacteria widely present in soil and animal intestines'], homecare:['High-risk individuals (pregnant, elderly, immunocompromised) should avoid deli meats, hot dogs, soft cheeses, and unpasteurized dairy','Consume only pasteurized dairy products','Heat ready-to-eat meats until steaming hot before consuming','Clean refrigerator regularly — Listeria can grow in the fridge'], whenToSeeDoctor:'Immediately for pregnant women with flu-like illness, and for anyone with stiff neck, severe headache, confusion, or fever after eating high-risk foods. Listeria meningitis has 20-30% mortality. IV antibiotics (ampicillin) are required.', urgency:'high' },

  { name:'Campylobacteriosis', aliases:['campylobacteriosis','campylobacter infection','campylobacter food poisoning','poultry food poisoning','campylobacter gastroenteritis'], emoji:'🐓', type:'infectious', description:'One of the most common bacterial causes of gastroenteritis worldwide, caused by Campylobacter jejuni. Typically acquired from undercooked poultry or contaminated water. Usually self-limiting but can cause complications.', symptoms:['Diarrhea (often bloody)','Severe abdominal cramps (can mimic appendicitis)','Fever (38-39°C)','Nausea and vomiting','Headache and muscle pain','Symptoms begin 2-5 days after exposure, last 3-7 days'], causes:['Undercooked poultry (chicken is the primary source)','Unpasteurized milk','Contaminated water and raw produce','Contact with infected animals (farm animals, cats, dogs)','Cross-contamination during food preparation'], homecare:['Drink ORS to prevent dehydration','Eat bland foods as tolerated','Wash hands thoroughly after handling raw poultry','Cook chicken to 75°C internal temperature — no pink meat','Keep raw poultry separate from other foods in the refrigerator'], whenToSeeDoctor:'Seek medical advice for bloody diarrhea, high fever, severe dehydration, or if diarrhea lasts more than 7 days. Antibiotics (azithromycin) are used in severe cases. Rarely can trigger reactive arthritis or Guillain-Barré syndrome.', urgency:'medium' },

  { name:'Botulism', aliases:['botulism','clostridium botulinum','food botulism','paralysis food poisoning','botulinum toxin poisoning','canned food poisoning'], emoji:'🥫', type:'infectious', description:'A rare but life-threatening illness caused by a toxin produced by Clostridium botulinum bacteria. The toxin blocks nerve function, causing paralysis. Most commonly from improperly preserved or canned foods (food botulism) but also wound botulism and infant botulism.', symptoms:['Double vision and difficulty focusing','Drooping eyelids','Difficulty speaking and swallowing','Dry mouth','Descending muscle weakness — starts from the head and moves downward','Difficulty breathing (most dangerous)','No fever — distinguishes it from many other infections','Nausea and vomiting in food botulism'], causes:['Clostridium botulinum toxin in improperly home-canned or preserved foods','Fermented foods, smoked fish, flavored oils with herbs','Wound botulism from contaminated wounds (rare, associated with injection drug use)','Infant botulism from honey or soil (never give honey to children under 1 year)'], homecare:['Never give honey to infants under 12 months','Home-canned foods must be heated to 121°C at high pressure — boiling at 100°C is insufficient','Discard any canned food with bulging lids, spurting liquid, or bad odor without tasting','Do not feed infants old, improperly stored home-prepared foods'], whenToSeeDoctor:'Immediately — botulism is a medical emergency. Descending paralysis and breathing difficulty can be rapidly fatal. Antitoxin must be given as early as possible. Mechanical ventilation may be required. All cases should be reported to public health.', urgency:'high' },

  { name:'Staphylococcal Infection', aliases:['staphylococcal infection','staph infection','staphylococcus aureus','staph aureus','staph skin infection','staph bacteria'], emoji:'🦠', type:'infectious', description:'Infections caused by Staphylococcus aureus bacteria, which can range from minor skin infections to life-threatening bloodstream infections, pneumonia, and toxic shock syndrome. S. aureus is one of the most common and versatile bacterial pathogens.', symptoms:['Skin infections: boils, impetigo, cellulitis, wound infections','Bacteremia (bloodstream): fever, chills, extreme illness','Pneumonia: cough, fever, difficulty breathing','Toxic shock syndrome: sudden high fever, rash, dangerously low blood pressure','Food poisoning: nausea and vomiting 1-6 hours after eating contaminated food (rapid onset)'], causes:['Staphylococcus aureus — carried in nose of ~30% of healthy people','Skin-to-skin contact','Contaminated surfaces and objects','Contaminated food (the bacteria produce toxins)','Breaks in the skin providing entry'], homecare:['Keep skin wounds clean and covered','Wash hands frequently especially after touching wounds or nose','Do not share personal items — towels, razors','Cook and store food at safe temperatures','Complete the full antibiotic course as prescribed'], whenToSeeDoctor:'See a doctor for any spreading skin infection, high fever, joint pain, or if a wound is not healing. Staph infections require specific antibiotic choice based on sensitivity testing. Serious staph infections require hospitalization and IV antibiotics.', urgency:'medium' },

  { name:'MRSA', aliases:['mrsa','methicillin resistant staphylococcus aureus','drug resistant staph','antibiotic resistant staph','mrsa infection','superbug skin'], emoji:'⚠️', type:'infectious', description:'Methicillin-Resistant Staphylococcus aureus — a strain of Staphylococcus aureus that has developed resistance to most common antibiotics. A major public health concern. Can cause severe skin infections, pneumonia, bloodstream infections, and surgical site infections.', symptoms:['Skin: painful, red, swollen bump resembling a spider bite or pimple that does not heal with standard treatment','Wound infection: redness, swelling, warmth, pus with no response to common antibiotics','Invasive MRSA: fever, chills, low blood pressure, respiratory failure — in hospital settings'], causes:['MRSA bacterium resistant to methicillin, oxacillin, and most penicillins','Spreads through direct skin contact','Contact with contaminated surfaces or shared personal items','Healthcare settings (hospital-acquired MRSA)','Community-acquired MRSA from gyms, sports, close contact'], homecare:['Keep any skin lesion clean and covered','Wash hands with soap frequently and thoroughly','Do not share towels, razors, or sports equipment','Shower immediately after gym use or contact sports','Complete all antibiotic courses exactly as prescribed'], whenToSeeDoctor:'Any skin infection that does not improve after 48-72 hours of antibiotic treatment requires medical review for possible MRSA. MRSA requires specific antibiotics (e.g. vancomycin IV, doxycycline, trimethoprim-sulfamethoxazole orally). Inform healthcare providers of confirmed MRSA history.', urgency:'high' },

  { name:'Clostridium Difficile', aliases:['clostridium difficile','c diff','c difficile','antibiotic associated diarrhea','clostridioides difficile','c diff colitis','pseudomembranous colitis'], emoji:'💊', type:'infectious', description:'A bacterial infection of the colon caused by Clostridium difficile, usually occurring after antibiotic use that disrupts the normal gut flora. Causes diarrhea ranging from mild to life-threatening colitis. Major cause of hospital-associated illness.', symptoms:['Watery diarrhea (3 or more loose stools per day)','Abdominal cramps and pain','Fever','Nausea','Loss of appetite','Severe colitis: bloody stool, severe abdominal pain, swollen abdomen, high fever'], causes:['Disruption of gut microbiome by antibiotics allows C. difficile overgrowth','C. difficile spores spread through contact with contaminated surfaces, healthcare environments, stool','Risk factors: recent antibiotic use, hospitalization, elderly, immunosuppressed, PPI use'], homecare:['Do not stop antibiotics causing C. diff without medical advice','Wash hands with soap and water (not just hand sanitizer — alcohol does not kill C. diff spores)','Clean contaminated surfaces with bleach-based disinfectant','Probiotics (Lactobacillus) during antibiotic courses may reduce risk — discuss with doctor','Avoid antidiarrheal medications without medical advice'], whenToSeeDoctor:'Any diarrhea during or after antibiotic treatment requires medical assessment. C. diff is treated with specific antibiotics (metronidazole, vancomycin, or fidaxomicin). Severe cases with colitis require hospitalization. Fecal microbiota transplant is used for recurrent C. diff.', urgency:'high' },

  /* ── VECTOR-BORNE ── */
  { name:'Chikungunya', aliases:['chikungunya','chikungunya fever','chikungunya virus','chik','joint fever mosquito','chickungunya'], emoji:'🦟', type:'infectious', description:'A viral disease transmitted by Aedes mosquitoes (same mosquitoes that carry dengue and Zika). Named from a Makonde word meaning "to walk bent over" — due to severe joint pain. Rarely fatal but joint pain can persist for months.', symptoms:['Sudden high fever (above 39°C)','Severe joint pain and swelling — in multiple joints, especially hands, wrists, ankles, feet','Muscle pain','Headache','Rash over the trunk and limbs','Fatigue'], causes:['Chikungunya virus (alphavirus)','Transmitted by bites of Aedes aegypti and Aedes albopictus mosquitoes','Mosquitoes breed in stagnant water near homes'], homecare:['Rest and drink plenty of fluids to stay hydrated','Take paracetamol for fever and pain — do not take ibuprofen or aspirin until dengue is excluded','Elevate and gently move affected joints to reduce stiffness','After dengue is ruled out, NSAIDs can help joint inflammation','Eliminate all standing water around home — mosquito breeding sites'], whenToSeeDoctor:'See a doctor for diagnosis (blood test) to exclude dengue. Seek emergency care for confusion, severe vomiting, severe joint swelling, or difficulty walking. Elderly and those with chronic diseases need medical monitoring.', urgency:'medium' },

  { name:'Zika Virus', aliases:['zika virus','zika','zika fever','zika infection','aedes zika','microcephaly virus'], emoji:'🦟', type:'infectious', description:'A viral infection transmitted by Aedes mosquitoes. Usually mild in adults, but can cause severe birth defects (microcephaly) in babies born to infected pregnant women. Also linked to Guillain-Barré syndrome. Can be sexually transmitted.', symptoms:['Mild fever','Rash (flat or raised red spots all over the body)','Joint pain','Red eyes (conjunctivitis)','Muscle pain and headache','Most people (80%) have no symptoms'], causes:['Zika virus (flavivirus)','Primarily transmitted by Aedes mosquitoes','Sexual transmission (male to partner — virus can persist in semen for weeks)','Mother to fetus during pregnancy','Blood transfusion (rare)'], homecare:['Pregnant women should avoid travel to Zika-endemic areas','Use condoms consistently to prevent sexual transmission after possible exposure','Use insect repellent and wear long sleeves to prevent mosquito bites','Eliminate standing water around the home','Seek urgent medical advice if pregnant and possibly exposed'], whenToSeeDoctor:'Pregnant women who have been in Zika-affected areas should seek medical advice immediately regardless of symptoms. Zika can cause microcephaly and other brain defects in the fetus. All persons with Zika symptoms should see a doctor for testing.', urgency:'high' },

  { name:'Japanese Encephalitis', aliases:['japanese encephalitis','je','japanese encephalitis virus','jev','rice field mosquito','culex encephalitis'], emoji:'🦟', type:'infectious', description:'A serious viral brain inflammation (encephalitis) caused by Japanese Encephalitis Virus, transmitted by Culex mosquitoes in Asia. Primarily affects children. Preventable by vaccination. Has up to 30% mortality and 50% of survivors have neurological complications.', symptoms:['Most infections (>99%) are asymptomatic or mild','Severe disease: sudden high fever, severe headache, stiff neck','Altered consciousness, confusion, and disorientation','Seizures — especially in children','Tremors and abnormal posture (Parkinson-like features)','Focal weakness or paralysis'], causes:['Japanese Encephalitis Virus (flavivirus)','Transmitted by Culex tritaeniorhynchus mosquitoes','Mosquitoes breed in rice paddies and irrigated areas','Pigs and wading birds are the main animal reservoirs'], homecare:['Vaccination is the most important prevention measure — highly effective','Use mosquito nets and repellent, especially in rural and agricultural areas','Wear long-sleeved clothing in endemic areas at dusk and dawn','Eliminate standing water and reduce mosquito exposure near pig farms'], whenToSeeDoctor:'Immediately if fever with altered consciousness or seizures occurs, especially in children in endemic areas. JE requires intensive care. There is no specific antiviral treatment — management is supportive. Vaccination should be given before travel to endemic regions.', urgency:'high' },

  { name:'Nipah Virus', aliases:['nipah virus','nipah','nipah encephalitis','niv','bat virus','fruit bat fever'], emoji:'🦇', type:'infectious', description:'A rare but extremely dangerous zoonotic virus (animal-to-human) causing severe encephalitis with up to 40-75% case fatality rate. Transmitted from fruit bats to humans via contaminated fruit or date palm sap, and can spread person-to-person. Has epidemic potential.', symptoms:['Fever, headache, and muscle pain','Dizziness, drowsiness, and altered consciousness','Encephalitis — confusion, seizures, coma','Respiratory distress in some outbreaks','Rapid deterioration over 1-2 weeks'], causes:['Nipah virus — paramyxovirus','Natural host: Pteropus fruit bats (flying foxes)','Humans infected through eating fruits contaminated by bat saliva or urine','Drinking raw date palm sap lapped by bats','Person-to-person spread in close contact (healthcare settings, family)'], homecare:['Avoid eating fruits that may have been partially eaten by bats','Avoid raw date palm sap — especially in Bangladesh and India','Healthcare workers must use full PPE when treating suspected Nipah cases','No vaccine currently available — prevention is the only protection'], whenToSeeDoctor:'Immediately — any unexplained encephalitis with high fever in Nipah-endemic areas (Bangladesh, India, Malaysia) requires urgent hospital isolation. Nipah is a notifiable disease. Healthcare worker contact must be traced and monitored.', urgency:'high' },

  { name:'West Nile Virus', aliases:['west nile virus','wnv','west nile fever','west nile encephalitis','culex mosquito virus'], emoji:'🦟', type:'infectious', description:'A viral infection transmitted by Culex mosquitoes. Most infected people have no symptoms. About 1 in 5 develop West Nile fever. Less than 1% develop life-threatening neurological disease (encephalitis or meningitis). Birds are the main reservoir.', symptoms:['Most cases: no symptoms (80%)','West Nile fever: fever, headache, body aches, rash, fatigue — lasts days to weeks','Severe neurological disease (rare): high fever, stiff neck, confusion, seizures, muscle weakness, paralysis'], causes:['West Nile Virus (flavivirus)','Transmitted by bites of Culex mosquitoes','Birds are the amplifying hosts — mosquitoes pick up the virus from birds','Not spread person-to-person (except rarely via blood transfusion, organ transplant, or pregnancy)'], homecare:['Use mosquito repellent (DEET) on exposed skin outdoors','Wear long sleeves and pants at dawn and dusk','Install and repair window and door screens','Eliminate standing water around home — Culex mosquitoes breed in still water','Report dead birds to local authorities — they can indicate WNV activity'], whenToSeeDoctor:'See a doctor if fever and headache develop after mosquito exposure. Seek emergency care immediately for confusion, extreme muscle weakness, or stiff neck — these suggest severe neurological West Nile disease. No specific antiviral treatment — supportive care.', urgency:'medium' },

  { name:'Scrub Typhus', aliases:['scrub typhus','tsutsugamushi disease','mite fever','chigger fever','orientia tsutsugamushi','scrub typhus fever'], emoji:'🪲', type:'infectious', description:'A disease caused by Orientia tsutsugamushi bacteria transmitted by the bite of larval trombiculid mites (chiggers) in scrub, grassland, or forest areas in Asia-Pacific. Often missed due to non-specific symptoms. A characteristic eschar (black scab at bite site) aids diagnosis.', symptoms:['Fever, headache, and muscle pain appearing 6-21 days after mite bite','Characteristic eschar (painless black scab) at the mite bite site','Rash starting on the trunk and spreading to limbs','Swollen lymph nodes near the eschar','Complications in untreated cases: pneumonia, myocarditis, meningitis'], causes:['Orientia tsutsugamushi bacteria transmitted by chigger mite larvae','Mites live in transitional zones between scrub and forest','Exposure during outdoor activities, farming, or military operations in Asia-Pacific'], homecare:['Wear protective clothing (long sleeves, pants tucked into socks) in scrub areas','Apply insect repellent (DEET) to skin and permethrin to clothing','Check for small red dots (mite bites) on skin after outdoor exposure — especially in skin folds','Shower and change clothes after outdoor activities in endemic areas'], whenToSeeDoctor:'Any fever after outdoor exposure in Asia-Pacific should include evaluation for scrub typhus. Check for an eschar. Doxycycline is highly effective and must be started early. Untreated scrub typhus can be fatal. Do not wait for test results if clinical suspicion is high.', urgency:'high' },

  { name:'Rocky Mountain Spotted Fever', aliases:['rocky mountain spotted fever','rmsf','rickettsia tick fever','spotted fever rickettsia','tick borne rash fever'], emoji:'🕷️', type:'infectious', description:'A serious tick-borne infection caused by Rickettsia rickettsii. Despite its name, occurs throughout the Americas. Can be fatal within days if not treated promptly. A characteristic spotted rash often appears on the wrists and ankles.', symptoms:['Sudden high fever, severe headache','Muscle aches and nausea','Spotted rash (may appear 2-5 days after fever) — typically starts on wrists and ankles, spreads to trunk, palms, and soles','Rash may become petechial (pinpoint hemorrhages)','Abdominal pain','Rapid deterioration if untreated — vascular damage, organ failure'], causes:['Rickettsia rickettsii bacteria','Transmitted by Dermacentor (dog tick) and other tick species','Tick must be attached for 4-6 hours to transmit infection','Outdoor activities in tick-endemic areas'], homecare:['Always check for ticks after outdoor activities — check all body folds','Remove ticks promptly with fine-tipped tweezers — grasp close to skin and pull steadily upward','Do not crush, burn, or twist the tick','Use tick repellent (DEET or permethrin)','Begin antibiotics (doxycycline) immediately if RMSF is suspected — do not wait for test results'], whenToSeeDoctor:'Immediately if fever, headache, and rash develop after a tick bite. RMSF is treated with doxycycline which must be started as early as possible — delays in treatment cause severe complications and death. Never wait for laboratory confirmation if suspicion is high.', urgency:'high' },

  { name:'Leishmaniasis', aliases:['leishmaniasis','kala-azar','visceral leishmaniasis','cutaneous leishmaniasis','sandfly fever','black fever','dum-dum fever'], emoji:'🦟', type:'infectious', description:'A parasitic disease transmitted by the bite of infected sandflies. Three main forms: cutaneous (skin sores), mucocutaneous (mouth and nose), and visceral (kala-azar — internal organs). Visceral form is fatal without treatment.', symptoms:['Cutaneous: painless skin ulcer with raised edges at the bite site','Visceral (kala-azar): prolonged irregular fever, significant weight loss, weakness, enlarged spleen and liver, darkening of skin','Mucocutaneous: destructive lesions of mouth, nose, and throat'], causes:['Leishmania parasites','Transmitted by bites of female Phlebotomus sandflies','Sandflies breed in cracks in walls, rubble, and dense vegetation','Animal reservoirs: dogs, rodents'], homecare:['Use insect repellent (DEET) and permethrin-treated clothing and bed nets','Use fine-mesh nets over beds and windows — sandflies are very small','Avoid outdoor activity at peak sandfly times (dusk to dawn)','Treat infected dogs to reduce animal reservoir'], whenToSeeDoctor:'See a doctor if you develop a non-healing skin ulcer after travel to endemic areas, or have prolonged fever with enlarged spleen and liver. Visceral leishmaniasis requires specific antiparasitic treatment (liposomal amphotericin B, miltefosine) and is fatal without treatment.', urgency:'high' },

  { name:'Filariasis', aliases:['filariasis','lymphatic filariasis','wuchereria bancrofti','lymphedema tropical','mosquito worm','tropical swelling disease'], emoji:'🦟', type:'infectious', description:'A parasitic infection caused by filarial worms transmitted by mosquitoes. The worms infect the lymphatic system, causing lymphedema (swelling of limbs) and — in chronic infection — elephantiasis (massive grotesque swelling). One of the leading causes of disability worldwide.', symptoms:['Acute: fever, pain, and swelling of lymph nodes','Lymphedema: swelling of arms, legs, or genitals from blocked lymph flow','Elephantiasis: massively swollen and hardened limbs or genitals in chronic disease','Hydrocele: fluid accumulation around testicles in men','Tropical pulmonary eosinophilia: cough and wheeze from immune reaction to microfilariae'], causes:['Wuchereria bancrofti, Brugia malayi, Brugia timori — filarial worms','Transmitted by mosquito bites (Culex, Anopheles, Aedes species depending on region)','Endemic in tropical and subtropical regions of Africa, Asia, South America'], homecare:['Take preventive annual doses of antifilarial drugs if offered in endemic areas (mass drug administration programs)','Use mosquito nets and repellent to prevent bites','Lymphedema management: daily limb washing, skin care, exercises, and elevation','Wear properly fitted compression garments for lymphedema'], whenToSeeDoctor:'See a doctor if recurrent fevers with limb swelling occur after living in endemic areas. Diethylcarbamazine (DEC), albendazole, and ivermectin are used for treatment. Lymphedema requires ongoing specialist management.', urgency:'medium' },

  { name:'Elephantiasis', aliases:['elephantiasis','massive limb swelling tropical','lymphatic elephantiasis','filarial elephantiasis','podoconiosis'], emoji:'🦵', type:'infectious', description:'The most severe manifestation of lymphatic filariasis — massive, disfiguring swelling of limbs (usually legs), genitals, or breasts due to chronic lymphatic damage from filarial worm infection. Extremely debilitating and stigmatizing. Also can occur from repeated soil exposure (podoconiosis).', symptoms:['Massive irreversible swelling of one or both legs, arms, or genitals','Skin becomes thickened, hardened, and warty in texture','Recurring acute inflammatory episodes (fever, pain, redness in affected limb)','Secondary bacterial skin infections are frequent','Severe social and functional disability'], causes:['Chronic lymphatic filariasis (Wuchereria bancrofti)','Long-standing lymphatic obstruction from repeated infections','Podoconiosis: from barefoot exposure to red volcanic soil in highland areas'], homecare:['Morbidity management is the focus — prevention of further swelling and infections','Daily limb washing with soap and water, moisturizing, and exercise','Elevation of limb when resting and at night','Prompt treatment of any bacterial skin infection on the swollen limb','Protective shoes and clothing to prevent soil exposure'], whenToSeeDoctor:'Elephantiasis requires specialist lymphedema management. Surgery (debulking) may help in some cases. Preventive antifilarial drugs can reduce progression if worms are still active. Psychological and social support are important aspects of care.', urgency:'medium' },

  { name:'River Blindness', aliases:['river blindness','onchocerciasis','onchocerca volvulus','black fly disease','nodding disease related','african river blindness'], emoji:'🦟', type:'infectious', description:'A parasitic infection caused by Onchocerca volvulus worms transmitted by blackflies breeding in fast-flowing rivers. The second leading infectious cause of blindness worldwide. The worms produce millions of microfilariae that migrate to the eyes and skin, causing severe damage.', symptoms:['Skin: intense itching, rash, skin nodules (containing adult worms), skin depigmentation and thickening','Eyes (chronic exposure): impaired vision, snowflake corneal opacities, eventual blindness','Ocular lesions develop silently over years','Nodules under the skin especially over bony prominences'], causes:['Onchocerca volvulus parasitic worm','Transmitted by Simulium blackfly bites near fast-flowing rivers','Endemic in sub-Saharan Africa, Yemen, and Latin America'], homecare:['Annual ivermectin is the cornerstone of treatment and prevention (mass drug administration programs)','Avoid areas with heavy blackfly activity near fast-flowing rivers in endemic regions','Wear protective clothing with long sleeves in endemic areas','Do not donate blood if you have or have had onchocerciasis'], whenToSeeDoctor:'See a doctor for skin nodules or vision changes after living in endemic areas. Ivermectin kills microfilariae and must be taken annually. Doxycycline kills the Wolbachia bacteria that the worms depend on, providing a more definitive treatment option.', urgency:'high' },

  { name:'Toxoplasmosis', aliases:['toxoplasmosis','toxoplasma gondii','cat litter infection','cat parasite','toxo','congenital toxoplasmosis'], emoji:'🐱', type:'infectious', description:'A parasitic infection caused by Toxoplasma gondii, one of the world\'s most common parasites. Usually harmless in healthy adults but extremely dangerous to pregnant women (risk of birth defects) and people with weakened immune systems.', symptoms:['Healthy adults: usually no symptoms, or mild flu-like illness with swollen lymph nodes','Immunocompromised: brain infection (toxoplasmic encephalitis) with headache, confusion, seizures','Congenital (newborn): eye damage, brain damage, jaundice, enlarged spleen and liver','Ocular: blurry vision, eye pain, sensitivity to light from retinal inflammation'], causes:['Toxoplasma gondii parasite','Cats are the definitive host — oocysts shed in cat feces','Humans infected via: raw or undercooked meat, contaminated produce, cat feces, soil, mother to fetus'], homecare:['Pregnant women should not clean cat litter boxes — delegate to someone else','Wear gloves when gardening and wash hands immediately after','Cook meat to safe internal temperatures — well done','Wash all fruits and vegetables before eating','Outdoor cats pose higher risk than indoor cats'], whenToSeeDoctor:'Pregnant women who suspect exposure should be tested immediately — treatment can prevent transmission to the fetus. Immunocompromised individuals with confusion or seizures need emergency evaluation. Specific antiparasitic treatment (pyrimethamine + sulfadiazine) is available.', urgency:'high' },

  { name:'Schistosomiasis', aliases:['schistosomiasis','bilharzia','blood fluke','swimmer\'s itch schistosoma','schistosoma infection','liver fluke water'], emoji:'🌊', type:'infectious', description:'A chronic parasitic disease caused by Schistosoma worms that penetrate the skin during contact with contaminated freshwater. Second most common parasitic disease globally after malaria. Affects mainly the urinary system (S. haematobium) or intestines and liver.', symptoms:['Swimmer\'s itch: itchy rash at point of skin penetration','Acute schistosomiasis (Katayama fever): fever, cough, muscle ache, abdominal pain, diarrhea','Chronic: blood in urine or stool, liver enlargement, portal hypertension, anemia, bladder cancer (S. haematobium)','Children: growth retardation and anemia'], causes:['Schistosoma haematobium, S. mansoni, S. japonicum','Freshwater snails release cercariae (larval worms) which penetrate human skin','Contact with contaminated lakes, rivers, and irrigation channels in endemic areas','Sub-Saharan Africa, Middle East, South America, Southeast Asia'], homecare:['Avoid swimming or wading in freshwater in endemic areas (the sea is safe)','If accidental exposure occurs, dry off quickly — vigorous toweling may reduce cercarial penetration','Do not use untreated freshwater for washing — use safe treated water','Participate in praziquantel mass treatment programs if offered in endemic areas'], whenToSeeDoctor:'See a doctor if blood in urine or stool occurs after freshwater exposure in endemic areas, or with fever and rash weeks after exposure. Praziquantel is highly effective treatment. One dose is curative in most cases.', urgency:'medium' },

  { name:'Trachoma', aliases:['trachoma','chlamydia trachomatis eye','chronic eye infection','trichiasis','blind eye infection','sandy disease'], emoji:'👁️', type:'infectious', description:'The world\'s leading infectious cause of blindness, caused by repeated Chlamydia trachomatis eye infections. Common in dry, impoverished communities with poor water access and sanitation. Repeated infections cause scarring of the eyelid that turns eyelashes inward, scratching the cornea.', symptoms:['Eye discharge (watery then mucopurulent)','Eye irritation, redness, and itching','In advanced stages: eyelid scarring (trachomatous scarring)','Trichiasis: eyelashes turning inward and scratching the cornea (extremely painful)','Corneal scarring causing vision loss and blindness'], causes:['Chlamydia trachomatis bacteria','Spreads through direct contact with eye or nasal discharge from an infected person','Flies carrying discharge from one person to another\'s eyes','Poor sanitation, crowded conditions, lack of clean water and access to latrines'], homecare:['Wash face at least once daily — even when water is scarce, clean face and hands reduce transmission significantly','Keep flies away from children\'s faces','Improve latrine use to reduce fly breeding sites','Complete the full course of prescribed antibiotic eye ointment or systemic antibiotics'], whenToSeeDoctor:'See a doctor for any persistent eye discharge in a child, or any eye irritation and vision changes in an endemic area. Surgery is needed for trichiasis to prevent blindness. Azithromycin is effective for early trachoma.', urgency:'medium' },

  { name:'Leprosy', aliases:['leprosy','hansen\'s disease','mycobacterium leprae','lepra','numbness skin patches','leprosy infection'], emoji:'🦠', type:'infectious', description:'A chronic infectious disease caused by Mycobacterium leprae, primarily affecting the skin, peripheral nerves, and upper respiratory tract. One of humanity\'s oldest diseases. Now curable with multidrug therapy. Contrary to popular belief, it is not highly contagious.', symptoms:['Skin patches — pale or reddish, often with reduced or absent sensation','Numbness or tingling in the hands and feet','Thickened, firm, or dry skin','Painless ulcers on the soles of the feet','Nosebleeds and nasal congestion','Muscle weakness especially in hands, feet, and eyelids','Painless lumps on the face, ears, and limbs'], causes:['Mycobacterium leprae (and M. lepromatosis)','Spread through droplets from the nose and mouth during prolonged close contact','Very poorly contagious — most people have natural immunity','Long incubation period of 5-20 years'], homecare:['Complete the full multidrug therapy course as prescribed (6-12 months minimum)','Care for numb hands and feet — inspect daily for injuries, wear protective footwear','Soak and oil hands and feet daily if skin is dry and cracked','Eye care if blinking is reduced — use lubricating eye drops and wear protective glasses'], whenToSeeDoctor:'See a doctor if you have unexplained, insensate skin patches with thickened skin. Early treatment prevents disability. Leprosy is NOT a reason for social exclusion — it is curable and far less contagious than other respiratory infections. Multidrug therapy (MDT) is provided free by WHO.', urgency:'medium' },

  { name:'Osteomyelitis', aliases:['osteomyelitis','bone infection','infected bone','staph bone infection','bone marrow infection','chronic bone infection'], emoji:'🦴', type:'infectious', description:'An infection of the bone caused by bacteria (most often Staphylococcus aureus) or occasionally fungi. Can be acute (recent onset) or chronic (long-standing). Can lead to bone death if untreated.', symptoms:['Deep bone pain (more severe than expected from surface appearance)','Swelling, warmth, and redness over the affected bone','Fever and chills','Difficulty moving the affected limb or joint','In children: refusal to use a limb or bear weight','Draining pus in chronic cases'], causes:['Staphylococcus aureus (most common)','Spreads to bone via bloodstream from another infection site','Direct infection from open fractures, surgery, or implants','Spread from adjacent soft tissue infection','Diabetes and peripheral vascular disease increase risk significantly'], homecare:['Take antibiotics for the full prescribed course — often 4-6 weeks or longer','Keep the affected area rested and elevated','Follow up regularly — treatment must be monitored by imaging','Control blood sugar if diabetic','Never skip antibiotic doses'], whenToSeeDoctor:'Any deep persistent bone pain with fever requires urgent medical assessment. Osteomyelitis requires prolonged antibiotics and sometimes surgery. Early treatment prevents chronic bone damage and bone death.', urgency:'high' },

  /* ── VIRAL ── */
  { name:'Rabies', aliases:['rabies','dog bite infection','rabies virus','hydrophobia','rabies encephalitis','bite animal virus'], emoji:'🐕', type:'infectious', description:'A fatal viral disease transmitted through the saliva of infected animals (dogs most commonly) via bites or scratches. Once symptoms develop, rabies is almost always fatal — making post-exposure prophylaxis (PEP) immediately after a bite critically important.', symptoms:['Prodromal stage: fever, headache, pain or tingling at bite site','Excitation stage: anxiety, confusion, agitation, hallucinations, excessive salivation','Hydrophobia — intense fear and spasms when trying to swallow water (classic sign)','Aerophobia — spasms triggered by air movement','Paralysis and coma follow','Death within days of symptom onset'], causes:['Rabies virus (lyssavirus)','Transmitted through bites or scratches from infected animals — dogs (95% of human cases), bats, foxes, cats, monkeys','Virus travels from the wound along nerves to the brain'], homecare:['After any bite or scratch from an animal — immediately and thoroughly wash the wound with soap and water for at least 15 minutes','Go to a hospital or clinic within hours — do not wait for symptoms','Post-exposure prophylaxis (vaccine + immunoglobulin) is nearly 100% effective if given before symptoms start','Vaccinate all pet dogs to eliminate the primary source'], whenToSeeDoctor:'IMMEDIATELY after any animal bite — especially from an unknown, stray, or sick animal. Do not wait for symptoms — by the time symptoms appear, it is almost always fatal. Wound washing and PEP must begin within hours of exposure for maximum effectiveness.', urgency:'high' },

  { name:'Ebola', aliases:['ebola','ebola virus disease','evd','ebola hemorrhagic fever','viral hemorrhagic fever','marburg related'], emoji:'☠️', type:'infectious', description:'A rare but severe and often fatal illness in humans caused by Ebola virus. Characterized by sudden onset of fever followed by hemorrhage (bleeding). Up to 90% case fatality rate in some outbreaks. Spreads through direct contact with bodily fluids of infected people.', symptoms:['Sudden fever, severe headache, muscle pain, and weakness','Vomiting and diarrhea (often bloody)','Rash','Impaired kidney and liver function','Hemorrhage: internal and external bleeding (red eyes, bleeding from gums, skin, and orifices in later stages)','Multi-organ failure'], causes:['Ebola virus (filovirus)','Spread through direct contact with blood, body fluids (saliva, sweat, vomit, semen, breast milk) of infected persons','Fruit bats (Pteropus) believed to be natural reservoir','Initial human infection from contact with infected animals (bats, monkeys, chimpanzees)'], homecare:['During an Ebola outbreak: avoid all contact with infected individuals without proper PPE','Do not touch the bodies of Ebola victims — burial teams with PPE must handle them','Wash hands frequently and avoid touching eyes, nose, and mouth','No specific home treatment — all suspected cases require immediate hospital isolation'], whenToSeeDoctor:'Immediately if in an outbreak area with fever, bleeding, and severe illness. Ebola requires specialist isolation units, supportive intensive care, and specific antiviral treatments (mAb114, REGN-EB3). All suspected cases are a public health emergency.', urgency:'high' },

  { name:'Monkeypox', aliases:['monkeypox','mpox','monkeypox virus','human monkeypox','pox rash infection','mpv'], emoji:'🐒', type:'infectious', description:'A viral disease caused by monkeypox virus (MPXV), related to but less severe than smallpox. Can spread through close contact with infected animals or between humans. Causes a distinctive pox rash. Declared a WHO Public Health Emergency of International Concern in 2022.', symptoms:['Fever, headache, muscle aches, and swollen lymph nodes (distinguishes from smallpox — lymph nodes not swollen in smallpox)','Rash appearing 1-5 days after fever — starts on face, spreads to body','Rash progresses through stages: flat spots → raised bumps → blisters → pustules → scabs','Rash may also appear on palms, soles, and genitals','Lesions are painful, deeply embedded, and all at the same stage'], causes:['Monkeypox virus (orthopoxvirus)','Animal-to-human: contact with infected rodents, monkeys, or their body fluids','Human-to-human: close physical contact including skin-to-skin, respiratory droplets, sexual contact','Contaminated materials (bedding, clothing)'], homecare:['Isolate at home until all lesions have fully scabbed and fallen off','Cover lesions with loose clothing or bandages','Do not share towels, bedding, or utensils','Wash hands frequently with soap and water','Take pain relievers for fever and lesion pain'], whenToSeeDoctor:'See a doctor if you develop a new rash with fever and swollen lymph nodes, or after sexual or close physical contact with a known case. Antiviral treatment (tecovirimat) is available for severe or high-risk cases. Vaccination (modified vaccinia Ankara) is available for high-risk contacts.', urgency:'high' },

  { name:'Smallpox', aliases:['smallpox','variola','variola major','variola virus','black pox','historical pox'], emoji:'⚠️', type:'infectious', description:'A highly contagious and deadly viral disease caused by the Variola virus. Eradicated globally in 1980 through vaccination — the only human disease to have been eradicated. Stocks of the virus are now only held at two WHO-authorized repositories. Historically had 30% case fatality rate.', symptoms:['High fever, severe headache, and back pain','After 2-4 days: distinctive rash appearing first on face and spreading to body','Rash progresses through macules → papules → vesicles → pustules → scabs','All lesions are at the same stage at any given time (unlike chickenpox)','Pitted scars (pockmarks) in survivors','Hemorrhagic form: widespread bleeding — almost universally fatal'], causes:['Variola major or Variola minor virus','Only known natural reservoir is humans','Spread through direct face-to-face contact with infected persons and respiratory droplets','Also spreads via contaminated bedding and clothing'], homecare:['No currently circulating natural smallpox exists — eradicated since 1980','Routine childhood smallpox vaccination ended in the 1970s in most countries','Stockpiles of vaccine are maintained for bioterrorism emergencies','If a suspected case occurs — call national public health emergency lines immediately'], whenToSeeDoctor:'Smallpox does not naturally circulate. Any case must be treated as a public health emergency and potential bioterrorism event. National emergency authorities must be alerted immediately. Vaccination, antiviral tecovirimat, and strict quarantine would be the response.', urgency:'high' },

  { name:'Yellow Fever', aliases:['yellow fever','yellow fever virus','flavivirus jungle fever','jaundice mosquito fever','yellow fever vaccine preventable'], emoji:'🦟', type:'infectious', description:'A viral hemorrhagic fever transmitted by Aedes aegypti mosquitoes. Named for the jaundice it causes. Most cases are mild, but 15% develop a severe, toxic phase with liver failure and hemorrhage. Preventable by a single highly effective vaccine.', symptoms:['Initial phase: fever, headache, muscle pain, nausea, vomiting — lasts 3-4 days','Most recover at this point','Toxic phase (15%): return of high fever, severe abdominal pain with vomiting, bleeding from eyes, mouth, and stomach, jaundice','Multi-organ failure and high mortality in the toxic phase'], causes:['Yellow Fever Virus (flavivirus)','Transmitted by Aedes mosquitoes — sylvatic (jungle) and urban cycles','Endemic in tropical Africa and South America'], homecare:['Vaccination is the most important prevention — provides lifelong immunity after a single dose','Required for entry into many countries (mandatory on international travel certificate)','Use mosquito repellent and wear protective clothing','Mosquito nets at night'], whenToSeeDoctor:'Any fever after travel to endemic areas requires medical assessment. Severe cases require hospital intensive care. No specific antiviral treatment — management is supportive. Vaccination should be done at least 10 days before travel to endemic regions.', urgency:'high' },

  { name:'Hantavirus', aliases:['hantavirus','hantavirus pulmonary syndrome','hvps','sin nombre virus','rodent virus','mouse droppings fever'], emoji:'🐀', type:'infectious', description:'A viral disease transmitted from rodents to humans through contact with infected rodent urine, droppings, or saliva. In the Americas, Hantavirus Pulmonary Syndrome (HPS) rapidly causes severe respiratory failure with high mortality.', symptoms:['Early: fever, severe muscle aches (especially thighs, hips, back), fatigue, nausea','Late (after 3-5 days): sudden cough, shortness of breath, and fluid in lungs (pulmonary edema)','Rapid respiratory failure requiring mechanical ventilation in HPS','Hemorrhagic fever with renal syndrome (HFRS) form in Asia/Europe: kidney failure'], causes:['Hantavirus — carried by rodents (deer mice, cotton rats, rice rats, white-footed mice)','Inhalation of aerosolized rodent urine, droppings, or saliva','Rodent bites (rare)','Not spread person-to-person (HPS form)'], homecare:['Seal holes and gaps in walls to prevent rodents from entering the home','Use snap traps or professional pest control rather than stirring up dust with brooms in infested areas','Wet-clean areas with rodent droppings before sweeping — use bleach solution','Wear an N95 mask when cleaning potentially contaminated spaces','Ventilate cabins, sheds, or buildings that have been closed before entering'], whenToSeeDoctor:'Immediately for any rapidly worsening respiratory illness after rodent exposure — HPS progresses from early symptoms to respiratory failure in hours. There is no specific antiviral treatment — intensive care with mechanical ventilation is required. Mortality remains 35-40% in HPS.', urgency:'high' },

  { name:'Norovirus', aliases:['norovirus','winter vomiting bug','norovirus gastroenteritis','stomach virus','cruise ship illness','vomiting bug'], emoji:'🤮', type:'infectious', description:'A highly contagious virus causing sudden onset of vomiting and diarrhea. The most common cause of acute gastroenteritis worldwide. Spreads extremely easily — a very small number of viral particles can cause infection. Most people recover within 1-3 days.', symptoms:['Sudden onset of nausea, vomiting (sometimes projectile)','Diarrhea','Stomach cramps and pain','Low-grade fever','Muscle aches and headache','Symptoms last 1-3 days'], causes:['Norovirus (calicivirus)','Spread through: contaminated food or water, person-to-person contact, touching contaminated surfaces then face','Extremely contagious — just 18 viral particles can cause infection','Survives on surfaces for days and is resistant to many disinfectants'], homecare:['Drink ORS frequently to prevent dehydration — especially important for children and elderly','Eat bland food as tolerated when vomiting eases','Stay home from work or school for at least 48 hours after last vomiting or diarrhea episode','Wash hands thoroughly with soap and water (alcohol gel does NOT kill norovirus)','Clean contaminated surfaces with bleach-based disinfectant (1:10 bleach solution)'], whenToSeeDoctor:'Most adults recover without medical care. See a doctor for: signs of dehydration in children or elderly (no urination, dry mouth, dizziness), blood in stool, or symptoms lasting more than 3 days. IV fluids may be needed for severe dehydration.', urgency:'low' },

  { name:'Rotavirus', aliases:['rotavirus','rotavirus diarrhea','baby diarrhea virus','infant gastroenteritis virus','rotaviral diarrhea','rotavirus vaccine'], emoji:'👶', type:'infectious', description:'The most common cause of severe diarrhea and dehydration in infants and young children worldwide. Before rotavirus vaccination, it caused nearly 500,000 child deaths per year globally. Highly preventable with an oral vaccine given in infancy.', symptoms:['Watery diarrhea lasting 3-8 days','Vomiting — usually precedes diarrhea','Fever','Severe dehydration — the main cause of death in children','Loss of appetite and fatigue','Older children and adults: usually asymptomatic or very mild'], causes:['Rotavirus — a segmented double-stranded RNA virus','Fecal-oral spread — contaminated hands, surfaces, food, and water','Extremely contagious — can remain infectious on hard surfaces for hours','Children under 5 most severely affected'], homecare:['Begin ORS immediately at the first sign of diarrhea — do not wait','Continue breastfeeding if applicable','Monitor for dehydration signs: sunken eyes, dry mouth, no tears, no urination for 6 hours, lethargy','Give zinc supplements as recommended in some guidelines','Wash hands thoroughly with soap and water before preparing food and after nappy changes'], whenToSeeDoctor:'Go to emergency if the child shows signs of severe dehydration, is unresponsive, or cannot keep any fluids down. Children under 6 months with rotavirus must be seen by a doctor. IV fluids may be needed. Rotavirus vaccination (2 oral doses in infancy) is highly protective.', urgency:'high' },

  { name:'Adenovirus', aliases:['adenovirus','adeno virus','adenovirus infection','adenovirus cold','adenovirus pink eye','adenovirus pneumonia','adenoviral disease'], emoji:'🦠', type:'infectious', description:'A family of common viruses that cause a wide range of illnesses including common colds, sore throat, bronchitis, pneumonia, pink eye (conjunctivitis), diarrhea, and urinary tract infections. Can be more severe in immunocompromised individuals.', symptoms:['Upper respiratory: runny nose, sore throat, cough, fever','Conjunctivitis: red, watery eyes with discharge','Gastrointestinal: diarrhea, vomiting, abdominal pain','Pneumonia: productive cough, fever, difficulty breathing','Urinary: painful urination, bloody urine (hemorrhagic cystitis)','Generally self-limiting in immunocompetent individuals'], causes:['Adenovirus — over 50 types','Spreads through respiratory droplets, direct contact, and fecal-oral route','Contaminated water (swimming pools not adequately chlorinated)','Survives on surfaces for days'], homecare:['Rest and drink plenty of fluids','Paracetamol for fever and pain relief','Wash hands frequently — especially after contact with an infected person','Clean and disinfect shared surfaces','Stay home from school or work during acute illness'], whenToSeeDoctor:'See a doctor for difficulty breathing, high fever lasting more than 5 days, severe conjunctivitis, or any adenovirus illness in an immunocompromised person. Antiviral treatment (cidofovir) is used only in severe cases in immunocompromised patients.', urgency:'low' },

  { name:'Cytomegalovirus', aliases:['cytomegalovirus','cmv','cmv infection','congenital cmv','cytomegalovirus disease','cmv retinitis'], emoji:'🦠', type:'infectious', description:'A common herpesvirus (HHV-5) that most people carry latently without any symptoms. Can cause serious disease in people with weakened immune systems (HIV/AIDS, transplant recipients) and significant birth defects when acquired by a pregnant woman (congenital CMV — the most common congenital infection).', symptoms:['Healthy adults: usually no symptoms, or mononucleosis-like illness','Immunocompromised: CMV retinitis (blindness), pneumonia, colitis, encephalitis','Congenital CMV: hearing loss, intellectual disability, vision loss, small head size (microcephaly)','Transplant recipients: fever, low white cell count, organ-specific disease'], causes:['Human cytomegalovirus (HHV-5)','Spreads through body fluids — saliva, urine, blood, breast milk, sexual contact','Pregnant women most commonly exposed through young children in daycare','Remains latent in the body for life after primary infection'], homecare:['Pregnant women should wash hands thoroughly after changing nappies or handling toys of young children','Avoid sharing cups, utensils, or kissing young children on the mouth if pregnant','Immunocompromised individuals should take antiviral prophylaxis as prescribed'], whenToSeeDoctor:'Immunocompromised individuals with unexplained fever, vision changes, or diarrhea need urgent CMV evaluation. All babies born with confirmed congenital CMV should receive antiviral treatment (valganciclovir) and hearing assessments. Antivirals (ganciclovir, valganciclovir) are used for treatment.', urgency:'medium' },

  { name:'Epstein-Barr Virus', aliases:['epstein barr virus','ebv','epstein barr','herpesvirus 4','ebv infection','hhv-4'], emoji:'🦠', type:'infectious', description:'A ubiquitous herpesvirus (HHV-4) that infects over 95% of adults worldwide. Primary infection typically causes infectious mononucleosis (glandular fever). Remains latent for life and is associated with several cancers (Burkitt lymphoma, nasopharyngeal carcinoma, Hodgkin lymphoma).', symptoms:['Primary infection (mono): fever, severe sore throat, swollen lymph nodes in neck, profound fatigue, enlarged spleen','Rash — especially if amoxicillin is given (classic clue)','Jaundice in some cases','Fatigue can persist for months (post-viral fatigue)','Most adults: previously infected, no new symptoms'], causes:['Epstein-Barr Virus (herpesvirus 4)','Spreads through saliva ("kissing disease")','Also through blood transfusion and organ transplantation','Reactivates in immunocompromised individuals'], homecare:['Rest during the acute phase — fatigue can be severe','Drink plenty of fluids for sore throat (cold drinks, ice cream)','Do not take amoxicillin or ampicillin — causes severe rash in EBV infection','Avoid contact sports for at least 4 weeks if spleen is enlarged — risk of rupture'], whenToSeeDoctor:'See a doctor for severe sore throat with significant lymph node swelling and fatigue. Avoid amoxicillin — inform the doctor of EBV suspicion. Seek emergency care for sudden severe left abdominal pain (splenic rupture). Fatigue lasting more than 3 months needs investigation for CFS/ME.', urgency:'medium' },

  { name:'Mononucleosis', aliases:['mononucleosis','mono','glandular fever','kissing disease','infectious mononucleosis','ebv mono','epstein barr mono'], emoji:'😴', type:'infectious', description:'An infectious disease caused by primary Epstein-Barr Virus (EBV) infection, most common in adolescents and young adults. Characterized by a triad of fever, sore throat, and swollen lymph nodes, with profound fatigue that can last weeks to months.', symptoms:['Severe sore throat (often the most painful of their life)','Profoundly swollen, tender lymph nodes in the neck (and sometimes armpits and groin)','High fever','Extreme fatigue that may last weeks to months','Enlarged spleen (splenomegaly) in up to 50%','Rash (especially if amoxicillin given)','Mild jaundice in some'], causes:['Epstein-Barr Virus (HHV-4)','Spread through saliva — kissing, sharing cups, coughing','Most common in teenagers and young adults (primary infection in childhood is usually asymptomatic)'], homecare:['Rest is the primary treatment — do not rush recovery','Eat soft, cold foods for sore throat — ice cream, cold drinks, smoothies','Paracetamol or ibuprofen for fever and throat pain','Avoid all contact sports, heavy lifting, and vigorous exercise for at least 4-6 weeks — spleen rupture risk','Do not take amoxicillin or ampicillin'], whenToSeeDoctor:'See a doctor for severe throat pain to exclude strep throat and confirm EBV. Seek emergency care for sudden severe left abdominal pain — this could be splenic rupture (medical emergency). Also see doctor if jaundice, difficulty breathing, or extreme weakness develops.', urgency:'medium' },

  { name:'Herpes Simplex', aliases:['herpes simplex','hsv','cold sore','oral herpes','genital herpes','hsv-1','hsv-2','herpes virus'], emoji:'💋', type:'infectious', description:'A very common viral infection caused by Herpes Simplex Virus (HSV-1 and HSV-2). HSV-1 typically causes oral herpes (cold sores); HSV-2 typically causes genital herpes. Once infected, the virus remains latent in nerves and can reactivate. Not curable but very manageable.', symptoms:['Tingling, itching, or burning sensation at the site before an outbreak (prodrome)','Small, painful fluid-filled blisters that break and form sores','Oral herpes: sores around mouth, lips, or gums (cold sores)','Genital herpes: sores on genitals, buttocks, or thighs','Flu-like symptoms during first outbreak (fever, swollen lymph nodes)','Sores heal within 1-2 weeks'], causes:['Herpes Simplex Virus type 1 (primarily oral) and type 2 (primarily genital)','Spreads through skin-to-skin contact — kissing (HSV-1), sexual contact (HSV-2)','Can spread even when no sores are visible (asymptomatic shedding)','From mother to newborn during delivery (neonatal herpes — serious)'], homecare:['Avoid touching sores and wash hands immediately if you do','Do not kiss infants or young children if you have an active cold sore — neonatal herpes is very dangerous','Inform partners about herpes status — use condoms to reduce transmission risk','Antiviral medications (acyclovir, valacyclovir) reduce outbreak severity and duration','Cold compresses and topical creams relieve discomfort'], whenToSeeDoctor:'See a doctor for first outbreak or uncertain diagnosis. Seek emergency care if newborn has signs of herpes (blisters, fever within weeks of birth). Pregnant women with genital herpes need obstetric management. Daily suppressive antivirals can reduce transmission significantly.', urgency:'medium' },

  { name:'Herpes Zoster', aliases:['herpes zoster','shingles','zoster','varicella zoster reactivation','nerve pain rash','chickenpox reactivation'], emoji:'🔥', type:'infectious', description:'A painful rash caused by reactivation of the Varicella-Zoster Virus (the same virus that causes chickenpox) from its latent state in nerve tissue. Can occur in anyone who has had chickenpox. Risk increases with age and immune suppression.', symptoms:['Pain, burning, or tingling in a band-like area on one side of the body','Sensitivity to touch in the affected area','Fluid-filled blisters in a stripe or belt pattern following a dermatome (nerve path)','Rash typically on the torso but can affect face, eye, or other areas','Fever and headache','Post-herpetic neuralgia: severe nerve pain persisting months to years after rash heals'], causes:['Varicella-Zoster Virus (VZV) reactivating from dorsal root ganglia','Risk factors: age over 50, immune suppression (HIV, chemotherapy, steroids), stress','Not caused by contact with chickenpox after initial infection'], homecare:['Keep the rash clean and dry','Wear loose, non-irritating clothing over the rash','Cool wet compresses may ease discomfort','Do not burst the blisters','Avoid contact with pregnant women, newborns, and immunocompromised individuals during active rash'], whenToSeeDoctor:'See a doctor within 72 hours of rash onset — antiviral medications (acyclovir, valacyclovir) are most effective when started early. Seek urgent care if rash is near the eye (herpes ophthalmicus) — can cause blindness. Shingles vaccination recommended for those over 50.', urgency:'high' },

  { name:'Shingles', aliases:['shingles','shingles rash','herpes zoster shingles','zoster nerve pain','painful rash one side','chickenpox nerve reactivation'], emoji:'🔥', type:'infectious', description:'The common name for Herpes Zoster — a painful, blistering rash caused by reactivation of the chickenpox virus from nerve tissue. One in three people will develop shingles in their lifetime. Complications include severe, long-lasting nerve pain (post-herpetic neuralgia) and vision loss.', symptoms:['Stabbing or burning pain on one side of the body or face','Sensitivity and pain to even light touch in the affected area (allodynia)','Distinctive stripe of fluid-filled blisters following a nerve path on one side','Rash typically clears in 2-4 weeks','Post-herpetic neuralgia: severe pain in the rash area lasting months to years'], causes:['Varicella-Zoster Virus reactivation','Occurs in those with previous chickenpox infection','Immune system weakening with age or illness allows reactivation'], homecare:['Begin antiviral medication immediately when rash appears — within 72 hours for maximum effect','Calamine lotion and cool compresses reduce itching and discomfort','Keep blisters uncovered or covered only with a light non-sticky dressing','Paracetamol or prescription pain medication for nerve pain'], whenToSeeDoctor:'See a doctor urgently as soon as the distinctive one-sided rash appears — ideally within 24-72 hours for antivirals to be most effective. Emergency care for eye involvement, facial nerve involvement (Ramsay Hunt syndrome), or immune suppression with shingles.', urgency:'high' },

  { name:'HPV', aliases:['hpv','human papillomavirus','hpv infection','hpv virus','cervical hpv','wart virus','hpv cancer'], emoji:'🦠', type:'infectious', description:'Human Papillomavirus — the most common sexually transmitted infection worldwide. Over 200 strains exist. Low-risk strains cause genital warts; high-risk strains cause cervical cancer, throat cancer, anal cancer, and other cancers. Preventable by vaccination. Most infections clear on their own.', symptoms:['Most infections: no symptoms at all','Genital warts (low-risk strains): soft, flesh-colored warts in the genital area','Abnormal cervical cells (high-risk strains): detected on Pap smear — no symptoms until cancerous','Throat HPV: usually no symptoms; associated with oropharyngeal cancer'], causes:['Human Papillomavirus — more than 200 strains','Transmitted through sexual contact — vaginal, anal, oral sex','Skin-to-skin genital contact even without penetration','Can be transmitted even without visible warts or symptoms'], homecare:['HPV vaccination before sexual debut is highly effective (Gardasil, Cervarix)','Regular Pap smears (cervical screening) detect precancerous changes before cancer develops','Use condoms — reduces but does not eliminate HPV transmission','No treatment for the infection itself — treatments target the warts or cell changes it causes'], whenToSeeDoctor:'All women should attend regular cervical screening (Pap smear) as recommended. See a doctor for any new genital warts. Anyone aged 9-26 should receive HPV vaccination. Discuss with doctor if older vaccination is appropriate.', urgency:'medium' },

  { name:'Genital Warts', aliases:['genital warts','condyloma acuminata','hpv warts','genital warts hpv','condylomata','anogenital warts'], emoji:'🦠', type:'infectious', description:'Soft, skin-colored growths in the genital area caused by low-risk strains of Human Papillomavirus (primarily HPV 6 and 11). Not cancerous, but can be uncomfortable, spread to sexual partners, and cause significant psychological distress.', symptoms:['Single or multiple soft, flesh-colored or pink bumps in the genital area','May be flat, raised, or cauliflower-like in appearance','Usually painless, but may itch, burn, or bleed','Can appear on penis, scrotum, vulva, vagina, cervix, anus, or thighs','In women, warts inside the vagina or cervix may only be detected on examination'], causes:['HPV types 6 and 11 (low-risk HPV strains)','Transmitted through direct sexual contact — vaginal, anal, or oral sex','Condoms reduce but do not eliminate transmission risk since warts may extend to uncovered areas'], homecare:['Do not attempt to remove genital warts with over-the-counter wart removers — these are not suitable for genital use','Inform sexual partners so they can be checked','Abstain from sexual contact or use condoms during treatment period','Avoid smoking — it increases HPV persistence and recurrence'], whenToSeeDoctor:'See a doctor for all genital warts — several treatment options exist (cryotherapy, laser, topical prescription treatments such as imiquimod or podophyllotoxin). Warts may recur. HPV vaccination even after wart diagnosis may prevent other HPV strain infections.', urgency:'medium' },

  { name:'HIV', aliases:['hiv','human immunodeficiency virus','hiv infection','hiv positive','retrovirus','hiv1','hiv2'], emoji:'🔴', type:'infectious', description:'Human Immunodeficiency Virus — a retrovirus that attacks the CD4+ T cells of the immune system, gradually weakening it. Without treatment, HIV progresses to AIDS. With antiretroviral therapy (ART), people with HIV can live long, healthy lives and have near-normal life expectancy. Not curable but highly manageable.', symptoms:['Acute HIV (2-4 weeks after infection): fever, rash, swollen lymph nodes, sore throat, muscle aches (flu-like)','Asymptomatic phase: no symptoms for years while virus slowly damages immune system','Advanced HIV/AIDS: opportunistic infections (pneumocystis pneumonia, CMV, toxoplasmosis), unusual cancers, severe weight loss'], causes:['Human Immunodeficiency Virus (HIV-1 and HIV-2)','Transmitted through: unprotected sexual intercourse, sharing needles, blood transfusion, mother to child (during pregnancy, birth, or breastfeeding)','Not spread through casual contact — saliva, sweat, tears, or air'], homecare:['Take antiretroviral therapy (ART) exactly as prescribed — never skip doses','Attend regular medical reviews to monitor CD4 count and viral load','Use condoms consistently to prevent transmission to partners','PrEP (pre-exposure prophylaxis) — effective prevention for HIV-negative high-risk individuals','Inform sexual partners and encourage testing'], whenToSeeDoctor:'Get tested if you have had any HIV risk exposure. HIV testing is available at all hospitals and many clinics. Early ART initiation preserves immune function, prevents AIDS, and prevents transmission to others. PEP (post-exposure prophylaxis) must be started within 72 hours of high-risk exposure.', urgency:'high' },

  { name:'AIDS', aliases:['aids','acquired immunodeficiency syndrome','hiv aids','advanced hiv','end stage hiv','acquired immune deficiency syndrome'], emoji:'🔴', type:'infectious', description:'Acquired Immunodeficiency Syndrome — the most advanced stage of HIV infection, characterized by severe immune suppression (CD4 count below 200 cells/μL). Makes a person highly vulnerable to life-threatening opportunistic infections and certain cancers. Preventable with early HIV treatment.', symptoms:['Rapid, unexplained weight loss (wasting syndrome)','Recurring fever and drenching night sweats','Extreme fatigue','Prolonged swollen lymph nodes','Diarrhea lasting more than a week','Sores in the mouth, genitals, or anus','Pneumonia — pneumocystis pneumonia is the most common AIDS-defining illness','Memory loss and confusion','Skin lesions — Kaposi sarcoma (purple lesions)'], causes:['Untreated or inadequately treated HIV infection','CD4 cell count falling below 200 cells/μL or development of AIDS-defining illness'], homecare:['Begin or resume antiretroviral therapy immediately — this is the most critical intervention','Treat all opportunistic infections as they arise with specific medications','Take prophylactic medications to prevent opportunistic infections (trimethoprim-sulfamethoxazole, azithromycin, fluconazole)','Eat a nutritious diet and maintain hygiene to support remaining immune function'], whenToSeeDoctor:'Immediately — AIDS requires urgent specialist HIV care. ART initiated even at this late stage can reconstitute the immune system to a significant degree. Each opportunistic infection must be diagnosed and treated specifically. Palliative care coordination is also important.', urgency:'high' },

  { name:'Syphilis', aliases:['syphilis','treponema pallidum','primary syphilis','secondary syphilis','tertiary syphilis','lues','congenital syphilis','painless sore sti'], emoji:'🦠', type:'infectious', description:'A sexually transmitted bacterial infection caused by Treponema pallidum. Progresses through distinct stages (primary, secondary, latent, tertiary) over years if untreated. Highly curable with penicillin at any stage but can cause serious heart, brain, and organ damage if neglected.', symptoms:['Primary: single painless sore (chancre) at infection site — often missed because it is painless','Secondary (4-10 weeks later): non-itchy rash on palms and soles, flu-like illness, mucous patches in mouth','Latent: no symptoms but still infected','Tertiary: gummas (soft tissue damage), heart and aorta damage, neurosyphilis (brain damage), blindness'], causes:['Treponema pallidum bacteria','Transmitted through sexual contact — vaginal, anal, oral sex','Sores make transmission very easy even with brief contact','Mother to fetus during pregnancy (congenital syphilis — causes birth defects and stillbirth)'], homecare:['Take the full prescribed antibiotic course — single penicillin injection for early syphilis','Inform all recent sexual partners so they can be tested and treated','Abstain from sex until treatment is complete and confirmed cured (blood test)','Use condoms consistently to reduce future risk'], whenToSeeDoctor:'See a doctor for any painless genital sore or unexplained rash on palms and soles. All pregnant women should be screened for syphilis. Syphilis is fully curable with penicillin at all stages — treatment of later stages prevents further damage. Sexual partners must be traced and treated.', urgency:'high' },

  { name:'Gonorrhea', aliases:['gonorrhea','gonorrhoea','the clap','neisseria gonorrhoeae','gonococcal infection','urethral discharge','gonorrhea sti'], emoji:'🦠', type:'infectious', description:'A sexually transmitted bacterial infection caused by Neisseria gonorrhoeae. Can infect the genitals, rectum, and throat. A leading cause of pelvic inflammatory disease and infertility in women. Antibiotic resistance is a growing major concern.', symptoms:['Men: burning urination, white, yellow, or green urethral discharge, painful testicles','Women: often no symptoms or mild increase in vaginal discharge, burning urination, pelvic pain','Rectal infection: discharge, anal itching, or soreness','Throat infection: sore throat (usually mild)','Disseminated: fever, joint pain, skin rash — if bacteria spread to bloodstream'], causes:['Neisseria gonorrhoeae bacteria','Transmitted through unprotected vaginal, anal, or oral sex','Can infect eyes if contaminated hands touch eyes (gonococcal conjunctivitis)','Newborns can be infected during delivery'], homecare:['Take the prescribed antibiotics for the complete course — often a single injection (ceftriaxone) plus oral azithromycin','Inform all recent sexual partners so they can be tested and treated','Abstain from sex until 7 days after treatment and symptoms have resolved','Use condoms consistently for future prevention'], whenToSeeDoctor:'See a doctor for any genital discharge or pain. Gonorrhea is diagnosed by urine test or swab. Growing antibiotic resistance makes it essential to have a sensitivity test and take the correct prescribed antibiotics. Test of cure (retest after treatment) is recommended for gonorrhea.', urgency:'high' },

  { name:'Chlamydia', aliases:['chlamydia','chlamydia trachomatis','chlamydia infection','chlamydial infection','sti chlamydia','silent sti'], emoji:'🦠', type:'infectious', description:'The most common bacterial sexually transmitted infection worldwide, caused by Chlamydia trachomatis. Often called the "silent infection" because most people (especially women) have no symptoms. Can cause pelvic inflammatory disease, infertility, and ectopic pregnancy if untreated.', symptoms:['Most women: no symptoms','Women when symptomatic: unusual vaginal discharge, burning urination, pelvic pain','Men: burning urination, discharge from penis, testicular pain','Rectal infection: discharge, pain, or bleeding from anus','Both sexes: chlamydia can infect the throat (usually asymptomatic)'], causes:['Chlamydia trachomatis bacteria','Transmitted through unprotected vaginal, anal, or oral sex','From mother to infant during childbirth (can cause eye and lung infection in newborn)'], homecare:['Take the full prescribed antibiotic course — doxycycline for 7 days or single-dose azithromycin','Abstain from sex until you and your partner have completed treatment','Inform all recent sexual partners so they can be tested and treated','Use condoms consistently for future prevention'], whenToSeeDoctor:'Annual chlamydia testing is recommended for all sexually active people under 25. Get tested if you have had unprotected sex or new partners. Chlamydia is fully curable with antibiotics. Treating both partners simultaneously prevents re-infection.', urgency:'medium' },

  { name:'Pelvic Inflammatory Disease', aliases:['pelvic inflammatory disease','pid','pelvic infection','fallopian tube infection','salpingitis','sti pid','uterus infection'], emoji:'🔴', type:'infectious', description:'An infection of the female reproductive organs — including the uterus, fallopian tubes, and ovaries — usually caused by sexually transmitted bacteria (chlamydia or gonorrhea). If untreated, leads to chronic pelvic pain, infertility, and ectopic pregnancy.', symptoms:['Lower abdominal and pelvic pain (most common symptom)','Fever and chills','Unusual or increased vaginal discharge (may be foul-smelling)','Painful intercourse','Painful or burning urination','Irregular menstrual bleeding','In severe cases (tubo-ovarian abscess): severe pain, high fever, nausea, vomiting'], causes:['Chlamydia trachomatis or Neisseria gonorrhoeae (most common STIs causing PID)','Bacteria from vagina and cervix ascending to upper reproductive tract','Risk factors: multiple partners, unprotected sex, history of STIs, IUD insertion'], homecare:['Take the complete prescribed antibiotic course — PID requires combination antibiotics for at least 14 days','Both you and your partner(s) should be tested and treated for STIs simultaneously','Rest during treatment','Abstain from sex until treatment is complete and confirmed resolved'], whenToSeeDoctor:'See a doctor promptly for lower abdominal pain in a sexually active woman. Severe PID with fever and vomiting requires hospitalization and IV antibiotics. Delay in treatment significantly increases the risk of infertility, ectopic pregnancy, and chronic pelvic pain.', urgency:'high' },

  { name:'Bacterial Vaginosis', aliases:['bacterial vaginosis','bv','bv infection','gardnerella vaginosis','vaginal infection','fishy vaginal discharge','vaginal dysbiosis'], emoji:'🦠', type:'infectious', description:'The most common vaginal infection in women of reproductive age — a disruption of the normal vaginal microbiome where Lactobacillus is replaced by an overgrowth of bacteria including Gardnerella vaginalis. Associated with but not exclusively an STI.', symptoms:['Thin, gray, or white vaginal discharge','Strong fishy odor especially after sex','Vaginal itching or burning (milder than thrush)','Some women have no symptoms'], causes:['Disruption of normal vaginal flora — overgrowth of Gardnerella, Prevotella, and other anaerobes','New or multiple sexual partners','Vaginal douching (strongly discouraged)','Smoking','Antibiotics disrupting normal flora'], homecare:['Avoid vaginal douching — it worsens and can cause BV','Use fragrance-free soaps for external genital washing only — not inside the vagina','Complete the full course of prescribed antibiotics (metronidazole or clindamycin)','Probiotics (Lactobacillus) after treatment may help restore healthy flora','Male partners do not need treatment; female partners may need to be assessed'], whenToSeeDoctor:'See a doctor for diagnosis — BV has specific antibiotic treatment. Untreated BV during pregnancy increases risk of preterm birth, so pregnant women should always seek treatment. Recurrent BV may require extended antibiotic courses or suppressive therapy.', urgency:'medium' },

  { name:'Candidiasis', aliases:['candidiasis','thrush','vaginal thrush','genital thrush','candida infection','yeast infection','candida albicans'], emoji:'🍄', type:'infectious', description:'A fungal infection caused by Candida species (most commonly Candida albicans). Can affect many parts of the body: vagina, penis, skin folds, mouth (oral thrush), esophagus, or bloodstream (invasive candidiasis). Very common and usually easily treatable.', symptoms:['Vaginal: thick white "cottage cheese" discharge, intense itching and burning, redness','Male genital: redness, itching, and rash on the head of the penis','Skin folds: red, itchy, moist rash in armpits, groin, under breasts','Invasive candidiasis: fever, chills in immunocompromised patients — very serious'], causes:['Candida albicans (most common) overgrowth when normal flora or immune balance is disrupted','Antibiotic use (kills bacteria allowing Candida overgrowth)','Uncontrolled diabetes (high glucose promotes Candida growth)','Immune suppression (HIV, chemotherapy, steroids)','Pregnancy','Tight synthetic underwear and poor ventilation'], homecare:['Apply antifungal cream (clotrimazole) to affected skin or genital area','Oral antifungal fluconazole tablet for vaginal thrush — single dose often sufficient','Wear loose, cotton underwear','Keep skin folds clean and dry','Control blood sugar if diabetic','Probiotics may help restore normal flora after antibiotic use'], whenToSeeDoctor:'See a doctor if: first-ever episode (to confirm diagnosis), recurrent infections (4+ per year — may indicate diabetes or immune issue), symptoms in men, severe infection, or if OTC treatment fails. Invasive candidiasis requires IV antifungal treatment.', urgency:'low' },

  { name:'Oral Thrush', aliases:['oral thrush','oral candidiasis','thrush mouth','candida mouth','white patches mouth','oral fungal infection'], emoji:'👄', type:'infectious', description:'A fungal infection of the mouth and throat caused by Candida albicans. Common in infants, elderly, denture wearers, inhaled steroid users, and immunocompromised individuals. Appears as white, creamy patches on the tongue and inside of the cheeks.', symptoms:['White, creamy patches on tongue, inner cheeks, gums, tonsils, or roof of mouth','Patches can be scraped off leaving a raw, red surface underneath','Redness and soreness in the mouth','Difficulty swallowing (if extends to throat)','Cracking at the corners of the mouth (angular cheilitis)','Loss of taste'], causes:['Candida albicans overgrowth in the mouth','Dentures (especially if not cleaned)','Inhaled corticosteroids (steroid inhalers for asthma)','Dry mouth from medications or mouth breathing','Antibiotics','Weakened immune system — HIV, chemotherapy, diabetes'], homecare:['Rinse mouth after using steroid inhalers — use a spacer device to reduce mouth deposition','Clean dentures thoroughly daily and remove overnight','Limit sugary foods — Candida thrives on sugar','Rinse mouth with diluted salt water','Take antifungal medications as prescribed (nystatin suspension, fluconazole tablet)'], whenToSeeDoctor:'See a doctor for white patches in the mouth — especially in adults and immunocompromised individuals. Nystatin or fluconazole are used for treatment. Recurrent or severe oral thrush in adults needs investigation for underlying immune suppression or diabetes.', urgency:'medium' },

  { name:'Tinea Versicolor', aliases:['tinea versicolor','pityriasis versicolor','skin discoloration fungal','malassezia skin','skin color patches fungal','white patches skin fungi'], emoji:'🍄', type:'infectious', description:'A common, non-contagious fungal skin condition caused by overgrowth of Malassezia yeasts that normally live on the skin. Causes patches of skin that are lighter or darker than surrounding skin. Common in warm, humid climates.', symptoms:['Patches of skin lighter or darker than surrounding skin — most obvious in tanned skin','Most common on chest, back, shoulders, and upper arms','Fine, scaly texture of the patches','Mild itching (usually mild or absent)','Patches do not tan in sunlight — may appear white in summer','May appear slightly pink or brown in fairer skin'], causes:['Malassezia globosa and furfur — yeasts normally present on skin','Overgrowth triggered by warm, humid weather, sweating, oily skin, or immune suppression'], homecare:['Apply antifungal shampoo (selenium sulfide or ketoconazole) to affected areas — leave for 5-10 minutes before showering','Repeat twice a week for 2-4 weeks','Shower and change clothes after sweating','Wear loose, breathable, light-colored clothing in hot weather','Skin color returns gradually over months after treatment — this is normal'], whenToSeeDoctor:'See a doctor if patches are widespread, not responding to OTC antifungal treatment, or repeatedly recurring. Oral antifungal treatment (fluconazole, itraconazole) is prescribed for widespread or recurrent tinea versicolor.', urgency:'low' },

  { name:'Aspergillosis', aliases:['aspergillosis','aspergillus infection','mold lung infection','aspergillus fumigatus','invasive aspergillosis','fungal lung infection'], emoji:'🍄', type:'infectious', description:'A range of conditions caused by Aspergillus mold, which is inhaled and normally harmless to healthy people. In immunocompromised individuals, it can cause life-threatening invasive infection of the lungs, sinuses, and brain. Allergic aspergillosis affects asthma and cystic fibrosis patients.', symptoms:['Allergic: wheezing, coughing, mucus plugs, worsening asthma','Aspergilloma (fungus ball): chronic cough, coughing blood, chest pain — in pre-existing lung cavities','Invasive (immunocompromised): fever, cough, chest pain, shortness of breath, rapid deterioration'], causes:['Aspergillus fumigatus (most common) and other Aspergillus species','Mold spores are everywhere in the environment — inhaled by everyone but only cause disease in susceptible individuals','Immunocompromised: chemotherapy, stem cell transplant, prolonged steroid use, HIV/AIDS'], homecare:['Immunocompromised individuals should wear N95 masks during construction or dusty activities','HEPA air filters in hospital rooms for high-risk patients','Avoid compost heaps, decaying leaves, and building construction if immunocompromised','Antifungal prophylaxis as prescribed for high-risk patients'], whenToSeeDoctor:'Immunocompromised individuals with new respiratory symptoms require urgent evaluation for invasive aspergillosis — it progresses rapidly and has high mortality. Voriconazole is the drug of choice for invasive aspergillosis. Diagnosis requires CT scan, culture, and galactomannan blood test.', urgency:'high' },

  { name:'Histoplasmosis', aliases:['histoplasmosis','histoplasma capsulatum','cave fever','spelunker\'s lung','ohio valley disease','bird droppings fungal infection'], emoji:'🍄', type:'infectious', description:'A fungal infection caused by Histoplasma capsulatum, found in soil enriched by bird or bat droppings. Endemic in the Mississippi and Ohio River Valleys of the USA, and parts of Central and South America. Inhaled from disturbed soil, most infections are mild or asymptomatic.', symptoms:['Most infections: no symptoms','Acute: flu-like illness — fever, cough, headache, muscle aches, fatigue','Severe pulmonary disease: progressive pneumonia-like illness in high exposure or immunocompromised','Disseminated (immunocompromised): fever, weight loss, enlarged liver and spleen, mouth sores'], causes:['Histoplasma capsulatum spores in soil with bird or bat droppings','Activities that disturb soil: caving (spelunking), demolition, construction, excavation in endemic areas','Bird roosts, chicken coops, old buildings with bat colonies'], homecare:['Wear a properly fitted N95 respirator when working in caves or disrupting soil in endemic areas','Wet soil before disturbing to reduce dust','HEPA vacuum instead of sweeping in contaminated areas'], whenToSeeDoctor:'See a doctor if respiratory illness develops after potential exposure — especially in endemic areas. Mild cases resolve without treatment. Moderate to severe cases and all immunocompromised patients need antifungal treatment (itraconazole or amphotericin B).', urgency:'medium' },

  { name:'Cryptococcosis', aliases:['cryptococcosis','cryptococcal meningitis','cryptococcus neoformans','pigeon droppings fungal','hiv fungal brain infection','crypto meningitis'], emoji:'🍄', type:'infectious', description:'A serious fungal infection caused by Cryptococcus neoformans or Cryptococcus gattii. Found in soil, pigeon droppings, and decaying wood. Primarily affects the lungs and can spread to the brain (cryptococcal meningitis) — a leading cause of meningitis in HIV patients.', symptoms:['Pulmonary: often asymptomatic or mild pneumonia-like illness','Cryptococcal meningitis: severe headache, fever, stiff neck, confusion, altered consciousness — can be insidious onset over weeks','In HIV patients: often subacute onset with headache and subtle confusion progressing over weeks'], causes:['Cryptococcus neoformans (mainly immunocompromised) and C. gattii (can affect healthy individuals)','Inhaling spores from pigeon droppings, decaying wood, or soil','Not spread person-to-person'], homecare:['HIV patients should take antifungal prophylaxis (fluconazole) when CD4 count is very low','Avoid exposure to pigeon droppings — if unavoidable, wear an N95 mask','ART in HIV patients is the most important prevention for cryptococcal disease'], whenToSeeDoctor:'Any headache with fever and confusion in an HIV patient or immunocompromised person requires urgent lumbar puncture to exclude cryptococcal meningitis. It is treated with amphotericin B plus flucytosine, then fluconazole. Mortality is high without treatment.', urgency:'high' },

  { name:'Mucormycosis (Black Fungus)', aliases:['mucormycosis','black fungus','mucor infection','rhizopus infection','covid black fungus','zygomycosis','black fungus infection'], emoji:'🍄', type:'infectious', description:'A rare but very aggressive and life-threatening fungal infection caused by molds from the Mucorales family (Rhizopus, Mucor, Cunninghamella). Gained global attention during the COVID-19 pandemic. Has a very high mortality rate even with treatment.', symptoms:['Rhino-orbital-cerebral (most common): one-sided facial pain and swelling, black necrotic lesion on palate or nasal mucosa, loss of vision, confusion — progresses rapidly','Pulmonary: cough, fever, chest pain, coughing blood','Cutaneous: black, necrotic wound after trauma','Disseminated: multi-organ failure'], causes:['Rhizopus, Mucor, Cunninghamella molds found in soil and decaying matter','Inhaled into sinuses and lungs, or inoculated through wounds','Risk factors: uncontrolled diabetes (especially diabetic ketoacidosis), prolonged corticosteroid use, immunosuppression, COVID-19 with steroid treatment'], homecare:['Strict blood sugar control in diabetics is the most important prevention','Avoid excessive corticosteroid use (use minimum effective dose for minimum duration)','Keep wounds clean and covered to prevent fungal inoculation','Report any black nasal discharge, nasal pain, or facial pain to a doctor immediately'], whenToSeeDoctor:'Immediately — mucormycosis is a surgical emergency. Black nasal/palatal discharge or necrosis in a diabetic or immunocompromised patient requires emergency surgical debridement and antifungal therapy (liposomal amphotericin B). Every hour of delay worsens outcomes.', urgency:'high' },

  /* ── CHILDHOOD / RESPIRATORY ── */
  { name:'Hand Foot and Mouth Disease', aliases:['hand foot and mouth disease','hfmd','hfm disease','coxsackievirus','blistering rash child','mouth sores toddler virus'], emoji:'👋', type:'infectious', description:'A common mild viral illness in children under 5, caused primarily by Coxsackievirus A16 and Enterovirus 71. Causes distinctive sores in the mouth and a rash on hands and feet. Usually resolves without treatment within 7-10 days.', symptoms:['Fever','Sore throat and painful mouth sores (ulcers on tongue, gums, inside of cheeks)','Red spots or blisters on palms of hands, soles of feet, and sometimes buttocks','Loss of appetite (due to mouth pain)','General malaise and fussiness in infants','Enterovirus 71 can rarely cause viral meningitis or encephalitis'], causes:['Coxsackievirus A16 (most common)','Enterovirus 71','Spreads through direct contact with saliva, blister fluid, respiratory droplets, and feces of infected children','Very contagious in daycare and preschool settings'], homecare:['Give paracetamol or ibuprofen for fever and pain','Offer cool fluids, ice chips, and soft foods to ease mouth pain — cold yogurt and ice cream help','Avoid acidic, spicy, or salty foods which irritate mouth sores','Keep child home from school until fever has resolved and sores have healed','Wash hands frequently especially after nappy changes'], whenToSeeDoctor:'See a doctor if the child has a fever above 39°C, is not drinking fluids, has severe headache or neck stiffness, appears very ill, or symptoms last more than 10 days. Seek emergency care for any seizure, confusion, or breathing difficulty.', urgency:'low' },

  { name:'Scarlet Fever', aliases:['scarlet fever','scarlatina','strep rash','strawberry tongue','sandpaper rash','streptococcal rash','scarlet rash'], emoji:'🔴', type:'infectious', description:'A bacterial infection caused by Group A Streptococcus (same bacteria that causes strep throat) that produces a toxin causing a characteristic red rash. Most common in children 5-15. Treated effectively with antibiotics to prevent complications such as rheumatic fever.', symptoms:['Bright red rash with sandpaper texture — starts on neck and trunk, spreads to limbs','Red face with pale area around the mouth (circumoral pallor)','Strawberry tongue — red, bumpy tongue with white coating initially','Sore throat and fever — may precede rash by 1-2 days','Flushed face','Chills and headache','Nausea'], causes:['Group A Streptococcus (Streptococcus pyogenes) producing an erythrogenic toxin','Spreads through respiratory droplets','Less commonly through infected skin (impetigo)'], homecare:['Give antibiotics for the full course as prescribed — 10 days of penicillin or amoxicillin','Give paracetamol or ibuprofen for fever and sore throat pain','Offer cool soft drinks and foods for throat comfort','Child can return to school 24 hours after starting antibiotics if feeling well','Keep child\'s utensils and towels separate during illness'], whenToSeeDoctor:'See a doctor promptly for the characteristic rash with sore throat. Full 10-day antibiotic course is essential to prevent rheumatic fever and glomerulonephritis. Follow up if rash worsens, new joint pain develops, or high fever persists beyond 48 hours of antibiotics.', urgency:'medium' },

  { name:'Diphtheria', aliases:['diphtheria','corynebacterium diphtheriae','bull neck disease','grey membrane throat','diphtheritic membrane'], emoji:'🦠', type:'infectious', description:'A serious bacterial infection caused by Corynebacterium diphtheriae, characterized by a thick gray membrane covering the throat and airway that can cause suffocation. Also produces a toxin that damages the heart and nerves. Preventable by DTP vaccination.', symptoms:['Sore throat and mild fever','Thick, gray membrane covering throat and tonsils — pathognomonic finding','Swollen lymph nodes causing "bull neck" appearance','Difficulty breathing or swallowing from airway obstruction','Nasal discharge (often blood-tinged)','Toxin effects: heart rhythm abnormalities, nerve paralysis','Hoarse voice'], causes:['Corynebacterium diphtheriae bacteria and the toxin it produces','Spreads through respiratory droplets and close contact','Unvaccinated or under-vaccinated populations at highest risk'], homecare:['This is a medical emergency — do NOT attempt home management','Ensure all family members and contacts are vaccinated (DTP)','Isolate the patient — diphtheria is highly contagious','Seek emergency medical care immediately'], whenToSeeDoctor:'Immediately — diphtheria can cause airway obstruction and death. Requires antitoxin (given as emergency) plus penicillin or erythromycin in hospital. Notify public health authorities immediately — all contacts require assessment and booster vaccination.', urgency:'high' },

  { name:'Whooping Cough (Pertussis)', aliases:['whooping cough','pertussis','bordetella pertussis','100 day cough','whoop cough','cough with whoop','infant pertussis'], emoji:'😮', type:'infectious', description:'A highly contagious respiratory illness caused by Bordetella pertussis bacteria, characterized by severe, uncontrollable coughing fits followed by a high-pitched "whoop" as the person breathes in. Can be fatal in infants. Preventable by pertussis vaccination.', symptoms:['Early stage (1-2 weeks): runny nose, mild cough — highly contagious at this stage','Paroxysmal stage (up to 10 weeks): intense coughing fits followed by high-pitched whoop','Turning blue or red in the face during fits','Vomiting after coughing fits','Extreme fatigue after fits','Infants: may not have the whoop but have periods of apnea (not breathing)'], causes:['Bordetella pertussis bacteria','Spreads very easily through respiratory droplets — one of the most contagious diseases known','Immunity from vaccination wanes over time — adults can spread to unvaccinated infants'], homecare:['Take antibiotics for the full course as prescribed (azithromycin or clarithromycin)','Eat small frequent meals to manage vomiting','Stay well hydrated','Rest and avoid activities that trigger coughing fits','Keep infants away from anyone with a cough during outbreaks'], whenToSeeDoctor:'All infants under 6 months with persistent cough or any apnea must be hospitalized — pertussis can be life-threatening in this age group. See a doctor for any prolonged coughing illness (over 2 weeks). Tdap booster vaccination is recommended for adults who will be around infants.', urgency:'high' },

  { name:'Polio', aliases:['polio','poliomyelitis','infantile paralysis','polio virus','poliovirus','flaccid paralysis child'], emoji:'🦽', type:'infectious', description:'A crippling and potentially fatal infectious disease caused by poliovirus. Can cause permanent paralysis. Nearly eradicated globally through vaccination — still present in very small pockets. Post-polio syndrome can cause new weakness decades after original infection.', symptoms:['Most infections (72%): no symptoms','Abortive polio: fever, sore throat, nausea — resolves within days','Non-paralytic polio: above symptoms plus stiff neck and back','Paralytic polio (1%): acute flaccid paralysis, usually of one or both legs — asymmetric, fever present when paralysis starts'], causes:['Poliovirus types 1, 2, and 3','Fecal-oral route — contaminated water and food','Oral-oral spread also possible','Unvaccinated individuals at risk'], homecare:['Oral Polio Vaccine (OPV) and Inactivated Polio Vaccine (IPV) — ensure complete vaccination from birth','Ensure safe water and sanitation to prevent fecal-oral transmission','Report any case of acute flaccid paralysis in a child under 15 to health authorities immediately'], whenToSeeDoctor:'Report any child under 15 with sudden-onset limb weakness to health authorities immediately — it is a notifiable emergency for global eradication efforts. Supportive care including physiotherapy is the treatment. No specific antiviral treatment exists.', urgency:'high' },

  { name:'Rubella', aliases:['rubella','german measles','three day measles','togavirus','rubella rash','congenital rubella'], emoji:'🌹', type:'infectious', description:'A contagious viral infection caused by the Rubella virus. Usually mild in children and adults but devastating if a pregnant woman is infected — especially in the first trimester, causing congenital rubella syndrome (cataracts, deafness, heart defects). Preventable by MMR vaccine.', symptoms:['Pink-red rash starting on face and spreading down the body — lasts about 3 days','Mild fever','Swollen lymph nodes behind the ears and neck (often the first sign)','Red, inflamed eyes (conjunctivitis)','Joint pain in older children and adults','Mild sore throat'], causes:['Rubella virus (togavirus)','Spreads through respiratory droplets','Highly contagious 1 week before to 1 week after rash appears','Congenital: infected mother transmits to fetus across placenta'], homecare:['Rest and take paracetamol for fever and discomfort','Isolate immediately from pregnant women — this is critical','Pregnant women must seek urgent medical advice if exposed to rubella','Ensure MMR vaccination is up to date in all children'], whenToSeeDoctor:'Pregnant women with any rubella exposure or symptoms should seek emergency advice — congenital rubella syndrome can cause severe birth defects. All children should receive two doses of MMR vaccine. Adults born before mass vaccination should check their immunity status.', urgency:'high' },

  { name:'Roseola', aliases:['roseola','roseola infantum','exanthem subitum','sixth disease','baby rash after fever','hhv-6 rash','three day fever'], emoji:'🌸', type:'infectious', description:'A common childhood viral illness caused by Human Herpesvirus 6 (HHV-6). Characterized by high fever for 3-5 days, followed by a distinctive rash appearing as the fever breaks. Affects primarily children 6 months to 3 years. Usually benign and self-limiting.', symptoms:['High fever (39-40°C) lasting 3-5 days — child may not look as ill as temperature suggests','Fever breaks and a pink rash appears on trunk and spreads to neck, arms, legs','Rash is non-itchy and lasts 1-3 days','Mild upper respiratory symptoms','Swollen lymph nodes in neck','Febrile seizures may occur during high fever phase'], causes:['Human Herpesvirus 6 (HHV-6) — most common cause','Human Herpesvirus 7 (HHV-7) — less common cause','Spreads through saliva of infected adults who show no symptoms themselves'], homecare:['Give paracetamol or ibuprofen to control high fever and prevent febrile seizures','Dress child in light clothing and keep cool','Ensure adequate fluid intake','Reassure parents — rash appearing as fever breaks is a good sign of recovery','Roseola is not contagious once the rash appears'], whenToSeeDoctor:'See a doctor if a child under 1 year has a high fever, or if fever lasts more than 5 days without rash appearing. Seek emergency care for febrile seizures (though brief febrile seizures are usually not dangerous). Immunocompromised children with roseola require medical evaluation.', urgency:'low' },

  { name:'Fifth Disease', aliases:['fifth disease','slapped cheek disease','erythema infectiosum','parvovirus b19','slapped face rash','lacy rash child'], emoji:'👋', type:'infectious', description:'A common mild childhood viral illness caused by Parvovirus B19. Named "fifth disease" as it was the fifth rash-causing childhood illness classified. Characterized by a distinctive "slapped cheek" appearance on the face. Dangerous in pregnancy and for those with sickle cell disease.', symptoms:['Distinctive bright red rash on both cheeks — "slapped cheek" appearance','Lacy, net-like pink rash on trunk and limbs appearing after the facial rash','Mild fever, runny nose, and headache before the rash','Rash may come and go for weeks, worsening with heat, exercise, and sunlight','Joint pain in adults and older children (can be severe)'], causes:['Parvovirus B19','Spreads through respiratory droplets','Contagious in the week before the rash appears — not contagious once rash is present'], homecare:['Rest and take paracetamol for fever and joint pain','No specific treatment needed in healthy children — resolves on its own','Warn pregnant women and those with sickle cell disease who were exposed — they need medical evaluation','Keep child away from pregnant women until diagnosis is confirmed'], whenToSeeDoctor:'Pregnant women must see a doctor urgently if exposed — parvovirus B19 can cause severe fetal anemia (hydrops fetalis) and fetal death. People with sickle cell disease or other blood disorders may develop a transient aplastic crisis (sudden drop in red cells) and need urgent blood test and hospital care.', urgency:'medium' },

  { name:'Kawasaki Disease', aliases:['kawasaki disease','mucocutaneous lymph node syndrome','kawasaki syndrome','coronary artery aneurysm child','strawberry tongue fever child'], emoji:'❤️', type:'infectious', description:'A rare but serious childhood illness of unknown exact cause (possibly infectious trigger) causing inflammation of blood vessels throughout the body, particularly the coronary arteries. The leading cause of acquired heart disease in children in developed countries. Treated with IVIG and aspirin.', symptoms:['Persistent fever lasting 5 or more days — the defining feature','Rash over trunk and groin','Red cracked lips and strawberry tongue','Red swollen hands and feet — peeling of skin from fingertips in recovery phase','Red eyes without discharge (conjunctivitis)','Swollen lymph node on one side of the neck'], causes:['Exact cause unknown — possibly an abnormal immune response to an infectious trigger','Predominantly affects children under 5','More common in children of East Asian ancestry'], homecare:['Kawasaki disease requires hospital treatment — do not attempt home management','Give aspirin and paracetamol as prescribed for fever while awaiting hospital treatment','Prompt treatment prevents coronary artery aneurysms — the most feared complication','After discharge: give aspirin as prescribed, attend all follow-up echocardiograms'], whenToSeeDoctor:'Immediately — any child with fever lasting 5 or more days with any of the other features (rash, red eyes, swollen lips/tongue, swollen hands/feet, lymph node) requires urgent hospital admission. IVIG must be given within 10 days of fever onset to prevent coronary artery aneurysms.', urgency:'high' },

  { name:'RSV', aliases:['rsv','respiratory syncytial virus','rsv bronchiolitis','infant wheezing virus','winter respiratory virus','rsv infection'], emoji:'🫁', type:'infectious', description:'Respiratory Syncytial Virus — the most common cause of bronchiolitis and pneumonia in infants and young children. Almost all children are infected by age 2. Usually mild in older children and healthy adults, but can be severe in premature infants, children under 6 months, elderly, and immunocompromised.', symptoms:['Mild upper respiratory symptoms initially — runny nose, mild cough, fever','In infants: wheezing, rapid breathing, retractions (pulling in of chest wall muscles while breathing)','Poor feeding and irritability in infants','Nasal flaring and increased work of breathing','Apnea (pauses in breathing) especially in very young or premature infants'], causes:['Respiratory Syncytial Virus','Spreads through respiratory droplets and direct contact','Highly contagious in winter months','Reinfection is common throughout life — immunity is not long-lasting'], homecare:['Keep nostrils clear with saline drops and bulb syringe for infants','Use cool-mist humidifier in the child\'s room','Encourage small, frequent feeds if feeding poorly','Keep child upright after feeding','No antibiotics needed (viral) — treat fever with paracetamol'], whenToSeeDoctor:'Seek emergency care if an infant has: rapid breathing (more than 60 breaths per minute), blue or pale lips, severe retractions, extreme fussiness or lethargy, or feeding less than half normal. Premature infants with RSV should always be assessed by a doctor. Nirsevimab (monoclonal antibody) is now available for RSV prevention in high-risk infants.', urgency:'high' },

  { name:'Croup', aliases:['croup','laryngotracheobronchitis','barking cough child','seal bark cough','stridor cough child','parainfluenza croup'], emoji:'🦭', type:'infectious', description:'A common viral infection in children 6 months to 3 years causing inflammation and swelling of the larynx and trachea, resulting in a distinctive barking cough (like a seal), hoarse voice, and stridor (high-pitched noise when breathing in). Most cases are mild and manageable at home.', symptoms:['Distinctive harsh barking or seal-like cough — often sudden onset at night','Hoarse voice','Stridor — noisy, high-pitched sound when breathing in, especially when upset or crying','Mild fever','Worsening at night and when child is upset','Mild cases: stridor only when crying; severe cases: stridor at rest'], causes:['Parainfluenza virus (most common — types 1 and 2)','RSV, adenovirus, influenza virus, and other respiratory viruses','Spreads through respiratory droplets and contact with infected surfaces'], homecare:['Breathe in cool night air — stand with child at an open window or door for 10 minutes','Cool mist humidifier in the room','Stay calm and comfort the child — crying worsens stridor','Paracetamol for fever and discomfort','Dexamethasone (oral steroid) prescribed by a doctor dramatically reduces severity and duration'], whenToSeeDoctor:'See a doctor urgently or call emergency services if: stridor is present at rest, child appears distressed or is struggling to breathe, has bluish lips, is drooling or cannot swallow, or is unusually tired. Oral dexamethasone prescribed by a doctor is very effective and should be given early in moderate croup.', urgency:'medium' },

  { name:'Bronchiolitis', aliases:['bronchiolitis','infant bronchiolitis','baby breathing difficulty','rsv bronchiolitis','infant wheezing','lower respiratory infant'], emoji:'🫁', type:'infectious', description:'An acute lower respiratory infection of the small airways (bronchioles) of the lungs, almost exclusively affecting infants and children under 2. The most common cause of hospitalization in infants. Most commonly caused by RSV.', symptoms:['Runny nose and mild cough initially — 2-3 days before breathing difficulty','Rapid, shallow breathing','Wheezing — high-pitched whistling on breathing out','Chest recessions — ribs visible as baby breathes in (intercostal, subcostal retractions)','Poor feeding','Irritability and restlessness','Fever (usually mild)'], causes:['Respiratory Syncytial Virus (most common)','Rhinovirus, parainfluenza, adenovirus, human metapneumovirus','Spreads through respiratory droplets and direct contact'], homecare:['Position baby slightly upright for easier breathing','Saline nasal drops and gentle suctioning of nasal secretions before feeds','Offer small, frequent feeds — every 30-60 minutes if needed','Keep room at comfortable temperature with good air flow','Avoid smoking near the baby — passive smoke dramatically worsens respiratory illness'], whenToSeeDoctor:'See a doctor for any wheeze in an infant. Go to emergency immediately if: breathing rate is very fast, ribs are visibly pulling in, lips are turning blue, infant is exhausted, or feeding is severely reduced. Infants under 3 months with bronchiolitis should always be assessed in hospital. Nirsevimab can prevent severe RSV bronchiolitis.', urgency:'high' },

  { name:'Epiglottitis', aliases:['epiglottitis','swollen epiglottis','drooling stridor adult','supraglottitis','haemophilus influenzae throat','tripod position stridor'], emoji:'🚨', type:'infectious', description:'A rare but life-threatening infection of the epiglottis (the flap of tissue that covers the windpipe during swallowing), causing rapid swelling that can completely block the airway. A medical emergency. Most commonly caused by Haemophilus influenzae type b (Hib) — largely preventable by Hib vaccine.', symptoms:['Sudden high fever','Severe sore throat disproportionate to visible redness','Drooling — inability to swallow (very characteristic sign)','Muffled or hot-potato voice (soft, strained voice)','Stridor (harsh breathing sound when inhaling)','Sitting upright in tripod position to keep airway open','Rapid deterioration — child looks extremely ill'], causes:['Haemophilus influenzae type b (Hib) — most common before universal Hib vaccination','Streptococcus, Staphylococcus in post-vaccine era','Rarely: thermal injury from steam burns, trauma','Now more common in adults (unvaccinated) than in vaccinated children'], homecare:['This is a life-threatening emergency — call emergency services immediately','Do NOT examine the child\'s throat, use a tongue depressor, or place anything in the mouth — this can trigger complete airway obstruction','Keep child calm and allow them to take the position they find most comfortable for breathing','Do NOT lay the child down'], whenToSeeDoctor:'Call emergency services immediately — epiglottitis can progress to complete airway obstruction and death in minutes. Definitive airway management in hospital by experienced staff is required. IV antibiotics and airway management are the treatment. Universal Hib vaccination has dramatically reduced incidence.', urgency:'high' },

  { name:'Pneumocystis Pneumonia', aliases:['pneumocystis pneumonia','pcp','pneumocystis jirovecii','hiv pneumonia','aids pneumonia','pjp pneumonia'], emoji:'🫁', type:'infectious', description:'A severe fungal pneumonia caused by Pneumocystis jirovecii (formerly carinii), affecting almost exclusively people with severely weakened immune systems — particularly HIV/AIDS patients with CD4 count below 200. A major AIDS-defining illness with significant mortality.', symptoms:['Progressive shortness of breath — worsening with exertion','Dry, non-productive cough','Fever (often low-grade)','Fatigue and weight loss','Rapid respiratory rate','Hypoxia — oxygen levels fall dramatically on exercise','Chest X-ray: bilateral perihilar infiltrates'], causes:['Pneumocystis jirovecii fungus','Affects almost exclusively immunocompromised individuals — HIV, organ transplant, long-term steroids, cancer chemotherapy','The organism is widespread in the environment — normally harmless in healthy individuals'], homecare:['HIV patients with CD4 count below 200 should take prophylactic trimethoprim-sulfamethoxazole (co-trimoxazole)','Take antiretroviral therapy consistently to keep CD4 count above 200','Do not stop prophylaxis without medical advice'], whenToSeeDoctor:'Immediately for any immunocompromised patient with progressive breathlessness, dry cough, and fever — PCP can be rapidly fatal. Requires hospitalization, high-dose trimethoprim-sulfamethoxazole IV, and often corticosteroids for severe cases. Oxygen and ICU admission may be needed.', urgency:'high' },

  { name:'Dengue', aliases:['dengue','dengue fever','breakbone fever','dengue mosquito','platelet drop','low platelet'], emoji:'🦟', type:'infectious', description:'A mosquito-borne viral disease spread by Aedes mosquitoes. Very common in India especially during and after monsoon. Can be severe in some cases.', symptoms:['Sudden high fever (104°F / 40°C)','Severe headache','Pain behind the eyes','Joint and muscle pain (breakbone fever)','Skin rash','Mild bleeding (nose, gums)','Low platelet count'], causes:['Bite of Aedes aegypti mosquito infected with dengue virus','Stagnant water breeding grounds near home','No person-to-person transmission'], homecare:['Rest and drink plenty of fluids — ORS, coconut water, juices','Paracetamol for fever — NEVER aspirin or ibuprofen','Monitor platelet count if fever persists','Use mosquito repellent and nets','Get a blood test to confirm'], whenToSeeDoctor:'Severe abdominal pain, persistent vomiting, blood in urine or stool or vomit, rapid breathing, fatigue or restlessness — go to hospital immediately. Warning signs of severe dengue.', urgency:'high' },

  { name:'Typhoid', aliases:['typhoid','typhoid fever','enteric fever','salmonella','typhoid infection'], emoji:'🌡️', type:'infectious', description:'A bacterial infection caused by Salmonella typhi, usually spread through contaminated food and water. Common in areas with poor sanitation. Treatable with antibiotics.', symptoms:['Prolonged high fever gradually rising','Weakness and fatigue','Stomach pain','Headache','Loss of appetite','Constipation or diarrhea','Rose-colored spots on skin (rare)'], causes:['Contaminated water or food','Poor hand hygiene','Consuming raw or undercooked food from unhygienic sources','Contact with infected person'], homecare:['Take prescribed antibiotics — do NOT stop early','Rest and drink plenty of clean boiled water','Eat easily digestible food — khichdi, banana, boiled rice','Maintain strict hand hygiene','Avoid outside food until fully recovered'], whenToSeeDoctor:'Suspected typhoid must be confirmed with a blood test. See a doctor immediately — antibiotics are required and should not be self-prescribed.', urgency:'high' },

  { name:'Malaria', aliases:['malaria','malarial fever','malaria infection','malaria mosquito','chills fever'], emoji:'🦟', type:'infectious', description:'A serious mosquito-borne disease caused by Plasmodium parasites. Transmitted by the Anopheles mosquito. Treatable if diagnosed early.', symptoms:['High fever with chills and sweating in cycles','Headache','Muscle aches','Fatigue','Nausea and vomiting','Anemia','Jaundice in severe cases'], causes:['Bite of infected Anopheles mosquito','No person-to-person transmission','More common in tropical and subtropical regions'], homecare:['Take prescribed antimalarial drugs — complete the course','Rest and drink plenty of fluids','Take paracetamol for fever (not aspirin or ibuprofen)','Sleep under mosquito nets','Use mosquito repellents'], whenToSeeDoctor:'Suspected malaria requires immediate blood test. Severe malaria with confusion, seizures, difficulty breathing, or jaundice is a medical emergency.', urgency:'high' },

  { name:'Chickenpox', aliases:['chickenpox','chicken pox','varicella','itchy blisters','pox','blister rash'], emoji:'🔴', type:'infectious', description:'A highly contagious viral infection causing an itchy blister-like rash. Most common in children but can be severe in adults. Usually resolves in 1-2 weeks.', symptoms:['Itchy red spots that blister and then crust over','Rash starting on face, chest, and back then spreading','Fever','Fatigue','Loss of appetite','Headache'], causes:['Varicella-zoster virus','Highly contagious — spreads through air and direct contact','A person is contagious from 1-2 days before rash until all blisters crust over'], homecare:['Calamine lotion on blisters to reduce itching','Trim fingernails and avoid scratching to prevent scars','Cool baths with baking soda or oatmeal','Paracetamol for fever — NEVER aspirin in children','Stay isolated until all blisters have crusted'], whenToSeeDoctor:'High fever, blisters in eyes or genitals, signs of bacterial infection (redness, warmth, pus around blisters), confusion, or stiff neck.', urgency:'medium' },

  { name:'COVID-19', aliases:['covid','covid-19','coronavirus','corona virus','corona','covid infection'], emoji:'🦠', type:'infectious', description:'An infectious disease caused by the SARS-CoV-2 coronavirus. Symptoms range from mild cold-like illness to severe pneumonia. Most people recover fully.', symptoms:['Fever and chills','Dry cough','Fatigue','Loss of taste or smell','Sore throat','Headache','Muscle aches','Shortness of breath (severe cases)'], causes:['Respiratory droplets from infected person','Close contact without mask','Touching contaminated surfaces then touching face','More severe in elderly and those with pre-existing conditions'], homecare:['Isolate immediately to prevent spread','Rest and drink plenty of fluids','Paracetamol for fever and body aches','Monitor oxygen levels with pulse oximeter if available','Ventilate room well'], whenToSeeDoctor:'Difficulty breathing, persistent chest pain, confusion, inability to wake or stay awake, or oxygen saturation below 94%. These require emergency care.', urgency:'high' },

  { name:'Measles', aliases:['measles','rubeola','koplik spots','measles rash'], emoji:'🔴', type:'infectious', description:'A highly contagious viral infection preventable by vaccination. Causes a characteristic red rash. Serious complications can occur especially in children.', symptoms:['High fever','Cough, runny nose, and red eyes (appear first)','Koplik spots (small white spots inside mouth)','Red blotchy rash spreading from face downward','Sensitivity to light'], causes:['Measles virus (highly contagious)','Spreads through air when infected person coughs or sneezes','Unvaccinated individuals are at high risk'], homecare:['Rest and drink plenty of fluids','Paracetamol for fever','Vitamin A supplements as recommended by doctor','Keep room dimly lit if eyes are sensitive','Isolate from unvaccinated people'], whenToSeeDoctor:'Difficulty breathing, seizures, confusion, ear pain, or severe eye infection. Measles can cause pneumonia and brain inflammation.', urgency:'high' },

  { name:'Hepatitis', aliases:['hepatitis','liver infection','hepatitis a','hepatitis b','hepatitis c','jaundice liver','liver disease'], emoji:'🍋', type:'infectious', description:'Inflammation of the liver caused by viruses (A, B, C, D, E), alcohol, or other causes. Hepatitis A and E are food/water-borne; B and C are blood/sexual contact.', symptoms:['Jaundice (yellow skin and eyes)','Dark urine','Pale stools','Fatigue','Nausea and vomiting','Abdominal pain (upper right)','Fever (in acute hepatitis)'], causes:['Hepatitis A and E: contaminated food or water','Hepatitis B and C: blood contact, unprotected sex, sharing needles','Alcohol abuse','Certain medications or toxins'], homecare:['Rest and avoid strenuous activity','Eat a balanced low-fat diet','Avoid alcohol completely','Take prescribed medications','Stay hydrated','Avoid spreading to others through good hygiene'], whenToSeeDoctor:'Suspected hepatitis requires blood tests. Yellow eyes or skin, dark urine, or abdominal pain warrant immediate medical evaluation.', urgency:'high' },

  /* ── MENTAL HEALTH ── */
  
  { name:'Anxiety', aliases:['anxiety','stress','panic attack','worry','nervousness','mental stress','overthinking','panic','fear','anxious'], emoji:'😰', type:'mental', description:'A mental health condition characterized by persistent worry, fear, or unease. One of the most common mental health conditions globally and very treatable.', symptoms:['Excessive worry and fear','Rapid heartbeat (palpitations)','Sweating and trembling','Shortness of breath','Difficulty concentrating','Insomnia','Irritability','Headaches'], causes:['Stress and major life events','Trauma or past experiences','Genetics and brain chemistry','Certain medical conditions','Caffeine and alcohol','Social pressure'], homecare:['Deep breathing exercises (4-7-8 breathing)','Regular physical exercise (30 min daily)','Limit caffeine and alcohol','Maintain a sleep routine','Talk to a trusted friend or family member','Mindfulness and meditation apps can help'], whenToSeeDoctor:'Anxiety interfering with daily life, frequent panic attacks, thoughts of self-harm, or symptoms lasting more than 6 months. Therapy (CBT) and medication are highly effective.', urgency:'medium' },

  { name:'Depression', aliases:['depression','depressed','sadness','feeling low','hopeless','no motivation','empty feeling','mental health'], emoji:'😔', type:'mental', description:'A common and serious mental health condition causing persistent feelings of sadness and loss of interest. It affects how you feel, think, and handle daily activities.', symptoms:['Persistent sad or empty feeling','Loss of interest in activities once enjoyed','Fatigue and decreased energy','Changes in appetite and weight','Sleep problems (insomnia or oversleeping)','Difficulty concentrating','Feelings of worthlessness or guilt','Thoughts of death or suicide'], causes:['Brain chemistry imbalance','Hormonal changes','Genetic factors','Traumatic or stressful life events','Chronic illness or pain','Substance abuse'], homecare:['Maintain a daily routine','Get regular exercise — even short walks help','Connect with friends and family','Avoid alcohol','Get adequate sleep','Seek professional support — talking to a therapist helps enormously'], whenToSeeDoctor:'Thoughts of self-harm or suicide — seek immediate help. Also see a doctor if depression is severe, lasting more than 2 weeks, or interfering with daily function.', urgency:'high' },

  { name:'Insomnia', aliases:['insomnia','sleep problem','cant sleep','difficulty sleeping','sleeplessness','poor sleep','sleep disorder'], emoji:'😴', type:'mental', description:'Difficulty falling asleep or staying asleep that affects daytime functioning. Affects about 30% of adults. Usually treatable with lifestyle changes.', symptoms:['Difficulty falling asleep at night','Waking during the night','Waking too early','Not feeling rested after sleep','Daytime tiredness','Irritability and mood problems','Difficulty concentrating'], causes:['Stress and anxiety','Poor sleep habits (irregular schedule, screen use)','Caffeine, nicotine, or alcohol','Certain medications','Pain or medical conditions','Shift work or jet lag'], homecare:['Go to bed and wake at the same time every day','Avoid screens 1 hour before bed','Keep bedroom cool, dark, and quiet','Avoid caffeine after 2 PM','Do not lie awake in bed — get up if unable to sleep after 20 min','Try relaxation techniques — deep breathing, progressive muscle relaxation'], whenToSeeDoctor:'Insomnia lasting more than 1 month, associated with depression or anxiety, significantly affecting work or relationships, or if you suspect sleep apnea.', urgency:'low' },

  { name:'Panic Disorder', aliases:['panic disorder','panic attack','panic','sudden terror','heart racing anxiety','choking anxiety','palpitations anxiety','fear of dying suddenly'], emoji:'😰', type:'anxiety', description:'A condition marked by recurrent, unexpected panic attacks — sudden surges of intense fear that peak within minutes. People often develop fear of future attacks, leading to significant changes in behavior.', symptoms:['Sudden intense fear or terror','Racing or pounding heartbeat','Sweating and trembling','Shortness of breath or choking sensation','Chest pain or discomfort','Nausea or stomach distress','Dizziness or faintness','Fear of losing control or dying','Numbness or tingling'], causes:['Genetic predisposition','Chronic stress or major life changes','History of trauma or abuse','Overactive fight-or-flight response','Caffeine or stimulant use','Medical conditions affecting heart or thyroid'], homecare:['Practice slow, deep diaphragmatic breathing during an attack','Ground yourself using the 5-4-3-2-1 senses technique','Reduce caffeine and alcohol intake','Regular aerobic exercise reduces attack frequency','Keep a panic diary to identify triggers','Join a support group or therapy group'], whenToSeeDoctor:'First panic attack should always be evaluated to rule out heart or thyroid conditions. See a psychiatrist if attacks are recurrent or causing avoidance of daily activities. CBT and/or medication are very effective.', urgency:'medium' },

  { name:'Social Anxiety', aliases:['social anxiety','social anxiety disorder','social phobia','fear of people','fear of embarrassment','shyness extreme','fear of judgment','performance anxiety','public speaking fear'], emoji:'😶', type:'anxiety', description:'An intense, persistent fear of social situations where one might be watched, judged, or embarrassed. Goes far beyond ordinary shyness — it significantly interferes with work, school, and relationships.', symptoms:['Intense fear of social or performance situations','Fear of acting in a way that will be humiliating','Avoiding social situations or enduring them with great distress','Physical symptoms in social settings — blushing, sweating, trembling, nausea','Replaying social interactions and dwelling on perceived mistakes','Difficulty making eye contact or speaking in groups'], causes:['Genetics and family history','Overactive amygdala (fear center of brain)','History of bullying, teasing, or social humiliation','Overprotective parenting','Early childhood trauma or abuse'], homecare:['Practice gradual exposure to feared social situations','Challenge negative thoughts — ask "Is this truly as bad as I think?"','Join low-pressure social groups or classes to build confidence','Controlled breathing before and during social events','Avoid alcohol as a social crutch — it worsens anxiety long-term'], whenToSeeDoctor:'When social anxiety is preventing you from working, studying, forming relationships, or living normally. CBT (especially exposure therapy) is highly effective. Medication may also help.', urgency:'medium' },

  { name:'Generalized Anxiety Disorder', aliases:['generalized anxiety disorder','gad','chronic worry','excessive worry','constant anxiety','worrying about everything','anxiety disorder','free floating anxiety'], emoji:'😟', type:'anxiety', description:'A condition of persistent, excessive, and uncontrollable worry about multiple areas of life — health, money, work, family — even when there is little reason to worry. The worry is disproportionate and hard to control.', symptoms:['Excessive worry about many different things most days','Difficulty controlling the worry','Restlessness or feeling on edge','Fatigue and tiredness','Difficulty concentrating','Irritability','Muscle tension','Sleep disturbances — difficulty falling or staying asleep'], causes:['Genetics and family history of anxiety','Chronic stress or long-term difficult circumstances','Brain chemistry imbalances (serotonin, norepinephrine)','Traumatic or negative life events','Certain personality traits — perfectionism, low frustration tolerance'], homecare:['Schedule a daily "worry time" to contain anxious thoughts','Practice mindfulness meditation to reduce rumination','Regular exercise — yoga, walking, swimming are especially helpful','Limit news and social media consumption','Write worries down and challenge them rationally'], whenToSeeDoctor:'When worry is daily, uncontrollable, and interfering with daily functioning for more than 6 months. A psychiatrist or psychologist can diagnose and provide CBT and/or medication.', urgency:'medium' },

  { name:'Phobia', aliases:['phobia','specific phobia','irrational fear','fear of spiders','fear of heights','fear of flying','fear of blood','fear of needles','extreme fear'], emoji:'😱', type:'anxiety', description:'An intense, irrational, and persistent fear of a specific object, situation, or activity that poses little or no actual danger. The fear leads to avoidance and significant distress.', symptoms:['Immediate intense fear when exposed to the specific trigger','Knowing the fear is excessive but being unable to control it','Avoiding the feared object or situation at great personal cost','Physical symptoms on exposure — heart racing, sweating, trembling','In children, crying, tantrums, or freezing'], causes:['Negative or traumatic experience with the feared object','Learned fear from watching others','Genetics and family history','Information-based fear from media or others'], homecare:['Gradually expose yourself to the feared object in a safe, controlled way','Learn relaxation techniques to use during exposure','Educate yourself about the feared object to reduce mystery','Tell trusted people so they can support you'], whenToSeeDoctor:'When the phobia is causing you to restrict your life significantly. Exposure therapy (a type of CBT) has very high success rates for specific phobias.', urgency:'low' },

  { name:'Agoraphobia', aliases:['agoraphobia','fear of open spaces','fear of crowds','fear of leaving home','fear of public places','fear of being outside','trapped feeling outside'], emoji:'🏠', type:'anxiety', description:'An anxiety disorder involving intense fear and avoidance of situations where escape might be difficult or help unavailable during a panic attack — such as open spaces, public transport, crowded places, or being outside the home alone.', symptoms:['Fear of open spaces, crowds, or public transport','Avoiding situations where escape seems difficult','Fear of being outside the home alone','Needing a companion to leave the house','Severe cases result in being completely housebound','Panic attack symptoms when forced into feared situations'], causes:['Usually develops following panic attacks','Genetic predisposition to anxiety','Prolonged stress or trauma','Gradual avoidance that reinforces fear'], homecare:['Take very small steps outside — even to the doorway, then the porch','Go with a trusted support person initially','Practice relaxation during outings','Track progress and celebrate small wins'], whenToSeeDoctor:'Agoraphobia can become completely disabling. A psychiatrist or psychologist should be seen as early as possible. CBT with gradual exposure and sometimes medication are the main treatments.', urgency:'high' },

  { name:'Claustrophobia', aliases:['claustrophobia','fear of enclosed spaces','fear of small rooms','fear of elevators','fear of mri','fear of tunnels','enclosed space anxiety'], emoji:'🚪', type:'anxiety', description:'An intense fear of confined or enclosed spaces such as elevators, MRI machines, small rooms, tunnels, or crowded areas. It is a specific phobia that can interfere significantly with medical care and daily activities.', symptoms:['Intense fear when in or anticipating enclosed spaces','Sweating, trembling, rapid heartbeat','Shortness of breath or choking sensation','Need to escape immediately from enclosed spaces','Avoiding elevators, MRI scans, tunnels, small rooms'], causes:['Negative experience in an enclosed space','Genetic tendency toward anxiety','Learned from watching others','Childhood experiences of being confined'], homecare:['Practice controlled breathing when in enclosed spaces','Gradual exposure — start with mildly confined spaces','Distract yourself with music or podcasts in elevators','Focus on an exit point to feel more in control'], whenToSeeDoctor:'When claustrophobia is affecting medical care (avoiding MRIs, procedures) or daily life. Exposure therapy is very effective. Medication may help for specific situations.', urgency:'low' },

  { name:'Health Anxiety', aliases:['health anxiety','hypochondria','hypochondriasis','illness anxiety','fear of disease','fear of cancer','doctor shopping','medical anxiety','cyberchondria'], emoji:'🩺', type:'anxiety', description:'Excessive preoccupation with having or developing a serious illness, despite medical reassurance. The person interprets normal bodily sensations as symptoms of serious disease. Previously known as hypochondria.', symptoms:['Constant worry about having a serious illness','Repeatedly checking body for symptoms','Frequently seeking medical reassurance but not being satisfied','Avoiding medical care for fear of diagnosis','Researching symptoms obsessively (cyberchondria)','Interpreting normal sensations as signs of disease'], causes:['Prior serious illness in self or close family member','Anxiety or OCD tendencies','Childhood experiences of illness','Exposure to alarming health information','Loss of a loved one to illness'], homecare:['Set limits on symptom checking and health research','Practice mindfulness to observe sensations without judgment','Resist the urge to seek repeated reassurance','Engage in activities to redirect attention from body'], whenToSeeDoctor:'When health worries are consuming hours of each day and causing significant distress. CBT specifically designed for health anxiety is very effective.', urgency:'medium' },

  { name:'Separation Anxiety', aliases:['separation anxiety','separation anxiety disorder','fear of being alone','fear of losing loved ones','fear of abandonment child','clingy child anxiety','adult separation anxiety'], emoji:'👨‍👩‍👧', type:'anxiety', description:'An excessive and developmentally inappropriate fear of separation from attachment figures. Common in children but can also occur in adults. Leads to avoidance of separation and significant distress.', symptoms:['Excessive distress when separated or anticipating separation from loved ones','Persistent worry about harm befalling loved ones','Refusal to go to school or leave home','Nightmares about separation','Physical complaints (stomachache, headache) before separation','Clinging and shadowing behavior'], causes:['Genetic predisposition to anxiety','Traumatic separation or loss','Overprotective parenting styles','Stressful life events — moving, divorce, bereavement'], homecare:['Maintain consistent, predictable routines','Use gradual separation practice','Reassure calmly without excessive accommodation','Avoid reinforcing avoidance behaviors'], whenToSeeDoctor:'When separation anxiety is preventing school attendance, work, or normal development. Child therapists use play therapy; CBT is used for older children and adults.', urgency:'medium' },

  { name:'Selective Mutism', aliases:['selective mutism','child not speaking at school','won\'t talk in public','situational mutism','silent child','refuses to speak outside','not speaking in social situations'], emoji:'🤐', type:'anxiety', description:'A childhood anxiety disorder where a child who speaks normally at home is consistently unable to speak in certain social situations, such as at school. It is not a choice — the child is genuinely unable to speak due to anxiety.', symptoms:['Failure to speak in specific social situations despite speaking in others (e.g., speaks at home, silent at school)','Consistent pattern lasting more than 1 month','Significantly affects education and social life','May communicate through gestures, nodding, or whispering','Appears shy, frozen, or expressionless in triggering situations'], causes:['Social anxiety is the primary driver','Genetic predisposition to anxiety','Temperament — highly sensitive or inhibited children','Bilingual children navigating two languages'], homecare:['Never force the child to speak — this worsens anxiety','Use positive reinforcement for any verbal attempt','Arrange playdates in comfortable settings to build confidence','Work closely with school to create a supportive plan'], whenToSeeDoctor:'As early as possible — early intervention has the best outcomes. A child psychologist experienced in selective mutism should be consulted. Behavioral therapy with gradual exposure is the treatment.', urgency:'medium' },

  /* ── MOOD ── */
  { name:'Major Depressive Disorder', aliases:['major depressive disorder','major depression','clinical depression','mdd','severe depression','deep depression','feeling hopeless','can\'t get out of bed','depression'], emoji:'😞', type:'mood', description:'A serious mood disorder characterized by persistent low mood, loss of interest in activities, and a range of physical and emotional symptoms that significantly impair functioning. Episodes can be single or recurrent.', symptoms:['Persistent sad, empty, or hopeless mood most of the day, nearly every day','Loss of interest or pleasure in all or almost all activities','Significant weight loss or gain, or change in appetite','Insomnia or sleeping too much','Fatigue and loss of energy','Feelings of worthlessness or excessive guilt','Difficulty concentrating or making decisions','Recurrent thoughts of death or suicidal ideation'], causes:['Brain chemistry imbalances (serotonin, dopamine, norepinephrine)','Genetic predisposition','Stressful life events — loss, trauma, relationship breakdown','Chronic illness or pain','Hormonal changes','Substance abuse'], homecare:['Maintain a daily routine even when motivation is low','Engage in physical activity — even a short daily walk helps','Stay connected with trusted people — avoid isolation','Limit alcohol — it is a depressant','Sleep and wake at consistent times','Break large tasks into small steps'], whenToSeeDoctor:'Always see a doctor or mental health professional for depression. If you have thoughts of suicide or self-harm, seek emergency help immediately. Treatment with therapy, medication, or both is very effective.', urgency:'high' },

  { name:'Persistent Depressive Disorder', aliases:['persistent depressive disorder','dysthymia','chronic depression','low grade depression','always sad','never happy','dysthymic disorder','mild chronic depression'], emoji:'🌧️', type:'mood', description:'A chronic form of depression lasting at least 2 years in adults (1 year in children). The mood is consistently low but may not be as severe as major depression. People often describe it as "always feeling down" or "never feeling happy."', symptoms:['Depressed mood for most of the day, more days than not, for at least 2 years','Low energy and fatigue','Low self-esteem','Poor concentration or difficulty making decisions','Feelings of hopelessness','Sleep changes — insomnia or oversleeping','Reduced appetite or overeating'], causes:['Genetic factors','Brain chemistry imbalances','Chronic stress or long-term difficult life circumstances','Trauma or early childhood adversity','Untreated or undertreated major depression'], homecare:['Behavioral activation — schedule small enjoyable activities daily','Regular physical exercise has significant antidepressant effect','Maintain social connections despite low mood','Practice self-compassion — chronic depression is an illness, not a character flaw','Keep a mood journal to track patterns'], whenToSeeDoctor:'Persistent low mood lasting months should always be evaluated by a psychiatrist. Combination of psychotherapy (CBT or IPT) and antidepressants is often most effective for dysthymia.', urgency:'medium' },

  { name:'Seasonal Affective Disorder', aliases:['seasonal affective disorder','sad','winter depression','seasonal depression','winter blues','low mood in winter','seasonal mood disorder'], emoji:'🌨️', type:'mood', description:'A type of depression that follows a seasonal pattern, typically starting in autumn and resolving in spring. Thought to be related to reduced sunlight affecting the body\'s internal clock and brain chemistry.', symptoms:['Depression, hopelessness, and low mood in autumn and winter','Oversleeping and difficulty waking','Increased appetite — especially craving carbohydrates','Weight gain','Low energy and fatigue','Social withdrawal','Loss of interest in usual activities'], causes:['Reduced sunlight disrupting circadian rhythm','Reduced serotonin levels due to less sunlight','Excess melatonin production in darker months','Vitamin D deficiency','Genetic predisposition'], homecare:['Light therapy — sit in front of a 10,000-lux light box for 20-30 min each morning','Go outside in natural daylight even in winter','Exercise regularly, especially outdoors','Maintain social activities during winter months','Vitamin D supplementation if deficient'], whenToSeeDoctor:'If seasonal mood changes significantly impair your functioning each year. A psychiatrist can prescribe antidepressants or confirm light therapy protocol. Start treatment before the season begins.', urgency:'medium' },

  { name:'Postpartum Depression', aliases:['postpartum depression','postnatal depression','baby blues severe','depression after birth','after baby depression','ppd','new mother depression','maternal depression'], emoji:'👶', type:'mood', description:'A serious mood disorder occurring after childbirth, going well beyond the "baby blues." It involves intense sadness, exhaustion, and anxiety that interferes with a mother\'s ability to care for herself and her baby.', symptoms:['Persistent sadness and crying','Extreme fatigue not relieved by sleep','Difficulty bonding with the baby','Withdrawing from family and friends','Loss of appetite or overeating','Anxiety and irritability','Feelings of worthlessness or inadequacy as a parent','Thoughts of harming oneself or the baby'], causes:['Rapid hormonal changes after delivery','Sleep deprivation','Lack of social support','History of depression or anxiety','Difficult pregnancy or delivery','Infant health problems'], homecare:['Tell your partner, family member, or doctor how you are feeling — do not suffer alone','Accept help with the baby, household, and meals','Rest whenever the baby sleeps','Join a postpartum support group','Gentle exercise when cleared by doctor'], whenToSeeDoctor:'Any signs of postpartum depression — especially thoughts of harming yourself or the baby — require immediate medical attention. Highly treatable with therapy and/or antidepressants safe for breastfeeding.', urgency:'high' },

  { name:'Postpartum Psychosis', aliases:['postpartum psychosis','postnatal psychosis','psychosis after birth','hallucinations after baby','confusion after childbirth','puerperal psychosis'], emoji:'🚨', type:'mood', description:'A rare but severe psychiatric emergency that occurs shortly after childbirth. Involves a sudden break from reality, including hallucinations, delusions, and severe confusion. Requires immediate hospitalization.', symptoms:['Hallucinations (hearing or seeing things that aren\'t there)','Delusions (false beliefs — e.g., baby is possessed or not her own)','Severe confusion and disorientation','Extreme agitation or restlessness','Rapid mood swings','Not sleeping at all despite exhaustion','Talking or behaving in a strange or incoherent way'], causes:['Rapid hormonal changes post delivery','Genetic predisposition — especially family or personal history of bipolar disorder','First-time motherhood','Sleep deprivation'], homecare:['This is a psychiatric emergency — do NOT manage at home alone','Stay with the mother at all times until help arrives','Remove access to anything that could cause harm','Call emergency services or take to hospital immediately'], whenToSeeDoctor:'IMMEDIATELY — this is a psychiatric emergency. The mother and baby are at risk. Call emergency services or go to the nearest hospital right away. Hospitalization is almost always required.', urgency:'high' },

  { name:'Premenstrual Dysphoric Disorder', aliases:['premenstrual dysphoric disorder','pmdd','severe pms','mood before period','extreme pms','premenstrual depression','period mood disorder'], emoji:'🌑', type:'mood', description:'A severe form of premenstrual syndrome (PMS) where emotional and physical symptoms are intense enough to significantly disrupt daily life. Symptoms occur in the week before menstruation and improve after the period starts.', symptoms:['Severe mood swings','Intense irritability or anger','Marked depression, hopelessness, or sadness','Anxiety and tension','Difficulty concentrating','Fatigue and low energy','Changes in appetite or cravings','Bloating, breast tenderness, headaches','Feeling overwhelmed or out of control'], causes:['Abnormal sensitivity to hormonal fluctuations (estrogen and progesterone)','Serotonin system dysregulation','Genetic predisposition','Stress and prior trauma may worsen symptoms'], homecare:['Track symptoms across menstrual cycle to confirm PMDD pattern','Regular aerobic exercise throughout the month','Reduce caffeine, alcohol, and salt in the 2 weeks before period','Calcium and vitamin B6 supplementation may help','Stress management techniques — yoga, mindfulness'], whenToSeeDoctor:'When PMDD symptoms are disrupting work, relationships, or daily life every month. A gynecologist or psychiatrist can recommend SSRIs, hormonal treatments, or combined approaches.', urgency:'medium' },

  { name:'Bipolar I', aliases:['bipolar 1','bipolar i','bipolar disorder','manic depression','mania','manic episode','bipolar one','extreme mood swings','manic depressive'], emoji:'🔄', type:'mood', description:'A mood disorder involving at least one manic episode — a period of abnormally elevated, expansive, or irritable mood lasting at least 7 days. Manic episodes can be so severe they require hospitalization. Depressive episodes also occur.', symptoms:['Manic episodes: elevated or irritable mood, extreme energy, decreased need for sleep','Grandiose sense of self, racing thoughts, rapid speech','Reckless or impulsive behavior — spending, sexual, risky activities','Depressive episodes: sadness, hopelessness, fatigue, suicidal thoughts','Psychotic features (hallucinations, delusions) can occur in severe mania','Mood cycles that are distinct and represent a clear change from baseline'], causes:['Strong genetic component','Brain structure and chemistry differences','Stressful life events can trigger episodes','Substance use can precipitate episodes','Sleep disruption is a major trigger'], homecare:['Take mood stabilizer medication consistently — do NOT stop without medical advice','Maintain a strict sleep schedule — disrupted sleep can trigger episodes','Keep a mood chart to catch early warning signs','Reduce alcohol and drugs completely','Tell trusted people your warning signs so they can alert you'], whenToSeeDoctor:'A psychiatrist must manage bipolar I — it requires medication (mood stabilizers, antipsychotics). Stopping medication is dangerous. If signs of mania appear, contact your psychiatrist immediately.', urgency:'high' },

  { name:'Bipolar II', aliases:['bipolar 2','bipolar ii','bipolar two','hypomania','hypomanic episodes','bipolar depression','soft bipolar'], emoji:'🌗', type:'mood', description:'A mood disorder involving at least one hypomanic episode (a less severe form of mania) and at least one major depressive episode. The hypomanic episodes do not cause hospitalization but represent a clear change from usual behavior.', symptoms:['Hypomanic episodes: elevated mood, increased energy, decreased sleep need, but less severe than full mania','No psychosis during hypomania','Depressive episodes are the dominant and most disabling feature','Mood instability between episodes','Impulsive decisions during hypomania that cause later regret'], causes:['Genetic predisposition — strong family history link','Brain chemistry differences','Stressful life events','Sleep disruption'], homecare:['Medication adherence is essential — do not adjust doses without doctor guidance','Track mood daily using an app or journal','Prioritize sleep — maintain consistent sleep times','Avoid alcohol and recreational drugs','Build a crisis plan with your psychiatrist'], whenToSeeDoctor:'A psychiatrist is required for diagnosis and treatment of bipolar II. It is often mistaken for depression, leading to ineffective treatment. SSRIs alone can trigger hypomania — always disclose full mood history.', urgency:'high' },

  { name:'Cyclothymia', aliases:['cyclothymia','cyclothymic disorder','mild bipolar','mood cycling','up and down moods','emotional instability','chronic mood swings','cyclothymia disorder'], emoji:'〰️', type:'mood', description:'A chronic mood disorder involving numerous periods of hypomanic and depressive symptoms that are not severe enough to qualify as full hypomanic or major depressive episodes. Mood is never fully stable for more than 2 months.', symptoms:['Frequent shifts between mild elation and low mood','Low-level hypomanic symptoms — increased energy, less sleep, talkativeness','Mild depressive symptoms — sadness, fatigue, low self-esteem','Never symptom-free for more than 2 months at a time','Mood instability interferes with relationships and functioning'], causes:['Genetic predisposition — related to bipolar disorder','Brain chemistry fluctuations','Chronic stress or early childhood trauma'], homecare:['Track mood patterns to become aware of cycles','Maintain consistent sleep and daily routines','Limit caffeine and alcohol','Practice stress reduction — yoga, mindfulness, journaling'], whenToSeeDoctor:'A psychiatrist can diagnose and help manage cyclothymia with mood stabilizers and psychotherapy. It carries a risk of developing full bipolar disorder, so early treatment is important.', urgency:'medium' },

  /* ── PSYCHOTIC ── */
  { name:'Schizophrenia', aliases:['schizophrenia','schizophrenic','psychosis','hallucinations','hearing voices','delusions','losing touch with reality','mental disorder voices'], emoji:'🌀', type:'psychotic', description:'A serious, chronic mental disorder affecting how a person thinks, feels, and behaves. People with schizophrenia may seem to have lost touch with reality. It is highly treatable but requires lifelong management.', symptoms:['Hallucinations — hearing voices most common','Delusions — fixed false beliefs (persecution, grandiosity)','Disorganized thinking and speech','Disorganized or abnormal motor behavior','Negative symptoms — flat affect, alogia (reduced speech), avolition (lack of motivation)','Social withdrawal and neglect of hygiene','Cognitive difficulties — memory, attention, planning'], causes:['Genetic predisposition','Dopamine and glutamate dysregulation in the brain','Brain development abnormalities','Prenatal exposure to infections or malnutrition','Cannabis use in genetically vulnerable individuals','Extreme stress or trauma can trigger onset'], homecare:['Antipsychotic medication must be taken consistently — never stop without medical guidance','Maintain structured daily routine','Reduce stress — stress worsens psychotic symptoms','Family support and education are crucial','Avoid alcohol and all recreational drugs'], whenToSeeDoctor:'A psychiatrist must manage schizophrenia — it requires antipsychotic medication. During a psychotic episode (break from reality), take the person to emergency services. Do not attempt to manage a psychotic crisis alone.', urgency:'high' },

  { name:'Schizoaffective Disorder', aliases:['schizoaffective disorder','schizoaffective','schizophrenia with mood','psychosis and depression','psychosis and mania','mixed psychotic disorder'], emoji:'🌀', type:'psychotic', description:'A chronic mental health condition featuring symptoms of both schizophrenia (psychosis) and a mood disorder (depression or bipolar). It is considered between schizophrenia and a mood disorder on the diagnostic spectrum.', symptoms:['Hallucinations and delusions (psychotic symptoms)','Concurrent or alternating mood episodes — depression or mania','Disorganized thinking and speech','Periods of relatively normal functioning between episodes','Impaired social and occupational functioning'], causes:['Genetic factors related to both schizophrenia and mood disorders','Brain chemistry imbalances','Stressful life events can trigger episodes','Substance use'], homecare:['Take all prescribed medications consistently — usually antipsychotics plus mood stabilizers or antidepressants','Track mood and psychotic symptoms','Maintain a stable daily routine','Avoid alcohol and drugs','Lean on family and case manager support'], whenToSeeDoctor:'Requires a psychiatrist for management. Both psychotic and mood symptoms must be treated simultaneously. During psychotic episodes, emergency services may be required.', urgency:'high' },

  { name:'Delusional Disorder', aliases:['delusional disorder','delusions','fixed false beliefs','paranoia','persecutory delusions','jealousy delusion','erotomanic delusion','grandiose delusion'], emoji:'🔍', type:'psychotic', description:'A condition characterized by the presence of one or more persistent delusions — fixed, false beliefs that do not change even when confronted with evidence. Unlike schizophrenia, hallucinations are absent or minimal and functioning outside the delusion is relatively preserved.', symptoms:['Persistent delusions lasting at least 1 month','Common types: persecutory (being followed/poisoned), jealous (partner unfaithful), erotomanic (someone is in love with them), grandiose (exaggerated power/worth), somatic (bodily disease)','Behavior related to the delusion but otherwise functioning relatively normally','No significant hallucinations or disorganization'], causes:['Genetic predisposition','Brain dopamine dysregulation','Social isolation','Sensory impairment (hearing or vision loss)','Extreme stress'], homecare:['Do not argue directly about the delusion — this rarely helps and increases distress','Maintain a calm, consistent relationship','Gently encourage professional help','Ensure the person is safe and not acting on dangerous delusions'], whenToSeeDoctor:'A psychiatrist is needed to assess and treat delusional disorder. People with this condition often do not believe they are ill, making engagement difficult. Antipsychotic medication is the main treatment.', urgency:'high' },

  { name:'Brief Psychotic Disorder', aliases:['brief psychotic disorder','sudden psychosis','temporary psychosis','short psychosis','reactive psychosis','acute psychotic episode'], emoji:'⚡', type:'psychotic', description:'A sudden, short-term episode of psychosis lasting more than 1 day but less than 1 month, often triggered by extreme stress or trauma. The person returns to their previous level of functioning after the episode resolves.', symptoms:['Sudden onset of hallucinations','Delusions','Disorganized speech or behavior','Grossly disorganized or catatonic behavior','Marked emotional turmoil','Episode resolves within 1 month'], causes:['Severe stress or trauma (grief, assault, disaster) — called brief reactive psychosis','Childbirth (postpartum)','Genetic vulnerability to psychosis'], homecare:['This is a psychiatric emergency — do NOT manage alone at home','Stay calm and stay with the person','Remove hazards from environment','Take the person to an emergency room or call emergency services'], whenToSeeDoctor:'Immediately — a brief psychotic episode requires emergency psychiatric evaluation. Hospitalization may be needed for safety. With treatment, prognosis is excellent and full recovery is common.', urgency:'high' },

  /* ── OCD-RELATED ── */
  { name:'OCD', aliases:['ocd','obsessive compulsive disorder','obsessions','compulsions','intrusive thoughts','checking','washing hands repeatedly','contamination ocd','harm ocd','counting rituals'], emoji:'🔁', type:'anxiety', description:'A disorder in which a person experiences unwanted, intrusive thoughts (obsessions) that cause intense anxiety, and engages in repetitive behaviors or mental acts (compulsions) to reduce that anxiety. Compulsions provide only temporary relief and consume significant time.', symptoms:['Intrusive, unwanted thoughts, images, or urges (obsessions)','Repetitive behaviors or mental acts performed to reduce anxiety (compulsions)','Common obsessions: contamination, harm, symmetry, forbidden thoughts','Common compulsions: washing, checking, counting, arranging, mental reviewing','1+ hour per day spent on obsessions/compulsions','Significant distress and impairment to daily life'], causes:['Brain circuitry differences (orbitofrontal cortex and striatum)','Genetic predisposition','Stressful or traumatic life events','Streptococcal infections in children (PANDAS)'], homecare:['Resist the compulsion — the anxiety will eventually decrease without it (ERP principle)','Practice mindfulness to observe obsessive thoughts without reacting','Maintain daily structure and routine','Do not seek reassurance — it feeds OCD in the long run','Read about ERP (Exposure and Response Prevention) therapy to understand treatment'], whenToSeeDoctor:'OCD requires specialist treatment. ERP therapy, a specific type of CBT, is the gold standard. Medication (SSRIs at high doses) is also effective. Seek a therapist specializing in OCD.', urgency:'medium' },

  { name:'Body Dysmorphic Disorder', aliases:['body dysmorphic disorder','bdd','body image disorder','preoccupied with appearance','obsessed with flaws','mirror checking disorder','cosmetic surgery obsession','imagined ugliness'], emoji:'🪞', type:'anxiety', description:'A condition where a person is excessively preoccupied with a perceived defect in their appearance — one that others cannot see or consider minor. The preoccupation causes significant distress and impairment, including avoidance of social situations.', symptoms:['Preoccupation with a perceived flaw in appearance (e.g., nose, skin, hair)','Repetitive behaviors — mirror checking, skin picking, excessive grooming','Comparing appearance to others constantly','Avoiding social situations because of appearance','Seeking cosmetic procedures that provide temporary or no relief','Significant time and distress consumed by appearance concerns'], causes:['Genetic and neurobiological factors (related to OCD)','Cultural and media pressure on appearance','History of teasing or trauma about appearance','Low self-esteem'], homecare:['Limit mirror-checking to 2 intentional checks per day','Avoid seeking reassurance about appearance from others','Redirect attention to activities and goals beyond appearance','Challenge all-or-nothing thinking about appearance'], whenToSeeDoctor:'BDD requires specialist mental health treatment — CBT with ERP and/or SSRIs are effective. Cosmetic surgery should not be pursued as it rarely resolves BDD and can worsen it.', urgency:'medium' },

  { name:'Hoarding Disorder', aliases:['hoarding disorder','hoarding','can\'t throw things away','excessive collecting','cluttered home','compulsive hoarding','saving everything'], emoji:'📦', type:'anxiety', description:'A persistent difficulty discarding or parting with possessions regardless of their actual value, leading to the accumulation of clutter that congests living spaces and significantly impairs daily functioning.', symptoms:['Persistent difficulty discarding or parting with possessions','Strong urge to save items and distress when discarding','Accumulation of items that clutters living areas','Living spaces are unusable for their intended purpose','Social isolation and embarrassment about the home','Decision-making difficulties'], causes:['Genetic and neurobiological factors (related to OCD)','Traumatic loss or extreme deprivation','Grief — holding onto possessions of deceased loved one','Belief that possessions are uniquely valuable or may be needed later'], homecare:['Start with a small, low-stress area (one shelf or drawer)','Sort items into keep, donate, and discard piles','Challenge beliefs about why items must be saved','Involve a supportive non-judgmental person for encouragement'], whenToSeeDoctor:'Hoarding disorder typically worsens without treatment. A therapist specializing in hoarding can use CBT tailored to this condition. Professional organizers with mental health knowledge can also help.', urgency:'medium' },

  { name:'Trichotillomania', aliases:['trichotillomania','hair pulling disorder','pulling hair out','hair pulling anxiety','bald patches from pulling','trich'], emoji:'💇', type:'anxiety', description:'A body-focused repetitive behavior (BFRB) involving recurrent, compulsive urges to pull out hair from the scalp, eyebrows, eyelashes, or other areas. Often done unconsciously and causes significant distress and hair loss.', symptoms:['Recurrent pulling out of hair resulting in hair loss','Repeated attempts to decrease or stop the behavior','Feeling of tension before pulling or when trying to resist','Feeling of pleasure or relief during or after pulling','Hair loss and bald patches','Distress and shame about the behavior'], causes:['Related to OCD spectrum disorders','Genetic predisposition','Triggers: stress, boredom, anxiety, watching screens','Emotional regulation difficulty'], homecare:['Use awareness training — notice when and where pulling occurs','Replace pulling with a competing response (squeezing a stress ball, wearing a hair band)','Identify triggers and change environments where pulling occurs','Use a habit tracker to notice progress'], whenToSeeDoctor:'HRT (Habit Reversal Training) with a trained therapist is the most effective treatment. Medication (NAC, SSRIs) may also help. Seek a therapist specializing in BFRBs.', urgency:'low' },

  { name:'Excoriation Disorder', aliases:['excoriation disorder','skin picking disorder','dermatillomania','compulsive skin picking','picking skin until bleeding','acne picking compulsion'], emoji:'🩹', type:'anxiety', description:'A body-focused repetitive behavior (BFRB) involving repetitive, compulsive picking at skin, causing tissue damage. Like trichotillomania, it is related to the OCD spectrum and involves difficulty resisting urges despite harm caused.', symptoms:['Recurrent picking at skin causing sores, wounds, or scarring','Repeated attempts to stop without success','Tension before picking or when resisting','Relief or pleasure during or after picking','Significant time consumed by picking (30+ minutes daily)','Distress and shame; hiding skin with clothing or makeup'], causes:['OCD spectrum disorder','Stress and emotional dysregulation','Genetics','Triggers: boredom, anxiety, sensory seeking'], homecare:['Keep nails short to reduce picking effectiveness','Cover skin with bandages or clothing in picking areas','Use barrier tools — fidget toys, textured objects','Identify triggers and replace the behavior'], whenToSeeDoctor:'Habit Reversal Training (HRT) and Comprehensive Behavioral Treatment (ComB) with a specialist are most effective. Medication can be added if needed.', urgency:'low' },

  /* ── TRAUMA ── */
  { name:'PTSD', aliases:['ptsd','post traumatic stress disorder','trauma','flashbacks','nightmares trauma','hypervigilance','traumatic stress','war trauma','assault trauma','accident trauma'], emoji:'💥', type:'anxiety', description:'A mental health condition triggered by experiencing or witnessing a terrifying event. The person continues to relive the trauma through flashbacks and nightmares and may feel constantly on edge or emotionally numb.', symptoms:['Intrusive memories, flashbacks, or nightmares of the trauma','Avoiding reminders of the traumatic event','Negative changes in thinking and mood — guilt, blame, emotional numbness','Hyperarousal — being easily startled, always on alert, irritability','Sleep disturbances','Difficulty concentrating','Feeling detached from others'], causes:['Experiencing or witnessing a traumatic event (combat, assault, disaster, accident, abuse)','Not all trauma leads to PTSD — severity, support, and resilience factors influence risk','Previous trauma or mental health conditions increase risk','Lack of support after trauma'], homecare:['Ground yourself during flashbacks — use the 5-4-3-2-1 technique','Maintain a safe, structured daily routine','Stay connected with safe, trusted people','Avoid alcohol and drugs — they worsen PTSD symptoms','Gentle exercise can reduce hyperarousal'], whenToSeeDoctor:'PTSD requires specialist treatment. Trauma-focused therapies (EMDR, CPT, Prolonged Exposure) are highly effective. Medication can support treatment. Do not wait — symptoms worsen without treatment.', urgency:'high' },

  { name:'Acute Stress Disorder', aliases:['acute stress disorder','asd','trauma reaction','immediate trauma response','shock after trauma','acute stress response'], emoji:'🆘', type:'anxiety', description:'A short-term condition occurring within 3 days to 1 month after exposure to a traumatic event. Symptoms are similar to PTSD but shorter in duration. Without treatment, it can progress to PTSD.', symptoms:['Intrusive re-experiencing of the traumatic event','Flashbacks, nightmares, or emotional distress when reminded of trauma','Avoidance of trauma reminders','Negative mood — guilt, numbness, hopelessness','Dissociation — feeling detached from self or surroundings','Hyperarousal — startle response, irritability, sleep problems'], causes:['Exposure to actual or threatened death, serious injury, or sexual violence','Witnessing trauma happening to others','Learning of trauma to a close family member'], homecare:['Allow yourself to grieve and process the event — do not suppress feelings','Talk to trusted people about what happened when ready','Maintain basic self-care — sleep, food, gentle activity','Limit media coverage of the traumatic event'], whenToSeeDoctor:'See a mental health professional promptly — early intervention can prevent development of PTSD. Trauma-focused CBT in the acute phase is very effective.', urgency:'high' },

  { name:'Adjustment Disorder', aliases:['adjustment disorder','difficulty adjusting','stress reaction','situational depression','can\'t cope with change','stress after major life event','situational anxiety'], emoji:'🔀', type:'mood', description:'An emotional or behavioral reaction to a specific stressor (major life change, loss, or difficult event) that is disproportionate to the event and significantly impairs functioning. Not as severe as PTSD — the stressor need not be traumatic.', symptoms:['Emotional or behavioral symptoms in response to a specific stressor','Symptoms begin within 3 months of the stressor','Marked distress out of proportion to the stressor','Significant impairment in daily functioning','Symptoms resolve within 6 months of the stressor ending','May present as depression, anxiety, conduct problems, or mixed'], causes:['Major life changes — divorce, job loss, bereavement, illness, relocation','Multiple smaller stressors accumulating','Limited coping skills or support network'], homecare:['Identify and name the specific stressor clearly','Use active coping — problem-solve what you can control','Lean on your support network','Journaling about the transition and your feelings','Practice relaxation techniques'], whenToSeeDoctor:'Short-term therapy (CBT, supportive counseling) is very effective. See a mental health professional if symptoms are significantly impairing functioning or not improving after a few weeks.', urgency:'low' },

  { name:'Reactive Attachment Disorder', aliases:['reactive attachment disorder','rad','attachment disorder child','emotionally withdrawn child','neglected child attachment','no bond with caregiver'], emoji:'👶', type:'anxiety', description:'A childhood disorder in which a child does not form healthy emotional bonds with caregivers, usually resulting from severe neglect or early childhood trauma. The child is emotionally withdrawn and rarely seeks comfort.', symptoms:['Rarely seeks comfort when distressed','Rarely responds to comfort when offered','Minimal social and emotional responsiveness','Positive emotions are limited','Unexplained irritability, sadness, or fearfulness in interactions with caregivers'], causes:['Severe neglect of emotional and physical needs in early childhood','Frequent changes in caregivers (institutional care)','Abuse in early childhood'], homecare:['Provide a stable, nurturing, and predictable caregiving environment','Be patient — building trust takes considerable time','Use consistent routines and gentle predictability','Celebrate small positive interactions'], whenToSeeDoctor:'A child psychologist or psychiatrist specializing in attachment should be consulted. Family therapy focused on attachment (e.g., Theraplay) is recommended. Early intervention is crucial.', urgency:'high' },

  { name:'Disinhibited Social Engagement', aliases:['disinhibited social engagement disorder','dsed','overly friendly child','child approaches strangers','no stranger danger','over familiar child'], emoji:'🤝', type:'anxiety', description:'A childhood attachment disorder where a child is overly familiar and approaches strangers without appropriate caution. Unlike RAD, the child does engage socially — but indiscriminately, without discrimination between caregivers and strangers.', symptoms:['Reduced or absent reticence in approaching unfamiliar adults','Overly familiar verbal or physical behavior with strangers','Little or no checking back with caregiver in unfamiliar settings','Willingness to go off with an unfamiliar adult'], causes:['History of social neglect or institutional care','Repeated changes in primary caregivers','Insufficient opportunities to form stable attachments'], homecare:['Create a stable, consistent caregiving environment','Teach age-appropriate social boundaries gently and repeatedly','Supervision in social environments is essential for safety'], whenToSeeDoctor:'A child psychiatrist or attachment-informed therapist should be involved. Dyadic developmental psychotherapy and attachment-focused family therapy are used.', urgency:'medium' },

  /* ── NEURODEVELOPMENTAL ── */
  { name:'ADHD Inattentive', aliases:['adhd inattentive','inattentive adhd','add','attention deficit disorder','can\'t focus','easily distracted','losing things','forgetful adhd','daydreaming disorder'], emoji:'💭', type:'mood', description:'A presentation of ADHD characterized primarily by difficulty sustaining attention, being easily distracted, forgetfulness, and disorganization — without prominent hyperactivity or impulsivity. Often underdiagnosed, especially in girls.', symptoms:['Difficulty sustaining attention in tasks or play','Easily distracted by unrelated stimuli','Does not seem to listen when spoken to directly','Fails to follow through on instructions or finish tasks','Loses things necessary for tasks (keys, phone, schoolwork)','Forgetful in daily activities','Avoids tasks requiring sustained mental effort','Disorganized — difficulty organizing tasks and managing time'], causes:['Genetic factors — strong hereditary component','Differences in dopamine regulation in prefrontal cortex','Premature birth or low birth weight','Prenatal exposure to toxins'], homecare:['Use external organization systems — planners, reminders, alarms','Break tasks into small, timed chunks','Work in a low-distraction environment','Use body-doubling (working alongside someone else)','Regular aerobic exercise improves focus'], whenToSeeDoctor:'A psychiatrist or psychologist can diagnose ADHD through clinical assessment. Medication (stimulants or non-stimulants), CBT, and coaching are the main treatments. Diagnosis can transform daily life.', urgency:'medium' },

  { name:'ADHD Hyperactive', aliases:['adhd hyperactive','hyperactive adhd','hyperactivity','can\'t sit still','impulsive child','fidgeting','restless adhd','overactive child'], emoji:'⚡', type:'mood', description:'A presentation of ADHD where hyperactivity and impulsivity are the dominant symptoms. The person cannot remain still, interrupts frequently, and acts before thinking. More commonly identified in children, particularly boys.', symptoms:['Fidgeting with hands, feet, or squirming in seat','Leaving seat in situations where remaining seated is expected','Running or climbing excessively in inappropriate situations','Unable to play or engage in quiet activities','Always "on the go" as if driven by a motor','Talking excessively','Blurting out answers before a question is completed','Difficulty waiting turn — interrupting or intruding'], causes:['Genetic predisposition','Dopamine and norepinephrine dysregulation','Brain development differences in frontal lobe','Premature birth or low birth weight'], homecare:['Provide frequent movement breaks','Use fidget tools during seated activities','Set clear, consistent rules and routines','Use positive reinforcement for appropriate behavior','Reduce screen overstimulation'], whenToSeeDoctor:'A pediatrician, psychiatrist, or psychologist can assess and diagnose. Medication combined with behavioral strategies is most effective. School accommodation plans are important for children.', urgency:'medium' },

  { name:'ADHD Combined', aliases:['adhd combined','adhd','attention deficit hyperactivity disorder','combined adhd','adhd both types','full adhd'], emoji:'🌪️', type:'mood', description:'The most common presentation of ADHD, where a person meets criteria for both inattentive and hyperactive-impulsive symptoms. Affects academic performance, work, relationships, and self-esteem across the lifespan.', symptoms:['Both significant inattention and hyperactivity-impulsivity present','Difficulty sustaining attention AND difficulty sitting still or controlling impulses','Symptoms present in multiple settings — home, school, work','Symptoms begin in childhood (before age 12)','Cause significant impairment to social, academic, or occupational functioning'], causes:['Genetic — 70-80% heritability','Dopamine and norepinephrine dysregulation','Brain volume and connectivity differences','Premature birth, prenatal substance exposure'], homecare:['Combine organizational strategies with movement outlets','Use structured, predictable routines','Reward positive behaviors consistently','ADHD coaching and CBT for adults is very effective','Regular exercise is a natural dopamine booster'], whenToSeeDoctor:'Requires comprehensive assessment by a psychiatrist or psychologist. Combined type ADHD often needs both medication and behavioral therapy. Early diagnosis improves lifetime outcomes significantly.', urgency:'medium' },

  { name:'Autism Level 1', aliases:['autism level 1','autism spectrum level 1','high functioning autism','asperger like','mild autism','social communication difficulties','asd level 1'], emoji:'🧩', type:'mood', description:'The mildest level of autism spectrum disorder (formerly "high-functioning autism"). The person requires some support. Social communication challenges are present but the person can function with minimal assistance.', symptoms:['Difficulties with social communication and interaction','Trouble understanding social cues, sarcasm, or unspoken rules','Preference for routines and sameness','Narrow, intense interests','Sensory sensitivities — to sound, light, texture, or touch','May mask difficulties in social settings, causing exhaustion','Formal or unusual speech patterns'], causes:['Strong genetic component','Brain connectivity differences','Gene mutations affecting neural development','Advanced parental age is a risk factor'], homecare:['Use clear, literal communication — avoid sarcasm or ambiguous language','Provide advance warning before routine changes','Allow time for special interests — they provide regulation and joy','Create low-sensory environments where possible'], whenToSeeDoctor:'A developmental pediatrician, psychiatrist, or clinical psychologist can diagnose. Social skills therapy, CBT, and speech therapy can be helpful. Diagnosis can provide enormous relief and access to support.', urgency:'low' },

  { name:'Autism Level 2', aliases:['autism level 2','asd level 2','moderate autism','autism requiring substantial support','autism spectrum disorder moderate'], emoji:'🧩', type:'mood', description:'A moderate level of autism spectrum disorder where the person requires substantial support. Marked deficits in social communication are present, and restricted and repetitive behaviors occur frequently enough to be obvious to the casual observer.', symptoms:['Marked deficits in social communication — limited initiation','Unusual or reduced response to social approaches from others','Rigid behavior and significant difficulty coping with change','Restricted and repetitive behaviors that are frequent and obvious','Limited range of interests','Difficulties functioning without support across settings'], causes:['Genetic and neurological factors','Same causes as all autism — level describes degree of support needed, not cause'], homecare:['Visual schedules and clear routines reduce anxiety significantly','Social stories help navigate unfamiliar situations','Sensory accommodations — noise-cancelling headphones, weighted blankets','Allow processing time — do not rush responses'], whenToSeeDoctor:'A multidisciplinary team (developmental pediatrician, speech therapist, OT, psychologist) is ideal. ABA therapy, speech and language therapy, and occupational therapy are key supports.', urgency:'medium' },

  { name:'Autism Level 3', aliases:['autism level 3','severe autism','asd level 3','autism requiring very substantial support','nonverbal autism'], emoji:'🧩', type:'mood', description:'The most severe level of autism spectrum disorder, requiring very substantial support. Severe deficits in social communication, very limited initiation, and extremely restricted and repetitive behaviors markedly impair functioning.', symptoms:['Severe deficits in verbal and nonverbal social communication','Very limited initiation of social interactions','Minimal response to social overtures from others','Extreme difficulty coping with change — severe distress when routines are disrupted','Repetitive behaviors markedly interfere with functioning','May be nonspeaking or have very limited speech'], causes:['Genetic and neurological factors','May be associated with other genetic conditions (e.g., Fragile X, Rett syndrome)'], homecare:['Consistent, structured environment is essential','Augmentative and Alternative Communication (AAC) systems (picture boards, apps)','Sensory accommodations are critical','Caregivers should access respite care to prevent burnout'], whenToSeeDoctor:'Full-time specialist support is required. A multidisciplinary team including behavioral support, speech therapy, OT, and medical management should be coordinated. Caregiver support is equally important.', urgency:'high' },

  { name:'Asperger Syndrome', aliases:['asperger syndrome','asperger\'s','aspergers','high functioning autism','asd without intellectual disability','social difficulties with intelligence'], emoji:'🧩', type:'mood', description:'Now included within Autism Spectrum Disorder Level 1 in modern diagnostic systems, Asperger syndrome was characterized by significant difficulties in social interaction and nonverbal communication, alongside restricted and repetitive patterns of behavior, but without significant delays in language or cognitive development.', symptoms:['Significant difficulty with social interaction and understanding social rules','Intense focus on specific interests (encyclopedic knowledge of narrow topics)','Preference for routines and predictability','Literal thinking and difficulty with figurative language','Strong sense of justice and fairness','Often above-average intelligence in specific areas'], causes:['Genetic factors — runs in families','Neurological development differences','Not caused by parenting style, vaccines, or diet'], homecare:['Use explicit social rules and scripts for complex situations','Channel intense interests into academic or career pursuits','Provide quiet, low-stimulation environments','Peer support groups can build community'], whenToSeeDoctor:'Diagnosis and support from a psychologist or psychiatrist experienced in autism. Social skills training, CBT, and vocational support can be highly beneficial.', urgency:'low' },

  { name:'Tic Disorder', aliases:['tic disorder','tics','motor tics','vocal tics','involuntary movements','twitching','blinking tic','throat clearing tic'], emoji:'💫', type:'mood', description:'A condition involving sudden, repetitive, nonrhythmic movements or sounds (tics) that are difficult to control. Can be motor (movements) or vocal (sounds). Includes transient, chronic, and Tourette syndrome depending on duration and type.', symptoms:['Simple motor tics: eye blinking, head jerking, shoulder shrugging','Vocal tics: throat clearing, sniffing, grunting','Tics are worse with stress and better during focused activity or sleep','Premonitory urge before the tic — a sensation that is relieved by performing the tic','Ability to suppress tics temporarily but with increasing discomfort'], causes:['Genetic predisposition','Dopamine system dysregulation','PANDAS (tics triggered by streptococcal infection in children)','Stress exacerbates tics'], homecare:['Reducing stress through relaxation techniques can decrease tic frequency','Avoid calling attention to tics — this increases anxiety and tics','Good sleep reduces tic severity','CBIT (Comprehensive Behavioral Intervention for Tics) techniques can be practiced'], whenToSeeDoctor:'A neurologist or child psychiatrist should be seen for diagnosis and treatment. CBIT is highly effective. Medication may be considered if tics are causing significant impairment.', urgency:'low' },

  { name:'Tourette Syndrome', aliases:['tourette syndrome','tourette\'s','tourettes','vocal and motor tics','coprolalia','involuntary swearing','multiple tics'], emoji:'💬', type:'mood', description:'A neurodevelopmental disorder involving multiple motor tics and at least one vocal tic, present for more than 1 year. Contrary to popular belief, only a minority of people with Tourette syndrome have coprolalia (involuntary swearing).', symptoms:['Multiple motor tics (movements)','At least one vocal tic (sounds)','Tics present for more than 1 year','Tics begin before age 18','Premonitory urge relieved by the tic','Tics wax and wane in severity and type','Commonly associated with OCD and ADHD'], causes:['Genetic — strong hereditary component','Dopamine and serotonin dysregulation','Basal ganglia circuit abnormalities','PANDAS in some cases'], homecare:['Stress reduction is the most important self-management tool','CBIT techniques — habit reversal training for specific tics','Educate school and social environments about the condition','Support groups provide community and coping strategies'], whenToSeeDoctor:'A neurologist or child psychiatrist should diagnose and manage Tourette syndrome. CBIT is the behavioral treatment of choice. Medication (antipsychotics, alpha-2 agonists) may be prescribed for impairing tics.', urgency:'medium' },

  /* ── EATING ── */
  { name:'Anorexia Nervosa', aliases:['anorexia nervosa','anorexia','not eating','fear of weight gain','extreme dieting','starvation disorder','restriction eating','too thin eating disorder'], emoji:'⚖️', type:'mood', description:'A serious eating disorder characterized by severe restriction of food intake, intense fear of gaining weight, and a distorted body image. It has the highest mortality rate of any psychiatric disorder.', symptoms:['Significantly low body weight','Intense fear of gaining weight or becoming fat','Distorted body image — sees self as fat even when underweight','Restriction of calories or food groups','Denial of seriousness of low body weight','Absence of menstrual periods in women','Physical signs: fine body hair (lanugo), cold intolerance, fatigue, brittle hair and nails'], causes:['Genetic predisposition','Cultural emphasis on thinness','Perfectionism and anxiety','History of trauma, bullying, or comments about body size','Media and social media exposure'], homecare:['Do not comment on weight or food choices — this worsens the disorder','Encourage professional help without pressure or ultimatums','Maintain mealtimes as calm, social, neutral events','Avoid diet talk or body comparison in the household'], whenToSeeDoctor:'Urgently — anorexia can be life-threatening. Medical monitoring, nutritional rehabilitation, and eating disorder-specific psychotherapy (FBT, CBT-E) are required. In severe cases, inpatient treatment is necessary.', urgency:'high' },

  { name:'Bulimia Nervosa', aliases:['bulimia nervosa','bulimia','binge and purge','purging','vomiting after eating','laxative misuse','eating disorder purging'], emoji:'🔄', type:'mood', description:'An eating disorder characterized by recurrent episodes of binge eating followed by compensatory behaviors such as self-induced vomiting, laxative use, or excessive exercise, driven by an overconcern with body shape and weight.', symptoms:['Recurrent episodes of eating a large amount of food in a short period','Feeling out of control during binge episodes','Compensatory behaviors: vomiting, laxatives, diuretics, fasting, or excessive exercise','Self-evaluation overly influenced by body shape and weight','Usually at a normal weight (unlike anorexia)','Swollen cheeks (from parotid glands)','Dental erosion from stomach acid'], causes:['Genetic predisposition','Dieting and restrictive eating (increases binge risk)','Emotional dysregulation — using food to cope','Cultural pressure on thinness','History of trauma or abuse'], homecare:['Avoid skipping meals — regular eating reduces binge urges','Remove the habit of eating secretly or in hiding','Identify emotional triggers for binges and find alternative coping strategies','Tell a trusted person — secrecy maintains the cycle'], whenToSeeDoctor:'An eating disorder specialist should be seen. CBT-E is the gold standard treatment for bulimia. Medication (SSRIs) can reduce binge-purge frequency. Dental and medical monitoring are also needed.', urgency:'high' },

  { name:'Binge Eating Disorder', aliases:['binge eating disorder','bed','binge eating','overeating disorder','compulsive overeating','eating large amounts','loss of control eating'], emoji:'🍽️', type:'mood', description:'The most common eating disorder, characterized by recurrent episodes of eating large amounts of food quickly and feeling out of control during the episode, without regular compensatory behaviors. Associated with significant distress and often obesity.', symptoms:['Recurrent episodes of binge eating (at least once a week for 3 months)','Eating much more rapidly than normal','Eating until uncomfortably full','Eating large amounts when not physically hungry','Eating alone due to embarrassment','Feeling disgusted, depressed, or guilty after bingeing','No regular purging behaviors'], causes:['Emotional eating and difficulty tolerating negative emotions','Genetic predisposition','History of dieting','Trauma, depression, or anxiety','Weight stigma and shame'], homecare:['Eat regular scheduled meals to prevent extreme hunger that triggers binges','Keep a food and emotion diary','Identify emotional triggers and develop alternative coping strategies','Practice mindful eating — slow down and pay attention to food','Avoid labeling foods as "bad" — restriction increases binge urge'], whenToSeeDoctor:'CBT is highly effective for BED. A therapist specializing in eating disorders is ideal. DBT and interpersonal therapy are also used. Medication can help. Addressing co-occurring depression and anxiety is important.', urgency:'medium' },

  { name:'Avoidant Restrictive Food Intake', aliases:['arfid','avoidant restrictive food intake disorder','picky eating extreme','fear of food','texture aversion eating','limited food intake not weight related','food phobia'], emoji:'🥗', type:'mood', description:'An eating disorder involving persistent avoidance or restriction of food based on sensory characteristics (texture, smell, color), fear of negative consequences (choking, vomiting), or apparent lack of interest in eating. Not driven by body image concerns.', symptoms:['Persistent avoidance or restriction of food intake','Significant weight loss or nutritional deficiency','Dependence on nutritional supplements or tube feeding','Significant interference with psychosocial functioning','Limited repertoire of accepted foods','Intense distress or gagging when exposed to non-accepted foods'], causes:['Sensory processing differences (common in autism)','Traumatic food-related experience (choking, severe vomiting)','Anxiety disorder predisposition','Never extended food variety in childhood'], homecare:['Food chaining — gradually expand from accepted foods by making small changes','Make mealtimes calm and pressure-free','Offer new foods alongside accepted ones without pressure','Never force eating or use food as punishment/reward'], whenToSeeDoctor:'A multidisciplinary team (dietitian, occupational therapist for sensory issues, psychologist) is ideal. CBT and exposure therapy for food are used. Medical monitoring of nutritional status is important.', urgency:'medium' },

  { name:'Pica', aliases:['pica','eating non-food items','eating dirt','eating chalk','eating hair','eating ice compulsively','pagophagia'], emoji:'🪨', type:'mood', description:'An eating disorder characterized by the persistent eating of non-nutritive, non-food substances for at least 1 month — such as dirt, chalk, clay, paper, hair, or ice. Common in young children, pregnant women, and people with intellectual disabilities.', symptoms:['Persistently eating non-food substances','Common substances: dirt, clay, chalk, paper, hair, ice, paint chips','Behavior is inappropriate for developmental level','Behavior is not culturally sanctioned','Can cause significant medical complications — lead poisoning, intestinal blockage, parasites'], causes:['Nutritional deficiency (iron, zinc)','Developmental disorders (intellectual disability, autism)','Pregnancy — cravings for specific non-foods','Cultural practice in some communities','Stress or neglect'], homecare:['Test and correct any nutritional deficiencies','Keep non-food substances out of reach','Use redirection when pica behavior is observed','Ensure a nutritionally adequate diet'], whenToSeeDoctor:'Always — pica can cause serious medical complications. Treat any nutritional deficiencies. A developmental specialist or psychiatrist should be involved. Behavioral therapy is used for persistent pica.', urgency:'high' },

  { name:'Rumination Disorder', aliases:['rumination disorder','regurgitating food','re-chewing food','food coming back up','rumination syndrome'], emoji:'🔄', type:'mood', description:'A condition where a person repeatedly and unintentionally regurgitates undigested food from the stomach, re-chews it, and then re-swallows or spits it out. Not associated with nausea or disgust, distinguishing it from vomiting disorders.', symptoms:['Repeated regurgitation of food shortly after eating','Regurgitated food is undigested and not acidic (recent meals)','Re-chewing, re-swallowing, or spitting out regurgitated food','No nausea, retching, or disgust associated','May cause weight loss, nutritional deficiency, dental erosion','Embarrassment in social eating situations'], causes:['Habit that develops from stress or sensory seeking','Underlying gastrointestinal issues','Developmental or intellectual disability','Anxiety or emotional distress'], homecare:['Diaphragmatic breathing exercises after meals — this is the primary behavioral treatment','Eat in a calm, relaxed environment','Sit upright after eating','Avoid eating when stressed'], whenToSeeDoctor:'A gastroenterologist and psychiatrist or psychologist should both be involved. Diaphragmatic breathing retraining is highly effective. Biofeedback may also help.', urgency:'medium' },

  /* ── PERSONALITY ── */
  { name:'Borderline Personality', aliases:['borderline personality disorder','bpd','borderline personality','emotional instability','fear of abandonment','self harm bpd','identity disturbance','unstable relationships'], emoji:'🌊', type:'personality', description:'A personality disorder characterized by a pervasive pattern of instability in interpersonal relationships, self-image, and emotions, and marked impulsivity. Intense fear of abandonment — real or imagined — is central to the disorder.', symptoms:['Frantic efforts to avoid real or imagined abandonment','Unstable and intense interpersonal relationships (idealization and devaluation)','Identity disturbance — unstable self-image','Impulsivity in at least 2 self-damaging areas (spending, sex, substance use, reckless driving)','Recurrent suicidal behavior, gestures, or self-harm','Emotional instability — intense mood episodes lasting hours to days','Chronic feelings of emptiness','Intense anger, difficulty controlling anger','Transient paranoia or dissociation under stress'], causes:['Genetic predisposition','History of childhood trauma, abuse, or neglect','Emotionally invalidating environment during childhood','Biological sensitivity and emotional reactivity'], homecare:['Use DBT (Dialectical Behavior Therapy) skills: distress tolerance, mindfulness, emotion regulation, interpersonal effectiveness','Use a crisis plan when self-harm urges arise','Call a trusted person or crisis line when feeling overwhelmed','Avoid making major decisions during intense emotional states'], whenToSeeDoctor:'DBT (Dialectical Behavior Therapy) is the gold-standard treatment for BPD and has excellent outcomes. A psychiatrist experienced in personality disorders should manage medication. Recovery is absolutely possible.', urgency:'high' },

  { name:'Narcissistic Personality', aliases:['narcissistic personality disorder','npd','narcissist','narcissism','grandiosity','lack of empathy','self-centered','attention seeking personality'], emoji:'👑', type:'personality', description:'A personality disorder characterized by a pervasive pattern of grandiosity, need for admiration, and lack of empathy. Beneath the grandiose exterior often lies fragile self-esteem vulnerable to the slightest criticism.', symptoms:['Grandiose sense of self-importance','Preoccupied with fantasies of unlimited success, power, or beauty','Believes they are special and unique, understood only by other special people','Requires excessive admiration','Sense of entitlement','Exploits others to achieve goals','Lacks empathy','Often envious of others or believes others envy them','Shows arrogant, haughty behaviors'], causes:['Overvaluation or excessive praise in childhood','Childhood abuse or neglect','Genetic predisposition','Cultural emphasis on individualism and status'], homecare:['Therapy is the primary treatment — self-help has limited effect alone','Practice listening to others with genuine curiosity','Work on accepting constructive criticism without viewing it as an attack'], whenToSeeDoctor:'Psychotherapy (particularly schema therapy or transference-focused psychotherapy) is the treatment for NPD. People with NPD often seek help for depression or relationship breakdown rather than NPD itself.', urgency:'low' },

  { name:'Antisocial Personality', aliases:['antisocial personality disorder','aspd','antisocial personality','psychopathy','sociopathy','disregard for others','rule breaking','conduct disorder adult'], emoji:'⚠️', type:'personality', description:'A personality disorder characterized by a pervasive pattern of disregard for and violation of the rights of others. Includes persistent lying, exploitation, impulsivity, and lack of remorse. Associated with criminal behavior in severe cases.', symptoms:['Failure to conform to social norms and lawful behavior','Deceitfulness, lying, manipulating for personal gain','Impulsivity and failure to plan ahead','Irritability and aggressiveness — repeated fights or assaults','Reckless disregard for the safety of self or others','Consistent irresponsibility','Lack of remorse for hurting or exploiting others'], causes:['Genetic predisposition','Conduct disorder in childhood (required for diagnosis)','Childhood abuse, neglect, or chaotic environment','Neurobiological differences — reduced amygdala function'], homecare:['Therapy requires specialist expertise and willingness to engage','Anger management programs may help with impulsivity','Substance abuse treatment if co-occurring'], whenToSeeDoctor:'Specialized forensic or personality disorder services are most appropriate. Motivation to change is essential for therapy to work. Family members of people with ASPD may benefit from therapy themselves.', urgency:'medium' },

  { name:'Histrionic Personality', aliases:['histrionic personality disorder','hpd','histrionic personality','attention seeking','drama personality','excessive emotionality','seductive behavior disorder'], emoji:'🎭', type:'personality', description:'A personality disorder characterized by a pervasive pattern of excessive emotionality and attention-seeking behavior. People with HPD feel uncomfortable when they are not the center of attention and may use dramatic or provocative behavior to gain it.', symptoms:['Uncomfortable when not the center of attention','Inappropriate sexually seductive or provocative behavior','Rapidly shifting and shallow emotions','Uses physical appearance to draw attention','Impressionistic speech — lacks detail','Theatrical and exaggerated emotional expression','Suggestible — easily influenced by others','Considers relationships more intimate than they actually are'], causes:['Genetic predisposition','Parenting styles that rewarded drama or attention-seeking','Cultural factors'], homecare:['Therapy is the primary treatment','Practice pausing and listening in conversations','Work on building deeper, more reciprocal relationships'], whenToSeeDoctor:'Psychotherapy — particularly psychodynamic therapy or CBT — is the treatment. HPD is often accompanied by depression or anxiety, which may be the presenting concern.', urgency:'low' },

  { name:'Paranoid Personality', aliases:['paranoid personality disorder','ppd','paranoid personality','suspicious of everyone','can\'t trust anyone','always thinks people have bad motives','extreme suspicion'], emoji:'👁️', type:'personality', description:'A personality disorder characterized by a pervasive distrust and suspiciousness of others, such that their motives are interpreted as malevolent. The paranoia is persistent, affects multiple relationships, and is not caused by schizophrenia or a mood disorder.', symptoms:['Suspects without sufficient basis that others are exploiting or deceiving them','Preoccupied with unjustified doubts about loyalty or trustworthiness of others','Reluctant to confide in others for fear information will be used against them','Reads hidden demeaning or threatening meanings into benign remarks','Bears grudges persistently','Perceives attacks on character not apparent to others and reacts with anger','Recurrent suspicions about fidelity of partner'], causes:['Genetic factors related to schizophrenia spectrum','Childhood trauma, abuse, or discrimination','Chronic experiences of being targeted or wronged'], homecare:['Build trust very gradually — do not expect rapid openness','Avoid confrontational debates about the paranoid beliefs','Consistent, transparent, and predictable behavior from those around them'], whenToSeeDoctor:'Paranoid personality disorder is challenging to treat as trust in therapists is difficult. CBT and supportive therapy with patience can help. Medication is not the primary treatment but may be used for co-occurring anxiety or depression.', urgency:'low' },

  { name:'Schizoid Personality', aliases:['schizoid personality disorder','schizoid personality','emotionally detached','loner','no interest in relationships','emotional coldness','socially isolated personality'], emoji:'🧊', type:'personality', description:'A personality disorder characterized by a pervasive pattern of detachment from social relationships and a restricted range of emotional expression. People with schizoid personality prefer solitary activities and appear emotionally cold or indifferent.', symptoms:['Neither desires nor enjoys close relationships including family','Almost always chooses solitary activities','Little interest in sexual experiences with others','Finds pleasure in few activities','No close friends or confidants other than first-degree relatives','Appears indifferent to praise or criticism','Shows emotional coldness, detachment, or flattened affect'], causes:['Genetic factors related to schizophrenia spectrum','Childhood emotional neglect or cold parenting','Highly introverted temperament'], homecare:['Solitude is not inherently harmful — balance with manageable social contact','Online or interest-based communities may suit the preference for limited interaction'], whenToSeeDoctor:'Most people with schizoid personality do not seek treatment. If distress or impairment is present, supportive therapy or CBT can help with specific concerns.', urgency:'low' },

  { name:'Schizotypal Personality', aliases:['schizotypal personality disorder','schizotypal personality','magical thinking','odd beliefs','eccentric personality','ideas of reference','peculiar thinking','brief psychosis like symptoms'], emoji:'🔮', type:'personality', description:'A personality disorder characterized by acute discomfort in close relationships, cognitive or perceptual distortions, and eccentricities of behavior. Includes magical thinking, ideas of reference, and odd speech. Considered part of the schizophrenia spectrum.', symptoms:['Ideas of reference (believing unrelated events have special personal meaning)','Odd beliefs or magical thinking (superstitions, belief in special powers)','Unusual perceptual experiences','Odd thinking and speech','Suspiciousness or paranoid ideation','Inappropriate or constricted affect','Eccentric behavior or appearance','Lack of close friends outside family','Excessive social anxiety'], causes:['Genetic — closely related to schizophrenia in family studies','Childhood trauma or neglect','Neurobiological factors'], homecare:['Consistent, low-pressure social connections can help over time','Social skills training can be practiced in safe environments'], whenToSeeDoctor:'A psychiatrist should assess for psychosis risk. Low-dose antipsychotics may help with perceptual distortions. CBT and social skills training are beneficial. Close monitoring for progression to schizophrenia is important.', urgency:'medium' },

  { name:'Avoidant Personality', aliases:['avoidant personality disorder','avpd','avoidant personality','fear of rejection','extreme shyness','avoiding relationships','feelings of inadequacy','hypersensitive to criticism'], emoji:'🚶', type:'personality', description:'A personality disorder characterized by pervasive feelings of inadequacy, extreme sensitivity to criticism or rejection, and avoidance of social activities despite a desire for relationships. Different from schizoid personality — the person wants connection but fears rejection too much to pursue it.', symptoms:['Avoids occupational activities involving significant interpersonal contact','Unwilling to get involved with people unless certain of being liked','Shows restraint in intimate relationships due to fear of ridicule','Preoccupied with being criticized or rejected in social situations','Inhibited in new interpersonal situations due to feelings of inadequacy','Views self as socially inept, personally unappealing, or inferior','Unusually reluctant to take personal risks or new activities'], causes:['Genetic predisposition to anxiety and inhibited temperament','Childhood rejection, ridicule, or neglect by parents or peers','Chronic experiences of being criticized'], homecare:['Gradual exposure to feared social situations with support','Practice self-compassion — challenge harsh self-critical thoughts','Online communities can provide safer first steps toward connection'], whenToSeeDoctor:'CBT with gradual exposure, schema therapy, and social skills training are the treatments of choice. Antidepressants or anxiolytics may help reduce the anxiety that maintains avoidance.', urgency:'low' },

  { name:'Dependent Personality', aliases:['dependent personality disorder','dpd','dependent personality','can\'t make decisions alone','clingy adult','needs others for everything','fear of independence'], emoji:'🤝', type:'personality', description:'A personality disorder characterized by a pervasive and excessive need to be taken care of, leading to submissive and clinging behavior and fears of separation. The person has difficulty making everyday decisions without reassurance from others.', symptoms:['Difficulty making everyday decisions without excessive advice and reassurance','Needs others to assume responsibility for major life areas','Has difficulty expressing disagreement for fear of loss of support','Difficulty starting projects without excessive support from others','Goes to excessive lengths to obtain nurturance and support','Feels uncomfortable or helpless when alone','Urgently seeks new relationship when one ends','Unrealistically preoccupied with fears of being left to care for themselves'], causes:['Overprotective or authoritarian parenting','Genetic predisposition to anxiety','Cultural factors valuing submissiveness and self-sacrifice'], homecare:['Practice making small decisions independently, then building up','Challenge catastrophic beliefs about being alone','Develop interests and skills independent of others'], whenToSeeDoctor:'Psychotherapy (CBT, psychodynamic) focused on autonomy and self-efficacy is the main treatment. Progress is gradual. Medication may help co-occurring anxiety or depression.', urgency:'low' },

  { name:'Obsessive Compulsive Personality', aliases:['obsessive compulsive personality disorder','ocpd','perfectionism disorder','rigid personality','control freak','perfectionist','inflexibility','overly organized personality'], emoji:'📋', type:'personality', description:'A personality disorder characterized by a preoccupation with orderliness, perfectionism, and control — at the expense of flexibility, openness, and efficiency. Different from OCD: the behaviors are ego-syntonic (the person sees them as correct and desirable).', symptoms:['Preoccupied with details, rules, lists, order, organization to the point that the activity is lost','Perfectionism that interferes with task completion','Excessively devoted to work and productivity at expense of leisure and friendships','Overconscientious and inflexible about ethics, morals, or values','Unable to delegate tasks unless done exactly their way','Miserly spending — hoarding money for future disaster','Shows rigidity and stubbornness'], causes:['Genetic predisposition','Childhood environment emphasizing rules, perfectionism, or punishment for mistakes','Anxious temperament'], homecare:['Practice intentional imperfection — send an email without rereading it 5 times','Delegate tasks and practice tolerating how others do things','Schedule leisure time and treat it as non-negotiable'], whenToSeeDoctor:'CBT and psychodynamic therapy can help. People with OCPD often come to therapy for depression, burnout, or relationship problems rather than recognizing OCPD itself. Progress is possible with motivated engagement.', urgency:'low' },

  /* ── DISSOCIATIVE ── */
  { name:'Dissociative Identity Disorder', aliases:['dissociative identity disorder','did','multiple personality disorder','alternate personalities','alters','identity switching','mpd'], emoji:'🪞', type:'anxiety', description:'A condition involving the presence of two or more distinct personality states or identities that recurrently take control of behavior. Associated with severe trauma, usually childhood abuse. Formerly known as multiple personality disorder.', symptoms:['Two or more distinct personality states (alters) with their own perspectives and behaviors','Amnesia between personality states — not remembering what happened during another alter','Gaps in memory of daily events','Hearing internal voices (alters communicating)','Depersonalization and derealization','Identity confusion — not knowing who you are','Fugue states — finding yourself in a place without knowing how you got there'], causes:['Severe, repeated childhood trauma — usually physical or sexual abuse','An extremely overwhelming experience requiring psychological separation to survive','Absence of adequate external support after trauma'], homecare:['Safety planning is essential — work with a trauma-informed therapist','Ground yourself during dissociative episodes using sensory techniques','Learn to recognize switches and practice internal communication between alters'], whenToSeeDoctor:'DID requires a trauma-informed therapist with specific expertise in dissociative disorders. Treatment is long-term and involves trauma processing (e.g., EMDR) and integration or cooperation of alters.', urgency:'high' },

  { name:'Depersonalization Disorder', aliases:['depersonalization disorder','dpdr','depersonalization','derealization','feeling unreal','out of body feeling','watching yourself from outside','feeling like a robot','detached from self'], emoji:'👁️', type:'anxiety', description:'A dissociative disorder involving persistent or recurrent experiences of feeling detached from one\'s mind or body (depersonalization) or feeling that the surroundings are unreal (derealization). Reality testing remains intact — the person knows they are real.', symptoms:['Feeling detached from thoughts, feelings, sensations, or body (depersonalization)','Feeling as if you are an outside observer of your thoughts and feelings','Surroundings feeling unreal, dreamlike, or foggy (derealization)','Feeling emotionally or physically numb','Reality testing is intact — you know you are real','Episodes may be brief or persistent','Significant distress or impairment'], causes:['Anxiety and panic disorder','Trauma and PTSD','Cannabis or hallucinogen use','Extreme stress or sleep deprivation','Anxiety disorder'], homecare:['Grounding techniques — hold ice, focus on textures, smell strong scents','Reduce anxiety — it is the most common driver of DPDR','Vigorous exercise can help reconnect with the body','Limit cannabis and alcohol which worsen dissociation'], whenToSeeDoctor:'A mental health professional can diagnose and offer CBT specifically targeting depersonalization. Treating underlying anxiety or trauma is often key. Medication is secondary but may help co-occurring anxiety.', urgency:'medium' },

  { name:'Dissociative Amnesia', aliases:['dissociative amnesia','memory loss psychological','blocking traumatic memories','fugue state','losing memories after trauma','psychogenic amnesia'], emoji:'🧠', type:'anxiety', description:'An inability to recall important autobiographical information, usually traumatic or stressful in nature, that is too extensive to be explained by ordinary forgetfulness. Can be localized (specific event blocked), selective, or rarely generalized (entire life forgotten).', symptoms:['Inability to recall important personal information — typically around a traumatic event','Memory loss too extensive for ordinary forgetfulness','May involve forgetting a specific event, period, or rarely all personal information','Dissociative fugue (purposeless wandering with amnesia) in some cases','No neurological cause found on medical testing','Significant distress or functional impairment'], causes:['Trauma — abuse, violence, accidents, war, natural disaster','Extreme emotional stress','Psychological conflict too overwhelming to consciously tolerate'], homecare:['Create safety in the environment before attempting memory work','Journaling may help reconnect with fragmented memories over time','Work only with a trained trauma therapist — premature memory retrieval can be harmful'], whenToSeeDoctor:'A trauma-informed psychiatrist or psychologist should assess and treat. Specialized therapy (hypnotherapy in some settings, EMDR) may help memory retrieval safely. Never attempt to force memory recall independently.', urgency:'high' },

  /* ── SOMATIC ── */
  { name:'Conversion Disorder', aliases:['conversion disorder','functional neurological symptom disorder','psychosomatic neurological','paralysis from stress','blindness from stress','functional seizures','psychogenic seizures','fnd'], emoji:'⚡', type:'mood', description:'A condition in which psychological stress manifests as neurological symptoms — such as weakness, paralysis, blindness, non-epileptic seizures, or speech problems — without any underlying neurological disease. The symptoms are real and involuntary.', symptoms:['Weakness or paralysis in a limb','Non-epileptic seizures (functional seizures)','Episodes of blindness or double vision','Speech problems — slurred speech or inability to speak','Sensory disturbances — numbness or loss of feeling','Swallowing difficulties','Symptoms inconsistent with known neurological disease patterns'], causes:['Psychological stress or trauma (often preceding symptoms)','Emotional conflict that cannot be expressed verbally','History of trauma or abuse','Pre-existing neurological disorder (increases risk)'], homecare:['Understanding that symptoms are real, not imagined, is important for all involved','Reduce overall stress load','Physiotherapy is often the most important treatment','Avoid medical investigations that reinforce sick role'], whenToSeeDoctor:'A neurologist and psychiatrist should work together. Physiotherapy, CBT, and psychotherapy targeting underlying psychological factors are the main treatments. Prognosis is better with early treatment.', urgency:'high' },

  { name:'Somatic Symptom Disorder', aliases:['somatic symptom disorder','ssd','psychosomatic','bodily distress','physical symptoms anxiety','medically unexplained symptoms','health preoccupation with physical symptoms'], emoji:'🩺', type:'mood', description:'A condition involving distressing physical symptoms along with excessive thoughts, feelings, and behaviors related to those symptoms. The physical symptoms are real and may or may not have a medical explanation, but the degree of concern is disproportionate.', symptoms:['One or more physical symptoms causing distress or disruption (pain, fatigue, neurological symptoms)','Excessive and persistent thoughts about the seriousness of symptoms','High level of health-related anxiety','Excessive time and energy devoted to symptoms or health concerns','Symptoms are persistent — often lasting 6+ months'], causes:['Chronic stress','History of trauma or abuse','Anxiety and depression','History of serious childhood illness','Family attitudes of excessive concern about physical illness'], homecare:['Maintain normal daily activities despite symptoms — avoidance worsens the cycle','Focus on functioning rather than symptom elimination','Challenge catastrophic thoughts about physical symptoms','Mindfulness reduces the distress around symptoms'], whenToSeeDoctor:'CBT is the most effective treatment, helping change the relationship with symptoms. A doctor-therapist team approach (primary care and mental health) works best.', urgency:'medium' },

  { name:'Illness Anxiety', aliases:['illness anxiety disorder','illness anxiety','health anxiety no symptoms','hypochondria new','fear of getting sick','constantly worried about illness','medically unexplained worry'], emoji:'🩻', type:'anxiety', description:'A condition of preoccupation with having or developing a serious illness, despite having little or no physical symptoms, and normal medical evaluations. Formally known as hypochondriasis when physical symptoms are absent or minimal.', symptoms:['High anxiety about having a serious illness','Minimal or absent physical symptoms','Excessive health behaviors — frequent doctor visits or medical tests — OR avoidance of medical care','Easily alarmed by health news or information about disease','Reassurance provides only temporary relief','Health concern persists despite normal medical findings'], causes:['Anxiety disorder predisposition','Personal or family history of serious illness','Childhood experiences of illness being given excessive attention','Exposure to alarming health information'], homecare:['Limit internet symptom searching to once per day at most','Practice sitting with uncertainty rather than seeking reassurance','Redirect attention to activities outside of health monitoring'], whenToSeeDoctor:'CBT specifically designed for health anxiety is very effective. A therapist experienced in health anxiety is recommended. Medication (SSRIs) may also help.', urgency:'low' },

  { name:'Factitious Disorder', aliases:['factitious disorder','munchausen syndrome','feigning illness','faking medical symptoms','intentional symptom production','munchausen by proxy'], emoji:'🎭', type:'mood', description:'A serious mental disorder in which a person deliberately creates, fakes, or exaggerates physical or psychological symptoms in themselves (or another person under their care — Factitious Disorder Imposed on Another/FDIA) to assume the sick role, without external gain.', symptoms:['Deceptive behavior in the absence of obvious external rewards','Creating or exaggerating physical or psychological symptoms','Extensive knowledge of medical terminology','Seeking treatment at many different facilities','Worsening of reported symptoms when not being observed','In FDIA: creating symptoms in another person, usually a child'], causes:['History of childhood abuse, neglect, or illness','Personality disorder features','Need for the attention and care associated with being ill','Emotional difficulties managing self-esteem'], homecare:['Confrontation is almost always counterproductive — person will leave and seek care elsewhere','A compassionate, non-punitive therapeutic relationship is key'], whenToSeeDoctor:'A psychiatrist is essential — confrontation without psychiatric backup is not recommended. Long-term psychotherapy addressing the underlying emotional needs is the treatment. FDIA cases require child protection services to be involved immediately.', urgency:'high' },

  /* ── ADDICTION ── */
  { name:'Gambling Disorder', aliases:['gambling disorder','gambling addiction','problem gambling','compulsive gambling','can\'t stop gambling','betting addiction'], emoji:'🎲', type:'addiction', description:'A behavioral addiction involving persistent and recurrent problematic gambling behavior that causes significant distress or impairment. The person has lost control over gambling despite serious negative consequences.', symptoms:['Needs to gamble with increasing amounts of money to achieve the desired excitement','Restless or irritable when trying to reduce or stop gambling','Repeated unsuccessful efforts to control, cut back, or stop gambling','Often preoccupied with gambling','Gambles when feeling distressed (helpless, guilty, anxious, depressed)','Chasing losses — returning to win back lost money','Lies to conceal involvement in gambling','Has lost significant relationships, job, or opportunities due to gambling'], causes:['Dopamine system dysregulation — gambling activates reward circuits','Genetic predisposition to addiction','Impulsivity traits','Exposure to gambling in family or culture','Financial stress'], homecare:['Gamblers Anonymous — 12-step fellowship for gambling recovery','Blocking software for online gambling accounts','Remove access to cash and bank cards as practical safety step','Ask a trusted person to manage finances temporarily'], whenToSeeDoctor:'A psychiatrist or addiction specialist should be seen. CBT is effective for gambling disorder. Gamblers Anonymous alongside therapy provides the best outcomes. Financial counseling is also important.', urgency:'high' },

  { name:'Internet Addiction', aliases:['internet addiction','screen addiction','online addiction','can\'t stop using internet','excessive internet use','internet use disorder','online compulsive use'], emoji:'📱', type:'addiction', description:'A pattern of excessive and compulsive internet use that significantly impairs daily life — including relationships, work or school, physical health, and sleep. While not yet an official DSM diagnosis for internet broadly, it is widely recognized clinically.', symptoms:['Preoccupation with the internet when offline','Need to use internet for increasing amounts of time for the same effect','Repeated unsuccessful efforts to cut back','Restlessness, irritability, or depression when not using internet','Using internet to escape or relieve negative mood','Loss of significant relationships, job, or educational opportunity due to internet use','Lying about how much time is spent online'], causes:['Dopamine reinforcement from social media, notifications, and online rewards','Social isolation — the internet fills social needs','Underlying depression, anxiety, or ADHD','Highly engaging platform design'], homecare:['Screen time tracking and daily limits using phone settings','Scheduled internet-free times (mealtimes, mornings, 1 hour before bed)','Develop offline hobbies and in-person social activities','Remove social media apps from phone — use browser only if needed'], whenToSeeDoctor:'A psychologist specializing in behavioral addictions can help. CBT targeting compulsive use patterns is effective. Treating underlying conditions (anxiety, depression, ADHD) is equally important.', urgency:'medium' },

  { name:'Gaming Disorder', aliases:['gaming disorder','video game addiction','can\'t stop gaming','compulsive gaming','gaming addiction','online gaming addiction'], emoji:'🎮', type:'addiction', description:'A pattern of gaming behavior characterized by impaired control over gaming, increasing priority given to gaming over other activities, and continuation or escalation of gaming despite negative consequences. Officially recognized by WHO in ICD-11.', symptoms:['Impaired control over gaming (onset, frequency, duration, termination)','Increasing priority given to gaming over daily activities and other interests','Continuation of gaming despite awareness of negative consequences','Gaming behavior leads to significant distress or impairment in personal, family, social, educational, or occupational functioning','Behavior pattern lasting at least 12 months'], causes:['Reward and achievement systems in games designed for compulsive use','Dopamine reinforcement','Social connection through gaming (especially online multiplayer)','Underlying depression, anxiety, or ADHD'], homecare:['Set clear daily gaming time limits and stick to them','No gaming before school, work, or meals','Develop offline interests and physical activities','Sleep hygiene — no gaming in the 2 hours before bed'], whenToSeeDoctor:'A psychologist experienced in behavioral addictions is recommended. CBT targeting gaming behaviors is effective. Address any underlying mental health conditions that gaming may be masking or exacerbating.', urgency:'medium' },

  { name:'Sex Addiction', aliases:['sex addiction','hypersexuality','compulsive sexual behavior','pornography addiction','out of control sexual behavior','hypersexual disorder'], emoji:'🔞', type:'addiction', description:'A pattern of out-of-control sexual thoughts, urges, and behaviors that cause significant personal distress and impaired functioning, despite repeated attempts to control them. Can involve pornography, affairs, compulsive masturbation, or other sexual behaviors.', symptoms:['Recurrent and intense sexual fantasies, urges, or behaviors that feel out of control','Uses sexual activity to cope with difficult emotions or life stressors','Repeated unsuccessful attempts to reduce or stop','Continues despite significant negative consequences (relationship damage, STIs, legal problems)','Sexual preoccupation consumes significant time and energy','Significant distress about sexual behavior'], causes:['Dopamine and reward circuit involvement','Trauma history — especially sexual trauma','Attachment disorders','Underlying depression, anxiety, or bipolar disorder'], homecare:['12-step programs (Sex Addicts Anonymous, SAA) provide community and structure','Identify emotional triggers and develop alternative coping strategies','Install internet content filters if pornography is the primary issue'], whenToSeeDoctor:'A therapist specializing in compulsive sexual behavior is recommended. CBT and mindfulness-based approaches are used. Treating co-occurring mental health conditions is essential. Partner therapy may also be needed.', urgency:'medium' },

  { name:'Work Addiction', aliases:['work addiction','workaholism','compulsive working','can\'t stop working','overworking','working to the point of burnout','cannot rest from work'], emoji:'💼', type:'addiction', description:'A compulsive and uncontrollable need to work excessively, used to manage emotions, avoid personal life, or derive self-worth exclusively from productivity. Often praised by society, making it one of the least recognized behavioral addictions.', symptoms:['Thinking about work when not working','Working beyond what is required by job demands or financial need','Using work to escape negative emotions or problems','Restless, irritable, or anxious when not working','Deprioritizing relationships, health, and leisure for work','Failed attempts to reduce working hours','Work is causing health problems but continues regardless'], causes:['Perfectionism and fear of failure','Equating self-worth with productivity','Anxiety management through busyness','Workaholic culture and employer expectations','Childhood experiences around achievement and approval'], homecare:['Schedule non-work time as firmly as work meetings','Practice doing nothing without guilt — start with 5 minutes','Deliberately engage in activities with no productive output','Talk to trusted others about the pattern'], whenToSeeDoctor:'A psychologist or therapist specializing in burnout and behavioral patterns can help. CBT and psychodynamic therapy both address the underlying drivers of work addiction. Burnout prevention is an urgent reason to seek help early.', urgency:'medium' },

  { name:'Shopping Addiction', aliases:['shopping addiction','compulsive buying disorder','compulsive shopping','oniomania','can\'t stop buying','retail therapy disorder','overspending compulsively'], emoji:'🛍️', type:'addiction', description:'A pattern of compulsive, uncontrolled buying that goes well beyond what is needed, used to manage emotions, and causing significant financial and interpersonal problems. The brief emotional high of purchasing is followed by guilt and shame.', symptoms:['Preoccupation with buying things','Buying more than intended or needed','Shopping as a response to negative emotions','Failed attempts to stop or control shopping','Financial problems as a result of spending','Hiding purchases from others','Significant guilt or shame after buying'], causes:['Dopamine release from the act of purchasing','Anxiety and emotional dysregulation','Low self-esteem — items provide temporary confidence','Culture of consumerism and social media marketing'], homecare:['Delete shopping apps and unsubscribe from marketing emails','Introduce a 48-hour waiting period before any non-essential purchase','Use cash rather than cards — physical money creates more awareness','Identify emotional triggers that precede shopping urges'], whenToSeeDoctor:'A psychologist specializing in compulsive behaviors can help. CBT targeting the purchasing behavior and underlying emotional triggers is effective. Financial counseling alongside therapy is recommended.', urgency:'medium' },

  { name:'Alcohol Use Disorder', aliases:['alcohol use disorder','aud','alcoholism','alcohol addiction','alcohol dependency','alcohol abuse','can\'t stop drinking','problem drinking'], emoji:'🍺', type:'addiction', description:'A chronic relapsing brain disorder characterized by compulsive alcohol use, loss of control over intake, and a negative emotional state when not using. Ranges from mild to severe. Physical dependence can develop and withdrawal can be life-threatening.', symptoms:['Drinking more or for longer than intended','Persistent desire or unsuccessful efforts to cut down','Spending a great deal of time drinking or recovering','Craving alcohol','Failure to fulfill major role obligations at home, work, school','Continued drinking despite social, relationship, or health problems','Giving up activities due to drinking','Tolerance — needing more to feel the effect','Withdrawal symptoms when stopping'], causes:['Genetic predisposition — 50% heritability','Stress, trauma, and untreated mental health conditions','Early initiation of drinking','Social and cultural factors'], homecare:['Never stop heavy drinking abruptly without medical supervision — withdrawal can cause seizures and be fatal','Avoid keeping alcohol at home','Alcoholics Anonymous — 12-step support group','Tell your doctor honestly about your drinking'], whenToSeeDoctor:'A psychiatrist or addiction medicine specialist is required. Medical detoxification may be needed for physical dependence. Medications (naltrexone, acamprosate, disulfiram) are effective. AA and CBT-based programs support recovery.', urgency:'high' },

  { name:'Opioid Use Disorder', aliases:['opioid use disorder','opioid addiction','heroin addiction','painkiller addiction','prescription opioid addiction','opioid dependency','oud'], emoji:'💊', type:'addiction', description:'A chronic disorder characterized by loss of control over opioid use (prescription painkillers or heroin) despite serious negative consequences. Physical dependence and intense withdrawal symptoms develop rapidly. Overdose risk is high.', symptoms:['Taking opioids in larger amounts or for longer than intended','Persistent desire or unsuccessful efforts to cut down or control use','Spending a great deal of time obtaining, using, or recovering from opioids','Craving opioids','Failure to fulfill major role obligations','Continued use despite social and interpersonal problems','Withdrawal symptoms when stopping — severe muscle pain, vomiting, anxiety, insomnia'], causes:['Genetic vulnerability to addiction','Chronic pain treated with opioids','Trauma and untreated mental health disorders','Accessibility of prescription opioids'], homecare:['Medication-Assisted Treatment (MAT) with buprenorphine or methadone is the most effective approach — see a doctor','Never use alone — opioid overdose can be fatal within minutes','Keep naloxone (Narcan) available and teach others to administer it','Narcotics Anonymous for peer support'], whenToSeeDoctor:'Opioid use disorder requires medical management — seek help immediately. MAT (buprenorphine, methadone) saves lives and must be started by a doctor. Never attempt to detox from opioids without medical supervision.', urgency:'high' },

  { name:'Cannabis Use Disorder', aliases:['cannabis use disorder','marijuana addiction','weed addiction','cannabis dependency','pot addiction','daily weed use','can\'t stop smoking weed'], emoji:'🌿', type:'addiction', description:'A pattern of problematic cannabis use characterized by loss of control, continued use despite problems, tolerance, and withdrawal symptoms. More prevalent with high-potency modern cannabis products.', symptoms:['Using cannabis in larger amounts or over a longer period than intended','Persistent desire or unsuccessful attempts to cut down','Spending a great deal of time obtaining or using cannabis','Craving cannabis','Failing to fulfill major role obligations due to cannabis use','Continuing use despite social and relationship problems','Withdrawal: irritability, anxiety, insomnia, decreased appetite when stopping'], causes:['Daily or high-frequency use','High-potency cannabis products','Genetic predisposition','Using cannabis to manage anxiety, depression, or sleep problems (which it worsens long-term)'], homecare:['Taper use gradually rather than stopping abruptly','Remove cannabis products and paraphernalia from home','Identify and address emotional reasons for use','Marijuana Anonymous peer support'], whenToSeeDoctor:'A psychiatrist or addiction specialist can help. CBT is effective for cannabis use disorder. Treating co-occurring anxiety, depression, or ADHD is important as these frequently drive cannabis use.', urgency:'medium' },

  { name:'Stimulant Use Disorder', aliases:['stimulant use disorder','cocaine addiction','amphetamine addiction','meth addiction','methamphetamine addiction','stimulant dependency','cocaine use disorder'], emoji:'⚡', type:'addiction', description:'Loss of control over use of stimulant drugs (cocaine, methamphetamine, prescription stimulants) despite serious negative consequences. Associated with intense euphoria and powerful psychological dependence.', symptoms:['Using stimulants in larger amounts or for longer than intended','Persistent desire or unsuccessful efforts to cut back','Spending a great deal of time obtaining, using, or recovering from stimulants','Craving stimulants','Failure to fulfill major role obligations','Continued use despite serious health and interpersonal problems','Tolerance — needing much more to achieve the same effect','Withdrawal: fatigue, depression, increased sleep and appetite, irritability'], causes:['Dopamine surge — the most powerful reward signal in the brain','Genetic predisposition','Trauma and untreated mental health conditions','Social or occupational pressures'], homecare:['Narcotics Anonymous and Cocaine Anonymous for peer support','Remove all drug paraphernalia and break contact with drug supply network','Establish a structured daily routine during recovery','Exercise has shown benefit in recovery from stimulant disorders'], whenToSeeDoctor:'A psychiatrist or addiction medicine specialist is needed. No FDA-approved pharmacotherapy currently (research ongoing). CBT and contingency management have best evidence. Mental health co-treatment is essential.', urgency:'high' },

  { name:'Sedative Use Disorder', aliases:['sedative use disorder','benzodiazepine addiction','benzo addiction','sleeping pill addiction','valium addiction','xanax addiction','sedative dependency'], emoji:'💤', type:'addiction', description:'Loss of control over use of sedative, hypnotic, or anxiolytic drugs (benzodiazepines, sleeping pills, barbiturates) despite serious negative consequences. Physical dependence develops rapidly and withdrawal can be life-threatening.', symptoms:['Using sedatives in larger amounts or for longer than intended','Unsuccessful efforts to cut down or control use','Craving sedatives','Failure to fulfill role obligations','Continued use despite social, relationship, or health problems','Tolerance — needing larger doses for the same effect','Severe withdrawal symptoms: anxiety, tremors, insomnia, seizures'], causes:['Legitimate medical use that escalated','Anxiety and insomnia driving use','Genetic predisposition to addiction','Easy prescription access'], homecare:['NEVER stop benzodiazepines abruptly — this can cause fatal seizures','Medical supervision for a very slow taper is the only safe approach','Do not combine with alcohol or opioids — extremely dangerous combination'], whenToSeeDoctor:'Immediately — sedative dependence requires medical management. A doctor will supervise a very gradual taper. Rehabilitation and CBT support the process. Never detox from benzodiazepines or barbiturates at home.', urgency:'high' },

  { name:'Nicotine Use Disorder', aliases:['nicotine use disorder','smoking addiction','tobacco addiction','cigarette addiction','vaping addiction','nicotine dependency','can\'t quit smoking'], emoji:'🚬', type:'addiction', description:'Dependence on nicotine delivered through cigarettes, vaping, or other tobacco products. One of the most common and harmful addictions worldwide. Nicotine dependence involves both physical withdrawal and strong psychological habit.', symptoms:['Smoking or vaping more than intended','Persistent unsuccessful attempts to quit','Spending significant time related to tobacco use','Craving nicotine — especially in situations associated with smoking (coffee, after meals)','Continuing despite known health harm','Withdrawal: irritability, anxiety, difficulty concentrating, increased appetite, restlessness'], causes:['Nicotine\'s powerful effect on dopamine reward system','Habit formation around situations and emotions','Genetic predisposition to nicotine metabolism and addiction','Marketing and social normalization'], homecare:['Set a firm quit date and tell others about it','Nicotine Replacement Therapy (NRT) — patches, gum, lozenges — double quit rates','Replace the habit: chew gum, drink water, use a straw','Identify and prepare for high-risk situations for smoking'], whenToSeeDoctor:'A doctor can prescribe varenicline (Champix/Chantix) or bupropion which significantly improve quit rates. Combination of NRT, medication, and behavioral support gives the best results.', urgency:'medium' },

  /* ── IMPULSE ── */
  { name:'Intermittent Explosive Disorder', aliases:['intermittent explosive disorder','ied','explosive anger','rage attacks','anger outbursts','violent temper','road rage disorder','anger disorder'], emoji:'💢', type:'mood', description:'A disorder involving recurrent, sudden episodes of impulsive, aggressive, or violent behavior or angry verbal outbursts grossly out of proportion to the triggering situation. The person feels a sense of tension before and relief after the outburst.', symptoms:['Recurrent outbursts of aggression — verbal or physical','Outbursts are grossly disproportionate to the provocation','Outbursts are impulsive, not planned','Feeling tense or aroused before the outburst','Feeling relief during the outburst, followed by guilt or remorse','Significant distress or functional impairment from the outbursts'], causes:['Serotonin dysregulation','History of childhood abuse or exposure to violence','Genetic predisposition','Underlying mood disorder or ADHD'], homecare:['Remove yourself from the triggering situation before escalating','Identify early physical warning signs of anger (clenched jaw, raised voice) and act early','Regular aerobic exercise reduces baseline arousal','Anger management journaling'], whenToSeeDoctor:'CBT focused on anger management, impulse control, and triggers is the treatment of choice. Medication (SSRIs, mood stabilizers) may also help. A psychiatrist or psychologist experienced in anger disorders should be consulted.', urgency:'medium' },

  { name:'Kleptomania', aliases:['kleptomania','compulsive stealing','can\'t stop stealing','stealing for tension relief','impulse stealing','shoplifting compulsion'], emoji:'🤲', type:'addiction', description:'An impulse control disorder characterized by recurrent failure to resist impulses to steal items that are not needed for personal use or monetary value. The act provides relief of tension, not material gain.', symptoms:['Recurrent failure to resist impulses to steal objects not needed for personal use','Increasing sense of tension before committing the theft','Pleasure, gratification, or relief at the time of theft','The theft is not committed out of anger, revenge, or delusion','Significant guilt or shame after stealing','Items stolen are often discarded, given away, or returned'], causes:['Serotonin, dopamine, and opioid system dysregulation','Co-occurring mood or anxiety disorders','History of trauma','Genetic predisposition'], homecare:['Remove yourself from situations that trigger the urge to steal','Find alternative tension-relief activities','Do not keep stolen items — creating distance from the reward cycle helps'], whenToSeeDoctor:'A psychiatrist or psychologist experienced in impulse control disorders can help. CBT and SSRIs are effective treatments. Legal consequences may require involvement of forensic mental health services.', urgency:'medium' },

  { name:'Pyromania', aliases:['pyromania','fire setting','fascination with fire','compulsive fire lighting','fire starting disorder'], emoji:'🔥', type:'addiction', description:'An impulse control disorder involving recurrent, deliberate fire setting accompanied by tension before the act and pleasure, relief, or gratification when setting fires or witnessing their aftermath. Not motivated by financial gain, anger, or concealing crime.', symptoms:['Recurrent deliberate and purposeful fire setting on more than one occasion','Tension or affective arousal before setting the fire','Fascination with, interest in, or attraction to fire','Pleasure, gratification, or relief when setting fires or observing their aftermath','Not set for monetary gain, to conceal criminal activity, or out of anger'], causes:['Impulse control disorder — impulse system dysregulation','Co-occurring personality disorder or intellectual disability','History of childhood trauma or neglect'], homecare:['Pyromania is a serious public safety concern — home management alone is not appropriate','Keep all fire-starting materials out of reach','Immediately involve a mental health professional'], whenToSeeDoctor:'Pyromania requires professional treatment — the fire-setting behavior poses significant risk to self and others. CBT and functional behavior analysis are used. Medication may help co-occurring disorders. Legal involvement is common.', urgency:'high' },

  /* ── EMOTIONAL PATTERNS / STATES ── */
  { name:'Pathological Lying', aliases:['pathological lying','compulsive lying','pseudologia fantastica','can\'t stop lying','habitual lying','chronic lying disorder'], emoji:'🤥', type:'mood', description:'A pattern of chronic, compulsive lying that occurs without clear external motivation. The lies are often elaborate, internally consistent, and may serve to enhance self-image or create an exciting narrative. Associated with several personality disorders.', symptoms:['Lying is habitual and occurs without clear benefit','Lies are elaborate, detailed, and internally consistent','The person may believe their own lies temporarily','Lying occurs even in low-stakes situations','Significant impact on relationships and trust','May be associated with borderline, antisocial, or narcissistic personality features'], causes:['Personality disorder features','Low self-esteem — lying serves to create an idealized self','Childhood environment where lying was adaptive or necessary','Impulse control problems'], homecare:['Therapy is the primary approach — self-help has limited effect alone','Journaling about the emotional need behind the lie can build self-awareness'], whenToSeeDoctor:'A psychologist or psychiatrist can help identify and treat the underlying cause. CBT and psychodynamic approaches are used. If associated with a personality disorder, treating the personality disorder is the priority.', urgency:'low' },

  { name:'Emotional Dysregulation', aliases:['emotional dysregulation','can\'t control emotions','emotional instability','intense emotions','mood swings','emotion regulation difficulty','emotional reactivity'], emoji:'🌊', type:'mood', description:'A pattern in which a person has difficulty regulating emotional responses — experiencing emotions that are more intense, longer lasting, and harder to manage than expected given the situation. Common across many mental health conditions.', symptoms:['Emotional responses are more intense than the situation warrants','Emotions feel overwhelming or out of control','Quick shifts between emotional states','Difficulty calming down once upset','Impulsive behavior driven by intense emotions','Difficulty problem-solving when emotionally activated','Emotional outbursts followed by guilt or shame'], causes:['Underlying condition (ADHD, PTSD, BPD, ASD, bipolar disorder)','Childhood environment lacking emotional validation','Neurological differences in amygdala and prefrontal cortex communication'], homecare:['DBT (Dialectical Behavior Therapy) skills are specifically designed for emotion regulation','Practice the STOP skill: Stop, Take a breath, Observe, Proceed mindfully','Use physical exercise to discharge intense emotions','Identify the specific emotion and what need it reflects'], whenToSeeDoctor:'Emotional dysregulation should be evaluated to identify any underlying condition. DBT therapy is the most evidence-based approach. A psychiatrist may assess for medication to reduce emotional reactivity.', urgency:'medium' },

  { name:'Alexithymia', aliases:['alexithymia','can\'t describe feelings','don\'t know what i feel','emotionally illiterate','not knowing emotions','can\'t identify emotions'], emoji:'🤔', type:'mood', description:'A subclinical phenomenon involving difficulty identifying, describing, and distinguishing feelings from bodily sensations. Not a formal diagnosis but a trait associated with many mental health conditions and affecting emotional wellbeing and relationships.', symptoms:['Difficulty identifying and distinguishing between emotions','Difficulty describing feelings to others','Limited ability to fantasize or think imaginatively about feelings','Preference for focusing on external events rather than inner experience','Emotional experiences perceived as physical sensations rather than feelings'], causes:['Neurological differences in interoception (sensing internal body state)','Associated with autism spectrum disorder, PTSD, eating disorders, substance use','Childhood environment that discouraged emotional expression'], homecare:['Use an emotions vocabulary wheel to build emotional awareness','Practice naming your body sensations and what emotion they might represent','Journaling about physical sensations and possible emotional connections','Mindfulness body scan practices'], whenToSeeDoctor:'A psychologist can help build emotional awareness through specialized psychotherapy. Somatic therapy and emotion-focused therapy are particularly helpful. Addressing any underlying condition is also important.', urgency:'low' },

  { name:'Anhedonia', aliases:['anhedonia','can\'t feel pleasure','loss of enjoyment','nothing brings happiness','emotionally flat','numbness to pleasure','joy is gone'], emoji:'😶', type:'mood', description:'A reduced ability or inability to feel pleasure from activities that were previously enjoyable. A core symptom of depression, schizophrenia, and other mental health conditions, but can also occur independently.', symptoms:['Loss of interest in previously enjoyed activities','Inability to feel pleasure from things that normally provide it','Social withdrawal — seeing others feels meaningless','Decreased motivation and drive','Feeling emotionally flat or numb','Difficulty experiencing positive emotions','May report enjoying activities less even when continuing them'], causes:['Dopamine system dysfunction','Core symptom of major depression, bipolar depression, schizophrenia','Burnout','Chronic stress','Substance use'], homecare:['Behavioral activation — schedule activities even without motivation and do them anyway','Exercise is the most powerful evidence-based way to restore dopamine function','Maintain social connection even when it feels meaningless','Sun exposure and regular sleep schedule support dopamine rhythm'], whenToSeeDoctor:'Anhedonia lasting weeks should be evaluated for depression or other conditions. A psychiatrist can assess and prescribe if needed. Therapy and medication together have better outcomes than either alone.', urgency:'medium' },

  { name:'Apathy Syndrome', aliases:['apathy syndrome','apathy','no motivation','can\'t be bothered','no interest in anything','emotional blunting','total lack of drive'], emoji:'😑', type:'mood', description:'Profound lack of motivation, emotion, and interest in activities not explained by reduced consciousness or emotional distress. Distinct from depression — the person does not feel sad, just flat and unmotivated. Common in neurological and psychiatric conditions.', symptoms:['Profound lack of motivation for goal-directed behavior','Reduced initiation of activities','Diminished emotional responsiveness','Lack of concern about personal issues or responsibilities','Reduced social interaction','Flat affect — limited emotional expression','Not distressed about the lack of motivation'], causes:['Brain conditions — Parkinson\'s disease, dementia, stroke, TBI','Psychiatric conditions — schizophrenia, depression (a subtype)','Medication side effects (antipsychotics, antidepressants in some people)','Burnout'], homecare:['External structure and prompting from others helps initiate activities','Small, achievable daily goals','Physical activity — even minimal movement can increase engagement','Reduce medication doses only under doctor supervision if they may be causing apathy'], whenToSeeDoctor:'A neurologist and psychiatrist should evaluate apathy — it may signal an underlying neurological condition. Medication (dopamine agonists, stimulants in some cases) may help apathy in specific conditions.', urgency:'medium' },

  { name:'Emotional Numbness', aliases:['emotional numbness','feeling nothing','can\'t feel emotions','emotionally numb','blunted emotions','disconnected from feelings','emotional blunting'], emoji:'🧊', type:'mood', description:'A state in which a person feels cut off from their emotions — unable to feel either positive or negative feelings. Often a protective response to overwhelming trauma, stress, or a side effect of medication.', symptoms:['Feeling detached from one\'s own emotions','Unable to feel happiness, sadness, or other emotions','Sense of emotional emptiness or inner blankness','Reduced ability to care about things that were previously important','Difficulty connecting emotionally with others','Feeling like going through the motions without genuine engagement'], causes:['Trauma response — emotional shutdown to protect from overwhelming feelings','Chronic stress or burnout','Side effect of certain medications (SSRIs, antipsychotics)','Depression','Dissociation'], homecare:['Gentle physical activity helps reconnect with the body','Creative outlets — art, music, writing — can bypass verbal emotional barriers','Somatic practices — yoga, body scan, breathwork — can thaw emotional numbness','If medication-related, discuss with prescribing doctor'], whenToSeeDoctor:'A mental health professional can determine whether emotional numbness is trauma-related, depression-related, or medication-induced and treat accordingly. Somatic therapies and EMDR are particularly helpful for trauma-related numbing.', urgency:'medium' },

  { name:'Derealization', aliases:['derealization','world feels unreal','dreamlike state','things look fake','unreality feeling','detached from surroundings','foggy perception','nothing feels real'], emoji:'🌫️', type:'anxiety', description:'A dissociative experience in which the external world feels unreal, foggy, dreamlike, far away, or artificially constructed. The person knows the world is real but cannot shake the perception. Often occurs alongside depersonalization.', symptoms:['Surroundings feel unreal, dreamlike, or artificial','Objects may appear blurry, flat, colorless, or without depth','Sense of being separated from the world by glass or a veil','Sounds may feel muffled or distant','Time feels distorted — slowed or sped up','Reality testing is intact — the person knows they are real'], causes:['Anxiety and panic attacks (very common trigger)','Dissociative disorders','Cannabis use or psychedelic drug use','Severe stress or sleep deprivation','Sensory deprivation'], homecare:['Grounding exercises — focus intensely on physical sensations','Reduce anxiety — it is the most common driver','Vigorous exercise and cold exposure help reconnect to reality','Reduce cannabis and alcohol'], whenToSeeDoctor:'A mental health professional should assess for anxiety, dissociative disorder, or substance-related causes. CBT for depersonalization-derealization is effective. Treating underlying anxiety is key.', urgency:'medium' },

  { name:'Learned Helplessness', aliases:['learned helplessness','feeling powerless','nothing i do matters','giving up','hopelessness','passive resignation','believing you cannot change things'], emoji:'🧱', type:'mood', description:'A psychological state in which a person who has repeatedly experienced uncontrollable negative events begins to believe they have no control over their situation, stops trying to improve it, and becomes passive even when change is possible. Associated with depression.', symptoms:['Belief that one cannot influence outcomes regardless of actions','Passive resignation in the face of problems','Failure to seek solutions even when available','Generalized helplessness across new situations','Low motivation and initiative','Associated with depression and hopelessness'], causes:['Repeated exposure to uncontrollable aversive events (abuse, chronic illness, oppression)','Chronic stress and failures in key life areas','Depression maintains and deepens learned helplessness'], homecare:['Start with very small actions where control is demonstrable','Keep a record of things you DID change, however small','Challenge the belief "nothing I do matters" with specific counterexamples'], whenToSeeDoctor:'CBT specifically targeting hopeless and helplessness beliefs is highly effective. A therapist can help rebuild a sense of agency step by step. Treating underlying depression is essential.', urgency:'medium' },

  { name:'Caregiver Burnout', aliases:['caregiver burnout','carer burnout','compassion fatigue caregiver','exhausted from caring','family caregiver stress','burnt out caregiver'], emoji:'🏥', type:'mood', description:'A state of physical, emotional, and mental exhaustion that can occur when someone spends significant time caring for a family member or loved one with illness, disability, or mental health needs. Associated with grief, resentment, and loss of identity.', symptoms:['Overwhelming exhaustion — physical and emotional','Feeling increasingly resentful of the person being cared for','Neglecting one\'s own health and needs','Feeling hopeless or helpless about the caregiving situation','Withdrawing from social activities and relationships','Changes in sleep and appetite','Losing enjoyment in activities outside caregiving','Increased use of alcohol or sleep aids'], causes:['Taking on more caregiving responsibilities than one person can manage','Lack of respite or support from others','Unclear boundaries between caregiving role and personal identity','Financial strain from caregiving costs'], homecare:['Accept help — you cannot care well for others if you are depleted','Schedule regular time off from caregiving — this is not selfish, it is necessary','Join a caregiver support group','Name and express your emotions — resentment is normal and does not make you a bad person'], whenToSeeDoctor:'A therapist experienced in caregiver issues can provide essential support. Family therapy may help distribute caregiving burden. Your doctor should monitor your own physical health during this time.', urgency:'medium' },

  { name:'Moral Injury', aliases:['moral injury','guilt from actions','betrayal of values','moral distress','conscience trauma','soldier guilt','healthcare worker moral injury'], emoji:'⚖️', type:'mood', description:'The deep moral distress and psychological injury that results from participating in, witnessing, failing to prevent, or learning about events that violate one\'s deeply held moral beliefs. Common in military personnel, healthcare workers, and first responders.', symptoms:['Profound guilt or shame about specific actions or inactions','Feeling of having betrayed one\'s own moral code','Anger at others who ordered or permitted the morally injurious act','Spiritual crisis or loss of meaning','Difficulty forgiving oneself or others','Social withdrawal and moral alienation','Symptoms overlap with PTSD but centered on moral violation rather than fear'], causes:['Participating in actions that violate personal moral code (combat, medical triage decisions)','Witnessing others commit atrocities without being able to intervene','Betrayal by leaders or institutions trusted to be ethical'], homecare:['Talk to others who understand the specific context (peers, veterans, colleagues)','Distinguish between moral responsibility and actual culpability','Engage with spiritual or philosophical resources that address forgiveness and moral complexity'], whenToSeeDoctor:'A therapist with specific training in moral injury is needed. Adaptive Disclosure Therapy (developed specifically for moral injury) and meaning-making therapy are the most targeted approaches.', urgency:'medium' },

  { name:'Complicated Grief', aliases:['complicated grief','prolonged grief','grief disorder','can\'t get over death','stuck in grief','chronic bereavement','grief that won\'t heal'], emoji:'🖤', type:'mood', description:'A persistent, intense grief response that does not follow the expected trajectory of bereavement and significantly impairs functioning for months or years after the loss. Also called prolonged grief disorder in current diagnostic systems.', symptoms:['Intense longing and yearning for the deceased','Frequent thoughts or preoccupations with the deceased','Difficulty accepting the death','Bitterness or anger about the loss','Feeling that life is meaningless without the deceased','Difficulty engaging in activities or planning for the future','Emotional numbness','Feeling that a part of oneself has died'], causes:['Sudden, traumatic, or violent death','Loss of a child','Ambivalent or dependent relationship with the deceased','Multiple concurrent losses','Lack of social support'], homecare:['Allow yourself to grieve at your own pace while maintaining basic self-care','Keep connecting with supportive people — isolation deepens complicated grief','Preserve memories while building a life that includes them'], whenToSeeDoctor:'Complicated grief responds to specific therapy (Complicated Grief Treatment / CGT) developed specifically for this condition. Standard depression or PTSD treatments alone are less effective. See a grief specialist.', urgency:'medium' },

  { name:'Prolonged Grief Disorder', aliases:['prolonged grief disorder','pgd','grief that lasts years','unresolved grief','persistent bereavement','grief not moving on','pathological grief'], emoji:'🕯️', type:'mood', description:'Formally recognized in DSM-5-TR as a diagnosis, Prolonged Grief Disorder involves intense grief lasting more than 12 months (6 months in children) after bereavement, with specific symptoms causing significant impairment. Distinct from complicated grief by formal diagnostic criteria.', symptoms:['Intense longing for the deceased person nearly every day for 12+ months','Preoccupation with the deceased or circumstances of the death','At least 3 of: difficulty accepting the death, disbelief, avoiding reminders, intense emotional pain, difficulty engaging with life, emotional numbness, feeling life is meaningless, feeling lonely and detached','Clinically significant distress or functional impairment','Not explained by another mental health disorder'], causes:['Nature of the relationship — loss of spouse, child, or highly significant person','Traumatic nature of the death','Pre-existing depression or anxiety','Lack of social support after loss'], homecare:['Allow the loss to be central in your life without letting it define everything','Continue meaningful activities in honor of the person lost','Daily rituals of remembrance can structure grief'], whenToSeeDoctor:'Complicated Grief Treatment (CGT), developed specifically for this diagnosis, is highly effective. It differs meaningfully from standard grief counseling. A therapist trained in CGT should be sought specifically.', urgency:'medium' },

  { name:'Eco-Anxiety', aliases:['eco-anxiety','climate anxiety','environmental anxiety','fear of climate change','climate grief','climate distress','eco grief'], emoji:'🌍', type:'anxiety', description:'Chronic fear of environmental doom — a persistent anxiety arising from awareness of and concern about climate change, ecological destruction, and an uncertain environmental future. A rational response to real threats that becomes disordered when it significantly impairs functioning.', symptoms:['Persistent worry and anxiety about climate change and ecological collapse','Intrusive thoughts about environmental catastrophe','Feeling overwhelmed by climate news','Guilt about personal environmental impact','Difficulty enjoying the present due to future worry','Anger and despair about inaction by governments or corporations','Difficulty making future plans (career, relationships, having children)'], causes:['Exposure to climate science and distressing environmental news','Witnessing environmental changes (fires, floods, extreme weather)','Sense of helplessness about a global-scale problem','Young people and activists particularly affected'], homecare:['Balance informed engagement with intentional news limits','Channel anxiety into climate action — reduces helplessness','Connect with a community working on climate solutions','Ground in present-moment enjoyment of nature'], whenToSeeDoctor:'A therapist familiar with eco-anxiety (also called climate-aware therapist) is ideal. CBT and ACT (Acceptance and Commitment Therapy) frameworks are used. Treatment focuses on building resilience alongside meaningful action.', urgency:'low' },

  { name:'Technostress', aliases:['technostress','technology stress','digital overwhelm','screen fatigue','tech overload','digital stress','information overload'], emoji:'📱', type:'mood', description:'Psychological stress related to the use of technology — from feeling overwhelmed by digital demands, constant connectivity, rapid technological change, or inability to cope with new technologies. A modern occupational and personal health concern.', symptoms:['Feeling overwhelmed by the number of digital communications and tasks','Anxiety about not responding to messages quickly enough','Fatigue from constant screen exposure','Irritability related to technology use','Difficulty mentally disconnecting from work due to constant connectivity','Feeling incompetent when unable to keep up with new technology','Sleep disturbance related to evening screen use'], causes:['Always-on workplace culture and remote work demands','Notification overload from multiple platforms','Rapid technological change requiring constant adaptation','Blurring of work and personal digital spaces'], homecare:['Turn off all non-essential notifications','Set specific times to check email and messages — not continuously','Create device-free times: mornings, meals, 1 hour before bed','Take regular screen breaks — 5 minutes every hour'], whenToSeeDoctor:'If technostress is causing significant anxiety, burnout, or sleep disruption, a psychologist can help develop healthier digital boundaries. CBT and mindfulness-based approaches are used.', urgency:'low' },

  { name:'Burnout Syndrome', aliases:['burnout syndrome','burnout','job burnout','work burnout','professional burnout','complete exhaustion','emotional exhaustion work'], emoji:'🔥', type:'mood', description:'A state of chronic stress leading to physical and emotional exhaustion, cynicism and detachment, and feelings of ineffectiveness and lack of accomplishment. Officially recognized by WHO as an occupational phenomenon.', symptoms:['Exhaustion — feeling completely drained even after rest','Cynicism and detachment — feeling removed from and uncaring about work','Inefficacy — feeling that nothing you do makes a difference','Physical symptoms — headaches, gastrointestinal issues, frequent illness','Decreased performance and productivity','Difficulty finding meaning in work','Emotional numbness and feeling empty'], causes:['Chronic overwork and lack of work-life balance','Feeling undervalued or unrecognized','Lack of control over one\'s work','Mismatch between personal values and organizational demands','Lack of recovery time between stressors'], homecare:['Take actual rest — not productive rest, but genuine rest','Set firm limits on working hours and defend them','Reconnect with activities outside of work that provide meaning and joy','Talk honestly with a trusted person about how you are feeling'], whenToSeeDoctor:'A psychologist or psychiatrist can distinguish burnout from depression and provide targeted treatment. Work-related psychotherapy, stress management, and sometimes career counseling are the approaches used.', urgency:'medium' },

  { name:'Imposter Syndrome', aliases:['imposter syndrome','impostor syndrome','feeling like a fraud','don\'t deserve success','fear of being found out','fake at work','doubting own achievements'], emoji:'🎭', type:'mood', description:'A psychological pattern in which a person doubts their accomplishments and has a persistent, internalized fear of being exposed as a fraud, despite clear external evidence of their competence. Very common in high-achieving individuals.', symptoms:['Persistent belief that one does not deserve success or current position','Fear of being found out as incompetent or fraudulent','Attributing success to luck, timing, or deceiving others','Inability to internalize accomplishments','Perfectionism as self-protection against exposure','Significant anxiety around evaluation or performance','More common in women, minorities, and first-generation professionals'], causes:['Socialization that downplays competence (especially for women and minorities)','Perfectionist and anxious temperament','Entering a new role or environment','Cultural messages about who "belongs" in certain fields'], homecare:['Write down your achievements and contributions regularly to externalize evidence','Talk to peers — imposter syndrome is extremely common and shared experience normalizes it','Notice when you are attributing success to luck and challenge that attribution'], whenToSeeDoctor:'CBT targeting the core beliefs of imposter syndrome is effective. A therapist can help build an accurate, balanced self-assessment. Often addressed well in coaching alongside therapy.', urgency:'low' },

  { name:'Decision Fatigue', aliases:['decision fatigue','too many decisions','can\'t make decisions anymore','mental exhaustion from choices','choice overload','decision paralysis'], emoji:'🧠', type:'mood', description:'A state of mental depletion resulting from the burden of making too many decisions, causing a decline in decision quality, avoidance of decisions, or impulsive choices as the mental energy available for deliberate thinking is depleted.', symptoms:['Feeling mentally drained after making many decisions','Making increasingly poor or reckless decisions later in the day','Avoiding making decisions by procrastinating or deferring to others','Impulsive decisions that would not have been made when fresh','Difficulty concentrating on important choices','Irritability and short temper related to having to decide things'], causes:['High-decision-volume roles (executives, healthcare workers, parents)','Information overload in modern life','Lack of adequate rest and recovery','Perfectionism — every decision feels high stakes'], homecare:['Make important decisions earlier in the day when mental energy is highest','Reduce trivial decisions — simplify routines (meal planning, standard outfits)','Take breaks between decision-intensive tasks','Accept "good enough" rather than seeking the perfect choice'], whenToSeeDoctor:'If decision fatigue is part of burnout, ADHD, or executive dysfunction, professional assessment is helpful. A psychologist or coach can help with decision-making frameworks and underlying conditions.', urgency:'low' },

  { name:'Emotional Exhaustion', aliases:['emotional exhaustion','emotionally drained','nothing left to give','emotional depletion','compassion drain','running on empty emotionally'], emoji:'😮‍💨', type:'mood', description:'A state of feeling emotionally depleted, overwhelmed, and unable to meet continuing emotional demands. Often a precursor to or component of burnout, depression, and compassion fatigue. The person feels they have nothing left to give emotionally.', symptoms:['Feeling emotionally drained and overwhelmed','Difficulty showing care or empathy','Irritability and short temper','Physical fatigue accompanying emotional depletion','Difficulty engaging emotionally with others','Feeling detached or going through the motions','Dreading interactions that involve emotional demand'], causes:['Sustained high-emotional-demand roles or situations','Lack of recovery time','Unresolved grief, conflict, or stress','Caretaking of others without adequate self-care'], homecare:['Permission to do less — emotional rest is a legitimate need','Set boundaries on emotional demands in your environment','Engage in low-stimulation, restorative activities — nature, quiet, creative activities','Avoid people or situations that drain without replenishing'], whenToSeeDoctor:'A therapist can help identify and address the sources of emotional exhaustion and develop sustainable coping strategies. Burnout assessment is important. If depressive symptoms accompany emotional exhaustion, a psychiatrist should be consulted.', urgency:'medium' },

  { name:'Compassion Fatigue', aliases:['compassion fatigue','secondary trauma','vicarious trauma','helper fatigue','caregiver trauma','empathy burnout','caring too much fatigue'], emoji:'💔', type:'mood', description:'A combination of physical, emotional, and spiritual depletion resulting from caring for people in pain. Distinct from burnout in that it involves exposure to others\' trauma and suffering, not just work overload. Common in healthcare workers, therapists, first responders, and caregivers.', symptoms:['Reduced empathy and compassion despite wanting to care','Emotional numbness to others\' suffering','Intrusive thoughts or images of others\' traumatic stories','Physical symptoms — fatigue, headaches, sleep disturbance','Hopelessness about the ability to help','Dreading work or contact with those needing care','Cynicism about the worth of helping professions'], causes:['Prolonged exposure to the trauma and suffering of others','Insufficient supervision, debriefing, or support in helping roles','Personal history of trauma that is activated by clients\' stories','Overidentification with those being helped'], homecare:['Regular supervision and debriefing in your professional role','Conscious decompression rituals between work and personal life','Limit caseload — advocacy for sustainable work conditions','Deliberately engage with things that are joyful and restorative'], whenToSeeDoctor:'A therapist experienced in compassion fatigue and vicarious trauma is ideal. Specific interventions (Trauma Stewardship model, self-care planning) are used. A psychiatrist should assess for PTSD if trauma exposure has been severe.', urgency:'medium' },

  { name:'Secondary Traumatic Stress', aliases:['secondary traumatic stress','secondary trauma','vicarious traumatization','secondary ptsd','trauma from hearing trauma','indirect trauma'], emoji:'🔄', type:'anxiety', description:'PTSD-like symptoms resulting from indirect exposure to trauma — hearing about or working closely with survivors of traumatic events. Distinct from compassion fatigue in that the symptom profile closely mirrors PTSD rather than burnout.', symptoms:['Intrusive symptoms — flashbacks or images from others\' trauma stories','Nightmares related to others\' traumatic events','Hypervigilance and exaggerated startle response','Avoidance of reminders of clients\' trauma','Emotional numbing','Decreased sense of personal safety in the world','Feeling changed by exposure to others\' trauma'], causes:['Working directly with trauma survivors (therapists, social workers, nurses, journalists)','High caseload of trauma cases without adequate support','Personal history of trauma that is activated by others\' stories'], homecare:['Debriefing with trusted colleagues or supervisors','Conscious separation between work trauma material and personal life','Limit exposure to graphic or traumatic material outside of work'], whenToSeeDoctor:'A trauma-informed therapist should provide EMDR or trauma-focused CBT for secondary traumatic stress. Supervision structures within workplaces are essential prevention.', urgency:'medium' },

  /* ── SLEEP ── */
  { name:'Night Terrors', aliases:['night terrors','sleep terrors','parasomnia','screaming in sleep','child waking up screaming','non-rem sleep disorder','night terror disorder'], emoji:'😱', type:'mental_health', description:'A sleep disorder involving episodes of intense fear, screaming, and agitation during non-REM sleep, typically within the first few hours of falling asleep. Unlike nightmares, the person is not truly awake during the episode and usually has no memory of it.', symptoms:['Sudden arousal from sleep — sitting up and screaming','Eyes open but not awake or aware','Intense fear, sweating, and rapid heartbeat during episode','Inconsolable during the episode','Returns to normal sleep after the episode','No or minimal memory of the episode in the morning','Episodes occur in the first third of the night'], causes:['Sleep deprivation — the most common trigger','Fever in children','Stress and anxiety','Irregular sleep schedules','Genetic predisposition — runs in families','Sleep-disordered breathing (sleep apnea) can worsen'], homecare:['Ensure consistent, adequate sleep — address sleep deprivation first','Establish a calming bedtime routine','Do not try to wake the person during an episode — stay calm and ensure safety','Reduce stress and workload before bed'], whenToSeeDoctor:'If night terrors are frequent, causing injury, persisting into adulthood, or significantly disrupting household sleep, see a sleep specialist or psychiatrist. Sleep study may be needed to rule out sleep apnea. Medication is rarely needed.', urgency:'low' },

  { name:'Sleepwalking', aliases:['sleepwalking','somnambulism','walking in sleep','getting up while asleep','sleepwalking disorder','non-rem parasomnia'], emoji:'🚶', type:'mental_health', description:'A sleep disorder involving episodes of walking or performing complex behaviors during sleep, typically during non-REM deep sleep in the first half of the night. The person appears awake but is not conscious and usually has no memory of the episode.', symptoms:['Getting up and walking around while asleep','Eyes open but glassy and unseeing','Performing complex behaviors — going to the bathroom, eating, leaving the house','Unresponsive or difficult to rouse during an episode','No memory of the episode in the morning','May mumble incoherently during the episode','Risk of injury during sleepwalking'], causes:['Sleep deprivation — strongest trigger','Fever','Stress and anxiety','Certain medications (sedatives, antipsychotics)','Sleep-disordered breathing','Genetic predisposition'], homecare:['Ensure adequate total sleep — most sleepwalking resolves with more sleep','Secure the sleeping environment — lock doors and windows, remove hazards','Do not abruptly wake the sleepwalker — gently guide back to bed','Consistent sleep schedule and sleep hygiene'], whenToSeeDoctor:'If sleepwalking is frequent, causing injury, dangerous behaviors (leaving the house), or persisting into adulthood. A sleep specialist can perform a sleep study. Medication (low-dose clonazepam or melatonin) may be prescribed in some cases.', urgency:'medium' },

  { name:'REM Sleep Disorder', aliases:['rem sleep disorder','rbd','rem sleep behavior disorder','acting out dreams','kicking in sleep','violent sleep movements','punching while sleeping'], emoji:'💤', type:'mental_health', description:'A sleep disorder in which the normal muscle paralysis of REM sleep is absent, causing a person to physically act out their dreams — which can be vivid and violent. Punching, kicking, shouting, and even getting out of bed can occur. Associated with neurodegenerative conditions.', symptoms:['Physically acting out dreams during REM sleep — punching, kicking, thrashing','Shouting or talking during sleep','Vivid, often violent dream content','Potential for injury to self or bed partner during episodes','Episodes occur in the second half of the night (when REM sleep is predominant)','Person may remember the dream when woken during or after an episode'], causes:['Idiopathic (unknown cause) in younger people','Strongly associated with synucleinopathies (Parkinson\'s disease, Lewy body dementia, multiple system atrophy) — may precede them by years','Certain medications (antidepressants — SSRIs, SNRIs)','Narcolepsy'], homecare:['Make the sleep environment safe — pad bed frame, remove sharp objects, place mattress on floor if needed','Bed partner may need to sleep separately temporarily for safety','Avoid alcohol and sleep deprivation which worsen RBD'], whenToSeeDoctor:'Immediately — RBD requires evaluation by a sleep specialist or neurologist. A sleep study (polysomnography) is needed to confirm. It is a significant risk marker for neurodegenerative disease. Medication (melatonin, clonazepam) is effective and important.', urgency:'high' },

  /* ── LIFESTYLE ── */
  /* ── LIFESTYLE: METABOLIC ── */
  { name:'Metabolic Syndrome', aliases:['metabolic syndrome','syndrome x','insulin resistance syndrome','cardiometabolic syndrome'], emoji:'⚖️', type:'lifestyle', description:'A cluster of conditions occurring together — high blood pressure, high blood sugar, excess abdominal fat, and abnormal cholesterol — that together significantly increase the risk of heart disease, stroke, and type 2 diabetes. Affects around 1 in 3 adults globally.', symptoms:['Large waist circumference (above 90cm in men, 80cm in women for South Asians)','High fasting blood sugar','High triglyceride levels','Low HDL (good) cholesterol','High blood pressure','Fatigue and low energy','Dark velvety skin patches (acanthosis nigricans)'], causes:['Obesity especially central abdominal fat','Insulin resistance','Physical inactivity','Unhealthy diet high in refined carbs and sugar','Genetic predisposition','Chronic stress and poor sleep'], homecare:['Lose 5-10% of body weight — dramatically improves all components','150-300 minutes of moderate aerobic exercise per week','Low-sugar, low-refined-carbohydrate diet — Mediterranean or low-glycemic approach','Increase dietary fiber — vegetables, legumes, whole grains','Reduce alcohol','Manage stress and improve sleep quality'], whenToSeeDoctor:'All five components of metabolic syndrome should be assessed together. Annual blood tests (fasting glucose, lipid panel) and blood pressure monitoring. A physician or endocrinologist can guide risk reduction and medication if lifestyle changes are insufficient.', urgency:'medium' },

  { name:'Insulin Resistance', aliases:['insulin resistance','prediabetic insulin','impaired insulin sensitivity','hyperinsulinemia'], emoji:'🩸', type:'lifestyle', description:'A condition in which cells in the muscles, fat, and liver do not respond well to insulin and cannot easily take up glucose. The pancreas compensates by making more insulin. Over time this leads to prediabetes and type 2 diabetes.', symptoms:['Fatigue especially after meals','Difficulty losing weight','Dark skin patches around the neck and armpits (acanthosis nigricans)','Increased hunger and cravings for sweets','Difficulty concentrating (brain fog)','Abdominal weight gain','Elevated fasting insulin on blood tests'], causes:['Obesity and excess visceral fat','Sedentary lifestyle','High sugar and refined carbohydrate diet','Chronic sleep deprivation','Chronic stress and elevated cortisol','Genetic predisposition'], homecare:['Regular exercise — even a 30-minute daily walk significantly improves insulin sensitivity','Low-carbohydrate or Mediterranean-style diet','Avoid sugary drinks and processed foods','Improve sleep to 7-9 hours per night','Manage chronic stress','Lose excess abdominal fat — even modest weight loss reverses insulin resistance'], whenToSeeDoctor:'Fasting insulin and glucose tests can identify insulin resistance before diabetes develops. A doctor or endocrinologist can guide lifestyle changes and prescribe metformin if risk is high.', urgency:'medium' },

  { name:'Prediabetes', aliases:['prediabetes','borderline diabetes','impaired fasting glucose','impaired glucose tolerance','high blood sugar borderline'], emoji:'🩸', type:'lifestyle', description:'A serious health condition where blood sugar levels are higher than normal but not yet high enough to be type 2 diabetes. Without lifestyle changes, prediabetes is very likely to become type 2 diabetes within 5 years. However, it is fully reversible.', symptoms:['Often no symptoms','Increased thirst','Frequent urination','Fatigue','Blurred vision','Slow-healing cuts','Darkened skin in body creases (acanthosis nigricans)','Increased hunger'], causes:['Excess weight especially abdominal fat','Physical inactivity','Family history of diabetes','Age over 45','Gestational diabetes history','PCOS','High blood pressure and cholesterol'], homecare:['Lose 5-7% of body weight if overweight — most effective intervention proven to prevent progression to diabetes','150 minutes of moderate exercise per week (brisk walking is sufficient)','Low-glycemic diet — reduce white rice, white bread, sugar, sweetened drinks','Increase vegetables, whole grains, and legumes','Quit smoking'], whenToSeeDoctor:'Fasting glucose between 100-125 mg/dL or HbA1c between 5.7-6.4% indicates prediabetes. Annual follow-up with a doctor. A diabetes prevention program (lifestyle intervention) reduces progression by 58%.', urgency:'medium' },

  { name:'Non-Alcoholic Fatty Liver', aliases:['non alcoholic fatty liver','nafld','fatty liver lifestyle','liver fat lifestyle'], emoji:'🍋', type:'lifestyle', description:'Accumulation of excess fat in the liver in people who drink little or no alcohol. Closely linked to obesity, insulin resistance, and metabolic syndrome. Can progress from simple fatty liver to liver inflammation (NASH) and eventually cirrhosis.', symptoms:['Usually no symptoms in early stages','Fatigue','Mild discomfort in right upper abdomen','Slightly enlarged liver found on ultrasound','Raised liver enzymes on blood tests'], causes:['Obesity especially abdominal fat','Type 2 diabetes and insulin resistance','High triglycerides','Rapid weight loss or crash dieting','Metabolic syndrome'], homecare:['Weight loss of 7-10% of body weight significantly reduces liver fat','Low-sugar, low-processed-food diet — avoid fructose corn syrup and sweetened drinks','Regular aerobic and resistance exercise','Avoid alcohol completely even though not the primary cause','Control blood sugar and cholesterol'], whenToSeeDoctor:'Regular liver function blood tests and annual liver ultrasound. A hepatologist should evaluate if enzymes are significantly elevated or NASH (inflammation) is suspected. Fatty liver can be reversed with weight loss.', urgency:'medium' },

  { name:'Obesity Hypoventilation', aliases:['obesity hypoventilation syndrome','ohs','pickwickian syndrome','obesity breathing problem','hypoventilation obesity'], emoji:'💨', type:'lifestyle', description:'A breathing disorder affecting some obese individuals where the body fails to breathe rapidly or deeply enough, resulting in low oxygen and high carbon dioxide levels in the blood. Also known as Pickwickian syndrome.', symptoms:['Excessive daytime sleepiness','Shortness of breath with minimal activity','Loud snoring and sleep apnea','Morning headaches','Fatigue and low energy','Bluish tinge to lips and skin (cyanosis) in severe cases','Swollen ankles from fluid retention'], causes:['Severe obesity — BMI typically above 30 kg/m²','Impaired respiratory muscle function from excess weight on the chest','Sleep apnea reducing respiratory drive','Altered brain signaling for breathing'], homecare:['Weight loss is the primary treatment and can resolve the condition','Use prescribed CPAP or BiPAP breathing machine at night','Elevate the head of the bed','Avoid alcohol and sedatives which suppress breathing','Regular gentle physical activity as tolerated'], whenToSeeDoctor:'Any obese person with excessive daytime sleepiness, morning headaches, or breathing difficulty needs a pulmonologist evaluation and sleep study. Blood gas testing confirms the diagnosis. BiPAP is often required while weight is being addressed.', urgency:'high' },

  { name:'Central Obesity', aliases:['central obesity','abdominal obesity','belly fat','visceral fat','apple shape body','waist fat'], emoji:'⚖️', type:'lifestyle', description:'Excess fat accumulated around the abdomen and surrounding internal organs (visceral fat). Central obesity is more dangerous than general obesity because visceral fat is metabolically active and releases inflammatory hormones.', symptoms:['Large waist circumference (above 90cm for men, 80cm for women in South Asian populations)','Abdominal bloating','Fatigue','Difficulty fitting into clothes around the waist','Associated metabolic syndrome components'], causes:['Excess calorie intake over expenditure','Sedentary lifestyle','High cortisol from chronic stress (deposits fat centrally)','Poor sleep','Hormonal changes — menopause in women, low testosterone in men','Genetic predisposition'], homecare:['Caloric deficit diet — reduce ultra-processed foods, sugary drinks, and refined carbs','150-300 minutes of aerobic exercise weekly — helps specifically reduce visceral fat','Strength training 2-3 times per week','Manage stress — cortisol drives central fat deposition','Improve sleep quality — sleep deprivation increases abdominal fat'], whenToSeeDoctor:'Waist circumference and waist-to-hip ratio should be measured at annual health checks. A doctor can assess associated risks (metabolic syndrome, cardiovascular risk) and guide a comprehensive weight management plan.', urgency:'medium' },

  /* ── LIFESTYLE: MUSCLE, BONE & POSTURE ── */
  { name:'Sarcopenia', aliases:['sarcopenia','age related muscle loss','muscle wasting elderly','loss of muscle mass','muscle atrophy aging'], emoji:'💪', type:'lifestyle', description:'The progressive loss of skeletal muscle mass and strength associated with aging. Leads to reduced physical function, frailty, falls, and loss of independence. Accelerated by inactivity, poor protein intake, and chronic disease.', symptoms:['Gradual weakness in arms and legs','Reduced grip strength','Difficulty with everyday tasks — climbing stairs, carrying groceries','Slowed walking speed','Fatigue with light activities','Recurrent falls','Loss of muscle definition and size'], causes:['Natural aging process (begins after age 30 and accelerates after 60)','Physical inactivity — use it or lose it','Low protein intake','Hormonal changes (reduced testosterone, estrogen, and growth hormone)','Chronic disease and inflammation','Poor nutrition and malabsorption'], homecare:['Resistance and strength training 2-3 times per week — the most effective intervention','Increase dietary protein to 1.2-1.6g per kg body weight per day','Distribute protein intake across all meals rather than one large serving','Vitamin D supplementation (deficiency accelerates muscle loss)','Stay active throughout the day — avoid prolonged sitting','Balance and coordination exercises to reduce fall risk'], whenToSeeDoctor:'Grip strength testing and walking speed assessment can identify sarcopenia. A geriatrician or physiotherapist can create a tailored exercise and nutrition plan. Falls associated with weakness need urgent evaluation.', urgency:'medium' },

  { name:'Muscle Loss', aliases:['muscle loss','muscle wasting','muscle atrophy','muscle weakness','loss of muscle'], emoji:'💪', type:'lifestyle', description:'Reduction in muscle mass and strength from disuse, poor nutrition, illness, or aging. Even short periods of bed rest or inactivity cause rapid muscle loss. Reversible with proper exercise and nutrition.', symptoms:['Visible reduction in muscle size','Weakness and reduced strength','Fatigue with normal activities','Slower movement and reduced coordination','Difficulty with activities previously done easily'], causes:['Prolonged inactivity or bed rest','Inadequate protein intake','Aging','Chronic illness or hospitalization','Malnutrition','Hormonal imbalances'], homecare:['Resume physical activity as soon as medically possible after illness or bed rest','Progressive resistance exercise — start light and build gradually','Protein intake of at least 1.2g per kg body weight per day','Include leucine-rich foods — eggs, milk, meat, legumes — to stimulate muscle protein synthesis','Adequate total calorie intake to fuel muscle recovery'], whenToSeeDoctor:'Unexplained or rapid muscle loss warrants medical evaluation to rule out underlying disease. A physiotherapist and dietitian can design an effective recovery plan.', urgency:'medium' },

  { name:'Bone Density Loss', aliases:['bone density loss','low bone density','osteopenia','reduced bone mass','bone thinning'], emoji:'🦴', type:'lifestyle', description:'A reduction in bone mineral density below the normal range for age and sex, but not yet as severe as osteoporosis. A warning stage that increases fracture risk if not addressed. Fully modifiable with lifestyle intervention.', symptoms:['Usually no symptoms until a fracture occurs','Occasional back pain','Slight loss of height over years'], causes:['Inadequate calcium and vitamin D intake','Sedentary lifestyle','Smoking','Excessive alcohol','Prolonged corticosteroid use','Hormonal changes — menopause, low testosterone','Malabsorption conditions (celiac disease, Crohn\'s)'], homecare:['Calcium-rich diet — dairy, fortified plant milks, leafy greens, sesame, tofu','Vitamin D3 supplementation if deficient — essential for calcium absorption','Weight-bearing exercise daily — walking, jogging, dancing, resistance training','Quit smoking and limit alcohol','Avoid excessive caffeine'], whenToSeeDoctor:'DEXA scan (bone density test) is recommended for all women over 65, men over 70, and younger individuals with risk factors. A doctor can prescribe bone-protective medications if bone loss is significant.', urgency:'medium' },

  { name:'Vitamin B12 Deficiency', aliases:['b12 deficiency','vitamin b12 deficiency','cobalamin deficiency','low b12','megaloblastic anemia b12'], emoji:'💊', type:'lifestyle', description:'A deficiency of vitamin B12, essential for nerve function, DNA synthesis, and red blood cell production. Very common in vegetarians, vegans, and older adults. Can cause irreversible nerve damage if untreated.', symptoms:['Fatigue and weakness','Pale or jaundiced skin','Tingling or numbness in hands and feet','Difficulty walking and balance problems','Cognitive difficulties — memory and concentration problems','Mood changes — depression, irritability','Sore, smooth tongue','Megaloblastic anemia'], causes:['Vegan or strict vegetarian diet (B12 found only in animal products)','Pernicious anemia (autoimmune destruction of intrinsic factor)','Older age — reduced stomach acid impairs B12 absorption','Long-term metformin use','Gastrectomy or gastric bypass surgery','Inflammatory bowel disease'], homecare:['B12 supplements — sublingual (under tongue) or oral high-dose supplements for dietary deficiency','Regular B12-fortified foods — nutritional yeast, fortified plant milks, cereals','Intramuscular B12 injections for pernicious anemia or malabsorption (cannot rely on oral route)','Monitor blood levels annually'], whenToSeeDoctor:'Blood tests for serum B12, full blood count, and methylmalonic acid levels confirm deficiency. Neurological symptoms from B12 deficiency need urgent treatment to prevent permanent nerve damage.', urgency:'medium' },

  { name:'Vitamin C Deficiency', aliases:['vitamin c deficiency','ascorbic acid deficiency','scurvy','low vitamin c'], emoji:'🍊', type:'lifestyle', description:'A deficiency of vitamin C (ascorbic acid), essential for collagen synthesis, immune function, and iron absorption. Severe deficiency causes scurvy. More common in those with poor diets, smokers, and elderly individuals.', symptoms:['Fatigue and irritability','Joint and muscle pain','Swollen, bleeding, or spongy gums','Slow wound healing','Easy bruising — pinpoint red spots (petechiae)','Dry, rough skin and hair loss','In severe deficiency (scurvy): corkscrew hairs, perifollicular hemorrhage'], causes:['Diet lacking fresh fruits and vegetables','Smoking (doubles vitamin C requirements)','Alcoholism','Older age with poor diet','Malabsorption conditions'], homecare:['Eat fresh fruits and vegetables daily — citrus fruits, guava, kiwi, strawberries, capsicum, broccoli','Vitamin C supplement 500-1000mg daily if diet is poor','Avoid cooking vegetables at high temperatures — heat destroys vitamin C','Quit smoking'], whenToSeeDoctor:'Blood test can confirm vitamin C levels. Scurvy is a medical emergency — severe gum bleeding, joint hemorrhage, or impaired wound healing needs urgent medical treatment.', urgency:'low' },

  { name:'Vitamin A Deficiency', aliases:['vitamin a deficiency','retinol deficiency','night blindness vitamin','low vitamin a'], emoji:'👁️', type:'lifestyle', description:'A deficiency of vitamin A, essential for vision, immune function, and skin health. Leading cause of preventable blindness in children in developing countries. Common in those with very low-fat, low-vegetable diets.', symptoms:['Night blindness — difficulty seeing in dim light (earliest sign)','Dry, rough skin (xerosis)','Dry eyes','Increased susceptibility to infections','Slow wound healing','Bitot\'s spots — foamy patches on the whites of the eyes (severe deficiency)','In children: growth retardation'], causes:['Diet lacking liver, dairy, eggs, and orange-yellow vegetables','Malabsorption (celiac disease, Crohn\'s, cystic fibrosis)','Chronic liver disease','Prolonged low-fat diet preventing fat-soluble vitamin absorption'], homecare:['Eat vitamin A-rich foods — liver, eggs, dairy, orange and yellow vegetables (carrots, sweet potato, pumpkin), dark leafy greens','Vitamin A supplements only under medical supervision — excess is toxic','Pair plant-based beta-carotene sources with healthy fats for better absorption'], whenToSeeDoctor:'Night blindness or recurrent infections should prompt blood testing for vitamin A levels. Supplementation should be medically guided as vitamin A toxicity causes serious harm. Children with deficiency need specialist management.', urgency:'medium' },

  { name:'Vitamin E Deficiency', aliases:['vitamin e deficiency','tocopherol deficiency','low vitamin e'], emoji:'💊', type:'lifestyle', description:'A deficiency of vitamin E, a fat-soluble antioxidant that protects cells from damage and supports immune function and nerve health. Rare from diet alone — usually occurs with fat malabsorption conditions.', symptoms:['Muscle weakness','Coordination and balance problems (ataxia)','Peripheral neuropathy — numbness and tingling','Retinal damage and vision problems','Impaired immune response','Muscle pain'], causes:['Fat malabsorption conditions — Crohn\'s disease, cystic fibrosis, short bowel syndrome','Very low-fat diets','Rare genetic disorders affecting vitamin E metabolism','Premature infants (have low stores)'], homecare:['Eat vitamin E-rich foods — nuts (almonds, sunflower seeds), vegetable oils, avocado, leafy greens','Vitamin E supplement if malabsorption is the underlying cause — under medical supervision','Address the underlying malabsorption condition'], whenToSeeDoctor:'Neurological symptoms (balance problems, weakness) in a person with known malabsorption should prompt vitamin E level testing. Supplementation dose and duration should be medically supervised.', urgency:'low' },

  { name:'Vitamin K Deficiency', aliases:['vitamin k deficiency','low vitamin k','bleeding vitamin k','clotting vitamin deficiency'], emoji:'💊', type:'lifestyle', description:'A deficiency of vitamin K, essential for blood clotting and bone metabolism. Uncommon in healthy adults with normal diets but occurs with fat malabsorption, liver disease, or prolonged antibiotic use.', symptoms:['Easy bruising','Excessive bleeding from cuts','Heavy menstrual periods','Blood in urine or stool','Bleeding gums','In newborns: potentially life-threatening bleeding (vitamin K deficiency bleeding)'], causes:['Fat malabsorption (biliary disease, celiac, Crohn\'s)','Long-term broad-spectrum antibiotics destroying gut bacteria','Severe liver disease','Warfarin medication (antagonizes vitamin K)','Very poor diet'], homecare:['Eat vitamin K-rich foods — dark leafy greens (spinach, kale, broccoli), fermented foods (natto)','If on warfarin: maintain consistent vitamin K intake — sudden changes affect INR dramatically','Vitamin K supplement under medical supervision if malabsorption is the cause'], whenToSeeDoctor:'Unexplained easy bruising or bleeding warrants a clotting screen including vitamin K status. Newborns receive a vitamin K injection at birth to prevent deficiency bleeding — ensure this is not missed.', urgency:'medium' },

  { name:'Iron Overload', aliases:['iron overload','hemochromatosis','high iron','excess iron','ferritin high','iron toxicity'], emoji:'🩸', type:'lifestyle', description:'A condition where too much iron accumulates in the body, damaging organs including the liver, heart, and pancreas. Can be hereditary (hemochromatosis) or result from excessive iron supplementation or repeated blood transfusions.', symptoms:['Joint pain — especially knuckle joints','Fatigue and weakness','Abdominal pain','Bronze or grey skin discoloration','Loss of libido','Irregular heartbeat','Liver enlargement','In advanced cases: cirrhosis, diabetes, heart failure'], causes:['Hereditary hemochromatosis — HFE gene mutation (most common cause)','Excessive iron supplementation','Repeated blood transfusions','Chronic liver disease'], homecare:['Do not take iron supplements unless prescribed by a doctor','Avoid vitamin C supplements with meals (increases iron absorption)','Avoid raw shellfish (risk of Vibrio infection is high with iron overload)','Treatment is regular therapeutic phlebotomy (blood removal) as prescribed by a doctor — do not skip sessions'], whenToSeeDoctor:'Elevated serum ferritin and transferrin saturation on blood tests should prompt specialist evaluation. Hereditary hemochromatosis is managed with regular venesection (blood removal). Family members should be screened if genetic hemochromatosis is diagnosed.', urgency:'medium' },

  { name:'Zinc Deficiency', aliases:['zinc deficiency','low zinc','zinc shortage','zinc poor diet'], emoji:'💊', type:'lifestyle', description:'A deficiency of zinc, essential for immune function, wound healing, taste and smell perception, and protein synthesis. Common in those with poor diets, vegetarians, and people with malabsorption.', symptoms:['Impaired immune function — frequent infections','Poor wound healing','Loss of taste and smell','Hair loss','Diarrhea','Skin rashes — eczema-like patches','Poor growth in children','Low testosterone levels in men'], causes:['Low intake of zinc-rich foods (meat, shellfish, legumes, seeds, nuts)','Vegetarian or vegan diet (phytates in plant foods reduce zinc absorption)','Malabsorption conditions','Excessive alcohol use','Sickle cell disease','Pregnancy and breastfeeding increase requirements'], homecare:['Eat zinc-rich foods — red meat, oysters, shellfish, pumpkin seeds, chickpeas, cashews, tofu','Soak legumes and grains before cooking to reduce phytate content and improve zinc absorption','Zinc supplement (zinc gluconate or zinc picolinate) — 8-11mg daily if diet is insufficient','Do not over-supplement — excess zinc impairs copper absorption'], whenToSeeDoctor:'Blood zinc levels can confirm deficiency. A doctor can advise appropriate supplementation dose and duration. Investigate underlying malabsorption if zinc deficiency is persistent despite adequate diet.', urgency:'low' },

  { name:'Magnesium Deficiency', aliases:['magnesium deficiency','low magnesium','hypomagnesemia','magnesium shortage','low mg'], emoji:'💊', type:'lifestyle', description:'A deficiency of magnesium, involved in over 300 enzymatic reactions in the body including muscle and nerve function, blood sugar regulation, and blood pressure. Very common — estimated to affect up to 45% of people.', symptoms:['Muscle cramps and spasms — especially leg cramps at night','Fatigue and weakness','Anxiety and irritability','Headaches and migraines','Irregular heartbeat (palpitations)','Difficulty sleeping','Constipation','Tingling and numbness'], causes:['Low dietary intake — processed food diet lacking magnesium-rich foods','Excessive alcohol use','Type 2 diabetes (increases urinary magnesium losses)','Long-term use of proton pump inhibitors (PPIs) and diuretics','Malabsorption conditions','Chronic stress'], homecare:['Eat magnesium-rich foods — dark leafy greens, nuts (almonds, cashews), seeds (pumpkin, chia), whole grains, dark chocolate, legumes, avocado','Magnesium glycinate or magnesium citrate supplement 200-400mg daily — better absorbed than magnesium oxide','Reduce alcohol and limit caffeine','Avoid prolonged PPI use if not medically necessary'], whenToSeeDoctor:'Serum magnesium blood test can confirm deficiency (note: serum levels may appear normal even with tissue deficiency). Persistent muscle cramps, palpitations, or severe anxiety should be evaluated by a doctor.', urgency:'low' },

  { name:'Calcium Deficiency', aliases:['calcium deficiency','low calcium','hypocalcemia','calcium shortage','weak bones calcium'], emoji:'🦴', type:'lifestyle', description:'Insufficient calcium intake or absorption, leading to reduced bone density and neuromuscular dysfunction. Long-term deficiency causes osteoporosis. Acute severe hypocalcemia (low blood calcium) is a medical emergency.', symptoms:['Muscle cramps and spasms','Tingling in hands, feet, and face','Brittle or easily broken nails','Dental problems','Fatigue and weakness','Confusion and memory problems (in significant deficiency)','Bone pain and fractures (chronic deficiency)'], causes:['Inadequate dietary calcium intake','Vitamin D deficiency (required for calcium absorption)','Lactose intolerance with dairy avoidance and no substitution','Malabsorption conditions','Hypoparathyroidism','Long-term corticosteroid use'], homecare:['Calcium-rich foods — dairy products, fortified plant milks, tofu, dark leafy greens, sesame, sardines with bones','Calcium carbonate (with food) or calcium citrate (without food) supplements — 500mg doses absorbed better than single large doses','Ensure adequate vitamin D — calcium cannot be absorbed without it','Spread calcium sources throughout the day'], whenToSeeDoctor:'Blood calcium levels should be tested. Vitamin D level is equally important. A doctor should guide supplementation to avoid over-supplementation, which can increase kidney stone risk.', urgency:'medium' },

  { name:'Potassium Deficiency', aliases:['potassium deficiency','low potassium','hypokalemia','low k','potassium shortage'], emoji:'💊', type:'lifestyle', description:'A lower than normal level of potassium in the bloodstream. Potassium is essential for nerve and muscle cell function, particularly heart muscle. Significant hypokalemia can cause life-threatening heart arrhythmias.', symptoms:['Muscle weakness and cramps','Fatigue','Constipation','Abnormal heart rhythm (palpitations)','Numbness or tingling','Nausea and vomiting','In severe deficiency: paralysis and dangerous heart arrhythmias'], causes:['Excessive sweating','Chronic diarrhea or vomiting','Diuretic medications (especially loop and thiazide diuretics)','Inadequate dietary intake','Eating disorders (laxative abuse and purging)','Alcohol abuse'], homecare:['Eat potassium-rich foods — bananas, avocados, sweet potatoes, spinach, tomatoes, beans, yogurt, orange juice','Potassium supplement only under medical supervision — uncontrolled supplementation can cause dangerous hyperkalemia','Rehydrate well with electrolyte solutions after significant sweating or diarrhea'], whenToSeeDoctor:'Serum potassium is measured on a standard blood test. Hypokalemia on blood tests requires medical evaluation and supervised correction. Severe deficiency with cardiac symptoms needs emergency care.', urgency:'medium' },

  { name:'Sodium Imbalance', aliases:['sodium imbalance','low sodium','high sodium','hyponatremia','hypernatremia','salt imbalance'], emoji:'💊', type:'lifestyle', description:'Abnormal sodium levels in the blood — either too low (hyponatremia) or too high (hypernatremia). Sodium regulates fluid balance, blood pressure, and nerve and muscle function. Both extremes are serious.', symptoms:['Hyponatremia (low sodium): nausea, headache, confusion, fatigue, muscle cramps, seizures in severe cases','Hypernatremia (high sodium): excessive thirst, dry mouth, lethargy, confusion, muscle twitching'], causes:['Hyponatremia: excessive water intake, heart failure, kidney disease, liver cirrhosis, certain medications (diuretics, antidepressants)','Hypernatremia: dehydration, excessive sodium intake, diabetes insipidus'], homecare:['Do not over-restrict or over-consume sodium without medical guidance','For exercise-related hyponatremia: drink sports electrolyte drinks rather than plain water during long endurance events','Avoid excessive salt in processed foods to prevent hypernatremia','Follow fluid restrictions if prescribed for heart failure or liver cirrhosis'], whenToSeeDoctor:'Sodium levels are measured on a blood test. Any significant sodium abnormality requires medical management — correction must be done slowly to avoid brain damage. Confusion, seizures, or severe lethargy from sodium imbalance is a medical emergency.', urgency:'high' },

  { name:'Folate Deficiency', aliases:['folate deficiency','folic acid deficiency','low folate','megaloblastic anemia folate','vitamin b9 deficiency'], emoji:'💊', type:'lifestyle', description:'A deficiency of folate (vitamin B9), essential for DNA synthesis, cell division, and red blood cell production. Critical during pregnancy — deficiency causes neural tube defects. Also causes megaloblastic anemia.', symptoms:['Fatigue and weakness (megaloblastic anemia)','Pale skin','Shortness of breath','Mouth sores and sore tongue','Neural tube defects in newborns (if deficient during early pregnancy)','Cognitive difficulties and irritability'], causes:['Poor diet lacking green vegetables, legumes, and fortified foods','Alcoholism — impairs folate absorption and increases requirements','Pregnancy — dramatically increases folate requirements','Malabsorption conditions','Certain medications (methotrexate, some anticonvulsants)'], homecare:['Eat folate-rich foods — dark leafy greens, lentils, chickpeas, fortified cereals, asparagus, avocado','400 micrograms folic acid supplement daily for all women planning pregnancy or in the first trimester (reduces neural tube defect risk by 70%)','Avoid excessive alcohol'], whenToSeeDoctor:'Blood folate and full blood count tests confirm deficiency. Women planning pregnancy should start folic acid 3 months before conception. Higher doses (5mg) are required if previous neural tube defect pregnancy history or on anticonvulsant medications.', urgency:'medium' },

  { name:'Iodine Deficiency', aliases:['iodine deficiency','low iodine','iodine shortage','goiter iodine','thyroid iodine deficiency'], emoji:'🦋', type:'lifestyle', description:'A deficiency of iodine, an essential trace element required for thyroid hormone production. The most common preventable cause of intellectual disability globally. Causes goiter (enlarged thyroid) and thyroid dysfunction.', symptoms:['Goiter — visible swelling at the front of the neck','Fatigue and weakness','Weight gain despite normal eating','Feeling cold all the time','Hair loss and dry skin','Memory and concentration difficulties','Slowed heart rate','In pregnant women: risk of severe cognitive impairment in the baby'], causes:['Inadequate dietary iodine intake — rare with iodized salt use','Living in iodine-depleted regions (mountainous areas, inland regions)','Vegan diet without dairy or seafood','Avoiding iodized salt'], homecare:['Use iodized salt for cooking','Eat iodine-rich foods — seafood, seaweed, dairy products, eggs','Iodine supplement for pregnant and breastfeeding women as per national guidelines','Do not take iodine supplements without guidance — excess iodine also harms the thyroid'], whenToSeeDoctor:'Thyroid function tests and urinary iodine can assess iodine status. A goiter or thyroid dysfunction needs endocrinologist evaluation. Pregnant women with suspected iodine deficiency need urgent management.', urgency:'medium' },

  { name:'Selenium Deficiency', aliases:['selenium deficiency','low selenium','selenium shortage'], emoji:'💊', type:'lifestyle', description:'A deficiency of selenium, a trace mineral with antioxidant properties important for thyroid function, immune response, and DNA synthesis. Rare in most countries but can occur in areas with selenium-depleted soil.', symptoms:['Muscle weakness and fatigue','Fertility issues in men (poor sperm quality)','Hair and nail changes — brittle or white nails, hair loss','Increased susceptibility to infection','Cognitive decline','In severe deficiency: Keshan disease (cardiomyopathy), Kashin-Beck disease (joint disorder)'], causes:['Low selenium content in soil (and therefore food) in certain regions','Very restrictive or vegan diets from selenium-poor areas','Malabsorption conditions — Crohn\'s disease, celiac disease','Total parenteral nutrition without selenium supplementation'], homecare:['Brazil nuts — just 1-2 per day provides the recommended daily selenium intake','Eat selenium-rich foods — seafood, organ meats, eggs, whole grains, sunflower seeds','Selenium supplement 55-200 micrograms daily if deficient — do not exceed 400 micrograms (toxic)'], whenToSeeDoctor:'Blood selenium levels can be tested if deficiency is suspected. A doctor should guide supplementation dose. Selenium excess (selenosis) causes hair loss, nail brittleness, and nerve damage — do not over-supplement.', urgency:'low' },

  { name:'Omega-3 Deficiency', aliases:['omega 3 deficiency','low omega 3','essential fatty acid deficiency','fish oil deficiency','epa dha deficiency'], emoji:'🐟', type:'lifestyle', description:'Inadequate intake of omega-3 fatty acids (EPA and DHA), essential for brain function, cardiovascular health, inflammation control, and eye health. Very common in populations consuming little oily fish.', symptoms:['Dry, flaky skin','Dry eyes','Fatigue and poor concentration','Joint pain and stiffness','Mood changes — depression and irritability','Poor memory','Brittle hair and nails'], causes:['Low consumption of oily fish','Vegan or vegetarian diet without algae-based omega-3','High intake of omega-6 fatty acids relative to omega-3 (typical in processed food diets)'], homecare:['Eat oily fish 2-3 times per week — salmon, sardines, mackerel, anchovies, herring','Fish oil supplement (1000-2000mg EPA+DHA per day) if diet is insufficient','Algae-based omega-3 supplement for vegans and vegetarians','Reduce omega-6 rich oils (sunflower, corn, soybean oil) which compete with omega-3'], whenToSeeDoctor:'Omega-3 index blood testing is available but not routinely offered. A doctor or dietitian can guide supplementation especially during pregnancy, breastfeeding, and for those with cardiovascular disease or depression.', urgency:'low' },

  { name:'Protein Deficiency', aliases:['protein deficiency','low protein intake','inadequate protein','kwashiorkor','protein malnutrition'], emoji:'🥩', type:'lifestyle', description:'Insufficient protein intake to meet the body\'s needs for tissue repair, enzyme production, immune function, and muscle maintenance. Ranges from subtle functional deficiency to severe malnutrition (kwashiorkor and marasmus).', symptoms:['Muscle loss and weakness','Fatigue','Slow wound healing','Frequent infections','Swollen abdomen or legs (edema) from low albumin','Dry, brittle hair and hair loss','Cracked or peeling skin','Poor growth in children'], causes:['Very low-protein diet','Vegan diet without adequate protein sources','Elderly people with poor appetite and reduced protein intake','Malabsorption conditions','Eating disorders','Severe illness or cancer'], homecare:['Aim for at least 0.8-1.0g of protein per kg body weight daily (higher for elderly, athletes, or ill individuals)','Include protein in every meal — eggs, legumes, dairy, meat, fish, tofu, tempeh, nuts, seeds','Distribute protein evenly across 3-4 meals for best muscle protein synthesis','Consider protein powder supplementation if dietary intake is insufficient'], whenToSeeDoctor:'Serum albumin and prealbumin tests assess protein status. A dietitian should evaluate and guide protein intake, particularly in elderly patients, those with malabsorption, or after illness.', urgency:'medium' },

  { name:'Malnutrition', aliases:['malnutrition','undernutrition','nutritional deficiency','poor nutrition','malnourished'], emoji:'🍽️', type:'lifestyle', description:'A condition resulting from inadequate or imbalanced intake of nutrients. Includes both undernutrition (deficiency of calories and nutrients) and overnutrition (excess of certain nutrients). A global health crisis affecting billions.', symptoms:['Unintentional weight loss','Fatigue and weakness','Reduced muscle mass','Poor wound healing','Impaired immune function and frequent infections','Difficulty concentrating','In children: stunted growth, delayed development','In severe cases: swollen belly, hair discoloration, skin breakdown'], causes:['Inadequate food access (poverty, disaster, conflict)','Poor diet quality despite adequate calories','Malabsorption conditions','Chronic illness increasing nutritional needs','Eating disorders','Neglect or social isolation especially in elderly'], homecare:['Eat a varied diet including all food groups — carbohydrates, protein, healthy fats, fruits, vegetables','Small frequent nutritious meals if appetite is poor','High-calorie, high-protein foods for those underweight','Nutritional supplements if advised by a healthcare provider'], whenToSeeDoctor:'Unexplained weight loss exceeding 5% of body weight in 6 months or any signs of malnutrition need medical assessment. A physician and dietitian should work together. Hospital admission may be needed for severe malnutrition.', urgency:'high' },

  { name:'Underweight', aliases:['underweight','low body weight','thin','bmi underweight','low weight'], emoji:'⚖️', type:'lifestyle', description:'Having a body weight below what is considered healthy for height — typically defined as a BMI under 18.5 kg/m². Being underweight increases risk of nutritional deficiencies, bone loss, immune dysfunction, and fertility problems.', symptoms:['BMI below 18.5 kg/m²','Fatigue and low energy','Frequent illness','Poor concentration','Dry skin, brittle hair and nails','Feeling cold all the time','Irregular or absent periods in women','Muscle weakness'], causes:['Inadequate caloric intake relative to needs','High metabolism','Eating disorders (anorexia, restrictive patterns)','Chronic illness increasing metabolic demand or reducing appetite','Malabsorption','Hyperthyroidism'], homecare:['Increase caloric intake with nutrient-dense foods — nuts, avocado, whole grains, dairy, protein sources','Eat 5-6 small meals per day rather than 3 large ones','Strength training to build muscle mass alongside increased calorie intake','Avoid filling up on low-calorie liquids before meals'], whenToSeeDoctor:'Unexplained underweight or inability to gain weight despite eating adequately needs medical investigation to rule out malabsorption, thyroid disease, or eating disorder. A dietitian and physician should assess and manage together.', urgency:'medium' },

  { name:'Muscle Wasting', aliases:['muscle wasting','cachexia','muscle breakdown','catabolic muscle loss','sarcopenic obesity'], emoji:'💪', type:'lifestyle', description:'Accelerated loss of muscle tissue beyond normal aging, often seen in serious illness, malnutrition, inactivity, or as part of cachexia in cancer and chronic disease. Significantly impairs function and worsens health outcomes.', symptoms:['Visibly reduced muscle size especially in thighs and upper arms','Profound weakness','Difficulty performing basic tasks — standing, walking, climbing stairs','Fatigue disproportionate to activity','Unintentional weight loss','Reduced grip strength'], causes:['Serious illness — cancer, heart failure, kidney disease, HIV (cachexia)','Prolonged bed rest or immobilization','Severe malnutrition or inadequate protein intake','Aging combined with inactivity','Inflammation — high inflammatory cytokines break down muscle'], homecare:['Progressive resistance exercise — even gentle exercise with resistance bands reduces muscle loss','Protein intake at least 1.5g per kg per day — distribute across all meals','Leucine-rich protein sources stimulate muscle protein synthesis — meat, fish, dairy, eggs, soy','Address the underlying disease causing wasting','Appetite stimulants or nutritional supplements as medically prescribed'], whenToSeeDoctor:'Unexplained or rapid muscle wasting needs urgent medical evaluation. A multidisciplinary team including physician, physiotherapist, and dietitian should manage cachexia together.', urgency:'high' },

  { name:'Chronic Dehydration', aliases:['chronic dehydration','persistent dehydration','not drinking enough water','low fluid intake','subclinical dehydration'], emoji:'💧', type:'lifestyle', description:'A state of consistently inadequate fluid intake where the body operates in a mildly dehydrated state over time. Impairs kidney function, cognitive performance, physical stamina, and gut health.', symptoms:['Persistent mild thirst (often ignored)','Dark yellow urine','Fatigue and low energy','Difficulty concentrating and brain fog','Headaches especially in the afternoon','Dry mouth and lips','Infrequent urination (less than 4-6 times per day)','Constipation'], causes:['Inadequate daily fluid intake','High ambient temperatures or physical activity increasing fluid losses','Excessive alcohol, coffee, or energy drink consumption','Forgetting to drink — especially in older adults who have a blunted thirst response'], homecare:['Drink 2-3 liters of water per day (adjust for heat and activity)','Carry a reusable water bottle and sip regularly throughout the day','Eat water-rich foods — cucumber, watermelon, tomatoes, soups, yogurt','Monitor urine color — pale yellow indicates good hydration','Set reminders to drink water if you tend to forget'], whenToSeeDoctor:'Significant dehydration with confusion, no urination for 8+ hours, very dark urine, or rapid heart rate needs medical evaluation. Elderly individuals and those on diuretics are at highest risk of dehydration-related complications.', urgency:'low' },

  /* ── LIFESTYLE: POSTURE & MUSCULOSKELETAL ── */
  { name:'Poor Posture', aliases:['poor posture','bad posture','postural dysfunction','slouching','posture problems'], emoji:'🧍', type:'lifestyle', description:'Habitual positioning of the body that places strain on muscles, joints, and ligaments over time, leading to pain, fatigue, and structural changes. One of the most common contributing factors to neck, back, and shoulder pain.', symptoms:['Neck and shoulder pain and tension','Upper and lower back pain','Headaches from neck strain','Fatigue from muscles working harder than necessary','Rounded upper back appearance','Forward head position'], causes:['Prolonged sitting — especially at desks or using devices','Weak core and postural muscles','Poor ergonomic setup at work','Excessive screen time','Carrying heavy bags on one shoulder','Muscle imbalances'], homecare:['Ergonomic workstation setup — screen at eye level, chair supporting lumbar curve','Take breaks every 30-60 minutes to stand and move','Strengthen core and back muscles — specific postural exercises and yoga','Chin tuck exercises to counteract forward head posture','Awareness practice — check and correct posture throughout the day','Stretching chest and hip flexors which tighten with prolonged sitting'], whenToSeeDoctor:'Persistent neck or back pain from poor posture should be assessed by a physiotherapist who can design a specific corrective exercise program. A physician should evaluate pain that is severe, associated with nerve symptoms, or not improving.', urgency:'low' },

  { name:'Text Neck', aliases:['text neck','phone neck','smartphone neck','neck flexion pain','forward neck phone'], emoji:'📱', type:'lifestyle', description:'A modern repetitive strain condition caused by excessive forward head bending while using smartphones, tablets, or other handheld devices. The head weighing significantly more in a tilted position places enormous strain on the neck and upper back.', symptoms:['Neck pain and soreness — especially after phone use','Stiffness and reduced range of neck movement','Upper back and shoulder pain and tightness','Headaches at the base of the skull','Tingling or numbness in the arms in severe cases'], causes:['Prolonged smartphone and tablet use with head tilted downward','Poor ergonomics — holding device at chest level instead of eye level','Weak neck and upper back muscles','Prolonged sitting and sedentary lifestyle'], homecare:['Hold devices at eye level rather than looking down','Set a timer and limit continuous phone use to 20-minute sessions with breaks','Chin tuck exercises — 10 repetitions multiple times daily','Stretch the neck and upper back regularly','Strengthen neck extensor and upper back muscles'], whenToSeeDoctor:'Persistent neck pain, arm tingling, or pain not improving with posture correction should be assessed by a physiotherapist. Nerve compression symptoms (numbness, weakness in arm) require medical evaluation.', urgency:'low' },

  { name:'Tech Neck', aliases:['tech neck','computer neck','screen neck','monitor neck pain','prolonged screen neck'], emoji:'💻', type:'lifestyle', description:'Neck and upper back pain caused by prolonged use of computers, tablets, and screens with poor posture. A broader term than text neck, encompassing all screen-device-related neck strain. Extremely common in office workers.', symptoms:['Chronic neck stiffness and pain','Upper back and shoulder tension','Headaches','Reduced neck range of movement','Fatigue in neck and shoulder muscles by end of the day','Eye strain often accompanies'], causes:['Monitor positioned too low or too high','Prolonged sitting at a desk without breaks','Forward head posture while working on screens','Weak postural muscles','Stress and tension causing muscles to tighten'], homecare:['Position monitor at eye level — top of screen at or just below eye height','Sit with feet flat on the floor, back supported, and screen 50-70cm away','Use the 20-20-20 rule for screens — every 20 minutes look at something 20 feet away for 20 seconds','Regular stretch breaks — shoulder rolls, neck stretches, chest openers','Strengthen deep neck flexors and back muscles'], whenToSeeDoctor:'Physiotherapy assessment is recommended for persistent tech neck pain. Occupational health evaluation can optimize workstation ergonomics. Nerve symptoms require medical assessment.', urgency:'low' },

  { name:'Forward Head Posture', aliases:['forward head posture','head forward position','head protrusion','cervical kyphosis','poking chin'], emoji:'🧍', type:'lifestyle', description:'A postural dysfunction where the head sits forward of the ideal alignment over the shoulders. For every inch the head moves forward, the effective weight on the cervical spine nearly doubles, causing significant strain on neck and upper back structures.', symptoms:['Neck pain and muscle tension','Upper back tightness and rounded shoulders','Headaches — especially at the back of the head','Jaw pain (TMJ dysfunction)','Reduced neck mobility','Fatigue in neck and shoulder muscles','In severe cases: nerve compression with arm tingling'], causes:['Prolonged screen use in a forward-leaning position','Weak deep neck flexor muscles','Tight chest and anterior shoulder muscles','Poor sitting habits over many years'], homecare:['Chin tuck exercise — the most effective exercise — gently tuck the chin in and up to elongate the back of the neck, hold 5 seconds, 10 repetitions','Strengthen deep neck flexors and rhomboid muscles','Stretch chest (pectoral) muscles which are typically tight','Pillow height adjustment — too high or too low a pillow worsens forward head posture during sleep'], whenToSeeDoctor:'A physiotherapist can assess and design a specific corrective exercise and manual therapy program. X-ray of the cervical spine is recommended if nerve symptoms are present or pain is severe.', urgency:'low' },

  { name:'Rounded Shoulders', aliases:['rounded shoulders','shoulder roll forward','kyphotic shoulders','bad shoulder posture','protracted shoulders'], emoji:'🧍', type:'lifestyle', description:'A postural condition where the shoulder blades drift forward around the ribcage, causing the shoulders to appear rounded and hunched. Associated with tight chest muscles and weak upper back and rotator cuff muscles.', symptoms:['Shoulders resting in a forward, hunched position','Upper back aching and stiffness','Neck pain','Reduced shoulder mobility and flexibility','Tightness across the chest','Can contribute to shoulder impingement and rotator cuff issues'], causes:['Prolonged sitting with arms forward (typing, driving)','Chest muscle tightness from pushing exercises without balancing pulling exercises','Weak rhomboid and lower trapezius muscles','Poor posture habits'], homecare:['Chest stretching — doorway chest stretch held for 30 seconds','Strengthen mid and lower trapezius — rows, face pulls, band pull-aparts','Wall angels exercise — stand against a wall and slide arms upward','Posture awareness — consciously draw shoulder blades back and down','Balance pushing (chest) and pulling (row) exercises in workouts'], whenToSeeDoctor:'A physiotherapist can assess scapular muscle strength and design a corrective program. Shoulder pain, clicking, or restricted movement that does not improve with exercise needs medical evaluation for rotator cuff pathology.', urgency:'low' },

  { name:'Flat Feet', aliases:['flat feet','pes planus','fallen arches','flat foot','pronated feet'], emoji:'🦶', type:'lifestyle', description:'A condition where the arches of the feet are absent or reduced, causing the entire sole of the foot to contact the ground when standing. Can be painless or cause significant foot, ankle, knee, and back pain.', symptoms:['Flat appearance of foot sole (no visible arch when standing)','Foot pain and aching especially after prolonged standing or walking','Swelling along the inside of the ankle','Fatigue in the legs','Knee pain from altered lower limb alignment','Back pain'], causes:['Genetic predisposition — family history of flat feet','Tibialis posterior tendon dysfunction','Obesity increasing load on the arch','Aging','Pregnancy (hormonal loosening of ligaments)','Previous foot injuries'], homecare:['Supportive footwear with good arch support — avoid flat flip-flops and worn-out shoes','Orthotic insoles — either off-the-shelf or custom-made to support the arch','Calf muscle stretching — tight calves worsen flat feet','Intrinsic foot muscle strengthening — towel scrunches, single-leg calf raises','Maintain a healthy weight'], whenToSeeDoctor:'Painful flat feet should be assessed by a podiatrist or orthopedic specialist. Custom orthotics are very effective. Children with flat feet should be evaluated to distinguish normal developmental flatness from pathological arch absence.', urgency:'low' },

  { name:'Overpronation', aliases:['overpronation','excessive pronation','foot rolling inward','pronated gait','overpronation running'], emoji:'🦶', type:'lifestyle', description:'Excessive inward rolling of the foot during walking or running, where the foot rolls more than the normal 15 degrees. Can lead to a chain of problems affecting ankles, shins, knees, hips, and lower back.', symptoms:['Shoes wearing unevenly on the inner side','Ankle pain and instability','Shin splints','Knee pain — medial knee pain from altered alignment','Hip and lower back pain','Plantar fasciitis'], causes:['Flat feet or low arches','Weak hip and core muscles allowing the leg to internally rotate','Tight calf and Achilles tendon','Genetic foot structure','Inappropriate footwear without adequate support'], homecare:['Stability or motion control running shoes — significantly reduce pronation','Custom orthotic insoles if pronation is severe','Hip abductor and external rotator strengthening — gluteus medius exercises are key','Calf stretching — tight calves worsen pronation','Single-leg balance exercises to improve ankle stability'], whenToSeeDoctor:'A podiatrist can perform gait analysis and prescribe custom orthotics. A physiotherapist can address muscle imbalances. Persistent pain from overpronation should be evaluated.', urgency:'low' },

  { name:'Knee Valgus', aliases:['knee valgus','knock knees','knees caving in','valgus knee','knee cave','dynamic knee valgus'], emoji:'🦵', type:'lifestyle', description:'An alignment where the knees cave inward toward each other, either statically or during dynamic movement like squatting or jumping. A common contributor to knee pain and injury risk, particularly ACL and patellofemoral pain.', symptoms:['Knees visibly angling inward during standing, walking, or squatting','Knee pain especially on the inner (medial) side','Patellofemoral pain (pain around the kneecap)','Hip and lower back pain','Increased risk of ACL and meniscus injury during sports'], causes:['Weak hip abductor and external rotator muscles (especially gluteus medius)','Weak quadriceps and VMO (inner quad) muscle','Overpronated feet transmitting inward force up the kinetic chain','Poor movement patterns developed from early life'], homecare:['Glute strengthening exercises — clamshells, hip abduction, lateral band walks, single-leg squats','VMO (inner quadriceps) strengthening — terminal knee extensions, narrow stance squats','Squat and deadlift technique correction — cue \'knees out\'','Foot orthotics if overpronation is contributing','Movement pattern re-education with a physiotherapist or qualified coach'], whenToSeeDoctor:'Persistent knee pain from valgus alignment should be assessed by a physiotherapist or sports medicine doctor. Children with significant static knock-knee deformity (genu valgum) require orthopedic assessment.', urgency:'low' },

  { name:'Hip Imbalance', aliases:['hip imbalance','hip asymmetry','hip muscle imbalance','uneven hips','hip weakness'], emoji:'🦴', type:'lifestyle', description:'An asymmetry in strength, flexibility, or alignment between the two hips, or between hip flexors and extensors, causing altered movement patterns and increased risk of hip, knee, and lower back pain.', symptoms:['One hip appearing higher than the other','Lower back pain and tightness on one side','Uneven gait or limping','Hip stiffness on one side','Knee or ankle pain from compensatory movement patterns','Lateral hip pain (gluteal tendinopathy)'], causes:['Prolonged sitting causing hip flexor tightening','Weak gluteal muscles — especially gluteus medius','Leg length discrepancy (anatomical or functional)','Previous injury creating compensatory patterns','Sport-specific repetitive movements'], homecare:['Hip flexor stretching — kneeling lunge stretch held 30-60 seconds','Glute strengthening — bridges, clamshells, deadlifts, single-leg exercises','Core strengthening to stabilize the pelvis','Mobility work — hip circles, 90/90 hip stretch','Gait re-education if an abnormal pattern has developed'], whenToSeeDoctor:'Persistent hip pain or visible pelvic asymmetry should be assessed by a physiotherapist. Leg length discrepancy causing imbalance may benefit from a heel lift. Severe hip pain needs imaging to rule out labral tears or hip joint pathology.', urgency:'low' },

  { name:'Core Weakness', aliases:['core weakness','weak core muscles','poor core stability','core instability','weak abdominals'], emoji:'💪', type:'lifestyle', description:'Insufficient strength and endurance of the deep stabilizing muscles of the trunk (transversus abdominis, multifidus, pelvic floor, diaphragm), leading to spinal instability, poor posture, and increased injury risk during daily activities and exercise.', symptoms:['Lower back pain with prolonged sitting or standing','Back fatigue during everyday tasks','Poor posture — difficulty maintaining upright position','Difficulty with balance and coordination','Increased injury risk during exercise or lifting','Pelvic floor dysfunction in some cases'], causes:['Sedentary lifestyle','Prolonged sitting','Inadequate exercise targeting deep core muscles','Post-pregnancy — abdominal muscles stretched and weakened','Post-surgery recovery','Aging'], homecare:['Deep core activation exercises — drawing in the navel gently (abdominal bracing), dead bugs, bird-dogs','Plank progressions — starting with a modified plank on knees and building to full plank','Bridge exercises for posterior chain and core integration','Pilates and yoga — both emphasize deep core stability','Progress to functional movements — squats, deadlifts — once basic core stability is achieved'], whenToSeeDoctor:'Persistent lower back pain from core weakness should be assessed by a physiotherapist. Postpartum women with diastasis recti (abdominal separation) need specialized assessment before returning to exercise.', urgency:'low' },

  { name:'Sedentary Lifestyle Syndrome', aliases:['sedentary lifestyle syndrome','physical inactivity','too much sitting','sedentary behavior','inactivity syndrome'], emoji:'🛋️', type:'lifestyle', description:'A pattern of very low physical activity and excessive sitting that contributes to a wide range of health problems. Prolonged sitting is now recognized as an independent risk factor for cardiovascular disease, type 2 diabetes, and early mortality — even in those who exercise.', symptoms:['Fatigue and low energy levels','Weight gain and muscle weakness','Poor cardiovascular fitness','Back, neck, and hip pain from prolonged sitting','Increased risk of metabolic syndrome','Mood changes — depression and anxiety correlate with inactivity','Poor sleep quality'], causes:['Desk-based work — 8+ hours of sitting daily','Excessive recreational screen time','Car-dependent lifestyle with minimal walking','Low motivation or access to exercise'], homecare:['Stand and move at least 2-3 minutes every 30 minutes of sitting — set a timer','Aim for 7,000-10,000 steps per day — a pedometer or phone step counter helps','30 minutes of moderate aerobic activity most days of the week','Take the stairs, park further away, walk to nearby destinations','Active commuting — cycling or walking to work'], whenToSeeDoctor:'Annual health checks should include a discussion of physical activity levels. A doctor can screen for metabolic consequences of inactivity (blood pressure, blood sugar, lipids). A physiotherapist can help establish a safe exercise start-up program.', urgency:'medium' },

  { name:'Overtraining Syndrome', aliases:['overtraining syndrome','overtraining','burnout athlete','overtraining fatigue','excessive exercise syndrome'], emoji:'🏃', type:'lifestyle', description:'A state of physical and psychological fatigue resulting from excessive training load without adequate recovery. Paradoxically, performance decreases despite continued or increased training. Common in athletes and exercise enthusiasts.', symptoms:['Persistent fatigue not relieved by rest','Declining performance despite continued training','Increased susceptibility to illness and infections','Mood disturbances — irritability, depression, loss of motivation','Sleep disturbance','Elevated resting heart rate','Muscle soreness that does not resolve','Loss of appetite and unintended weight loss'], causes:['Training volume and intensity increased too rapidly','Inadequate rest days between sessions','Poor sleep and recovery','Caloric deficit — inadequate fueling for training load','Psychological stress compounding physical stress'], homecare:['Complete rest from training for 1-2 weeks — not just reduced training','Prioritize sleep — 8-9 hours per night during recovery','Adequate caloric and protein intake to support recovery','Gradual return to training after full recovery — start at 50% of previous volume','Address psychological stress','Work with a coach to plan periodized training with built-in recovery weeks'], whenToSeeDoctor:'A sports medicine doctor can confirm overtraining syndrome and rule out other causes of fatigue. Blood tests check for iron deficiency, thyroid dysfunction, and other contributors. A sports psychologist may help if motivation and mood are significantly affected.', urgency:'medium' },

  { name:'Exercise Addiction', aliases:['exercise addiction','compulsive exercise','excessive exercise','exercise dependence','obligatory exercise'], emoji:'🏋️', type:'lifestyle', description:'A compulsive, unhealthy relationship with exercise where the person feels driven to exercise excessively despite injury, illness, or disruption to daily life. Often coexists with eating disorders.', symptoms:['Inability to take rest days even when injured or ill','Intense anxiety, guilt, or irritability when unable to exercise','Exercise takes priority over relationships, work, and social life','Exercising to compensate for eating (common with eating disorders)','Declining performance due to inadequate recovery','Physical signs of overtraining — frequent injuries, fatigue, poor sleep'], causes:['Psychological dependence on endorphin release from exercise','Perfectionism and high achievement drive','Underlying anxiety, depression, or eating disorder','Societal reinforcement of extreme fitness as a positive trait'], homecare:['Recognize the signs and acknowledge the problem — often requires external feedback from loved ones','Schedule mandatory rest days and practice tolerating rest without guilt','Seek psychological support — CBT is effective for compulsive exercise','Address any underlying eating disorder simultaneously','Gradually diversify coping mechanisms beyond exercise'], whenToSeeDoctor:'Exercise addiction requires psychological assessment and treatment — ideally from a psychologist or psychiatrist familiar with eating disorders. A physician should assess for physical complications from overtraining.', urgency:'medium' },

  /* ── LIFESTYLE: SPORTS & REPETITIVE STRAIN INJURIES ── */
  { name:'Runner\'s Knee', aliases:['runner\'s knee','patellofemoral pain syndrome','pfps','knee pain running','anterior knee pain'], emoji:'🦵', type:'lifestyle', description:'Pain around or behind the kneecap (patella), commonly caused by repetitive stress from running, jumping, or squatting. The most common running-related injury.', symptoms:['Pain around or behind the kneecap — dull aching','Worse going down stairs or hills','Pain when squatting or sitting for prolonged periods (cinema sign)','Grinding or clicking sensation at the kneecap','Swelling around the knee in some cases'], causes:['Overuse from running — increasing mileage too quickly','Weak hip abductors and quadriceps','Overpronation or poor foot biomechanics','Running on hard surfaces','Poor running technique'], homecare:['Reduce running mileage temporarily — do not train through the pain','Ice after activity — 15-20 minutes','Hip strengthening — clam shells, lateral band walks, single-leg squats to address root cause','Quadriceps and hamstring strengthening','Stretching IT band, quadriceps, and calves','Gradually return to running when pain-free'], whenToSeeDoctor:'Persistent knee pain lasting more than 2 weeks despite rest should be assessed by a physiotherapist or sports medicine doctor. Imaging is not usually needed initially but may be required to rule out other conditions.', urgency:'low' },

  { name:'Shin Splints', aliases:['shin splints','medial tibial stress syndrome','mtss','shin pain running','shin ache running'], emoji:'🦵', type:'lifestyle', description:'Pain along the inner edge of the shinbone (tibia), most commonly from running or jumping. One of the most common overuse injuries in runners and military recruits.', symptoms:['Dull aching pain along the inner shin during and after exercise','Tenderness and soreness along the shin bone','Mild swelling in the lower leg','Pain that improves with rest but returns with activity'], causes:['Rapid increase in running mileage or intensity','Running on hard surfaces','Inadequate footwear or worn-out running shoes','Overpronation','Weak hip and ankle muscles','Inadequate warm-up'], homecare:['Rest from running or high-impact activity for 2-4 weeks','Ice the shin 15-20 minutes after activity','Supportive footwear and orthotic insoles if overpronating','Gentle calf stretching','Cross-train with low-impact activity — cycling or swimming','Gradual return to running using run-walk intervals'], whenToSeeDoctor:'Pain that is severe, focal (one specific painful spot on the bone), or not improving with 2-4 weeks rest needs X-ray or MRI to rule out a stress fracture — which requires longer rest and possibly offloading.', urgency:'low' },

  { name:'Stress Fracture', aliases:['stress fracture','bone stress injury','hairline fracture','running stress fracture','fatigue fracture'], emoji:'🦴', type:'lifestyle', description:'A small crack in a bone caused by repetitive stress and overuse, rather than a single trauma. Common in weight-bearing bones — metatarsals, tibia, and navicular. Requires adequate rest to heal fully.', symptoms:['Localized, pinpoint bone pain that worsens progressively with activity','Pain relieved by rest but returns with weight-bearing','Tenderness when pressing directly on the bone','Mild swelling over the affected area','In severe cases: pain at rest or at night'], causes:['Rapid increase in training volume or intensity','Inadequate recovery between sessions','Low bone density — calcium and vitamin D deficiency','Relative energy deficiency in sport (RED-S) — not eating enough to fuel training','Biomechanical issues and poor footwear'], homecare:['Complete rest from the aggravating activity — typically 6-12 weeks depending on location','Non-weight-bearing with crutches for high-risk fractures (navicular, femoral neck)','Maintain fitness with swimming, upper body work, or cycling if pain-free','Address nutritional deficiencies — calcium and vitamin D supplementation','Gradual return to activity only after confirmed healing'], whenToSeeDoctor:'Suspected stress fracture should be assessed by a sports medicine doctor. X-ray may miss stress fractures initially — MRI is more sensitive. Certain stress fractures (femoral neck, navicular, anterior tibia) are high-risk and require specialist management.', urgency:'medium' },

  { name:'Rotator Cuff Injury', aliases:['rotator cuff injury','rotator cuff tear','shoulder tendon injury','rotator cuff strain','shoulder rotator cuff'], emoji:'💪', type:'lifestyle', description:'Injury to one or more of the four muscles and tendons forming the rotator cuff that stabilize the shoulder joint. Ranges from mild tendinitis to complete tear. One of the most common shoulder problems.', symptoms:['Shoulder pain — especially with overhead reaching and lifting','Pain when sleeping on the affected shoulder','Shoulder weakness when lifting or rotating the arm','Clicking or cracking sounds in the shoulder','Difficulty reaching behind the back','In complete tears: sudden sharp pain and significant weakness'], causes:['Repetitive overhead movements — swimming, tennis, painting, throwing','Acute injury from a fall or lifting a heavy object','Age-related tendon degeneration (most common in those over 40)','Poor shoulder muscle strength and imbalance'], homecare:['Rest from aggravating overhead activities during the acute phase','Ice for the first 48-72 hours, then heat','Anti-inflammatory medications (NSAIDs) for pain if tolerated','Rotator cuff strengthening exercises — external rotation with resistance band','Posture improvement — rounded shoulders worsen rotator cuff impingement'], whenToSeeDoctor:'Shoulder pain with significant weakness, inability to lift the arm, or acute severe pain after injury needs urgent assessment — a complete tear may require surgical repair. Physiotherapy is the primary treatment for partial tears.', urgency:'medium' },

  { name:'ACL Injury', aliases:['acl injury','anterior cruciate ligament tear','acl tear','acl rupture','knee ligament injury'], emoji:'🦵', type:'lifestyle', description:'A tear or sprain of the anterior cruciate ligament — one of the key ligaments stabilizing the knee joint. One of the most serious sports injuries, often requiring surgery and months of rehabilitation.', symptoms:['A popping sound at the time of injury','Severe knee pain immediately after injury','Rapid significant knee swelling (within hours)','Loss of full range of motion','Knee feels unstable or gives way','Inability to continue activity after the injury'], causes:['Sudden stopping, cutting, or pivoting movements in sports','Landing awkwardly from a jump','Direct contact (collision) to the knee','High-risk sports: football, basketball, netball, skiing'], homecare:['Apply ice and elevate the leg immediately after injury','Do not return to sport until medically cleared','Use crutches to offload the knee if advised','Pre-operative physiotherapy to reduce swelling and maintain muscle strength while awaiting surgery decision','Rigorous structured rehabilitation for 9-12 months after surgical reconstruction'], whenToSeeDoctor:'Suspected ACL injury requires urgent sports medicine or orthopedic assessment. MRI confirms the diagnosis. The decision between surgical reconstruction and conservative management depends on the patient\'s activity level and associated injuries.', urgency:'high' },

  { name:'Meniscus Tear', aliases:['meniscus tear','torn meniscus','knee cartilage tear','medial meniscus tear','lateral meniscus tear'], emoji:'🦵', type:'lifestyle', description:'A tear in one of the two C-shaped pieces of cartilage (menisci) that act as cushions between the thigh bone and shin bone in the knee. Common in both athletes and older adults.', symptoms:['Pain in the knee — typically on the inner or outer side','Swelling that develops gradually over 24-48 hours (slower than ACL)','A popping sensation at the time of injury','Stiffness and difficulty bending the knee','Locking or catching sensation in the knee','Giving way of the knee'], causes:['Sudden twisting of the knee in sports (traumatic tear)','Degenerative tears in middle-aged and older adults — from daily wear and tear','Direct contact or impact to the knee'], homecare:['Rest, ice, compression, and elevation (RICE) in the acute phase','Anti-inflammatory medications for pain and swelling if tolerated','Quadriceps strengthening exercises once swelling reduces','Avoid deep squatting and high-impact activity until assessed'], whenToSeeDoctor:'Suspected meniscus tear should be assessed by a sports medicine or orthopedic doctor. MRI confirms the diagnosis. Physiotherapy is often sufficient for degenerative tears and small peripheral tears. Surgical trimming (meniscectomy) or repair may be needed for locked or unstable tears.', urgency:'medium' },

  { name:'Achilles Tendinitis', aliases:['achilles tendinitis','achilles tendinopathy','achilles tendon pain','heel cord pain','achilles inflammation'], emoji:'🦵', type:'lifestyle', description:'Inflammation or degeneration of the Achilles tendon — the large tendon connecting the calf muscles to the heel bone. One of the most common overuse injuries in runners.', symptoms:['Pain along the Achilles tendon — worst in the morning or after activity','Stiffness and tenderness at the back of the heel','Mild swelling or thickening of the tendon','Pain worsening with increased activity (running, jumping)','Creaking or crackling sensation on moving the tendon'], causes:['Rapid increase in running volume or intensity','Tight or weak calf muscles','Sudden increase in hill running or speed work','Worn-out footwear','Overpronation','Poor recovery between sessions'], homecare:['Reduce running load — do not train through pain','Eccentric calf raises — the most evidence-based exercise for Achilles tendinopathy (lower heel over the edge of a step)','Calf stretching','Ice after activity','Supportive footwear and heel lifts to temporarily offload the tendon','Gradual return to running over 8-12 weeks'], whenToSeeDoctor:'Achilles pain should be assessed by a physiotherapist or sports medicine doctor. Imaging is needed if a complete tendon rupture is suspected — a gap or positive Thompson test (squeezing calf does not move foot) is a surgical emergency.', urgency:'medium' },

  { name:'Golfer\'s Elbow', aliases:['golfer\'s elbow','medial epicondylitis','medial elbow pain','golfer elbow tendinopathy','forearm flexor tendinopathy'], emoji:'💪', type:'lifestyle', description:'Pain and inflammation at the medial epicondyle — the bony bump on the inner side of the elbow — where the forearm flexor tendons attach. Caused by repetitive gripping, wrist flexion, or forearm pronation.', symptoms:['Pain and tenderness on the inner side of the elbow','Pain radiating down the forearm toward the wrist','Stiffness of the elbow especially in the morning','Weakness in the hand and wrist','Pain with gripping, squeezing, or swinging a racket or club'], causes:['Repetitive wrist flexion and gripping — golf swing, throwing, racket sports','Occupational overuse — carpenters, plumbers, mechanics','Poor technique in sports or repetitive work tasks'], homecare:['Rest from aggravating activities','Ice the medial elbow 15-20 minutes after activity','Gentle forearm flexor stretching','Eccentric wrist flexor exercises — the most effective rehabilitation exercise','Counterforce brace (elbow strap) to reduce tendon load during activity','NSAIDs for short-term pain relief'], whenToSeeDoctor:'Persistent pain lasting more than 6-8 weeks despite conservative management needs physiotherapy assessment. Corticosteroid injection may provide short-term relief. Ultrasound-guided treatments (platelet-rich plasma) are used for refractory cases.', urgency:'low' },

  { name:'Trigger Finger', aliases:['trigger finger','stenosing tenosynovitis','finger locking','clicking finger','trigger thumb'], emoji:'🤙', type:'lifestyle', description:'A condition in which a finger gets stuck in a bent position and then straightens with a snap — like a trigger being pulled and released. Caused by inflammation narrowing the space in the tendon sheath.', symptoms:['Finger stiffness especially in the morning','A popping or clicking sensation when moving the finger','Tenderness at the base of the affected finger (at the palm)','Finger locking in bent position, sometimes requiring the other hand to straighten it','A bump (nodule) on the palm at the base of the finger'], causes:['Repetitive gripping actions — tools, gardening, racket sports','Diabetes significantly increases risk','Rheumatoid arthritis','Hypothyroidism','Carpal tunnel syndrome often coexists'], homecare:['Rest the hand from repetitive gripping activities','Ice the palm at the base of the finger','Gentle finger flexion and extension exercises','Splinting the finger at night in extension to rest the tendon','NSAIDs for pain and inflammation'], whenToSeeDoctor:'Trigger finger that locks or is significantly painful should be assessed by an orthopedic or hand surgeon. Corticosteroid injection into the tendon sheath is highly effective. Surgical release is performed if injections fail.', urgency:'low' },

  { name:'De Quervain\'s Tenosynovitis', aliases:['de quervain\'s','de quervain tenosynovitis','thumb tendon pain','radial wrist pain','new mother wrist','gamer thumb'], emoji:'🤙', type:'lifestyle', description:'Inflammation of the tendons on the thumb side of the wrist, causing pain and swelling near the base of the thumb. Often called \'new mother\'s wrist\' because it commonly affects women who repetitively lift infants.', symptoms:['Pain and swelling near the base of the thumb','Pain radiating up the forearm','Difficulty with pinching and gripping','A \'catching\' or \'snapping\' sensation when moving the thumb','Finkelstein\'s test positive — tucking thumb in fist and tilting wrist toward little finger causes severe pain'], causes:['Repetitive thumb and wrist movements — lifting a baby, gardening, gaming','Pregnancy and new motherhood (hormonal changes affect tendon sheath)','Rheumatoid arthritis'], homecare:['Rest and avoid aggravating movements — pinching, gripping, repetitive thumb use','Thumb spica splint — immobilizes thumb and wrist to allow tendon rest','Ice the radial wrist 15-20 minutes several times daily','Gentle thumb and wrist stretching after the acute phase'], whenToSeeDoctor:'Suspected De Quervain\'s should be confirmed by a doctor (Finkelstein\'s test is diagnostic). Corticosteroid injection into the tendon sheath is highly effective. Surgical release is an option for refractory cases.', urgency:'low' },

  { name:'Repetitive Strain Injury', aliases:['repetitive strain injury','rsi','occupational overuse syndrome','work related upper limb disorder','overuse injury'], emoji:'💻', type:'lifestyle', description:'An umbrella term for pain in muscles, tendons, and nerves from repetitive movements, poor ergonomics, or sustained awkward postures — particularly affecting the upper limb. Extremely common in office workers, musicians, and manual workers.', symptoms:['Aching, burning, or throbbing pain in the affected area','Tenderness and swelling','Stiffness and reduced range of movement','Tingling and numbness (if nerves are involved)','Weakness and reduced grip','Symptoms worse during or after repetitive activity and better with rest'], causes:['Repetitive movements without adequate rest','Sustained awkward postures — wrist extension while typing','Forceful or gripping movements','Vibrating tools','Psychological stress (increases muscle tension)','Poor ergonomics'], homecare:['Reduce or modify the aggravating activity','Regular microbreaks — 30 seconds of stretching every 20-30 minutes','Ergonomic assessment and correction of workstation','Gentle stretching of affected muscles and tendons','Ice or heat for pain relief','Progressive strengthening once acute pain settles'], whenToSeeDoctor:'Any RSI significantly affecting work or daily life needs physiotherapy and occupational health assessment. Specific RSI conditions (carpal tunnel, tendinopathies) require specific treatments. Untreated RSI can become chronic and disabling.', urgency:'medium' },

  /* ── LIFESTYLE: SLEEP & DIGITAL HABITS ── */
  { name:'Poor Sleep Hygiene', aliases:['poor sleep hygiene','bad sleep habits','sleep hygiene problems','irregular sleep','insomnia habits'], emoji:'😴', type:'lifestyle', description:'Behavioral and environmental habits that chronically impair sleep quality and duration. The foundation of most insomnia. Highly responsive to behavioral intervention without the need for medication.', symptoms:['Difficulty falling asleep','Frequent waking during the night','Waking unrefreshed','Daytime fatigue and sleepiness','Difficulty concentrating','Mood changes — irritability and low mood'], causes:['Irregular sleep and wake times','Excessive screen exposure in the hour before bed','Caffeine in the afternoon or evening','Alcohol before bed (disrupts sleep architecture)','Napping during the day','Exercising late at night','Bedroom too warm, light, or noisy'], homecare:['Fixed wake-up time every day — the most powerful sleep regulator','Bedroom only for sleep and sex — not work or screens','Wind-down routine 30-60 minutes before bed — dim lights, no screens','No caffeine after 2pm','Avoid alcohol within 3 hours of sleep','Cool, dark, quiet bedroom environment'], whenToSeeDoctor:'Sleep hygiene changes should be tried for 4-6 weeks before seeking medication. Cognitive Behavioral Therapy for Insomnia (CBT-I) is significantly more effective than sleeping pills for chronic insomnia and should be offered first.', urgency:'low' },

  { name:'Social Media Addiction', aliases:['social media addiction','social media overuse','phone addiction','instagram addiction','tiktok addiction','social media compulsion'], emoji:'📱', type:'lifestyle', description:'A behavioral addiction characterized by compulsive, excessive use of social media platforms that interferes with daily functioning, relationships, work, sleep, and mental health. Associated with depression, anxiety, and loneliness.', symptoms:['Checking social media constantly despite not intending to','Feeling anxious or irritable when unable to access social media','Losing track of time on social media','Social media use interfering with work, study, or sleep','Comparison with others causing low mood or low self-esteem','Using social media as a primary coping mechanism for boredom or distress'], causes:['Variable reward mechanics built into social platforms (similar to slot machines)','Dopamine reinforcement from likes and notifications','Fear of missing out (FOMO)','Social isolation and loneliness using social media as substitute','Adolescent identity formation increasingly mediated through online platforms'], homecare:['Use built-in screen time tracking and daily limits on apps','Turn off all non-essential notifications','Delete social media apps from the home screen — add friction to access','Designate phone-free times — meals, first hour of morning, last hour of night','Replace social media scrolling with specific offline activities — walks, hobbies, in-person socializing'], whenToSeeDoctor:'Social media use causing significant distress, depression, or functional impairment should be assessed by a psychologist or psychiatrist. CBT and Acceptance and Commitment Therapy (ACT) are effective.', urgency:'low' },

  { name:'Screen Addiction', aliases:['screen addiction','screen time addiction','video game addiction','screen overuse','device addiction','screen dependency'], emoji:'📺', type:'lifestyle', description:'Compulsive, excessive use of digital screens — smartphones, computers, gaming, or television — that impairs daily functioning, relationships, sleep, physical activity, and mental health. A growing concern particularly in children and adolescents.', symptoms:['Spending most of leisure time on screens','Losing track of time on devices','Irritability or distress when screen time is restricted','Screens displacing physical activity, sleep, and face-to-face interaction','Declining academic or work performance attributable to screen use','Using screens as the primary mechanism to manage emotions'], causes:['Highly engaging and reward-triggering content design','Easy accessibility of devices at all times','Social reinforcement through multiplayer gaming and social media','Inadequate alternative activities or coping mechanisms','Parental modeling of excessive screen use'], homecare:['Set and enforce daily screen time limits — separate limits for different screen types','Phone-free bedroom at night','Designated screen-free family time','Increase structured offline activities — sports, hobbies, outdoor time','Teach children alternative boredom management skills'], whenToSeeDoctor:'Gaming disorder is recognized by the WHO. Significant impairment in a child or adult from screen use should be assessed by a psychologist. Gaming addiction programs and CBT are effective.', urgency:'low' },

  { name:'Blue Light Damage', aliases:['blue light damage','screen blue light','digital eye strain','blue light eye damage','melatonin blue light'], emoji:'👁️', type:'lifestyle', description:'The adverse effects of excessive exposure to blue-wavelength light emitted from digital screens and LED lighting, including disruption of melatonin production and sleep, as well as digital eye strain. The long-term risk of retinal damage remains under study.', symptoms:['Eye strain, dryness, and irritability after prolonged screen use','Headaches during or after screen use','Blurred vision after screen sessions','Difficulty falling asleep after evening screen use','Disrupted circadian rhythm — feeling alert at bedtime'], causes:['Blue light wavelengths from LED screens, smartphones, and tablets','Evening screen use when melatonin production begins','Prolonged screen use without breaks','Reduced blink rate causing dry eyes'], homecare:['Enable night mode or warm color settings on all devices in the evening','Blue light filter glasses — most helpful for evening use','Follow the 20-20-20 rule — every 20 minutes look 20 feet away for 20 seconds','No screens for 1 hour before bedtime','Increase blink frequency consciously during screen use', 'Use artificial tears for dry eyes from screen use'], whenToSeeDoctor:'Persistent eye strain, headaches, or vision changes from screen use should be assessed by an optometrist. Regular eye examinations are recommended for all screen workers. Current evidence does not confirm permanent retinal damage from typical screen exposure.', urgency:'low' },

  { name:'Circadian Rhythm Disorder', aliases:['circadian rhythm disorder','circadian rhythm disruption','body clock disruption','delayed sleep phase','circadian misalignment'], emoji:'🕐', type:'lifestyle', description:'A disruption of the internal biological clock (circadian rhythm) that regulates the timing of sleep, wakefulness, hormone release, and many other bodily functions. Can be caused by lifestyle factors, shift work, or jet lag.', symptoms:['Inability to fall asleep at a socially normal time (delayed sleep phase)','Waking much earlier than desired (advanced sleep phase)','Excessive daytime sleepiness','Difficulty functioning during conventional working hours','Poor sleep quality despite adequate total duration','Mood disturbance and cognitive impairment'], causes:['Irregular sleep-wake schedule','Excessive evening light exposure (screens and artificial light)','Insufficient morning daylight exposure','Night shift work or rotating shifts','Frequent long-haul travel across time zones','Adolescent biological delay in circadian timing'], homecare:['Consistent sleep and wake times every day — including weekends','Morning bright light exposure — go outside within 30 minutes of waking (the most powerful circadian reset)','Darkness in the evening — dim lights 2 hours before bed, no screens or use blue light filters','Melatonin supplement 0.5-1mg 2 hours before the desired sleep time — for delayed sleep phase'], whenToSeeDoctor:'A sleep specialist can diagnose specific circadian rhythm disorders with a sleep log and actigraphy (activity monitoring). Bright light therapy using a 10,000 lux light box is an effective treatment for delayed sleep phase disorder.', urgency:'low' },

  { name:'Shift Work Disorder', aliases:['shift work disorder','shift worker sleep problems','night shift sleep disorder','rotating shift insomnia','night worker fatigue'], emoji:'🌙', type:'lifestyle', description:'A circadian rhythm disorder affecting people who work non-traditional hours — night shifts, rotating shifts, or early morning shifts. The misalignment between work schedule and biological clock causes chronic sleep deprivation, fatigue, and health risks.', symptoms:['Insomnia or inability to sleep during available daytime sleep time','Excessive sleepiness during work hours at night','Fatigue and reduced alertness at work','Gastrointestinal problems — shift workers have higher rates of IBS and peptic ulcers','Mood disturbance — depression and irritability','Increased risk of cardiovascular disease and metabolic syndrome long-term'], causes:['Night and rotating shift work forcing sleep during biological wake hours','Social and family obligations often limit daytime sleep','Light exposure at night suppresses melatonin','Inability to maintain consistent sleep timing due to shift rotation'], homecare:['Blackout curtains and white noise for daytime sleep','Avoid caffeine after the middle of your shift','Bright light exposure (lightbox) during night shifts helps maintain alertness','On days off — avoid complete reversal to normal schedule if possible (partial adjustment)','Melatonin supplement before daytime sleep may help'], whenToSeeDoctor:'Persistent shift work disorder significantly impairing safety, performance, or health should be assessed by a sleep specialist. Prescribed melatonin and light therapy protocols can help with adaptation.', urgency:'medium' },

  { name:'Jet Lag', aliases:['jet lag','jet lag disorder','time zone syndrome','circadian jet lag','transmeridian travel fatigue'], emoji:'✈️', type:'lifestyle', description:'A temporary circadian rhythm disorder caused by rapid travel across multiple time zones, causing the body\'s internal clock to be out of sync with the local environment. Eastward travel is generally harder to adjust to than westward.', symptoms:['Insomnia at night in the new time zone','Daytime sleepiness','Difficulty concentrating and impaired performance','Irritability and mood changes','Gastrointestinal disturbance — constipation, diarrhea','Headaches','General malaise'], causes:['Rapid crossing of 3 or more time zones','Eastward travel (advancing the clock) is harder than westward travel','Age increases susceptibility','Dehydration from air travel compounds symptoms'], homecare:['Shift sleep to the destination time zone 2-3 days before travel if possible','Outdoor bright light exposure in the morning at the destination helps reset the clock faster','Melatonin 0.5-1mg at bedtime in the new time zone for 2-3 nights','Stay well hydrated during and after the flight','Avoid alcohol on the plane','Short naps of 20-30 minutes help alertness without disrupting nighttime sleep'], whenToSeeDoctor:'Jet lag is a self-resolving condition. Frequent long-haul travellers with significant impairment may benefit from a formal light therapy and melatonin protocol from a sleep specialist.', urgency:'low' },

  /* ── LIFESTYLE: STRESS & HORMONAL ── */
  { name:'Chronic Stress', aliases:['chronic stress','long term stress','persistent stress','stress syndrome','prolonged stress'], emoji:'🧠', type:'lifestyle', description:'A state of ongoing physiological and psychological stress where the body\'s stress response remains chronically activated. Associated with wide-ranging harm to cardiovascular, immune, digestive, and mental health.', symptoms:['Persistent anxiety and feeling overwhelmed','Irritability and mood instability','Fatigue despite adequate sleep','Difficulty concentrating and forgetfulness','Headaches and muscle tension','Digestive complaints — nausea, IBS-like symptoms','Sleep disturbance','Increased susceptibility to illness'], causes:['Chronic work pressure and job insecurity','Relationship and family conflict','Financial stress','Bereavement or caregiving','Chronic illness','Perfectionism and high self-expectation'], homecare:['Regular aerobic exercise — the most physiologically effective stress reducer','Daily mindfulness or meditation practice — even 10 minutes reduces cortisol','Social connection — time with supportive people buffers stress','Prioritize sleep — stress and sleep deprivation are bidirectional','Journaling to externalize and process stressors','Time management and priority setting to reduce overwhelm'], whenToSeeDoctor:'Chronic stress causing significant anxiety, depression, physical symptoms, or burnout should be evaluated by a doctor or psychologist. CBT, Mindfulness-Based Stress Reduction (MBSR), and medication may be indicated.', urgency:'medium' },

  { name:'Adrenal Fatigue', aliases:['adrenal fatigue','adrenal burnout','hpa axis dysregulation','chronic stress fatigue','cortisol exhaustion'], emoji:'⚡', type:'lifestyle', description:'A term used to describe a collection of non-specific symptoms attributed to prolonged stress and overworking of the adrenal glands. Note: adrenal fatigue is not a recognized medical diagnosis — symptoms may reflect HPA axis dysregulation, chronic stress, or underlying conditions such as hypothyroidism or depression.', symptoms:['Persistent fatigue especially in the morning','Salt and sugar cravings','Difficulty getting out of bed','Low energy in the afternoon with a second wind in the evening','Feeling overwhelmed by mild stressors','Mild depression and anxiety','Brain fog'], causes:['Prolonged psychological and physical stress','Poor sleep chronic over time','Overtraining','Nutritional deficiencies'], homecare:['Prioritize 8-9 hours of sleep per night — the most important intervention','Reduce physical and psychological stressors','Balanced diet with adequate protein and complex carbohydrates — avoid excessive caffeine and sugar','Gentle exercise — not high-intensity training while fatigued','Adaptogenic herbs (ashwagandha, rhodiola) — some evidence for stress-related fatigue (consult a doctor before use)'], whenToSeeDoctor:'Significant unexplained fatigue should be medically evaluated to rule out thyroid disease, anemia, diabetes, depression, and true adrenal insufficiency (Addison\'s disease — a real and serious medical condition requiring urgent diagnosis and treatment).', urgency:'medium' },

  { name:'Cortisol Imbalance', aliases:['cortisol imbalance','high cortisol','low cortisol','cortisol dysregulation','stress hormone imbalance'], emoji:'⚡', type:'lifestyle', description:'Abnormal cortisol levels — either chronically elevated (from stress, Cushing\'s syndrome) or insufficient (from adrenal insufficiency, Addison\'s disease). Cortisol is the primary stress hormone and also regulates blood sugar, immune function, and inflammation.', symptoms:['High cortisol: weight gain especially around abdomen and face, hypertension, easy bruising, poor wound healing, anxiety, insomnia, blood sugar elevation','Low cortisol: extreme fatigue, low blood pressure, dizziness on standing, salt cravings, weight loss, nausea, low mood'], causes:['Chronic psychological stress (elevated cortisol)','Cushing\'s syndrome — cortisol overproduction (tumor)','Addison\'s disease — adrenal insufficiency (autoimmune, infection)','Prolonged exogenous steroid use'], homecare:['Stress management practices to normalize stress-induced cortisol elevation','Regular sleep patterns — cortisol peaks naturally in the morning and falls through the day, disrupted by poor sleep','Avoid caffeine excess which amplifies cortisol response','Regular exercise normalizes cortisol rhythm'], whenToSeeDoctor:'Suspected Cushing\'s syndrome or Addison\'s disease requires endocrinologist evaluation — these are serious conditions. Any collapse, severe dizziness, or rapid deterioration in someone with low cortisol requires emergency care.', urgency:'medium' },

  { name:'Hormonal Imbalance', aliases:['hormonal imbalance','hormone disorder','hormone dysregulation','imbalanced hormones','endocrine imbalance'], emoji:'⚖️', type:'lifestyle', description:'A broad term for when one or more hormones are produced in abnormal quantities. Hormones regulate virtually every process in the body. Imbalances cause a wide range of symptoms depending on which hormones are affected.', symptoms:['Fatigue and low energy','Weight changes','Mood swings and irritability','Sleep disturbance','Low libido','Irregular periods or absent periods (women)','Skin and hair changes','Brain fog'], causes:['Stress and elevated cortisol','Thyroid dysfunction (hypothyroidism or hyperthyroidism)','Polycystic ovary syndrome (PCOS)','Menopause and perimenopause','Insulin resistance and diabetes','Pituitary or adrenal tumors','Environmental endocrine disruptors'], homecare:['Identify and manage stress — stress disrupts multiple hormonal axes','Regular exercise and healthy weight — adipose tissue produces estrogen and disrupts hormonal balance','Balanced diet with adequate protein, healthy fats, and fiber','Minimize exposure to endocrine disruptors — plastics (BPA), certain pesticides, parabens in cosmetics','Adequate sleep — hormone regulation occurs largely during sleep'], whenToSeeDoctor:'Suspected hormonal imbalance needs blood hormone testing (TSH, FSH, LH, estrogen, testosterone, prolactin, cortisol depending on symptoms). An endocrinologist or gynecologist can diagnose and treat specific hormone disorders.', urgency:'medium' },

  { name:'Low Testosterone', aliases:['low testosterone','hypogonadism','low t','testosterone deficiency','male hypogonadism','androgen deficiency'], emoji:'⚕️', type:'lifestyle', description:'Below-normal testosterone levels in men, causing a range of physical and psychological symptoms. Testosterone is essential for muscle mass, bone density, energy, libido, and mood. Can be primary (testicular) or secondary (pituitary/hypothalamic) in origin.', symptoms:['Reduced sex drive and libido','Erectile dysfunction','Fatigue and low energy','Reduced muscle mass and increased body fat','Mood changes — depression, irritability, difficulty concentrating','Reduced body and facial hair','Osteoporosis in long-standing cases','Hot flushes in some men'], causes:['Primary hypogonadism: testicular damage from injury, infection (mumps orchitis), chemotherapy, or genetic conditions','Secondary hypogonadism: pituitary or hypothalamic dysfunction','Obesity (converts testosterone to estrogen)','Chronic stress and sleep deprivation','Age-related decline (andropause)','Certain medications (opioids, anabolic steroids)'], homecare:['Maintain a healthy weight — obesity significantly lowers testosterone','Regular resistance and high-intensity exercise elevates testosterone','Adequate sleep — testosterone peaks during deep sleep','Reduce chronic stress — cortisol suppresses testosterone','Avoid excessive alcohol'], whenToSeeDoctor:'Morning serum testosterone and LH levels are required for diagnosis. An endocrinologist or urologist can assess and discuss testosterone replacement therapy (TRT) — benefits and risks require careful discussion.', urgency:'medium' },

  { name:'High Estrogen', aliases:['high estrogen','estrogen dominance','hyperestrogenism','excess estrogen','estrogen dominance syndrome'], emoji:'⚖️', type:'lifestyle', description:'Elevated estrogen levels relative to other hormones, particularly progesterone, causing a range of symptoms in both women and men. Excess estrogen promotes certain hormone-sensitive conditions.', symptoms:['Women: irregular or heavy periods, bloating, breast tenderness, mood swings, low libido, weight gain around hips and thighs, PMS','Men: gynecomastia (breast tissue growth), erectile dysfunction, infertility, weight gain, fatigue'], causes:['Obesity (adipose tissue converts androgens to estrogen)','Environmental estrogens — BPA in plastics, certain pesticides','Excess alcohol (impairs estrogen metabolism in the liver)','Liver dysfunction reducing estrogen clearance','Certain medications (oral contraceptives, HRT)','Polycystic ovary syndrome'], homecare:['Maintain a healthy weight — reducing adipose tissue reduces estrogen production','Eat cruciferous vegetables — broccoli, cauliflower, Brussels sprouts contain indole-3-carbinol which supports estrogen metabolism','Reduce alcohol','Minimize BPA exposure — avoid heating food in plastic containers','Increase dietary fiber to promote estrogen excretion'], whenToSeeDoctor:'Hormone levels including estradiol and progesterone should be measured at the appropriate time of the menstrual cycle. A gynecologist or endocrinologist can diagnose and treat estrogen dominance and associated conditions.', urgency:'low' },

  { name:'Andropause', aliases:['andropause','male menopause','late onset hypogonadism','men aging hormones','male hormone decline'], emoji:'⚕️', type:'lifestyle', description:'The gradual decline in testosterone and other hormones in middle-aged men, typically beginning in the 40s to 50s. Unlike female menopause, andropause is a slow, progressive process without a clear end point.', symptoms:['Fatigue and reduced energy','Reduced sex drive','Erectile dysfunction','Mood changes — irritability, depression','Reduced muscle mass and increased abdominal fat','Difficulty concentrating and memory changes','Sleep disturbances','Reduced bone density'], causes:['Age-related decline in testosterone production','Leydig cell (testosterone-producing) decline with age','Contributing factors: obesity, sedentary lifestyle, chronic stress, poor sleep, alcohol'], homecare:['Regular resistance exercise — the most effective lifestyle intervention for maintaining testosterone levels','Maintain a healthy weight','Adequate sleep — testosterone is produced during sleep','Reduce stress and alcohol','Eat a balanced diet with adequate zinc and healthy fats — both support testosterone production'], whenToSeeDoctor:'Serum testosterone measurement (morning sample) and LH/FSH levels establish the diagnosis. An endocrinologist or urologist can discuss testosterone replacement therapy (TRT) — a decision that requires careful individual risk-benefit assessment.', urgency:'low' },

  /* ── LIFESTYLE: WOMEN\'S HEALTH ── */
  { name:'Menopause', aliases:['menopause','change of life','climacteric','natural menopause','postmenopause'], emoji:'🌸', type:'lifestyle', description:'The natural biological process marking the permanent end of menstrual cycles, diagnosed after 12 consecutive months without a period. Occurs typically between age 45-55. The transition affects multiple body systems.', symptoms:['Hot flushes — sudden sensations of heat, typically in face and chest','Night sweats','Irregular periods leading up to menopause','Vaginal dryness and discomfort during sex','Mood changes — irritability, anxiety, low mood','Sleep disturbance','Cognitive changes — difficulty concentrating','Urinary symptoms'], causes:['Natural depletion of ovarian follicles with aging','Surgical menopause after oophorectomy (ovary removal)','Premature ovarian insufficiency in some women'], homecare:['Dress in layers and use a fan for hot flushes','Cool bedroom and breathable bedding for night sweats','Regular exercise reduces hot flush frequency and supports mood and bone health','Pelvic floor exercises for urinary symptoms','Vaginal moisturizers and lubricants for dryness (non-hormonal options)','Mind-body approaches — mindfulness, CBT effective for menopausal symptoms'], whenToSeeDoctor:'A doctor can discuss and prescribe hormone replacement therapy (HRT) — the most effective treatment for menopausal symptoms and bone protection. HRT benefits and risks should be individually discussed. Gynecologist or GP with menopause expertise is recommended.', urgency:'low' },

  { name:'Perimenopause', aliases:['perimenopause','menopausal transition','premenopause','before menopause','perimenopause symptoms'], emoji:'🌸', type:'lifestyle', description:'The transitional phase leading up to menopause, typically beginning in the mid-40s and lasting 4-8 years. Characterized by irregular cycles and fluctuating hormone levels causing a variety of symptoms.', symptoms:['Irregular periods — longer, shorter, heavier, or lighter than usual','Hot flushes and night sweats','Mood swings and increased anxiety','Sleep disturbances','Fatigue','Changes in libido','Vaginal dryness beginning','Brain fog and difficulty concentrating'], causes:['Declining and fluctuating estrogen and progesterone as ovarian reserve decreases','Irregular ovulation causing irregular cycles','The transition can begin in the early 40s or even late 30s'], homecare:['Symptom tracking with a diary to identify patterns','Regular exercise for mood, sleep, and weight management','Reduce alcohol and caffeine which worsen hot flushes','Good sleep hygiene — night sweats disrupt sleep significantly','Mind-body practices for anxiety and mood'], whenToSeeDoctor:'A doctor can confirm perimenopause with clinical assessment (FSH levels vary widely and are not always diagnostic). HRT can be started in perimenopause to manage symptoms and protect bone density. Abnormal bleeding should always be evaluated.', urgency:'low' },

  { name:'Early Menopause', aliases:['early menopause','premature menopause','menopause before 45','menopause 40s'], emoji:'🌸', type:'lifestyle', description:'Menopause occurring before age 45. Earlier than the typical range, increasing the risk of cardiovascular disease, osteoporosis, and cognitive decline compared with naturally timed menopause due to longer hormone deficiency.', symptoms:['Cessation or irregularity of periods before age 45','Hot flushes and night sweats at a younger age than expected','Mood changes and anxiety','Sleep disturbance','Vaginal dryness','Reduced fertility'], causes:['Accelerated natural depletion of ovarian reserve','Autoimmune conditions attacking the ovaries','Cancer treatment — chemotherapy and radiation','Surgical removal of ovaries','Genetic factors — family history of early menopause'], homecare:['HRT is strongly recommended until the average age of natural menopause (51) to protect the heart and bones — discuss with a doctor','Regular weight-bearing exercise for bone health','Calcium and vitamin D supplementation','Psychological support — early menopause can be emotionally distressing especially regarding fertility'], whenToSeeDoctor:'Any woman under 45 who stops menstruating for more than 3 months should be urgently evaluated by a gynecologist or endocrinologist. FSH levels confirm the diagnosis. Fertility specialists should be consulted if pregnancy is desired.', urgency:'medium' },

  { name:'Premature Ovarian Failure', aliases:['premature ovarian failure','poi','premature ovarian insufficiency','early ovarian failure','ovarian insufficiency'], emoji:'🌸', type:'lifestyle', description:'A condition where the ovaries stop functioning normally before age 40, causing low estrogen and infertility. Affects 1 in 100 women under 40 and 1 in 1000 women under 30. Significant health impacts if untreated.', symptoms:['Irregular or absent periods before age 40','Hot flushes and night sweats','Vaginal dryness','Difficulty conceiving (infertility)','Mood changes — anxiety and depression','Reduced bone density','Fatigue'], causes:['Autoimmune destruction of ovarian tissue (most common identifiable cause)','Chromosomal abnormalities (Turner syndrome, fragile X premutation)','Cancer treatment — chemotherapy and pelvic radiation','Family history of POI','Unknown cause in many cases'], homecare:['HRT until natural menopause age (51) is essential to protect cardiovascular, bone, and cognitive health','Regular weight-bearing exercise','Calcium, vitamin D, and other supplements as advised','Psychological support — the diagnosis profoundly affects fertility plans and identity'], whenToSeeDoctor:'POI requires specialist evaluation by a reproductive endocrinologist. Genetic testing, autoimmune screening, and bone density testing are part of the workup. HRT is essential and should be started promptly. Egg donation may be needed for pregnancy.', urgency:'medium' },

  { name:'Pelvic Floor Dysfunction', aliases:['pelvic floor dysfunction','pelvic floor weakness','pelvic floor disorder','pelvic dysfunction','weak pelvic floor'], emoji:'🏥', type:'lifestyle', description:'A condition where the pelvic floor muscles and connective tissue fail to work properly — either too weak (causing prolapse and incontinence) or too tight (causing pain with intercourse, difficulty urinating or defecating).', symptoms:['Urinary leakage with coughing, sneezing, or exercise (stress incontinence)','Urgency to urinate and leakage before reaching the toilet','Feeling of pressure or heaviness in the pelvic area (prolapse)','Pain with intercourse (dyspareunia)','Difficulty emptying the bladder or bowel completely','Chronic pelvic pain'], causes:['Pregnancy and vaginal childbirth (most common cause in women)','Chronic constipation and straining','Obesity','Menopause (estrogen loss weakens pelvic tissues)','Chronic heavy lifting','Age'], homecare:['Pelvic floor muscle exercises (Kegel exercises) — must be performed correctly, ideally guided by a pelvic floor physiotherapist','High-fiber diet to prevent straining with bowel movements','Manage body weight','Avoid high-impact exercise until the pelvic floor is rehabilitated','Bladder training for urge incontinence'], whenToSeeDoctor:'A pelvic floor physiotherapist is the first line treatment and is highly effective. A gynecologist or urogynecologist should assess for prolapse or severe incontinence. Pelvic floor dysfunction is very treatable — it should not be accepted as inevitable.', urgency:'medium' },

  { name:'Urinary Incontinence', aliases:['urinary incontinence','bladder leakage','leaking urine','stress incontinence','urge incontinence','overactive bladder leakage'], emoji:'🏥', type:'lifestyle', description:'Involuntary loss of urine. Extremely common — affects 1 in 3 women at some time in their lives and many men, particularly after prostate treatment. Significantly impacts quality of life and social participation.', symptoms:['Leaking urine when coughing, sneezing, laughing, or exercising (stress incontinence)','Sudden urgent need to urinate with leakage (urge incontinence)','Frequent urination (more than 8 times in 24 hours)','Waking repeatedly at night to urinate','Feeling the bladder does not empty completely'], causes:['Weak pelvic floor muscles (pregnancy, childbirth, age)','Menopause — estrogen loss weakens urethral and pelvic tissues','Prostate problems or surgery in men','Obesity','Overactive bladder — abnormal bladder contractions','Chronic constipation compressing the bladder'], homecare:['Pelvic floor exercises (Kegel exercises) — the primary treatment for stress incontinence','Bladder training — gradually extending time between toilet visits for urge incontinence','Maintain a healthy weight','Reduce caffeine and alcohol which irritate the bladder','Timed voiding — scheduled toilet trips prevent urgency episodes'], whenToSeeDoctor:'Urinary incontinence should not be accepted as normal or inevitable. A doctor can identify the type and cause. A pelvic floor physiotherapist provides first-line treatment. Specialist referral for persistent or severe incontinence.', urgency:'medium' },

  { name:'Overactive Bladder', aliases:['overactive bladder','oab','urge incontinence','bladder urgency','urgency frequency syndrome'], emoji:'🏥', type:'lifestyle', description:'A syndrome of urinary urgency (sudden compelling desire to urinate that is difficult to defer) usually accompanied by frequency and nocturia, with or without urge incontinence. Very common — affects 1 in 6 adults.', symptoms:['Sudden, urgent need to urinate','Difficulty deferring the urge to urinate','Frequent urination — more than 8 times in 24 hours','Waking 2 or more times per night to urinate (nocturia)','Urge incontinence — leaking before reaching the toilet in some people'], causes:['Involuntary or overactive detrusor muscle contractions','Aging','Neurological conditions — stroke, Parkinson\'s, MS','Bladder outlet obstruction in men from enlarged prostate','Bladder irritants — caffeine, alcohol, spicy foods','Chronic UTIs or bladder stones'], homecare:['Bladder training — gradually extending time between toilet trips','Reduce caffeine, alcohol, and spicy foods that irritate the bladder','Pelvic floor exercises to suppress urge','Timed voiding — schedule toilet trips to prevent urgency','Maintain a healthy weight','Double voiding — after urinating, wait and try again'], whenToSeeDoctor:'An overactive bladder significantly affecting quality of life should be assessed by a doctor. Bladder diary tracking helps. Anticholinergic medications or mirabegron can be prescribed if lifestyle measures are insufficient. Botox injections to the bladder are used for refractory cases.', urgency:'medium' },

  /* ── LIFESTYLE: HAIR, SKIN & APPEARANCE ── */
  { name:'Male Pattern Baldness', aliases:['male pattern baldness','androgenetic alopecia male','mpb','male hair loss','testosterone hair loss','receding hairline'], emoji:'💈', type:'lifestyle', description:'The most common type of hair loss in men, caused by sensitivity of hair follicles to dihydrotestosterone (DHT). Follows a predictable pattern of recession at the temples and crown. Affects 50% of men by age 50.', symptoms:['Receding hairline starting at the temples','Thinning at the crown (vertex)','Progressive merging of temple and crown thinning','Hair miniaturization — hairs become finer before falling out','Eventual complete baldness in severe cases'], causes:['Genetic predisposition (inherited from both parents)','DHT (dihydrotestosterone) sensitivity causing hair follicle miniaturization','Androgen hormones — primarily testosterone and DHT'], homecare:['Minoxidil (topical solution or foam) — applied daily to the scalp, delays further loss and promotes some regrowth','Finasteride (tablet, prescription only) — 5-alpha reductase inhibitor reducing DHT, most effective in younger men with earlier stage loss','Avoid tight hairstyles and harsh chemical treatments that may worsen hair fragility','Low-level laser therapy devices — some evidence for slowing loss'], whenToSeeDoctor:'A dermatologist can confirm the diagnosis and discuss all treatment options including medical therapies, PRP (platelet-rich plasma) injections, and hair transplantation surgery. Starting treatment early maximizes results.', urgency:'low' },

  { name:'Female Pattern Hair Loss', aliases:['female pattern hair loss','androgenetic alopecia female','fphl','female hair thinning','diffuse hair loss women'], emoji:'💆', type:'lifestyle', description:'The most common form of hair loss in women, characterized by diffuse thinning across the top of the scalp while the frontal hairline is usually preserved. Unlike men, women rarely develop complete baldness.', symptoms:['Widening of the central parting','Thinning at the top and crown of the scalp','Preserved frontal hairline','Hair feels thinner and less voluminous','More hair on the brush or in the shower than previously'], causes:['Genetic predisposition','Androgen sensitivity of hair follicles','Hormonal changes — menopause, post-pregnancy, PCOS','Nutritional deficiencies — iron, ferritin, biotin, zinc, protein'], homecare:['Minoxidil 2% or 5% (topical) — applied to the scalp daily, the main evidence-based treatment','Ensure adequate ferritin, iron, zinc, and biotin through diet or supplementation if deficient','Gentle hair care — avoid tight hairstyles, excessive heat styling, and harsh chemicals','Reduce stress — major stress can trigger telogen effluvium (temporary excessive shedding)'], whenToSeeDoctor:'Female hair loss should be evaluated by a dermatologist to exclude treatable causes — thyroid disease, iron deficiency anemia, PCOS, and autoimmune alopecia. Blood tests are essential before starting treatment.', urgency:'low' },

  { name:'Alopecia Areata', aliases:['alopecia areata','patchy hair loss','alopecia','autoimmune hair loss','bald patches'], emoji:'💆', type:'lifestyle', description:'An autoimmune condition causing patchy, non-scarring hair loss on the scalp, face, or body. The immune system attacks hair follicles. Usually reversible, but highly unpredictable — some people experience full recovery, others develop extensive loss.', symptoms:['Round or oval patches of sudden hair loss on the scalp','Patches can occur on the beard, eyebrows, eyelashes, or body','Exclamation mark hairs at the edge of patches','Nail changes — pitting, ridging in some cases','Alopecia totalis: complete scalp hair loss','Alopecia universalis: complete body hair loss'], causes:['Autoimmune T-cell attack on hair follicles','Genetic predisposition','Associated with thyroid disease, vitiligo, and other autoimmune conditions','Stress may trigger initial episodes'], homecare:['Topical or intralesional corticosteroid treatment as prescribed — the main treatment for patchy disease','Scalp massage and camouflage cosmetics for confidence while waiting for regrowth','Protect the scalp (sunscreen, headwear) if significant hair loss','Support groups — alopecia can profoundly affect self-esteem'], whenToSeeDoctor:'A dermatologist should assess and confirm the diagnosis. Newer JAK inhibitor medications (baricitinib, ritlecitinib) are now approved for severe alopecia areata and show excellent results. Thyroid function and other autoimmune tests should be checked.', urgency:'low' },

  { name:'Telogen Effluvium', aliases:['telogen effluvium','stress hair loss','excessive hair shedding','diffuse hair shedding','post illness hair loss'], emoji:'💆', type:'lifestyle', description:'A temporary form of hair loss where large numbers of hairs shift prematurely into the shedding (telogen) phase, usually triggered by a stressful event 2-4 months prior. The most common cause of sudden diffuse hair shedding.', symptoms:['Noticeable increase in hair shedding — especially when washing, brushing, or on the pillow','Diffuse thinning across the entire scalp rather than one area','Hair loss peaks 2-4 months after the trigger event','Most cases resolve within 6-9 months without treatment'], causes:['Physical shock — major surgery, significant blood loss, severe illness, crash dieting','Emotional shock — bereavement, extreme stress','Hormonal changes — postpartum (very common after childbirth), stopping oral contraceptives','Nutritional deficiencies — iron deficiency, low protein','Thyroid disease'], homecare:['Identify and address the triggering cause — most cases resolve spontaneously once the trigger resolves','Ensure adequate iron (ferritin ideally above 70 ng/mL), protein, and biotin intake','Gentle hair care — avoid excess heat, tight hairstyles, and harsh treatments','Be patient — regrowth takes 6-12 months'], whenToSeeDoctor:'A dermatologist or GP can confirm telogen effluvium with a pull test and blood tests (ferritin, thyroid, zinc, B12). Treatment focuses on addressing the underlying cause. Chronic telogen effluvium lasting more than 6 months needs thorough investigation.', urgency:'low' },

  { name:'Scalp Psoriasis', aliases:['scalp psoriasis','psoriasis scalp','dandruff psoriasis','scalp plaques','sebopsoriasis'], emoji:'🔴', type:'lifestyle', description:'Psoriasis affecting the scalp, causing raised, reddish, scaly patches that may extend beyond the hairline onto the forehead, back of the neck, or behind the ears. Can cause significant itching and is often mistaken for severe dandruff.', symptoms:['Thick, silver-white scales on the scalp','Reddish, raised plaques beneath the scales','Itching and dryness of the scalp','Flaking on hair and shoulders','Temporary hair loss from scratching (grows back after treatment)','Bleeding when scales are removed'], causes:['Autoimmune acceleration of skin cell turnover','Genetic predisposition','Triggers: stress, scalp injury (Koebner phenomenon), certain infections, medications'], homecare:['Medicated shampoos containing coal tar, salicylic acid, or ketoconazole','Topical corticosteroid solutions or foams applied to the scalp as prescribed','Gently remove scales after softening with oil before shampooing','Avoid scratching — causes infection and worsens lesions','Manage stress — a major trigger for psoriasis flares'], whenToSeeDoctor:'A dermatologist can confirm the diagnosis and prescribe appropriate topical treatments. Severe or extensive scalp psoriasis may need phototherapy or systemic treatments including biologics.', urgency:'low' },

  { name:'Chronic Acne', aliases:['chronic acne','persistent acne','adult acne','acne vulgaris chronic','hormonal acne'], emoji:'🔴', type:'lifestyle', description:'Persistent acne lasting more than 6 months or into adulthood, characterized by comedones, papules, pustules, and in severe cases, cysts and nodules. Caused by a combination of sebum production, bacteria, and inflammation.', symptoms:['Whiteheads and blackheads (comedones)','Red, inflamed pimples (papules and pustules)','Painful cysts and nodules in severe cases','Oily skin','Post-inflammatory hyperpigmentation (dark marks after spots)','Scarring in severe or untreated cases'], causes:['Excess sebum production — influenced by androgens','Propionibacterium acnes (C. acnes) bacteria proliferation','Follicular hyperkeratinization (blocked pores)','Hormonal fluctuations — menstrual cycle, PCOS, puberty','Dietary factors — high glycemic index diet and dairy may worsen in some people','Stress increases androgen production'], homecare:['Twice daily gentle cleansing with a non-soap face wash','Non-comedogenic (won\'t block pores) moisturizer and sunscreen','Avoid picking or squeezing — worsens scarring and infection','Topical benzoyl peroxide or salicylic acid products (over-the-counter)','Low-glycemic diet may help some people','Manage stress'], whenToSeeDoctor:'Moderate or severe acne, acne not responding to over-the-counter products, or acne causing scarring needs dermatologist assessment. Prescription options include topical and oral antibiotics, retinoids, combined oral contraceptives (for women), and isotretinoin for severe cases.', urgency:'low' },

  { name:'Rosacea', aliases:['rosacea','facial redness','couperose','rosacea face','skin redness disorder'], emoji:'🔴', type:'lifestyle', description:'A chronic inflammatory skin condition causing persistent facial redness, visible blood vessels, and sometimes acne-like breakouts. Usually affects the nose, cheeks, forehead, and chin. Flares are triggered by various stimuli.', symptoms:['Persistent facial redness — especially across the nose and cheeks','Flushing easily with heat, alcohol, spicy food, or emotion','Visible dilated blood vessels on the face (telangiectasia)','Bumps and pimples (papulopustular rosacea)','Burning or stinging sensation on the face','In severe cases: rhinophyma (bulbous red nose)','Eye irritation and redness (ocular rosacea)'], causes:['Genetics — fair-skinned people of Northern European ancestry are most affected','Abnormal immune and neurovascular responses','Demodex mite proliferation on the skin','Triggers: sun exposure, heat, spicy food, alcohol, exercise, stress, certain skin products'], homecare:['Identify and avoid personal triggers','Use a bland, fragrance-free gentle cleanser and moisturizer','Daily broad-spectrum SPF 30+ sunscreen — sun is a major trigger','Avoid hot drinks, spicy foods, and alcohol if these trigger flushes','Cooling face mists or fans during flares','Green-tinted primer under makeup can camouflage redness'], whenToSeeDoctor:'A dermatologist can diagnose rosacea and prescribe topical medications (metronidazole, azelaic acid, brimonidine) and oral antibiotics. Vascular laser therapy targets persistent redness and broken vessels.', urgency:'low' },

  { name:'Hyperpigmentation', aliases:['hyperpigmentation','dark spots','skin darkening','melasma','post inflammatory hyperpigmentation','dark skin patches'], emoji:'🔴', type:'lifestyle', description:'Patches of skin that become darker than the surrounding skin due to excess melanin production. Common, harmless, and often cosmetically distressing. Multiple causes and types require different management approaches.', symptoms:['Flat, dark patches or spots on the skin','More noticeable on sun-exposed areas','May follow acne spots (post-inflammatory hyperpigmentation)','Butterfly-shaped darkening across cheeks and nose in melasma','Worsens with sun exposure'], causes:['Sun exposure — the primary driver of most hyperpigmentation','Post-inflammatory response after acne, eczema, or injury','Hormonal changes — melasma from pregnancy or oral contraceptives','Certain medications (NSAIDs, tetracyclines, chemotherapy)','Addison\'s disease (systemic cause requiring medical evaluation)'], homecare:['Daily broad-spectrum SPF 50+ sunscreen — the most important treatment to prevent worsening','Physical sun avoidance and protective clothing','Topical vitamin C serum (antioxidant brightening)','Niacinamide (vitamin B3) — reduces melanin transfer to skin cells','Topical ingredients: alpha arbutin, kojic acid, azelaic acid — evidence-based brightening agents'], whenToSeeDoctor:'A dermatologist can prescribe hydroquinone (prescription in many countries), tretinoin, or combination creams for significant hyperpigmentation. Chemical peels and laser treatments are options for stubborn cases.', urgency:'low' },

  { name:'Melasma', aliases:['melasma','pregnancy mask','chloasma','hormonal skin darkening','facial melasma'], emoji:'🔴', type:'lifestyle', description:'A common skin condition causing symmetrical brown or grey-brown patches, primarily on the face — cheeks, bridge of the nose, forehead, and upper lip. Strongly associated with hormonal changes and sun exposure.', symptoms:['Symmetrical brown or grey-brown patches on the face','Primarily affects cheeks, forehead, upper lip, chin, and nose bridge','Patches do not cause physical symptoms (no pain or itching)','Worsens in summer and with sun exposure','May fade in winter and during periods of less sun exposure'], causes:['Hormonal triggers — pregnancy (\"mask of pregnancy\"), oral contraceptives, HRT','UV radiation stimulating melanocytes','Genetic predisposition — more common in darker skin tones and in women','Thyroid disease (associated factor)'], homecare:['Strict sun protection is the single most critical step — SPF 50+ broad-spectrum sunscreen applied every 2 hours during sun exposure','Wide-brimmed hat for outdoor sun protection','Topical vitamin C, niacinamide, and azelaic acid for gentle brightening','Consider stopping or changing oral contraceptives if they appear to be a trigger'], whenToSeeDoctor:'A dermatologist can prescribe triple combination creams (hydroquinone, tretinoin, corticosteroid) which are highly effective. Chemical peels and laser treatments (with caution in darker skin tones) are additional options.', urgency:'low' },

  { name:'Stretch Marks', aliases:['stretch marks','striae','striae distensae','pregnancy stretch marks','growth stretch marks'], emoji:'🔴', type:'lifestyle', description:'Lines or streaks on the skin that occur when the skin is rapidly stretched, causing the dermis to tear. Initially appear red, purple, or pink and fade to silver or white over time. Very common — affect up to 90% of pregnant women.', symptoms:['Linear streaks or bands on the skin','Initially red, pink, purple, or dark brown','Fade to silver, white, or flesh-colored over time','Most common on abdomen, breasts, upper arms, thighs, hips, and buttocks','May feel slightly raised or itchy when new'], causes:['Rapid skin stretching — pregnancy, rapid growth spurts, rapid weight gain or loss','Corticosteroid use (thins the skin)','Cushing\'s syndrome (excess cortisol)','Genetic predisposition — family history increases risk'], homecare:['Moisturize skin regularly during pregnancy and rapid growth — may reduce severity (evidence is mixed)','Gradual weight gain during pregnancy reduces skin stretching speed','Maintain stable weight — avoid rapid yo-yo weight changes','Topical vitamin C, hyaluronic acid, and retinoids may improve appearance of new stretch marks'], whenToSeeDoctor:'Stretch marks are a cosmetic concern, not a medical problem. A dermatologist can discuss treatment options including topical retinoids, microneedling, laser therapy, and radiofrequency — most effective on newer, still-pink stretch marks.', urgency:'low' },

  { name:'Cellulite', aliases:['cellulite','orange peel skin','dimpled skin','cellulitis skin dimples','gynoid lipodystrophy'], emoji:'🔴', type:'lifestyle', description:'The dimpled, lumpy appearance of skin caused by fat pushing through fibrous connective tissue bands beneath the skin. Affects up to 90% of women after puberty and is not a medical condition. Influenced by genetics, hormones, and lifestyle.', symptoms:['Dimpled or lumpy skin resembling orange peel or cottage cheese','Most commonly on buttocks, thighs, hips, and abdomen','Worse in areas of higher fat accumulation','Not associated with pain or medical risk'], causes:['Fibrous connective tissue bands (septa) pulling skin downward while fat pushes upward','Genetic predisposition — strongly hereditary','Female sex — estrogen promotes fat storage in areas prone to cellulite','Sedentary lifestyle and excess body fat worsen appearance','Thin skin (with aging) makes it more visible'], homecare:['Regular exercise — reduces overall body fat and improves skin tone','Strength training builds muscle under the skin, improving the surface appearance','Maintain a healthy body weight','Stay well hydrated','Dry body brushing and massage — may temporarily improve appearance by stimulating circulation'], whenToSeeDoctor:'Cellulite is a cosmetic concern. A dermatologist can discuss evidence-based treatments — subcision, acoustic wave therapy, and topical treatments. No treatment completely eliminates cellulite but some reduce its appearance.', urgency:'low' },

  /* ── LIFESTYLE: CIRCULATION & INFLAMMATION ── */
  { name:'Poor Circulation', aliases:['poor circulation','impaired circulation','reduced blood flow','circulation problems','peripheral circulation problems'], emoji:'🫀', type:'lifestyle', description:'Reduced blood flow to various parts of the body, particularly the extremities. Not a disease itself but a sign of underlying conditions affecting the blood vessels, heart, or blood. Causes a range of symptoms and warrants investigation.', symptoms:['Cold hands and feet','Numbness or tingling in extremities','Leg pain or cramps when walking','Skin discoloration — pale, blue, or mottled skin','Swelling in hands and feet','Slow-healing wounds on the feet or legs','Fatigue'], causes:['Atherosclerosis (plaque in arteries)','Diabetes damaging blood vessels','Peripheral artery disease','Blood clots','Poor cardiac output (heart failure)','Prolonged sitting or standing','Smoking','Raynaud\'s phenomenon'], homecare:['Regular walking and exercise to stimulate circulation','Quit smoking — the most important step for vascular health','Elevate legs when sitting for long periods','Wear compression stockings if recommended','Stay well hydrated','Avoid prolonged sitting — move every 30 minutes','Manage underlying conditions — blood pressure, cholesterol, blood sugar'], whenToSeeDoctor:'Poor circulation with painful leg cramps on walking, cold blue extremities, non-healing foot wounds, or sudden-onset symptoms needs urgent medical evaluation to identify and treat the underlying vascular cause.', urgency:'medium' },

  { name:'Cold Extremities', aliases:['cold extremities','cold hands and feet','cold fingers','cold toes','poor peripheral blood flow'], emoji:'❄️', type:'lifestyle', description:'Persistently cold hands, feet, fingers, or toes even in warm environments. Can be a normal variation or a sign of reduced peripheral circulation, Raynaud\'s, thyroid disease, anemia, or vascular disease.', symptoms:['Hands and feet feeling cold to touch even in a warm room','Numbness or tingling accompanying the cold sensation','Blanching (turning white) of fingers in the cold (suggests Raynaud\'s)','Poor peripheral circulation signs — pale or bluish discoloration','Associated fatigue or other systemic symptoms suggesting thyroid disease'], causes:['Normal variation — particularly common in women','Raynaud\'s phenomenon','Hypothyroidism','Anemia — reduced oxygen-carrying capacity of blood','Peripheral artery disease','Diabetes','Poor cardiac output','Smoking'], homecare:['Dress in layers and warm the core body first — warm core improves peripheral circulation','Keep hands and feet protected in the cold — mittens are warmer than gloves','Gentle regular exercise — improves peripheral circulation over time','Quit smoking','Stay well hydrated'], whenToSeeDoctor:'Persistent cold extremities should be evaluated with thyroid function tests, full blood count, and blood sugar. A vascular assessment may be needed. Color changes (white or blue) of the fingers with cold warrant assessment for Raynaud\'s and connective tissue disease.', urgency:'low' },

  { name:'Raynaud\'s Phenomenon', aliases:['raynaud\'s phenomenon','raynaud disease lifestyle','vasospasm cold','fingers white blue cold','raynaud syndrome'], emoji:'❄️', type:'lifestyle', description:'Episodes of reduced blood flow to the fingers and toes (and sometimes nose and ears) triggered by cold or emotional stress, causing the affected areas to turn white then blue then red as blood flow returns. Primary Raynaud\'s has no underlying disease.', symptoms:['Fingers or toes turning white (pallor) then blue (cyanosis) then red (reactive hyperemia) in sequence','Triggered by exposure to cold or emotional stress','Numbness and coldness during the white and blue phases','Pain or tingling as blood flow returns (red phase)','Episodes last minutes to an hour'], causes:['Primary Raynaud\'s: overreactive blood vessel response to cold or stress — no underlying disease','Secondary Raynaud\'s: associated with connective tissue diseases (scleroderma, lupus), arterial disease, or certain medications'], homecare:['Keep the whole body warm — core warmth reduces peripheral vasospasm','Wear mittens and warm socks in cold environments','Avoid cold water immersion of hands','Quit smoking — nicotine causes vasoconstriction','Reduce caffeine','Manage stress','Chemical hand warmers for cold environments'], whenToSeeDoctor:'All new Raynaud\'s cases should be evaluated to rule out secondary causes (blood tests for ANA, ESR, CRP, and nailfold capillaroscopy). Secondary Raynaud\'s with sores or ulcers needs urgent specialist treatment. Medications (calcium channel blockers) reduce attack frequency in severe cases.', urgency:'low' },

  { name:'Chronic Inflammation', aliases:['chronic inflammation','systemic inflammation','low grade inflammation','inflammatory state','chronic inflammatory condition'], emoji:'🔥', type:'lifestyle', description:'Persistent, low-grade activation of the immune and inflammatory system throughout the body, contributing to aging, cardiovascular disease, type 2 diabetes, cancer, Alzheimer\'s, and many other chronic diseases. Often clinically silent until disease appears.', symptoms:['Often no direct symptoms in early stages','Fatigue and low energy','Joint and muscle aches','Frequent minor illnesses','Brain fog and cognitive fatigue','Weight gain despite normal diet','Raised inflammatory markers on blood tests (CRP, ESR)'], causes:['Obesity especially central adiposity — fat tissue releases inflammatory cytokines','Ultra-processed food diet high in refined sugar and trans fats','Physical inactivity','Chronic stress','Inadequate sleep','Smoking','Gut microbiome imbalance (dysbiosis)','Chronic unresolved infections or autoimmune activity'], homecare:['Anti-inflammatory diet — Mediterranean diet (olive oil, fish, vegetables, legumes, whole grains)','Regular moderate exercise — reduces CRP and inflammatory cytokines','Lose excess abdominal fat','Quit smoking','Sleep 7-9 hours per night','Manage chronic stress','Limit alcohol and ultra-processed foods'], whenToSeeDoctor:'High-sensitivity CRP (hsCRP) is a blood marker of systemic inflammation. A doctor can investigate causes and assess cardiovascular risk. Persistent raised inflammatory markers warrant specialist evaluation to exclude autoimmune disease or malignancy.', urgency:'medium' },

  { name:'High Uric Acid', aliases:['high uric acid','hyperuricemia','elevated uric acid','uric acid gout risk','purine excess'], emoji:'🩸', type:'lifestyle', description:'Elevated levels of uric acid in the blood (hyperuricemia) without necessarily causing symptoms. When levels are very high, uric acid crystals can deposit in joints (causing gout) or the kidneys (causing kidney stones). Very common, largely lifestyle-driven.', symptoms:['Often asymptomatic','Gout attacks in those who develop crystal deposition — severe joint pain','Kidney stones — flank pain, blood in urine','Tophi — chalky lumps under the skin in chronic severe hyperuricemia'], causes:['High-purine diet — red meat, organ meat, shellfish, beer','Excess fructose (soft drinks and fruit juice)','Alcohol especially beer','Dehydration','Diuretic medications','Reduced kidney uric acid excretion','Obesity'], homecare:['Drink 2-3 liters of water daily to promote uric acid excretion','Reduce red meat, organ meat, and shellfish consumption','Eliminate or reduce alcohol especially beer','Avoid fructose-sweetened drinks','Maintain a healthy weight','Cherries and vitamin C — both shown to modestly reduce uric acid levels'], whenToSeeDoctor:'Serum uric acid levels are measured on a blood test. A doctor can prescribe urate-lowering therapy (allopurinol, febuxostat) if levels are persistently high or if gout or kidney stones occur. Target uric acid below 360 micromol/L (6 mg/dL) if gout has occurred.', urgency:'low' },

  { name:'Gout Flare', aliases:['gout flare','acute gout attack','gout attack','gout episode','joint gout attack'], emoji:'🦴', type:'lifestyle', description:'An acute episode of intense joint pain, swelling, redness, and warmth caused by the sudden deposition of monosodium urate crystals in a joint. The most painful form of arthritis. The big toe joint is most commonly affected.', symptoms:['Sudden onset of severe, excruciating joint pain — often waking from sleep','Most commonly affects the big toe joint (podagra)','Swelling, redness, warmth, and extreme tenderness at the joint','The joint may be too sensitive to tolerate a sheet touching it','Fever in some cases','Episode typically resolves in 3-10 days without treatment'], causes:['Trigger of uric acid crystal deposition — often a dietary trigger, dehydration, alcohol, or illness','Underlying hyperuricemia (elevated blood uric acid)','Triggers: alcohol, shellfish, red meat, dehydration, diuretics, surgery, trauma'], homecare:['Take colchicine or NSAIDs at the very first sign of an attack — early treatment dramatically reduces severity and duration','Apply ice to the joint — 15-20 minutes several times per day','Rest the affected joint — avoid pressure or weight-bearing','Drink plenty of water','Avoid alcohol and purine-rich foods during and after the attack'], whenToSeeDoctor:'First gout attack should be evaluated by a doctor to confirm the diagnosis (joint fluid analysis if uncertain) and assess serum uric acid. Recurrent attacks warrant long-term urate-lowering therapy with allopurinol or febuxostat.', urgency:'medium' },

  /* ── LIFESTYLE: DIGESTIVE & FOOD SENSITIVITIES ── */
  { name:'Non-Celiac Gluten Sensitivity', aliases:['non celiac gluten sensitivity','ncgs','gluten sensitivity','gluten intolerance non celiac','wheat sensitivity'], emoji:'🌾', type:'lifestyle', description:'A condition where individuals experience symptoms similar to celiac disease when consuming gluten but without the autoimmune intestinal damage or antibodies of true celiac disease. The diagnosis is one of exclusion after ruling out celiac and wheat allergy.', symptoms:['Abdominal pain and bloating after eating gluten-containing foods','Diarrhea or constipation','Fatigue and brain fog after gluten consumption','Headaches','Muscle and joint pain','Skin rash in some cases','Symptoms improve significantly on a gluten-free diet'], causes:['Exact mechanism unclear — may involve innate immune response to gliadin or fermentable carbohydrates in wheat (FODMAPs)','Not autoimmune (unlike celiac)','Not IgE-mediated (unlike wheat allergy)'], homecare:['Gluten-free diet — eliminates wheat, barley, and rye','Read food labels carefully — gluten hides in many processed foods, sauces, and medications','Track symptoms to confirm gluten is the trigger (food diary)','Unlike celiac disease, strict cross-contamination avoidance may not be necessary for all — sensitivity varies'], whenToSeeDoctor:'A gastroenterologist should be consulted to formally exclude celiac disease (blood tests and small bowel biopsy) before committing to a gluten-free diet — the diet must be maintained at the time of testing. A dietitian can help ensure nutritional adequacy on a gluten-free diet.', urgency:'low' },

  { name:'Histamine Intolerance', aliases:['histamine intolerance','histamine sensitivity','histamine excess','dao enzyme deficiency','histamine food reaction'], emoji:'🍷', type:'lifestyle', description:'A condition where the body cannot break down histamine efficiently, causing symptoms resembling an allergic reaction after consuming high-histamine foods. Related to reduced diamine oxidase (DAO) enzyme activity rather than a true allergy.', symptoms:['Headaches or migraines after consuming red wine, aged cheese, or fermented foods','Flushing and skin redness','Nasal congestion and runny nose','Itching and urticaria (hives)','Digestive symptoms — abdominal pain, bloating, diarrhea','Heart palpitations','Fatigue'], causes:['Reduced diamine oxidase (DAO) enzyme activity — impairs histamine breakdown in the gut','Gut inflammation or dysbiosis reducing DAO production','Certain medications blocking DAO — some antibiotics, NSAIDs, antidepressants','High-histamine diet without adequate enzyme capacity to process it'], homecare:['Low-histamine diet — avoid fermented foods, aged cheeses, red wine, vinegar, cured meats, smoked fish, spinach, tomatoes, and strawberries','Eat fresh foods rather than leftovers (histamine increases with food age)','DAO enzyme supplement taken before high-histamine meals — helps some people','Food diary to identify personal high-histamine triggers'], whenToSeeDoctor:'A gastroenterologist or allergist can help diagnose histamine intolerance by excluding true allergies and confirming response to a low-histamine diet. A dietitian can help create a nutritionally balanced low-histamine meal plan.', urgency:'low' },

  { name:'Food Sensitivity', aliases:['food sensitivity','food intolerance','food hypersensitivity','food reaction','non allergic food reaction'], emoji:'🍽️', type:'lifestyle', description:'An adverse reaction to specific foods that is not mediated by IgE antibody (not a true allergy) and does not cause anaphylaxis. Reactions are typically dose-dependent, delayed, and involve the digestive system and general wellbeing.', symptoms:['Bloating, gas, and abdominal discomfort after eating trigger foods','Diarrhea or loose stools','Fatigue and brain fog following trigger food consumption','Headaches','Skin reactions — rashes, worsening eczema','Symptoms typically delayed hours after eating (unlike allergy which is immediate)'], causes:['Enzyme deficiencies — lactase deficiency causing lactose intolerance','FODMAP foods (fermentable carbohydrates) causing IBS-like symptoms','Food additives — preservatives, sulfites, MSG','Non-celiac gluten sensitivity','Histamine intolerance','Gut microbiome imbalance'], homecare:['Elimination and reintroduction diet — remove suspected foods for 2-4 weeks and reintroduce one at a time to identify triggers','Food and symptom diary','Work with a dietitian to ensure nutritional completeness when eliminating food groups','Low-FODMAP diet is the most evidence-based dietary approach for IBS and food sensitivity symptoms'], whenToSeeDoctor:'A gastroenterologist should be consulted to exclude organic disease (celiac, IBD) before attributing symptoms to food sensitivity. A registered dietitian should supervise elimination diets to prevent nutritional deficiency. Allergy testing should exclude true IgE-mediated food allergy.', urgency:'low' },

  { name:'Leaky Gut', aliases:['leaky gut','intestinal permeability','gut permeability','leaky gut syndrome','increased gut permeability'], emoji:'🏥', type:'lifestyle', description:'A concept where the tight junctions of the intestinal lining become loose, allowing bacteria, toxins, and undigested food particles to pass into the bloodstream, potentially triggering immune responses. Scientifically recognized as increased intestinal permeability — its role in causing systemic disease remains under research.', symptoms:['Chronic bloating and gas','Digestive discomfort','Fatigue','Brain fog','Food sensitivities','Skin problems — rashes, eczema, acne','Joint pain','Frequent illness from impaired immune function'], causes:['Poor diet high in processed foods, sugar, and alcohol','Chronic stress reducing gut barrier function','Dysbiosis — imbalance in gut bacteria','NSAID overuse — directly damages gut lining','Chronic infections or inflammatory bowel conditions','Gluten in those with celiac disease or NCGS'], homecare:['High-fiber diet feeding beneficial gut bacteria — vegetables, legumes, whole grains, fruit','Fermented foods — yogurt, kefir, kimchi, sauerkraut to support gut microbiome','Remove ultra-processed foods, excess sugar, and alcohol','Manage stress — the gut-brain axis means stress directly impairs gut barrier function','Glutamine supplementation — some evidence for supporting gut barrier repair','Probiotics — strain-specific evidence is growing'], whenToSeeDoctor:'Current evidence does not support commercial \'leaky gut\' testing. A gastroenterologist should evaluate persistent digestive symptoms to exclude IBD, celiac disease, or IBS before attributing symptoms to gut permeability.', urgency:'low' },

  { name:'Dysbiosis', aliases:['dysbiosis','gut dysbiosis','gut flora imbalance','gut bacteria imbalance','microbiome dysbiosis'], emoji:'🦠', type:'lifestyle', description:'An imbalance in the gut microbiome — the trillions of bacteria and other microorganisms residing in the digestive tract — where harmful bacteria predominate over beneficial ones. Associated with digestive problems, immune dysfunction, and potentially far-reaching systemic effects.', symptoms:['Chronic bloating and gas','Irregular bowel habits — constipation or diarrhea','Abdominal discomfort after eating','Fatigue','Sugar and refined carbohydrate cravings','Frequent infections suggesting impaired immunity','Brain fog (gut-brain axis disruption)'], causes:['Antibiotic use — disrupts and reduces microbial diversity','High-sugar, low-fiber processed food diet — feeds harmful bacteria','Chronic stress — the gut-brain axis means stress directly alters gut bacteria composition','Proton pump inhibitor (PPI) overuse','Lack of dietary diversity — fewer plant species in the diet'], homecare:['Eat 30 different plant foods per week — dietary diversity is the most powerful driver of microbiome diversity','High-fiber foods (prebiotic) — feed beneficial bacteria (onions, garlic, leeks, bananas, oats, asparagus)','Fermented foods provide live beneficial bacteria (yogurt, kefir, kimchi, sauerkraut, miso)','Avoid unnecessary antibiotics','Reduce sugar and processed food intake','Probiotics — beneficial for specific conditions (IBS, antibiotic-associated diarrhea)'], whenToSeeDoctor:'A gastroenterologist should investigate significant or persistent digestive symptoms to exclude pathological causes. The microbiome field is rapidly evolving — evidence-based testing and interventions are being developed. Commercially sold dysbiosis tests vary widely in validity.', urgency:'low' },

  { name:'Poor Gut Health', aliases:['poor gut health','bad gut health','unhealthy gut','gut problems','digestive health problems'], emoji:'🏥', type:'lifestyle', description:'A general state of suboptimal gastrointestinal health characterized by digestive discomfort, irregular bowel habits, and poor gut microbiome diversity. The gut is increasingly recognized as central to overall health through the gut-brain, gut-immune, and gut-metabolic axes.', symptoms:['Frequent bloating and gas','Abdominal pain or discomfort','Irregular bowel habits — alternating constipation and diarrhea','Heartburn and indigestion','Food intolerances developing','Fatigue and brain fog associated with eating','Frequent illness','Skin problems'], causes:['Low-fiber, highly processed diet','Antibiotic overuse','Chronic stress','Insufficient sleep','Sedentary lifestyle','Excess alcohol','Inadequate hydration'], homecare:['High-fiber diet — aim for 25-35g fiber daily from diverse plant sources','30 or more different plant species per week for microbiome diversity','Fermented foods daily — yogurt, kefir, kimchi, sauerkraut, kombucha','Stay well hydrated — 2 liters per day minimum','Regular exercise improves gut motility and microbiome health','Manage stress — a major driver of gut dysfunction','Minimize unnecessary antibiotics and PPIs'], whenToSeeDoctor:'Persistent gut symptoms should be evaluated by a gastroenterologist to exclude IBD, celiac disease, and bowel cancer before attributing them to lifestyle factors. A dietitian can help design a gut-health-focused dietary plan.', urgency:'medium' },

  { name:'Obesity', aliases:['obesity','overweight','weight problem','fat','bmi high','gaining weight'], emoji:'⚖️', type:'lifestyle', description:'A complex condition involving excess body fat that increases the risk of health problems. BMI above 30 is classified as obese. Highly preventable and manageable.', symptoms:['Excess body weight and fat','Shortness of breath with activity','Snoring or sleep apnea','Back and joint pain','Fatigue','Excessive sweating'], causes:['Consuming more calories than burned','Sedentary lifestyle','Genetics and family history','Certain medications','Hormonal disorders (thyroid, PCOS)','Poor sleep'], homecare:['Create a calorie deficit — reduce portions and choose healthy foods','Exercise at least 30 minutes most days','Drink water instead of sugary drinks','Eat more vegetables, fruits, and whole grains','Track food intake','Get enough sleep (poor sleep increases hunger hormones)'], whenToSeeDoctor:'BMI above 30, obesity-related health problems (diabetes, hypertension, sleep apnea), or inability to lose weight despite lifestyle changes. Medical supervision is recommended.', urgency:'medium' },

  { name:'PCOS', aliases:['pcos','polycystic ovary','polycystic ovarian syndrome','irregular periods','hormonal imbalance','pco','ovarian cyst'], emoji:'🌸', type:'lifestyle', description:'Polycystic Ovary Syndrome is a hormonal disorder common among women of reproductive age. It affects menstrual cycles, fertility, and metabolism.', symptoms:['Irregular or absent menstrual periods','Excess hair on face or body (hirsutism)','Acne and oily skin','Hair thinning or loss on scalp','Weight gain (especially around abdomen)','Difficulty getting pregnant','Small cysts on ovaries (on ultrasound)'], causes:['Excess insulin and insulin resistance','Low-grade inflammation','Genetics and family history','Excess androgen hormones'], homecare:['Maintain a healthy weight — even 5-10% weight loss improves symptoms','Follow a low glycemic diet (avoid refined carbs and sugar)','Exercise regularly','Manage stress','Track your menstrual cycle'], whenToSeeDoctor:'Irregular periods, difficulty conceiving, or symptoms of PCOS. Diagnosis requires blood tests and ultrasound. An endocrinologist or gynecologist can help manage this effectively.', urgency:'medium' },

  { name:'Dehydration', aliases:['dehydration','not drinking water','thirst','dry mouth','dark urine','dehydrated'], emoji:'💧', type:'common', description:'Dehydration occurs when your body loses more fluid than you take in. Even mild dehydration affects energy and mood. Very common especially in hot climates.', symptoms:['Extreme thirst','Dark yellow or brown urine','Dry mouth and lips','Fatigue and dizziness','Headache','Decreased urination','Dry skin'], causes:['Not drinking enough water','Excessive sweating in heat or during exercise','Diarrhea or vomiting','Fever','Certain medications (diuretics)'], homecare:['Drink water regularly throughout the day — aim for 8-10 glasses','ORS for severe dehydration','Eat foods with high water content — cucumber, watermelon, oranges','Avoid excessive caffeine and alcohol','Drink more in hot weather or when exercising'], whenToSeeDoctor:'No urination for 8+ hours, sunken eyes, rapid heartbeat, confusion, or if unable to keep fluids down. Severe dehydration requires IV fluids.', urgency:'medium' },

  { name:'Heat Stroke & Heat Exhaustion', aliases:['heat stroke','heat exhaustion','sunstroke','sun stroke','overheating','heat illness'], emoji:'☀️', type:'emergency', description:'Heat stroke is a life-threatening emergency where the body overheats (above 104°F/40°C). Heat exhaustion is the milder precursor. Both require immediate action.', symptoms:['High body temperature (heat stroke: above 104°F)','Hot and red dry skin (no sweating in heat stroke)','Heavy sweating and pale skin (heat exhaustion)','Rapid heartbeat','Confusion or unconsciousness (heat stroke)','Nausea and vomiting','Headache and dizziness'], causes:['Exposure to high temperatures','Physical exertion in hot weather','Insufficient fluid intake','Wearing heavy clothing in heat','Working outdoors in summer'], homecare:['MOVE to a cool shaded area immediately','Remove excess clothing','Apply cool water to skin, especially neck, armpits, and groin','Fan the person','Drink cool water if conscious and alert','Use cool wet cloths or ice packs'], whenToSeeDoctor:'Heat stroke is a MEDICAL EMERGENCY — call ambulance immediately. Unconsciousness, confusion, or high fever in hot conditions requires immediate emergency care.', urgency:'high' },

  { name:'Urinary Tract Infection (UTI)', aliases:['uti','urinary tract infection','urine infection','burning urination','frequent urination','bladder infection','cystitis'], emoji:'🔥', type:'common', description:'An infection in any part of the urinary system. More common in women. Usually affects the bladder (cystitis) but can spread to kidneys if untreated.', symptoms:['Burning sensation when urinating','Frequent urge to urinate','Cloudy or foul-smelling urine','Pelvic pain in women','Blood in urine (pinkish or red)','Low-grade fever'], causes:['Bacteria (usually E. coli) entering the urinary tract','Poor hygiene','Dehydration','Holding urine for too long','Sexual activity','Pregnancy'], homecare:['Drink plenty of water to flush bacteria out','Urinate frequently — do not hold it in','Wipe from front to back after toilet','Wear cotton underwear and loose clothing','Cranberry juice may help prevent (not treat) UTIs'], whenToSeeDoctor:'UTI symptoms lasting more than 2 days, high fever, back or flank pain (possible kidney infection), blood in urine, or UTI during pregnancy — always needs medical treatment.', urgency:'medium' },

  { name:'Skin Rash', aliases:['rash','skin rash','dermatitis','eczema','skin irritation','itchy skin','red skin','skin allergy'], emoji:'🔴', type:'common', description:'A rash is a change in the skin that causes redness, itching, or inflammation. Can be caused by allergies, infections, heat, or skin conditions.', symptoms:['Redness or discoloration of skin','Itching or burning sensation','Bumps, blisters, or patches','Swelling','Dry, flaky, or scaly skin','Warmth in the affected area'], causes:['Allergic reaction to food, plants, or chemicals','Eczema (atopic dermatitis)','Heat rash (prickly heat)','Contact dermatitis (soap, detergent, jewelry)','Viral or bacterial infections','Psoriasis'], homecare:['Avoid the suspected cause (soap, food, fabric)','Apply calamine lotion or hydrocortisone cream for itching','Use a cold compress for relief','Keep the area clean and dry','Wear loose, breathable cotton clothing','Moisturize dry skin regularly'], whenToSeeDoctor:'Rash spreading rapidly, blisters, peeling skin, difficulty breathing, rash with fever, or rash not improving after 1 week.', urgency:'medium' },

  { name:'Toothache', aliases:['toothache','tooth pain','dental pain','tooth decay','cavity','gum pain','wisdom tooth'], emoji:'🦷', type:'common', description:'Pain in or around a tooth, usually caused by tooth decay, infection, or gum disease. Can range from mild discomfort to severe throbbing pain.', symptoms:['Sharp, throbbing, or constant tooth pain','Pain when biting or chewing','Sensitivity to hot and cold','Swelling around the tooth or jaw','Fever (if infection is present)','Headache'], causes:['Tooth decay (cavity)','Cracked or chipped tooth','Infected tooth (abscess)','Gum disease','Grinding teeth (bruxism)','Impacted wisdom tooth'], homecare:['Rinse with warm salt water','Apply clove oil with a cotton ball to the area (natural anesthetic)','Take OTC pain relievers (ibuprofen works best for dental pain)','Apply ice pack on cheek','Avoid very hot, cold, or sweet foods'], whenToSeeDoctor:'Severe pain, swelling of face or jaw, fever, difficulty swallowing or breathing, or if pain persists more than 1-2 days. Dental infections can be dangerous if untreated.', urgency:'medium' },

  { name:'Eye Strain', aliases:['eye strain','digital eye strain','tired eyes','eye fatigue','blurry vision','eye pain from screen','computer vision'], emoji:'👁️', type:'lifestyle', description:'Discomfort in the eyes after intense use, especially from screens. Very common in the digital age. Usually temporary and resolves with rest.', symptoms:['Sore, tired, or burning eyes','Blurred or double vision','Headache','Difficulty concentrating','Dry or watery eyes','Neck and shoulder pain'], causes:['Prolonged screen use (computer, phone, TV)','Poor lighting','Incorrect screen distance or angle','Uncorrected vision problems','Dry air from air conditioning'], homecare:['Follow the 20-20-20 rule: every 20 min, look at something 20 feet away for 20 seconds','Adjust screen brightness and font size','Position screen at arm\'s length','Use artificial tear drops for dry eyes','Take regular breaks from screens'], whenToSeeDoctor:'Persistent blurred vision, double vision, sudden vision changes, eye pain with redness, or if headaches are severe and recurring. Get regular eye checkups.', urgency:'low' },

  { name:'Vitamin D Deficiency', aliases:['vitamin d deficiency','low vitamin d','vitamin d','bone pain','sun vitamin'], emoji:'☀️', type:'lifestyle', description:'Vitamin D deficiency is extremely common especially in people with indoor lifestyles. It affects bones, immune function, and mood. Easily corrected.', symptoms:['Bone pain and tenderness','Muscle weakness and fatigue','Frequent infections','Depression or low mood','Hair loss','Slow wound healing'], causes:['Insufficient sun exposure','Darker skin (requires more sun exposure)','Indoor lifestyle','Poor diet (few vitamin D-rich foods)','Obesity (vitamin D gets stored in fat)','Older age (skin produces less vitamin D)'], homecare:['Spend 15-30 minutes in morning sunlight daily','Eat vitamin D-rich foods — fatty fish, egg yolks, fortified dairy and cereals','Take vitamin D3 supplements as prescribed','Combine with calcium and magnesium for bone health'], whenToSeeDoctor:'Suspected deficiency requires a blood test (25-OH Vitamin D). Severe deficiency needs prescription-strength supplements.', urgency:'low' },

  { name:'Kidney Stones', aliases:['kidney stones','kidney stone','renal calculi','nephrolithiasis','stone in kidney','urinary stone','severe back pain urine'], emoji:'🪨', type:'common', description:'Hard deposits of minerals and salts that form inside the kidneys. Can cause severe pain when passing through the urinary tract. Very common, especially in men.', symptoms:['Severe, sharp pain in the back, side, or lower abdomen','Pain that comes in waves','Pain during urination','Pink, red, or brown urine','Nausea and vomiting','Frequent urge to urinate','Cloudy or foul-smelling urine'], causes:['Dehydration and not drinking enough water','High salt or protein diet','Family history','Obesity','Certain medications or supplements (calcium, vitamin C excess)'], homecare:['Drink at least 2-3 liters of water daily','Reduce salt and animal protein in diet','Lemon juice in water increases citrate (prevents stone formation)','Take prescribed pain relievers','Strain urine to catch passed stone for analysis'], whenToSeeDoctor:'Severe pain, fever with pain (sign of infection), inability to pass urine, or if stone does not pass after several days. Large stones may need medical removal.', urgency:'high' },

  { name:'Sinusitis', aliases:['sinusitis','sinus','sinus infection','sinus pain','facial pain','sinus headache','blocked sinus','nasal congestion'], emoji:'👃', type:'common', description:'Inflammation of the sinuses (air-filled cavities in the skull) usually caused by infection or allergy. The face, forehead, and nose can be painful and congested.', symptoms:['Pain and pressure in face (cheeks, forehead, around eyes)','Nasal congestion and discharge (thick yellow or green)','Loss of smell and taste','Headache','Fatigue','Sore throat from drainage','Cough'], causes:['Viral infection (most common) — often follows a cold','Bacterial infection','Allergies','Nasal polyps or deviated septum','Dry air'], homecare:['Steam inhalation 2-3 times daily','Nasal saline irrigation (Neti pot or nasal spray)','Stay well hydrated','Use a humidifier','Apply warm compress over sinuses','Rest and avoid cold air'], whenToSeeDoctor:'Symptoms lasting more than 10 days without improvement, high fever, severe headache, stiff neck, vision changes, or swelling around eyes.', urgency:'low' },

  { name:'Mumps', aliases:['mumps','swollen cheeks','swollen glands','parotid gland swelling'], emoji:'🏥', type:'infectious', description:'A contagious viral infection that mainly affects the salivary glands, causing characteristic swollen, puffy cheeks. Preventable by MMR vaccination.', symptoms:['Swollen and painful salivary glands (puffy cheeks and jaw)','Fever','Headache','Muscle aches','Loss of appetite','Difficulty chewing and swallowing'], causes:['Mumps virus (paramyxovirus)','Spreads through respiratory droplets and saliva','Unvaccinated individuals at high risk'], homecare:['Rest and drink plenty of fluids','Soft foods that are easy to chew','Cold or warm packs on swollen glands','Paracetamol for pain and fever','Gargle with warm salt water for throat discomfort'], whenToSeeDoctor:'High fever, severe headache with stiff neck (meningitis), testicular pain and swelling in males, or hearing loss after mumps.', urgency:'medium' },

  { name:'Jaundice', aliases:['jaundice','yellow eyes','yellow skin','yellowish','yellowing of skin'], emoji:'🍋', type:'common', description:'Yellowing of the skin and whites of the eyes caused by high bilirubin levels. It is a symptom of an underlying condition, not a disease itself.', symptoms:['Yellow discoloration of skin and eyes','Dark yellow or brown urine','Pale or clay-colored stools','Itching','Fatigue','Abdominal pain','Nausea'], causes:['Liver disease (hepatitis, cirrhosis)','Bile duct obstruction (gallstones)','Hemolysis (destruction of red blood cells)','Newborn jaundice (physiological — common and usually benign)','Certain medications'], homecare:['Rest completely','Avoid alcohol completely','Eat a light, low-fat diet','Stay hydrated','Avoid heavy or spicy food','Light exposure for newborn jaundice (under doctor supervision)'], whenToSeeDoctor:'Jaundice always requires medical evaluation to find the underlying cause. See a doctor promptly — especially if accompanied by fever, abdominal pain, or confusion.', urgency:'high' },

  { name:'Cholesterol (High)', aliases:['high cholesterol','cholesterol','hypercholesterolemia','lipid problem','bad cholesterol','ldl','hdl'], emoji:'🫀', type:'lifestyle', description:'High cholesterol means you have too much of a fatty substance in your blood. Over time it can lead to blocked arteries and heart disease. Usually has no symptoms.', symptoms:['Usually no symptoms','Chest pain (if arteries are blocked)','Xanthelasma (yellowish deposits around eyes) in extreme cases','Detected only through blood test'], causes:['Unhealthy diet (high in saturated and trans fats)','Sedentary lifestyle','Obesity','Smoking','Family history','Diabetes and hypothyroidism'], homecare:['Reduce saturated fats (butter, red meat, full-fat dairy)','Eat more fiber — oats, beans, fruits, vegetables','Exercise 30 min most days','Quit smoking','Lose excess weight','Eat healthy fats — olive oil, nuts, avocado'], whenToSeeDoctor:'Get cholesterol checked every 5 years from age 20. If levels are high, a doctor will recommend diet changes and possibly medication (statins).', urgency:'medium' },

  { name:'Vertigo', aliases:['vertigo','dizziness','spinning sensation','balance problem','dizzy','lightheaded'], emoji:'🌀', type:'common', description:'A sensation of feeling off balance or that the world is spinning around you. Often caused by an inner ear problem. Usually not serious but very disorienting.', symptoms:['Sensation of spinning or movement when still','Loss of balance','Nausea and vomiting','Headache','Sweating','Ringing in the ears (tinnitus)'], causes:['BPPV (benign paroxysmal positional vertigo — most common)','Meniere\'s disease (inner ear fluid)','Labyrinthitis (inner ear infection)','Migraine','Head injury'], homecare:['Sit or lie down immediately when dizzy to avoid falling','Move slowly — especially when getting up','Epley maneuver (for BPPV — a series of head movements)','Avoid caffeine and alcohol','Stay well hydrated'], whenToSeeDoctor:'Vertigo with chest pain, difficulty speaking, double vision, weakness or numbness, or sudden severe headache — these may indicate stroke. Also see doctor if vertigo is persistent or recurrent.', urgency:'medium' },
];

/* ── SEARCH FUNCTION ── */
function searchOfflineDB(query) {
  const q = query.toLowerCase().trim();
  if (!q || q.length < 2) return null;

  let best = null;
  let bestScore = 0;

  for (const d of DISEASE_DB) {
    let score = 0;
    const nameLower = d.name.toLowerCase();

    // Exact name match — highest priority
    if (nameLower === q) { score = 100; }
    // Name starts with query
    else if (nameLower.startsWith(q)) { score = 80; }
    // Name contains query
    else if (nameLower.includes(q)) { score = 60; }
    else {
      // Check aliases
      for (const alias of d.aliases) {
        if (alias === q) { score = Math.max(score, 90); break; }
        if (alias.startsWith(q)) { score = Math.max(score, 70); }
        else if (alias.includes(q)) { score = Math.max(score, 50); }
        else if (q.includes(alias) && alias.length > 3) { score = Math.max(score, 40); }
      }
    }

    if (score > bestScore) { bestScore = score; best = d; }
  }

  return bestScore >= 40 ? best : null;
}
